insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-08-22','Ana: Envío correo a Pedro Garvi, Coord. Progr. Personas sin Hogar de Cáritas (pgarvi.cdcoriacaceres@caritas.es) solicitando Cerficado con fechas de estancias de Javier en Centro Vida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-08-22','Ana: Llamo de Ventura al 927 245 250, éste es el número desde el que me llamó la última vez, pero es del OBISPADO de Cáceres... ········· Llamo al 682 483 126: me confirma que sí renovó su DNI. Mañana lo llevará a la ONCE para que lo escaneen y me lo envíen por correo. ·············· Con ello ya podré cumpimentar los datos pendientes de las solicitud del viaje de Navidad "Vacaciones en familia" de la ONCE. ················· *También le informo que desde la Secc. Ecca. se ha autorizado este viaje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-08-22','Ana: Tras recibir llamada de Azucena, Cuñada de Juanjo (625 367 302), envío mail a Maite, Jefa CTAEx: "En relación a Juan José Maseda del Sol, con plaza en C.O. en Novaforma, ¿podrías mirar porfa si tiene pedida plaza residencial / RAL? Me ha llamado la cuñada, dice que ya no pueden más con él, tiene incidencias cada dos por tres en casa, ayer “la volvió a liar” Y la convivencia es cada vez es más insostenible. Tiene un niño pequeño y expresa que esto no puede seguir así. Añade que la última vez que le visitó Virginia-Ed. de Futuex él aceptó ingreso en centro. Nosotras, para variar, aún no tenemos información al respecto. ..." ············· Respuesta de Maite: "Está el 8º en Novaforma. Eso se traduce en años de espera. Sino ampliamos no va a entrar pronto" **Procederemos a solicitar ampliación de centros. ································································································································································································· Envío correo a la Secc. Ecca. ctutelar@: "He recibido llamada de la cuñada de JUAN JOSÉ MASEDA DEL SOL, con quien convive y quien le ayuda a administrarse. Solicitan un extra de 50€ para unas zapatillas y chándal. Como no es mucho, os lo envío directamente a vosotras. Sería para retirar el extra de la oficina bancaria y ya ella le acompaña a comprarlo, esta vez no es con presupuesto de tienda. Ya me decís si es viable y cuándo podrían ir a retirarlo." ········································ Respuesta de Lourdes, Secc. Ecca.: "se autoriza el extra de 50€, indícales que podrán pasar a retirarlos la próxima semana, del 28 de agosto al 1 de septiembre." ··············· Llamo a Azucena y se lo comunico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-08-22','Ana: correo de Miguel, A. Jurídico, al ctutelar y las TS: "Buenos días, parte económica acaba de llamarme Belén de Unicaja (924-550079) porque está allí la curatelada asistencial para sacar dinero y al no tener nuestro escrito habitual me han llamado para preguntar. Les he dicho que os pondréis en contacto con ellos esta mañana para confirmarles que pueda o no retirar dinero, pero que hasta que desde la Comisión no enviéis documento autorizando reintegros o transferencias que no den nada. El email al que os tenéis que dirigir en caso de enviar alguna autorización es buzon7116@unicaja.es Parte social: es una curatela de Tere… Llamad a la oficina y aclarárselo." ···································· Respuesta de Icíar, Secc. Ecca.: "He hablado con el banco, la señora ha ido a sacar dinero, vive sola, no tiene ninguna asignación establecida porque según informe social no deja a nadie entrar en la casa. Amalia lo debió de derivar a Futuex pero no sé qué habrá pasado. El del banco me ha facilitado el número de teléfono de un abogado que es quien dice le lleva todo, Pedro 637430192., por si hubiera que ponerse en contacto. Le he dicho que mañana le mandamos autorización para que pueda retirar algo de dinero, lo último que ha sacado son 400 € el 27 de julio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2023-08-22','Ana: Envío mail a Miguel, A. Jurídico: "Me pregunta la compañera el CAMP de Don Benito, si se llegó a pedir abogado de oficio para NATLAIA MEJÍAS MILLÓN. Desde el centro me confirman que la acompañarán al Juzgado de Castuera, pero necesitan saber eso o cómo se va a proceder. Por favor, ponge en contacto con ella ditectamente: Toñi, TS: 20113 // antonia.escobare@salud-juntaex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2023-08-23','Ana: Respuesta de Miguel, A. Jurídico, a Toñi, TS CAMP Las Cruces (20113 // antonia.escobare@salud-juntaex.es): "para la citación del 5-9-2023 hemos solicitado que el juzgado de Castuera pida abogado de oficio. Ese día habréis de acompañar a Natalia. Nosotros salvo que el juzgado no lo estimase oportuno asistiremos vía videoconferencia." ································································································································································································ Llamada de Toñi, TS - CAMP: comunica que está habiendo problemas en relación con las salidas de Natalia a domicilio. ······ Ella cuenta que cuando llegó la madre estaba detenida por haber apuñalado a su pareja. Al parecer esto está en investigación. Ha preguntado a los SSASB para que cuando puedan le informen al respecto. También van a preguntar a la policía. No es la primera vez que Natalia regresa contando sucesos para nada normales. ··············· Llamada de Ana, Responsable Asistencial del CAMP. Está supliendo a Clemen, Directora en sus vacaciones. Considera que las salidas al domicilio son demasiado largas y contraproducentes. **Acordamos que hasta que no se esclarezca los hechos no volverá a ir a casa de la madre. Y las visitas al padre serán de menor duración. ················· Me informa también que cuando bajó del Autobús la educadora le vio besar a un hombre de más de 50 años. Ella dice que es su novio. Le cuenta en su despacho que tuvo tocamientos en el bus. Y que habían quedado esa tarde a las 19 h. En su lugar acudió a la cita Fernando, un Educador del Centro, y llamaron también a Colaboración Ciudadana. El hombre no llegó a presentarse. ···· Se decide restringir también las salidas sola por Don Benito, se acaban de conocer y pueden buscarse. ······ Explicaron a Natalia que si quieren ser pareja, él deberá ir a presentarse para que le conozcan en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-08-23','Ana: Correo de de Puerto, TS SSASB (ssb5@mancomunidadvalledelalagon.es): "ayer estuvieron las auxiliares SAD en el domicilio de ENRIQUE, no le pudieron hacer la comida porque no tiene menaje de cocina (ni sartén, ni cazuela) Se le ha dicho que debe adquirirlo para poder realizar las comidas..." ··································································································································································································· Correo-respuesta de Estrella, Secc. Ecca., sobre el presupuesto/tto. dental: "se autorizó un presupuesto de una limpieza por importe de 30 €. El 30 de junio hablé con Inoa(clínica dental “El parque” de Montehermoso.927 675873)me enviaría factura cuando se hiciera el trabajo. Y hasta ahí te puedo contar" ···················· Informo mediante mail a Ana Benavente, ESM y Puerto, SSASB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2023-08-23','Maite:ha venido Ramón. Ha subido aprovechando que en ese momento no estaba el personal de seguridad. Ha preguntdo por Teresa, le han indicado que se siente ya así lo ha hecho. Alberto a llamado a Rosa ( guardia de seguridad) se lo ha llevado y ha venido la policía. Ha subido para preguntar qué ha pasado. Se le ha informado de sus visitas de la semana pasada y del dinero que e le facilita. Han hablado con él pero no se lo han llevado detenido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-08-23','Maite: Durante la estancia de JOsé MAría en el domcilio familiar hablé con él. Estaba muy contento y se mostraba muy tranquilo. Me dijo:  ves como todo llega. Está empezando a ser consciente de los avances en su comportamiento. La psicóloga me comentó que comenzaba a tomar conciencia de sus actos anteriores. Desde el centro nos indican que la vuelta fue bien. La estancia en su casa ha sido positiva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-08-23','Maite: Con fecha 21 de agosto se ha adjudicado plaza a Aarón en el CAMP de Don Benito. Hablé con Estrella de la UHDAC para que se pongan de acuerdo con el centro para el dia del ingreso. Soraya Masa me dijo que será la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2023-08-23','Ana: Julio, Aux. Secc. Soc, me confirma que ha puesto a la firma el CI de Hermenegildo que ha llegado por correo postal. En cuanto esté firmado lo enviará al CAMP por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-08-23','Ana: A petición de Julia, llamo al Juzgado de Paz de Cilleros (927 512 318) varias veces, pero el teléfono no está operativo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-08-23','Ana: Llamada de Jesús Manuel (635 336 539) en relación a mi llamada de hace dos días. Hoy un poco más calmado, quiere "aclarar que todo es mentira, que quien mete a mendigos en el portal es la vecina de arriba, que él no deja entrar a nadie y tampoco lleva amigos, que hace meses que no va nadie a su casa y la última persona que acudió fue su hijo. Y que también se encuentra muchas veces sucio el portal con colillas y latas de bebidas" ··········· Luego hace más acusaciones a la vecina de arriba, diciendo que le "robó agua del contador", y que le "tiró orines a su terraza desde arriba". ···················· Vuelve a quejarse de la gestión por parte de la CTAEx, que se le da "una miseria para pasar la semana", que se tiene que buscar la vida para sobrevivir, que lleva 7 años queriendo cambiar de casa y no se le permite", "Que se le han negado tratamientos dentales, que envió presupuesto hace años con la educadora", y que "le estamos poniendo en peligro de muerte" ················· Dice también que su "padre le incapacitó para robarle su dinero", que le "quitó millones"... ········· Que ha "solicitado audiencia con la Jueza hasta 7 veces y no le hacen caso".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-08-23','Ana: Llamo al CRR de Mérida (924 30 45 38 / 650 103 996), hablo con Sara, Educadora. Le solicito Certificado de Residencia en el centro con la fecha de Ingreso en el mismo. ········ Se lo pedirá a Javier Pecero, Director para que nos lo remitan a la mayor brevedad. ·················· *Guardo en el expediente digital y remito a Miguel, A. Jurídico, el Cdo. de Residencia en PP.SS. remitido por Javier Pecero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-08-23','miguel, llega por sirex,secretaria general, y abogacia (Felisa) citación para reconocimiento forense el 25-8-23 del jzdo nº1 CC. Envío por email y por lexnet solicitud para que se inhiban y adjunto certificado de residencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2023-08-23','Maite: ha llamado Inma, trabajadora social del hospital de don Benito. Rafael se encuentra ingresado por un síncope. Lo ha visto el neurólogo y confirma principios dedeterioro cognitivo. Preguntan si hay posibilidad de que no vuelva al domicilio. Le he pedido que envíen informe de alta donde recoja esta informacón.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-08-23','Ana: Envío correo a Sheila, Cristina y Pedro, CRR-CC (crr@grupociudadjardin.com): "Como ya sabéis, el procedimiento para revisión de la sentencia de JUAN JOSÉ BERGANTIÑO GLEZ. está en marcha y el próximo día 4 de septiembre tiene cita para reconocimiento con el Médico Forense. Es por este motivo que me pongo en contacto con vosotros, para solicitar INFORME DEL CRR sobre la evolución de Juanjo desde que reside en vuestro recurso y especialmente sobre el estado actual del mismo y las medidas de apoyo que consideráis que a día de hoy necesita, para poder adjuntarlo al escrito que elaboraremos desde el Gabinete Técnico de la CTAEx para contestar al REQUERIENTO QUE SE NOS HACE DEL JUZGADO a fin de revisar su sentencia y establecer nuevas Medidas Judiciales de Apoyo si así lo estima el Juez Nos lo han pedido hoy mismo desde Abogacía General de la Junta y no nos dan mucho marge, por lo que agradeceríamos nos lo hicieseis llegar a la mayor brevedad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-08-23','Ana: correo del PAF (programafamilia@tajosalor.es): "Solamente informaros que hemos acompañado a Aitor al médico de atención primaria para que le deriven al ECA. Cuando le citen le acompañaremos también y os vamos contando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-08-23','Ana: Llamada de Francisco (641 569 490), dice que está sin tabaco y se sube "por las paredes", este mes ha tenido más gastos y ya no le queda dinero. En el centro le han dicho que no le pueden dar más tabaco. Pide un extra de 60€ para tener hasta primeros de mes que pueda volver a retirar su asignación. ··············· Consultaré a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-08-24','Ana: Envío a Julio, Aux. Adtvo. CTAEx, oficio solicitud de informe de psiquiatría al ESM-CC, para que lo remita por SIREX. ········································································································································································································· Se le autoriza el extra de 60 € que solicitó ayer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-08-24','Ana: Envío a Julio, Aux. Adtvo. CTAEx, oficio solicitud de informe de psiquiatría al ESM-CC, para que lo remita por SIREX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-05-22','Ana: Recibimos Certificado Actualizado de Pensión de Orfandad. Guardado en el expdte.','2');
