insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2023-08-24','Ana: Correo de Maite, Jefa Secc. Ecca., a Araceli, TS de Mentalia - Arévalo (tsocialpsicogeriatria.arevalo@mentaliasalud.es): "Le paso a la sección económica la información para que se abone la deuda. Me llama la atención el elevado gasto de medicamentos. Pensaba que todo entraba por la seguridad social. ¿ Le pautan desde el servicio de salud mental fármacos que no están subvencionados?. Vamos a valorar la posibilidad de aumentar su asignación mensual para que no genere deudas derivas de los medicamentos. También aprovecho para pedirte , cuando puedas, me envíes informe de evolución y médico con su pauta de medicación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2023-08-24','Ana: Envío correo a registro (oac.merida.san@juntaex.es): "Adjunto remito Oficio-Solicitud de Certificado Actualizado de Prestación de Orfandad, relativo a INÉS MUÑOZ ALÍAS, cuyo cargo ostenta la CTAEx, para darle registro y remitir a la Dirección Provincial del INSS de Cáceres, junto a la siguiente documentación: - Testimonio de acuerdo de aceptación del cargo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2023-08-25','Maite:Futuex envió este correo. Buenos días damos traslado sobre info obtenida a través de ts de hospital Villanueva/Don Benito, en relación a tutelado Rafael Davila, residente en Quintana de la Serena. Gestiones realizadas: Con fecha, miércoles 23 de agosto de 2023, se reciben dos llamadas telefónicas de la trabajadora social del hospital de Don Benito-Villanueva, para comunicar lo siguiente: que Rafael Dávila está ingresado desde hace unos días, debido a que lo han encontrado tirado en el suelo, sin saber especificar si ha sido en su vivienda o en la calle, sufriendo un síncope. El equipo médico que le atiende y valora su situación, necesita informar a sus tutores, pero no han sido capaces de comunicarse vía telefónica, intentando a varios números de la comisión tutelar, de ahí que hayan llamado a nuestro número para conseguir pasar la información. Exponen que la situación sanitaria de Rafael, según las primeras valoraciones, es preocupante por el deterioro cognitivo que presenta,(en los últimos seguimientos no se evidenciaba tal situación, de hecho se le habían ampliado las horas de ayuda a domicilio y esta dando buen resultado este apoyo) no obstante desde el hospital consideran que dificulta que se le pueda dar alta para regresar solo a su domicilio, con los riesgos que ello conlleva. De ahí que solicitan hablar con sus tutores para valorar la situación. La última visita presencial realizada, ha sido el 03 de este mismo mes de agosto, presentando el propio Rafael quejas al no recibir un extra de dinero y los días de la feria de agosto. Encontrándose su vivienda, aun teniendo auxiliar de ayuda a domicilio, no demasiado bien. La respuesta de la auxiliar es que la dueña le esconde los productos de limpieza. La respuesta de María, dueña de la vivienda, es que la auxiliar le tiene desatendido. Tanto en la visita de junio, como esta de agosto, físicamente se encontraba bien, presentando como decimos, quejas solo, en el tema económico. Ayer hablé de nuevo con la trabajadora social del hospital. Sigue ingresado. Tb consulté con Miguel la posibilidad de solicitar internamiento involuntario. Como es una curatela económica , propopone solicitar revisón de medidas para ampliar la curatela y a la vez pedir medidas cautelares. Le transmití esta información a la trabajdora social. Hablamos de la posibilidad de una plaza sociosanitaria pero tb se necesita la autorización de internamiento involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2023-08-25','Maite: correo de FUTUEX. Buenos días, Tras llamar a Isabel Valadés y no atender el teléfono, se recibe llamada de Sara, hija de Isabel Valadés (629 116 101). Nos informa que su madre se encuentra ingresada en observación a espera de subir a planta. Le han solicitado TAC, analitica y endoscopia. Indica que se ha caído en la calle mareada y pérdida de conocimiento cuando fue a la farmacia. Comenta que ha informado a Amalia de la situación. Durante el tiempo de vacaciones de la persona del equipo que efectúa el appto, ha tenido la cita de digestivo solicitada por su médico de atención primaria en su última consulta (12 de Julio) en la que nos indica Sara que le mandaron pruebas para posterior revisión. Sara coincide en lo que venimos observando estos últimos meses en cada seguimiento efectuado y reflejado en la herramienta en el archivo gestiones realizadas: Incongruencia en el discurso que denota posible delirio o desestabilización de su patología mental siendo palpable el gran deterioro físico y cognitivo en la actualidad. Última visita efectuada, el pasado 12 de julio, acompañamiento cita médico de atención primaria precisamente por estos problemas intestinales. Informamos a Sara de la fecha de consulta en psiquiatría el próximo 1 de septiembre a las 09:20h. Es muy importante que acuda a la consulta ya que son más de 5 años sin revisión en el ESM. Esta cita se solicitó a principios de año con imposibilidad de adelantar fecha. Debido al cese temporal del programa, desde el equipo de apoyo social comunitario no se puede efectuar el acompañamiento. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-08-25','Ana: Llamo al C.S. de Miajadas (927 16 06 63), a Beatriz, persona que me atienda, le sorprende que no llamara la Dra. Sara, MAP de Joaquina, pues dice le pasaron nota. Hoy no podemos hablar con ella pues está de saliente. Hasta el martes no estará en la consulta. ······· Me facilita un correo electrónico para que le escriba y envíe sentencia y ella lo imprimirá y se lo dejará en la consulta. ················· Escribo al correo: beatriz.garrido@salud-juntaex.es "En relación a Dª. JOAQUINA MAYORAL SUÁREZ, cuyo cargo de CURADOR ejerce la COMISIÓN TUTELAR DE ADULTOS DE EXTREMADURA, me pongo en contacto con usted debido a las última incidencias y atenciones domiciliarias realizadas desde el Centro de Salud a Joaquina. Según me informa su hija María, le han visitado 2 veces en pocos días y han tenido que inyectarle medicación dada la alteración que presentaba. Como puede ver en el fallo del testimonio de sentencia judicial adjunto, la Comisión Tutelar (CTAEx), a día de hoy, ejerce el cargo únicamente en el ámbito de la salud. Es por ello que, dado los últimos informes de Servicios Sociales y comunicaciones de su hija, solicitamos: 1. Nos remitan informes médicos de la atención dispensada en su domicilio 2. Si volvieran a atenderla por motivos de posible descompensación a nivel psicopatológica, por favor, si fuera posible, la derivaran erívenla a urgencias del hospital correspondiente para que pueda ser valorada por especialista en Psiquiatría Sabemos que es un caso difícil. Como sabrá vivió durante años en un centro de salud Mental en Mérida, pero desde que le dieron el alta en el mismo, Joaquina presenta un importante deterioro. Ya ha sido valorada de nuevo por el Juzgado y correspondiente Médico Forense, habiendo dictado nuevas Medidas Judiciales de Apoyo y autorización de ingreso en centro, nos obstante, esta última sentencia no adquiere firmeza hasta el día 18 de septiembre, por lo que no podemos actuar aún en base a ella. Ante cualquier duda/aclaración, no dude en contactar. Y, si lo considera, podemos hablar el martes, que es cuando me han dicho que estará en el centro de salud. Pongo en copia a Maite, Jefa de Sección de la CTAEx."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='CAMARA'and apellido2='MORENO'),'2023-08-25','Ana: correo de Icíar, CTAEx: "ya le ha entrado la pensión a Alfonso en la cuenta de Unicaja, además del mes de junio y la paga extra. Rosa del socio le va a ir pasando las mensualidades por la ccc de Caixabank hasta agotar el saldo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2023-08-25','Ana: Llamada de Mª Antonia (927 095 795) Ya no quiere hacerse el tratamiento dental en la Clínica Monreal, porque dice que es muy caro. ········· Pedirá a la otra clínica que ha encontrado que envén otro presupuesto y se pongan en contacto con la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2023-08-25','Ana: Recibimos del INSS, el certificado actualizado de orfandad solicitado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-08-24','Ana: Correo de Puerto, TS SSASB (ssb5@mancomunidadvalledelalagon.es): "hoy han estado las auxiliares en el domicilio, ya ha conseguido una cazuela, solo le han podido hacer unos macarrones "limpios" no tiene casi nada para cocinar... si se le ha aumentado la cuantía habría que controlar si se lo está gastando en otra cosa... Yo esta semana no puedo visitarlo, en cuanto pueda veré con qué cuenta en la cocina y te comento..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2023-08-25','Ana: Correo de María, TS de la Res. Sierra de San Pedro (927 38 32 58 / serviciossociales@centrodemayoressierradesanpedro.es): " Te envío un informe del padrón de Cáceres para poder solicitar la renovación del DNI de Tomasa Sancho García, me han asegurado que con éste documento se puede realizar dicha gestión." ····························· Mi respuesta: "El Certificado de Padrón que me envías es del Ayuntamiento de Cáceres, voy a solicitar la que acuda la unidad móvil de la Policía Nacional a vuestro centro, espero que no haya problemas estando empadronada en un municipio diferente al que reside. No obstante, creo que necesito informe médico que indique su imposibilidad de desplazamiento a la Comisaría a tal fin. Voy a aportar el que enviasteis en febrero, paro no sé si nos servirá, si no fuera así te lo diré para que nos remitas uno actualizado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-08-25','Ana: envío correo a Laura Salguero, Cristian Diaz, Maite, Admón. e Isabel, Directora de la ONCE (LASS@once.es, CRDR@once.es, MTALA@once.es): "En relación a Ventura Gómez García, tal y como acordé con Laura, me pongo en contacto con vosotros por varias cuestiones: 1- Desde la sección económica se ha aprobado el viaje de diciembre de Navidades en Familia que proponíais y organizáis desde vuestra entidad. 2- No he podido cumplimentar la solicitud aún, porque el DNI de Ventura que tenemos escaneado está caducado desde abril. Hablé con Ventura hace varios días para pedirle que, a través vuestra, si no os importa, me hagáis llegar el nuevo, que fue a renovarlo, escaneado a color, para que lo tengamos en el expediente y para todas las gestiones necesarias, como por ejemplo rellenar la instancia del viaje. Pero aún no lo he recibido, me imagino que no os ha dicho nada. Voy a llamarlo de nuevo para recordárselo Pero os lo comunico para que estéis al corriente y, por favor, colaboréis conmigo al respecto. 3- Entendemos que la cuantía que corresponde a Ventura es el máximo que viene en la información. ¿Qué plazo hay para abonarlo? Para recordárselo a las compañeras de la sección económica, pues no quiero que se pase. Y de momento, creo que eso es todo." ····························································································································································································································································· Llamo a Ventura (682 483 126): dice que ha estado esta mañana en la ONCE y Maite, Admón., ha escaneado su DNI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='MARTINEZ'and apellido2='VAZQUEZ'),'2023-08-25','Ana: Llama María, TS de La Providencia (824 903 608): no habían dicho nada antes porque estaban pendientes de los resultados de una analítica. Como está todo bien, mañana Concepción se irá a pasar unos días con su hija a Jabugo, hasta el viernes próximo. Acudirán, como es habitual, a recogerla en coche. ········ Solicitan un extra de 200 € que habrá que transferir a la cuenta de La Providencia, ellas se lo pueden adelantar. ·········································· Respondo a María TS (trabajadorasocial@providencia.es) al correo remitido y pongo en copia a la secc. ecca. para que den OK: "Tal y como hemos acordado mediante conversación telefónica, desde la sección social del Gabinete Técnico de la CTAEx, tal y como se hiciera en otros periodos vacacionales, y no existiendo ninguna circunstancia que desaconseje estas salidas, SE AUTORIZA LA ESTANCIA EN LA FECHA INDICADA EN EL DOMICILIO FAMILIAR DE JABUGO, siempre y cuando sea factible económicamente. Pongo en copia a mis compañeras de la sección económica para que confirmen que puede asumirlo y en tal caso, además, os hagan la transferencia de 200€ solicitado como extra para dicho viaje. Pongo en copia así mismos a Maite, Jefa de la CTAEx, para que esté al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN DIEGO'and edp.apellido1='BAUTISTA'and apellido2='GOMEZ'),'2023-08-25','Ana: Correo de Lola, TS Plena Inclusión, Cabeza del Buey (directorarail@plenainclusioncabezadelbuey.org) al ctutelar@: "Hemos organizado una salida de 3 días a una casa rural en Córdoba. Del 5 al 7 de septiembre Irán 4 personas con discapacidad y 4 apoyos El desplazamiento se hará en furgoneta de la empresa El total de la salida es de 250€ que incluye: desplazamiento, comidas, alojamiento y alguna excursión a Córdoba que hagan. ¿Podría participar Rubén?" ································ Mi respuesta con copia a Maite y Secc. Ecca.: "Desde la sección social de la CTAEx, si es viable económicamente, SE AUTORIZA LA PARTICIPACIÓN DE RUBÉN EN ESTE VIAJE. Pongo en copia a las compañeras del a sección económica para que confirme si es viable, y en tal caso, procedan abonarlo en la forma que les indiquéis. Pongo en copia también a Maite, Jefa de CTAEx."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN DIEGO'and edp.apellido1='BAUTISTA'and apellido2='GOMEZ'),'2023-08-28','Ana: Correo-respuesta de Lourdes, Secc. Ecca., a Lola Casallo, Plena Inclusión: "se autoriza el gasto para la excursión de Ruben. En esta semana recibirán la transferencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2023-08-24','Maite: ha llegado este correo de Raquel del CCR Mérida.  Buenos días, según petición de Rubén Montero, necesita una reunión presencial para tratar los siguientes temas: • Presentación de una factura proforma para la compra de una furgoneta. • Solicitar alta de autónomo • Compatibilidad de otras ayudas con las actuales. Quedamos a la espera de respuesta. Gracias de antemano','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2023-08-25','Maite: he hablado con Raquel sobre el correo de ayer. Cuando vuelva Amalia , le llmaremos o le daremos una cita. Desde el centro no ven viable la compra de una furgoneta ni necesario. Respecto a la cuota de autónomo ( quiere ser jardinero) plantean hbalar con el y poner como requisito formarse en este campo y que aduqiera un compromiso, ya que cambia de idea con facilidad. Hablaremos con él a la vuelta de vacaciones','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-08-28','Ana: Envío correo a Amadora Pérez, Gerente del Cáterin Sol (amadora@solcatering.es // 927 278 236): "Me pongo en contacto contigo para solicitar un nuevo servicio de catering para otra persona a cargo de la Comisión Tutelar de Adultos de Extremadura. Te anoto los siguientes datos para formalizar el servicio de cáterin, si es posible, a partir del martes de la semana que viene: Usuario del servicio de catering: VENTURA GÓMEZ GARCÍA Domicilio: AVDA. HERNAN CORTES, 52, 4º A - CÁCERES DNI: 07432074S Teléfono: 682 483 126 Al igual que en el otro caso, el email para el envío de las facturas es: ctutelar@salud-juntaex.es En cuanto me confirmes avisaré a la persona del día de comienzo del servicio." ················ Respuesta de Amadora - Catering Sol: "Tomamos nota para iniciar el servicio el próximo martes día 5 de septiembre. Muchas gracias por contar con nosotros para vuestros servicios." ············· Llamo a Ventura (682 483 126) para comuncárselo. ··················· Envío tambIén correo informativo a Julia Durán, TS Hogar Mayores (julia.duranm@salud-juntaex.es) y Laura, TS ONCE (LASS@once.es). ····································································································································································································································· Subo al portafirmas digital solicitud de participación en el Programa Navidades en Familia de la ONCE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-08-28','Ana: Correo de Puerto, TS SSASB a la CTAEx, ESM y Alcaldía de Valdeobispo: "A/A. COMISIÓN TUTELAR DE ADULTOS DE EXTREMADURA Y EQUIPO DE SALUD MENTAL DEL SES: Buenos días: según informan desde el Ayuntamiento de Valdeobispo (Alcaldía, auxiliares SAD y vecinos del municipio) D.ENRIQUE SANTOS GARCÍA-PUENTE con DNI 11.782.012-D durante este fin de semana ha estado muy alterado, me comentan los siguientes hechos: - Se ha paseado por el municipio desnudo, acudiendo a las casas de los vecinos pidiendo dinero. La verdad que está siempre por lo visto pidiendo dinero a la gente (me consta que a la Secretaria, a menudo) - Se tuvo que llamar a la guardia civil el viernes desde el Ayuntamiento porque los vecinos fueron a comunicar que Enrique iba con una catana/arma blanca amenazando a la gente - Además deja la basura en la calle y no la lleva al contenedor - Por otro lado, según me informan las auxiliares SAD no ha comprado comida para poder elaborarla adecuadamente y también carece de menaje de cocina para poder cocinar (Hay que recordar que se ha quedado sin servicio de comidas-cena debido al cierre de la Residencia de mayores de Valdeobispo) - Enrique se dirige a la gente con comentarios "obscenos" (a mí por teléfono en alguna ocasión también me lo ha hecho) Por todo ello, se observa desestabilización y dificultades importantes para poder prestar el SAD, os iré informando al respecto... Lo que se comunica a los efectos oportunos" ······························· Respondo a todos: "Como vemos la situación de Enrique es cada vez más compleja e insostenible, no sólo por la gravedad de sus últimos comportamientos de inadaptación social, con la alarma social y riesgo que genera (como la agresión de su perro a una vecina de la localidad o las amenazas con una catana) sino también por la falta de apoyos con los que cuenta y que contamos en el Gabinete Técnico de la CTAEx y el riesgo también para su propia salud. Sinceramente tenemos serias dudas de que pueda seguir residiendo solo en su propio domicilio y es por ello que, además de creer conveniente que le valoren desde el Servicio de Psiquiatría por una posible descompensación psicopatológica, estamos comenzando a plantearnos el solicitar al Juzgado una Autorización de Internamiento Involuntario, eso sí, siendo conscientes, que con su perfil, será complicado el ingreso en los centros existentes en la comunidad. No sé si desde el Equipo de Salud Mental contempláis convocar una Subcomisión de Casos, pero creemos que puedes ser conveniente para valorar de forma conjunta todas las opciones. Puerto, no sé si desde la Guardia Civil os han facilitado el acta/informe de actuación, si es así, agradeceríamos nos lo hicieseis llegar y sino, por favor, facilítame el contacto telefónico para que podamos solicitarlo desde aquí." ············· Respuesta de Puerto: "le diré al Alcalde que lo solicite... y cuando lo tenga te lo envío." ···································································································· Respuesta de Ana Benavente, TS ESM: "Hablado con la Dra. Gómez, se plantea hacer un ingreso para valorar si las conductas que presenta el paciente derivan de una descompensación de su enfermedad mental. Sospechamos que hay comportamientos que tienen que ver más con sus rasgos de personalidad, que con su trastorno bipolar, por tanto habrá que abordarlos según las características de los mismos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-08-28','Ana: Tras recibir corro de Juanma, hermano de José Blás (jmcl1966@hotmail.com // 687 819 309): "llámame cuando puedas, la convivencia de Jose con nuestra madre se ha deteriorado mucho durante el verano y me temo que pueda pasar algo grave.", le llamo: pensaba que la cosa estaba mejor en casa, pues su madre no le estaba contando toda la verdad, pero expresa que ella pasa miendo en casa estando a solas con su hijo. José Blas se pone agresivo con ella y le levanta la mano. La situación ha ido a peor durante los meses de verano. ··········· Él ha llegado a decir que sí quiere ir a vivir a un centro, pero Juanma no está seguro de que llegado el momento realmente acepte el ingreso. ············· Puesto que no contamos con Autorización de Internamiento Involuntario habrá que solicitarlo. Jaunma solicitará informe a su centro de referencia (Down-CC) para que podamos aportarlo a la solicitud. ·············· Por otra parte recomiendo que indique a su madre, que en momentos de agresividad llame al 112 ole avise al menos a él para que pueda activarlo. ··· Dice que le tiene dicho que pulse el botón de teleasistencia, pero que se lo dirá también.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='VALERO'and apellido2='AGUEDO'),'2023-08-28','Maite: la semana pasada llamó Juan Antonio, director del CAM Ana Bolaños de Olivenza. Natalia , auqnue ya ha cumplido la mayoría de edad y está curatelada por nosotros, continua en el centro a la espera de plaza. Quiere que le enviemos una autorización para que él pueda gestionar lo que necesite Natalia. Me dijo que lo habiamos hecho con Juan josé Mesa Candil (busqué en el expediente y no la tenemos, se la pedí a él para ver el modelo y tampoco la ha encontrado). La urgencia era que estaba tramitando una prestación del INSS para Natalia ( prestación por hijo a cargo) y tenía que firmar. Le djie que nos la enviara para que la firme la director agerente ya que ella es la reprsentante legal. Hoy se ha firmado y la hemos enviado por registro al INSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-08-29','Ana: En relación a los 3 correos de ayer de Isabel, escribo a Paula y Beatriz, CRR, y Ana Benavente, TS ESM: "Buenos días a todas, Ayer contesté a los dos primeros correos de Isabel; en uno pedía que se le volviera a hacer transferencias a su madre para que fuera a visitarla; en el segundo pedía otro extra (además de sus asignaciones económicas periódicas y el extra anual) para hacerse un tatuaje. En ambos casos se le denegó la petición argumentando el motivo. A este tercer correo de ayer no le contesté, como sabéis, el acuerdo para que no llame y/o escriba sin control todos los días, era que las comunicaciones serían una vez a la semana, pero ella por supuesto lo intenta continuamente. Os lo reenvío porque me parece muy significativo y nos da la impresión de que los acuerdos adoptados en la subcomisión no están funcionando todo lo bien que quisiéramos. Ana ¿te importaría hacérselo llegar al Psiquiatra? No tengo su contacto. Gracias." ······················ Tercer correo de Isabel: "El día 19 fue cuando me tragué los lápices porque discutí con las monitoras y con Ceferino puedo ir al pueblo después de día 19 de septiembre no? Tiene que pasar un mes para poder ir allí lo acordado con el psiquiatra" ···································································································································· Respuesta de Paula, TO CRR: "por parte del CRR queremos comentaros que a nosotras no nos ha hecho llegar estas demandas. En las citas solemos recordar el acuerdo hecho con Isa acerca de las comunicaciones tanto con la comisión tutelar, como en relación a lo acordado en la subcomisión respecto a su cuidado y las condiciones de visita respecto a su madre (ante la nueva autolesión "empezamos a contar de cero" otra vez de cara a una nueva posible salida). Isa continúa demandando determinadas cosas a través de un sistema que en el pasado le ha funcionado, pero el cambio se producirá a través de la modificación de nuestras formas de respuesta. Ese es al menos el objetivo de canalizar las demandas y que pueda orientarlas de forma apropiada. Isa sabe que puede, con apoyo de profesionales en el CRR, planificar gastos y priorizar unos frente a otros, sabiendo que en este proceso hay que elegir opciones y descartar otras. Esto es un proceso en el que llevamos trabajando tiempo con Isa, y en el que debemos seguir haciéndolo. Espero que esto pueda aportar un poco respecto al trabajo conjunto que podemos realizar. Desde el CRR: • Seguiremos planificando acciones/gastos en un proceso de aprendizaje de Isabel de priorización y toma de decisiones. • Recordando los acuerdos alcanzados y motivando a Isabel para que pueda orientarse a los objetivos de autonomía y autocuidado. • Facilitando oportunidades para participar en diferentes actividades y experimente de manera natural obstáculos u otras situaciones en las que podamos apoyar para aprender estrategias de afrontamiento. Si os parece, le podéis recordar a Isa la canalización responder a sus demandas a la comisión tutelar un día a la semana, independientemente de que el resto de la semana siga enviando correos, puesto que el envío es incontrolable, pero no la respuesta, que es la que nosotros podemos manejar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2023-08-29','Ana: Correo de Valle, TS RR.MM. Comser, Almendralejo: "Te mando esta documentación de cuando estuvo con nosotros JOSÉ LÓPEZ RUÍZ (T1) y que ahora está en Navalmoral de la Mata. Verás los residentes que son T1, al ser plazas del SES no hay que comunicar el ingreso involuntario. Como José perdió la plaza T1, para poder gestionarle la plaza T2, si que tuve que comunicar el ingreso involuntario (no sé si sabrás que fiscalía ahora mira todo con lupa y exige que se cumpla la ley y que sea la familia la que solicite el internamiento no voluntario y no las residencias). El caso es que te mando el AUTO y la comunicación al Juzgado del traslado a Navalmoral de la Mata, para que tú la tengas." ·································· Renvío correo a Miguel, A. Jurídico, con copia a Maite, Jefa Secc. CTAEx, y Teresa: "Te reenvío correo de la TS de la anterior residencia en que estaba ingresado JOSÉ LOPEZ RUIZ. Como ves ahora se encuentra en residencia de mayores en Navalmoral de la Mata. *En la parte dispositiva de la resolución del procedimiento de internamiento, “Se ACUERDA como medida cautelar: MANTENER EL INTERNAMENTO”, pero insta al REPRESENTANTE LEGAL “a iniciar el correspondiente procedimiento de provisión de medidas de apoyo y autorización del ingreso” El viernes, que vuelve Tere, ya si necesitas algo lo vemos, porque era un caso que llevaba ella, pero por lo que veo ya lleva más de un mes en mi zona." ···································································································································································································· Respuesta de Miguel, A. Jurídico: "Buenos días Ana, si te fijas bien dice que notifican el Auto al guardador de hechos, ministerio fiscal, a nosotros… Transcurrido un año desde la actual ley 8/21 de oficio deben ser los juzgados (directamente o a través del Ministerio Fiscal los que insten dichos procedimientos de revisión de medidas de apoyo, con lo cual lo iniciará con seguridad el juzgado). En cuanto al internamiento que dice la resolución, si ya lo está entiendo que está todo en regla y por tanto no hay que hacer nada. Si tenéis cualquier duda decímelo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-08-29','Ana: correo de Puerto, TS SSASB de Valdeobispo (ssb5@mancomunidadvalledelalagon.es): "me confirman en el Ayuntamiento que ayer ingresaron a Enrique en unidad psiquiatría del Hospital Plasencia. Sinceramente, solo a su casa no debería volver, necesita un centro donde se asegure la cobertura de las necesidades básicas y el control sanitario pertinente dada su patología y comportamiento..." ·························· Otro correo de Puerto: "Buenas de nuevo, he estado hablando con Sergio, del puesto guardia civil de Montehermoso para preguntar por cómo conseguir el informe de actuación de la guardia civil que vino a Valdeobispo, me comenta que llamando al 062 me dirán qué patrulla fue la que intervino, y después se solicita por escrito el acta de actuaciones. Le he dado mi teléfono y me lo va a averiguar, cuando lo tenga te digo la patrulla que fue para solicitar informe de actuaciones... " ···················· Nuevo correo de Puerto: "Hola otra vez, ha estado la psiquiatra de Enrique en el Ayuntamiento, yo no la he podido atender, le ha entregado las llaves de la casa de Enrique al Alcalde y le ha mencionado que tiene al perrito, su mascota ... "para que las auxiliares lo atiendan" ... como comprenderás el SAD no presta ese servicio ... no sé cómo podemos hacer esto?" ··············· Conversación telefónica con Puerto: Preguntará a unas tías de Enrique, aunque no tienen apenas relación, si quieren acoger/hacerse cargo estos días del perrito. ······································ Nuevo correo de Puerto: ", amigos de la familia de Enrique me dicen que no pueden hacerse cargo del perrito... habrá que ver el tema de una protectora o perrera..." ·································· Llamo a la Protectora de animales y plantas de Plasencia (610 661 885): me dicen que Valdeobispo no les corresponde. El Ayto. debe tener un convenio con Diputación, habría que entregar una Autorización por escrito del dueño del animal al Ayto. para que puedan recoger de forma definitiva al perro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-08-29','Ana: Envío a Julio, Aux. Adtvo. CTAEx, Solicitud de Elección de Centros, firmada por la Vicepresidenta de la CTAEx, para que remita por REGISTRO a la U.G. PP.AA. - SEPAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-08-29','Ana: Envío correo a Laura, Cristina y Maite de la ONCE: "Remito adjunta la SOLICITUD DE PARTICIPACIÓN EN EL PROGRAMA DE NAVIDAD EN FAMILIA relativa a VENTURA GÓMEZ GARCÍA para este año 2023. En relación a los otros dos documentos: - Cesión de derechos de imagen – mayores de edad - Consentimiento expreso para tratamiento de datos personales Mi compañero Asesor Jurídico, me comunica, en base a las legislaciones actuales, que puede firmarlos el propio Ventura, si entiende el contenido y extensión de los mismos (consideramos que sí lo puede entender). No obstante, si lo creyerais necesario, una vez que los haya firmado Ventura, podríais enviárnoslos escaneados para que se acompañe también de la firma de la Representante Legal. No obstante, como digo, en principio no sería necesario. *Por último, dado que aún faltan algunos meses para el viaje, desde la sección económica no creen conveniente abonarlo ya, dado que nos digáis que así hay que hacerlo. Por ello, agradecerían que nos informaseis de la fecha tope para proceder al abono."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-08-29','Ana: Llamada de Julia (644 876 893): mañana tiene cita de Psiquiatría en el ESM de Coria a las 9:00 h. El único autobús de línea que hay no llega a tiempo para la cita, por lo tanto pedirán el servicio de taxi. A la vuelta regresarán en autobús. ···· Patricia, Ed. Futuex, le acompañará al a cita de mañana. ······· Solicitarán al Psiquiatra ingreso en CRR. ············· Con respecto a mis llamadas al Jdo. de Paz, dice que ya no hace falta, que el dinero que le tienen que ingresar (no sé muy bien de qué se trata) se lo ingresarán en la cuenta de su madre. Ya les han facilitado el número. ······················· Comunico a la secc. ecca. (ctutelar@) la necesidad del servicio de taxi. ························································································································· Por otra parte, Julia informa de que los Trabajos en Beneficio de la Comunidad los está haciendo en el C. Salud, como limpiadora. Comenzó ayer y finaliza el día 7 de septiembre. De momento está contenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-08-29','Ana: Llamada de Ana Benavente, TS ESM-Plas (74955): me comunica que Javier ha ingresado en UHB. Estaba muy alterado, contando que había visto en Plasencia a un chico que conoció estando en Cáceres y que le obligaba a robar. Lo describió y dijo que le había amenazado con matarle. ········· Estaba bastante descontrolado e insistía en que quería marcharse de nuevo a Cataluña. Le han recordado cómo fue la experiencia allí y le han ofrecido ingresar en UHB aceptándolo. ········· *Con respecto a lo que contó de que un gitano había dado de alta un enganche de la luz en otro domicilio, indico que no le han pasado ningún recibo. Sospechamos que tanto eses discurso como el de hoy pueda obedecer a su delirio. ······················· Pido que nos mantengan informados sobre evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-08-29','Ana: Envío 2 correos a Paula, TO CRR Plas. Uno solicitando nos envíen Certificado de Ingreso para comunicar el cambio de residencia al Jdo. ··············· el segundo: "Os reenvío correo con cita en el Equipo de Salud Mental de Plasencia el próximo día 26 de octubre relativa a DOROTEO DÍAZ CERRO. Espero que desde el centro se le pueda acompañar a la misma. Por otra parte, ¿sería posible que acudieseis con él al centro de salud para modificar el domicilio a efectos de comunicaciones, para que recibáis directamente ahí las citas, que siguen llegando al anterior centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-08-29','Ana: Conversación con Toñi, TS CAMP Don Benito (20113): el ingreso de Aarón está previsto a partir del día 12 de septiembre, pues la tanto Clemen, Directora del centro, como Montse, TS de referencia de RAE, están de vacaciones. ·················· No obstante, dado que es urgente, lo mismo intentan adelantarlo a la semana que viene. ············· Me envía documentos para poner a la firma y me solicita número de cuenta. ······································· Cumplimento y subo al portafirmas digital los documentos y pido a las compañeras de la secc. ecca. que le envíen a Toñi el nº de cuenta de Aarón. ······························ Envío a Toñi (antonia.escobare@salud-juntaex.es) el resto de documentación solicitada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-08-30','Ana: Correo de Jesús Manuel (jesusmanuelramosbargom@gmail.com) en la tarde de ayer: "Soy Jesús Manuel la vivienda donde vivo es inavitable por los continuos robos de agua luz ayanamirnto de morada y rotura de tres candados e incluso llevan un tiempo acusándome de cosas que no hago creo que el dueño aparte de eso quiere vender la vivienda. Manden una persona para que busque otra vivienda y dinero extra para poder gestionar dicho cambio y emplearlo en buscar un sitio donde pueda vivir tranquilo esperollevo siete años pidiendo otro piso y no recibo contestación las umillaciones que recibo son una pasada un mendigo mudo que viene a mantener relaciones con la de arriba son varias veces que se orina en el balcón que da a mí dormitorio espero su llamada" ······································ Mi respuesta: "Como ya se le indicó mediante conversación telefónica la semana pasada, usted puede buscar por sí mismo una vivienda de su elección y remitir a esta dirección el contrato a su nombre para que sea estudiado por los Asesores Jurídicos y la Sección Económica para que puedan valorar la viabilidad por ambas partes. La resolución judicial sobre su cargo no se lo impide. Por otra parte, como ya se le explicó, el Programa de Apoyo Comunitario, a través del cual le visitaba una Educadora, lamentablemente, y por razones ajenas a este Gabinete Técnico de la CTAEx, ha quedado en suspenso y posiblemente hasta noviembre no volverá a ponerse en marcha." ························································································································································································ Llamada de Isabel, madre de Jesús Manuel (657 947 818) dice que la vivienda en que reside su hijo se encuentra en muy malas condiciones y con mucha suciedad. Que allí no se puede vivir. Su otra hija ha estado allí y que "eso es inhumano". Le explico que ya se lo expliqué a su hijo la semana pasada por teléfono y esta mañana en la respuesta a su correo. Él puede buscar una nueva vivienda de alquiler, si quiere con la ayuda de su hermana, y enviar el contrato para su estudio por los A. Jurídicos y la secc. ecca. ········· Ella dice que no le importaría ayudarle económicamente a tal fin.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-08-30','Ana: Envío a Toñi, TS CAMP Don Benito (20113 / antonia.escobare@salud-juntaex.es): "Adjunto los siguientes documentos firmados digitalmente por la Vicepresidenta de la CTAEx: - Autorización Salidas Ocio - Autorización Salida Gestiones Ya pedí a la sección económica que enviara los datos de la cuenta. Imagino que lo harán esta misma mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-08-30','Ana: Envío correo a Puerto, TS SSASB; Maite, Jefa Secc.; y Miguel, Asesor Jurídico CTAEx: "Ayer a última hora llamé a la Protectora de animales y plantas de Plasencia (610 661 885): me dicen que Valdeobispo no les corresponde. El Ayto. debe tener un convenio con Diputación, habría que entregar una Autorización por escrito y firmada por el dueño del animal al Ayto. para que puedan recoger de forma definitiva al perro. ¿Podrías por favor preguntar al respecto? Con respecto a la firma del documento, no sé si sería suficiente con la firma de la Vicepresidenta de la CTAEx, pues se trata de una Curatela con funciones Representativas y con la legislación actual no estoy segura de que no sea necesaria la firma del propio Enrique, quien no querrá firmar. Pongo en copia a mi compañero Miguel, Asesor Jurídico, para que nos aclare esta cuestión. Y a Maite, Jefa, para que esté al corriente. Por otra parte, he pensado que tal vez, una “guardería para perros” podría ser una opción, pero no sé si las hay cerca ni si Enrique podría asumir este gasto, pues no sé cuánto supondría… (ni por cuánto tiempo, pues no sabemos hasta cuándo estará ingresado…)" ················································································ Reenvío a Miguel, A. Jurídico, correo de Puerto, TS, con CONVENIO entre Ayto. y Diputación CC: "Te reenvío correo de Puerto, TS de Valdeobispo con el convenio firmado por el Ayto. y la Diputación de Cáceres, para la recogida de peros “abandonados”. Te explico, ENRIQUE SANTOS GARCÍA PUENTE ha ingresado en la UHB, no sabemos por cuánto tiempo. Él tiene un perrito y ningún familiar/conocido quiere hacerse cargo de él. Entre otra cosas porque el animal ya ha mordido a varias personas en la localidad. Ya nos dices cuándo lo leas, pues el animal está sólo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2023-08-30','Maite: he hablado con Inma, trabajadora social del hospital de Don Benito. Rafael sigue ingresado. No hay previsión de alta, aunque se encuentra mejor. Le he dado el correo de Teresa para que envíe el informe de alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2023-08-30','Ana: Envío correo a Teresa y Maite, CTAEx: "informaros que hace unos días, recibí llamada de Eloy (650 58 74 46), padre de JUAN JOSÉ GONZÁLEZ CASARES. Vuelve a insistir que Juanjo no está a gusto en el centro de Vva. Serena, que se lo dice cada vez que va a casa y que se quiere ir a vivir más cerca de su pueblo… Que le insiste en que no quiere hacer pan, que quiere seguir estudiando. Con respecto al traslado, le expliqué que, si se confirmase que él quiere solicitarlo, pronto cumplirá un año en el centro, y por tanto, se podría solicitar. No obstante le expliqué que puede tardar mucho tiempo pues en Cáceres hay pocas plazas. Y en cuanto a los estudios, ya le dije también que se había valorado esta opción, pero que su hijo no presenta capacidad suficiente a tal fin. Para la formación básica contó con muchos apoyos desde el C. Menores y desde el propio IES, además de adaptaciones curriculares. Pero él insiste en que al menos podría intentarlo. Por último dice que Juanjo también le ha hablado de que le había propuesto cambiar a un piso de la misma asociación y que eso quizá podría motivarle mientras siga en Vva. Os lo comento por si queréis volver a hablar con el centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2023-08-29','Ana: María José, TS (serviciossociales@centrodemayoressierradesanpedro.es): me envía Informe Médico Actualizado. Guardo en el expediente digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2023-08-30','Ana: Cumplimento y subo al portafirmas digital la SOLICITUD DE DESPLAZAMIENTO DE EQUIPO MÓVIL DE LA POLICÍA NACIONAL para la renovación del DNI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-08-25','Ana: Correo de Miguel, A. Jurídico, a Maite, Ángel y a mí: "Buenos días Ceferino, ha estado llamando y envió esta mañana a ctutelar email que veréis debajo donde dice haber subido un video contra circulo rojo (creo que los ha llamado ladrones, no logro ver el video…en youtube creo que lo ha subido) Ha recibido una llamada amenazante, y el CRR me ha enviado email que veréis debajo. A él como veréis en el email ya le dije que borre ese video y no suba ninguno. He intentado sin éxito hablar con el número de móvil que dice el centro desde donde le han llamado (seguiré insistiendo…) Él dice que no es capaz de borrarlo… Si esto llega a mayores irá a juicio y allí intentaremos defenderle. Pongo en copia a Angel para cuando vuelva." ·············· Guardo el hilo de correos (Ceferino, Paula y Miguel) en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-08-28','Ana: Correo de Miguel, A. Jurídico, a Maite, Ángel y a mí: "Buenos días, tras conversación hoy con Ceferino, me confirma que borró el video de internet. También dice que va a enviarnos a Angel y a mi el enlace Word con la tercera parte de la trilogía escrita en común con Isabel Cano a la que a su vez quiere dar de alta en circulo rojo. Cuando vuelva Angel lo veré todo con él."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-08-30','Ana: Reenvío correo de Gema, Directora Residencia, a Alberto, Jefe Secc. Ecca.: "Buenas Alberto, Imagino que ya te lo habrán pasado las compañeras, porque entró también a ctutelar@, pero por si acaso. Se trata de un documento de pago por Sanción de la Agencia Tributaria e información sobre la pérdida del derecho a reducción."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2023-08-23','Ana: Correo de Icíar, CTAEx: "Estoy con el inventario de esta señora, que por lo que tengo apuntado es de tu zona. Nos han enviado informe social de Aldeanueva de la Vera diciendo que no reside allí que lo más seguro es que esté en Plasencia. El caso es que la cuenta de Unicaja ya está bloqueada y no sé cómo vive si no puede sacar dinero." ··················································································· Esta Sra. está en paradero desconocido. Ya le avisaron a Julio, CTAEx, desde el Juzgado. ············· Julio ha solicitado informe social a los SSASB de Plasencia. ··············· Tampoco se ha asignado aún TS de la CTAEx para elaborar el Plan de Intervención Inicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2023-08-23','Ana: Correo de Estrella Durán, TS CSS (estrella.duranc@salud-juntaex.es): "Ayer estuvimos el ETAC (Equipo Asertivo Comunitario), concretamente la Psiquiatra, la Enfermera y yo a ver a Alfonso Marín. Nos encontramos la misma situación de siempre, su desorden de horarios, comidas, etc, sus quejas, su malhumor y sus delirios de grandeza... Según su madre está fumando el doble ya que el dinero que le dais para este fin, no le llega para el mes, solo para 15 días. Además, también consume porros, que según él se los llevan a casa y no sabía decirnos cuántos fuma exactamente al día. Eran las 12 del mediodía y todavía no se había acostado, o sea había estado toda la noche despierto, dice que lo único que hace es fumar porque tampoco puede jugar con ordenador...por tener algún problema A su madre todavía no la han llamado para operarla de la rodilla, nos avisará cuando la citen para dicha operación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2023-08-30','Ana: Envío correo a Estrella Durán, TS CSS (estrella.duranc@salud-juntaex.es): "La verdad es que no hay prácticamente diferencia entre lo que nos informas y la información del Programa de Apoyo Comunitario gestionado por Futuex, de las últimas visitas que realizaron. La realidad es que es muy difícil la intervención con ALFONSO MARÍN DE CÁCERS, primero porque no quiere ningún tipo de control y no acepta seguimientos, y segundo por el desorden horario (la mayoría de las veces que han ido a visitarlo estaba dormido y sólo pueden hablar con la madre) y por la actitud que presenta. En mi opinión requeriría un apoyo y seguimiento diario de profesionales que trabajaran con él todo lo relacionado con unos hábitos de vida saludable, además de la reducción del consumo de sustancias tóxicas y el abordaje de otros alicientes/motivaciones en su vida. Pero como bien sabéis, además de que él no quiere ingresar en ningún recurso residencial, tampoco existe otro tipo de recurso desde el que puedan visitarle a diario y aunque en la zona en que vive existiera un centro de día al que pudiera acudir de Salud Mental (como los CRPS) tampoco lo aceptaría. Aprovecho para informarte, pues no sé si te lo he dicho ya, que además en los próximos 2 meses no contaremos tampoco con el Programa de Apoyo Comunitario, al parecer con el cambio de gobierno no ha sido posible la firma de la renovación del convenio. Con suerte, si todo va bien, se reanudará en noviembre." ···································································································································································································· Tras hablar con Isabel de Cáceres, madre de Alfonso (680 784 490), envío un correo a Alberto: "En relación a ALFONOS MARÍN DE CÁCERES, he recibido llamada de su madre Isabel (680 784 490). Solicitan un extra para poder ir de vacaciones ahora en septiembre a Leganés con familiares que residen allí. Solicitan se les haga una transferencia de igual cuantía a la asignación mensual periódica en concepto de estas vacaciones. Si es viable, por parte de la sección social, ok a este extra."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-08-23','Ana: correo de Alberto, jefe secc. ecca.: "ANA: TE VUELVO A ENVIAR EL CORREO DE FECHA 28/07/2023, X SI CONSIDERAS HABLAR CON EL CENTRO - MARÍA YA VA A ACTUAR A TRAVÉS DE LA ENTIDAD FINANCIERA ---LA INTENCIÓN ES DEVOLVER E IMPEDIR CUALQUIER TIPO DE CARGO/PAGO NO AUTORIZADO. MARÍA: OBTÉN TODA LA INFORMACIÓN POSIBLE EN RELACIÓN CON EL CORREO ANTERIOR: UNICAJA CÁCERES (TUTELADO RESIDE EN CRR CÁCERES). OBJETIVO: DEVOLVER/IMPEDIR CUALQUIER CARGO SIMILAR A LOS INDICADO. HAY UN CARGO MÁS NO INCLUIDO EN TABLA INICIAL"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-08-18','Ana: correo de Alberto, Jefe secc. ecca.: "LOURDES/ANA: ESTO ES LO QUE HA SOLICITADO CRR - PUEDE ACEPTARSE - ANA, SI TIENES ALGO QUE INDICAR...ES EL MOMENTO SE AUTORIZA REINTEGRO PERMANENTE DE 277 €/MES DISTRIBUIDOS DE LA SIGUIENTE FORMA....LOURDES: • 110 € LA 1ª SEMANA DE CADA MES. • 50 € RESTO SEMANAS DE CADA MES. SE AUTORIZA EXTRA ANUAL X 1.800 €/AÑO - DADO QUE DESDE SEPTIEMBRE 2023 QUEDAN 4 MESES PARA FINALIZAR EL AÑO, X ESTE PERÍODO LE CORRESPONDEN 600 € A ABONAR X CONCEPTO "EXTRA ANUAL". LOURDES: COMPRUEBA DURANTE UN PAR DE MESES QUE NO LE COBRAN LOS 600 €/MES DEL CENTRO QUE LE ESTABAN CARGANDO EN CUENTA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-08-30','Ana: Envío correo a Estrella Durán, TS CSS (estrella.duranc@salud-juntaex.es): "En relación a CONCHI FERNÁNDEZ MUÑOZ, quería comentarte y hacerte una consulta: Hace un par de semanas recibí llamada de Maribel Fdez. Muñoz, una de sus hermanas residentes en Trujillo (682 733 187). Decía que acuden a visitarla periódicamente cada 15/20 días desde hace 10 años al CRR, actualmente al CSS ya que está allí ingresada temporalmente. Expresan que les supone mucho gasto tener que abonar la gasolina cada vez que van a verla y solicitan, si es posible, que Conchi les ayude con unos 20-30 €/mes para sostener este gasto, pues su situación económica actual no es buena. Lo comenté con Alberto, jefe de secc. económica, pues desconocía la situación económica de Conchi, pero él me dice con bastante criterio, que deberíamos cerciorarnos con los profesionales de ambos recursos de que efectivamente se realizan estas visitas. Así mismo yo también quería saber si realmente son positivas para ella. Hablé con Paula, T.O. del CRR, la semana pasada al respecto y me decía que sí considera que las visitas que realizan las hermanas a Conchi son positivas para ella. No obstante, nos gustaría conocer también vuestra opinión profesional y además, saber si Conchi está dispuesta a facilitar ese dinero a sus hermanas a tal fin. Ya me decís cuando podáis."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-08-16','Ana: Desde la Secc. Ecca. se aprueban el gasto para las vacaciones - Viaje IMSERSO-PLENA INCLUSIÓN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2023-08-16','Ana: Corre de Alberto, Jefe Secc. Ecca.: "ANA: COSTE VIAJE 284,83 € --- EXCEPTO QUE PIDAN A ULTIMA HORA REINTEGRO PARA EL VIAJE. SITUACIÓN ECO DE ESTA PERSONA ES DIFICIL YA QUE SU ÚNICO INGRESO ES UNA PRXHCARGO DE 453,30 €/MES X 12. SALDO HOY: 9.000 €/APROX. OPINION ECO: A NIVEL ECO HAY QUE ESTAR MUY PENDIENTE YA QUE TIENE UNOS INGRESOS MUY BAJOS Y CUALQUIER GASTO DISTINO A PAGO CENTRO O DECESO, REPERCUTE MUCHO (LA VERDAD QUE ÚNICAMENTE TAXIS Y VACACIONES). SI CONSIDERAS QUE ABONEMOS LO HACEMOS, PERO EL PRIMER AÑO QUE EL SALDO COMIENCE A SER NEGATIVO---TENDRÁS QUE APRETAR AL CENTRO MARIA: SI ANA INDICA QUE ABONEMOS, PAGAMOS LAS VACACIONES----MIRA DOCUMENTO ADJUNTO. MARIA: LA ULTIMA RENDICIÓN DE IGNACIO RODRIGUEZ ALCANTARA ES DE 2020 ----- ACTUALIZAR CUANDO SE PUEDA." ··················· *Se autoriza el viaje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2023-08-30','miguel, llega email de curro en relación al procedimiento de revisión de medidas ------------------------------------------------ Lo reenvío a la parte social, económica y juridica: Buenos días, os adjunto en relación con el procedimiento de Revisión de Medidas del tutelado , remito requerimiento de abogacía general (Curro), para que le remitamos, antes del 6-9-2023 ya que la vista el el 7-9-23: Informe económico y social, que incluya ámbitos y extensión que resulten afectados por su discapacidad y necesidad de apoyo, así como cualquier consideración que estimemos conveniente sobre el mismo. Os recuerdo que esta es la Curatela donde solicitamos (si no recuerdo mal en 2022…) LA RECUPERACION DE LA CAPACIDAD del Curatelado. El Juzgado se equivocó y no hizo durante muchos meses nada alegando que pensaban que el escrito era para una rendición de cuentas anual…vamos que no comenzaron la revisión de medidas de apoyo hasta finales del año pasado, cuando nos notificaron que le citaban para que le viera el forense. Parte social y jurídica: He hablado con el Jzdo nº1 de Herrera y me confirman que el forense ya le vio, que ya estamos nombrados Defensores Judiciales y que la citación es para que el Juez lo explore o reconozca y que el mismo día será la vista motivo por el cual Curro necesitará los informes social y económico que os solicito. Voy a solicitar videoconferencia para nosotros pero ya me han avisado que posiblemente no les de tiempo a aceptarla…(en principio, en la documentación adjuntada, nada se dice que tengamos que intervenir) Parte social (Ana y Maite os pongo en copia porque Tere no está): En su día no teníamos informes médicos, y al menos hay que mandar lo más actualizado posible un informe social en el sentido de en que nos basamos para solicitar que deje de ser Curatelado. Importante: Parte social, organizad que alguien le acompañe día 7-9-2023, hora 11h, en el juzgado nº1 Herrera del Duque(no sé si sigue viviendo solo en Fuenlabrada de los Montes) Parte económica: Cualquier duda decídmelo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='CAPILLA'and apellido2='CAPITA'),'2023-08-30','Ana: Toñi Escobar, TS CAMP Ntra. Sra. Las Cruces, D.Benito (924 021 574 / antonia.escobare@salud-juntaex.es): remite Consentimiento Informado para realización de PEG, que a su vez le ha enviado desde el HDBV. ················· Adjunta Informe de Alta de Medicina Interna. Guardo en el expte. digital. ································································· Envío a Inmaculada Gil, TS HDBV (maria.gilto@salud-juntaex.es) y a Toñi, TS CAMP (antonia.escobare@salud-juntaex.es): el CI firmado por la Vicepresidenta de la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-08-30','Ana: Correo de Sara García Martín, TS Residencial Banium, Baños de Montemayor (TrabajadoraSocialBanium@hotmail.com): "Me pongo en contacto con ustedes para informar que Concepción Barbero Sánchez ha recibido una carta del SES en la mañana de hoy, en la cual la citan para que acuda mañana por la mañana a una consulta de traumatología. Les informo para que puedan prever que les enviaremos una nueva declaración jurada del servicio de acompañamiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2023-08-25','Maite: He hablado con la hija. La va a acompañar ella a la cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-08-31','Ana: Recibimos Resolución del INSS DENEGANDO la solicitud de PFHC. Causa: "NO INCAPACITADO JUDICIALMENTE". ············· Envío el documento a Maite y Ángel, CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-07-25','Ana: Recibimos INFORME SOCIAL emitido por Mª José Acosta, TS SSASB - Mancomunidad Integral Sierra de San Pedro (691 596 071 / Ayto. Cedillo: 927 59 00 29) para Inventario: Víctor Manuel tiene 62 años, padece la enfermedad de Alzehimer que afecta a la mayoría de sus capacidades cognitivas. Fue intervenido por Cáncer de Vegiga. ·········· Reside en la RR.MM. La Hermandad - Grupo Asoma, de la localidad de Cedillo, en la que ingresó por emergencia social de forma voluntaria cuando aún mantenía autonomía. ······· Tiene reconocido Grado III de Dependencia y percibe la prestación ecca. vinculada al servicio residencial. ······ No presenta capacidad de autocuidado ni puede realizar ninguna activida del día a día. ··············· Está divorciado. Tiene un hijo de 20 años que no muestra interés y no representa ninguna ayuda ni apoyo para Victor Manuel. ········· Según fuentes secundarias, "ha estado integrado en la localidad de Cedillo. Su carácer era retraído pero se mostraba sociable y afable, resaltan su bondad en el trato con los paisanos/as y su vulnerabilidad para se manipulado por otras personas" ················ Fue empleado de Iberdrola, actualmente prejubilado con unos ingresos que ascienden a 3.920€/mes. ············· Su situación ecca., así como otras cuestioens, han estado supervisadas por su abogado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-08-31','miguel, llega por fax auto denegatorio del procedimiento de ITR 1008/2023 del Jzdo nº1 de Badajoz. ********************************************** Envío email a la parte social porque lo voy a solicitar de nuevo para el jzdo Decano lo asigne al jzdo nº4: Buenos días, adjunto auto denegatorio que ha llegado por fax de Joaquina Salguero Capote. Como veréis aunque el juzgado nº4 Badajoz es el que suele conocer de asuntos de discapacidad y familia, el juzgado Decano lo asignó al Jzdo nº1 de Badajoz y éste lo ha denegado. Y aunque no es firme la resolución, para evitar perder más tiempo, y conforme las indicaciones que nos da el fallo (leedlo), procedo a solicitar de nuevo el ITR al Jzdo Decano, pidiéndole explícitamente que lo asigne al Jzdo nº4 de Badajoz. He incorporado al escrito el Auto denegatorio y la denuncia-queja que una ciudadana hizo en el registro de servicios sociales del IMSS. Maite: en el portafirmas te he dejado nuevo oficio para que lo firmes, en cuanto puedas firmalo y a partir de mañana que los juzgados volverán por septiembre a la normalidad lo enviaré vía Lexnet.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-08-31','miguel, llega el Auto no firme de 24-7-2023, se lo reenvío a la parte social y a Inés (para que pida el testimonio de firmeza)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-08-31','Ana: Tras llamada de Estrella, TS CSS (24146) y la propia Desideria, envío correo al Alberto: "En relación a DESIDERIA BARBERO BUENO, acaban de llamarme del C. Sociosantirario, ella y la TS. En sus AUTORIZACIONES DE RETIRADA DE EFECTIVO, consta que la primera vez del mes, debe ir acompañada de la Educadora de Futuex. Pero como vamos a estar al menos 2 meses sin el programa, habrá que modificar dicha autorización y enviarla de nuevo al banco. *Piden también que se le envíe el mismo documento al Sociosanitario, a la TS, Estrella: estrella.duranc@salud-juntaex.es , por si hubiera algún problema con el banco cuando acuda a retirarlo." ················································ Respuesta de Alberto: "LOURDES: MODIFICACIÓN REINTERO PERMANENTE A PARTIR DE YA Y LO REVISAMOS EN 2 MESES ----- OJO: REENVÍA TAMBIEN COPIA AUTORIZACIÓN A CSS PLASENCIA (estrella.duranc@salud-juntaex.es)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-08-31','Ana: Llamada de José Manuel (627 788 797), con las demandas habituales: comprar una TV, irse de vacaciones a algún hostal a Olivenza o a la Vera, irse a vivir a otro sitio de alquirer, que le deriven a CRR, que no le quieren en el barrio, que necesita ir a Fisioterapia porque le duelen las rodillas... ······················ Ayer estuvo en Don Benito, regresó en el autobús de las 16:30 h. ·································· *Tiene cita en el Neurólogo el día 7 de septiembre. ··············· Y el 31 de octubre un juicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-08-31','Ana: recibimos por fax AUTO DE INTERNAMIENTO, con la misma especificación para el internamiento que en la Medida Judial de apoyo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-08-31','Ana: LLamada de María Enfermera UHB HVP - Plas. (Control de Enfermería: 78582), Javier está insistiendo en querer hablar conmigo, les ha dicho que soy su tutora. Le explico que el Cargo recae en la Comisión Tutelar de Adultos y yo soy la TS. ······ Javier está de nuevo con la idea de volver a marcharse a Cataluña. ········· Me piden que llame mañana antes de las 12.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2023-08-31','Ana: Envío email a la oficina de registro (oac.merida.san@juntaex.es): "Adjunto remito la siguiente documentación para remitir por REGISTRO a la Oficina Expedición DNI - Policía Nacional Cáceres: - Oficio - Solicitud de Desplazamiento de un Equipo Móvil a la residencia de mayores en que reside firmado digitalmente por la Vicepresidenta de la Comisión Tutelar de Adultos - Informe Médico acreditativo de la imposibilidad de realizar el desplazamiento - Informe del Padrón Municipal - Decreto de Nombramiento de la Directora Gerente - Resolución de Delegación de Funciones - DNI de la Vicepresidenta de la Comisión Tutelar De Adultos En el oficio consta la dirección a la que hay que remitirlo." ······································· Respuesta de la oficina de registro: "Tenemos comunicación con la Comisaría Provincial de Cáceres, lo vamos a enviar ahí que la dirección coincide."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2023-08-31','Ana: Correo de Miguel, A. Jurídico, a Toñi, TS CAMP (20113 // antonia.escobare@salud-juntaex.es): "la fecha del juicio del día 5-9-2023 ha sido aplazada al día 12-9-23 a la 13h. Por tanto ese es el día en que hay que acompañar a Natalia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2023-08-18','Ana: Recibimos INFORME DE SEGUIMIENTO de ESM - Plas.: Fecha de la última consulta 14/08/23. ···· En el año 2023 ha retomado el contacto con el ESM, que había abandonado a mitad del 2022. ······ A la exploración se muestra inquieta, angustiada, con ideas de perjuicio sin estructurar, con aspecto algo descuidado. SIN CONCIENCIA DE ENFERMEDAD. Protesta porque no se le ha devuelto su capacidad jurídica. ····· *Ha retomado tratamiento con Olanzapina, pero persiste el estado de angustia y paranoidismo. No permite que se le incremente la dosis. ··· Acepta la toma de Alprazolam y Lormetazepam. "Parece adherida al tratamiento". La mediación la retira de la farmacia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2023-08-31','Ana: Correo-respuesta de Alberto; jefe secc. ecca.: "MARIA: LO ANTES POSIBLE, HACEMOS TRANSFERENCIA PUNTUAL X 490 €, CONCEPTO "VACACIONES", A LA CCC MADRE TUTELADO (Isabel (680 784 490)) QUE ES LA MISMA CCC A LA QUE TRANSFERIMOS LA PERMANENTE. AVISAR A MADRE X TELÉFONO"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-08-31','Ana: correo, a través del contacto "Salud Extremadura" de Beatriz Barroso Díez, hija de Mª Pilar (Email del trabajo: Beatriz.barroso@getir.com / Email personal: Bei199716@gmail.com / Telefono: +44 74 15 907 370): "Hola, Mi nombre es Beatriz Barroso Diez, soy hija de Maria del Pilar Diez Santiago. Mi madre acaba de ser internada hace un par de semanas en unos de los centros de Hernan Perez que pertenece a Mensajeros de La Paz. Yo resido en Londres, Reino Unido , y se me hace imposible poder contactar con ella regularmente por teléfono. Y su otro hijo ( Jorge Barroso Diez) esta en prison desde el pasado enero ya que agredió a mi madre. He intentado llamar a los numero que aparece en esta pagina, pero por alguna razón,desafortunadamente, no consigo que de señal. Me gustaría poder contactar con la persona que esta designada a mi madre ya que la antigua empleada me acaba de informar que ya no estará mas y necesito arreglar algunas cosas con urgencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-09-01','Ana: Tras recibir llamada de José Manuel (618 907 184), envío correo a Alberto, Jefe S. Ecca., con copia a Maite, Jefa CTAEx y Miguel, A. Jurídico: "He recibido llamada de José Manuel Romero Mediavilla. Dice que ayer le llamaron de Movistar y ha hecho un contrato de fibra óptica, nueva tarjeta de móvil, “canales de TV”, canales de fútbol y una X-BOX (que quiere cambiarla por una Televisión y se lo están mirando). Ayer mismo fueron los técnicos a su casa a las 16:30 h. Dice que ya se está angustiando porque que no sabe qué va a pasar, que qué consecuencias va a tener… finalmente ha dicho que va a llamar para intentar darlo de baja hoy mismo. No obstante, estad pendiente por si le pasan los recibos al mes que viene para devolverlo. Me planteo si no hay posibilidad de hacer un escrito y enviarlo a Movistar comunicando que este Sr. No tiene “capacidad” para formalizar con validez un contrato de estas características. Pongo en copia a Miguel a este respecto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-09-01','Ana: Envío correo a Beatriz, hija de Pilar (email del trabajo: Beatriz.barroso@getir.com Email personal: Bei199716@gmail.com): "Encantada. Mi nombre es Ana, soy Trabajadora Social del Gabinete Técnico de la Comisión Tutelar de Adultos de Extremadura y llevo la zona en la que reside tu madre. El problema de no poder contactar por teléfono es que llamas desde fuera de España, no es la primera vez que nos pasa. Al parecer los teléfonos de la Junta de Extremadura (o al menos del SEPAD) no están habilitados ni para realizar ni para recibir llamadas desde el Extranjero. Yo podría solicitar que de forma excepcional me habilitaran un día y una franja horaria concreta para recibir llamadas, pero supondría tener que acordar nosotras previamente y con antelación que día y horario sería. Si crees que las cuestiones podemos abordarlas por este medio estupendo, sino intentamos la opción que te digo. Cuando dices “Me gustaría poder contactar con la persona que esta designada a mi madre ya que la antigua empleada me acaba de informar que ya no estará”, imagino que te refieres a la Educadora del Programa de Apoyo Comunitario conveniado con la Junta de Extremadura y gestionado por Futuex. Este convenio finalizó justo ayer y debía haberse prorrogado desde hoy mismo. No obstante, según nos han informado, debido al cambio de Gobierno no ha sido posible firmar dicha renovación y hasta noviembre no volverá a entrar en funcionamiento. Por lo que no contaremos con el apoyo de estas educadoras (o las que contraten en su lugar) hasta entonces. Si quieres puedes comunicarnos esas cuestiones que necesitas arreglar con urgencia, que supongo tendrá que ver con tu madre, y vemos qué se puede hacer. Pongo en copia a la Jefa de Sección de la CTAEx por si finalmente hubiera que habilitar las llamadas, para que esté al corriente, pues le competería iniciar la petición."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-09-01','Ana: Tras leer correo de Sonia, ASINDI, escribo a Pilar Martín, TS ESM CC (pilar.martinp@salud-juntaex.es) y Estrella Durán, TS de CSS-Plas. (estrella.duranc@salud-juntaex.es): "Me remiten desde ASINDI, esta citación en el Servicio de Psiquiatría del Equipo de Salud Mental de Cáceres para el día 22 de septiembre. Yo entiendo que esta cita habrá que anularla, puesto que Aarón, al alta de la UHDAC ingresará en el CAMP de Don Benito. Entiendo que una vez allí, le asignarán Médico de Atención Primaria y solicitarán cita en el ESM de allí también. *O no sé, si es posible, pues creo que en alguna otra ocasión se ha hecho, se le haga desde el Sociosanitario derivación directa al Equipo nuevo correspondiente. Por ello os pongo en copia a las dos, que conoceréis mejor que yo estos trámites. Ya me decís."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-09-01','Ana: correo de Guadalupe Cortés, TS SAD - IMAS (guadalupe.cortes@ayto-caceres.es): "Buenos días Ana Me comunica Julia Durán, Trabajadora Social del Hogar de Mayores "Peña del Cura", que desde la Comisión Tutelar se ha contratado un servicio de catering privado para Ventura Gómez García y que comenzará a recibirlo el día 5/09/2023. No se si el catering se ocupará de comidas y cenas y, en definitiva, como puede afectar a la prestación del Servicio de Ayuda a Domicilio que prestamos a Ventura (6 horas semanales distribuidas en 3 días/2 horas). Por favor, decidme cómo proceder. Quizás fuera oportuno espera un tiempo para ver la adaptación. Muchas gracias. En otro orden de cosas comentaros que el día 8/8/2023 se le instaló a Ventura el Servicio de Teleasistencia del IMAS." ·································································································································································································· Mi respuesta: "Pues a ti no te puse en copia cuando escribí a las compañeras para informar porque, sinceramente no pensaba que fuera a afectar. Como le denegaron el catering municipal (que yo desconocía el criterio de ingresos económicos, muy lógico por otra parte y me parece perfecto) se le buscó una privado. El cáterin es sólo para comidas (primer plato, segundo, postre y pan) en principio no incluye las cenas, pero según me dicen, como la cantidad es buena, hay personas que también les llega para la cena, no sé si será el caso, porque tampoco sé la cantidad que come Ventura. La comida se la entregan un día a la semana, los martes, va preparada (envases termosellados) para que se conserve bien en la nevera. No entiendo bien a qué te refieres en que pueda afectar o que haya que esperar un tiempo para ver la adaptación. Si lo consideras lo hablamos. *En cuanto al Teleasistencia, perfecto, gracias por infamar. Las veces que he hablado con él no me ha dicho nada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-09-01','Ana: Llamada de Francisco, ha hablado con el Psicólogo porque quiere ver a su hija, aunque sea de forma supervisada en punto de encuentro. Le ha dicho que tendrán que valoarlo el Psiquiatra y en caso de que su hija quiera y lo varloren también positivo para ella. ··*Lleva 7 años sin verla y expresa sufrir mucho por ello. ············· También necestiará informe postivo del ECA. ················· Él, a parte de la manutención, dice que le pasa un dinero de un piso que tienen él y su madre alquilado (de su padre fallecido) y le dan de ahí tamibíen dinero a su hija. ···································· **Mientras no le dejen verla no quiere que se dé más dinero a su prima para libros ni ninguna otra cuestión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-09-01','-Amalia : llamo por tf a la RM la Granadilla para informar de la situación , el jgdo. no admite el Intern. Involuntario. Pido tf de ella o familiares para contactar con ellos e intentar que colaboran para que ingrese voluntariamente . Tf de su prima Carmen 924259391 Tf de su sobrina Agustina 653335156 Datos de su hijo Jonathan Pozo Salguero ,617066661-644849848. tiene 3 hijos vive en la Bda. A. Dominguez de Badajoz en C/ La Jara , 10. Su pareja es Luis Hdez. Valero . Tiene 2 protesis , y 78 años. No responden a las llamadas realizadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-09-01','Amalia : contacto con el TS de la Morera. Antonia ha demandado Aprosuba de Zafra , voy a gestionarlo. Nombre: JUAN CARLOS Apellidos: GALLARDO BECERRA Asunto: INFORMACIÓN SOBRE PERSONA TUTELADA Mensaje: Soy trabajador social en la Mancomunidad Río Bodión y recientemente se ha empadronado una persona con discapacidad junto al resto de su familia en La Morera. No me facilitan documentos pero por algún contacto, creo que pudiera estar tutelada por la Comisión Tutelar de Adultos. Le indico los datos por si fuera así, ya que es necesario exponer su situación actual: Antonia Pérez Pérez (08836273H) Correo Electrónico y/o Teléfono de Contacto: carlosgallabece@gmail.com y telefóno 662376496','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-09-04','Amalia : consigo localizar el tf de su hijo y lo llamo por tf. Me dice que no tiene contacto con la madre , lo abandonó con 3 años y lo crió un tio suyo. Le doy informacion de cómo se encuentra su madre y queda en ir a verla . Le he pedido que intente hablar con ella para que acuda a la R.M o a un hostal .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-09-04','-Amalia : el hijo ha hablado con Joaquina , ella quiere ingresar ya en R.M. Luis , su pareja , no quiere y se queda en la calle. LLamo a Radio taxi y solicito taxi adaptado . Contacto con el Dtor. de la R.M. Virgen de Guadalupe para indicarle que va para allá y que tendrá que abonar el transporte en métalico y la CTAEX le hará un reintegro inmediato . El hijo me cuenta que su madre le ha dicho que le han robado el dinero , el movil , los anillos... Que Luis ha pasado la noche en el hospital pq se había caido. Que consume alcohol . Le explico al Dtor de la R.M. que ingresa voluntariamente y que si decide irse de nuevo no se le puede retener.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-09-04','Buenos días Amalia. Te paso la dirección actual de Antonia y su unidad de convivencia según el padrón municipal: Antonia está empadronada en la C/ Hernán Cortés, 20 de La Morera (06176). Convive con: - Fernanda (79 años) . madre - Pedro (48 años) - hermano - Domingo (37 años) - hermano. El teléfono de contacto que me han facilitado es el de Pedro: 640831790. En los próximos días intentaré hacer una visita domiciliaria y ya te contaré lo que observe. Quedo a la espera de tus gestiones con Aprosuba Zafra y con Futuex cuando se inicie el convenio. Saludos. (662376496)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2023-09-04','TERESA SOLICITO INFORME SOCIAL A PETICION DE MIGUEL PARA REVISON DE MEDIDAS ANTTE LA SITUACION ACTUAL EN LA QUE SE ENCUENTRA POR EL DETERIORO COGNITIVO QUE SUFRE TRAL EL HALTA HOSPITALARIA ARCHIVO INFORME DE ALTA DEL HOSPITAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2023-09-04','TERESA COMIENZA LAS PRACTICA DEL CURSO DE INFORMATICA QUE HA HECHO DURANTE EL MES DE SEPTBRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-09-05','miguel, no enviamos desde la parte jurídica vía lexnet el 2º intento de internamiento involuntario (al jzdo Decano para que el Jzdo nº4 Badajoz conozca del caso) porque ayer ingresó en el Centro de Olivenza','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-09-05','-Amalia : escribo al Dtor de la R.M. Buenos días , adjunto toda la documentación de Joaquina S.C. que tenemos en su expediente . Cómo ha pasado la noche ? en qué condiciones se encuentra ? supongo que tendrá que verla un médico. Para cuadrar el tema económico , os paso Cdo. de Orfandad con cuantía exacta para que calculéis el copago de la plaza . Cómo lo hacéis desde esa residencia , lo cargáis directamente a su Nº cuenta ? si es así os paso su Nº al final del escrito . En la R. M. de la Granadilla se le entregaban 100 € al mes de gastos de bolsillo que iba a retirar con su pareja , ambos se fueron de la residencia , él se llama Luis Hernández Valero.No acepta el ingreso en residencia y sigue viviendo en la calle . Al estar en silla de ruedas indicadme cómo se le puede dar ese dinero , podemos hacer reintegro como hemos hecho con la factura del taxi o que le carguéis en su cuenta los gastos. Igualmente para podologia, peluquería ... lo cargáis directamente en cuenta ? ES31 2085 4511 960332538410 IBERCAJA OLIVENZA . Os paso tf. de familiares de Joaquina , su hijo Jonathan es el que ha podido hablar con ella para que ingresase en la residencia. Tf de su prima Carmen 924259391 Tf de su sobrina Agustina 653335156 Datos de su hijo Jonathan Pozo Salguero ,617066661-644849848. tiene 3 hijos vive en la Bda. A. Dominguez de Badajoz en C/ La Jara , 50.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-09-05','-Amalia : escribo al SSASB del IMSS de Badajoz para comunicar el ingreso . Buenos días , ayer tras conseguir localizar a su hijo y comentarle la situación en la que se encontraba su madre, fue a verla al parque de San Fco. donde se encontraba y ella aceptó de forma voluntaria ingresar en la plaza de la R.M. de Olivenza que tenía asignada. Estaba en un estado deplorable , sin apenas comer , le han robado las pocas pertenencias que llevaba ,entre ellas el móvil , y su pareja estaba fuera . Al parecer hay noches en las que la dejaba allí sola , justo la noche anterior la había pasado en el hospital por una caída sufrida por estado de embriaguez. Gestioné el traslado y ayer quedó ingresada en la residencia . Su pareja , Luis Hernández Valero de 78 años y que igual que ella abandonó voluntariamente la plaza en la R.M. La Granadilla , quiere seguir viviendo en la calle y no acepta incorporarse a la plaza que tiene asignada en Don Benito . Este señor no tiene medidas de apoyo judiciales. Muchas gracias por vuestra colaboración con este caso. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-09-05','-Amalia : comunico a May el ingreso : Buenos días , Joaquina ingresó ayer día 4 / 09/23 en la R.M. Virgen de Guadalupe de Olivenza de manera voluntaria . Su pareja , Luis Hernández Valero se niega a ingresar en la plaza de Don Benito . No tiene medidas judiciales de apoyo. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-09-05','-Pido al Dtor R.M. cdo de ingreso para dar a Miguel para comunicarlo al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2023-09-05','CRR mERIDA : Informarles sobre la situación de Almudena Correyero. Desde el viernes pasado, está teniendo encuentros con su ex novio Miguel Ángel, con quien ha mantenido relación y convivencia en su domicilio de Don Benito, según información que precede de informes y profesionales del anterior recurso. Este hombre cuenta con antecedentes legales. Se ha encontrado con Almudena por la zona del CRR y a raíz de las salidas con él, no ha estado viniendo a comer ni realizar tomas medicación, en horas pautadas. Esta mañana hablamos con ella, nos ha confirmado que es su ex novio, que en el año 2013 se ha ido con él, estando en el Hospital Sociosanitario y que desde entonces no había vuelto a tener contacto. La intervención se ha basado en trasladarle nuestro apoyo, denotando que la decisión que tome, será informada a su representante legal. Se ha sincerado, comentó que el hombre la invitó a pasar la tarde del viernes en un hostal y han mantenido relaciones. Expresa la idea de irse con él, al menos un fin de semana. Hoy nos ha comentado que iban a comer juntos, ya que él se volvía a Don Benito a las 17 hs, por lo que acordamos que salga a la comida pero que a las 17 horas regrese al Centro. Se ha ido antes de lo previsto, sin tomar medicación y ha llamado hace diez minutos, agitada y el hombre le ha cogido el teléfono para hablar con la profesional que recibió la llamada. ----------------------------------- Amalia : informo que es el mismo novio que el de Emi Morales.Solicito a los asesores jurdicos opinión para impedir que acuda al CRR .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-09-06','-Amalia : Hablo con Maribel, tengo que enviarle a ella renuncia de la plaza de CO en Ap3 . Por decreto solicitar CO Zafra , no tiene dependecia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-09-06','TERESA Buenos días compañeras!! Aitor ha recibido la citación para el forense, es el próximo martes día 12 a las 12:30h. Le acompañaremos nosotras a la cita. También le han mandado la cita para ir al ECA pero no sabía cuándo, mañana le voy a acompañar al médico de atención primaria porque le dan el resultado de unas analíticas y veré la carta. Seguimos en contacto! Buena mañana!!!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-09-06','Ángel: Se celebra el juicio por delitos leves, procedimiento 105/22, en el Juzgado de Primera Instancia e Instrucción, nº 5, de Plasencia. Adrián ha reconocido la agresión. Le absuelven por su incapacitación y le condenan a medida de seguridad para recibir tratamiento médico durante 2 meses y a pagar al otro 38 euros, por los 5 días que tardó en sanar la agresión leve.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='PARRA'and apellido2='DOMINGUEZ'),'2023-09-06','CIERRE DE EXPTE. Se recibe DIOR, de 05/09/2023, por la que se declara la firmeza del Auto n.º 123/23, de 16 de junio, mediante el que decae la curatela provisional que la CTAEx venía ejerciendo y se nombra curador a D. José Emilio Parra Díaz. Se procede a cerrar el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2023-09-06','TERESA Buenas tardes Teresa, he intentado contactar vía telefónica con usted, pero no se si se encuentra trabajando o está de vacaciones. Le comento por aquí los hechos que vienen aconteciendo en el centro residencial de Medina de las Torres donde se encuentra José González Fernández. Desde hace un par de semanas este residente muestra inquietud y nerviosismo que le ha impedido dormir con normalidad, según refiere motivado a un estado de intranquilidad porque sus hermanos querían vender la casa que él tiene en Monesterio. Los primeros días dormía mal y pasaba gran parte de la noche despierto, pero conforme han ido pasando los días este comportamiento se ha ido agravando alterando el funcionamiento del centro. Concretamente el residente sale de su habitación durante la madrugada en ropa interior y deambula por todas las instalaciones, sin respetar silencio, incluso entrando en las habitaciones de otros residentes, motivo por el cual muchos me trasladan su queja porque no pueden descansar como lo hacían de forma habitual. Además sale al exterior del centro (zona de porche y jardín) y se pone a llamar a voces a la gente que pasa por la calle para pedirles tabaco y a regar las zonas exteriores llegando el agua hasta la carretera, todo ello a horas de la noche/madrugada y en ropa interior. Por otra parte no respeta las zonas destinadas a personal del centro y entra y sale a su antojo para poner cosas personales en las diferentes instalaciones como cámaras de alimentos, almacenes, lavandería, así como a la cocina para coger cuchillos y utilizarlos, según dice cuando se le ve salir, para cortar alguna cosa... En varias ocasiones se le ha visto fumar dentro de las instalaciones del centro, por los pasillos y en los baños. Ha llegado a coger a otros usuarios dependientes que se trasladan en silla de ruedas y que tienen un deterioro cognitivo avanzado, con intención de llevarlos fuera del centro supuestamente a darles un paseo. Su actitud y comportamiento actual es inadecuado, muy alterado, muy excitado, muy agitado, queriendo hacer cosas continuamente. Por todo ello se ha estado revisando la toma de la medicación pautada y además se habló con su médico de atención primaria para que le prescribiera algo más que pudiera tenerlo más tranquilo. Todo esto no ha tenido efecto y el comportamiento va agravandose con los días, haciendo caso omiso a lo que se le dice en cuanto a las normas de comportamiento en el centro, y en ocasiones alternándose y enfadandose con el personal que le llama la atención cuando realiza algunos de estos actos mencionados. Por todo ello veo la necesidad de ponerlo en su conocimiento ya que todo esto está alterando el buen funcionamiento del centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='RIVERA'and apellido2='RAMOS'),'2023-09-06','-Amalia : escribo a S. eco : hay que cambiar la transferencia que se le hace a su hija de 600€ al mes a su hermano Joaquín Rivera por la misma cantidad a partir del mes de inicio de Octubre. Joaquín , con el que me he reunido hoy , traía dos carticas de la Caixa. En una está con su hermano José y en otra está él solo. Os lo he escaneado y guardado en la carpeta económica de su expediente. Creo que la mejor opción es la cuenta en la que él está solo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='ESTEVEZ'and apellido2='RODRIGUEZ'),'2023-09-06','-Amalia : hablo con Begoña , J.PFHC para solicitar los meses de junio y julio que le deben , agosto sí ha entrado y los atrasos de 13000€ era hasta mayo . Lo soluciona sobre la marcha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='RIVERA'and apellido2='RAMOS'),'2023-09-06','TF DE JOAQUIN 698922767 . LLamarle para decirle a partir de qué dia puede ir a por el dinero . Vive con su hno. y los nietos de éste .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2023-09-06','Antes de nada, me presento. Soy Fernando, nuevo psicólogo del CRR de Mérida después de la marcha de Ana. Os informamos, después de que Javier Pecero os haya comunicado que Miguel Ángel (con quien se está viendo Almudena) se ha marchado, que sigue estando presente de manera irregular y quedando con Almudena. Almudena sigue en el CRR y, aunque manifieste ideas de marcharse, se le comunica que siga con su proceso de recuperación y mantiene buena actitud. Un saludo, Fernando Barrios López','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2023-09-07','Amalia Diaz Gonzalez hofacoordinacion@gmail.com Buenos días , recibida comunicación de la Dtra. del CEE Los Ángeles que se añade a la de HOFA considerando positiva la salida. Esta salida se encuadra en la autorización general que ya tenéis . Gracias por la comunicación , esperemos que la disfrute . Un saludo. HOFA coordinacion >hofacoordinacion@gmail.com> Amalia Diaz Gonzalez REGINA REINA LARA, acogida en el recurso sito en C/ Rota 41 de Badajoz y gestionado por Asociación HOFA, disfrutará de permiso en C/ REYES CATÓLICOS 1A VALVERDE DE LEGANES (Badajoz) del 7 al 10 de septiembre de 2023 con Dª MARIA DEL CARMEN GONZÁLEZ CORDERAS DNI 80052778 J quien será responsable de la misma durante este periodo, por considerarse beneficioso para su evolución. Email de HOFA: Buenos días, Amalia. Tal y como hablamos, Regina va a pasar este puente con la familia de un compañero de residencia. Hemos recabado información de la directora de Los Ángeles y hemos tenido una entrevista con ellos y consideramos que va a ser muy positiva para Regina. Saludos. ---------------------------------------------- Buenos días , recibida comunicación de la Dtra. del CEE Los Ángeles que se añade a la de HOFA considerando positiva la salida. Esta salida se encuadra en la autorización general que ya tenéis . Gracias por la comunicación , esperemos que la disfrute . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-09-07','TERESA Hace aproximadamente un año Aitor fue contratado por una empresa de transporte escolar para hacer el acompañamiento de los niños en la ruta escolar En cuanto tuvimos conocimiento nos pusimos en contacto con la empresa para comunicarles que Aitor no reúne un perfil idóneo para llevar a cabo este trabajo. Ángel envió a la empresa todo lo que nos pidieron para anular ese contrato y que le dieran de baja. Pues bien, me llama una tal Sonia que trabaja en esta empresa para comunicarme que no sabe el motivo por el cual no se le ha dado de baja a Aitor y ha estado cobrando todos estos meses la nómina. Que el departamento laboral esta ya gestionado todo para la baja y que nos van a pedir la devolución de las nominas ingresadas en una cuenta de la entidad ABANCA. Quedan a nuestra disposición para lo que necesitemos…. Como veis esto es ya rizar el rizo¡¡¡ El contacto de la empresa es Sonia Pizarro 671670168 soniapizarro@externaservicios.net Quedo a la espera de lo que me indiques desde ambas áreas porque yo no se ya ni que hacer con este caso…. Buena mañana¡','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2023-09-07','TF ALMUDENA 613375511 TF ANTONIO 622442705','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-09-07','eMAIL DE SU HNA. Me ha comentado mi padre que necesitas unos documentos judiciales de Alberto. Te envío el número de teléfono de su abogado, él te puede dar toda la información. Se llama Jose Antonio Romero Porro. Teléfono 924 24 23 04 Se lo paso a Miguel para que obtenga la informacion .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-09-07','miguel, tras conversación on el aogado Jorge Calvo 644340448 (me indica que tenemos abiertos dos asuntos:) 1.-Hacer nueva ejecución del laudo arbitral que se dicto 21-9-22 (para lo cual hablo con Cristina la procuradora, tlfno 660-404923) quien me confirma que hacer "Poder Apud Acta de solicitud al jzdo de 1º instancia nº7 Badajzo, con rgtro de reparto 1340/2023, estando pendiente de asignación de nº de procedimiento) Hablo con Marta de Gerencia y queda en llamarme el lunes para darme día y hora para que Estrella la Gerente me acompañe al jzdo al poder. 2.-La contra parte va a solicitar la ejecución que se perdió y ello conlleva que no nos aceptarán la compensación (respecto a lo que se debe y portanto habría que abonar sin posibilidad de recuperar ese dinero por insolvencia de los inquilinos). Jorge propone que les demos Orden de retirada del asunto para que así tarde más el jzdo en notificar a la tutelada y así ganar tiempo en el procedimiento paralelo de solicitud de ejecución que va a solicitar nuevo. De esa forma cuando el jzdo nos comunique de ese pago, nos opongamos desde la Ctaex solicitando al jzdo que pidan un abogado de oficio (es una teoría jurídica pero que en la práctica no es seguro que la juez la estimase y la tutelada acabe pagando igualmente)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-09-07','miguel, email de Jose Antonio Porro (abogado) Como ya os indiqué, redacté la solicitud de indulto que fue presentada en el Ministerio de Justicia encabezada por su padre, estrategia que se consideró la más oportuna y que se acompañó de una carta dirigida por el padre a la Casa Real soliciitando a la Reina que se interesara por ayudar a Alberto. Con carácter inmediato, presenté una solicitud ante el Juzgado de lo Penal interesando que se acordara la suspensión de la ejecución de la pena impuesta hasta que se resolviera el expediente de indulto que ya se estaba tramitando. De hecho, el Fiscal Jefe de la Audiencia Provincial emitió un informe a petición del Ministerio de Justicia apoyando la solicitud de indulto por las excepcionales causas de justicia y equidad concurrentes. Pero hete aquí que el último día de julio nos notifican un Auto por el que la juez desestima la petición de suspensión de la ejecución de la pena y ordena el ingreso en prisión. Encontrándome yo en Estados Unidos me llama el padre de Alberto y me dice que su hijo ha tomado la decisión de ingresar en prisión, porque no está bien y porque le ha dicho que quiere acabar con todo. Yo le hago ver que el Auto es recurrible y que yo lo voy a recurrir, existiendo argumentos lógico jurídicos contundentes. Le hago ver además que primero lo recurriré en Reforma, lo que nos daría al menos un par de meses o tres de margen, y que de ser desestimada la Reforma recurriría en Apelación, lo que nos darí otro margen de un par de meses. Aun estando en las montañas rocosas en Estados Unidos interpongo el recurso, pero unos días después el padre me comunica que su hijo no le ha hecho ni puñetero caso y que se ha presentado voluntariamente en prisión para cumplir la pena. Te adjunto escrito de indulto, solicitud de suspensión de la ejecución de la pena de prisión y recurso contra el Auto que acordaba el ingreso en prisión que presenté el 10 de agosto. En el encabezamiento de la solicitud de indulto se expresa el tiempo de la condena y el número de procedimiento. Si no me equivoco, son 18 meses de prisión. Como verás, el recurso lo formulé el 10 de agosto. Muy probablemente, el indulto, que sigue su curso, se resolverá antes de que Alberto cumpla la condena que, voluntariamente, ha decidido empezar a cumplir. Si necesitas más información, estoy a vuestra entera disposición. ---------------------------------------------------- Envío email al abogado Jose A. Porro: Buenas tardes José Antonio, la hermana de Alberto ha remitido a mi compañera trabajadora social a ti para que nos remitas la resolución que indica procedimiento, motivo, condena, tiempo de la misma, ya que su hermana Anuski le ha confirmado que ya ha entrado en centro penitenciario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-09-11','-Amalia , pongo en firma la renuncia de CO. Ella voluntariamente quiere pedir plaza CO . En agosto se pidió internamiento involuntaro de ingreso en centro . El juzgado ha solicitado nueva dirección.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCO ANTONIO'and edp.apellido1='BENITEZ'and apellido2='PIN'),'2023-08-08','TERESA MARCO ANTONIO ES PERCEPTOR DE UNA ORFANDAD SIMPLE. SE GENERO COBRO INDEBIDO POR EL COMPLEMENTO A MININIMOSPOR AL SUPERAR EL NIVEL DE RENTAS DERIVADAS DEL TRABAJO SE SOLICITA PENSION DE ORFANDAD ABSOLUTA YA QUE HA FALLECIDOSU MADRE Y VALOREN SI LE PERTENCEE EN FUNCION A LOS INGRESOS QUE PERCIBE DERIVADOS DE SU TRABAJO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-09-11','-Amalia . Llama su expareja , Victor Alambra 625683454, victoralhambra@hotmail.com . Es de Ciudad Real , estuvieron juntos 4 años . Aportó dinero para reformar la casa cuando estuvo con él . Trabaja en el aeropuerto de Málaga , donde se conocieron. LLama para contar como fué su relación con él . Le ayudó en buscar especialistas en su patología mental. Traslada los deseos de Damián. Su deseo es ser independiente y vivir autónomo .Quiere vender la casa de Málaga y comprar en Mérida. En Málaga lo pasó muy mal y no le conviene volver allí . Estuvo con gente que metió en su casa muy conflictiva con los que no le conviene volver a tener relación. Siguen siendo amigos y es un apoyo para él . Anoto su TF , se le puede llamar . Está interesado en comprar el piso de Damián . Lo llamaré para darle información sobre la venta. Le interesa aunque sea en mal estado pq él lo rehabilitaría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-09-11','-Amalia , escribo a Miguel : Buenas , me ha llamado la expareja de Damián , el chico es muy educado y bastante sensato. Finalmente Damián decidió vender su piso de Málaga para comprar aquí en Mérida . Se ha solicitado autorización judicial ? es necesario ? Este chico estaría interesado en comprar el piso , sabe de su estado por la prima y él lo rehabilitaría . Cuando se le ponga precio se le puede llamar como posible comprador. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-09-11','MIGUEL : Buenos días como sabréis Alberto Ramos ya ha entrado en prisión para cumplir condena hace un mes aproximadamente. La condena es de 18 meses por la sentencia nº 167/2011 de 29-5-2012, jzdo de lo penal nº1 de Badajoz (Ejecutoria 443/12 de dicho jzdo). Amalia supongo que tendrás que poner en marcha la cuenta peculio e informar a la trabadora social del centro penitenciario para tome el tratamiento médico que requiera. Pongo en copia a Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-09-11','Amalia : hablo con Cristina , TS del C.penitenciario. Está en el Modulo 3 ( terapeutico ) Ya gestionado cta. peculio. me enviará precio del TV y como abonarlo. Ya lo han visitado el padre y la hna.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-09-11','Datos abogado Josefa Moya: Pedro Manuel Athané Cantón Abogado y Asesor Fiscal Avda. Antonio Chacón, 19 A 06300 Zafra (Badajoz) Tfno: 924 55 11 77 Fax: 924 55 27 56 Móvil: 637 430 192 Dirección Email: pac@multigestionempresarial.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-09-11','CATI , APROSUBA 3 : Varios contactos telefónicos de profesionales y compañeros y en todos Antonia Perez y su madre dicen que están ya en el pueblo y que no van a volver a Badajoz. Comentan que ya tiene médico de cabecera en el pueblo, que Antonia se ha caído de la escalera y ha roto el pie en dos sitios, que un tal t social Juan Carlos va a llamar a Sara (de centro ocupacional de Aprosuba 3 P. I. Badajoz) para que Antonia vaya a Zafra al centro ocupacional. Enviamos a c tutelar el documento de baja voluntaria, para que lo podamos enviar al sepad y así dar de baja en los listados de nuestra entidad. Con los cambios de la ley, no sé muy bien como poner….he puesto representante legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2023-09-11','Amalia : llamo a Almudena para hablar de su situación actual TF ALMUDENA 613375511 TF ANTONIO , PADRE DE ALMUDENA 622442705','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='SANCHEZ'and apellido2='MORENO'),'2023-09-11','Amalia , la familia ha vuelto a cargar a la cuenta de la hermana varios recibos. Contesto a Alberto : esta familia es tremenda , ya el juzgado les revocó el cargo de tutor al hermano por estar cargando a la cuenta de la tutelada sus propios gastos pero no cesa . Siga cargando gastos que no son de la tutelada , a pesar de que ya se les informó que se daría de baja a todos ellos y que no podían volver a cargarlos. Además , han acudido en varias ocasiones solicitando al SSASB del Ayto. de Badajoz, que les demos más dinero para manutención porque todo ha subido. No se le ha aceptado tal petición . Lo que sí tenemos que abonar : manutención ( se le envían 310 € para comida y gastos de limpieza e higiene de la casa ) , suministros de su vivienda : agua , luz , seguro de esa casa . Todo lo demás que veo en este email habría que devolverlo. El embargo sí se estaba abonando , copio lo acordado en la ultima reunión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-09-11','TERESA Marta ha asistido todos los días al centro desde que los usuarios han retomado la actividad, pero su madre nos comenta que continua llegando tarde por las noches a pesar de tener que venir al día siguiente. Te voy contando más a lo largo de la semana, ya que también se retoman las sesiones de habilitación funcional. Hoy he llamado a salud mental. Ya tiene la cita reprogramada en psiquiatría, es el 20 de octubre a las 11:00h. Estamos en contacto,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-09-11','Amalia : ingresó en la residencia tras hablar con su hijo . Ya he comunicado a todos los implicados el ingreso .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-09-04','Ana: Reenvío a Miguel, A. Jurídico, el Informe de Evolución que me remiten desde el CRR - CC. ·············· En el mismo expresan: "...Sigue teniendo gran dificultad en el manejo del dinero", "Pasa gran parte de su tiempo fuera del centro, sin embargo sus actividades no se encaminan a un ocio programado y de disfrte, sino a deambular por la ciudad en solitario", No asiste de forma regular al Programa de Apoyo Sostenido del CRPS, ni es constante en los compromisos adquiridos, "las relaciones sociales en el mismo son prácticamente inexistentes", "requiere supervisión para mantener una constancia en la higiene personal y cuidado de la ropa", "tiende a la acumulación de objetos innecesarios e incluso no permitidos en su habitación", "necesita apoyo para la reducción del consumo de bebidas energéticas, mantenimiento de una dieta adecuada y la creación de una rutina básica de cuidados", requiere intervención para "la creación de hábitos de vida saludables que permitan una mayor autonomía, ya que muestra una eficacia aparente que constrasta con la eficacia real", presenta la idea recurrente de "necesidad de salir del centro, sin que luego tenga la capacidad de seguir los planes y objetivos acordados"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-09-12','miguel, envío a Alicia la prima email: aliciaasimas@gmail.com Buenos días Alicia, para la venta del inmueble de Damian necesitamos que nos indiques un par de presupuestos de tasadoras a efectos de que tasen la vivienda para poder solicitar la autorización de venta. ***************************************************** Contesto a Damian, a la pregunta de cómo van los trámites para la venta de la vivienda: Buenos días Damian, nos hemos puesto en contacto con su prima porque necesitamos que la vivienda sea tasada. Una vez sea tasada se podrá solicitar al juzgado la autorización de venta. Estos trámites llevarán un tiempo, desconocemos cuanto pues depende de lo que tarde el juzgado en resolver. Me comunican que Victor Alhambra, expareja de Damian está interesado en comprarla. Todavía no he hablado con él y lógicamente el precio por el que se adjudicará deberá ser superior a la tasación que se haga. Entiendo que Damian no tendrá nada en contra de que sea Victor quien la compre, si ofrece más de lo que se tase. Quedo a la espera que o bien me facilites dos presupuestos o bien me indiques dos tasadoras de allí. Si lo prefieres las busco online. *******************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-09-07','miguel, email de Damian: Hola señor Miguel quería preguntarle cómo va el tema de mi piso.porque yo no veo al director.el director está muy ocupado.gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2023-09-12','miguel, recibo email del abogado Francisco Garrote Delgado (pablogarrotedelgado@icaba.com): Buenos días, Les di tu contacto a la notaría porque no se ponían de acuerdo de cómo lo iban hacer para llamaros. No se si lo han hecho y si tenemos noticia porque llevo bastante tiempo detrás de la notaría de aquí y movían nada. Llevo unos meses detrás de ellos, pero la notaria que está actualmente no está mucho tiempo en la notaría y parece que pasa de los temas, por eso nose si se han puesto en contacto ya con vosotros o no. Por otro lado, el procurador me ha mandado la minuta correspondiente al procedimiento de la autorización judicial. ********************************************************* mi contestación: Buenos días Pablo, ha pasado un año y no tenemos noticias vuestras de este expediente. En la notaria imagino por lo que dices se habrá firmado la escritura de adjudicación de herencia, que estaría pendiente de firmarse la correspondiente ratificación de la misma, que la firmaremos nosotros en Mérida cuando la envíen telemáticamente a la Notaría Fernández Pugnaire- Igartua Fesser- Hernández Téllez, C. Romero Leal, 24, 06800 Mérida, Badajoz, teléfono 924317761 (ext 013); email: joseluis@notariaromeroleal24.com Se aceptó vuestro presupuesto y estamos pendientes de que tramitéis la autorización de aprobación de herencia y autorización de venta. Guardo la factura del procurador que será abonada cuando finalicen los trámites. Por favor contactar con la notaria para agilizar este asunto y si no facilitan la documentación tendréis que poner una reclamación ante la notaria y/o al Colegio de Notarios. ********************************************************** Me llama Pablo Garrote 673163200 para decirme que tiene el Auto de autorización de aceptación de herencia desde Marzo y que en la notaria han cambiado de notaria y viene un día a la semana y que tienen parado el expte sin más explicación, que hablará con ellos para pedirles que o lo tramitan ya o lo lleva a otra notaria. Quedo a la espera de que me comente los avances. Dice que sólo hay una vivienda que heredar, nada más. Dará de nuevo mis datos a la notaria para se pongan en contacto conmigo para coordinar la ratificación de la adjudicación de herencia una vez sea firmada. ********************************************************* Recibo nuevo email del abogado Pablo Garrote Delgado: Buenas tardes, Ya he conseguido hablar con ellos y me han dicho que si que va a intentar tenerlo o bien para este jueves o como muy tarde la semana que viene, que la notaria solo viene un día a la semana y no sabe si para este jueves lo podrá tener. Tengo que llamar a Jose que me ha pedido dos testigos de calera para la escritura, voy a ver si puedo contactar con el.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-09-12','Ana: Llamo al ESM-CC para anular la cita de Psiquiatría el día 22 de septiembre. ············· Lo comunico a Estrella, TS CSS Plas., y Pilar, TS ESM-CC. ········································································································································ Correo de ayer de Sonia Bernabé, Asindi: "Hola Ana, me llamó Estrella el jueves desde la UDAC para decirme que Aaron Rosado Alarcón iba a ingresar en el CAMP de Don Benito y que si tenía ropa y otros enseres en ASINDI tendríamos que mandárselos allí. Hemos estado viendo todas sus pertenencias y es mucho. Estamos pensando cómo prepararlo y pedir presupuesto para mandarlo a Don Benito por una empresa de transporte porque nosotros no vamos a esta localidad. ¿Cómo procedemos? ¿Embalamos, pedimos presupuesto y os informamos? ¿Tenéis otra manera vosotros para hacérselo llegar? Bueno, también tendremos que preparar la baja del servicio de residencia RAE cuando nos digáis. No nos dijo fecha exacta de ingreso pero por lo visto iba a ser en esta semana." ······················ Mi respuesta: "La forma de proceder es la que tú indicas, pedir presupuesto a empresa de transporte a nombre de Aarón y enviarla al ctutelar@salud-juntaex.es para que autoricen (entiendo que no habrá problemas). No hay otra forma de hacerlo. En cuanto a la baja en vuestro servicio, si te parece, cuando nos confirmen fecha de ingreso lo preparamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2023-09-12','TERESA EMAIL DE LA EMPRESA DE SAD Le compramos nosotros los productos para la limpieza y os pasamos la factura, si te parece bien. Respecto al tema de ropa de cama y demás , he hablado con la trabajadora para que vaya a Galerías Tentudía de Zafra y elabore un presupuesto con las cosas que le hacen falta y os lo hago llegar por correo electrónico, ellos aceptan el pago por transferencia. Muchas gracias por todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-09-12','Ana: Llamada de M. Ángel desde el teléfono de un amigo. Está acudiendo a diario al comedor social y pernoctando en un PISO OKUPA en la C/General Margallo (Casco Antiguo de Cáceres). ············· Con respecto a las prestaciones, le informo de que se le ha denegado la PFHC. ···· Llamaré al INSS en relación a la P. Orfandad, aunque entiendo que responderán que tampoco reune requisitos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-09-12','Ana: correo de Ángel, A. Jurídico, a Alberto y a mí: "La editorial Punto Rojo nos ha remitido este contrato de edición de un libro que van a escribir, Isabel Cano Blázquez y Ceferino Mariscal Crespo. Si estáis de acuerdo y se autoriza el pago dadme el ok, para formalizar el contrato. Son 675 euros, iva incluido." ····························································································································································································· Envío correo a Paula, TO, y Bea, Psicóloga, del CRR: "En relación al correo que nos remitió Ángel, Asesor Jurídico, y que te reenvío, imagino que ya estáis al corriente. Desde la Sección Económica no piden que os solicitemos VALORACIÓN TÉCNICA por vuestra parte como profesionales del recurso, sobre la viabilidad real/importancia/ repercusiones positivas para ambos. Así mismo, Alberto, Jefe de dicha Sección, expresa, que “entiende que el coste de la edición deberían abonarla entre los dos”, con lo que supondría económicamente para Isabel, pues evidentemente las posibilidades económicas de uno y otro no tienen nada que ver. Quedamos a la espera de vuestra valoración para proceder con el resto de trámites y el abono correspondientes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2023-09-12','Ana: Llamada de Jairo, dice que el Dr. Agapito Herrero, Psiquiatra, le dará el alta hospitalaria parcial, tendría que ir a terapias a diario y mantener tratamiento ambulatorio en el ESM. Pero tendrá que buscar un alojamiento, él quiere ir a un piso de alquiler. ················· Dice que el Psiquiatra pide hablar con nosotros, que le llamemos. ·········· Llamaré también a Emilia, TS CSS. ······················· *Quiere apuntarse a la Escuela de Idiomas y a la UNED.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-09-12','Ana: correo de Ángel, A. Jurídico, a Alberto y a mí: "La editorial Punto Rojo nos ha remitido este contrato de edición de un libro que van a escribir, Isabel Cano Blázquez y Ceferino Mariscal Crespo. Si estáis de acuerdo y se autoriza el pago dadme el ok, para formalizar el contrato. Son 675 euros, iva incluido." ····························································································································································································· Envío correo a Paula, TO, y Bea, Psicóloga, del CRR: "En relación al correo que nos remitió Ángel, Asesor Jurídico, y que te reenvío, imagino que ya estáis al corriente. Desde la Sección Económica no piden que os solicitemos VALORACIÓN TÉCNICA por vuestra parte como profesionales del recurso, sobre la viabilidad real/importancia/ repercusiones positivas para ambos. Así mismo, Alberto, Jefe de dicha Sección, expresa, que “entiende que el coste de la edición deberían abonarla entre los dos”, con lo que supondría económicamente para Isabel, pues evidentemente las posibilidades económicas de uno y otro no tienen nada que ver. Quedamos a la espera de vuestra valoración para proceder con el resto de trámites y el abono correspondientes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-09-12','Ana: Tras llamada de Montaña (692 84 12 19), envío correo a la secc. ecca.: "Como sabéis, el saldo de la cuenta de BBVA de MONTAÑA GONZÁLEZ ROLO, se ha agotado y no ha podido retirar su asignación periódica. Ahora está viviendo en Domicilio Familiar en Cáceres. Cuando podáis, hay que hacer una nueva autorización de retirada de efectivo para retirarlo en la Oficina de UNICAJA en la Avda. de la Hispanidad. Julio porfa, cuando puedas, hay que hacer el cambio de domicilio en la base de datos: C/Cerezo, nº 7. - C.P. 10005 – Cáceres (Este es el domicilio familiar, de sus padres)" ········································· A Montaña le dieron el Alta Hospitalaria en el CSS el día 3 de julio de 2023. ··············· Desde que reside con sus padres ha tenido seguimiento en el ESM, con el Dr. Enrique Goenaga, Psiquiatra, el día 25/07/23. ··············· *Dice tener muchas ganas de irse a vivir sola a su casa, pero no prisas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-09-12','Ana: Llamada de Lara, Residente de la UHB del HVP (78622): Javier no ha vuelto a presentar alteración desde hace 10 días. Él lleva 1 semana demandando el alta. ····· Me pregunta si tenemos recurso para él. *Lo último que me dijo Ana Benavente, TS ESM-Plas. es que la derivación a CRR estaba hecha. ···· Preguntaré por la posicición en la lista de espera y en el peor de los casos, buscaré un hostal/pensión. *Tal y como solicitan, llamaré al Dr. Blanco, Psiquiatra (78583) cuando haya algo cerrado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-09-12','Buenos días, Amalia He hablado con Josefa Moya García, la señora que no dejaba entrar a nadie en su domicilio y la que tiene un abogado, he conseguido su teléfono, le he dicho que te vas a poner en contacto con ella, su número es 924098030. El abogado, Pedro, también espera tu llamada. La señora nos pide 400 € de nuevo y yo le voy a hacer una puntual hasta que se decida cuál es la asignación permanente. Hay que hablar con ella pues tiene unas facturas elevadísimas de luz y dos contratos de teléfono además de un préstamo que está pagando mensualmente. Bueno, hablamos y me dices','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='SANCHEZ'and apellido2='MORENO'),'2023-09-12','-Estrella : Buenos Días, El seguro que cargaban de Mapfre está dado de baja. No lo han cargado el 1 de septiembre. El seguro con CASER se mantiene, es de la casa donde vive. C/padre Fermin Barba,13. El seguro con Verti, no me facilitan información. Lo cargan el 3 de octubre, apuntado para mirarlo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-09-12','Amalia : LLamé a la TS del SSASB : trabajadora social de Valdelacalzada, Mª Angeles. Contacta con ella cuando puedas. 615625304/627051020','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2023-09-12','miguel, asisto videoconferencia al juicio por delito leve de lesiones y donde la condenan a multa de 200€ (6€ por día)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-09-12','TERESA Pablo vuelve a su casa ya que no quiere seguir en el centro y no tenemos manera de retenerlo, ya ha tenido varios intentos de fuga. Llegara mañana en taxi, saldrá del centro sobre las 12. Actualmente no tenemos convenio con Futuex con lo cual no podemos contar con el apoyo de la educadora. Va con dinero y con la medicación pero no tenensmo medios para asegurar que se tome la medición y que el dinero que lleva no lo gaste en alcohol. En cuanto esté en el pueblo comunicaremos al juzgado y solicitaremos autorización de ingreso involuntario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-09-12','Ana: Recibimos RESOLUCIÓN de PRESTACIÓN ECCA. VINCULADA A LA ATT. RESIDENCIAL por importe mensual de 300,38€/mes. Primer periodo a percibir: 01/08/23 - 31/08/23. ········································· Cumplimento el documento de comunicación de variación de circustancias para comunicar el fallecimiento de Josefa a Dependencia y lo subo al portafirmas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-09-12','Buenas tardes, Amalia. Mi nombre es María Ángeles, trabajadora social de Valdelacalzada, en sustitución de Carmen Márquez. Encantada. Te escribo para intentar ponernos en contacto las dos para tratar algunos temas importantes con el caso de Rosa Serrano García. Mis números de teléfono son los mismos que los de Carmen, pero, aun así, te los facilito por aquí: 615 62 53 04 / 627 05 10 20. He llamado a varios números de la Comisión Tutelar, pero sin éxito, y el hijo me ha facilitado tu correo. O bien, si lo prefieres, me puedes facilitar un número de teléfono y yo llamarte. Espero tu respuesta, Un afectuoso saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-09-12','Iciar : envía email a su abogado : Buenos días, Pedro Tal y como hemos acordado en conversación telefónica necesitaríamos que nos enviase información en relación con Dª Josefa: Fotocopia de DNI Comprobar si c/ Juan Justo Garcia, 2 -esc 2-01-b – Zafra y Av Estación 66 1 – Zafra, según me comenta podría ser del piso y del garaje, le vienen dos recibos del OAR Si mantiene el vehículo, porque si es así, habría que darlo de baja y cancelar el seguro. La compañía de teléfono con la que opera, le cargan dos recibos, al menos una de las dos se dará de baja. La empresa con la que adquirió los audífonos el marido para saber cuál es la cantidad que resta por pagar. El seguro que abona Liberty Seguros, si corresponde a seguro de hogar o decesos, y si no fuera así si tiene contratado algún seguro de decesos. Además, cualquier factura de sus servicios que se le adeude también nos la puede remitir a este correo junto con los datos bancarios para hacer transferencia. De momento eso es todo. Como le comenté, cuando venga de vacaciones mi compañera trabajadora social se pondrá en contacto con usted para seguir tratando el tema. Quedamos a la espera de sus noticias. Gracias y un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-09-12','Ana: correo del día 4/09 de Julián Álvarez, Gerente de COCEMFE, al ctutelar@: "Tras la petición de la Asistencia personal para el tutelado T.E.I. adjunto declaración jurada de la persona que realizará las funciones de asistente personal del tutelado. El régimen propuesto de salidas será de 3h semanales a razón de 10€ la hora, total al mes 120€ como máximo. De momento soy yo el que coordina dichas salidas, tras hablarlo con T.E.I., indicando al Asistente qué tipo de salida realizar. Estas salidas ya se han comenzado a realizar en agosto, con lo cual y si no hay ninguna contraindicación se le deberán abonar al ASISTENTE PERSONAL DE T.E.I. la cuantía de 120€ en cuenta bancaria. Necesitaría saber qué tipo de justificación de dichas salidas debe realizar el Asistente Personal para indicárselo y que os lo haga llegar para su cuantificación y pago. Si bien se prefiere que sea yo, Guardador de Hecho de tutelado, el que realice la justificación me lo indicáis. Para cualquier cuestión no dudéis en poneros en contacto conmigo." ···································· Respuesta de Lourdes, Secc. Ecca., ese mismo día: "Para justificar las salidas con una declaración jurada nos vale, te adjunto un tipo de modelo. Necesitamos la del mes de agosto para abonarla y guardarla en su expediente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2023-09-12','-Amalia : solicito a Lola que le renueven el DNI','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-09-13','Ana: Envío correo-e a Julio, Aux. Adtvo. CTAEx: "Adjunto Comunicación de fallecimiento relativa a JOSEFA SÁNCHEZ DÍAZ, para remitirla a Dependencia (Secc. Cáceres). Seguramente ya lo hayan comunicado desde la Residencia, que por eso no lo comuniqué yo, pero por si acaso… Ah! Adjunto también el Certificado Literal de Defunción, para que lo unas a la comunicación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-09-07','Correo de Puerto, TS SSASB: "Buenos días: no sé si respecto a las protectoras se ha podido contactar, el equipo de salud mental que atiende a Enrique me preguntaba por su perrito, les comenté que de momento está atendiéndolo el Ayuntamiento (cada dos días le van a dar comida y agua, pero está en el salón de la casa de Enrique y así mucho tiempo encerrado no puede estar) Respecto a Enrique me comentan que de momento sigue ingresado, a ver cómo evoluciona... Estaré de vacaciones desde el 11 al 18 de septiembre." ········································· Respuesta de Miguel, A. Jurídico: "Buenos días contactamos con el teléfono de la protectora de Plasencia y tampoco tenían hueco, por lo que desde aquí por ahora no podemos hacer más."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-09-04','Correo de Miguel, A. Jurídico, a Maite y Ana (ambas de vacaciones): " tras intentar con Plasencia y el teléfono que nos dieron 622068154 nos confirman que no hay hueco para el perro de Enrique Santos, y de echo están pagando residencias caninas. Debido a la falta de capacidad económica que tiene va a tener que quedarse el perro en las circunstancias actuales y esperar hasta que desde Valdeobispo nos vuelvan a decir algo, y así alargar los tiempos, a ver si con suerte vuelve pronto a su casa Enrique. Ya digo hoy por hoy no veo otra solución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-09-01','Ana: En relación a la consulta de Miguel, A. Jurídico, a Alberto, Jefe S. Ecca., de la posibilidad de abonar una guardería para perros, Alberto responde: "COSTE TOTAL ESTANCIA (INDEFINIDA (que quiere decir esto???) (INCLUYENDO PIENSO (tenemos pensado dar de comer al perro???), e IVA): Ejemplos: • 15 €/DÍA (456,25 €/MES) • 17 €/DÍA (517 €/MES) • 20 €/DÍA (608 €/MES) ESTAMOS HABLANDO DE IMPORTES ELEVADOS PARA LOS INGRESOS DE LOS QUE DISPONE (721 €/MES) Y ADEMÁS NO ESTAMOS HABLANDO DE UN PAGO PUNTUAL, SI NO DE UNA SITUACIÓN INDEFINIDA. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-09-13','Ana: correo de Estrella Durán, TS CSS - UME (estrella.duranc@salud-juntaex.es) del día 11/09: "Como sabréis está ingresado en la Unidad de Media Estancia de este centro socio-sanitario de Plasencia, Enrique Santos García-Puente. No tiene dinero y quiere que le compremos tabaco. Haced el favor de enviar lo antes posible una autorización para que podamos sacar dinero y comprárselo." ························ Consulto a la secc. ecca. ········· Respuesta de Lourdes, Secc. Ecca: "Ya está hecho, Ana. Se han autorizado para las tres semanas de septiembre a 145€ por semana, 435€ Si continua en octubre, ya nos avisaran." ····································································································································································································· Recibo llamda de CARMEN, HERMANA de Enrique (606 704 973): ····························································································································································································· Envío correo a Estrella, TS CSS: "Acabo de mantener conversación telefónica con Carmen, hermana de Enrique Santos Gía.-Puente. Ella vive fuera, pero está pasando unos días en Plasencia para poder realizar una serie de trámites/gestiones pendientes y conocedora del ingreso de su hermano, pregunta si podría ir a visitarle esta tarde o mañana. Por parte del Equipo Técnico de la CTAEx no hay inconveniente en ello, siempre y cuando el Psiquiatra de referencia (que no sé quién es, perdona) y resto del equipo consideréis que no es contraproducente en estos momentos. No sé cómo está evolucionando Enrique, ya me dices también cuando puedas. Te anoto aquí los datos de contacto para que podáis confirmarle, y en su caso, indicarle día y hora de visita: 606 704 973 / maluker6@hotmail.com Por cierto, ¿nos podríais facilitar informe de UHB de traslado a la UME?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-09-12','AITOR Buenos días compañeras, ayer acompañamos a Aitor al forense. Después nos llamaron a nosotras y nos hicieron algunas preguntas. Nos dijeron que evidentemente ella no decidía, pero que con la ley que hay no es posible ingresar a Aitor en un centro sin que él quiera, así que… Seguimos en contacto!! Buena mañana!!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-09-13','miguel, me preguntan desde la notaria de los santos de maimona del motivo por el que no está ratificado la escritura última de compraventa. Finalmente tendré que ir a los Santos para firmarla ya que la notaria de Mérida de D. Gonzalo Fdez Pugnaire pone pegas por no coincidir la sentencia con el certificado de nacimiento (falta que ponga Comisión Tutelar de Adultos) ----------------------------------------------------------- Mando email a José Lavado para preguntarle si ya tienen la rectificación del auto de venta (de algunos inmuebles)que iban a solicitar en mayo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2023-09-13','Amalia : comunico la deuda a S. eco. de 636€ por cobro indebido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-09-13','Ana: correo de Estrella, TS CSS-Plas. (estrella.duranc@salud-juntaex.es) del día 7/09: "Le comentó Prado la Psicóloga tema de pagos de desplazamientos a sus hermanas cuando la visiten y no dijo nada, se quedó callada, así que es lo único que te puedo decir... Si ella verbaliza que no vienen a verla sus hermanas, se lo volveremos a decir...." ······························· Llamo a Maribel, hermana de Conchi (682 733 187), y se lo comunico. Se queda muy extrañada, pues me comunica que precisamente fueran a verla el domingo pasado y fue Conchi quien sacó el tema, les dijo que le había preguntado Prado y ella dijo que sí. ················ Contesto a Estrella con esta información.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-09-13','Ana: Llamada de Julia (644 876 893) ya ha terminado los Trabajos en Servicio de la comunidad. Está contenta pues dice que le han tocado muy buenas compañeras. ············· Por otra parte dice que ha enviado un correo pidiendo dinero para peluquería y ropa para la boda de su hermana que es el 28 de septiembre. ············· Le informo de que Lourdes ya lo ha pasado a Alberto, Jefe de Secc. Ecca. Tienen que esperar hasta que este dé una respuesta. ················· Le informo también del gasto tan elevado que ha tenido en el último año (desde verano de 2022 hasta ahora) en facturas de taxis y le digo que eso no puede seguir así. De ahora en adelante tendrá que procurar que las citas se las programen en horario que coincida con el autobús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-09-13','Ana: correo de Isabel el día 7 al ctutelar@: "Buenos días Ana el día 23 de este mes a un mes que no me hago daño y quisiera saber si me puedo ir del 25 al 29 de septiembre ya que nace mi sobrina espero tu respuesta vale gracias" ···································· Respondo: "Buenos días Isabel, La semana pasada yo no estuve. Acabo de ver tu correo. La respuesta te la daremos llegado el momento, aún es pronto. La decisión no es sólo nuestra, si el Psiquiatra está de acuerdo y desde el CRR tampoco viesen inconveniente se podría autorizar. Pongo en copia a Paula y Bea del CRR y a Ana Benavente, del Equipo de Salud Mental, para que estén al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-09-13','De: PEDRO MANUEL ATHANE CANTON >pac@multigestionempresarial.com> Enviado el: miércoles, 13 de septiembre de 2023 10:59 Para: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: RE: Mari Pepa Moya Garcia Buenos días; En relación a la persona que nos ocupa Dña. Mari Pepa Garcia Moya, decir que su situación a día de la fecha es buena relativamente y que a mi parecer tiene un marcado trastorno de bipolaridad; si bien no se si es debido a un proceso degenerativo o a la ingesta de medicamentos con el alcohol. Ella piensa que todo el mundo le engaña y que se quedan con su dinero; desde el taxista, hasta el que suscribe, lo cierto que no se dónde van a parar las cantidades que ha sacado habitualmente. Para un mejor conocer la relación existente entre nosotros, debo de señalar que esta familia compuesta por su esposo D. Vicente Arriba y ella son clientes desde su llegada del País Vasco, llegando a ser la relación casi familiar. Al fallecimiento del esposo, se intensifico aún más la relación, pasando a ser casi de una dependencia total, ya que las asistentes sociales no eran de su agrado; si bien, el trabajo realizado por estas era encomiable. El problema surge cuando se intenta llevar a una residencia, negándose ella e iniciando un procedimiento ante los juzgados de Zafra para quedarse en su casa; por cierto facturas que adjunto para que se realice transferencia por esa comisión tutelar a los profesionales que intervinieron. A partir de ese momento, las llamadas a mi teléfono eran de tres a cinco diarias y a cualquier hora, en estos momentos son dos diarias y a horas convenidas. Por lo demás ella creo que lo que necesitaría es una persona de apoyo que pasara de tres a cuatro horas diarias con ella y que de algún modo se preocupase de su día a día. En contestación a sus preguntas sobre compañía de telefonía, Seguro, inmuebles de su propiedad, vehículo y teléfono de contacto; solo puedo comunicarles que los inmuebles de su propiedad son las catastrales: GARAJE 6255023QC2565N0007IK; PISO 6255023QC2565N0031MP. El teléfono 924098030. Y que sobre lo demás lo estoy averiguando. Adjunto NIF de la interesada y facturas pendientes, a medida que vaya teniendo la información solicitada se le ira aportando; al mismo tiempo, me gustaría saber si hay forma de valorar los servicios que yo le presto pues considero que deberían ser retribuidos pero no sé cómo hacerlo, lo mismo en esa comisión tutelar existen casos parecidos por los que guiarnos. Gracias de antemano. Quedo a su entera disposición. Un saludo. De: PEDRO MANUEL ATHANE CANTON Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-09-13','Los teléfonos de contacto son: Pedro: 637430192 Mª Pepa Moya Garcia 924098030.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-09-13','Ana: Ayer en ctutelar@ se recibe presupuesto de hostal de Olivenza para una estancia de José Manuel del viernes 15 al miércoles 20 con motivo de "vacaciones", José Manuel lleva tiempo demandando salir unos días de CC, sobre todo de su barrio, no tiene buenas relaciones con los vecinos. ······· Desde la secc. Social se dió OK. ························ *Respuesta de Alberto;Jefe Secc. Ecca., hoy a Lourdes: "LOURDES: OK A LOS 250 € VACACIONES TUTELADO ---- NINGÚN EXTRA MÁS RELACIONADO CON ESTO" ········································································· Se lo comunico a José Manuel. Se pone contento. ·············· Por otra parte, aprovecha para contarme que ha llamado al ESM, ha hablado con el Psiquiatra. Le ha dicho que se encuentra mal y que quiere ingresar aunque sea en el CSS de Plase. ··· Como tiene cita en Psiquiatría el día 29, volverán a valorarlo entonces.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-09-13','TERESA Te comento un poco sobre la situación actual de Marta. Su madre nos cuenta que la mayor parte de las noches no las pasa en casa. De hecho, durante el mes de agosto y estos días de septiembre han llevado un registro donde se reflejan las horas de salida y entrada en el domicilio. La mayoría de las horas fuera de casa de su madre parece que las pasa en un piso junto a otros jóvenes, probablemente consumidores de sustancias tóxicas. En este piso también convive su actual pareja, la cual ya ha tenido un enfrentamiento verbal con la madre de Marta en la calle. Además, la relación con sus hermanos también está empeorando. Lo que a mí Marta me cuenta no se corresponde con todo esto, pero sí hay personas que la han visto en la puerta de este piso y que aseguran que las compañías no son buenas. Además, a lo largo del día en el centro la notamos muy cansada a pesar de que ella diga que duerme bien, en casa de su madre y que, únicamente, comparte las tardes con su novio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-09-13','Ana: Llamo a Toni- P. Orfandad INSS: Confirma que Miguel Ángel percibión la P. Orfanda desde 2019 que falleció su padre hastra 2020, fecha en que causó baja por vencimiento, al cumplir los 25 años. ············· A día de hoy NO reúne requisitos para solictar la P. ORFANDAD. ································································· En su día, 2021, también solicitó Mínimos Vitales, pero se lo denegaron por no cumplir el requisito de haber estado al menos 12 meses de alta en la Seguridad Social. ·················· Ya sólo queda la opción de solicitar Renta Extremeña Garantizada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-09-13','Ana: Llamo a la Secc. de Dependencia I de CC (22058). Hablo con Manuel, Técnico. Revisa que está toda la documentación aportada para la revisión PIA y la PRIORIZACIÓN. Va a consultarlo a Carme Gallego, Jefa de Secc., para que lo pueda pasar ella directametne a la compañera del Equipo de Miajadas. ·············· Me devolverán la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-09-13','-Amalia : Buenos días , de este expediente me encargo yo del plan inicial . Ya he hablado por tf con la Srña. y con su abogado -amigo. Con Íciar ya me he coordinado para resolver el tema económico : -se le ha autorizado a sacar 400€ al mes , de los 1073€ que ingresa con P. viudedad. -De momento y hasta que se aclare todos los gastos que tiene no se le puede dar más .Tiene gastos elevados de luz ( 200€ / mes ) , más agua , IBI , móviles que se le van a dar de baja , préstamos .. -Desconocemos si tiene S. decesos y en su caso si se le pudiera gestionar alguno , por la edad puede ser que ya no sea posible. -Al cajero va en taxi , ella sola .Dice que sabe gestionar el dinero que saca . Debe facturas al taxista. -Le planteo la posibilidad de gestionar SAD , de momento no lo acepta . Insistiremos en ello . Espero a saber si tendríamos dinero para hacer copago . Voy a tramitarlo por dependencia. -Pedro , el abogado , tiene una relación casi familiar con ella. Tendrá que poner límites a sus llamadas y visitas . Va a pasar factura por su trabajo . -La delegada tutelar ya estaba gestionada , a la espera de que se retome de nuevo el programa . Fue una primera visita y Pepi aceptó . Lo más difícil será ganarnos su confianza , es una señora muy desconfiada que no se relaciona con nadie , solo con Pedro . Sufre deterioro cognitivo y patología mental . Consume antidepresivos con alcohol . Se pasa la noche en vela y duerme por la mañana . No acepta ingreso en centro residencial y la sentencia nos recalca que la intervención tiene que estar basada en sus deseos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-09-14','Ana: Llamo al Puesto de la Guardia Civil de Montehermoso (927 43 02 48) para solicitar informe de actuaciones: la persona que me atiende dice que va a consultar las actuaciones realizadas entre el 25-28 de agosto y me llamará al respecto. ························································································ Nueva llamada de CARMEN, HERMANA de Enrique (606 704 973): ································ Correo de Carmen, hermana de Enrique (maluker6@hotmail.com): "Buenos días Ana, soy la hermana de Enrique Santos García-Puente, te informo que ayer me dieron el llavero de la casa de mi hermano, una concejala del ayuntamiento, habrá que decirles que no tienen ya que atender al perro y al pájaro, como te he dicho telefónicamente, dejo las llaves mañana en el centro sociosanitario." ·························· Lo comunicaré a Puerto, TS SSASB, y a Miguel, A. Jurídico CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-09-14','Ana: Llamada de Estela, EVD Miajadas (21965 / estela.merino@salud-juntaex.es): Ya ha hecho las gestiones oportunas para priorizar el expediente. Solicitará centro por emergencia social. ··· Estela recomienda, que s fuera necesario, una vez esté en el centro que le asignen volvamoa a solicitar REVISIÓN PIA para TRASLADO a la Res. Felipe Trigo o alguna otra con Ud. de Psicogeriatría. ··························· Tal y como acordamos le envío correo con AUTO: "Tal y como hemos acordado mediante conversación telefónica, adjunto la nueva resolución judicial relativa a JOAQUINA MAYORAL PIZARRO, en la que nombran a la CTAEx CURADORA REPRESENTATIVA y SE AUTORIZA SU INTERNAMIENTO EN CENTRO." ·································· Intercambio correos con Anabel, TS SSASB Miajadas y Estela, TS EVD-Miajadas: *A Joaquina le han rescindido el contrato de SAD-Dependencia por impago de 2 meses a la empresa. ······· Cuando se tenga acceso a sus cuentas y se haya saneado su situación ecca. se intentarán saldar las deudas. ················ *La ACEPTACION PIA la pondré a la firma de la D. Gerente el lunes 18, que ya adquiere firmeza la sentencia y le daré registro de entrada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-09-14','Ana: Llamo al Hotel Azar (927 42 18 33): tienen habitaciones disponibles, no habría ningún problema en que volviera a alojarse allí (estuvo en dos ocasiones en el mes de mayo). Mantienen el mismo precio: Alojamiento y desayuno 80€/noche. Media pensión (desayuno y comida) 95€. ··········································································································· Llamo al Dr. Blanco, Psiquiatra (78583): varias veces a lo largo de la mañana, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2023-09-14','buenas tardes, Amalia. En base a la muy positiva experiencia del fin de semana pasado y al deseo de Regina y de la familia en cuestión, se vuelve a solicitar permiso para este fin de semana. Saludos. REGINA REINA LARA, acogida en el recurso sito en C/ Rota 41 de Badajoz y gestionado por Asociación HOFA, disfrutará de permiso en C/ REYES CATÓLICOS 1A VALVERDE DE LEGANES (Badajoz) del 15 al 17 de septiembre de 2023 con Dª MARIA DEL CARMEN GONZÁLEZ CORDERAS DNI 80052778 J quien será responsable de la misma durante este periodo, por considerarse beneficioso para su evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-09-14','miguel, voy con Estrella la Gerente a firmar el poder apud acta para solicitar la ejecución del auto (por segunda vez). Se lo remito a la procuradora Cristina y al abogado Jorge','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-09-14','Amalia : escribo a Manuela de discapacidad te comento , JUANA DE LOS REMEDIOS PALOMO , quiere dejar la plaza RAL que tiene en Ctro. Ntra. Sñra. de la Luz para irse a vivir con su madre en Badajoz. Pero mantener la plaza en CO , y regresar a casa por la tarde . Es posible ?? La madre está de acuerdo. El centro ya lo sabe también , estoy esperando su respuesta . Esta chica ha tenido fugas del centro , y creo necesario un cambio . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-09-14','miguel, solicito vía email al abogado Enrique Perianes (que ya ha llevado el expte de Ricardo Rocha) presupuesto para tramitar la autorización judicial de venta del piso de Málaga del curatelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PUERTAS'and apellido2='GIL'),'2023-09-14','-Amalia . Su hno. Adelino solicita abono facturas de luz ( tf 603641483) y algo de dinero , la ultima vez se le environ 50€ , doy OK . Tere se encarga de volver a solicitar al centro el empadronamiento , es necesario para que el hno. tenga acceso a ayudas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2023-09-14','Ana: Entrego a Alberto, Jefe S. Ecca., Aviso de Apremio de Recaudación Ejecutiva del Ayto. de Valencia. (Importe a ingresar: 343,16€)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-09-14','Buenas , adjunto respuesta a mis escritos al organismo de pensiones alemán preguntando por la segunda pensión que percibía MARIA LUISA ESPINAR DEL ARCO. Nada , no nos saben decir . Confirmad que la otra pensión se esté percibiendo mensualmente . Miguel , quizás esto haya que aportarlo en la declaración de la renta , porque ellos contabilizan dos . Por mi parte , finalizo mi búsqueda , he enviado escritos a todos los organismos alemanes y al INSS y todos en la misma línea.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-09-15','miguel, contratamos al abogado Enrique Perianes(Enrique >2914@icaba.com>): Buenos días, de acuerdo. Si necesitas se os ingrese un depósito mándame el presupuesto. Adjunto documentación para que inicies los trámites: nota simple, compromiso del curatelado, certificado de residencia en CRR de Mérida, testimonios de incapacitación y nombramiento. Necesitaré los datos del procedimiento, juzgado y procurador para rellenar el modelo que te adjunto en los juzgados de Mérida. Quedo a tu disposición para cualquier duda o documentación que pueda faltar. ---------------------------------------------------------- Recibo email de Enrique(abogado): Buenas tardes Miguel. Cobramos 500 € mas IVA, Abogado y Procurador. Ya hablamos con Miguel Ángel que el presupuesto iba a ser muy ajustado en atención al tipo de procedimiento que estáis llevando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-09-15','Ana: Llamada de Montaña, TS SSASB La Cumbre (621 247 249): la situación sigue igual o peor. Ayer hubo una pequeña tormenta en Cáceres, el tejado de la casa está peor y teme que se derrumbe el del lado de la casa en que duerme Guadalupe. ················ Ni ella ni la jueza acaban de entender que no ingrese. ·············· El lunes hablaré con Maite, Jefa de Secc., y volveremos a instar la convocatoria de la Subcomisión para ingreso en UME y posterior derivación a CRR. ·········································· Envío correo a Montaña (ssasbmancomunidadtrujillo@gmail.com): "Tal y como hemos acordado, te reenvío el correo de Maite al ESM y adjunto el Auto Judicial en que se autoriza el INTERNAMIENTO, el cual ya ha adquirido firmeza."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-09-15','Ana: Llamo al teléfono del Dr. Blanco, Psiquiatra (78583), hablo con Lara Pecharroman, Psiquiatra Residente. Puesto que el Dr. Blanco, Médico de referencia no está hoy, dejarán el alta para el lunes, y así se marcha ya con la analítica hecha. Pedirán cita para revisión en ESM. ··········· Hablará con Javier para ver si está de acuerdo en ir al Hotel Azar. ·············· Correo de Lara, Residente de Psiquiatría HVP (lara.pecharroman@salud-juntaex.es): "Buenos días, soy Lara. He hablado con el paciente y se muestra conforme con el hotel que has encontrado. Se puede reservar para el lunes 18 de septiembre. Ese día le daremos el Alta y gestionamos desde aquí la revisión en el ESM." ··············· Contesto a Lara y envío correo al Hotel Azar (recepcion@hotelazar.com): "En relación a mi llamada de ayer consultando por la posibilidad de reserva de habitación para D. JAVIER AGUDO CUMPLIDO, con DNI 38848532Z , cuyo cargo de TUTELA ostenta la Comisión Tutelar de Adultos de Extremadura, y que ya se alojó en su establecimiento en el pasado mes de mayo, nos gustaría confirmamos reserva para la semana que viene completa a media pensión. Aún no sabemos si será necesario ampliarlo más. Fecha de entrada: Lunes 18/09/23 Fecha de salida: Lunes 25/09/23 Si hubiera cualquier cambio, nos pondríamos en contacto con ustedes. Rogamos confirmación. Gracias y un saludo." ·································································· Envío correo a Alberto, jefe S. Ecca.: "En relación a JAVIER AGUDO CUMPLIDO, y tal y como hablamos ayer, me confirman en el hospital que le darán el alta el lunes. He escrito al HOTEL AZAR para confirmar fechas. Te recuerdo los presupuestos que me facilitaron mediante conversación telefónica: - MEDIA PENSIÓN (Incluido desayuno y comida): 95€/noche. He pedido entrada Lunes 18 y salida lunes 25, de momento, por asegurarnos alojamiento y una semana. Entiendo que durante esta, habrá que buscar algún alojamiento más económico, pues según me dijo Mariluz, Jefa Salud Mental, puede ir para largo su ingreso en el CRR. Para empezar, desde el Equipo de Salud Mental han hecho dos veces mal la derivación…." ······························· *Envío a Alberto, S. Ecca., la FACTURA PROFORMA que me remiten desde el hotel. Hay que abonarla antes de su entrada. ······················· Comunico a Ana Benavente, TS ESM, el próximo Alta Hospitalario y la reserva en el hotel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-09-15','TERESA LLAMO A PABLO 621342359, SE ENCUENTRA BIEN ESTA LLENDO A LA FARMACIA PARA TOMARLA MEDICACION EL PROXIMO MARTES 19 TIENE CITA EN ECCA DE CACERES, CONTRATO TAXISTA MANUEL 696248835 PARA QUE LO LLEVE, ALLI LO ESPERA JULIA PARA ACOMPAÑARLE A CONSULTA LE HE AUTORIZADO REINTERGRO DE 70€ PARA QUE COMPRE COMIDA LA CASA TIENE LUZ PERO NO TIENE AGUA Y DEMANDA QUE LE DEMOS AL ALTA AL AGUA VAMOS A ESPERAR LA CONSULTA DEL MARTES A VER QUE NOS INDICAN DESDE EL ECAA SE PLANTA AL POSIBILIDAD DE CONVOCAR UNA SUBCOMISION HE INTENTANDO HABLAR CON PILAR MARITENEZ 54612 TRABAJASODORA SOCIAL DE SALUD MENTAL PERO HE CONSEGUIDO HABLAR CON ELLA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-09-15','Con respecto a las pensiones de Alemania, se está cobrando una pensión. El 1 de junio cobro los atraso pendientes (4.844,10€), y a partir del 28 de junio ya le entra la pensión de 1011,32€-------------------------------- La otra pensión no tienen constancia en el organismo alemán , Miguel propone seguir pagando la complementaria de la D. de la renta y dejarlo así.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-09-15','Ana: Tras hablar con Estrella, TS CSS-Plas. y Desideria, envío correo a Alberto, Jefe Secc.: "En relación a DESIDERIA BARBERO BUENO, Óscar nos envió correo a Estrella, TS del C. Sociosanitario y a mí. Necesito por favor, que me digáis cuánto antes cómo está la situación, si se ha hecho efectivo el cambio de domiciliación de suministros de la vivienda. Antes estaban a nombre de Ángel, marido fallecido, en una cuenta en Bankinter en la que también es titular la propia tutelada. La tutelada teme que esa cuenta se quede sin saldo y le corten los suministros. Además, ambas consideramos, que lo más conveniente para Desideria, sería anular dicha cuenta (la de Bankinter) y quedarse sólo con la otra que se le abrió una vez a cargo de la CTAEx. Pongo en copia a Estrella, compañera del C. Sociosanitario."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2023-09-15','Ana: Correo de Inés, Adtva. Secc. Jurídica, a los A. Jurídicos y a mí: "Buenos días compis, os envío comunicación del Juzgdo nº 1 de Plasencia, recibido vía Fax, referente a la SUSPENSION del juicio cuya celebración estaba fijada para el próximo día 19 de septiembre de 2023 a las 11:15 h. Ya está en su expediente y lo anoto tb en la hoja excell de citaciones." ······································ Mi respuesta: "Esta Sra., que yo sepa, sigue en paradero desconocido. Aún no se ha podido intervenir con ella."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-09-15','Ana: conversación con Estrella, TS del CSS, se plantean darle pronto el alta. Consideran que sus conductas obedecen más a sus rasgos de la personalidad que a su enfermedad mental. ··········· Manifiesto mi preocupación en relación al RIESGO que entendemos que supone Enrique para los vecinos el pueblo, no consideramos que Enrique esté en disposición de vivir sólo. Por este motivo y porque no tomo adecuadamente la medicación y además no cuenta ya con servicio de catering y tal y como ha demostrado, no tiene capacidad de autocontrol y adecuada gestión del dinero, no utilizando el dinero asignado a comida a tal fin. ···················· Vuelvo a plantear la posibilidad de convocar una Subcomisión con la finalidad de internamiento en centro. ·················· Enrique, viviendo solo, es un riesgo para sí mismo y para terceras personas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2023-09-15','Ana: Tras recibir correo-e de Ángel, A. Jurídico, envío correo a Felisa Custodio, TS CAMF-Alcúescar (trabajadora_social_alcuescar@imserso.es): "Te reenvío correo de, Ángel, A. Jurídico CTAEx, que a su vez nos reenvía el de Abogacía General, con REQUERIMIENTO DEL JUZGADO adjunto. Como ves solicitan INFORME MÉDICO. Yo entiendo que también tendría que aportarse Informe Social, pues las cuestiones que detallan y que deben especificarse, pero lo dejo de tu mano, si lo consideras y puedes, te lo agradeceríamos. En cuanto lo tengas, por favor, háznoslo llegar." ··········································· Respuesta de Felisa, TS-CAMF: "doy traslado a la Dirección y Responsable de Gestión del CAMF para la elaboración del informe médico, ya que nuestro médico del CAMF está de baja. En cuanto al resto de documentación ya disponen de todo el expediente en el Juzgado cuando iniciamos el proceso de curatela."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='PEREZ'and apellido2='JIMENEZ'),'2023-09-15','TERESA RECIBO LLAMADA DE ANA LA EDUCADORA PARA COMENTARME QUE ROSA HA SIDO AGREDIDA POR SU PAREJA HA DECIDIDO PONER DENUNCIA SE HA CELBRADO UN JUICIO RAPIDO Y LE HAN PUESTO ORDEN DE ALEJAMIENTO Y TRASLADO A OTRO CENTREO ARCHIVO SENTENCIA Te envío sentencia del juicio rápido celebrado ayer por el episodio de Rosa, vuestra tutelada, con un compañero de residencia con el que había iniciado relación. Fue todo muy rápido y no ha dado tiempo a procesar casi… la medida a adoptar es de orden de alejamiento mientras se tramita el traslado de centro de Celedonio. Soraya está informada. Rosa está en casa de sus padres desde ayer y él está aquí en el centro a la espera del traslado que no sabemos cuándo se realizará. Los padres de Rosa fueron informados de lo ocurrido ayer para pedirles colaboración…y no tienen inconveniente en que se queden unos días más si fuera necesario. Te iré informando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2023-09-15','-Amalia : llama Eva , la TS , está teniendo unas conductas extrañas . Le indico que la deriven a su centro de salud. Puede que haya que parar el proceso de hormonas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-09-15','Ana: Llamada de Isabel Cano, tiene FASCITIS PLANTAR y ayer le hicieron infiltraciones y le duele. ························ Vuelve a plantear su viaje al pueblo. ······ El día 21 tiene cita con el Psiquiatra, estará en función de lo que determine éste. ···· Ya le escribí al respecto a Ana Benavente y CRR. ··························· Por otra parte quiere comprar un móvil nuevo. Le recuerdo que eso tiene que ser con su extra anual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-09-15','Ana: Correo de Ángel, A. Jurídico: "Buenos días, Nos pide Escalona Informe en relación con la solicitud de remoción del cargo nuestro, que pide la sobrina. Importante, leed bien la demanda, porque hay que ir contestando en función de todo lo que dicen, según el criterio que seguimos en Comisión. Ana, es importante que desde el centro también den su punto de vista, puesto que en la demanda también hablan de ellos. ". ···················· Se lo reenvío a Leyre Sanz, TS de la Res. (t.socialcanovas@grupociudadjardin.com) pidiendo nos remitan INFORME a la mayor brevedad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='SANCHEZ'and apellido2='MORENO'),'2023-09-15','-Amalia : hablo con Almudena Ceballos ,TS IMSS Bjoz. , tenemos pendinte hacer visita junto con Teresa , delegada tutelar . Quedamos pte. a renovacion convenio con Futuex. La familia quiere pedir dependencia. Confirmo que tiene Grado1. Nivel 1 , expediente inactivo en 2016 por no aprobación PIA de la propuesta dada de P.E. SAD .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-09-13','Ana: Llamada de Julia, Coord. Casa Misericordia: Sergio ha protagonizado hurtos a otros residentes. Le han restringido las salidas. Quiere hablar conmigo. ····················· Llamo a Sergio, dice que se quiere marchar de la casa pues parece una prisión pues no le dejan salir, pero al preguntarle por qué no cuenta las incidencias. ·········· No quiere ir a ningún otro recurso (CRR ni PS). Quiere vivir de forma independiente de alquiler. ··········· Le indico que considero que aún no está preparado para ello y que igualmente habría que revisar su sentencia y puede que comunicar al Jdo. ··················· Volveremos a hablar esta semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-09-15','Ana: nueva llamada de Sergio (640 654 897): mantiene el deseo de irse de la casa. ··········· Le digo que he hablado con los A. Jurídicos y que vamos a enviar Informe al Juzgado. De momento lo más recomendable es que permanezca ahí hasta que responda el Juez. ··········· Sergio se replantea el traslado a CRR. Le digo que esa derivación deben hacerla el Psiquiatra y la TS del ESM. Debe solicitarlo en la próxima cita. ··············································································· Llamo a Julia, Casa Misericordia (615 62 86 80): El miedo de Julia es que Sergio vuelva a estar solo en la calle, a consumir y a atracar a punta de navaja. ·········· Le solicito INFORME de la INCIDENCIAS acaecidas en el centro y criterio técnico sobre de la conveniencia o no de que Sergio viva de forma independiente. ··················· Al parecer en estos dos día, ha estado más tranquilo y participando en las actividades habituales (Taller de mimbre entre otros).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2023-09-15','-Amalia: Buenas Angel , he conseguido contactar con su sobrina Angela , tf 643650084. El señor que quiere comprar la casa contactó con ella directamente para que le abriera la casa y ya ha ido el tasador . Me pregunta su sobrina si los efectos personales y alguna cosa que haya en el domicilio de su tía se lo puede quedar . Entiendo que eso no entra en la venta , hay fotos y enseres personales de la familia . Ya me dices . Buen finde','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-09-18','Ana: en relación al correo de Isabel pidiendo autorización (otro extra) para comprar un móvil nuevo, respondo con copia a las profesionales del CRR y a Ana Benavente, ESM: "Tal y como hablamos el viernes por teléfono, y tú misma pones en tu correo, este tipo de artículos debes comprarlos con la asignación extra anual. No obstante, también sabes que estas cuestiones tienes que hablarlas con las profesionales del centro para que nos las trasladen a nosotras si ellas lo consideran, pues también son ellas quienes os ayudan a administrar los extras. Si bien es cierto, además, que de momento el teléfono funciona, pues puedes enviar correos y hacer llamadas. Por otra parte, en cuanto a tu petición de ir a casa el día 25, como sabes, tiene que dar el visto bueno el Psiquiatra en función de tu evolución. Y por su puesto también contamos con la valoración del equipo del CRR. Pongo en copia a las compañeras del mismo así como a la del Equipo de Salud Mental para que nos transmitan el criterio de ambos equipos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-09-18','Ana: Envío correo a Julio, Aux. Adtvo. CTAEx: "Adjunto para remitir por REGISTRO la ACEPTACIÓN PIA de Servicio de Atención Residencial firmado por la Vicepresidenta de la CTAEX, relativo a JOAQUINA MAYORAL PIZARRO, a: SEPAD. GERENCIA TERRITORIAL DE CÁCERES. Plaza Hernán Cortes, 1 10001-CÁCERES CÓDIGO REGISTRO SIREX: A11030403" ··········································· Comunico a Estela Merino, TS del EVD-Miajadas (estela.merino@salud-juntaex.es) el registro de la misma. Y le envío los documentos relativos al cargo y delegación de funciones de la nueva D-Gerente. ··························································································································································································································································· Mai, Jefa de secc. de acceso a RR de Mayores, me comunica que van a darle plaza en la Residencia de Alcuéscar. ··· Me comunica además que no se dio cuenta ni de que era involuntario ni de que estaba a cargo de la CTAEx y ha llamado a la propia Joaquina y a su hija.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-09-18','Ana: envío correo a Montaña, TS SSASB: "No te llamo porque estoy hasta arriba. Sólo quería preguntarte por Guadalupe Gil Cabello, llevo todo el fin de semana con ella en mente, sobre todo por las lluvias, que no sé cómo habrán sido por esa zona de Cáceres y habrá podido afectar al tejado de su casa. Si hay alguna novedad, por favor, házmelo saber. Con Maite me reuniré en la segunda mitad de la mañana, a ver si tiene noticias de la Subcomisión solicitada. Luego te decimos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2023-09-18','Ana: En relación a los correos de Alberto y Ángel, CTAEx, sobre la venta de la vivienda de Martín y la visita a la misma, respondo a todos: "Martín, debido a la descompensación de su patología de base, no estaba en condiciones de tomar una decisión con respecto al a venta de sus inmuebles. Se pidió valoración al C. Sociosanitario. Entiendo que por eso no se solicitó a Futuex que acudieran a visitar la vivienda, en espera de que nos dijeran desde el CSS que se encontraba bien para ello. Volveremos a pedir valoración al centro, pues de no ser así, si no me equivoco, habrá que pedir autorización judicial para la venta. En cuanto a contratar la gestión a la inmobiliaria, me parece bien, en cuanto tengamos el consentimiento de alguna de las dos partes entiendo, no?" ········································································· Respuesta de Ángel: "Esperamos a recibir esa valoración para conocer la voluntad de Martín, en relación con la venta del inmueble, del que es propietario al 100% (vivienda de los Castellanos, en Cáceres). En cuanto a la venta podemos hacerla sin autorización judicial, Martín tiene una incapacidad parcial, su enfermedad no anula totalmente sus capacidades, sino solo levemente, tan solo necesita nuestro complemento, consentimiento, parecer y autorización. Como en otros casos, él tendría que firmar junto con nosotros la escritura pública de venta en Notaría."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='CAMARA'and apellido2='MORENO'),'2023-09-18','Ana: Recibimos escrito del Serv. de Prestaciones Soc. En relación a la devolución del importe de la mensualidad de julio, como consecuencia de la cancelación de la cuenta bancaria, proceden a regularizar su situación abonando en concepto de ATRASOS LA CANTIDAD DE 484,61€ junto con la nómina relativa al mes de septiembre de 2023. ··············· Lo comunico a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TERESA'and edp.apellido1='COELLO'and apellido2='GASPAR'),'2023-09-18','ARCHIVO El Jzdo. de 1.ª Inst. e Inst. n.º 1, de Don Benito, dictó Auto, de 4 de mayo de 2023, por el que se dicta medidas de apoyos judiciales y se nombra curador representativo a su hermano Mariano Coello Gaspar. De igual modo, y en el mismo auto, se deja sin efecto la Sentencia 427/17, de 4 de diciembre, por la que se incapacitaba a Dña. Teresa y se nombraba tutora a su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2023-09-18','TERESA Tras conversación con la directora de Inclusive, Maribel, para planetarle al opción de que Juan Jose pasara a VT me comenta que ahora mismo no hay plazas libres Con respecto a Juan Jose me comenta que está bien adaptado al centro, tiene su grupo de amigos con los que sale y hace actividades y se muestra contento con los talleres que realiza Con respecto al padre y creo que es aquí donde radica el problema y no en Juan Jose, no es consciente de las dificultades que presenta su hijo y lo quiere tratar como una persona sin discapacidad. En la salida a casa no le suministra la medicación y le deja dormido hasta las cinco de la tarde pues considera que su hijo está cansado y tiene que descansar. Tambien considera que ya tiene edad para beber alcohol y no comprende que con la meidcacon que tiene no puede beber alcohol. La próxima salida al domicilio es del 25 de sepbre al 16 de octubre…. Por otra parte Juan Jose manifiesta que el gustan los hombres, esto tampoco es aceptado por su padre Con respecto a la formación, el centro se está planteando el tema de oposiciones ya que Juan Jose tiene el graduado y el padre insiste en que se forme. Ven con esto una posible salida ya que consideran que tiene capacidad para desenvolver algún puesto de esta categoría. He quedado con Maribel que le va a preguntar qué tal se encuentra en el centro y si le gustaría trasladarse. Por mi parte opino que Juan Jose está bien en este centro, que el tema del traslado es mas bien un deseo del padre que de él y podría ser más contraproducente que beneficioso ya que Juan Jose tiene aquí ya su grupo de amigos y adaptado a sus rutina. El traslado supone empezar de nuevo con el hándicap que Juan Jose es bastante tímido y le cuesta relacionarse','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-09-18','Ana: Puesto que aún no he tenido respuesta de la Guardia Civil, llamo de nuevo al Puesto de Montehermoso (927 43 02 48): me atiende otra persona. Me dice que los informes/atestados hay que solicitarlos por escrito (OFICIO) bien a través de correo ordinario bien a través de e-mail: cc-pto-montehermoso@guardiacivil.org ··························································· Envío email al puesto de la Guardia Civil: "Tal y como me han indicado mediante comunicación telefónica, adjunto: - Oficio solicitando documentación (informe de actuaciones, denuncias e incidencias) - Testimonio de Aceptación del Cargo Relativos a D. ENRIQUE SANTOS GARCÍA-PUENTE, cuyo cargo de CURADOR REPRESENTATIVO ostenta la Comisión Tutelar de Adultos por Resolución Judicial. No obstante le daremos también registro y lo remitiremos por correo ordinario." ················ Lo reenvío a Julio, Aux. Adtvo. CTAEx, para que le dé registro y lo envíe por correo postal. ··································································································································· Estrella, TS UME-CSS, me remite Infome de alta en UHB por traslado a UME.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-09-18','-Amalia : hablo con su hermana , el resultado de paternidad que le han hecho a su sobrino ( hijo de la hna. que vive con ella ) ha dado negativo . Nos pide que hablemos con Antonia para que no vaya diciendo por ahí , que el padre del niño era este señor cuando es falso . Le he pedido que me envie ese documento por email . El niño tiene 19 años y el 33% discapacidad según Ana , la hermana. ( 681166315). Hablaré con Antonia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-09-15','miguel, tras reiteradas llamadas de Ana (hna de la curatelada asistencial) le indico que nosotros no entraremos en acuerdos previo a nuestro cargo de quién son o no los vehículos, pero como me pide un escrito de compraventa le envío el borrador. Y si la curatelada Antonia está de acuerdo en firmar la venta del focus y el compromiso de que una vez pagado el dacia se lo dará al suegro de Ana (Ana manifiesta que es quién ha estado pagando ambos vehículos). En caso de que la curatelada no quiera firmar ambos vehículos dice Ana que recurrirán vía judicial. Traslado a la parte social (Amalia y Maite) y a la Económica (Alberto) esta información: Buenos días, la curatelada asistencial tiene a su nombre dos vehículos: Ford Focus y Dacia…ambos tienen unos años. El primero parece ser que está pagado y al segundo me dice que le falta unos 8.500€ por pagar. Como es una cuestión anterior a entrar nosotros le he dicho que no vamos a entrar en este asunto y por tanto le he mandado un modelo tipo de compraventa de vehículo del Ford focus, y si Antonia está de acuerdo que lo firme. Y del Dacia quiere un documento firmado por su hermana Antonia que reconozca que lo está pagando ella y que se compromete a darselo al terminar los pagos. Aquí también le he dicho que nosotros no entramos y que por tanto si su hermana Antonia quiere firmárselo que es cuestión de ellas dos. En caso de que Antonia Remedios no quiera firmárselo Ana Isabel lo reclamará vía judicial. Por tanto, Amalia (me ha pedido tu email para comentarlo también a ti), tienes que hablar con la curatelada Antonia y que te diga si está o no de acuerdo y firmará esos documentos, que repito, son acuerdos de las dos hermanas anteriores a nosotros. Y en caso de que esté de acuerdo te enviaré la compraventa del focus y el compromiso de que Antonia reconoce que lo está pagando Ana Isabel y que en el futuro se lo dará también. Confirmame lo antes posible si Antonia Remedios está o no de acuerdo con ambas cosas. En dichos documentos no va a aparecer la Ctaex pues como digo son cuestiones anteriores a nuestro cargo que ni si quiera podemos consultar al banco por ser anteriores a nuestro nombramiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-09-18','Ana: envío correo a Julio, Aux. Adtvo. CTAEx: "Adjunto oficio solicitando Informe del Servicio de Psiquiatría y acuerdo de aceptación del cargo, relativos a JESÚS MANUEL RAMOS BARGÓN, para remitir por SIREX al Equino de Salud Mental de Cáceres."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TRINIDAD'and edp.apellido1='SAAVEDRA'and apellido2='PARRA'),'2023-09-18','miguel, envío email a la parte económica (Estrella/Alberto) y a la social (Tere): Buenos días, esta mujer no para de llamar a diario. El dinero de la herencia de la expareja dice que se lo van a ingresar ya y me pregunta si puede disponer de él o no. La he remitido a la parte económica y social para que comprobéis si le han ingresado el dinero y acordéis con ella las cantidades de que pueda disponer a partir de ahora. Por la parte jurídica no hay nada más que hacer pues ya envié el documento de desbloqueo e ingreso en cuenta a Ibercaja (Nuria). ------------------------------------------------------ Contestación de Estrella: Buenos días, a mi hoy ya me ha llamado 5 veces. Acabo de comprobarle la cuenta y NO le ha entrado nada. --------------------------------------------------------- Contestación de Tere: Una vez que tenga el dinero en la cuenta tendrá que hacer Alberto el cálculo de la asignación que se le va a dar….','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2023-09-15','miguel, envio email a Alberto y Tere: Buenos días, creo entender que la parte social y la económica no está de acuerdo con dar el dinero para el vehículo que pide comprar para la sobrina. Voy a solicitar al juzgado que se pronuncie sobre si comprar o no el vehículo a la sobrina. Alberto necesito saber cuánto dinero puede gastar como máximo? Del email que enviastes Alberto no me queda claro…parece que indiques que nada porque quedaría en negativo…y si tiene actualmente 8.800€ (no lo entiendo) Pide gastar 3.000 o 4.000€ y es su voluntad…Otra cosa será cómo afrontará el futuro, por eso se lo comunicaremos al juzgado…pero es posible que nos diga que nosotros sabremos, que para eso somos los tutores… En cuanto Alberto me indique si hay un importe máximo que pueda gastar preparo el escrito para el juzgado. ---------------------------------------------------- Tere está de acuerdo que se le conceda lo que pide, por lo que quedo pendiente de la decisión de Alberto (parte económica)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-09-18','-Amalia ; escrio al resto de secciones sobre la venta de su casa : Buenas , este chico es propietario de una vivienda que quiere vender . Me comentan desde el centro que José María no quiere tener vinculación con esta casa, pues le está generando deudas. Además, no se está haciendo cargo actualmente de los pagos, gastos y mantenimiento que requiere la vivienda. Le gustaría comenzar a gestionar la venta de la vivienda. ¿ qué opináis al respecto ? desde la parte social no vemos inconveniente. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2023-09-18','Maite: he enviado correo a Mariví. Buenos días Mariví, Hemos retomado, tras las vacaciones, el tema de la venta de la casa de Martín Domínguez Palencia. Necesitamos saber si actualmente se encuentra con capacidad para decir si quiere vender. Cuando hablamos anteriormente estaba descompensado y no era un momento adecuado. También nos comentaste que tenía problemas en la boca y necesitaría ir al dentista. No tenemos presupuesto , no sé si al final eso se ha llegado a hacer. Ya nos dices. Gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-09-18','Ana: Recibimos 2 email de Jose Luis Romero, hermano de José Manuel en el ctutelar@(joseluisromeromediavilla@gmail.com / 687 581 061): con imagen del Informe Médico de Alta del Serv. de Urgencias del H.U.B. - Ha asistido a urgencias demandando BZD, expreando ideas autolíticas y diciendo que tiene pensamientos de que todo el mundo le mira mal y habla mal de él. ························ Llamo a José Luis: Su hermano está de nuevo en casa desde ayer domingo. Dice que no se encuentra bien y que no para de llorar. ····················································· Llamo a José Manuel (627 788 797): esta mañana ha tenido otra crisis, ha llamado al 112, le han ofrecido ir a buscarlo en ambulancia para llevarlo al hospital y no ha querido ir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-09-19','Ana: correo de Estrella, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Habló Prado, la Psicóloga, con Conchi al respecto de que pagara el combustible a sus hermanas cuando la visitaran. Conchi no se pronunció, no dijo nada, así que cuando ella verbalice que desea que vengan sus hermanas, volveremos a comentarle la cuestión. No obstante, la siguen visitando, sobre todo Maribel... Por otra parte, te comento que estamos empezando a dar pases a Conchi al CRR, esta semana irá desde hoy martes día 19 al jueves 21, y si la salida va bien, se va definitivamente de alta el 26."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-09-19','Ana: En relación al correo de Guadalupe Cortés, TS SAD - IMAS (guadalupe.cortes@ayto-caceres.es): "En cuanto al SAD en principio no tendría porqué afectar, pero al haber hecho la ampliación para apoyar en elaboración de comidas, si dejamos de hacerlas, la auxiliar tendría más tiempo para dedicarse a las tareas domésticas y de aseo personal y eso es lo que quería valorar con vosotras: si os parece adecuado el tiempo de servicio o si veis necesario reducir alguna hora." ··························· Respondo: "...En cuanto a las horas de SAD de Ventura, si no hay inconveniente en que mantenga todas las horas que tiene actualmente, desde el área social del Equipo Técnico de la CTAEx, consideramos que lo ideal es que las mantenga. Es un apoyo que le viene muy bien en todos los sentidos. Además, creo que no os he comunicado aún, que el Programa de Apoyo Comunitario desde el que le visitaba la educadora, finalizó a 31 de agosto, y aunque la renovación del convenio estaba preparada, según nos dijeron, con el cambio de gobierno de la Junta, no pudo ser firmado ni por el Gobierno saliente ni por el nuevo. En teoría volverá a funcionar para noviembre..." ······························· Respuesta de Guadalupe: "Por nosotros no hay ningún problema en mantener el SAD como está ahora. Simplemente era para que lo valorarais porque supone un coste económico importante para el usuario, pero a nivel técnico si me parece adecuado continuar con el servicio." ········································································································································································································ Llamo a Ventura (682 483 126): No quiere cambiar de contrato a prepago. ···· Le explico que al devolver los recibos del contrato de Movistar que él dice haber cancelado, como su línea de teléfono la tiene también en Movistar, se la puedan acabar cortando. ······· *Se compromete a acudir a otra compañía de teléfono a solicitar la portabilidad. ······················· Lo comunico a Alberto y Lourdes, Secc. Ecca. ································································································································································································ En relación a la cita en el Jdo. el día 14-11-23 ante el juzgado nº6 de Cáceres >>ORD PROCEDIMIENTO ORDINARIO 0000307 /2022>>, correo de Ángel con aclaración: ", es la demanda declarativa de dominio, que el adquirente “de buena fe”, continúa reclamando. Te recuerdo, el piso de Ventura, que compró un tercero. Pues aunque se declaró la nulidad de la ejecución hipotecaria y por tanto, se retrotrae el procedimiento al inicio, este tercero mantiene que compró el piso sin saber nada y que es suyo…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2023-09-18','Ana: Correo de Maite, Jefa Secc. CTAEx, a Mariví, TS del CSS: "Hemos retomado, tras las vacaciones, el tema de la venta de la casa de Martín Domínguez Palencia. Necesitamos saber si actualmente se encuentra con capacidad para decir si quiere vender. Cuando hablamos anteriormente estaba descompensado y no era un momento adecuado. También nos comentaste que tenía problemas en la boca y necesitaría ir al dentista. No tenemos presupuesto , no sé si al final eso se ha llegado a hacer."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-09-19','Ana: Respondo al correo de Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es), preguntando por el grado de discapacidad de Enrique: "Enrique no está valorado de Discapacidad. Te paso documento que nos remitieron desde el CADEX cuando se solicitó el Certificado al conformar el inventario. Si consideráis que debería estar valorado, necesitaríamos los correspondientes informes médicos para adjuntarlos a la solicitud. En cuanto nos los hicieseis llegar tramitaría la solicitud de valoración. De dependencia tiene reconocido Grado I."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2023-09-19','Ana: Tras recibir llamada de Abraham (639 887 897), escribo a la secc. ecca. al ctutelar@: "Me ha llamado Abraham, hijo de PILAR GARCÍA MORENO, esta mañana no le querían dar la asignación en el banco, le han puesto muchos problemas pidiéndole la AUTORIZACIÓN, él les ha explicado que la tienen ya, que habitualmente le dan el dinero en base a la misma. Finalmente dice que se lo han dado a regañadientes. ¿Podríais, por favor, escribir también a la correspondiente oficina al respecto y, si fuera necesario, volver a enviar la autorización?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-09-19','Ana: Llamada de Ana Benavente, TS ESM-Plas (74955): Ha estado Javier en su despacho, está sin teléfono y no ha podido retirar del dinero en el banco (habitualmente lo saca del 1-8). *Lo comunico a la secc. ecca. para que escriban al banco. ······················ A las 13 h volverá Javier y me llamarán desde el despacho de Ana. ······················ Llaman Ana y Javier: va a intentar la tarjeta con la clave pin en el último piso en que se alojó, pues no lo recuerda y por eso el teléfono está apagado. ······ Le explico que ya he pedido a la secc. ecca. que envíen escrito al banco para que mañana pueda retirarlo. ····· Con su asignación mensual, puede comprarse la ropa perfectametne, pues sólo quedan 11 días para finalizar el mes. ············· *Buscará un piso de alquiler en estos días. En caso de que no encuentre nada, el jueves o viernes me volverán a llamar para ampliar la estancia en el hotel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-09-19','Ana: Llamada de José Manuel (627 788 797): hoy está mejor y más tranquilo. Ya le han dado de baja el contrato de telefonía último que hizo. *Necesita productos para la limpieza. ···················· Escribo a la secc. ecca. (ctutelar@): "...necesita un extra de 20€ para productos de limpieza, para que la Auxiliar de SAD, pueda continuar haciendo su trabajo. Si es posible, por favor, haced la autorización para que vaya a retirarlo el viernes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-09-19','Ana: Tras llamada de Ángel F. (643 622 174), envío correo a la secc. ecca. (cututelar@): "...Dice que ha perdido 40 € de la retira que efectuó ayer… y que por favor le demos otros 40€ para “compensárselo”. Mirad por favor si es viable y qué día podría ir a retirarlo. ··············································· En otro orden de cosas, Ángel Félix, comunica que sigue acudiendo al comdero social de Cáritas y que vive en la casa de una persona a la que le abona 200€ por el alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2023-09-19','Ana: En relación al correo-e de ayer de Alberto, Jefe S. Ecca., envío correo a Felisa Custodio, TS CAMF-Alcúescar (trabajadora_social_alcuescar@imserso.es): "En relación a la situación económica de Mª CAMEN GOMEZ MUÑOZ, te copio extracto del correo que me envía Alberto: “EL PROBLEMA ES QUE TIENE UNOS GASTOS ORDINARIOS ELEVADOS PARA SUS INGRESOS Y LO QUE VALE EL CENTRO 545,19 €/MES, QUE HACEN QUE CADA VEZ QUE HAY ALGO EXTRAORDINARIO SU SITUACIÓN ECO SE RESIENTA ENORMEMENTE ---- EN ESTE CASO HA SIDO PAGO DENTISTA X 1.500 €, Y DADO QUE ES ALGO SANITARIO QUE TENEMOS QUE ASUMIR, EL CENTRO DEBE APRETARSE PARA AHORRAR DINERO POCO A POCO QUE NOS PERMITA AFRONTAR SITUACIONES COMO ESTA --- XFA, HABLA CON ELLOS Y TRASMÍTELE ESTO (SOBRE TODO TEMA TELEFONÍA QUE HA SUBIDO MUCHO EN ESTE ÚLTIMO AÑO (PASAR A PREPAGO)). TELEFONIA: HAY SUBIDO EL GASTO - HAY QUE PASAR A TARJETA PREPAGO DE FORMA INMEDIATA --- NO PUEDE SOPORTAR ESTE NIVEL DE GASTO EN TELEFONÍA (Anexo tabla). ... GASTOS VARIOS ASOCIADOS A ESTANCIA EN CENTRO: HAN SUBIDO MUCHO EN RELACIÓN A FICHA ANTERIOR: HAY QUE MINORARLOS." (anexo nueva tabla) ... Así pues, por favor, si se puede hacer algo en relación al a telefonía, quiero decir, modificar tipo de contrato a uno más económico o pasar a tarjeta prepago (que sería lo ideal) agradeceríamos que os encargaseis de esa gestión. Y el resto de gastos, no sé si realmente se pueden minorar… no tengo claro al 100€ a qué obedecen… ya me dices cuando puedas." ······················ Respuesta de Felisa Custodio, TS: "El asunto de pasar a tarjeta de prepago de telefonía se trató de hacer desde aquí, Carmen fue varias veces a Cáceres y no fue capaz, nos derivaban a un teléfono para baja. Se llamaba a ese teléfono y decían que debía ser el representante legal quién hiciera el trámite, le disteis una autorización pero tampoco quisieron hacerlo. Finalmente vuestra compañera Lourdes Cortes Márquez me dijo que iba a llamar ella y a solucionarlo. Esto ha sido a principios de septiembre. - Los gastos de farmacia corresponden con pedidos que hace el departamento de enfermería a la farmacia que suministra medicinas al CAMF, corresponden con gastos no financiados por la Sanidad Pública. Voy a hablar con la farmacia para ver si le pueden reducir el gasto. Te pongo copia del correo que mande. - Los gastos extraordinarios de este verano han sido por qué se fue al viaje de peregrinación a Lourdes y a la playa a las vacaciones del IMSERSO, participa todos los años en las dos cosas, pero ya no sale más hasta el año que viene. Os pedí el visto bueno para ambos viajes. También la dentadura postiza le ha supuesto un gasto importante pero es que estaba sin dientes prácticamente. A ver si reduciendo el teléfono y algo de Farmacia (si es posible), mejora su situación que por cierto no tiene nada que ver a cuando no tenía la curatela, desde entonces ha mejorado mucho"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='TORES'and apellido2='NUÑEZ'),'2023-09-19','Ana: Respondo al correo-e de Miguel, A. Jurídico, consultando por contacto de familiares para la tramitación de una herencia o desbloqueo de cuentas y reparto: "En el Informe Social adjunto, tenéis los datos de los familiares fallecidos (padres) más el número de su hermano Alejandro: 634 60 88 46 y también de un primo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2023-09-19','Ana: Llamada de Raquel, TS del SSASB de Guadalupe (605 429 865) Juan acude ahora casi a diario, sobre todo a raíz de haber cesado el Programa de Apoyo Comunitario gestionado por Futuex. El apoyo de Teresa, le venía muy bien. ··············· Me pasa a Juan, pide un extra de 300 € para ropa y pagar deudas. También dice que el teléfono no le funciona. ·············· Vuelvo a hablar luego con Raquel, no considera que sea bueno que se le dé lo que pide, pues considera que gran parte de ello lo gastará en lo que no debe (máquinas tragaperras, alcohol...). ······· Cree que estaría bien la mitad 150 €, pues sin el apoyo de Futuex no tenemos garantías de que vaya a invertirlo en lo que dice. SI VUELVE A PEDIR MÁS O SOLICITAR PARA OTRA CUESTIONES, SE LE EMPLAZARÁ A NOVIEMBRE, CUANDO VUELVA A FUNCIONAR EL PROGRAMA DE FUTUEX Y TENGA EL APOYO Y SUPERVISIÓN DE TERESA, EDUCADORA. ···················· Envío correo a la secc. ecca., para, si es posible, hagan la gestión para que pueda retirarlo el jueves.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2023-09-20','Ana: Subo al portafirmas digital CI para Extracción Dentaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2023-09-20','Ana: Respuesta de Lourdes, Secc. Ecca., al correo de ayer: "Buenos días, acabo de reenviar autorización al banco."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2023-09-20','TERESA Carmelo sale todos los meses a visitar a su sobrina. La sobrina ha pedido la remoción pero no se la han dado y la ha recurrido. Carmelo solicita entre 3000 y 4000 euros para comprarle un coche a su sobrina y así poder llevar y traerle de la residencia Atendiendo a la nueva legislación entiendo que debemos pedir autorización al juez y que sea el quien decida…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='GUISADO'and apellido2='GONZALEZ'),'2023-09-20','-Amalia : hablo de este caso con Manuela , TS del CSS , esta señora es transeuntes , vive en la calle. Cuando llegue inventario vuelvo a llamarla para elaborar Plan de Intervención .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CELEDONIO'and edp.apellido1='GARCIA'and apellido2='MATEOS'),'2021-02-23','ARCHIVO La Sección 1.ª de la Audiencia Provincial de Cáceres, dictó Auto n.º 134/20, de 9 de noviembre, por el que se revoca, y deja sin efecto, el Auto n.º 53/20, de 25 de junio, por el que se nombraba tutor a la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2023-09-21','Ana: envío correo a Rosa Bravo, Adtvo. CSS Plas.: " Adjunto el Consentimiento Informado para extracción dentaria firmado por la Vicepresidenta de la Comisión Tutelar de Adultos, relativo a Teresa Nevado Martin."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='TORES'and apellido2='NUÑEZ'),'2023-09-21','Ana: envío correo a Mariví Clemente, TS CSS-Plas. : "En relación a procedimiento de REVISIÓN DE MEDIDAS DE APOYO relativo a JULIÁN TORES NÚÑEZ, solicitamos nos remitas, en cuanto puedas, Informe Social que incluya ámbitos y extensión que resulten afectados por su discapacidad y necesidad de apoyo, así como cualquier consideración que estimes conveniente sobre el mismo. Por otra parte, tenía pendiente solicitarte el Informe Médico de Alta del Hospital Virgen del Puerto de Plasencia, del ingreso de finales de enero de 2023, así como si hay algún otro de especialistas de consultas externas de este año." ···· "me dice Miguel, Asesor Jurídico, que la vista es el día 23, por lo que a ser posible lo necesitamos entre hoy y mañana. Disculpa el poco margen y la premura." ········································· Dado que Mariví se ha jubilado, reenvío correo a Emilia Almodóvar, TS CSS (emilia.almodovar@salud-juntaex.es), pues ahora lleva ella las unidades que llevaba Mariví.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRIADO'and apellido2='RODRIGUEZ'),'2023-09-21','Ana: Envío correo a José Aº Pulido, TS (tsocial1@mancomunidadsierrademontanchez.es) y a Gloria, Directora del PP.TT. - Almoharín (glomama2009@hotmail.com): "Buenos días José Antonio y Gloria, En relación a la demanda de revisión de medidas de apoyo de MARÍA JESÚS CRIADO RODRÍGUEZ, necesitamos que nos enviéis, para remitir al Juzgado, tal y cómo este solicita, Informe Médico de Atención Primaria e Informe Social en los siguientes términos: A) Descripción de la discapacidad de carácter psíquico que le afecte. En ningún caso, el informe incluirá un juicio sobre la capacidad de la persona, al haber sido suprimido el art. 200 CC, conforme al principio de igual capacidad jurídica consagrado en el art. 12 de la Convención sobre los derechos de las personas con discapacidad. B) Especificación de los ámbitos que resultan afectados por la discapacidad de la persona, que sugieren la necesidad de apoyo en relación con el acto/actos de que se trate para el ejercicio de su capacidad jurídica en condiciones de igualdad. 1.- HABILIDADES DE LA VIDA INDEPENDIENTE Para el autocuidado: aseo personal, vestirse, comer, desplazamiento, etc. Para actividades cotidianas: comprar, preparar la comida, limpiar la casa, telefonear, respuesta ante la necesidad de ayuda, etc. 2.- HABILIDADES ECONÓMINO-JURÍDICO-ADMINISTRATIVAS Y CONTRACTUALES Para conocimiento de su situación económica. Para tomar decisiones de contenido económico: seguimiento efectivo de sus cuentas, de sus ingresos, gastos, etc. Para administrar sus ingresos especificando si el apoyo se precisa incluso para el manejo de dinero de bolsillo. Para realizar actos de carácter económico o administrativo complejos como préstamos, enajenaciones, donaciones, etc. 3.- HABILIDADES SOBRE LA SALUD Para consentimiento de tratamiento médico. Para consentimiento de intervenciones quirúrgicas. Para seguimiento de pautas alimenticias. Para suministro de medicación pautada. C) Si la persona es capaz de expresar su voluntad, deseos y preferencias de manera libre. Esto presupone: i) un conocimiento suficiente de la realidad sobre el acto/s que se ven concernidos ii) que la voluntad no está condicionada o mediatizada por la discapacidad, lo que impediría el desarrollo pleno de su personalidad, iii) que la voluntad se halla exenta de influencias indebidas. D) Si la persona precisa de ajustes del procedimiento y, en su caso de un facilitador. E) Asimismo, el informe deberá definir la intensidad del apoyo. Es decir, si precisa supervisión o asistencia en alguno o varios de los ámbitos concernidos por la necesidad de apoyo, o si en alguna de las citadas áreas se precisa excepcionalmente un apoyo más intenso (de representación) por no ser posible determinar la voluntad, deseos y preferencias de la persona”. Desde Abogacía General de la Junta, lo piden a la mayor brevedad, espero no suponga mucho inconveniente"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2023-09-21','Ana: envío correo a Sheila, Directora del CRR -CC (crr@grupociudadjardin.com): "En relación con la revisión de medidas de apoyo de Martin Miranda Hernández, nos requieren desde el Juzgado Informe Médico de Atención Primaria, en el que, además de los términos que a continuación se exponen, debe manifestar si es posible el desplazamiento de dicho tutelado al Juzgado: A) Descripción de la discapacidad de carácter psíquico que le afecte. En ningún caso, el informe incluirá un juicio sobre la capacidad de la persona, al haber sido suprimido el art. 200 CC, conforme al principio de igual capacidad jurídica consagrado en el art. 12 de la Convención sobre los derechos de las personas con discapacidad. B) Especificación de los ámbitos que resultan afectados por la discapacidad de la persona, que sugieren la necesidad de apoyo en relación con el acto/actos de que se trate para el ejercicio de su capacidad jurídica en condiciones de igualdad. 1.- HABILIDADES DE LA VIDA INDEPENDIENTE Para el autocuidado: aseo personal, vestirse, comer, desplazamiento, etc. Para actividades cotidianas: comprar, preparar la comida, limpiar la casa, telefonear, respuesta ante la necesidad de ayuda, etc. 2.- HABILIDADES ECONÓMINO-JURÍDICO-ADMINISTRATIVAS Y CONTRACTUALES Para conocimiento de su situación económica. Para tomar decisiones de contenido económico: seguimiento efectivo de sus cuentas, de sus ingresos, gastos, etc. Para administrar sus ingresos especificando si el apoyo se precisa incluso para el manejo de dinero de bolsillo. Para realizar actos de carácter económico o administrativo complejos como préstamos, enajenaciones, donaciones, etc. 3.- HABILIDADES SOBRE LA SALUD Para consentimiento de tratamiento médico. Para consentimiento de intervenciones quirúrgicas. Para seguimiento de pautas alimenticias. Para suministro de medicación pautada. C) Si la persona es capaz de expresar su voluntad, deseos y preferencias de manera libre. Esto presupone: i) un conocimiento suficiente de la realidad sobre el acto/s que se ven concernidos ii) que la voluntad no está condicionada o mediatizada por la discapacidad, lo que impediría el desarrollo pleno de su personalidad, iii) que la voluntad se halla exenta de influencias indebidas. D) Si la persona precisa de ajustes del procedimiento y, en su caso de un facilitador. E) Asimismo, el informe deberá definir la intensidad del apoyo. Es decir, si precisa supervisión o asistencia en alguno o varios de los ámbitos concernidos por la necesidad de apoyo, o si en alguna de las citadas áreas se precisa excepcionalmente un apoyo más intenso (de representación) por no ser posible determinar la voluntad, deseos y preferencias de la persona”. ¿Podríais pedirle cita y solicitarlo a su MAP? Así mismo, necesitaremos Informe del Centro, para aportar a los que desde aquí se expidan, en el que también deben contemplarse las cuestiones indicadas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-09-13','Ana: correo-e de Juanma, hermano de José Blás (jmcl1966@hotmail.com // 687 819 309) al ctutelar@: "Buenos días Ana, soy el hermano de José Blas Cañas, la última vez que hablamos por teléfono me pediste que hablara con el centro ocupacional de Jose (Down) para que emitieran un informe recomendando su entrada en una residencia, finalmente he podido hablar con la psicóloga del centro pero me dice que ella solo puede dar fe de lo que ve día a día, y el problema es que Jose es como el Dr Jekyll y Mr. Hyde, en casa a solas con nuestra madre se vuelve un tirano pero en el centro tiene un comportamiento ejemplar - como siempre lo ha tenido -. Si ella refleja lo que ve, ese informe no va a ayudar porque solo puede decir "la familia me cuenta tal y cual pero en el centro ..." , aparte de que ella sigue pensando que lo mejor para Jose es un piso tutelado (aunque luego me reconoce que es practicamente imposible). En fin, que no tenemos informe de Down."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-09-14','-Amalia , hablo con Mamen de la R.M . ,no hay TS , ella hace alguanas funciones Tf 924490186 Se está adaptando bien, ha dejado la silla de ruedas y ya va con andador. Me va a enviar informes médicos y solicitud valoracion dependencia para que yo termine de cumplimentar y registrar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-09-14','-TF PADRE ALMUDENA . ANTONIO 622442705 Me llama para informar sobre la relacion de su hija con M.Angel .A éste lo trató el Dr.Alí en el CSS , le dijo que era un psicopata y que disfruta hundiendo a la gente . Es agresivo , frio y calculador. Ha seguido a su hija , ayer estuvo hasta las 24.00 en el parque detrás de la basilica de Sta. Eulalia en Mérida y no fue a comer. Los vió entrar en varios bares. Cree que Almudena solo funciona si se le quita la asignación economica como sancion. Tiene miedo a que se vuelva a repetir la historia. Hablo con CSS y con CRR .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-09-21','Ana: Envío correo-e a Julio, Aux. CTAEx: "Te envío oficios solicitando informes relativos a JOSÉ MANUEL ROMERO MEDIAVILLA, para remitir junto a documentación indicada y adjunta a: - Centro Salud - Equipo Salud Mental"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-09-21','TERESA Ayer he recibido llamada de Mª Jesus. Os pongo en situación Mª Jesus tras alta en piso supervisado de salud mental se fue a vivir con su tía, posteriormente se fue con un chico el cual ella dice que era su novio, tuvo problemas con el y se fue a vivir con su padre. Al poco tiempo me indica que ha vuelto con su novio que está viviendo con él y que esta embarrada, ella esta super feliz con esta nueva situación Bueno pues ayer me llama que ha denunciado al novio por agresión. Se ha buscado una abogado ha tenido un juicio y al novio le han puesto una orden de alejamiento. ( de esto parece ser que desde el juzgado no nos han informado) Ella ahora esta viviendo de nuevo con su tía y está planteándose irse a la casa de la mujer en Badajoz para estar más alejado del novio hasta que se tranquilice la cosa. Ella quiere recuperar su capacidad, la verdad que se encuentra muy bien acude a sus citas y toma la medicación. Ademas es super autónoma ( a la vista esta) hoy por hoy no tiene sentido que tenga medidas de apoyo (no se si la revisaran pronto) Esta preocupada porque teme que le quiten a su hijo por esta bajo la comisión tutelar y por todo lo que ha pasado con el novio. ME pregunta si es buena opción irse a la casa de la mujer, que si eso va a repercutir y le van a quitar a su hijo por estar alli…. No se que respuesta darle, entiendo que si ella esta bien estable con informe del psiquiatra que avalen que puede cuidar del niño no tienen por qué quitárselo no? A ver si me podéis dar un poco de luz con este caso y si consideráis que tenemos que intervenir de alguna manera…. Desde el punto de vista de lo social ella se mueve perfectamente por los recursos y sabe buscar la ayuda que necesita, además tiene el apoyo de la familia y administra bien su dinero con lo cual no veo que tenga que hacer ninguna intervención con ella a nivel social. Veo oportuno que revisen su sentencia porque a mi juicio no necesita tener ninguna medida de apoyo…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2023-09-21','miguel, hablo con servicio de sanidad animal de la Consejería de Agricultura y envío email a Tere y Maite (Secc Social): Buenos días, tras consultar a la multa en servicio de sanidad animal de la Consejería de Agricultura, me confirman de palabra que han estimado nuestras alegaciones y que van a archivar la multa, pero que enviarán a alguien a comprobar si ya no tiene cerdos, y otros animales, ya que él no puede tener animales sin estar autorizado por esta Consejeria de Agricultura. Ya le he comentado que es persona tutelada y que no ejercemos funciones de guardador de hecho. Para que no tengan problemas quienes vayan a visitarle para hacer las comprobaciones necesarias sobre el terreno, sería necesario que Tere cuando hables con él le vayas informando que no puede tener animales sin autorización de dicha Consejería de Agricultura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2023-09-21','TERESA ME ENVIA LUSIA TRABAJADORA SOCIAL DEL SASSB DE LA FUENTE PRESUPUESTO PARA UNA OBREA DEL TEJADO DE DIERGO POR IMPORTE DE 24.OOO€ ENVIO ESCRTIO AL SERVICIO TECNICO DEL AYUNTAMIENTO PARA QUE VALOREN LA NECESIDAD DE DICHA OBRA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-09-20','TERESA LLAMO A JULI TS DE ALCUESCAR PARA PREGUNTAR POR LA CONSULTA AL ECCA DE CACERES ME COMENTA QUE LLEGO BIEN, DESDE CACERES PLANTEAN QEU HAGAMOS DERIVACION A CASTUERA PARA SEGUIMIENTO LE COMENTAMOS A JULIA POSIBIIDAD DE QUE LE GUARDEN LA PLAZA Y NOS DICE QUE ESTA COMPICADO PORQEU ESTA ERA SU SEGUNDA OPORTUNIDAD PABLO MANIFIESTA QUE QUIERE VOLVER AL CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2023-09-21','Ana: Correo de Felisa Custodio, TS CAMF-Alcuéscar (trabajadora_social_alcuescar@imserso.es): "Estimada Ana, ya he hablado con Carmen y se ha comprometido a reducir los gastos de parafarmacia en la medida que se pueda. Por otro lado, ya se ha dado cuenta que el teléfono ha sido dado de baja el contrato por lo que mañana va a ir a una tienda de Vodafone a comprar una tarjeta de prepago por importe mensual de 20 euros."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2023-09-21','TERESA CON RESPECTO A LA MULTA DEL SEPRONA Buenos días, tras consultar a la multa en servicio de sanidad animal de la Consejería de Agricultura, me confirman de palabra que han estimado nuestras alegaciones y que van a archivar la multa, pero que enviarán a alguien a comprobar si ya no tiene cerdos, y otros animales, ya que él no puede tener animales sin estar autorizado por esta Consejeria de Agricultura. Ya le he comentado que es persona tutelada y que no ejercemos funciones de guardador de hecho. Para que no tengan problemas quienes vayan a visitarle para hacer las comprobaciones necesarias sobre el terreno, sería necesario que Tere cuando hables con él le vayas informando que no puede tener animales sin autorización de dicha Consejería de Agricultura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-09-21','Amalia : se presenta en el SEPAD Mérida el novio , Jose , 613135997 para hablar sobre el traslado del centro a su casa .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-09-21','TF madre de Juana ; Mª Rosa 641563790 TF JUANA PALOMO 632276309 La madre vive en los grupos SEPE del Gurugú . Tiene 1 hab. para ella , habría que comprar un cuarto . Vive allí un hijo pequeño de 14 años Mª Rosa tiene 59 años , está trasplantada de riñón percibe PNC Inv.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-09-21','-Amalia , estoy pte. de la respuesta del centro para que se marche a su casa y la respuesta de Manuela para dar CO para gestionar o no el traslado del centro a casa de la madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-09-21','-Amalia : se le sube asignacion en cuenta peculio de 260€ a 300€ mensuales .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-09-22','TERESA Pues ya le comenté a la asistenta de igualdad y van mañana a llamar para solicitar el recurso de la casa de la mujer Te paso ahora el número de mi abogada 618 10 57 43 se llama Gemma. Te iré comentando los cambios y avances te agradezco muchísimo todo en lo que estás ayudándome.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-09-22','Ana: En relación al correo de Carol, Directora de CRR-Plas (direccion.crrplasencia@grupo5.net): "Demanda desde la semana pasada la compra de un teléfono movil, cuyo precio gira en torno a los 400 €. Tenía dos moviles, pero la semana pasada él verbaliza que uno se le ha roto y el otro no le ofrece las prestaciones que él necesita para realizar sus videos. No nos queda muy claro cómo pero ayer nos informa que el segundo movil también está roto. Solicita usar el dinero extra (el de aqui en el CRR) para la compra de este dispositivo. Desde el centro entendemos que tener un móvil para él es importante y útil. Teniendo en cuenta que Paula está de baja, consideramos que la compra está justificada y lo vincularíamos a su regalo de cumpleaños y el buen uso/cuidado durante al menos 2 años. Ya nos decís que os parece..." ·························· Respondo: "...me parece bien vuestra propuesta. Puesto que lo vincula a su cumpleaños y la compra la realizará con el extra anual de este 2023 (del que ya dispone en el centro) por mi parte no hay inconveniente. Pongo en copia a Alberto, Jefe Secc. Económica y subrayo en verde en el hilo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-09-22','Ana: En relación al coreo de Carol, Directora de CRR-Plas (direccion.crrplasencia@grupo5.net): "La salida que plantea realizar es la semana del 25 al 29, coincidiendo con el posible nacimiento de su sobrina. Tal y como se acordó en la subcomisión, habría pasado un mes desde la ultima incidencia autolesiva. Por lo que según el documento de TMG que se realizó podría realizarse este viaje. El próximo jueves 21 tiene cita con su psiquiatra, el cual también valorará. Por nostras, no hay ningun problema o incidencia que no recomiende este viaje. Respecto al teléfono movil, tal y como le indicasteis vosotros no existe una urgencia inmediata para adquirir uno nuevo. En cuanto al libro que quiere editar conjuntamente con Ceferino, desde el CRR no se ha realizado apoyos o seguimiento respecto a esta elaboración. Consideramos que este libro no es el resultado de un trabajo continuado, estructurado y con esfuerzo por parte de los dos. Por lo que consideramos que estaría bien aplazar esta edición hasta que puedan perfeccionar y/o mejorar el contenido del mismo" ··············································· MI RESPUESTA: "o Si el Psiquiatra ayer no vio inconveniente, de acuerdo, que vaya al pueblo en las fechas que teníais previstas. ¿Podéis confirmárselo vosotras? Agradeceríamos, eso sí, que por favor nos hicierais llegar el documento de TMG. El día de la reunión había tan mal sonido que hay detalle que a Maite y a mí se nos escapan. Pongo en copia a Ana Benavente, TS ESM. o Para la compra del teléfono móvil que espere al extra anual del próximo año. o Y en cuanto a la edición del libro, conforme a lo que decís, se aplaza la edición. Pongo en copia a Ángel, Asesor Jurídico de la CTAEx, interlocutor con las editoriales, para que esté al corriente. Angel: subrayo en amarillo en el hilo." ········································································································································································································· Conversación con Ana Benavente, ESM: Me envía Documento TGM e Informe del Psiquiatra. Confirma que tal y como se acordó, habiendo transcurrido un mes sin autolesiones, Isabel puede ir al domicilio la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-09-18','Ana: Mai, Jefa de secc. de acceso a RR de Mayores, me comunica que van a darle plaza en la Residencia de Alcuéscar. ··· Me comunica además que no se dio cuenta ni de que era involuntario ni de que estaba a cargo de la CTAEx y ha llamado a la propia Joaquina y a su hija.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-09-19','Ana: Correo de Anabel, TS SSASB - Miajadas (servicios.sociales@miajadas.org): "Acabo de hablar con Joaquina, no es consciente de que se va a ir a un centro y ademas se niega a irse, resulta absolutamente imposible preparar nada de forma anticipada con ella, con lo cual, que vengan los servicios de emergencia se la lleven el dia que sea y que la familia o su hija, yo que se... se encargue de hacerle llegar las cosas. Yo creo que en este caso mi labor ha finalizado. y tambien creo que estamos tardando en protegerla de forma definitiva, cuando se habla con ella te encuetras con una mujer que se siente desesperada abandonada por todos y con imposibilidad de resolver las cosas por sus propios medios."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-09-20','Ana: correo de Noelia, Aux. Adtvo. Secc. RR Mayores (noelia.cuesta@salud-juntaex.es): "Envío copia de resolución de ingreso en centro residencial, de la tutelada Joaquina Mayoral. Se manda copia también al centro, para que podáis concertar el día del ingreso." ···················· Conceden plaza en la Residencia AMADA CORRAL de Alcuéscar. ······················································································ Maite, Jefa Secc. CTAEx, habla con Rosana, Directora RRMM Amada Corral (699 19 81 86). Acuerdan el ingreso para el martes 26.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2023-09-22','Ana: En relación al correo de Tensi, TS (ssbtensi@riberosdeltajo.es) comunicando que Isidro "el lunes 25 de septiembre tiene que acudir a Cáceres a consulta", llamo a la Mancomunidad Riberos del Tajo (927 300 400): me dicen que Tensi hoy está de médicos. ·············· Hablo con su compañera Esther, TS (927 45 00 36): el acompañamiento a la consulta médica lo hará una Concejala, Responsable de los PPTT que se ha ofrecido. El traslado se hará en taxi, con un taxista de confianza que además pone precio cerrado y asequible. *Lo comunico a la secc. ecca. ································· En cuanto al cambio de centro residencial, la semana que viene consultaré a Mayores su posición en las listas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='CRUZ'and apellido2='SANTOS'),'2023-09-22','TELEFONO DEL HIJO QUE VIVE CON ELLA 606 743 715 (Maximino).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='CRUZ'and apellido2='SANTOS'),'2023-09-22','CARNET DE CONDUCIR No posee.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-08-02','Ana: correo de Minerva, TS RR.MM. Cervantes: "Te envío informe del médico del centro, necesita revisión y ajuste de la prótesis dental porque le está ocasionando úlceras. He hablado con Patricia la educadora de Eugenia, me comenta que la semana que viene irá a ver presupuestos y os lo enviará para autorización."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2023-09-22','Ana: Envío correo a Rosa Bravo y Estrella Durán, CSS: "Nos han enviado esta cita de Andrés Silva Bonifacio, que le has llegado al centro de Cabeza del Buey. Al parecer siguen llegando allí. ¿Sería posible que algún día que desde vuestro centro vayan profesionales a acompañamientos/gestiones al hospital, solicitaran el cambio de domicilio para que las citas os lleguen directamente ahí a vosotras?" ···················· Cita de Dermatología: 08/11/23 a las 12h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-09-22','miguel, email de Tere: me reenvia email de la tutelada mariajesusmile@gmail.com> Pues ya le comenté a la asistenta de igualdad y van mañana a llamar para solicitar el recurso de la casa de la mujer Te paso ahora el número de mi abogada 618 10 57 43 se llama Gemma. Te iré comentando los cambios y avances te agradezco muchísimo todo en lo que estás ayudándome. ------------------------------------------------- Llamo a la abogada quien me da su email y le envío la documentación de incapacitación de la tutelada: gemmaalvarezmar@gmail.com Buenas tardes conforme conversación telefónica adjunto resoluciones de incapacitación, nombramiento y aceptación del cargo de tutor a favor de la Ctaex, junto al certificado de discapacidad. -------------------------------------------------------- Envío email a Tere con lo hablado con la abogada Gemma: Buenas tardes, he enviado un email a la abogada Gemma, tras conversación telefónica remitiéndole toda la documentación sobre incapacidad, nombramiento y aceptación del cargo a favor de la Ctaex. Me comenta que el procedimiento no está finalizado, ella puso una denuncia y han dictado la medida preventiva de orden de alejamiento, con lo que el juicio todavía no ha sido. La semana que viene estaré al habla con la abogada para que me informe con más detalle de todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2023-09-22','TERESA TERE: ACEPTAMOS MODIFICAR AYUDA DOMICILIO. COBRA: 200,56 €/MES PAGA: 480 €/MES A PARTIR DE 01/10/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-09-22','Ana: Llamada de Mai, Jefa Secc. Acceso RR Mayores (68496): me informa de que se le concede a Eugenia plaza por traslado a la Residencia de Hervás. ················ Aún no está lista la resolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-09-22','Ana: Llamo a María, hija de Joaquina (871 114 458): Finalmente ella contratará servicio puntual de la empresa de SAD que ha atendido este verano a su madre para que acompañen a Joaquina el martes cuando acuda el 112 a buscarla. Intentarán ir el día antes a preparar las cosas. Acudirán la empresaria, Almudena (678 295 726) y la Auxiliar que tuvo. ···························· Llamo al 112 ··········· Envío mail con escrito-solicitud de internamiento involuntario para el martes día 26 a las 9:00 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-09-25','Ana: envío correo a Minerva, TS del C.R. Cervantes (minerva.salvador@salud-juntaex.es): "dos cosas: 1- De este correo que me enviaste, sobre prótesis dental, ¿se ha llegado a hacer algo? Las compis de la sección económica me dicen que no llegamos a recibir presupuesto y con el fin del programa gestionado por Futuex… tampoco lo hemos recibido por esa vía. 2- Me llamó el viernes Mai, Jefa de Sección de acceso a recursos de mayores para comunicarme que le conceden plaza por traslado en la residencia de Hervás. Creo que aún no lo han comunicado a la Residencia porque no estaba lista la resolución." ··································································································································· Correo de Minerva, TS CR Cervantes: "Ya he hablado con la directora de Hervás, hemos concretado el traslado el lunes día 2 de octubre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2023-09-25','Ana: Estrella, Aux. Adtvo. CTAEx, me informa: Se ha aprobado presupuesto de clínica dental (inicialmente eran 1090€, pero al extraerse las piezas correspondientes en la Seg. Soc. (10 extracciones), el presupuesto se reduce a 640€, en cocepto de PRÓTESIS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-09-25','Ana: Reenvío a Sonia Bernabé - TS y Directora - Asindi (trabajosocial@asindi.e.telefonica.net) correo de Inés, Adtvo. CTAEx: "Os traslado citación para médico forense el 02/10/2023, a las 11:45 h. de Don Justo Hernández Castaño, referente a la Revision de Medidas. Lo manda Escalona. ..." Solicito realicen acompañamiento desde el centro.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-09-25','Ana: Reenvío a Sonia Bernabé - TS y Directora - Asindi (trabajosocial@asindi.e.telefonica.net) correo de Inés, Adtvo. CTAEx: "Os traslado citación para médico forense el 02/10/2023, a las 11:45 h. de Don Justo Hernández Castaño, referente a la Revision de Medidas. Lo manda Escalona. ..." Solicito realicen acompañamiento desde el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-09-20','Ana: Correo de Sonia Bernabé, Asindi: "el viernes 15 regresó Justo Hernández de la excursión. Tanto él como sus compañeros vinieron muy contentos. El sábado algunos de los participantes de estas vacaciones tenían síntomas y se les hizo la prueba del COVID. Justo es contacto estrecho de positivos y estamos controlándole por si fuera positivo en unos días. Te cuento todo esto porque vamos a retrasar el viaje para ver a su familia hasta el próximo viernes 29, y así evitamos que pueda ser positivo y contagie a su familia o la persona de Cruz Roja que le lleva. Su madre, a pesar de que tiene muchas ganas de ver a sus hijos, lo entiende. Voy a informar a la conductora de Cruz Roja."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-09-25','Ana: Llamada de Francisco, le han echado de Centro Vida - Cáritas. Ahora pernocta en un piso Okupa de Cáceres. ··········· Acude a comer al comedor social. ········ No quiere volver a C. Vida. ········ Ya pidió a Pilar Martín, TS ESM, que le derivaran al Piso Supervisado de Almendralejo. ··················· Mañana tiene cita de Psiquiatría en el ESM. Le acompañará su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-09-25','Ana: Llamada de Miguel Ángel. Sigue pernoctando en la casa Okupa. ········· Acude a comer al Comedor Social. ·················· Acudirá al IMAS para solicitar la R.E.G. ·············· Dice que tiene una causa pendiente. Acordamos que nos enviará el documento del juzgado a través de la T.S. del comedor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-09-25','Ana: Noelia, Aux. Adtvo. de la secc. de acceso a recursos de mayores, me envía RESOLUCIÓN DE TRASLADO a PATRONATO RESIDENCIA DE MAYORES DE HERVÁS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-09-22','Ana: Llamada de Ana Benavente: Javier ya tiene tarjeta nueva de telefono: 641 08 64 09. ··········· Del alojamiento no le ha confirmado nada, le dirá el lunes. ············ Por otra parte le ha informado que se ha comprado 3 chándal y 4 camisetas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-09-25','Ana: Correo de Ana Benavente, TS ESM (anamaria.benavente@salud-juntaex.es): "Javier Agudo ha encontrado piso para compartir. A partir de mañana se marchará, por lo que duerme esta noche en el hotel y desayuna mañana . Ya no se quedaría a la comida de mañana. Cualquier cosa me llamas." ························ Tras llamar a Javier (641 08 64 09), respondo a Ana Benavente: "Gracias por informar. Acabo de llamarlo (641 08 64 09) y me dice que aún no ha encontrado nada, que está buscando… de todas formas que para esta noche buscará algún hostal/pensión más económico que en el que ha estado." ················································································· Tras leer correo de Jenaro García-Arreciado, Psicólogo del CRPS de Plas (jjgarcia.sanmiguel@hospitalarias.es / 927 427 152): le llamo por teléfono. No han vuelto a saber nada de Javier y muestran interés y preocupación. Les parece una persona bastante funcional. Le facilito el nuevo número de Javier y acordamos que si vuelvo a hablar con él le propondré que vuelva a pasar por allí cualquier día en horario de mañana. Tanto él como su compñaero estarán encantados de atenderle.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LORENZO'and apellido2='FERNANDEZ'),'2023-09-25','EXITUS Falleció el 24/09/2023, a las 3 Hras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-09-20','Ana: Icíar me confirma que no ha perdido 40€, por lo que fuera, sólo retiró 50€ en lugar de los 90 de asignación. ··········· Realizará autorización para que pueda retirar los 40€. ···· Podrá acudir entre mañana y pasado (21-22 de sep)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-09-22','Ana: Tras intentar contactar infructuosamente con Ángel F., envío un correo a Yessica, TS del Comedor Soc. - Cáritas Plas. (ydearriba@caritasplasencia.org): "Quería preguntarte por ÁNGEL FELIX MAILLO SANTIBAÑEZ, hablé con él el martes y me dijo que acude al comedor a diario, la verdad es que me gustaría que me corroboraras que es así, pues es muy difícil hacer intervención y seguimiento con esta persona. También quería preguntarte si tienes algún medio para contactar con él, pues dice que su teléfono estropeado, es cierto que intento llamarle y da apagado. El caso es que hoy podría ir a retirar al banco un extra de 40 € que solicitó y no sé cómo comunicárselo. Si fuera posible que se lo comunicaras o supieras algún otro modo para que yo pudiera contactar con él te lo agradecería." ···························· Respuesta de Yessica, TS Caritas: "Hablé con Ángel Félix hace un momento cuando vino al Comedor a recoger la comida y me dijo que ya había retirado los 40€. Te confirmo que acude diariamente a comer al Comedor Social. Me pregunta si habéis resuelto la ayuda odontológica que solicitó."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-09-25','Ana: Envío correo-respuesta a Yessica, TS del Comedor Soc. - Cáritas Plas. (ydearriba@caritasplasencia.org): "le he preguntado a mis compañeras de la sección económica, sobre el presupuesto para el tratamiento bucodental y aquí no se ha recibido ningún presupuesto de al respecto. ¿Te importaría, si pasa por ahí, decirte que debe enviar el presupuesto al ctutelar@salud-juntaex.es? O bien desde la clínica dental, o bien a través tuya, si a ti no te importa." ···················· Respuesta de Yessica: "Buenos días, perfecto, mañana le indico."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TRINIDAD'and edp.apellido1='SAAVEDRA'and apellido2='PARRA'),'2023-09-25','miguel, vuelvo a hablar con Trinidad que me pregunta porqué no se ha desembolsado el dinero. Le vuelvo a remitir a Ibercaja pues los dos documentos que se pidieron para el desembolso e ingreso se remitieron ya, el último la semana pasada a Nuria, quién ya me informó y yo a la parte económica, a Alberto que se le ingresará la cuenta corriente pero los fondos de inversiones se pondrán a nombre de Trinidad pero no se convertirán en liquido. Me dice que su abogado Antonio Carretero quiere hablar conmigo. Le llamo y le comento lo mismo que a ella, y le indico los teléfonos de la parte económico y social, y el email de ctutelar, ya que ella insiste que se desbloque y convierta en liquido los fondos de inversion. Me comenta que va a solicitar la remoción a favor del hijo de ella-------------------------------------------------------- Envío email a la parte económica Alberto y Estrella y la parte social Tere: Hola, como sabéis la curatelada heredó de su expareja y tramitó su herencia al completo (notaria, impuestos e inscripción en registro de la propiedad) sin consultarnos y por tanto ocultando que estaba curatelada. Como ya está todo inscrito, sólo quedaba el desbloqueo de las cuentas de Ibercaja y ponerlo a nombre de ella, única heredera. Pues bien, Ibercaja nos pidió firmaramos unos documentos para que se le pudiera ingresar ese dinero, el último de ellos lo envié a Nuria (Ibercaja) la semana pasada. Por tanto Ibercaja está apunto de poner a nombre de Trinidad la cuenta corriente y los dos fondos que había de su expareja. Trinidad me ha insistido esta mañana por teléfono y tras lo cual me ha llamado su abogado Antonio Morcillo para preguntarme si tal como les ha dicho Ibercaja nosotros no vamos a hacer efectivo esos fondos. Ya le he comentado que la nueva situación tras el ingreso de la herencia de su expareja y por tanto las cantidades a recibir ella es una cuestión que tiene que tratar con la parte social y la económica, para lo cual le he dado vuestros teléfonos de contacto y el email de ctutelar al abogado. Este abogado va a solicitar ya la remoción del cargo a favor del hijo, y ya le he dicho que mientras sea curador la Ctaex se ejercerá el cargo como digan la parte económica y la social y si ello supone no desbloquear los fondos (puesto que va a recibir unos 24.000€ de la cuenta corriente) pues así será. Una vez que se resuelva el procedimiento de remoción que van a hacer, si nombran a un tercero…ya no sería asunto de la Ctaex. Os informo para lo sepáis cuando os llamen porque lo que quiere ella es disponer del dinero en su totalidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-09-25','Ana: Tras hablar Maite y yo con Alberto, Jefe Secc. Ecca., y después con Julia y su madre, envío correo a Alberto: "Tal y como hemos acordado mediante conversación en tu despacho, se autorizan 120 € para que Julia pueda comprarse ropa y calzado, además de acudir al a peluquería, por la boda de su hermana. *Se le puede hacer mediante transferencia bancaria a la cuenta de su madre, como habitualmente, si pudiera ser mañana mismo mejor, pues la boda es el próximo día 29. Por otra parte, informaros que he hablado con ella y su madre y ambas entienden y aceptan, que NO SE LES AUTORIZARÁ NINGÚN OTRO EXTRA DE AQUÍ A FINAL DE AÑO." ············································································ Julia también me cuenta que el día 21 tenía cita con Marisa, TS ESM - Coria, pero que no acudieron porque estaba lloviendo y además su made añade que tiene "las piernas fatal y no puede subir al coche de línea". Le recuerdo que tampoco se les puede dar más dinero para taxi. ····.... Dice que llamaron y aplazaron la cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-09-25','Ana: En relación al correo de Sonia Bernabé, TS y Directora de Asindi (trabajosocial@asindi.e.telefonica.net): "quería comentarte que tenemos preparados los paquetes con la ropa y enseres de Aaron Rosado Alarcón y, vamos a pedir presupuesto para enviarlos, según me dijiste al CAMP de Don Benito. Antes de mandarlos creo que es importante que me confirmes que va a ingresar en este centro para asegurarnos, y en cuanto esté concreto el presupuesto y comprobemos que tenemos el importe necesario pues lo mandamos lo antes posible." ··························· Respondo: "Sí, te confirmo que Aarón irá al CAMP de Don Benito. No obstante, me dijo Estrella, compañera, que habías hablado con ella y eran muchas las pertenencias las que Aarón tenía allí. Yo no sé qué es ni cuánto ocupa, pero ¿sería posible que antes de enviar presupuesto, hablases con la compañera del CAMP, para ver si puede llevar allí todo lo que tiene? No vaya a ser que después de enviarlo vayan a decir que no se puede y lo vayan a tirar… A mí no me importaría llamar, pero como no sé qué pertenencias son ni cuánto ocupa, agradecería que lo hablases tú directamente con ella por si hubiera alguna duda. La TS del CAMP es Toñi y el número del CAMP Las Cruces es: 924 02 15 64. Si allí dan el ok, ya nos podréis enviar el presupuesto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2023-09-25','Ana: Correo de Ángel, A. Jurídico: "Juan José González Carrero, ha heredado de su padre una vivienda en la que dispone del 100% del pleno dominio. Está en Cáceres, C/. Miralrío, 11. La hermana nos ha enviado documentación relacionada con los suministros, seguro y comunidad, para que procedamos al cambio de titular. Al margen de realizar estas gestiones, Juan José vive en C/. Cristu Benditu, nº2, B, 6º-A, de Cáceres, no? Si es así, podemos iniciar los trámites para vender el piso de Miralrío. Enviadme, por favor, la siguiente documentación/Info: Alberto: Saldo y cargos/gastos en su cuenta bancaria. Ana: Pensión que cobra y cuantía." ······································ Le envío certificados de pensiones (Orfandad y PFHC) actualizados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2023-09-26','-Amalia : No se le reconoce dependencia, ha dado un sin grado en la valoracion dependencia en Andalucia. Hablo con Manoli , la TS del ctro. penitenciario , me va a enviar todos los informes para que yo lo envíe al ESM de Caceres para que deriven a CRR por emergencia social . Manoli va a enviar informe por emergencia . Pilar ya es conocedora de todo . Sale en febrero del centro penitenciario . Si no entra en CRR habría que buscar un hostal para que cuando salga tengo un sitio donde ir y que busque luego un piso de alquiler .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2023-09-26','TERESA Me llama Jorge Moral de prestaciones para preguntar por Beatriz, quiere saber si está hospitalizada, le he dicho que está en UME, es por el tema de la ayuda a domicilio. Le han puesto en suspenso hasta que vuelva a su casa. Si quieres ponerte en contacto con él, su teléfono es 68532.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-09-26','Ana: Envío correo a Teresa Nogueira, TS NOVAFORMA (trabajadorasocial.novaforma@gmail.com): "...Azucena nos pidió que se solicitara centro residencial, dijo que la conveniencia se había deteriorado más y que Juan José aceptaba el ingreso. Esta cuestión también la había abordado con él la educadora del Programa de Apoyo Comunitario de Futuex. Finalmente hemos presentado solicitud de ampliación de centros. Además de NOVAFORMA se ha solicitado Plasencia, Alcántara y Mérida. Pero no estamos seguras de que llegado el momento vaya a aceptar el ingreso. ¿Podéis confirmarnos que Juan José acepta este ingreso? Te lo pregunto, más que nada, porque el Juzgado ha iniciado procedimiento de revisión de su sentencia. Nos requiere recabar y presentar Informes Médicos, NO nos piden Informe Social, pero me estaba planteando que podíamos presentar uno tuyo igualmente expresando la necesidad de este ingreso (si aún consideráis que existe esta necesidad). Recuerda que en Informe que nos facilitaron desde el IMAS, en ningún momento plantea esta opción. Dado que vosotros sois quienes más le conocéis y desde vuestro recurso se trabaja con él a diario, creo que vuestro criterio es fundamental para que lo tengan en cuenta en el Juzgado. Ya me dices cuando puedas. Y si lo tienes a bien, esperamos dicho informe para presentarlo en el Juzgado." ······························································································································································································ Envío correo a Julio, Aux. Adtvo. CTAEx: "adjunto oficios solicitando INFORMES respectivos al: - Centro de Salud – Aldea Moret - ESM – Cáceres Para remitir por registro" ································································································································································································· Cuñada de Juanjo: Azucena Merino López (azuydavid153@gmail.com // Tlf. 625 367 302)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2023-09-26','-Amalia : contacto con Roberto , Arquitecto técnico y le informo que han hecho la obra sin la licencia solicitada. Me pide que le reenvíe el email de la sobrina con las fotos del antest y después de la obra y el presupuesto .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-09-26','-Amalia , hablo con Pepa , no entiende nada , niega las medidas de apoyo , quiere tener acceso a todo su dinero. Habla de irse a Madrid con una prima a vivir .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-09-26','-Pido a su hija que nos pase por email el Nº cuenta donde abonar el agua . No se puede domiciliar , se abonará así todos los meses. Que me lo pase por email y se abona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-09-26','Ana: Envío correo a Toni-Futuex: "En relación con Ventura Gómez García, he hablado con la tienda de MOVISTAR a la que asiste habitualmente Ventura. Me informan que este verano estuvo allí Patricia, Educadora, un día con él y se llevó anotada toda la información sobre sus contratos de telefonía, la baja de ciertos servicios, el cambio de contrato a la tarifa más económica…) y que les dijo que nos lo haría llegar, pero de esto no hemos recibido nada. Puedes comprobar si Patricia te facilitó esta información y hacérnosla llegar, por favor?" ··················································································· Conversación con Cristina, Tienda de Movistar habitual de Ventura (927 289 002). Ventura solicitó cambio de contrato a uno más económico y más sencillo el día 16 de agosto. *Gestionaron también la baja de otras 2 líneas de telefono más seguro que tenía contratadas. ·········· Además tiene contratada una ALARMA desde 2020 (al parecer le da miedo que alguien entre en su casa). **Debe 4 facturas de 2 meses, 2 por cada mes (unas de líneas ya dadas de baja, más seguro) y otras dos de sus serv. habituales. *Le han dejado un PACK de 84,90€ que incluye 30 Gb + Llamadas Ilimitadas + CINE + TV Autonómicas. ······· A parte de esto, abona un seguro de 7,63 €/mes por rotura de terminal por caída (Hasta junio de 2024, que hace el año no se podria dar de baja) + Renting de Ordenador de 9€/mes. ····················· Cristina intentará enviarnos las facturas y nuevos contratos desde el móvil de Ventura al ctutelar@. ··············· *Le van a cortar la líneas, de hecho ahora ya sólo pude recibir llamadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-09-26','Ana: Llamada de May, Jefa Secc. Acceso RR. Mayores (68496): le conceden plaza a Flora en una de las residencias de mayores que había pedido, Almaraz. ·························· Comunico a Carol y Beatriz del CRR, para que me corroboren que Flora aún quiere ingresar en Centro d Mayores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2023-09-26','Ana: Reenvío a A. Jurídicos, correo de Ana Castillo Foronda TS - FUNDACIÓN AUTISMO SUR (teayudamos@autismosur.es): "Te envío un documento que tiene que firmar el tutor de Alexandru, para solicitar las nuevas medidas de apoyo judicial y revisar su tutela. Te comento que Alexandru está muy bien, muy estable, y realizando muchas actividades. Sin ningún problema de salud y a la espera que le realicen una analítica de revisión. En el momento que tengas el documento, me lo haces llegar." para que ellos den respuesta. ································································································································································································· Respuesta de Ángel, A. Jurídico: "En relación con su correo electrónico le indico que, de conformidad con la Disposición Transitoria sexta de la Ley 8/2021, de 2 de junio, por la que se reforma la legislación civil y procesal para el apoyo a las personas con discapacidad en el ejercicio de su capacidad jurídica y con la Nota de Servicio 3/2022, de fecha, 24 de agosto de 2022, emitida por la Fiscalía Superior de Extremadura, las revisiones de medidas de poyo deben adoptarse conforme a las previsiones de las conclusiones alcanzadas en reunión conjunta del CGPJ y FGE de 9 y 10 de junio de 2022. En dichas conclusiones, se señala expresamente, que la iniciativa para la revisión de medidas, debe ser judicial. En este sentido, el Ministerio Fiscal, conforme a la conclusión 4ª de las conclusiones mencionadas, llevará a cabo las solicitudes de revisión, en el plazo máximo de 3 años, desde la entrada en vigor de la Ley 8/21, de 2 de junio. Agradeciendo su colaboración," ··································· Nuevo correo de Ángel, A. Jurídico a Francisco M. Sánchez, Abogacía: "En relación con este expediente, ¿puedes indicarnos en qué estado se encuentra? ¿Asumió la Fundación Malagueña de Tutela el cargo?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2023-09-26','-Amalia : le entrego a Cati 3 copias del : -contrato de alquiler que no estaba firmado , se le ha puesto el sello de la CTAEX y Beni lo firmará. -anexo a ese contrato cambiando el nº 1 por el nº 4 a la vivienda. Con todo ello Cati irá al Ayto para empadronarse allí y después renovar su DNI. Uno de los originales es para la CTAEX , le pido que se lo quede ella y se lo entregue a la D. Tutelar que nos lo remitirá. Otra copia es para Beni .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-09-26','-Amalia : envio al centro original del consentimiento informado par depilacion laser .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-09-26','Ana: TRASLADO DE JOAQUINA A ALCUESCAR - INGRESO INVOLUNTARIO ························ Llamda de Rosana, Directora RRMM Amada Corral (699 19 81 86) y María, TS Alcuéscar: Joaquina ya ha llegado al Centro, pero tan alterada que la Médica del pueblo ha dispuesto que trasladen a Joaquina al Hospital de Cáceres. ······································································································ Llamada de María, hija de Joaquina (871 114 458): la Aux. de la empresa que ha contratado, Almudena, se ha implicado mucho. Esta tarde llevarán la maleta a la residencia con ropa y enseres de Joaquina. ···· Según dice ha sido la propia MAP la que ha alterado a su madre. ······· Ella había bajado de casa tranquila gracias a la implicación de la Enfermera y la Aux. ············ Le informo cómo ha llegado a Alcuéscar y que la trasladan al Hptal. ··································································································································································································· Lamada de Mª Carmen, TS UHB HSPA (56283): confirma que a Joaquina la dejan ingresada en la UHB. ·········································· Llamo a su hija para informarle pero no obtengo respuesta. ················· Envío correo informativo a Rosana, Directora Res. ····························· Correo respuesta de Rosana: "nos llamo la hija al centro para hablar con nosotros y nos explico que habia estado hablando con vosotros y ya me dijo lo del tema de la Ropa, nos llamaron del Hospital y estuve hablando con la enfermera y el Psiquiatra y les explique un poco la situación que se nos dio hoy, al igual que les puse en antecedentes de la situación en el Domicilio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-09-27','Ana: Reenvío a Alberto y Maite, Jefes de Secc. CTAEx, el correo con las facturas impagadas y el nuevo contrato de MOVISTAR, que hemos recibido en ctutelar@ ······················ Tendremos que reunirnos para valorar y tomar decisiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2023-09-26','Ana: Correo de Maite, jefa secc. a Emilia, TS CSS-Plas: "Buenos días Emilia, ¿ Podrías remitirnos informe de psiquiatría?. Nos vendría bien tenerlo en su expediente. Respecto a la venta de la casa, ¿sería posible que vosotros hablarais con él? , sino dinos cuando podemos llamarlo para planteárselo, si es posible a tu despacho, para que puedas aclararle cualquier cosa que pueda necesitar o recabar su consentimiento por escrito, si dice que sí a la venta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2023-09-26','Ana: Teresa, TS NOVAFORMA (trabajadorasocial.novaforma@gmail.com), nos reenvía correo de su compañero Javier, Psicólogo - Serv. Res. (tecnicosuperior4.novaforma@gmail.com): "En relación a nuestra conversación de la semana pasada sobre que las hermanas de Felipe: estaban muy preocupadas porque les habían informado desde La Haba de que la casa de Felipe estaba abierta y querían saber qué estaba haciendo la comisión tutelar al respecto (en resumen). Me dijo que no le dijera nada a Felipe de su llamada para que no se pusiera nervioso, pero ella misma el mismo día o al siguiente se lo dijo ella misma. Ayer volvieron a llamar y hablaron con Patricia. Preguntaron que si no se estaba haciendo nada desde la comisión tutelar y que no han tenido noticias sobre lo que nos preguntaron la semana pasada. Por lo visto les han vuelto a avisar de que la casa está abierta. Se lo han debido decir de nuevo a Felipe (con lo que conlleva para su salud física y mental darle este tipo de información sin filtros) y éste, por su cuenta ha buscado un cerrajero y lo ha mandado a su casa. Por mediación de Patricia, hablan con el cerrajero para que, antes de hacer nada y visto el trabajo necesario, envíe un presupuesto antes a Residencia o llame por teléfono. Estamos, por tanto a la espera." ································· Comunico a Teresa mi gestión de este verano, por la que no hemos vuelto a obtener respuesta. ········ *Nos enviarán el presupuesto del arreglo. ·············· En cuanto a la venta de la casa que plantea, le recuerdo que al ser las sobrinas también propietarias y no querer vender, tampoco podemos hacerlo. ·································· Nuevo correo de Teresa: "cuando hables con Angel por favor vamos a valorar también si el puede renunciar a su parte de la casa y por supuesto que deje de pagar suministros y demás ... es que es la historia de no acabar y a le le supone un problema de estrés y ansiedad constante." ··········· Respondo "¿Él quiere renunciar a su parte?" ················ Responde: "lo tenemos que valorar porque es una situación insostenible" ·············· Le indico que si él no expresa su deseo de renuncia a la propiedad no podrá hacerse.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-09-26','Ana: Correo de Sonia, ASINDI: "he hablado con la Trabajadora Social del Camp de Don Benito y, me dice que le podemos mandar todo y ellos al organizar ya ven si hay enseres que no le sirvan,.... Entonces, a no ser que me digas lo contrario, se lo vamos a mandar todo." ····························· Recuerdo que deben enviar presupuesto previo. ································································································································································································· Aarón está ingresado desde el día 14 de Septiembre en el CAMP, de momento, está bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-09-27','Ana: Envío correo a Julio y a Teresa, CTAEx: "Comunico cambio de domicilio, para que, cuando puedas, procedas al cambio en la base de datos. AARÓN ROSADO ALARCÓN ingresó el día 14 en el CAMP de Don Benito. Tere! De momento, sigo yo pendiente. Cuando pase el periodo de adaptación (a mediados de octubre, si todo va bien), ya puedes continuar con el seguimiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-09-26','Ana: Correo de Minerva, TS del C.R. Cervantes (minerva.salvador@salud-juntaex.es): "La directora ha decidido que se va a llevar a Eugenia con la furgoneta del centro si os parece bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-09-26','Ana: Correo de Esperanza, Enfermera de la Res. Antonio Zapata - Santos de Maimona (atsrmayores@lossantosdemimona.org), comunica que Arturo necesita ropa (ha cogido peso) y un andador nuevo (el suyo no se puede arreglar). ················· Indico que deben remitir presupuesto a ctutelar@','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-09-27','Flora Gutiérrez García, domicilio en C/Gabriel y Galán, 7. 3B. Se realizó visita a su domicilio, solicitando copia de nueva llave de entrada al portal. La compañía de seguro, después de varios contactos telefónicos, pasaron a valorarlo, pero informaron que era debido a un problema de la vecina del piso superior (afectación en el techo del cuarto de baño).el piso de Flora no tiene luz, de lo que ya se informó en su momento. La vecina no tenía seguro, y no quiso saber nada del caso. Esta gestión se realizó hace años, pero al final la educadora, permaneció con la llave, en una caja de custodia en la oficina, por si fuera necesario hacer alguna otra gestión. ---------------------------------------- En la proxima reunion recogeré esas llaves para su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='CANCHALES'and apellido2='MALDONADO'),'2023-09-27','Soledad Canchales: domicilio en C/ Regulares Marroquíes, 14 de Badajoz. Desde marzo de 2023, se han realizado dos visitas y varias gestiones de contacto con la empresa administradora de fincas de este edificio (Comunitas en Badajoz). primero nos dijeron que, pasada la Semana Santa, se pondrían en contacto para acometer dicha reforma del bajante general del bloque, que debe acometerse, desde la propia vivienda de Soledad. Pasada la semana santa, nos indican que el fontanero estaba de baja y así nos han tenido todos estos meses, hasta la fecha de hoy que escribe Hugo, responsable de Comunitas para ese bloque de viviendas, para solicitar las llaves y poder iniciar diga reforma, después de varios meses: “Buenos días, soy Hugo de Comunitas, era para ver si podíamos retomar la reparación del bajante en la vivienda de Juana Canchales en la CPP Regulares Marroquíes, 14.” ----------------------------- Se quedarán las llaves hasta que se retome el programa','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PAJARES'and apellido2='TALAVERA'),'2023-09-26','Ana: Desde el PAF Tajo-Salor (programafamilia@tajosalor.es) nos remiten INFORME relativo a SANTIAGO y la situación familiar. ·········· Desde el SSASB no llegaron a enviárnoslo y el inventario se remitió sin él. ············ Archivo en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PAJARES'and apellido2='TALAVERA'),'2023-09-27','Ana: Conversación con Mª José, madre de Santiago (671 605 814): trato de aclararle las dudas que presenta con respecto al funcionamiento de la CTAEx, organización y gestión de gastos. ··················· Santiago no tiene ningún tipo de ingresos, no reúne requisitos para pretación/pensión. ················ Tiene una cuenta compartida con su hermano en la que su madre les ha ido ingresando poco a poco algo de dinero (saldo entorno a 1500€ - La mitad corresponde a su hermano). ························ El padres lleva mucho tiempo sin pasarles la manutención. Va a iniciar procedimientos judiciales para reclarmarlo. ·········· Le facilito contacto de A. Jurídicos al respecto. ··································· Por otra parte, me informa que su hijo está en un proceso de selección para trabajar en el Eroski. Si finalmente fuera seleccionado, nos los comunicará. Sería necesaria, además de la firma de Santiago la de la Vicepresidenta de la CTAEx. ···················································· Su hermano Alexander reside en C. Residencial de Plena Inclusión Vera (Jaraíz de la Vera). ······································································································································································································ Envío correo a Alberto, con copia a los Juridicos, CTAEx, en relación a las 4 cuentas banarias que tiene Santiago y su situación económica: "...No sé si se ha llegado a hacer algo con algunas de estas cuentas. Santiago no tiene NINGÚN TIPO DE INGRESOS, y por lo pronto, según grado de discapacidad, NO CUMPLE REQUISITOS PARA SOLICITAR NINGUNA PRESTACIÓN/PENSIÓN (42% de Discapacidad reconocido). La madre es quién lo mantiene. He hablado con ésta, María José Talavera, me informa que su exmarido hace mucho tiempo que no les pasa nada de manutención. El dinero que tienen sus hijos en la cuenta compartida por ambos, dice que se lo ha ingresado casi todo ella poco a poco, para hacerles “hucha”. Ella estaba de autorizada, pero ya no tiene acceso. **Por otra parte, ella es la Tutora legal de su otro hijo que reside en un centro. Mi propuesta: - Cerrar las cuentas del B. Santander, si no se ha hecho ya (los 20 € que hay en una de ella no sé si se irán en comisiones) - Dividir el saldo de la cuenta compartida, para que cada hermano tenga su parte del dinero en su propia cuenta - Cuenta de Unicaja, no sé si sería la mejor opción para dejar en uso para Santiago y aprovechar que ya está abierta. - Angel y Miguel: no sé si vosotros podréis reclamar al padre la manutención correspondiente. Le he facilitado a la madre vuestros teléfonos al respecto pues ella de por sí va a iniciar procedimiento, pero no sabe como afecta la Medida Judicial de Apoyos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2023-09-27','TERESA En contestación a la llamada que tuviste del padre. Hemos hablado con Juan Jose e igualmente nos manifiesta que quiere cambiarse a otro centro más próximo a la localidad de su padre. También nos dice que se siente agobiado por el compañero con el cual parece que tiene una relación especial. Cuando se le argumenta que por nuestra parte se han hecho cambios (de habitación, taller, actividades, etc.) para evitar que estén juntos, pero ellos siguen manteniendo relación (se busca el uno al otro) Juan José se caya. Este chico tiene un problema de comunicación importante y es complicado saber sus sentimientos y que es realmente lo que quiere. Desde Centro Ocupacional el curso pasado se le ofreció hacer un curso del SEXPE relacionado con lo que a él le gusta y se negó rotundamente a salir de los talleres. En este momento está en el domicilio familiar, regresa el 13 de octubre y volveremos hablar con él, también se le ofrecerá desde CO alguna alternativa de estudios. Así están las cosas, te seguimos informando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='VELASCO'and apellido2='CAPERUZA'),'2023-09-27','Buenos días Amalia, he intentado ponerme en contacto contigo por teléfono para informarte de la agresión física de Fernando Velasco Caperuza a otro usuario en la Residencia de Mayores de Monesterio. La víctima ha interpuesto una denuncia por lo que será citado para un juicio rápido. Adjunto te envío el parte de lesiones y la denuncia. Estamos en contacto. Gracias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2023-09-27','Ana: Tras varios intentos infructuosos de hablar con Mai, Jefa Secc. Acceso RR. Mayores (68496 // margarita.masegosa@salud-juntaex.es) le envío un correo: "en relación con ISIDRO TORRES VILLEGAS, hace unos meses que la CTAEx aceptó el cargo de CURATELA REPRESENTATIVA, pero me informan desde los Pisos Tutelados de Casas de Millán, donde actualmente reside, que tiene solicitado desde hace tiempo ingreso en Centros de Mayores: LOS PINOS, EL CUARTILLO y alguno más. ¿Podríais por favor decirme en qué posición de encuentra en las distintas listas de espera?" ····················································· Respuesta de Mai: "Se encuentra en la posición N.º 22 para "Los Pinos", "El Cuartillo" N.º 62 y "Cervantes" de Cáceres nº 152"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-09-27','TERESA RECIBO LLAMADA DE RUFI POLICIA LOCAL El número de contacto es 664490060. PARA INFORMARSE SOBRE PABLO A NIVEL ECONOMICO LE HE INFORMADO QEU EL DOY 50€ TODOS LOS LUNES QUE ESTAMOS PENDIETNE DE QUE LE VUELVAN A ACEPTAR EN EL CENTRO ME INFORMA QUE JULIA LE HA DICHO QUE SU PLAZA YA ESTA OCUPADA ME CONFIRMA QUE VA A LA FARMACIA A TOMAR LA MEDICACION Y QUE ESTA SIN AGUA COMENTA QUE HA TENDIO QUE LLEVARLO DOS VECES A CASA EN ESTADO EBRIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-09-27','Ana: Correo-respuesta de Teresa Nogueira, TS NOVAFORMA (trabajadorasocial.novaforma@gmail.com): "Hola yo hago un informe sin problema, buen dia"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2023-09-27','Ana: envío correo a Teresa Nogueira, TS Novaforma (trabajadorasocial.novaforma@gmail.com): "CONFIRMADO! LOS SUMINISTROS DE LA “CASA” DE FELIPE ESTÁN TODOS DADO DE BAJA"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-09-27','Ana: Corro del PAF (programafamilia@tajosalor.es) "respecto a Aitor. Nos dice que ha encontrado un centro para desintoxicarse en Montijo, es una asociación que se llama Camino a la Vida, no sé si la conocéis. Nosotros hemos hablado con ellos porque Aitor está dispuesto a irse hoy mismo, nos dicen que han trabajado con otros tutelados pero no nos ha quedado muy claro como funcionan. El coste es de 300e/mes mínimo más los gastos que pueda ir teniendo Aitor. Aitor dice que va a mirar autobuses para irse, que tiene el dinero para el viaje y que se va. Nos decís algo o habláis con Aitor cuando podáis, vale?" ················································································· Mi respuesta: "Pues, tras tratarlo con las compañeras Trabajadoras Sociales, estamos todas de acuerdo en que se vaya e ingrese en el recurso! Puede ser muy buena oportunidad para él, si realmente lo aprovecha. Agradeceríamos que se lo transmitierais vosotras, pues aún me quedan otros asuntos que atender hoy."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-09-27','Ana: Recibimos RESOLUCIÓN del IMAS concedido a Ventura, Serv. TELEASISTENCIA domiciliaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-09-26','Ana: Recibimos RESOLUCIÓN del SEPAD declarando la no aprobación del PIA, de prestación ecca. de SAD, por NO ACEPTACIÓN de la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-09-28','Ana: en relación al correo del PAF (programafamilia@tajosalor.es): "Felisi ha ido al oftalmólogo y tiene que cambiar de gafas, Jesús pregunta si las de ahora no tienen garantía. Supongo que tendrá que pedir presupuestos y demás como siempre, si necesitáis algo nos decís." ······································ Respondo: "En cuanto a la garantía, si tiene que cambiar de gafas por variación en la graduación, no sirve la garantía. Y sí, como siempre, tiene que pedir presupuesto de óptica y remitirlos al ctutelar@salud-juntaex.es a la atención de la sección económica para que el Jefe de la misma lo autorice la compra. Después se abonará mediante transferencia al número de cuenta que indiquen en la óptica." ··················································································································································· Nuevo correo del PAF (programafamilia@tajosalor.es): con dos presupuestos de óptica. Cuando valore Alberto se les confirmará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2023-09-28','Ana: En relación al correo pte. de Lourdes, CTAEx: "recibo llamada de la cuñada de Josefa, se llama Pilar 605974377 Quiere hablar contigo, 1. Explica que su hermano es su pareja hace treinta y tantos años, y que se quieren casar 2. Dice que la vivienda esta en mal estado, y que tienen tres presupuestos para arreglarlo 3. Y también que no pueden sacar dinero." ··················································································· Llamo al Ayto. de Madrigalejo (927 35 40 02), hablo con Anabel, TS del SSASB. *Hará averiguaciones sobre las cuestiones planteadas y me informará al respecto. ················· Por otra parte, expresa que son una pareja muy tranquila, amorosa y que llevan bien la casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2023-09-28','Diego me ha pedido 150€ para la feria de Zafra Le he dado 1oo€, en la conversación telefónica le veo muy alterado a pesar de que ya tiene dinero pide más… el se suele conformar con lo que le damos, está claro que el tener a la pareja en casa le está descompensando. LA auxiliar de ayuda a domicilio dice que lleva una semana muy nervioso y no para de insultar a todo el mundo, que en un año que lleva en la vivienda nunca lo ha visto así. ¿Hay posibilidad de que vaya a verlo el médico a casa?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2023-09-28','Buenas tardes, Amalia. En base a la muy positiva experiencia de los fines de semana anteriores y al deseo de Regina y de la familia en cuestión, se vuelve a solicitar permiso para este fin de semana. Saludos. REGINA REINA LARA, acogida en el recurso sito en C/ Rota 41 de Badajoz y gestionado por Asociación HOFA, disfrutará de permiso en C/ REYES CATÓLICOS 1A VALVERDE DE LEGANES (Badajoz) del 29 de septiembre al 1 de octubre 2023 con Dª MARIA DEL CARMEN GONZÁLEZ CORDERAS DNI 80052778 J quien será responsable de la misma durante este periodo, por considerarse beneficioso para su evolución.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-09-28','TERESA ME FACILITAN DESDE EL PROGRAMA DE FAMILIA LOS TLFNO DE CONTACTO DE LA COMUNIDAD TERAPEUTICA CAMINO A LA VIDA JULIAN PRESIDENTE 657813847, CHARI TRABAJADORA SOCAL 924455058, tienen horario de 9.30 a 13:30h ME COMENTA JULIAN QUE TIENEN LA PLAZA RESERVADA Y PUEDE INGRESAR CUANDO QUIERA EL COSTE DEL CENTRO SON 300€ PARA MANUTENCION QUE LOS PAGAREMOS POR TRANSFERENCIA MAS EL DINERO DE BOLSILLO EMAIL: ARVCAMINOALAVIDA@GMAIL.COM······························································································································································································· Ana: Corro del PAF (programafamilia@tajosalor.es) "Nos comenta Aitor que no quiere el centro de Montijo que quiere el centro de Don Benito, que ya ha hablado con un tal Julián para ingresar. Os pasamos el teléfono 654 91 16 89. El centro se llama Luis Rojo. Dice que se va a ir esta tarde. De todas formas mañana te confirmamos si se ha ido o no."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-09-28','-Amalia : envío email a Jefa de Sección sobre lo que opinan desde el centro la Luz para trabajar con Juana . Recojo y gestiono conforme a respuesta : Vamos a solicitar ya CO, hablamos con la madre para ver como va la habitación y con Juana para decirle que lo estamos gestionando y no explote. No entiendo pq desde el centro están siendo restrictivos. Imagino que lo habrán intentado todo…. firma mayte 2022 -------------------------------------- De Amalia a Maria Teresa Gomez Martin Buenas , acabo de hablar con la TS del Ctro. Ntra. Sra. de la Luz. Se han reunido , la psicologa , TS , Felipe director de Residencia , Segunda , Jesús el Gerente ..para hablar del caso . Me dice que han puntualizado sobre dos asuntos : 1.El de facilitar salidas de fines de semana . No lo aceptan , no están dispuestos a asumir lo que ello va a conllevar por ej. creen que a su regreso el lunes no serían capaces de trabajar con ella. Y en definitiva no se está dando respuesta a lo que ella demanda que es dejar el centro. 2. Teniendo en cuenta la nueva ley , y siguiendo los deseos de Juani , lo que se tendría que facilitar es que saliera definitivamente del centro . ( entiendo que tampoco aceptarían que fuese a CO , aunque ya sabemos que no hay plazas ) Ante ésto, creo que no nos queda otra opción que solicitar CO externo en Aprosuba3 y en cuanto se lo den trasladarla a su domicilio . Hablar con la madre sobre la decisión tomada y ir preparando la habitación. Como no vea que nos estamos moviendo va a ser difícil de contener , desde el centro son muy restrictivos y me temo que se fugue . Aunque ya sabemos que en el domicilio es muy difícil que funcione . ¿ qué opinas ? por escrito no me van a indicar nada , ha sido una conversación telefónica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2023-09-28','Ana: correo aclaratorio de Lourdes, Aux. Secc. Ecca. CTAEx: "los justificantes de este organismo, al menos los cuatro últimos de julio, son de basura y alcantarillado. Y desde julio para adelante no salen más, pero claro, porque no les toca hasta final de octubre mandar el siguiente recibo. Por lo que al final, si que se abona, lo que no tiene es luz y agua."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-09-18','Ana: Correo de Julia, Casa de la Misericordia, adjunta PARTE DE INCIDENCIAS de Sergio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-09-28','-Amalia , tras email recibido de Magdalena , TS del SSASB , solicitando internamiento involuntario en centro , derivo el expediente a los jurídicos junto con el I.social y las fotografias que ha enviado : como continuación al email anterior sobre este caso , os paso toda la información que ha enviado la TS para solicitar I. Involuntario en centro . Este señor es consumidor alcohol . Con Enfermedad Mental Grave , ha sido derivado por el ESM en varias ocasiones a plaza en CRR , pero no se adapta a ninguno . Estuvo en el de Cáceres y en mayo de este año en el de Mérida ( en su expediente tenéis la renuncia voluntaria que presentó y otros informes sociales ) El tema del alcohol hace inviable el ingreso en CRR , además de que se exige la voluntariedad y él se niega a ingresar. Si se pudiera solicitar ingreso en CSS para compensación de su patología , es el único centro cerrado donde al menos tendría que permanecer hasta que el psiquiatra le diese el alta. No acude a consultas médicas, ni de su centro de salud en Atención Primaria ni las del ESM , por lo tanto el Int. Involuntario solicitado por el sistema sanitario tampoco sería posible. Un saludo. ----------------------------------------------- Se lo comunico también a Magdalena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-09-28','Ana: Tras reunirme con Maite y A. Jurídicos, envío correo a Julia, Coord. Casa Misericordia (casadelamisericordia.alcuescar@gmail.com): "los justificantes de este organismo, al menos los cuatro últimos de julio, son de basura y alcantarillado. Y desde julio para adelante no salen más, pero claro, porque no les toca hasta final de octubre mandar el siguiente recibo. Por lo que al final, si que se abona, lo que no tiene es luz y agua." ··········································· *Respuesta de Julia: "La próxima consulta es el 4 de octubre. Por el momento, está mejor, le subieron un poquito la medicación y está más tranquilo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2023-09-28','Ana: Llamo a Tensi, TS, al Ayto. de Pedroso de Acim (927 30 03 30) pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-09-28','Ana: Recibimos RESOLUCIÓN PIA le conceden "PLAZA para el Servicio de CENTRO RESIDENCIAL PARA MAYORES en el centro RESIDENCIA DE MAYORES "CATALINA CURIEL", sito en Almaraz. ························· Comunicado al CRR. Dicen que Flora se pondrá muy cotenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2023-09-29','Ana: Correo de Felisa Custodio, TS CAMF-Alcuéscar (trabajadora_social_alcuescar@imserso.es): "ya tiene Carmen tarjeta pre pago del móvil. Os adjunto justificante y el actual número de tfno. que le han dado. En cuanto al informe médico que os han solicitado del Juzgado, se lo pedí a Enfermería del CAMF el pasado 15 de septiembre pero aún no me lo han dado. El informe social ya lo tengo hecho, os mandaré los dos juntos." ·············· Reenvío a A. Jurídicos y a Secc. Ecca., por la factura. ······································································· Nuevo nº de Carmen: "663 313 975"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-09-29','Ana: correo de ayer de Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es): "Enrique está demandando comprarse ropa de entretiempo. El Psiquiatra cree conveniente que salga porque le beneficia psicoterapéuticamente. Le ha dicho que 50 euros máximo. Quería que vosotros lo autorizarais también" ······················································································ Mi respuesta: "Entiendo que la salida a comprar ropa será acompañado, ¿no es así? Teniendo en cuanta que el Psiquiatra considera que le beneficia psicoterapéuticamente, por parte del Gabinete Técnico de la CTAEx no hay inconveniente en que así sea." ···················· Respuseta de Estrella: "Sí, va acompañado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-09-28','Ana: Correo de Carolina, Directora del CRR (direccion.crrplasencia@grupo5.net): "Han contactado desde la residencia de Almaraz para el traslado de Flori a la residencia, en un principio hemos acordado el día 4. Me han dado su número de teléfono para que contactéis con ellos para la firma de del contrato y temas bancarios. 927544085 Raquel Por otro lado, informaros que el sábado vamos a realizar un acompañamiento a Badajoz a Flori a su piso ya que lo ha solicitado antes de ir a la residencia. Ella nos confirma que tiene llaves, pero me surge la duda de sí habéis cambiado de cerradura porque en un momento creo que se habló."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ANGEL'and edp.apellido1='IGLESIAS'and apellido2='RODRIGUEZ'),'2023-08-08','TERESA CAUSA BAJA EN CO PLACEAT, DESDE QUE INGRESO EN LA RESIDENCIA NTRA SRA DE LA ASUNCION EN GALISTEO 927452400 SE ESTABLECE 70€ DE DINERO DE BOLSILLO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2023-09-29','Ana: Llamo a Tensi, TS, a Mancomunidad (927 30 03 30): me enviará informe de la consulta médica del lunes. *Al final no hay que abonar taxi porque el Alcalde le traslacó en su propio vehículo. ································ En cuanto al cambio de centro, ahora está más lejos en las listas de espera de los centros solicitados. ········· NO vamos a solicitar revisión de grado de dependencia, pues aún es bastante autónomo y no daría más del Grado II que tiene reconocido. ············· Presenta GDS 5. ·········· Actualmente está más tranquilo. Ha entablado amistad con otra residente. ···· *Le han dado pautas a las Auxilires de la residencia con repecto a cómo deben hablarle y tratarle, pues con las voces se altera. Aunque no hay buena relación entre ellas y eso se nota en el ambiente. ··············· Si volviera a ocurrir alguna incidencia, llamarán al 112. ············· De momento vamos a esperar y ver cómo evoluciona, para no desarraigarlo de su entorno. ····· Si fuera preciso más adelante solicitaríamos revisión PIA para cambiar algun centro (El Cuartillo) y ampliar a un cuarto en que pudiera haber más opciones de ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-09-29','-Amalia : contacto con la TS del ESM para informar de la situación . He preguntado sobre sus ultimas citas y no hay nada más después de ingresar en CRR . Ya tengo informes médicos últimos del ESM , se los paso al asesor jurídico para que lo aporte al expediente. -------------------------- Me escribe la TS del SSASB: tras ponerme en contacto con personal del Centro Médico para solicitar informes actualizados de Don Francisco Casillas García, me comunican que el interesado al parecer, no tiene médico asignado en el municipio porque aún figura con el médico asignado en Mérida de cuando estuvo ingresado en el CRR. Sin embargo, tras entrevista con Francisco este me asegura que ya ha gestionado el cambio. Es por ello que desde el Centro Médico me indican que no pueden emitir ningún informe médico reciente. Según consta en la base de datos, en Mérida tenía asignado al Doctor Javier Blanco Aparicio, por si este dato puede servir de referencia. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-09-29','Amalia : escribo a los jurídicos: desde el centro médico del pueblo no pueden activar 112 para que lleven a Fco. a urgencias del hospital por posible descompensación psiquiátrica. Me indica la TS del SSASB que ha contactado con personal del Centro Médico para solicitar informes actualizados de Don Francisco Casillas García, y le comunican que el interesado al parecer, no tiene médico asignado en el municipio porque aún figura con el médico asignado en Mérida de cuando estuvo ingresado en el CRR. Sin embargo, tras entrevista con Francisco este asegura que ya ha gestionado el cambio. Es por ello que desde el Centro Médico me indican que no pueden emitir ningún informe médico reciente , ni lo han atendido . He contactado con la TS del ESM de Mérida , para informar de la situación y para solicitar si ellos pueden ir a valorar a este hombre o activar 112 . Confirmo que no ha vuelto a citas desde principios de año cuando lo derivaron al CRR . Me indica que no lo han vuelto a ver y que no lo pueden hacer porque no saben cómo se encuentra . Ya tengo los informes médicos últimos de los que disponen ellos . Te los adjunto para la solicitud de internamiento involuntario vía judicial para ingresar en urgencias del hospital para valoración de psiquiatría y proceder a compensación si fuera necesario . No acude a citas del ESM ni de su médico de A.P. , no está siguiendo la medicación pautada y tiene consumo activo de alcohol . Las condiciones higiénicas , sanitarias y sociales en las que vive son deplorables. Yo planteaba ingreso en CSS pero me confirma la compañera que no lo van a autorizar , porque antes tiene que pasar por la UHB. Aquí tengo dudas , se lo podemos preguntar a Soraya , a ver qué le parece a ella. Era por garantizar que pase a CSS y no le den el alta a la semana como nos ha pasado con otros casos. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-09-29','TERESA FINALMENTE AITOR HA INGRESADO EN Comunidad Terapéutica de drogodependencias LUIS ROJO EN DON BENITO PAGA 400€ MES POR MANUTENCION DIRECTOR JULIAN 654911689','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2023-09-29','Amalia : reside en CSS de Mérida . Miguel solicitó informes económicos y sociales de este señor del que somos defensa judicial . Yo lo solicité al CSS de Mérida y esta es la información que os pasa la compañera. En tu último email de este caso estabas a la espera de recibir los informes . Desde el centro , insisten en la necesidad de bloquear las cuentas , su hermano está sacando dinero de las mismas y te envía los justificantes bancarios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2023-09-29','Email de Mª Angeles Galindo del CSS de Merida : remito los movimientos bancarios de Joaquín Montaño Montaño en los que se puede comprobar que desde el 10/07/23 hasta el día 26/09/23 su hermano Damián ha realizado retiradas de efectivo en cajero, pagos con tarjeta de crédito y tiene recibos domiciliados por un importe total de 948,18€. En dichos movimientos bancarios también podréis comprobar que el paciente cobró en septiembre la pensión de orfandad absoluta con un importe de 832,80€, pero, sin embargo, no cobró la prestación familiar por hijo a cargo de 453,30€. Así que, tendréis que contactar con la Seguridad Social para que os informen de porqué le ha sido ingresada solo una de las dos pensiones. Adjunto también recibo de Servicios Financieros Carrefour, ya que, al parecer Damián ha realizado una compra en dicho supermercado y pretende financiarla con los ingresos económicos del paciente. Así que, por un lado, sería conveniente que dichos hechos los pongáis en conocimiento de la Fiscalía y que, por otro lado, evitéis que Damián siga siendo titular de dicha cuenta bancaria tan pronto como sea posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-09-29','Ana: Respondo a Carolina, Directora CRR: "He preguntado a las compañeras y nadie me confirma nada del cambio de cerradura de la vivienda. En nuestra Intranet no hay nada anotado de que se haya procedido a tal cambio, por tanto entiendo que no se habrá cambiado." ································· Pegunto igualmente a Toni-Futuex por mail, por si ella supiera algo al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-10-02','Ana: Correo-respuesta de Toni - Futuex, en relación a las llaves de la vivienda de Flora: "...La llave del portal, si ha cambiado, pero la de su domicilio es la misma, lo que nos consta de aquella gestión es que la casa no tenia luz y muchas cosas acumuladas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-10-02','TERESA He llamado al centro para ver como estaba Aitor y ya no está. El sábado se marcho y a las dos de la mañana llamo la guardia civil al centro porque se lo habían encontrado. El director del centro les dijo que el no se hacia cargo pues se marchó voluntariamente porque se quería drogar. Dice que avisaron a la madre pero les dijo que ella no podía ir a recogerlo. Julian no sabe decirme el pueblo en el que se lo encontró la guardia civil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-10-02','Ana: Recibo llamada de Belén, Directora de la Res. PATRONATO RESIDENCIA DE MAYORES DE HERVÁS (927 47 34 10 / residencia_mayores@hervas.es): Hoy ingresa Eugenia en su centro. Ha hablado con ella esta mañana, le ha dicho que estaba muy nerviosa. ···· Le explico que el cargo de la CTAEx es una CURATELA de contenido PATRIMONIAL. ··· Le enviaré adjunto el testimonio de la sentencia. ················· Le informo que tiene una asignación semanal de 20€/semana y que acude sola a retirarla. ························································································································································································ Envío correo a Alberto, a los A. Jurídicos y a Julio, CTAEx: "Julio, porfa, cuando puedas cambia su domicilio en la base de datos. Ángel y Miguel, entiendo que tenéis que comunicarlo al Juzgado, adjunto resolución de plaza por traslado por ella misma solicitado. Alberto, si no me equivoco, tiene cuenta en UNICAJA (hay sucursal en Hervás, no hay problema) pero hay que enviar allí AUTORIZACIÓN DE RETIRADA DE ASIGNACIÓN SEMANAL PARA GASTOS DE BOLSILLO. En cuanto al coste de la plaza, al ser del mismo tipo, seguirá abonando lo mismo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-10-02','Ana: correo de María, Secc. Ecca. a Alberto, Jefe Secc: "Buenos días Alberto, Juan Jose Maseda del Sol solicita 20 € de subida de su asignación quincenal. Ahora cobra 40 € quincenales. He hablado con Ana y por su parte da OK. -Saldo Unicaja 13.193 € -pensión : 437 € + 680 € -Gastos manutención : 465 € Ya me dices lo que tenga que hacerle" ····························································································································· Respuesta de Alberto: "SI YA TENEMOS OK DE ANA, INCREMENTAMOS ASIGNACIÓN DE TUTELADO QUE PASARÍA A SER DE 60 €/QUINCENA (120 €/MES) LO ANTES POSIBLE."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='CRUZ'and apellido2='SANTOS'),'2023-10-02','TERESA Acabo de hablar con la hija de Ana, esta indignada porque la junta es tutora de su madre. Ya le he explicado todo y le he dado los datos del juzgado, quiere pedir la remoción. Me dice que la madre no come, que la comida del catering es muy mala…. Hay posibilidad de contratar otro catering? También me dice que antes iba a la peluquería y al podólogo y que como ahora o tiene dinero no va a nada…. A mi el hijo no me ha comentado nada de que necesite esto…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2023-09-29','Ana: correo de Anabel, TS SSASB Vegas Altas I (ssb025vegasaltas@madrigalejo.es): envía fotos de la casa de Josefa. Guardo en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2023-10-02','Ana: Llamo a Anabel, TS del SSASB, al Ayto. de Madrigalejo (927 35 40 02), me indican que está en el Ayto. de Campo Lugar (927 35 00 02): Hizo una visita a domicilio. Josefa tiene problemas de movilidad, el escalón de bajada a la cocina y los que hay para acceder al patio suponen importantes barreras para ella. Además el suelo del patio tiene agujeros y una de las paredes se está cayendo. ········ Entregaron 3 presupuestos de Albañil a la Ed. Futuex. ················ Josefa tiene 2 hermanos en el pueblo, a los que también pertenece la casa en la que vive (herencia familiar). Teme que si ella fallece su pareja, Juan, se quede en la calle. ······· Josefa quiere testar, para que ésto no ocurra. ··········· Por otra parte Anabel expresa que Josefa se siente muy desprotegida. ············ En cuanto a su deseo de casarse, le ha explicado, como no le interesa porque se vería reducida su pensión pues su pareja, anque cobra una mínima, también tiene ingresos.····························· Pido a Toni-Futuex, los presupuesto de albañilería que no nos han remitido. ······················· Consulto a los A. Jurídicos sobre cómo proceder en cuanto a su deseo de testar. ···························································································································································································· Respuesta de Toni-Futuex: "He estado buscando y revisando y no tengo constancia nisiquiera que a Josefa se le haya visitado en Madrigalejo, en estos ultimos tiempos, durante la vigencia del proyecto, como hemos comentado, al tener que disfrutarse vacaciones antes del 31 de Agosto y al tener las noticias de la no continuidad inmediata ya en el mes de agosto, no se pudieron efectuar todos los seguimientos y se priorizó lo mas urgente e intentar pasar la información mas relevante. Pero a Madrigalejo, donde reside Josefa, no se había ido, tampoco en los meses anteriores, según he revisado, ni en julio ni en junio tengo constancia que se hubieran realizado seguimientos (al tener apoyo familiar y vivir con su pareja, los seguimientos eran esporádicos). Asique no se muy bien a que presupuestos se refieren, pero almenos en el presente, no se los han entregado a ninguna educadora del programa" ······································································································ Llamo a Pilar (605 974 377), hermana de Juan, pareja de "Pepa", Josefa cada día tiene más dificultades de movilidad, antes de ayer se cayó. Sería importante hacer las obras en la vivienda. *Han solicitado nuevo presupuesto, pues los anteriores eran muy antiguos. ···· En cuanto a la Notaría, hay un notario que suele ir los jueves al pueblo. Cuando tengan cita llamará a Ángél, A. Juríco para indicarle nobre, cita y teléfono de contacto. También enviará presupuesto. ················· El número de contacto de Juan y Pepa es: 695 90 02 35.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-10-02','Ana: Llamada de José Manuel, el viernes tuvo cita con el Psiquiatra, le ha cambiado la medicación. Le propusieron ingreso en CSS-Plas, pero no quiere. Le dijeron también que Centro de Mayores y también dijo que no.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-10-02','Ana: Llamada de Isabel, muy nerviosa pues dice que se le ha caído el teléfono y se le ha mojado y que además tiene la pantalla rota. *Le recuerdo que esas compras han de hacerlas con el extra anual y no sé si le queda para este año. ········· Igualmente le emplazo a hablar con Carolina, Directora y Psicóloga, y con Beatriz, Psicóloga CRR. ····· Si ella consideran hacer alguna otra propuesta deberán hacerlo por escrito. ··················· Correo de Isabel: "Bᴜᴇɴᴏs ᴅíᴀs ᴀɴᴀ ᴄᴏᴍᴏ ʏᴀ ᴀ ɴᴀᴄɪᴅᴏ ᴍɪ sᴏʙʀɪɴᴀ ʏ ɴᴏ ʟᴀ ᴇ ᴠɪsᴛᴏ ǫᴜɪsɪᴇʀᴀ ɪʀ ʟᴀ sᴇᴍᴀɴᴀ ᴅᴇʟ 9 ᴅᴇ ᴏᴄᴛᴜʙʀᴇ ʟᴏs 5 ᴅíᴀs ᴇsᴏ ᴘᴀʀᴀ ᴠᴇʀʟᴀ ᴍᴇ ʟᴏ ᴀ ᴅɪᴄʜᴏ ᴍɪ ʜᴇʀᴍᴀɴᴀ ᴀᴠᴇʀɪɢüᴇ sɪ ᴘᴜᴇᴅᴇ sᴇʀ ᴘᴏsɪʙʟᴇ ᴍᴇ ᴇ ᴘᴏʀᴛᴀᴅᴏ ᴍᴜʏ ʙɪᴇɴ ʏ ᴛᴏᴅᴏ ʏ ᴇsᴛᴏʏ ᴄᴏɴᴛᴇɴᴛᴀ ʏ ғᴇʟɪᴢ ᴍɪʀᴀ" (adjunta foto de su sobrina). ····· Respondo con copia a Carolina y Beatriz - CRR: "Muy bonita tu sobrina, ¡FELICIDADES! En cuanto a tu petición, para empezar estuviste la semana pasada en tu pueblo y no sé qué cuantía de dinero extra anual te quedará en el centro, pues es con lo que debes abonarlo. No obstante, tal y como te he dicho cuando hemos hablado por teléfono, estas peticiones debes realizarlas, en primero instancia, a las profesionales del CRR. Con ellas es con quienes has ido programando todas las salidas a lo largo del año, siempre y cuando hayas estado bien y cumplido el acuerdo con el Psiquiatra, y por supuesto, adaptándote siempre al presupuesto acordado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-10-02','Ana: Llamada de Ceferino, quiere comprar una Nintendo por su cumpleaños. *Ya se ha comprado el móvil por su cumpleaños, lo propuso él mismo, en lugar de la consola. ··········· Le indico que en cualquier caso, con el dinero que le queda en centro del extra anual (no sé cuánto es), podrá, con el visto bueno del equipo del cetro, adquirir lo que consideren necesario de aquí a final del año en otros conceptos, no por su cumpleaños.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-10-02','Ana: Recibo llamada de Estrella Durán, TS (24146), y María, Psiquiatra CSS-Plas.: le explico que desde el Gabinete Tco. no consideramos conveniente que regrese al domicilio, primero porque no contará con los apoyos que requiere para su autocuidado y su bienestar(ya no cuenta con servicio de comedor y el apoyo de las Aux. de SAD resulta insuficiente). No podemos garantizar que mantenga unos hábitos mínimamente saludables ni que tome la medicación. Y tampoco consideramos que viva sólo por la seguridad de terceras personas en su pueblo dados los antecedentes. Van a plantearle el ingreso en CRR. En caso de que no lo acepte, se podrá convocar una subcomisión. ······························································································································································································ Nueva llamada de Estrella, TS: Enrique no acepta ingreso en CRR. ···· Además expresa que pone verde a todo el mundo, se queja de todo (de estar allí, de la medicación y de todo). Él mismo dice que es independiente. Que le den una oportunidad. Que quiere un abogado. ······· Pidió los 50€ para capricho y después quería cosas distintas a las que inicialmente había pedido. ········ Dice obscenidades a las profesionales como "Qué buena estás" y "Te voy a empotrar"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-10-02','Ana: Subo al portafirmar digital, para la firma de la D. Gerente, la COMUNICACIÓN DE BAJA EN ASINDI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-10-02','Ana: Llamo a Ventura (682 483 126): mañana irá a la tienda de Movistar con Odair, su amigo (622 19 73 32). *Sigue empeñado en mantener contrato con Movistar, no quiere cambiar de compañía. ·············· Me llamarán cuando estén en la tienda. ···· *La propuesta es dar de baja la alarma de hogar, "Mivistar Salud" y el seguro del teléfono cuando se pueda. Y mantener el nuevo pack que informó Cristina. ··································································································································································································· Correo de Guadalupe Cortés, TS SAD (guadalupe.cortes@ayto-caceres.es): "Informaros que la auxiliar de ayuda a domicilio que atiende a Ventura Gómez García nos comunica que el frigorífico de la casa no funciona bien, parece ser que no cierra bien la puerta del congelador y esto hace que se forme mucho hielo y no funcione de manera adecuada. No sabemos si esta incidencia está cubierta por su seguro de hogar, de ahí que os lo comuniquemos. Por otra parte nos informa de que Ventura sigue recibiendo comida del banco de alimentos, además de la comida del catering que le habéis contratado, y que algunos días le sobra comida, pero no la pueden congelar por el problema con el frigorífico. Finalmente deciros que ya tiene activo el teléfono."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-10-02','Ana: Recibimos escrito del INSS: RESUELVEN ESTIMAR la reclamación previa presentada sobre la resolución denegatoria de la PFHC solicitada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-10-02','Ana: correo de Estrella, secc. ecca., al PAF: "Buenos días, desde la parte económica se autoriza el presupuesto para las gafas de Felisa por importe de 240 €. Quedo a la espera del número de cuenta para hacerle la transferencia a la óptica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-10-03','Ana: Envío a Sonia Bernabé la AUTORIZACIÓN PARA ACTIVIDADES EN LA NATURALEZA de los JEDES firmada por la D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2023-10-03','Ana: Envío a Sonia Bernabé la AUTORIZACIÓN PARA ACTIVIDADES EN LA NATURALEZA de los JEDES firmada digitalmente por la D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-10-03','Ana: envío correo a Sonia Bernabé, Asindi; Maribel Ramos, UPA; Y Charo, UPA: COMUNICACIÓN DE BAJA en los servicios prestado por ASINDI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-10-02','Ana: Correo de Ana Benavente, TS ESM (anamaria.benavente@salud-juntaex.es): "Estoy en consulta con Javier Agudo. Ha encontrado habitación para compartir en un piso con otras dos personas. Le cobran 220 euros. Está muy contento, con ánimo y bien. Mañana tiene cita de nuevo para empezar en el CRPS. Te sigo informando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2023-10-03','TERESA de Diego , efectivamente está "super-agresivo" , muy excitado amenazando a todo el mundo , tirando objetos , toda la vivienda revuelta, dice que ha perdido la cartera con la documentación y el dinero que le quedaba, amenaza con arremeter contra todos por la situación en la que se encuentra .. He mandado a la auxiliar para casa ya que no es aconsejable que se quede allí . con esa situación , este fin de semana lo han visto por la madrugada ( a las 4. a las 3 ) deambulando por la calle solo . Por otro lado, he ido al centro de salud para dar el aviso para que vayan a casa a verlo y procedan a alguna medida que proceda , pero curiosamente de todo el personal médico del centro solamente hay uno de los 5 médicos del centro y tendrá que atender a toda la población y no creen posible que pueda atender avisos , He vuelto al domicilio de Diego para ver si seguía allí para avisar yo mismo al 112 pero ya no estaba en el domicilio. ............................................................. han estado vecinos y familiares . yo he llamado al 112 pero decían que sin que hubiera nadie que se haga responsable de el y no estuviera alterando el orden público no podrían actuar con lo cual no he podido hacer gran cosa. Raquel su auxiliar también ha llamado para decir que le han llamado vecinos para decirle que esta muy agresivo etc y que no tiene control sobre si mismo . siento no poder dar otra noticia , pero es todo lo que puedo hacer . He estado hablando con su antigua cuidadora que tiene un conocimiento muy concreto y amplio sobre él se ha ofrecido como interlocutora y ha estado hablando con él pero es imposible hacerlo razonar. ......................................................... El fin de semana fatal , lo han vetado en un bar, muy agresivo , la auxiliar me acaba de llamar para ir a la casa porque ella le da miedo a entrar porque esta muy agresivo la situación es insostenible , ya hemos hablado con la medica suya .. pero parece que no hay muchas posibilidades de nada . Mi pregunta¿ tenéis alguna capacidad desde allí para poneros en contacto con alguien como tutores suyos y proponer un ingreso involuntario durante unos días para estabilizarlo o ver que hacer? Si tienes el teléfono de Raquel , su auxiliar ella misma te puede contar. Otra cosa la novia ya no esta en el domicilio. voy un momento al domicilio pero yo tampoco puedo hacer mucho mas , además estoy solo en el servicio y tengo citas programadas toda la mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-10-03','Ana: María, Secc. Ecca, comunica a la Residencia que Eugenia DEBE IR ACOMPAÑADA A RETIRAR SU ASIGNACIÓN por personal del centro, me equivoqué yo al decírselo a Belén. ··········· Hoy mismo enviarán la autorización al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='CAMARA'and apellido2='MORENO'),'2023-10-03','Ana: Correo de Cristina Hdez. TS ULE - CSS (cristina.hernandezca@salud-juntaex.es / 24205): "Soy Cristina, Trabajadora Social de la Unidad de larga estancia del Centro Sociosanitario de Plasencia. El paciente Alfonso Camara de CTA , ha tenido que ir a VITALDENT por problemas con la dentadura.Nos han dado un presupuesto de 427.74€, el cual te mando adjunto. Necesitamos autorización para poder pagar dicho presupuesto y así la clínica de comienzo con el arreglo." ················································ Lo reenvío a Alberto, Jefe Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2023-10-03','Ana: correo de Agustina Martín - Ayto. de la Haba (ayuntamiento@lahaba.es) a Ángel, A. Jurídico y a mí: "Siguiendo instrucciones del Sr. Alcalde les comunico que Felipe Blanco Guisado se ha puesto en contacto con él, además de su hermana mayor pidiéndole que el Ayuntamiento cierre definitivamente la puerta trasera de la vivienda en C/ Dos Pozos nº 7. Por parte del Ayuntamiento no hay inconveniente en tapiar la puerta, pero necesitamos la autorización de Comisión tutelar de Felipe, ya que él mismo no puede gestionarlo. Si ustedes como tutores de Felipe nos envían dicha autorización para ejecutar dichas obras, el Ayuntamiento tapiará la puerta sin ningún problema. Esperamos sus noticias." ·················· Respuesta de Ángel: "¿Pueden indicarnos el coste económico que supondrá tapiar la puerta?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-10-03','Ana: Llamada de Mª Sol Tafur, TS - ESM Trujillo (54509): la psiquiatra Mª José del Castillo nos enviará la convocatoria de la SUBCOMISIÓN DE CASOS. Será presencial en CC, posiblemente el día 23 o 26 de octubre. ······························································································································································································· Correo de Mª José Gómez del Castillo - Psiquiatría - Coordinadora ESM-CC (mariajose.gomezd@salud-juntaex.es): "El motivo de este mail es convocar una Subcomisión de Caso Clínico, solicitada por el ESM de Trujillo, para analizar la situación de Dña. María Guadalupe Gil Cabello, el próximo 26 de octubre a las 9.00h de forma presencial en el ESM de Cáceres por expreso deseo del ESM de Trujillo. Os facilitare información sobre el caso." ········································ Nueva llamada de Marisol Tafur: Daniel, Psiquiatra de UME, ha leído el Acta de la Reunión con el ESM de Trujillo e informes y ha determinado que es un claro caso de de EMERGENCIA y de UME. Por lo que ingresará directamente en UME. **SE SUSPENDE LA SUBCOMISIÓN. ······································································································································································································· Llamada de Montaña, TS SSASB: Le han llamado del Juzgado, estaba allí Guadalupe. Ha hablado con un abogado amigo suyo, por recomendación de éste quiere solicitar ABOGADO DE OFICIO. ············· Le firmó el documento a Montaña. ·················· *Ésta lo tramitará especificando que tiene Medidas Judiciales de Apoyo ejercidas por la CTAEx, que no tiene conciencia de enfermedad ni de tener estas medidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ANGEL'and edp.apellido1='IGLESIAS'and apellido2='RODRIGUEZ'),'2023-10-03','Ana: Actualmente reside en la RESIDENCIA GERIATRICA NUESTRA SEÑORA DE LA ASUNCION (GALISTEO). TLF. 927 452 400 ······················· Presenta deterioro cognitivo, no habla muy bien. ······· Vivía en su casa hasta que falleció su madre. Una vez que se quedó sólo con su padre es cuando se procedió al ingreso. ········ En el centro está tranquilo y adaptado a las rutinas del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-10-03','Ana: Llamada de Mª Carmen, TS UHB HSPA (56283): mañana dan el alta a Joaquina. ········· La trasladarán en ambulancia con un celador a lo largo de la mañana. ···· Mª Carmen añade que la Sra. "es muy intensa" y sigue sin querer ir a la residencia. ·············································· Llamo a Rosana, Directora RRMM Amada Corral (699 19 81 86) y se lo comunico. ······· Me enviará el Informe de Alta actualizado.','2');
