insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-10-03','Ana: Estrella, Secc. Ecca. llama a MAPFRE, sí le entra la reparación del frigorífico en la póliza. La marca es SAMSUNG y tiene entre 12 y 13 años. ······························································································································································································ Con respecto a los servicios de telefonía, Lourdes llama al 1004, le dicen que está dada de baja la Alarma de Prosegur, Movistar Salud... y que Ventura tiene que volver a llamar para corroborar la baja del contrato de los 48€ (móvil que no tiene ni usa). ··· Tal y como acordamos llamo a Ventura y Odair, éste se compromete a ayudarle para confirmar esta baja. ········· A partir de mañana día 4 pasarán la nueva facturación.','2');
