insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-10-04','Ana: Llamo a Ventura (682 483 126): le comunico que ya está abierto el parte del Seguro de Hogar por la avería del frigorífico. El técnico le llamará hoy para indicarle el día y la hora que irá a verlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2023-10-04','ADOPCIÓN DE MEDIDAS JUDICIALMENTE ADOPTADAS Mediante St. n.º 16/23, de 26 de enero, se nombra Curador Representavo a la CTAEx.*************************************Se procede a modificar el expte.*****************************************A partir de ahora será considerado 06/CR/07.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-10-04','Ana: Llamo al Abogado, Cándido Moreno (636 222 266): está ocupado y no puede atenderme, pero me facilita una dirección de correo para que le escriba: luiscandidom@yahoo.es ·········· Le envío un correo: "Tal y como hemos acordado mediante conversación telefónica, me pongo en contacto por este medio para consultarle acerca de ciertas dudas que tenemos relativas a las Prejubilación de D. Víctor Manuel Blanco Poveda, cuyo cargo de Curatela Representativa ejerce la Comisión Tutelar de Adultos de Extremadura (CTAEx) por Resolución Judicial. - Por un lado, no tenemos copia del CONTRATO DE PREJUBILACIÓN SUSCRITO, por lo que agradeceríamos que en cuanto pueda nos lo haga llegar. - Por otra parte, hemos recibido una carta de Iberdrola solicitando Certificado de la Seguridad Social de los pagos realizados durante el primer semestre del año. Entendemos que de estos pagos se encargó usted, puesto que la CTAEx, aceptó el cargo de curador a fecha de 30 de mayo del presente y a partir de ese momento el Juzgado da 60 días para poder elaborar inventario para poder intervenir. ¿Podría facilitarnos dicha información e indicarnos cómo debemos proceder a parir de ahora para que no tenga problemas al respecto? Es el primer caso que tenemos en la CTAEx de persona con contrato de prejubilación y no conocemos los modos de proceder. - Por último, me gustaría saber el procedimiento a seguir para solicitar un cambio de domiciliación bancaria de su nómina, si conoce el procedimiento, agradecería nos lo comunicara también."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='BLAZQUEZ'and apellido2='RAMOS'),'2023-10-04','-Amalia : escrio a mayores : tras conversación telefónica con May, os informo de la pensión que percibe este señor ,tutelado por la CTAEX y de sus bienes . 1.- PENSIÓN. D/Dª. BLAZQUEZ RAMOS, JUSTO, con DNI núm. 08622911G es beneficiario/a de una pensión de jubilación de Alemania por importe, para el presente año, de 610,28 euros mensuales en doce pagas. Se justifica en el extracto de movimientos bancarios , no tenemos cdo. PENSION RENTEN SERVICE DEUTSCHE POSTBANK A.G.27028 RENTEN SERVICENSBLAZQUEZ RAMOS JUSTO 30/09/22 30/09/22 2733716826 610,28 El ingreso será en la R. M. Felipe Trigo , gestiono el traslado para los próximos días , actualmente reside en CSS de Mérida .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-10-04','Ana: Envío correo a Sonia Bernabé, TS y Directora ASINDI, con copia a A. Jurídicos: "...*Necesitaríamos también INFORME SOCIAL tuyo en los términos que se indica en el el correo de Miguel. Subrayo en amarillo en el hilo. En cuanto a Roberto, aunque está pendiente de aclararse la situación, supongo que también sería bueno que fueras elaborando el Informe Social cuando puedas, pues entiendo que no tardarán mucho en pedirlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-10-04','Ana: Correo de Carolina, Directora del CRR: "Te escribo para informarte que en el día de ayer se recibió una carta del BBVA en la dirección del piso supervisado a nombre de Ceferino Marsical Crespo. Cuando la recoge la profesional nota que dentro hay algo parecido a una tarjeta de credito. En conversación posterior con Ceferino y al preguntarle por esta carta, nos informa que se la ha hecho online para cobrar los streaming. No nos da mucha más información, al adoptar una actitud defensiva. Os adjunto copia de la tarjeta, así como de la carta que había. La tarjeta no ha sido activada, pero desconozco sí ha abierto una cuenta o realizado algún trámite, él tampoco ha sabido decirnos. Le hemos explicitado que por su condición de persona incapacitada no puede realizar este trámite pero nos informa que lo hizo todo online." ······················· Lo reenvío a Alberto, Jefe Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-10-04','Ana: Llamo a Raquel - Res. Almaraz (927 544 085): me enviará al correo-e el contrato de la residencia para su firma, documento para domiciliación bancaria e información de los gastos habituales del centro. ········· Flora ingresa hoy entorno a las 10:30 h. ······························································································································································································ Envío a REGISTRO (oac.merida.san@juntaex.es): "Adjunto remito Oficio-Solicitud de Certificado Actualizado de Prestación de Orfandad, relativo a FLORA GUTIÉRREZ GARCÍA, cuyo cargo ostenta la CTAEx, para darle registro y remitir a la Dirección Provincial del INSS de Cáceres, junto a la siguiente documentación: - Testimonio de acuerdo de aceptación del cargo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2023-10-04','Ana: Envío correo a Maite Cañadas, Directora de la Res. San Francisco de Plas. (maria.canadasv@salud-juntaex.es): "Me pongo en contacto contigo en relación a MARÍA LUISA REY CAMPÓN, a petición de mis compañeros jurídicos, para solicitarte que nos hagáis llegar, a la mayor brevedad, INFORME SOCIAL para la REVISIÓN JUDICIAL DE LAS MEDIDAS DE APOYO en los siguientes términos: “- Informe Social sobre la situación actual de Dña. Luisa en cuanto a: • Discapacidad/Dependencia que presenta • Ámbitos y extensión que resulten afectados por su discapacidad y necesidad de apoyo • Cualquier consideración que estimen conveniente sobre ella en razón al procedimiento judicial de revisión de medidas de apoyo.“ Ante cualquier cuestión no dudes en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-04','ANGELICA MARIA MOLANO ALONSO Buenos días. Atendiendo a su consulta, le informamos que el equipo de Valoración del CADEX ha accedido a través de JARA a los informes médicos de Dª. María Carmen Leal Benito, en la solicitud presentada el 20 de Junio de 2023 autorizaba a los equipos de valoración del CADEX a acceder a dichos informes médicos. Su expediente está completo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2023-10-04','Ana: Correo de Felisa Custodio, TS CAMF-Alcuéscar (trabajadora_social_alcuescar@imserso.es) con INFORME SOCIAL PARA LA REVISIÓN DE LAS MEDIDAS. Desde el C. Salud no le han enviado el Informe Médico solicitado. ······················· Renvío a los A. Jurídicos el Informe Social. ················································· *Redacto y envío a Julio, para que registre en SIREX oficio-solicitud de Informe Médico al C. Salud. junto con el Testimonio de Aceptación del Cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-10-04','Ana: Correo de Pilar Martín, TS ESM-CC (pilar.martinp@salud-juntaex.es): "Hola Ana, tengo a un paciente tutelado por vosotros que me dice que quiere solicitar CRR, le entrego el informe médico para su MAP, pero con hacemos para la firma con vosotros?" ········································· Mi respuesta: "La solicitud, como en anteriores ocasiones desde que se solicita la firma del Representante Legal, una vez la haya firmado el propio Sergio nos la hacéis llegar para que acompañe también la firma de la actual Presidenta por delegación de la Comisión Tutelar de Adultos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2023-10-04','Ana: Llamada de Jairo, dice que el Dr. Agapito Herrero le han dicho que han solicitado la recuperación de su capacidad. Y que vaya buscando piso para irse a vivir de forma independiente. ··············· Por otra parte dice que se le ha pasado el plazo para matricularse en la UNED. Como alternativa quiere ir a la Academia Carlos I, le cuesta 80€/mes. Le recuerdo que es un coste elevado para los ingresos que percibe (PNC) y tendrá que enviar una propuesta específica formativa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-10-04','Ana: envío mail a Julio, Aux. Adtvo. CTAEx: "Adjunto, para su registro en SIREX, Oficio-solicitud de Informe del Servicio de Psiquiatría relativo a SERGIO SOLANILLA LUJÁN, junto a: - Acuerdo de Aceptación del Cargo - Parte de Incidencias del Centro en que reside Para remitir al ESM de Cáceres."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2023-10-04','Ana: Reenvío a Sheila Rguez., Directora Técnica CRR-CC (crr@grupociudadjardin.com) correo de Inés, Secc. Jurídica: "os reenvío correo recibido por Sirex, cédula de notificación referente a la revisión de medidas de Felix Valle Simon. (14/11/23)." y pido, si es posible, que le acompañen desde el CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-10-04','Ana: Llamada de Montaña (692 84 12 19), el 25 de julio tuvo su última cita de seguimiento en el ESM. Solicitaré informe de Alta del CSS (Dr. Daniel Pizarro) así como Informe Seguimiento en el ESM-CC. Su Psiquiatra es Enrique Goenaga. ··········· Ha recibido cartas de deuda del BBVA. Se la llevará a la TS para que nos la envíe por mail. ·········· Por otra parte dice que quiere irse a vivir ya sola a su piso, de momento sigue en casa de sus padres. Acordamos esperar a noviembre, pues ya habrá tenido su próxima cita en el ESM y podré derivarle al Progr. gestionado por Futuex, si se renueva el convenio. Le explico en que consiste y acepta la derivación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2023-10-05','TERESA EN LA ULTIMA VISITA A CASA DE SU MADRE NATALIA COMENTA QUE FUE LA POLICIA Y LA DETUVO. TRAS HABLAR CON LOS SERVICIOS SOCIALE DIANA 924478770/ DAIZ@AYTOBADAJOZ.ES NOS COMENTA QUE TRAS HABLAR CON LA POLICIA LE INFORMAN HA ESTADO DETENIDA POR VIOLENCIA HACIA SU PAREJA Y POR HURTO HAN INTENTADO HACER VISITA A DOMICILIO EN DOS OCASIONES PERO NO ESTABA VAN A INTENARLO DE NUVO MAÑANA PARA ELABORAR IFNORME SOCIAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2023-10-05','TERESA ME LLAMA BEATRIZ QUE HA IDO A PLACEAT TRUJILLO Y LE HAN DICHO QUE TIENEN PLAZA DISPONIBLE, ELLA COMENTA QUE QUIERE IRSE A ESE CENTRO. LE EXPLICO QUE AHI SOLO TIENEN CO Y NO PUEDE IR A SESE CENTRO. LA MADRE ME DICE QUE QUEIER QUE BEATRIZ VIVA CON ELLA Y VAYA A CO EN PLACEAR LLAMO A AMOR PARA EXPLICARLE QUE BEATRIZ ESTA A CARGO DE LA COMISION Y NO PUEDE SOLICITAR PLAZA COMUNCIO A MERCEDES DE PLENA INCLUSUION LLERENA LA SITUAICON PARA SU CONOCIMIENTO, LLAMA A BEATRIZ PARA HABLAR CON ELLA: He hablado con Bea y con los padres puesto que le he pedido que pusiera el modo "manos libres" para que ellos escucharan la conversación y dice que ella solo ha ido a preguntar si había plazas libres en ASPACE porque ese centro era el suyo y allí estaba muy bien y que le gusta más que el centro de Llerena porque así puede ir a dormir a casa. Le he explicado a los tres que esa opción no es la más adecuada puesto que los padres ya son mayores y necesitan ayuda para la comida, la compra etc y que Beatriz tb necesita apoyos que ellos no le pueden prestar si estuviera en casa. He sido muy directa al decirle que no podemos contar con el apoyo de la madre puesto que ella no ha mostrado estabilidad en estos últimos años y que se ha ido muchas veces de casa. Le he recordado al padre que puede solicitar el centro de mayores de Llerena y no se ha negado como otras veces, no ha dicho nada. Su padre dice que el otro día no había autobús desde Cáceres a Trujillo y se gastó 65€ en un taxi. Nosotros gestionamos el viaje hasta Cáceres y luego confiamos que su madre le coge el billete de bus desde Cáceres a Trujillo pero el otro dia dice que estaba completo. Le he quedado claro que la proxima vez le sacaremos nosotros tambien el billete de bus para las dos desde Cáceres a Trujillo. Ha sido una conversación en un tono muy tranquilo y yo le he planteado que se puede solicitar plaza en otro centro más cercano a Trujillo pero que tenga residencia a lo cuál Beatriz ha dicho que no, ha dicho que si tiene que dormir fuera de casa que prefiere quedarse en Llerena. Hemos quedado que regresa el jueves en el tren de las 16,40h y directamente la recogen dos compañeras para ir al cine a He hablado con Bea y con los padres puesto que le he pedido que pusiera el modo "manos libres" para que ellos escucharan la conversación y dice que ella solo ha ido a preguntar si había plazas libres en ASPACE porque ese centro era el suyo y allí estaba muy bien y que le gusta más que el centro de Llerena porque así puede ir a dormir a casa. Le he explicado a los tres que esa opción no es la más adecuada puesto que los padres ya son mayores y necesitan ayuda para la comida, la compra etc y que Beatriz tb necesita apoyos que ellos no le pueden prestar si estuviera en casa. He sido muy directa al decirle que no podemos contar con el apoyo de la madre puesto que ella no ha mostrado estabilidad en estos últimos años y que se ha ido muchas veces de casa. Le he recordado al padre que puede solicitar el centro de mayores de Llerena y no se ha negado como otras veces, no ha dicho nada. Su padre dice que el otro día no había autobús desde Cáceres a Trujillo y se gastó 65€ en un taxi. Nosotros gestionamos el viaje hasta Cáceres y luego confiamos que su madre le coge el billete de bus desde Cáceres a Trujillo pero el otro dia dice que estaba completo. Le he quedado claro que la proxima vez le sacaremos nosotros tambien el billete de bus para las dos desde Cáceres a Trujillo. Ha sido una conversación en un tono muy tranquilo y yo le he planteado que se puede solicitar plaza en otro centro más cercano a Trujillo pero que tenga residencia a lo cuál Beatriz ha dicho que no, ha dicho que si tiene que dormir fuera de casa que prefiere quedarse en Llerena. Hemos quedado que regresa el jueves en el tren de las 16,40h y directamente la recogen dos compañeras para ir al cine a','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-10-05','TERESA RECIBO LLAMADA DE MANUEL EL CURA DE ZALAMEA 600785148, ME PREGUNGA QUE CLASE DE TUTRELA TIENE PABLO COMENTA QUE EL DINERO QUE LE DAMOS SE LO GASTA EN LITRONAS, QUE EL OTRO DIA LO TUVO QUE CASER DE LA IGLESIA PORQUE ESTABA EBRIO Y QUE MAL COME, SERIA CONVENIENTE CONTRATAR UN CATERINGA Y EVITAR QUE MANEJE DINERO PORQUR SE LO GASTA EN ALCOHOL. HOY YA LE HAN PUESTO EL AGUA EN LA VIVIENDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-10-05','Ana: En relación al correo de Ángel sobre la propuesta que envía Ceferino de la Editorial: Envío correo a Carolina, Directora CRR: "Te reenvío correo de mi compañero Ángel, Asesor Jurídico, en relación a la solicitud de Ceferino de editar un nuevo libro y las respuestas a sus consultas desde la editorial. Ya le dije a los compañeros que, tal y como tú indicaste en uno de los correos: “Consideramos que este libro no es el resultado de un trabajo continuado, estructurado y con esfuerzo por parte de los dos. Por lo que consideramos que estaría bien aplazar esta edición hasta que puedan perfeccionar y/o mejorar el contenido del mismo” dejamos en stand by la edición hasta que desde el centro nos confirméis que ha perfeccionado y/o mejorado el contenido del último libro, tras su correspondiente trabajo previo. Hasta entonces no se va a contratar nada con la editorial. Agradeceríamos que trataseis también con él este asunto. Por cierto, al parecer ya no quiere editarlo con Isabel, dice que no lo han escrito juntos. Pongo en copia Ángel y a Alberto, Jefe de Secc. económica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-10-05','Ana: Correo de Estrella, Aux. Secc. Ecca CTAEx en relación al Técnico del seguro y arreglo del frigorífico: "ha llamado el técnico , acaba de ir al domicilio de Ventura, en resumen ¡!!que se tiene que comprar uno nuevo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2023-10-05','Ana: Llamo al CRR-CC (927 83 02 10): hablo con Cristina, Psicóloga. Ya tienen el Informe Médico para la revisión de medidas y el del centro están en ello, dice que esta misma semana terminan de redactarlo y nos envían los dos. ···························· En cuanto al propio Martín, me informa de que en los útlimos meses ha empeorado mucho, el deterioro cognitivo está yendo demasiado rápido. No obstante no hay más inflamaciones cerebrales. ··· Desde el centro es difícil intervenir con él, pues incluso se hace sus necesidades encima y él no se da cuenta. Requiere gran supervisión y apoyo y con las características del centro no se le puede disponesar toda la atención que necesita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-10-04','Ana: Nos envían desde la residencia (a.corral@grupociudadjardin.com) INFORME DE ALTA de la UHB: al ingreso: "ideas delirantes de persecución", "no sigue hilo conductor de la entrevista", "poco abordable. Contacto psicótico. Aspecto descuidado. Recelosa, suspizaz." "Lenguaje incoherente, berborreico." "Escasa conciencia de enfermedad". ···· Al alta: Evolucion favorable. "Tranquila, con ánimo adecuado y actitud colaboradora" "Pese a la insuficiencia de conciciencia de enfermedad acepta ir a la residencia"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-10-05','Ana: consulto a la residencia por el ingreso y las primeras horas de Joaquina en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2023-10-05','Ana: Corre de Belén Pavón (Belen.asoma@outlook.es): "Doña Salvadora Chaves Mendoza residente en pisos tutelados de Villa del Rey, tiene consulta médica en Hospital Universitario de Cáceres el día 6 de Octubre. Realizará acompañamiento Doña Fernanda Chaves Niso. Adjunto cita médica y declaración jurada y número de cuenta de Doña Fernanda Chaves Niso para realizar el pago de los 50€ estipulados por acompañamiento." ······················· Lo reenvío a la secc. ecca. para que hagan la transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-10-05','Ana: correeo de Sara, TS R.M. Banium Residencial (TrabajadoraSocialBanium@hotmail.com): "Informar que la usuaria Concepción Barbero Sánchez tiene consulta con el servicio de traumatología del Hospital Virgen del Puerto para una revisión de su evolución tras las recientes intervenciones, en la mañana de hoy. Para poder acudir a la consulta se le ha solicitado acompañamiento privado. Por lo que en los próximos días se les adjuntara una declaración firmada con el importe del acompañamiento." ······················ Pido que la declaración jurada la remitan directamente a la secc. ecca.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='MEJIAS'and apellido2='MARTINEZ'),'2023-10-05','ARCHIVO DE EXPEDIENTE El Jzdo. de 1.ª Inst. n.º1 de Cáceres, dicta Auto n.º 110/23, de 10 julio, por el que se acuerda no haber lugar a la adopción de medidas de apyo respecto de D Miguel Ángel. El mismo devino firme por DIOR de 26/09/23.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-10-05','miguel, llega Auto del procedimiento ITR del jzdo nº2 de Trujillo por el que se insta a los Colegios de Abogado y Procurador para que nombren de oficio, lo que hace suponer que la tutelada se ha opuesto. Envío email a la parte social: Ana, en relación al internamiento involuntario que solicitamos de Guadalupe Gil entiendo que ella se ha debido de oponer porque la juez Patricia ha solicitado abogado y procurador de oficio. Recordad que ya nos dijo la juez que sería complicado el internamiento de esta mujer, conforme apunte en la intranet del 28-7-23: “Quedé con Maite en llamar a la juez Patricia hoy. Me llama y hablamos sobre este caso y me confirma que los informes forense y del Ministerio Fiscal (Carmen Barquilla) entienden que no es necesario internamiento en unidad de psiquiatría por no haber alteración de conducta. Hace un año dictó internamiento similar y no se cumplió tampoco. Le explico tipos de recursos que tenemos básicamente y que para un internamiento neceistamos que el auto recoja expresamente unidad de psiquiatría. Me indica que si es un requisito para el acceso a los mismos tal como le digo, que dónde viene eso recogido, le digo que el lunes la llamará Maite por tener más conocimientos de los social a su teléfono particular (porque la juez teletrabajará el lunes) Tras comentarlo con Maite, me comenta que hablará con Soraya para que la informe bien d dónde se recogen dichos requisitos para entrar en esas unidades psiquiátricas.”','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-05','miguel, hablo telefónicamente con la abogada que habia pedido cita con la gerente Estrella, MARIA DE LA GRANADA GALAN MARTIN >2964@icaba.com>, tlfno 667876533. Hablamos detenidamente de la ejecución del procedimiento que ella ganó y por el que se condena en costas a nuestra tutelada. Parece ser que nuestro abogado Jorge Calvo nos ha puenteado pues ha presentado algún documento sin firmar por la Ctaex para evitar dicha ejecución, incluso fuera de tiempo y sin sentido pues fue desestimado. A partir del 10-9-23 en que tuvimos las ultimas noticias de él, el juzgado ha dictado dos resoluciones firmes instando al pago de las costas del procedimiento, lo cual desconocíamos en la Ctaex pues ni el abogado Jorge Calvo, procuradora Cristina Soto, ni el juzgado nos había comunicado nada, y por ese motivo ella había pedido cita a la gerente del Sepad para dar la queja pues si no pagamos tendría que instar la ejecución de la ejecución ya aceptada, lo que incrementaria las costas procesales. Quedo con ella que me envíe las resoluciones firmes del pago de costas y las facturas de la procuradora y de ella (abogada) y envío email a Alberto con toda la información para la transferencia urgente de las cantidades acordadas por el juzgado de unos 4.700€ en total(faltaría las costas de nuestro abogado y la procuradora) Acordamos no comentar esta conversación con nuestro abogado con dudosa conducta etica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2023-10-06','miguel, enviamos hoy por lexnet comunicación al jzdo del ingreso en la UHB esta semana del tutelado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-10-06','miguel, enviamos por lexnet contestación al requerimiento de que indiquemos la correcta dirección y que nos facilitó Amalia: Te paso la dirección actual de Antonia y su unidad de convivencia según el padrón municipal: Antonia está empadronada en la C/ Hernán Cortés, 20 de La Morera (06176). Convive con: - Fernanda (79 años) . madre - Pedro (48 años) - hermano - Domingo (37 años) - hermano. El teléfono de contacto que me han facilitado es el de Pedro: 640831790.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='CRUZ'and apellido2='SANTOS'),'2023-10-06','TERESA ENVIOPOR EMAIL post@drv-rheinland.de OFICIO CON DOCUEMNTANCION PARA EL CAMBIO DE PENSION DE LA CUENTA DE BANCA PUEYO A IBERCAJA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-10-06','Ana: Llamada de Jesús Manuel (635 336 539): cuesta entenderle al hablar. Cuenta que cuando fueron a hacer la revisión del gas a su vivienda, él se quedó escondido y les escuchó hablar y decir varias mentiras. Qué está "hasta los cojones". Acudió a la supuesta reunión de vecinos, pero cuando llegó no había nadie. ··········· "Un señor que pide limosna en el Burguer King acude a casa de la vecina de arriba y desde el balcón de ésta se orina en el suyo. ·········· "Los psiquiatras son unos hijos de puta que me han jodido la vida", "comprados por un paquete de café, un fajo de billetes y una botella de oporto", "el primero que atendió me intentó dar por culo, le gustaban los plumones" ·················· En cuanto a la búsqueda de nueva vivienda de alquiler pregunta cuál es el precio máximo que puede pagar". "Diré a mis familiares que lo busquen ellos porque yo no pienso buscar nada". ·············· Tiene próx. cita en Psiquiatría, ESM, el día 10/10. ··············· Por último añade que su hijo quiere asumir su tutela. ··············· Por otra parte dice que tanto su hijo como su hija están trabajando los dos, por tanto quiere dejar de pasarles la pensión. ········································································································ Llamada de su madre Isabel (657 947 818): en relación al cambio de vivienda, recuerdo a su madre que la Curatela que ejerce la CTAEx es para la administración de sus bines y para la salud. Su hijo tiene capacidad para buscar otra vivienda e indicarnos la información de la misma de cara a la formalización del contrato. ·································································································································································································· Llamo a Pilar Martín, TS ESM (54612): está ocupada, me devolverá la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-10-06','Ana: Llamada de Manuel Andrés Casado, EVD CC (22049): me enviará por mail la Aceptación PIA de Serv. Att. Residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-09-28','Ana: Recibimos INFORME SEGUIMIENTO PSIQUIATRÍA - ESM solicitado: Fecha consulta_26/09/23 ··· Dra. Cristina Donoso Jiménez. ··· "Antecedentes de consumo de múltiples sustancias" "Antecedentes de seguimiento en CEDEX y Comunidades Terapéuticas" "Diagnosticado de T. Esquizoafectivo tipo bipolar" "T. del desarrollo intelectual leve" "T. Personalidad cluster B" ····· Actualmente "ABUSO DE BENZODIACEPINAS" (refiere tomar 5-6 comprimidos de Trankimazin 2 mg", tiene pautado 1 cada 8 horas. "Ha acudido en varias ocasiones al urgencias y a su CS demandando recetas de ansiolíticos" "refiere buena cumplimentación del resto de tratamiento aunque los niveles de litio y valproico en sangre son infraterapéuticos en la última analítica" (19/09/23) "en estos momentos no presenta clínica psicótica o clínica afectiva mayor" "Ansiedad leve" "No ideas de muerte o autolícicas. No auto/heteroagresividad" "Actitudes manipuladoras en relación con la demanda de recetas" "Insisto en la necesidad de cumplimentar adecuadamente el tratamiento y acudir a CEDEX"','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-09-28','Ana: Recibimos INFORME SEGUIMIENTO PSIQUIATRÍA - ESM solicitado: Fecha consulta_26/09/23 ··· Dra. Cristina Donoso Jiménez. ··· "Antecedentes de consumo de múltiples sustancias" "Antecedentes de seguimiento en CEDEX y Comunidades Terapéuticas" "Diagnosticado de T. Esquizoafectivo tipo bipolar" "T. del desarrollo intelectual leve" "T. Personalidad cluster B" ····· Actualmente "ABUSO DE BENZODIACEPINAS" (refiere tomar 5-6 comprimidos de Trankimazin 2 mg", tiene pautado 1 cada 8 horas. "Ha acudido en varias ocasiones al urgencias y a su CS demandando recetas de ansiolíticos" "refiere buena cumplimentación del resto de tratamiento aunque los niveles de litio y valproico en sangre son infraterapéuticos en la última analítica" (19/09/23) "en estos momentos no presenta clínica psicótica o clínica afectiva mayor" "Ansiedad leve" "No ideas de muerte o autolícicas. No auto/heteroagresividad" "Actitudes manipuladoras en relación con la demanda de recetas" "Insisto en la necesidad de cumplimentar adecuadamente el tratamiento y acudir a CEDEX"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2023-10-06','-Amalia LLega emial de Mª Angeles Galindo con informe social . Le escribo a Icíar: de Joaquin ya estoy interviniendo en algunas cosas. Es defensa judicial y en el listado de casos para septiembre no está , entiendo que aún no es curatela. La compañera del CSS nos envía documentación e informe social , te lo paso para cuando toque el inventario ?? o lo habéis pedido vosotras ? No sé si este inventario lo llevas tú o otra de las compañeras. Ya me dices .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2023-10-06','CRR Mérida: Por completar la información. Esta misma noche, tras varias llamadas Almudena acude al centro mas tarde le la una de la madrugada, previo a esto y cuando se intenta hablar con ella telefónicamente, Miguel Angel responde al teléfono realizando insultos y amenazas a las profesionales (no siendo esto la primera vez). Cuando Almudena acude al centro, viene acompañada por él, siendo necesaria la intervención de la policía ya que este señor desde la puerta del centro realiza insultos y amenazas a las profesionales. Me parece preocupante esta situación ya que en este momento esta en riesgo tanto Almudena como el resto de las personas que residen y trabajan en el centro. Os escribo para comunicaros la evolución de Almudena las últimas dos semanas: la situación por lo general ha empeorado. A pesar de las intervenciones con ella por parte de todo el equipo y de sus intentos para conseguir mantener sus hábitos y responsabilidades en el centro, planteadas dentro de sus objetivos de recuperación, no está siendo capaz de asumirlos. Falta a sus tareas de ocupación tanto dentro como fuera del centro, a citas con profesionales del equipo y presenta cada vez más ansiedad, muy probablemente debido a su relación con Miguel Ángel. En varias ocasiones, a través de llamadas telefónicas a Almudena para preguntarle donde estaba ante la falta de alguna cita o tarea en el centro, se ha escuchado de fondo a Miguel Ángel insultando a profesionales, llegando en un par de ocasiones a cogerle el teléfono, insultando y realizando amenazas directamente. También, Miguel Ángel se ha llegado a presentar con Almudena en el centro, con muy mala actitud y mostrando resistencia a marcharse. Creemos que Almudena, de verdad está intentando poner límites a Miguel Ángel, pero no es capaz de mantenerlos ante la insistencia de éste. Hoy, ante un estado de ansiedad elevado, ha llegado llorando a la comida sin querer concretar a los profesionales que estaban presentes los motivos de su malestar. Os seguiré actualizando la información. Un saludo, Fernando Barrios López','2');
