insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-10-06','Ana: Llamo a Ventura (682 483 126) varias veces para indicarle que tendrá que pedir presupuestos para comprar un frigorífico nuevo. NO OBTENGO RESPUESTA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-10-06','Ana: Llamada de José Manuel, dice que ha pasado unos días muy malos, ha tenido que ir a urgencias de nuevo. Ahora dice que se encuentra mejor, que parece que ya está haciendo efecto el cambio de medicación. ···················· La propia Aux. de SAD le ha dicho esta mañana que no hacen falta los productos de limpieza todavía, lo pedía él porque le parecía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-10-06','TERESA RECIVO EMAIL DE M LUISA OLIVERA ECA CORIA Buenos días, Teresa. Estoy en consulta con Manuel Domínguez Martin. Te he llamado pero no ha sido posible. Desde hace un tiempo solicita CT "La Garrovilla", ya ha estado allí. No lo hemos derivado antes porque algún profesional del ECA consideraba que no era adecuada su derivación. Me dice que tú estás informada de que quiere ir y que estás de acuerdo, ¿es así? Si estás de acuerdo podemos intentar derivarlo. POR NUESTRA PARTE NOS PARECE BIEN QUE INGRESE EN LA CT LA GARROVILLA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-10-06','-Amalia , tras hablar con Maribel , no presento la solicitud de CO. Espero a resolucion de dependencia de Adriana , lo pedimos por PIA y se lo entrego a Maribel Ramos . No necesita pérfil ni nada pq ya lo tiene en el CADEX .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2023-10-06','-Amalia , escribo a Miguel . este señor ha sido trasladado varias veces de centros penitenciarios . Ha estado en Andalucía , en el de Badajoz ,pasó a Centro Penitenciario en Madrid y de éste al de Cáceres . El expediente lo sigo llevando yo . El internamiento involuntario que se solicitó fue para poder recibir tto. en el Hospital de Cáceres . Al final , el médico decidió dar el alta ante su falta de colaboración para recibir el tratamiento . Desconozco la ejecutoria por la que preguntas , tendrás que solicitar esa información al juzgado oportuno. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2023-10-09','Ana: Reenvío a los A. Jurídicos, INFORME MÉDICO del MAP e INFORME TÉCNICO DE SEGUIIENTO del CRR, para la revisión de las Medidas Judiciales de Apoyo. ················· En ambos se detallan el empeoramiento del estado de salud de Martín, así como la mayor dependendencia que presenta en todas la áreas, necesitando apoyo para todas las ABVD y las mayoría de las Instrumentales. ··········· En el del CRR resaltan la necesidad de cambio de Centro Residencial. (Esto ya está pedido a través de la Ley de Dependencia) ············································································· Envío también a los A. Jurídicos ACEPTACIÓN PIA de SOLICITUD DE CENTRO RESIDENCIAL, con los centros solicitado y grado nuevo de dependencia que le han reconocido: Grado III, para que lo añadan a los informes se se enviarán al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='DIESTRO'and apellido2='RESECO'),'2023-10-09','-Amalia : Contactan conmigo la TS del CSS Mérida . Quedamos pte. de la aceptación del cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-10-09','Soy María Ángeles, la Trabajadora Social de Valdelacalzada. Me pongo en contacto contigo para tratar el tema de Rosa con respecto a una cuestión en particular. Soy María Ángeles, la Trabajadora Social de Valdelacalzada. Me pongo en contacto contigo para tratar el tema de Rosa con respecto a una cuestión en particular. Mis teléfonos son 627051020 y 615625304.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-10-09','Ana: en relación al correo de la Residencia (a.corral@grupociudadjardin.com): "mañana la señora Joaquina Mayoral tiene consulta en Caceres en Oftalmología tenemos que ver quien la puede acompañar, conocemos a una chica en Caceres que acompañaba a otro señor pero no se como se le puede abonar, Joaquina me dice que no tiene dinero que es otra de las razones por la que necesitaba hablar, me dice que tiene que sellar en el Sexpe por una ayuda que tiene, que le devolvieron el recibo de la Luz y me comento que le dijeron que salieron unas ayudas para los gastos de Luz, Agua y gas que quiere solicitar." ························ Llamo al Centro, Rosana ha salido. Hablo con Andrea, Enfermera: Le indico que el acompañamiento no podríamos abonarlo aún, pues aún no podemos acceder a sus cuentas (nos falta el la firmeza de la resolución judicial), el acompañamiento se abonará, pero no puedo garantizar cuándo. ··· Hablará con la persona de confianza que puede hacerlo. ··············· En cuanto a la necesidad de ir a sellar al SEXPE, le indico que no es real, ella percibe una pensión a favor de familiares, no cobra ningún subsidio. ············································································ Hablo con Rosana - Directora Res. (601644886): Joaquina está bien, tranquila, parece estar adaptándose. Mañana recibirá la visita de su pareja. Saldrán por el pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-10-09','Ana: correo del PAF (programafamilia@tajosalor.es): "informaros que teníamos cita en una óptica en Cáceres para comprar las gafas de Felisa, el viernes lo quedamos cerrado y nos dijo que la llevaba su pareja. Hoy nos dice que su pareja no la puede llevar, miramos el horario de los autobuses y ya no llega a tiempo. Nos dice que lo dejemos para una tarde que le venga bien a Jesús. Sabemos que es complicado que entienda que no nos dedicamos solamente a ellos, pero es que siempre nos hacen lo mismo. La última cita médica de Aitor, nos desplazamos a Cáceres (que es verdad que está a media hora escasa pero nos descuadra toda la mañana) y no fueron porque no quisieron. No podemos estar así. Esto lo estamos haciendo “como un favor” porque al final no es nuestro trabajo y nos está quitando tiempo de ver y trabajar con familias con las que sí tenemos que hacerlo. No sé qué solución podéis darnos…" ······················ Mi respuesta: "entiendo perfectamente vuestra situación. Hablaré con Felisi al respecto, pues eso no lo pueden hacer. Pero también lo hablaré con las compañeras, porque sinceramente, no sé cuál puede ser la solución, máxime sin el apoyo del programa que gestionaba Futuex, y que al parecer no se podrá retomar hasta diciembre…" ······························· Llamo a Felisi (614 361 144): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2023-10-09','Ana: Llamada de Juan José (643 641 375): Dice que con la comida que le llevan del cátering no le llega para la cena y quiere que se amplíe con servicio de cena. ··············· Ocasionalmente trabaja en el Catering Sol sirviendo en eventos para sacarse un dinerino extra, pero es muy puntual. ·································································································································································································· Envío correo a Amadora Pérez, Gerente de Sol Catering (amadora@solcatering.es): "En relación a vuestro cliente D. JUAN JOSÉ GONZÁLEZ CARRERO, cuyo cargo de Curador ejerce la CTAEx, queríamos solicitar PRESPUESTO DE SERVICIO DE CENAS, para ser valorado por la sección económica. En caso de ser viable se podría contratar dicho servicio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2023-10-09','Ana: Correo final de Gema, directora Res. (gemarisan@hotmail.com), tras el intercambio de correos en relación a unas tasas de aduana que en teoría tenía que pagar León: "Me indica que NO QUIERE PAGAR NADA DE LA ADUANA. Que ha hablado con su amigo y que el libro no lo ha pagado aun ni nada, así que finalmente NO QUIERE EL LIBRO, NI NADA. Siento las molestias, pero D. León me da información contradictoria en cada reunión. Lo último que me indica hoy que no quiere saber nada del libro, que duda que su amigo lo haya comprado y que NO QUIERE PAGAR NADA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-10-09','Ana: Respuesta de Marisol Tafur, TS ESM (mariasoledad.tafur@salud-juntaex.es) a mi consulta: "Les acabo de enviar el informe de derivación a la UME. Supongo que se pondrán en contacto con vosotros, te he puesto a tí como persona de contacto para cualquier cuestión referente al ingreso. En cualquier caso, nos avisamos de cualquier cosa." ································································································································································································· Envío correo a Alberto, Secc. Ecca, con copia a Maite: "En relación, a MARÍA GUADALUPE GIL CABELLO, Curatela Representativa, en su momento en la Secc. Social, dadas las circunstancias, decidimos no controlar su cuenta. Es cierto que creíamos que el ingreso tendría lugar de forma próxima a la aceptación del cargo, pero, muy a pesar nuestra, aún habiendo autorización de ingreso involuntario, no ha sido así. Ahora ya el ingreso en C. Sociosanitario tendrá lugar en los próximos días (semanas). En la cuenta no tendrá dinero, no obstante, ya sí que habrá que incluir a la Vicepresidenta y comenzar a controlarlas, sobre todo de cara al próximo ingreso de la nómina a finales de mes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2023-10-09','Buenos días, Amalia. Adjunto comunicado de permiso de convivencia de Regina Reina Lara. Saludos. REGINA REINA LARA, acogida en el recurso sito en C/ Rota 41 de Badajoz y gestionado por Asociación HOFA, disfrutará de permiso en C/ REYES CATÓLICOS 1A VALVERDE DE LEGANES (Badajoz) del 11 al 15 de octubre de 2023 con Dª MARIA DEL CARMEN GONZÁLEZ CORDERAS DNI 80052778 J quien será responsable de la misma durante este periodo, por considerarse beneficioso para su evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2023-10-09','TERESA EMAIL ANTONIO NISA TS DEL SASB FUETNE DEL MAESTRE como ya sabréis desde el pasado Mares Diego se encuentra en la unidad de psiquiatría de Llerena, al parecer sigue igual , alterado obsesionado y descontrolado . por otro lado nos demandan la dentadura , ya que en esos días de extrema crisis la rompió Ponte en contacto con Raquel para que pueda realizar las gestiones con el dentista de poder repararla ( 654691289), ya que al parecer se ha negado a comer ... Por otro lado también quiero deciros que visto todo lo sucedido el día 4 formalice una queja al servicio de 112 por no haber atendido cuando el lunes lo solicité y no hacerlo hasta que la médica de Diego lo activó , ya que en esa jornada hubo muchos hechos que podrían haberse evitado: rompió la terraza entera de un bar, amenazó con un arma blanca a varios vecinos de la localidad , la vecina de mas de 80 años tuvo que irse de su vivienda por las amenazas que recibió por parte de diego , la vecindad no pudo a penas dormir ante las acciones que realizó durante toda la noche , etc No se cuando le darán el alta , pero viendo la situación y la escalada de posible violencia , obsesiones etc , tendríamos que pensar en ver la idoneidad de que siga en su domicilio o ir preparando su ingreso en un centro residencial donde pueda tener acceso a un control más continuo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2023-10-09','Buenos días, Amalia. Adjunto comunicado de permiso de convivencia de Regina Reina Lara. Saludos. REGINA REINA LARA, acogida en el recurso sito en C/ Rota 41 de Badajoz y gestionado por Asociación HOFA, disfrutará de permiso en C/ REYES CATÓLICOS 1A VALVERDE DE LEGANES (Badajoz) del 11 al 15 de octubre de 2023 con Dª MARIA DEL CARMEN GONZÁLEZ CORDERAS DNI 80052778 J quien será responsable de la misma durante este periodo, por considerarse beneficioso para su evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='BLAZQUEZ'and apellido2='RAMOS'),'2023-10-09','Justo ha ingresado hoy en la Felipe Trigo de Villanueva. Hay que hacer un reintegro extra de 25€ para que lo retire el próximo miércoles Concepto: dinero de bolsillo Hay que hacer autorización reintegro la primera semana de cada mes Cantidad 50€ Concepto: dinero de bolsillo mensual El resto de servicios y la plaza lo cargan en cuenta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CECILIO'and edp.apellido1='CASTELLANOS'and apellido2='RUIZ'),'2023-10-09','CIERRE DE EXPTE. POR DESESTIMACIÓN DE LA DEMANDA. Mediante St. n.ª 11/23, de 31 de marzo, dictada por el Jzdo. de 1.ª Inst. e Inst. n.º 1 de Fregenal de la Sierra, se desestima la demanda sobre determinación de la capacidad jurídica, medios de apoyo y salvaguardias, adecuados y efectivos para su ejercicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-10-09','Ana: Llamo a Pilar Martín (54612), me dice que está ocupada. Más tarde mirará quién es el facultativo de referencia y me lo dirá. ·················· Al final de la mañana, llamo al Aux. Adtvo (54613), me indica que su Psiquiatra es Cristina Donoso. ················ Llamo a Centralita (54698): le dejarán nota para que me llame cuando pueda. ··········· **La cita no la tiene mañana, la tiene el día 13. ····························· Llamo a Jesús Manuel: le han llamado esta mañana del Equipo de Salud Mental y sabe que tiene la cita el 13.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='CERRO'),'2023-10-09','Ana: Envío a Rosa Bravo, CI para ANESTESIA debidamente firmado y sellado por la Vicepresidenta de la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2023-10-09','-Amalia : A nivel eco : Juana tiene un nivel muy bueno de control de gastos . Alberto indica si sería conveniente poner un límite , tras hablar con el centro no lo considero necesario ; tiene capacidad para administrarse y así lo lleva haciendo desde hace años. En verano compró algunas cosas por internet con la tarjeta y desde la CTAEX se le bloqueó la misma . El centro vuelve a solicitar la conveniencia de que se la volvamos a conceder . Tanto yo como el centro le hemos explicado porqué se ha actuado así y lo ha entendido perfectamente. No habría problemas en volver a dársela. Vuelvo a solicitar a la S. eco su valoración al respecto , aún sin respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-10-09','Miguel : Buenos días, me ha llamado Damian preguntándome los trámites para la venta del piso. Le he explicado que su abogada de Málaga nos indica que elijamos uno en Mérida por si tuviese alguna preferencia, me ha dicho que no que lo elijamos nosotros, que él quiere al menos 150.000€ y que quería darte a ti el tlfno de Tecnocasa la inmobiliaria que quiere que se la venda. Con la prima dice no tener buena relación y que le pide además del pago de la cerradura que ya dio el visto bueno la parte económica, un viaje creo que a Plasencia…ya le he dicho que lo pida por los cauces que le indicastes. Me comenta que la condición para vender el piso es que después pueda comprarse uno en Mérida, que te lo trasmita. Ya le he dicho que tendrá que reflejarlo en un papel. Dice que no puede utilizar los canales habituales por que el director está de vacaciones y tardará en darle cita. Por tanto hay que evitar tramitar la venta si no le podemos garantizar la compra de vivienda en Mérida. Mañana lo comentaré con Alberto. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-10-09','Buenos días, Amalia Ha llamado Antonia- 656236029- diciendo que en el comedor le han dicho que le dan de baja porque con su sueldo y la pensión se pasa del límite para acceder a ese servicio, aunque ella ya no trabaja desde el día 6. Así se lo ha dicho, pero nada. --------------------------- Me reuno con ella el jueves para darle el cdo. PNC para que lo entregue en el comedor junto con la baja laboral','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2023-10-09','ANGEL escribe : En relación a Joaquín Montaño Montaño, ostentamos el cargo de Defensor Judicial, para encargarnos de proveer todo lo necesario para la administración de sus bienes. Esta medida cautelar se dictó porque consta acreditado que su hermano Damián, ha estado detrayendo dinero de la cuenta de Joaquín para usos distintos a sus necesidades. Adjunto el Auto. Actualmente, se ha iniciado el procedimiento de revisión de medidas, pendiente de resolución. Por lo expuesto, debemos actuar o intentarlo al menos, en la administración de sus bienes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2023-10-09','-Amalia : solicito a M. Angeles del CSS : Buenas , me indican los jurídicos que ya somos D. Judicial y el auto autoriza para administrar sus bienes. Joaquín está abonando algo de copago en el centro ? Cuánto tiempo lleva ahí ? Cual es el pronóstico ? Seguiremos hablando de este caso , se supone que entrará posteriormente como curatela . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-10-10','-Amalia : Hablo con su prima Conchita Garcia , reside en Madrid . Se preocupa por ella y habla a menudo por tf. No quiere que se vaya a vivir con ella a Madrid , tiene 74 años. Tf . 676676984 --------------------------- Hablo tb con Pepa , se encuentra muy confundida , tiene ideas de delirios , que ha denunciado a un vecino Fco. porque es él el que le roba ..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-10-10','Ana: Envío a REGISTRO (oac.merida.san@juntaex.es): "Adjunto remito Oficio-Solicitud de Certificado Actualizado de Pagos del primer semestre del año (Cotizaciones al Convenio Especial por Prejubilación), relativo a VICTOR MANUEL BLANCO POVEDA, cuyo cargo de CURATELA REPRESENTATIVA ostenta la CTAEx, para darle registro y remitir a la Dirección Provincial del INSS de Cáceres, junto a la siguiente documentación: - Testimonio de del Auto de la Medida Judicial, Nombramiento y Aceptación del Cargo" ··································································································································································································· Envío corro-e a los A. Jurídicos CTAEx:"...es el primer caso que tenemos que tiene un CONTRATO DE PREJUBILACIÓN con IBERDROLA (adjunto carta de Iberdrola y Extracto de liquidación-nómina). Tiene un convenio regulador especial según el cual debe hacer aportaciones a la Seguridad Social. Adjunto también el Informe de la Agencia Tributaria con información fiscal (Propiedades, Seguro de dependencia?, valores, fondos de inversión…). La situación parece compleja. Antes de aceptar el cargo, tenía un abogado que se encargaba de todas estas cuestiones, se llama Cándido Moreno (636 222 266). Yo intenté hablar con él, pero me dijo que esta ocupado y que le escribiera un mail. Así lo hice, le solicité información y colaboración, pero no obtuve respuesta. Icíar me dijo que ella también le escribió planteándole que continuase realizando las gestiones que venía haciendo, pues Victor Manuel tiene dinero y podría contratar sus servicios, pero tampoco le contestó. Yo ya he pedido a la Seguridad Social el certificado que solicita Iberdrola, no obstante, ¿sería posible que vosotros como Asesores Jurídicos contactaseis con el Abogado para: - Bien solicitar sus servicios, para que continúe realizando todas las gestiones de las que ya se encargaba antes - Bien para que, al menos, nos facilite toda la información que requerimos (Contrato de prejubilación de Iberdrola y toda la documentación relativa a las gestiones previas realizadas con la misma así como con la entidad bancaria)? Pongo en copia a Maite, Icíar y Alberto." ····················· Ángel, A. Jurídico, responde que llamará él al abogado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2023-10-10','Ana: A petición de Minerva, TS CR Cervantes, envío correo a Noelia, Aux. Adtvo. Secc. Mayores (noelia.cuesta@salud-juntaex.es): "quería pedirte que, cuando puedas, me digas en qué posición está en la lista de traslado. Ella reside en la Residencia Cervantes de Cáceres e ingresó vía decreto por emergencia social." ··························· Noelia contesta que ella no tiene acceso a esta información, al ser por Decreto. ············· Preguntaré a Mai o la Gerencia Territorial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-10-10','Ana: Envío correo-e a Belén Castellano, Directora de la Res. PATRONATO RESIDENCIA DE MAYORES DE HERVÁS (927 47 34 10 / residencia_mayores@hervas.es): "sólo quería preguntarte qué tal ha ido la primera semana de Eugenia en vuestro centro. Ya me dices cuando tengas un huequito." ························ Respuesta de Belén: "comunicarte que Eugenia está contenta se va adaptando bien, va cogiendo sus rutinas en la residencia y fuera de ella, sale mucho a pasear con Pedro por el pueblo. Dice que como en Cáceres solo podía salir tres horas, ahora que tiene total libertad para entrar y salir se aprovecha. Yo personalmente la veo bien, seguimos en contacto, gracias."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-10-06','Ana: Llamada de Manuel Andrés Casado - EVD CC (22049): han recibido la solicitud de revisión PIA, dejarán abierto a todos los centro residenciales de discapacidad. Me enviará por mail la Aceptación PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-10-04','miguel, email de Jose Santiago Lavado >2981@icaba.com> Buenas tardes Miguel. Aún no hemos tenido respuesta del juzgado, le pregunté al procurador y quedo en que lo miraría en el juzgado y me diría. Han pasado 15 días y no me ha dado respuesta, le he llamado y no me contesta. Te remito su núm de teléfono por si consideras debes ponerte en contacto con el. 607 821 764. Si se algo te lo haré llegar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-10-09','miguel, email de José Santiago Lavado: Por fin el viernes pude hablar con la funcionaria que lleva nuestro asunto, se comprometió conmigo que esta semana lo pasaba a su señoría para que firmara la rectificación, tengo su teléfono, por lo que si no nos llega la vuelvo a llamar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-10-10','Ana: envío correo a Alberto, Jefe Secc. Ecca: "En relación a JESÚS MANUEL RAMOS BARGÓN, tanto él como su madre indican que la casa en la que vive está cada día peor y no reúne condiciones óptimas de habitabilidad. Quiere buscar una vivienda nueva de alquiler, ya le he dicho que él mismo puede realizar la búsqueda y remitir la información pertinente al ctutelar@. No obstante necesita saber qué límite económico tiene a tal fin. Por favor, cuándo puedas, dime qué cuantía máxima podría destinar al abono de un alquiler. Pongo en copia a Icíar para qué esté al corriente, pues ella es la que suele tratar con él para cuestiones económicas. Y a Maite, dado lo complejo de este expdiente." ············································································ Respuesta de Alberto: "EN ESTE ÚLTIMO AÑO HA SUBIDO LOS CONSUMOS (RAZONABLE) Y BAJADO FARMACIA) + REINTEGROS: SOLICITUDES CONTINUAS: TIENE AUTORIZADO 75 €/SEMANA (325 €/MES), PERO LA REALIDAD ES QUE SE LE DAN 370 €/MES. INGRESOS: 783 €/MES + 200 € QUE LE ABONA SU MADRE. SITUACIÓN ECO: CORRECTA GRACIAS A CONTINUA GESTIÓN CTAEX. . POSIBILIDAD INCREMENTAR ALQUILER: SI, SI SE MANTIENE EL NIVEL DE GASTOS QUE HE INCLUIDO. LÍMITE INCRMENTO GASTO EN ALQUILER CON ESTOS DATOS: 325 €/MES (ASÍ NO AHORRARIAMOS UNA PAGA EXTRA ENTERA) --- ACTUALMENTE PAGA 250 €/MES. IMPORTANTE: TENED EN CUENTA LOS POSIBLES GASTOS DERIVADOS DE LOS DAÑOS QUE PUEDA DEJAR EN EL PISO --- SI ESO SE DISPARA VEREMOS QUE OCURRE. . VALORAD SUS CONTINUAS SOLICITUDES DE DINERO + SUS CLASES DE GUITARRA + POSIBILIDAD INCREMENTO GASTOS CONSUMOS O FARMACIA --- SI SUBIMOS ALQUILER Y CUALQUIERA DE LOS ANTERIORES SE INCREMENTA, HABRÍA QUE TOCAR EL REINTEGRO Y NO CONCEDERLE NI UN SÓLO EXTRA." ·················· Mi respuesta: "Cuando hable con él de nuevo, le diré que el límite está en 300€, pues la madre me ha verbalizado ya en varias ocasiones que ella podría ayudarle con algo más de dinero a tal fin."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2023-10-05','Ana: Tras llamada de Loli, RRMM Santa Catalina de Calzadilla (927 14 64 58 // residenciasantacatalina@gmail.com) comunicando que Emiliana necesita acompañamiento, le envío correo: "Tal y como hemos acordado te envío la Declaración Jurada de Acompañamiento, ya lo adaptáis a los servicios que se realicen e indicáis al final el número de cuenta para el abono del servicio realizado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='RODRIGUEZ'and apellido2='CACERES'),'2023-10-10','-Amalia : Hablo con P. Viudedad , su difunto marido , era perceptor de PNC , no creen que haya cotizado los años para generar pensión. De todas formas , registro solicitud y documentación a la oficina OAC de Sanidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-10-10','Ana: Envío correo a Rosa Bravo, Adtvo. CSS-Plas (rosamaria.bravop@salud-juntaex.es): "Tal y como hemos acordado, te envío: - Testimonio de Auto de Medidas Judicial, Nombramiento y Autorización de Internamiento (sí que pone “adecuado a su patología”) - Auto estimando el internamiento - Acuerdo de Aceptación del cargo por la CTAEx Como ves se autoriza por partida doble, en ambos documentos (2022 y 2023)." ······································································································································ Tras hablar con Montaña, TS La Cumbre (621 247 249), y a petición suya, llamo a Loli, Secretaria Judicial. ······························ Envío correo a A. Jurídicos: "He hablado con Loli, Secretaria Judicial (927 32 00 85) de la Jueza Patricia Gutiérrez, del Juzgado nº 2 de Trujillo. En relación a la Solicitud de Abogado de oficio por parte de Mª Guadalupe Gil Cabello, me indica que os ha remitido por LEXNET Resolución Judicial. Tal y como hablamos ayer Maite y yo con Ángel, se puede continuar con el proceso de ingreso en UME (C. Sociosanitario). Expresa que aún no siendo firme el último Auto en base a la reclamación de Mª Guadalupe, es procedente continuar con el ingreso." ······························································································································································································ Llamada de Mª Sol Tafur, TS ESM-Trujillo (54509): Me informa que finalmente han decidido que Mª Guadalupe ingres primero unos días en UHB. El lunes Miguel Medina, Psiquiatra, estará de guardia en el hptal. y si hay camas avisará al Dr. Alfredo, MAP de Guadalupe, para que active el 112 y la ingresen. ·········· Llamará ella a Montaña para comunicárselo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-10-10','Ana: Llamada de Cristina Donoso, Psiquiatra ESM-CC (54605 / cristina.donoso@salud-juntaex.es): Informo de la conversación mantenida con Jesús Manuel el viernes de la semana pasada, la dificultad para entenderle y los posibles delirios. Los tendrán en cuenta en la cita del viernes. ··········· Me indica que si algún día le vemos más alterado de lo habitual y sin querer ingresar voluntariamente, llamemos al 112 para comunicarlo. ················· Solicito me envíen INFORME de la consulta del día 13.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN FRANCISCO'and edp.apellido1='OSORIO'and apellido2='CALDERON'),'2023-10-10','TERESA ENVIO A SANDRA PSICOLOGA direcciontecnicacrrdonbenito@hospitalsanantonio.com CRR CITACION PARA EL DIA 16 Y LE SOLICITO INFORME PARA MEDIDAS DE APOYO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='GARCIA'and apellido2='AMBROSIO'),'2023-10-10','TERESA Le escribo para comunicarle que en el día de hoy se ha llevado a cabo la valoración de Dependencia de Félix García Ambrosio. El equipo de valoración nos ha comentado que a finales de semana nos llamarán para darnos los resultados de la valoración, si sigue con el mismo grado o pasa a Grado III. Estamos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-10-10','-Amalia : Hablo con ella y su abogado. Ha tenido problemas en el banco , los 400€ no están hechos como transferencia pte. si no puntual . Lourdes se lo anota para el mes que viene hasta que se pongan en pie sus cuentas. Hablo con el abogado , podría hacer todas esas gestiones de bancos , seguros , coches .. pero si se le autoriza y se le paga desde la CTAEX . Se lo digo Alberto , espero respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2023-10-10','-Amalia : información que solicitaba Alberto . El email es de Mª. Angeles Galindo del CSS Mérida. Joaquín paga tasas, las cuales abona mensualmente por un importe de 873,89€. Joaquín ingresó en una Unidad de Larga Estancia el día 08/05/2008. Como te comentaba en el informe social en julio solicitó plaza pública en centro residencial para personas mayores y plaza sociosanitaria T4. Así que, se prevé su externalización. Posiblemente, esté mucho tiempo en lista de espera, debido a que tiene un Grado II de dependencia y a que tiene una capacidad económica alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2023-10-10','Ana: Envío a los A. Jurídicos CTAEx: "Os reenvío correo de Maite Cañadas, Directora de la Residencia San Francisco de Plasencia con: - Informe Médico - Informe Social Para el procedimiento de revisión de medidas judiciales de apoyo relativo a Dª LUISA REY CAMPÓN. A ella también se lo pidieron directamente del Jdo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2023-10-10','Ana: Correo de Estrella Durán, CSS Plas (estrella.duranc@salud-juntaex.es): "ha ingresado hoy en UME de este centro socio-sanitario procedente de la UHB del Hospital Virgen del Puerto, Alfonso Marín de Cáceres."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-10-11','Ana: Nos remiten desde el ESM el Informe de Seguimiento solicitado. Guardado en expte. ···· La última consulta de seguimiento tuvo lugar el 31/08/2022. Las han retomado a raíz de nuestra solicitud de informe. ···· En las consultas siempre "se muestra querulante y desconfiado", "quejas con respecto a su curatela", "reticente con el tratamiento", Dx: Trastorno Bipolar, Trastorno Personalidad Paranoide, Trastorno por consumo de sustancias en remisión" ············· *Al final del informe indica: "El juzgado debe ordenar que el curador acompañe al paciente a las consultas. EL PACIENTE DEBE VENIR ACOMPAÑADO. UNA PERSONA DEBE RESPONSABILIZARSE DE QUE ACUDE A PONERSE EL INYECTABLE". ······························································ Se lo reenvío a Maite, Jefa CTAEx, quien responde: "Sin el apoyo de Futuex, no es posible que vaya acompañado. ¿ Sabemos cuando tiene cita de nuevo?. Se lo pasaré a Estrella. Pero hasta que no se tramite todo el tema de FUTUEX, no hay nada que hacer……."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2023-10-11','Ana: Envío a Asun Maqueda Grajera, TS CR Cervantes (masuncion.maqueda@salud-juntaex.es) CI para la administración de la Vacuna de la Gripe + la del recordatorio de la Covid, firmado digitalmente por la Vicepresidenta de la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-10-11','Ana: Correo de ayer de Puerto Paniagua, TS Valdeobispo (ssb5@mancomunidadvalledelalagon.es): "sabes cómo sigue Enrique? te comento, en el servicio de ayuda a domicilio municipal una de las auxiliares que iba a casa de Enrique ha terminado el contrato y hay nuevas peticiones que tengo que dar de alta, por tanto, al inicio del contrato de la auxiliar las horas de Enrique no se las puedo reservar, por tanto, se le va a dar de baja en el SAD municipal. Si vuelve lo pondría en la lista de espera hasta poder ponerle a dos auxiliares... aunque espero que siga en el sociosanitario porque dadas las circunstancias que tiene el mejor recurso es ese, unidad de rehabilitación de agudos." ··········································· Mi respuesta: "Gracias por informar, entiendo la situación ya que tengáis que darle de baja. Yo también considero, que al menos a día de hoy, debería permanecer en la Unidad de Media Estancia, que es dónde se encuentra, y si fuera preciso, traslado a la Unidad de Rehabilitación. El otro día me informaron que pensaban que la medicación no le hacía efecto, pero que una Enfermera se dio cuenta de que les estaba engañando y no se la estaba tomando. Yo entiendo que si en un centro especializado no se la toma, en casa será más complicado que lo haga. Ya propuse en su día que se convoque una subcomisión, pues es un caso muy complicado y en su localidad y domicilio, cada día contamos con menos apoyos para poder atenderle adecuadamente. Así mismo, consideramos que, dados los antecedentes y las circunstancias, el hecho de que viva solo supone un riesgo para su propia salud y bienestar así como para los vecinos del municipio. Pongo en copia a Estrella Durán, compañeras del Centro Sociosanitario; a Ana María Benavente, compañera del Equipo de Salud Mental; y a Maite, Jefa de Sección de la CTAEx, para que estén todas al corriente y mantengamos una adecuada coordinación con respecto a este caso." ···························· Respuesta de Estrella, TS CSS: "Reenvío al equipo ETAC y la Psiquiatra de UME."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-10-11','miguel, llega email de la notaria de Santos de Maimona donde ha sido firmada la compraventa con protocolo 772. Quedan por ratificar la compraventa de protocolo 344 de mayo-23 y ésta de protocolo 772. Cuando esté modificado el certificado de nacimiento donde se incluya que el tutor es la Ctaex podré ratificar dichas escrituras en la notaria de Mérida (está pte que lo modifiquen en rgtro civil de Badajoz donde se ha solicitado vía fax al jzdo de Villafranca nº1 para que insten a dicho rgtro civil y por email a dicho rgtro civil de Badajoz) Queda pendiente también que el jzdo haga la modificación del Auto que se presentó hace meses por el despacho de José Santiago (abogado de la otra parte)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TERESA'and edp.apellido1='CABRERA'and apellido2='MUÑOZ TORRERO'),'2023-10-11','MODIFICACIÓN DE EXPTE. Mediante Auto n.º 103/23, de 11 de julio, se Revisan las Medidas de Apoyo de Dña. Teresa. Se nombra Curador Representativo a la CTAEx. Se procede a la modificación del expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2023-10-11','Ana: Correo de Mª Ángeles, Aux. SAD (pedro69mariangeles64@gmail.com) al ctutelar@: "Buenos días. En el mes de julio se le reventó a Felipe Rodríguez Solís, de C/ Quinto Centenario n° 2- 1B, de Miajadas, el termo de agua. Por falta de tiempo y no tener la factura hasta ahora, no he hecho la petición de pago. El fontanero lo puso, aunque sabía que tardaría en cobrarlo, pues es algo muy necesario. Les mando la factura, para que den la orden de, que, el banco de Felipe haga el pago. Soy la cuidadora de Felipe. María de los Ángeles Ocampos Fenoy." ································ Respuesta de María, Secc. Ecca: "Buenos días M. Ángeles, me pongo a tramitar el pago."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-10-11','Ana: Envío a Pilar Cerrillo, TS Grupo Ciudad Jardín (calidad@grupociudadjardin.com): "adjunto te envío la autorización de vacunación del COVID y de la Gripe para Dº. María Jiménez Picón, firmada y sellada por la Vicepresidenta de la CTAEx."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2023-10-11','Ana: Recuerdo a Teresa, Novaforma, que en la Sentencia de Felipe especifica que la Curatela tiene alcance parcial extendiéndose en exclusiva "“evacuación de los actos de contenido netamente patrimonial”.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2023-10-11','Maite:ha llamado Mª Angeles, hermana de Isabel. Quiere ser su tutora y dice que Isabel quiere hacer testamento. Le he dicho que tiene que ser a través del juzgado. Y que si quiere hacer testamento no hay problema. Insinua que cuando su hermana fallezca la junta se queda con el dinero......le he dicho que los herederos , hay testamento o no , son los que se estabñece por ley...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='ESTEVEZ'and apellido2='RODRIGUEZ'),'2023-10-10','-Amalia: hablo con Gloria , PFHC por los meses de junio y julio pendientes . Se ha solicitado el abono el 6/09/23 , se cobrará la semana que viene . Septiembre está pagado pero viene devuelto por el banco , hay que hablar con el banco .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2023-10-11','Ana: Correo de Tensi, TS (ssbtensi@riberosdeltajo.es) con INFORME MÉDICO de Serv. Cirugía Gral. y Digestivo. ······ Diagnóstico HERNIA INGUINAL DERECHA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-10-09','Ana: correo de Carolina, Directora del CRR-Plas (direccion.crrplasencia@grupo5.net) con propuesta: "A pesar de haber adquirido un teléfono móvil en febrero y no tener claro cómo se ha roto el suyo, consideramos necesario para ella que tenga uno puesto que hace un uso habitual y ajustado del mismo. Por eso proponemos y hemos hablado con ella solicitar un adelanto del extra anual de 2024 tal y como nos indicasteis para la compra del mismo. No obstante, ella asumiría 30 euros (que ahorrará en el mes de noviembre y diciembre). Por lo que, si estaís de acuerdo, necesitariamos retirar de su cuenta 180 € (los 30 que ahorra ella se guardarán para 2024 ya que aún no están ahorrados)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-10-11','Ana: Llamada de Doroteo (609 928 621), dice que está muy bien allí en el CRR, pero que quiere pedir el traslado a CC. Argumenta que para estar más cerca de la familia, él no se lleva bien con la madre y se lo verbalizo y lo admite. ······· Le recuerdo que hasta que no lleve al menos un año en el centro no puede pedir el traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-10-09','Ana: correo de Carolina, Directora del CRR-Plas (direccion.crrplasencia@grupo5.net) con propuesta: "Consciente de la gravedad de apertura de cuenta/tarjeta bancaria y de las consecuencias respecto a vosotros. Le hemos informado de la penalización en sus extras por este mal uso (actualmente le quedan unos 700 € hasta final de año) Consideramos que vosotros la Comisión como tutores legales y para darle la importancia que merece a esta acción y ya que ha sido una propuesta vuestra, sería oportuno que le informeis por escrito de esta penalización y la cuantía que determineis (¿300?). Desvinculando esta acción del CRR Respecto al dinero mensual y gasto de cumpleaños sí que desde el centro mantenemos el trabajo y acuerdos, por lo que el día de su cumpleaños podría diponer de 40 € para irse a comer con quien quiera (no más porque ya se acordó que el regalo era el teléfono movil, acuerdo que él firmó con su psicóloga). Por otro lado y en la linea de trabajar el aumento de responsabilidad e implicación en su proceso de rehabilitación del que ayer hablamos y para aumentar su participación en grupos y funcionamiento de la residencia consideramos que bajarle su asignación como nos dijisteis no sería adecuado (puesto que ya tendría la penalización de su extra anual), pero sí que vincular los extras mensuales a su compromiso y poder hacer uso de ellos en función de la asistencia o no. De esta manera no usariamos el castigo como forma de aumentar su implicación sino el premio Ya nos decis que os parece. estamos en contacto"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2023-10-10','-Amalia . Defensa Judicial , empezamos a intervenir , el juzgado solicita medidas cautelares. En el expediente tengo archivado sus datos personales y su I.S. Está en CSS Mérida, el hermano le está sacando el dinero de las cuentas . LLamo a PFHC , no ha percibido la pensión en agosto . Me informan que su hno. Damián ha hecho un cambio de cuenta a B. Pueyo , la PF sigue en alta . La está cobrando él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-10-13','Ana: Envío correo a A. Jurídicos; Alberto, Jefe Secc. Ecca.; y Julio, Aux. Adtvo. - CTAEx: "...ha cambiado de recurso residencial. Ha ingresado, el día 4 de octubre, en la RESIDENCIA DE MAYORES “CATALINA CURIEL” DE ALMARAZ. • Julio, cuando puedas porfa, modifícalo en la base de datos. • Ángel y Miguel, supongo que tendréis que comunicarlo al Juzgado. Adjunto la resolución de plaza. o Por cierto, me dijo el miércoles que quiere vender su piso de Badajoz. • Alberto, en este centro sí paga por la plaza. En la página 4 de la resolución tienes el coste que le supone. *Además, habrá que ver si es necesario reajustarle la asignación mensual y enviar nueva autorización de retirada de efectivo al banco (en las mismas condiciones de periodicidad y acompañamiento, que en el CRR). Espero que haya la entidad bancaria." ·········································································· *Carolina, Directora-CRR, me confirma que comunicaron la baja en el servicio de SAD que recibía Flora en su centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-10-13','Ana: Envío correo-e a Alberto, Jefe Secc. Ecca. CTAEx: "En relación a Javier Agudo Cumplido, sigue a la espera de que le den plaza de nuevo en recurso residencial de Salud Mental. De momento ha encontrado una habitación de alquiler en piso compartido en Plasencia por la que abona 225€/mes (lo abona en mano). Por tanto, con la asignación mensual de 500€ no le llega para todo y solicita se le suba la asignación a 650€/mes. Yo lo veo bien pues él puede permitírselo. Habría que modificarlo ya para el mes que viene, pero para lo que queda de mes, no le da, por lo que ahora habría que autorizarle un extra de 150€." ······························· *Alberto autoriza ambas cuestiones. María hará las gestiones. ····· Yo le avisaré cuando cambien las circunstancias para volver a bajar el reintegro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2023-10-13','Ana: Envío a Alberto, Jefe Secc. Ecca. PRESUPUESTO Completo del Catering Sol (Comida + cena: PRECIO TOTAL SEMANA: 79,80€ IVA (10%) INCLUIDO) ························ Envío correo a Amadora Pérez, Gerente de Sol Catering (amadora@solcatering.es): "Confirmamos la ampliación del servicio de catering, incluyendo las cenas, conforme al presupuesto facilitado. Supongo que podrá ser efectivo para la semana que viene."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2023-10-13','Ana: envío a Belén Pavón, Responsable PPTT Villa del Rey - Grupo Asoma (Belen.asoma@outlook.es): "Adjunto remito el CONSENTIMIENTO INFORMADO para la administración de las Vacunas de la GRIPE + Recordatorio de COVID relativo a María Salvadora Chaves Mendoza, firmado digitalmente por la vicepresidenta de la CTAEx."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-10-13','miguel, Ana nos comunica el cambio de domicilio que Inés comunica al jzdo vía lexnet. En cuanto a la venta del inmueble la documentación de la herencia, junto con la tramitación de la declaración de herederos y las renuncias de las hermanas, hace meses que está parado en la notaria. Envío email a la notaria de plasencia mplgonzalez@despacho.notariado.org: Buenos días, necesitamos saber en qué estado se encuentra esta herencia. En su día sus hermanas querías renunciar a la herencia, pero estaba pendiente de firmarse la declaración de herederos, está firmada ya? Si es así qué necesitan para proceder a formalizar la escritura de adjudicación de herencia que sería ratificada por esta Comisión Tutelar de Adultos. Les adjunto nota simple y en cuanto a las cuentas bancarias que dejó su madre fallecida Modesta Garcia Piñero eran: 1.- Era titular junto con su hija Flora de la Cuenta nº 0182 2874 070201531924 de BBVA en la oficina de Badajoz , cuyo saldo a fecha de 30 de diciembre de 2020 era de 16.691,19€ 2.- Era titular de la Cuenta nº ES39 2048 1150 4634 00021974 de Liberbank cuyo saldo a fecha de 25 de noviembre de 2020 era de 188€ Quedo pendiente de su respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-10-13','Ana: Llamada de Carlos muy nervioso. Está ingresado en el Hptal. San Pedro de Alcántara. El miércoles por la tarde jugando a futbol se cayó y tuvieron que llamar a la ambulancia. Según dice, le hicieron radiografía, no hay fractura ni esguince. Sólo están dañados los tendones y necesita reposo. Pero le han dejado ingresado y no le dejan irse a casa. Y él se quiere ir a su casa. Se ha duchado él solo y se ha inyectado solo la Heparina (anticoagulante). ····· Dice que está en la planta 2, habitación 212, no sabe qué servicio es. ···························· Llamo a Luli, TS (56348): confirma que está en MEDICINA INTERNA. Entiende que si sique allí es porque hay criterio de ingreso. Le indico que es una CURATELA CON FUNCIONES ASISTENCIALES Y REPRESENTATIVAS. ····· Hablará con los Internistas y les facilitará mi número directo o me volverá a llamar. ·································· Llamada de Luli, ha hablado con la Internista y con la Dirección Médica: Le han puesto escayola, le habían "ingresado por situación social". Le van a dar el alta esta misma mañana. ··················· Para el Informe de Alta me dicen que lo solicite con oficio por registro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2023-10-13','Ana: Envío correo a la RRMM Santa Catalina de Calzadilla (residenciasantacatalina@gmail.com): "Adjunto el Consentimiento Informado para la administración de las vacunas de las GRIPE y el recordatorio del COVID, firmado digitalmente por la Vicepresidenta de la CTAEx."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-10-13','Ana: correo de Carolina, Directora del CRR-Plas (direccion.crrplasencia@grupo5.net): "informaros que Isabel tiene cita en los juzgados el día 26 de octubre a las 9,30, por el tema de la pareja de su madre. Otra profesional del centro también ha sido citada como testigo (fue a la educadora que Isa contó todo). En un porincipio Isabel se iba a ir a casa en esa semana para conocer a su sobrina, pero ésto lo impide. Como aún no ha llegado a verla consideramos que es beneficioso que se vaya la semana que viene del 16 al 20, que era la otra fecha que planteabamos. Por nuestra parte no hay problema y no han existido incidencias que justifiquen que no vaya. Ella es consciente de que es el último viaje del año, ya que no le queda más dinero de extras según lo planificado ." ··························· Damos el Ok al cambio de fecha del viaje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='LOPEZ'and apellido2='THOMAS'),'2023-10-13','Ana: Comunican desde la Residencia el fallecimiento. ··········· María - Secc. Ecca., ha hablado con la funeraria, la enterrarán esta tarde. ················ *No tiene seguro de decesos pero tiene dinero para abonarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-10-13','Ana: Guardo en el expediente digital la fotos, capturas de pantalla de WhatsApp y el escrito que Carmen, hermana de Enrique (maluker6@hotmail.com), que ha remitido al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-10-16','Ana: Correo de ayer de Azucena, Cuñada de Juanjo al ctutelar@ (azuydavid153@gmail.com // 625 367 302): "Hola a ber si le podéis buscar algo Juanjo para metelo en un centro por qué ya no se le puede aguantar más estos es importante cuando no tiene dinero me la lía y le tengo que dar yo el mío y ya no aguanto más la abitacion no la limpia su ropa no la coloca y muchas cosas más y no aguntimo más a ber si me puede dar una solución porfavor espero tu respuesta" ···································· *Respondo: "Entiendo que la situación cada día es más difícil. Desde aquí se ha solicitado la ampliación de la solicitud de centros, para que haya más opciones y puedan darle plaza antes. No obstante, de momento, él tendría que querer pues no tenemos autorización de internamiento involuntario. *De todas formas, decirte que el Juzgado ha iniciado procedimiento de revisión de sus medidas judiciales y desde aquí se le va a plantear al Juzgado la necesidad del ingreso en centro." ·························································· Nuevo correo de Azucena por la tarde: "Si estos ya no se puede aguantar más a ber si no tarda mucho el si quiere y se pone sería por la malas no lo aguanto más lo siento solo quiere dinero y cuando no tiene le tengo que dar yo y eso no puede ser gracias"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2023-10-11','TERESA Se adjunta expediente para ingreso por situación de EMERGENCIA SOCIAL de Mª Elena Durán Durán La señora se encuentra hospitalizada en UHB de LLERENA y recibirá el alta médica el viernes, no siendo posible su regreso al domicilio. Se encuentra Tutelada por la Comisión Tutelar de Extremadura y la persona de referencia es Maite (Jefa de la Comisión) 924006057. Teléfono de la trabajadora social del hospital de LLERENA 924 87 70 85 Psiquiatra de referencia: Constanza. En cuanto tengamos la resolución firmada os la haremos llegar pero el ingreso debe realizarse el mismo día del alta (aunque la resolución firmada os llegue con posterioridad). Por favor, contactar con el hospital para poder coordinar el traslado de esta señora. INGRESA EN RESDENCIA DE LOS SANTOS DE MAIMONA EL VIERNES 14','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-10-16','Ana: Envío a Gema Morato, Directora Res. Grupo Asoma (gemamg.asoma@gmail.com) C.I. administración Vacunas Gripe + Recordatorio COVID, firmado digitalmente por la Vicepresidenta de la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-10-16','Ana: Envío a Gema Morato, Directora Res. Grupo Asoma (gemamg.asoma@gmail.com) C.I. administración Vacunas Gripe + Recordatorio COVID, firmado digitalmente por la Vicepresidenta de la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-10-11','Ana: correo del PAF (programafamilia@tajosalor.es): "Buenos días compañeras, os adjunto el ticket de la compra realizada con Aitor. Otra cosilla, Felisi y Jesús han vuelto a dejarlo, ojalá sea la definitiva aunque no lo creo… Es bastante complicado que podamos movernos a Cáceres a por las gafas de Felisi por todo lo que conlleva: estar allí cuando llegue el autobús, acompañarles a la óptica, volver a llevarles a la estación y esperar a que cojan el bus, nosotras tenemos que pedir permiso, esperar que nos lo acepten… por lo que hemos pensado que podrían venir a ópticas de aquí de Arroyo, solicitar aquí los presupuestos y una vez que nos deis el ok pedirlas. Os parece bien? Se lo hemos comunicado también a Estrella que estaba esperando que le enviásemos la factura… lo habláis si queréis y nos decís, vale? Aitor, como era de esperar, quiere un móvil. Si os parece aprovechamos el día que vengan a las ópticas y pedimos presupuesto también y os lo enviamos." ············· Damos Ok a la propuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-16','NUEVO NºTF MOVIL DE CARMEN LEAL: 636593574 La estoy llamando para la cita del CADEX y no coge tf. Me devuelve la llamada , se niega a ir a la cita , avisamos al CADEX de la decisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='LOPEZ'and apellido2='THOMAS'),'2023-10-13','EXITUS El centro informa de su fallecimiento acaecido el 13/10/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-10-16','Ana: Correo-respuesta de Carmen Santos, hermana de Enrique (maluker6@hotmail.com): "por supuesto, muestra todo a la subcomisión por favor, mi hermano Jose Ignacio también ha realizado un escrito para el juzgado, le diré que te envíe copia a ti también. Sabemos y queremos el bien para nuestro hermano, es duro estar en un recurso alojativo, lo veo a diario en mi trabajo, pero su vida es mucho peor fuera, por estos motivos existen precisamente estos recursos, hay personas que no están capacitadas para vivir independientemente de una manera digna y saludable. Mi madre vivió esa dualidad de no poder más y a la vez de la presión como madre y también de la sociedad, de mi abuelo paterno, de mi hermano pequeño que ha vivido siempre fuera y no sabía de la realidad, pero realmente Enrique, Quique, como le llamamos tenía que haber estado ya hace muchos años en un recurso alojativo adecuado para su bienestar y el de todos." ··············································································································································································································· Correo de José Ignacio Santos, hermano de Enrique: "Soy Jose Ignacio Santos García-Puente. Adjunto le remito una copia del escrito enviado al Juzgado de Plasencia en relación a la petición de ingreso de mi hermano, Enrique Santos García-Puente, en un recurso asistencial. Quedo a su disposición en mi teléfono 670743476 para lo que consideren oportuno. En caso de alguna comunicación pueden hacerlo a este correo o al teléfono de mi esposa Amelia M. Ortiz 635108936, dado que en horas de trabajo normalmente no puedo llevar el teléfono conmigo" Adjunta enlace a la nube con el ESCRITO en documento. Lo descargo y guardo en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-10-16','Ana: Correo de Raquel Vadillo Martín - Dpto. Administración - Resid. "Catalina Curiel" - Almaraz (rvadillo@residenciacatalinacuriel.es): "Te mando toda la documentación perteneciente a Flora Gutiérrez, para que me remitáis firmado el contrato de admisión y la autorización bancaria. También te pregunto algunas cosas para que me deis respuesta en caso de que sucedan" ················ Llamo a Raquel y respondo a las preguntas planteadas. ······················ Le envío correo: "Seguro de Decesos, tiene póliza en Santa Lucía, adjunto copia de la Póliza. Como veréis en la misma, aparece con su madre ya fallecida. Aún no nos han enviado la actualización con ella sola, mi compañera volverá a reclamarla, pero el número de póliza es el mismo. En relación al resto de preguntas, espero haber aclarado tus dudas antes por teléfono, sino volvemos a hablar. Los documentos, en cuanto me los devuelvan firmados te los hago llegar. Y por último, cuando Alberto, Jefe de Secc. Ecca., valore todo lo que nos indicas sobre los gastos, te confirmamos la cuantía para gastos de bolsillo + extras." ········································ Reenvío a Alberto, Jefe S. Ecca. la Autorización Bancaria y el escrito con aclaraciones de previos de los distintos servicios. ························· Subo al portafirmas el contrato y la autorización de uso de cinturón en caso necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2023-10-16','-Amalia : escribo a Mª Angeles , es D. Judicial , pero con medidas cautelares para empezar a intervenir en las cuentas y evitar que su hno. se quede con su dinero . He averiguado en PFHC que en agosto su hno. ha cambiado el Nº cuenta , se ingresa en una cuenta de él . Procedo a solicitar al INSS cambio de las dos pensiones , Orfandad y PFHC al Nº cuenta donde está como único titular . Es de Ibercaja : ES62 2085 4511910331946300. Me dice Alberto que te comente esto : AMALIA: HABLA CON EL CENTRO PARA QUE SI PUEDEN LE PASEN LOS RECIBOS CUANDO YA TENGAMOS LAS 2 PENSIONES EN CCC SÓLO TUTELADO...SI ES POSIBLE. AMALIA: TELEFONÍA: EL TUTELADO TIENE QUE ABONAR ALGO X ESTE CONCEPTO??? O TODO LO QUE SE CARGA ES DEL HERMANO??? AMALIA: COMO VAMOS A PASAR LAS PENSIONES A CCC SÓLO TUTELADO SE DEJARÁN DE ABONAR COSAS QUE VAN A GENERAR DEUDA: FINANCIERA CAREFORU, TELEFONÍA, OAR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='LEAL'and apellido2='PARRA'),'2023-10-16','-Amalia : llega la firmeza de la sentencia . Estuvo en CSS de Mérida y desde allí me informan : Hola, este señor lleva ya mucho tiempo fuera: desde el 21/9/2021. Nosotros le derivamos al CRR, si no me equivoco, de Mérida, pero allí pidió el alta voluntaria y se marchó. En principio, según nos contaron, se fue con su hermano, Juan Luis. Que sepamos, es con quien más relación tenía. El teléfono de contacto de éste que nos consta es: 618601838. La dirección familiar que tenemos es C/ Pedregosa, 31, de Arroyo de San Serván. La madre: Ana Mª Parra Pérez: 633110741 - 646960328. La trabajadora Social de contacto en su pueblo que tenemos anotado es Beli: 678085402.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2023-10-16','Ana: En relación al correo de Alberto: "ANA: ACABAMOS DE HACER FICHA DE ESTA PERSONA. • SALDO HOY: 0 € • INGRESOS: PNC BASICA 484,61 €/MES • GASTOS: TODA LA PENSIÓN EN REINTEGROS ---- EL SALDO ANUAL Y PREVISTO ES NEGATIVO. • SEGÚN INFORME SOCIAL VIVE DE ALQUILER CON SU PAREJA (JESUS) QUE COBRA UNA PN SUPERIOR A 1.000 € • COMO TE INDIQUÉ ANTES EN SU CCC (TUTELADA) NO PAGA NI ALQUILER NI CONSUMOS. SUPONEMOS QUE LO PAGA EL • INFORME SOCIAL: INSINUA QUE EL ES LUDÓPATA (O LOS 2). ACTUACIONES: • ESTABLECEMOS UN REINTEGRO LO MÁS PEQUEÑO QUE CONSIDERES "O" RESTRINGIMOS TOTALAMNTE LA CUENTA Y VEMOS LO QUE OCURRE. • LA ÚLTMA PROPUESTA LA BASO EN LO QUE PARECE QUE COBRA JESUS, SU PAREJA... IMPORTANTE: ANA, NO TENEMOS DNI ACTUALIZADO...CUANDO PUEDAS HAY QUE INTENTAR CONSEGUIRLO O TRAMITARLO. ANA: HAY QUE VALORAR SI LE CANCELAMOS LAS TARJETAS YA O ESPERAMOS A QUE TOMEIS ALGUNA DECISIÓN." ···················································· Contesto con copia a Maite, jefa y TS: "Tod@s: Con esta persona no se ha llegado a trabajar aún. Si no me equivoco ninguna de las tres TS hicimos el plan de intervención inicial, pues cuando se aceptó el cargo estaba en paradero desconocido y quedó pendiente de reparto. Yo no sabía que había llegado ya IFORME SOCIAL en septiembre. Compis, viendo que en Septiembre no ha entrado ningún expediente de mi zona, pues “me quedo este”. Alberto, lo de la ludopatía, creo que lo que dice el Informe Social es que la familia de ella acuda a su novio de esto, pero no hay más información al respecto. Todo lo que tenemos es lo que ambos hemos leído, de momento no hay más. Tendrás que darme un margen. La intervención inicial y seguimiento en este caso va a ser complicado sin el apoyo del Programa-Convenio con Futuex. Pues la visita inicial podría hacerla, pero lo de hacerle seguimiento periódico en domicilio (Plasencia) es materialmente imposible. Maite lo hablamos cuando estés recuperada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-10-16','Ana: llamo a Javier (641 08 64 09) para confirmarle que se le ha aprobado el extra de este mes (150€) y la subida a partir del mes que viene (a 650€/mes, hasta que cambie situación y vuelva a ingresar en centro). *Pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2023-10-16','Ana: Llamo a Juan José (643 641 375): le confirmo que a partir de mañana comenzará a recibir el servicio de catering ampliado con las cenas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VERA LUCIA'and edp.apellido1='DA CONCEIÇAO'and apellido2='BEZERRA'),'2022-07-25','-Amalia : se hacen las gestiones para renovar su permiso de residencia , se archiva todo en su expediente. Tendría que renovarlo en 2027 nuevamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-10-17','Ana: Correo de Estela, Directora del CR Las Eras de Hernán Pérez (rmhernanperez@mensajerospazex.es) al ctutelar@: "me pongo en contacto con ustedes en referente a la residente Pilar Diaz, en primer lugar, informarles que está muy contenta y motivada en nuestra Residencia. En segundo lugar, hace unos días se ha puesto en contacto con nosotros el hijo de Pilar para hablar con ella, en ningún momento se le ha pasado el teléfono. El hijo nos explica que sabe que su madre esta aquí porque se lo ha dicho el hermano de Pilar, que había salido de permiso pero que en 2 días volvía al centro penitenciario en el que se encuentra. Habla con nuestro Neuropsicólogo y este le explica que por el bienestar de su madre no se le pasara el teléfono. El viernes día 13/10/2023 se puso en contacto con nosotros la trabajadora Social del Centro Penitenciario a la cual le dimos las mismas explicaciones y que además estaba bajo vuestra tutela. Nos dice que su hijo cuando se le conceda la salida de la cárcel quiere ir a vivir a casa de Pilar. Y para saber si eso sería posible, comento que esto sucedería por el mes de mayo 2024." ················································ Mi respuesta: "Muchas gracias por informar. Me alegro que Pilar se haya adaptado bien y se encuentre así de contenta y motivada. Ojalá siga así. Con respecto a las llamadas del hijo, perfecto, habéis actuado bien, pues por el bienestar de Pilar, dados los antecedentes, no le conviene ese contacto telefónico. En cuanto la consulta del piso de Pilar, lo valoraremos en equipo con los Asesores Jurídicos, para ver si es conveniente y viable lo que solicita (tiene otra hermana) y tendremos que ver también el Certificado de Titularidad del Catastro. Por último, por favor, cuando puedas, remíteme Certificado de Residencia de Pilar en vuestro centro con la fecha en la que ingresó en la misma, pues con tanto jaleo este verano olvidé pedíroslo." ·········································· Pido a Julio, CTAEx, que modifique el domicilio en la base de datos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-10-17','-Amalia : escribo a Miguel : adjunto informes médicos de hace unos meses y es lo más actualizado que vamos a tener porque no ha vuelto a consulta. El internamiento involuntario sería en CSS de Mérida para su estabilización y compensación de su patología mental . ( lo he hablado previamente con Soraya y lo ve así mejor . Si cuando ingrese allí consideran que tiene que venir a UHB lo trasladarán pero indicando CSS de entrada podría permanecer allí más tiempo. ) Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='CASQUERO'and apellido2='JAEN'),'2023-10-16','miguel, envío email a la notaria: amoreno@despacho.notariado.org Buenos días Angel, le escribo de la Comisión Tutelar de Adultos de la Junta de Extremadura, debido a que nos ha informado la pareja del fallecido Santiago Caquero, Mª Jesús Jimenez, que mañana se quiere firmar esta herencia. La comisión tutelar de adultos representa a una de las herederas, Maria Antonia Casquero Jaén. A fecha de hoy nadie nos ha enviado documentación, e informado al respecto. Por este motivo le indico que ni la tutelada ni la comisión asistirán mañana a dicha firma, caso que se realice. Ruego que se ponga en contacto con nosotros ya que como sabrá se requiere autorización judicial para la aprobación de dicha herencia, y esta comisión no puede aceptar la misma sin conocer el contenido de la misma *********************************************** Llamo a Maria Jesús Jimenez,638747719 ex pareja del fallecido padre de nuestra tutelada y le explico la situación: desconocemos del todo esta herencia pues nadie nos ha remitido información de la misma','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='CASQUERO'and apellido2='JAEN'),'2023-10-17','miguel, recibo email de la notaria de Navalmoral 927-530853 de la Mata,donde me confirman por teléfono que firmarán hoy...y me enviarán una copia para que la estudiemos y ratifiquemos más adelante. Me indica también que la herencia está en fuera de plazo y por tanto ya tiene recargo y pendiente de liquidarse "Buenos días Don Miguel, soy Ángel Moreno, oficial de la Notaría de Navalmoral de la Mata y el encargado de la herencia de Don Santiago Casquero Barroso. Efectivamente Doña María Jesús Jiménez Jiménez, viuda de dicho causante nos ha manifestado su intención hoy Martes 17 de octubre de iniciar la firma de la herencia de su esposo, junto con el resto de los herederos, Don Francisco, Doña Margarita y Don Ángel María Casquero Jaén y su nieta Doña Tamara Modesta Casquero Cebrian. Ya que según ha manifestado y tras ponerse en contacto varias veces con la Comisión Tutelar de Adultos de la Junta de Extremadura, tanto de forma personal, como a través de una gestoría contratada a tal fin, ha sido imposible dicha comunicación para la firma también de Doña María Antonia Casquero Jaén al encontrarse tutelada por la Junta de Extremadura. Al parecer es bastante difícil que todos los implicados en el día de hoy se pongan de acuerdo para la firma, pero al parecer hoy tienen que acudir todos a un tema en el Juzgado y era un día propicio para esta firma, siempre salvando la posible ratificación posterior de Doña María Antonia Casquero Jaén, así como de la persona que tiene su tutela y por supuesto la posterior aprobación judicial que dicha escritura requiere para su total validez. Todo ello se reseña en la escritura, será explicado por la Notaria en el día de hoy siendo asumido por todos y cada uno de los firmantes. Una vez firmada la escritura con su fecha y protocolo les será remitida una copia autorizada de la misma para su posible ratificación posterior y aprobación judicial".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='CASQUERO'and apellido2='JAEN'),'2023-10-16','miguel, me comunica por tlfno Amalia que la Ex pareja del padre fallecido va a firmar mañana la herencia en la notaria de Navalmoral de la Mata. Localizamos un email de la Gestoría y le envío email Info@tsmasesoria.es: Buenos días, en la mañana de hoy tras conversación de Maria Jimenez Jimenez 638747719, se nos ha informado por parte de la pareja del fallecido y padre de la tutelada Mª Antonia Casquero Jaen que se quiere firmar la adjudicación de herencia del fallecido padre. Hemos intentado contactar sin éxito con esta notaria vía telefónica sin éxito. Desde esta Comisión no se tiene información de dicha herencia por lo que se ruega que urgentemente se pongan en contacto con nosotros y nos remitan borrador de la escritura que mañana se quiere firmar. Esta Comisión no ratificará esta herencia hasta no haberla estudiado previamente. Se les recuerda también que dicha herencia requiere de la aprobación judicial de la misma para su validez. Necesitarán incorporar sentencia de incapacitación, y aceptación del cargo de tutor de la Comisión Tutelar de Adultos por lo que les requerimos para que nos faciliten email y teléfono de la persona de contacto de la notaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2023-10-17','Ana: Envío correo a Paz Boticario, TS Cruz Blanca (trabajosocialcf-caceres@cruzblanca.org): "Aquí tienes los Consentimientos Informados para la administración de las vacunas de la Gripe Estacional y el Recordatorio de Covid, firmadas digitalmente por la Vicepresidenta de la CTAEx"','2');
