insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2023-10-17','Ana: Envío a Esther, Adtvo. de la Residencia Ntra. Sra. de la Luz, de Malpartida de Plasencia (administracion@residencialaluz.com): CI para la administración de las vacunas de la GRIPE + Recordatorio COVID.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2023-10-16','TERESA Hola os adjunto la comunicación vía email a fiscalía de zafra, y paralelamente Inés lo va a comunicar al jzdo nº1 de Zafra por email. La fiscalía me acaba de confirmar por teléfono que lo remitan a la fiscalía de Badajoz para que les indiquen si han de proceder y cómo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2023-10-16','TERESA Pues mira, en un principio muy bien y ella manifestó lo contenta que estaba con el centro. Pero ha tenido momentos de querer irse porque entiende que hay muchos mayores. Se le trató de distraer dando una vuelta con ella y así hemos ido solventando la situación. Por otro lado, no duerme bien y está agitada de noche. Los enfermeros van a tratar de contactar con su psiquiatra para comentar este tema. Ella insiste en hablar con la psiquiatra. En cuanto a los gastos: Tenemos Servicios de Podología, Peluquería y Estética externo. La forma de proceder en el caso de personas válidas, es pagarles ellos directamente. Quizás en este caso, para que ella se sienta más autónoma, debería ser así: no se que opinas. Hablo con la Supervisora y te decimos si precisa algo. En cuanto a su ropa, si así es, su hijo preparó una maleta con alguna ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-10-17','Ana: Envío correo a Raquel Vadillo Martín - Dpto. Administración - Resid. "Catalina Curiel" - Almaraz (rvadillo@residenciacatalinacuriel.es): "Adjunto: - Contrato de Admisión - Autorización de Cinturón protector en caso necesario Relativos a FLORA GUTIÉRREZ GARCÍA, firmados digitalmente por la Vicepresidenta de la CTAEx. Los otros documentos te los harán llegar desde la sección económica." ··········································· *Envío nuevo correo a Raquel Vadillo - Res.: "Os anoto la respuesta de Alberto, Jefe de Secc. Económica, con la propuesta de asignación mensual y extraordinaria, tras haber hecho cálculos, para Flora Gutiérrez García: “PODRÍAMOS DARLE AL CENTRO UN DINERO ANUAL PARA QUE LO GESTIONE DURANTE UN AÑO (O SE LO MANDAMOS MES A MES) Y QUE NO PIDAN NADA----100 €/MES (1.200 €/AÑO): QUE INCLUIRÍA TODO: REINTEGROS + ACOMPAÑAMIENTOS + PELUQUERÍA + ASEO PERSONAL + ROPA/CALZADO + VACACIONES + VIAJES HABRÍA QUE DEJAR ESTO CLARO CON EL CENTRO ---- TEN EN CUENTA QUE DANDO ESE IMPORTE NO AHORRARÍAMOS NADA.” ¿Cómo veis esta posibilidad, de que pueda retirar con vuestro acompañamiento 100€ mensuales y que le ayudéis a administrárselo para todos los gastos que le puedan surgir en el día a día? Como ves, en esa cuantía se incluiría todo. ¿Crees que sería viable así? La otra opción es darle menos mes a mes y retirar un extra anual para que administréis por completo para los gastos del año. Valorarlo y me confirmáis cuando podáis."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-10-17','Ana: Mª Carmen, TS HSPA (mariac.rodriguez@externos.salud-juntaex.es): me envía INFORME DE ALTA del Serv. de Medicina Interna. "RX sin lesiones agudas valorables", Diagnóstico: "Esguince de rodilla LLI", tratamiento: "Calza- férula inguino-maleolar", "puede caminar", "no precisa HBPM" ············· Fue la JEFATURA DE GUARDIA quien indicó: "El paciente debe ingresar en Medicina Interna hasta contactar con Servicios de la Junta responsables".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-10-17','Ana: envío correo a Estrella Durán, TS CSS, con respuesta de Alberto para los gastos de Enrique: "Esto es lo que me dice Alberto, Jefe de Secc. económica tras haber hecho cuentas: “CÁLCULO ASIGNACIÓN: • 50 euros en un cartón de tabaco que le dura 10 días: 36,5 CARTONES TABACO AL AÑO X 50 €/CARTÓN: 1825 €/AÑO • 20 euros a la semana para gastos de bolsillo: 20 € X 52 SEMANAS: 1040 €/AÑO • TOTAL: 1825 + 1040=2865 €/52 SEMANAS==== 56 €/SEMANA (243 €/MES). ANA: ES ESTO A LO QUE SE REFIEREN???...PASAR DE 145 €/SEMANA A 56 €/SEMANA (QUE SE PUEDE REDONDEAR A 60 €) SI ADEMÁS NECESITAN UN DINERO EXTRA PARA ARTÍCULOS DE ASEO Y SIMILRES: TIENEN LA AUTORIZACIÓN GENERAL + LOS 90 € QUE HAY EN ADMISIÓN.” *Por tanto, podéis hacer uso de un máximo de 60€ semana para tabaco y otros gastos de bolsillo. Y para otros artículos necesarios, coherentes, podéis hacer uso de la AUTORIZACIÓN."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-10-17','Ana: Envío a Alberto, Jefe S. Ecca., los presupuestos de Frigoríficos remitidos por Guadalupe Cortés Terradillos, TS SAD - IMAS -CC (guadalupe.cortes@ayto-caceres.es). La Aux. SAD le acompañó. ······································· Envío correo a Guadalupe, TS: "Como puedes ver, Alberto ha dado el OK a la compra del frigorífico. Como no especifica cuál, supongo que Ventura puede elegir el que más le guste de entre los presupuestados. Necesitaríamos que acudiesen de nuevo al establecimiento elegido para que desde el mismo (o a través tuya) nos envíen factura proforma con el número de cuenta bancaria par que mi compañera Estrella, Sección Económica, pueda hacer la transferencia. Una vez abonado, entiendo que le llevarán el frigorífico a casa. Pongo en copia a Estrella"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='CAMARA'and apellido2='MORENO'),'2023-10-17','Ana: Correo de Estrella Guerrero, Aux. Adtvo. CTAEx: "Hola, se ha autorizado el presupuesto de la clínica dental por 427,74 €. Ya lo he comunicado a la clínica y a Cristina Hernández (TS)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-10-17','-Amalia : se registra comunicación de la baja laboral a PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-10-17','Ana: Icíar me reenvía correo de Paqui Berrocal, Ud. Prest. Ecca. Dependencia (francisca.berrocal@salud-juntaex.es): "TENEMOS PARADO EL EXPEDIENTE DE PAGOS INDEBIDOS DE DEPENDENCIA DE ESTE SEÑOR. LA RESOLUCIÓN SE OS NOTIFICÓ EN DICIEMBRE DE 2022 Y NO SABEMOS NADA AL RESPECTO. TENGO EL EXPEDIENTE PARA ENVIARLO A RECAUDACIÓN EJECUTIVA POR VIA DE APREMIO. POR FAVOR, DECIDME ALGO O LO ENVÍO YA. EL IMPORTE ADEUDADO ES DE 2280 €" ··············· Pregunta también por el coste del a plaza (le están cobrando más de lo que dice la resolución). ············ Respondo: "- El coste de la plaza es el que tú indicas. Te adjunto la resolución en que se detalla, para que podáis reclamarlo a la Residencia. *Si necesitas que llame yo, dímelo. - En cuanto al Cobro indebido, copio mis dos anotaciones en la Intranet:" ····· "Juraría que se lo di a Alberto en mano en su día, tal y como anoté que haría. Y también me suena algo de que hayan vuelto a subir algo en la fecha que te han dicho, pero creo que lo cogió directamente Óscar, así que yo ya no anoté nada… Pongo en copia Alberto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='CAMARA'and apellido2='MORENO'),'2023-10-18','Ana: Correo de Estrella, secc. ecco. a Vitaldent, con copia a Cristina, TS CSS-Plas, y a mí: "se adjunta justificante de transferencia realizada a Vitaldent., referente a nuestro tutelado D.Alfonso. por importe de 427,74 €. Les ruego me envíen la factura."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2023-10-09','TERESA como ya sabréis desde el pasado Mares Diego se encuentra en la unidad de psiquiatría de Llerena, al parecer sigue igual , alterado obsesionado y descontrolado . por otro lado nos demandan la dentadura , ya que en esos días de extrema crisis la rompió Ponte en contacto con Raquel para que pueda realizar las gestiones con el dentista de poder repararla ( 654691289), ya que al parecer se ha negado a comer ... Por otro lado también quiero deciros que visto todo lo sucedido el día 4 formalice una queja al servicio de 112 por no haber atendido cuando el lunes lo solicité y no hacerlo hasta que la médica de Diego lo activó , ya que en esa jornada hubo muchos hechos que podrían haberse evitado: rompió la terraza entera de un bar, amenazó con un arma blanca a varios vecinos de la localidad , la vecina de mas de 80 años tuvo que irse de su vivienda por las amenazas que recibió por parte de diego , la vecindad no pudo a penas dormir ante las acciones que realizó durante toda la noche , etc No se cuando le darán el alta , pero viendo la situación y la escalada de posible violencia , obsesiones etc , tendríamos que pensar en ver la idoneidad de que siga en su domicilio o ir preparando su ingreso en un centro residencial donde pueda tener acceso a un control más continuo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2023-10-13','Ángel: En relación con la ratificación de la herencia del padre, hemos solicitado testimonio de la firmeza de la sentencia de nombramiento y aceptación del cargo.','2');
