insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ANGEL'and edp.apellido1='IGLESIAS'and apellido2='RODRIGUEZ'),'2023-10-18','Ana: Mª Victoria, Aux. Adtvo. el EVD-Plas (mv.garcia@salud-juntaex.es) me envía la Aceptación PIA para PVS de Att. Residencial y el Anexo de las PVS. ····· La Técnico PIA, TS, es Sonia Velázquez. ············· Subo ambos documentos al portafirmas digital. ··········· Paso a las Aux. Secc. Ecca. CTAEx. el ALTA DE TERCEROS para que lo lleven al banco cuando puedan. ··················································································· Intercambio de correos con Ana María Alonso, Res. Mayores de Galisteo (tosalana@hotmail.com): le indico que ya me encargo yo de la documentación de Dependencia. ········· Pedro Ángel ha dado Grado III. ········· Se acepta PIA de Prestac. Ecca. Vinculada al Serv. ·················· Al cambiar de grado también le cambiará el precio de la plaza, ascendiendo 1550 €. ·············· En el último correo expresa: "Como ahora tarda unos meses en darle la ayuda nosotros le empezaremos a cobrar los 1550 euros en el mes de Abril que ya para ese mes ya tendrá la ayuda para que lo tengáis en cuenta. ··································································································································· Cuando tengamos la resolución se lo comunicaré a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2023-10-16','TERESA HABLOO CON FELI FONTANERO 629468102 PARA INSTALACION DE CALENTADOR ME MANDRA FACTURA Y NUMERO DE CUENTA PARA ABONAR POR TRANSFERENCIA BARTOLOME 673486021','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-10-18','Ana: Llamada de JM, ha ido al médico. El TAC Craneal le ha dicho que está todo muy bien. ·········· El colesterol le ha bajado. Pero tiene las transaminasas altas y el hígado dañado. ······················ Por otra parte, le felicito, pues es su cumpleaños, pero dice estar disgustado, puesto que desdela secc. ecca. le han denegado la comprar de la TV de 55 pulgadas que pidió. Le han dicho que compre una más pequeñas, de 43, pero se niega. *Plantea renunciar a la ropa de inviernos para comprarse la TV que él quiere.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2023-10-18','-Amalia : Contacta conmigo Ana Mariscal , IMSS Bjoz : 924010019 608817301 Esta Sña. es D. Judicial , tienen la sentencia desde el año pasado como C. Representativa. Vive en Gevora , en la casa familiar . Una sobrina ha ido a vivir con ella . Tiene REGA pero desde que está su sobrina , sale a pedir por las calles. La sobrina es hija de una de las herederas de la casa , su madre ha fallecido. Tiene GI dependencia Tiene SAD Ayto . Tno. compulsivo , retraso mental... Acude al ESM C. Jardín. Han hablado con Mar para que acuda AEMIS . Quedamos pte. a la acepación del cargo .','2');
