insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-10-18','Ana: llamo a Javier (641 08 64 09): le comunico la aprobación del extra y la subida de asignación a partir de noviembre. Le indico que si vuelve a ingresar en el CRR habrá que recalcular la asignación. Lo entiende perfectamente. ········································ Informo por mail también al respecto a Ana Benavente, TS ESM, para su conocimiento. ················ Respuesta de Ana Benavente: "Gracias por la información de Javier. El día 31 me han dicho que hay Comisión de Valoración para acceso a CRR. Ya te iré informando."','2');
