insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2023-10-18','MEDIDAS JUDICIALES DE APOYO Mediante Auto n.º 124/23, de 11 de julio, se dictan medidas judiciales de apoyo. Nos nombran Curador Representativo. Se procede a modificar el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='CRUZ'and apellido2='SANTOS'),'2023-10-18','TERESA TRAS CONVERSACION CON SU HIJO SE AUTORIZA REINTREGO PERMAMENTE DE 30€ MES PARA GASTOS DE BOLSILLO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ASCENSION'and edp.apellido1='PICON'and apellido2='PICON'),'2023-10-18','TERESA RECIBO LLAMADA DEL TRABAJADOR SOCIAL DE FERIA PARA PREGUNTAME SOBRE LA "TUTELA" COMENTA QUE TIENE PROBLEMAS RESPIRATORIOS PERO SE NIEGA A TOMAR LA MEDICACION Y A DEJAR FUMAR LA FAMILIA PLANTEA AL POSIBILIDAD DE INGREASAR EN ALGUN CENTRO, LES COMENTO QUE TIENEN QUE PLANTEARSELO AL PSIQUIATRA TELF FAMILIAR: 610634386','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-10-18','Ana: Envío a Raquel Vadillo Martín - Resid. "Catalina Curiel" correo-respuesta aclarando las dudas planteadas: "- Con respecto a los gastos, eso es, dispondría de 100€/mes (asignación mensual) que le ayudaríais a administrar para el resto de gastos. - Al banco se enviará desde aquí una AUTORIZACIÓN DE RETIRADA DE EFECTIVO PERIÓDICA. Para retirar el dinero en efectivo, sólo tenéis que acompañar a Flora, que deberá llevar y presentar en la oficina su DNI. Eso sí, para que no le den el dinero si no va acompañada, podéis facilitarnos los datos de la/s persona/s que la vayan a acompañar de forma habitual (Nombre, apellidos y DNI) - La autorización bancaria no creo que tarde en enviárosla, pues el Jefe de Sección Económica ya ha dado orden para ello. Supongo que estarán pendiente de la firma de la Vicepresidenta de la CTAEx. - Si a Flora le pasase algo por las tardes, fines de semana o festivos, tendréis que comunicarlo a la direcciones de correo: ctutelar@salud-juntaex.es // ana.matamorosg@salud-juntaex.es - Flora tiene Seguro de Decesos en Santa Lucía. El número que nos consta para los avisos es: 913652424 (quizás vosotras tengáis otros). Creo que el otro día os adjunté la copia de la póliza para que tuvierais en el expediente. En caso de defunción tendréis que llamar al seguro, dar el número de póliza y exponer la situación para que os den instrucciones de tanatorio y demás. Eso sí, podéis preguntar a la propia Flora si desea ser incinerada o enterrada y dónde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-10-18','Ana: Escribo a Marisol Tafur, TS ESM (mariasoledad.tafur@salud-juntaex.es) preguntando por el ingreso de Guadalupe, no he vuelto a saber nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2023-10-18','Ana: Remito a la Res. Padre Damián de Plasenzuela (residenciaplasenzuela21@gmail.com) el Consentimiento Informado para la administración de las Vacunas de la Gripe y la de recuerdo de Covid, firmadas digitalmente por la Vicepresidenta de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2023-10-18','Hola, Según la Nota Simple del Registro de la Propiedad que os envío, el inmueble de Ronda de los Tejares, en el que Mercedes tiene un 50%, correspondiendo el otro 50% a su hermano Bernabé, éste tiene una carga, anotación de embargo ejecutivo, por importe de 57.020,00 euros de principal, más 17.106,00 euros, en concepto de intereses, gastos y costas. Procedimiento ETJ 424/19, seguido en el Juzgado de Primera Instancia nº 4, de Córdoba. He pedido al Juzgado que nos informen. Amalia, podemos averiguar con el SSB de Córdoba si Bernabé vive en ese domicilio? Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-10-18','Miguel escribe a la TS del SSASB de Oliva: Buenas tardes, hasta ayer no han llegado los informes médicos. Estamos preparando la solicitud de internamiento involuntario, pero tardarán en asignarle juzgado y procedimiento porque los juzgados no tramitan estos expedientes con carácter urgente. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-10-18','Amalia : hablo con Pepa esta mañana , ayer le entró agua en casa . La comunidad de vecinos lo ha solucionado. Hay que averiguar si tiene Sg. del hogar y qué cubre , se lo paso a S. eco para que vean en sus cuentas. Le pido Pto. por su gestión al abogado antes de hacerle la autorizacion que pide. Pepa dice que el coche de su marido quedó siniestro tras un accidente que tuvo y se lo llevaron al desgüace. Dar de baja al seguro del coche. Dice que un vecino Fco. Duran Cardenas ,tf 642092612 le robó a su marido . Que está en casa de sus padres en el V. del Jerte. Hablo con el E. Dependencia Zafra , hay que hacer revision PIA para activar el expte. que está inactivo por no aceptación PIA . En Zafra hay SAD desde el Ayto. no habria que buscar empresa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-10-18','Amalia : pongo a portafirma revision PIA para solicitar SAD municipal . Tiene G.I , el PIA está inactivo pq no aceptó la prestación SAD .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-10-19','Ana: Recibimos RESOLUCIÓN del IMAS, DESESTIMANDO el Serv. de Catering por no cumplir los requisitos económicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-10-09','Ana: Desde la Secc. de Acceso a RR. de Salud Mental,copia de informe de alta en Piso Supervisado, Documento de Renuncia de 2016 y correo electronico explicativo, en que indica que Enrique en el piso provocó "situaciones tensas y violentas". En el Informe exponen el RECHAZO de Enrique a "asumir responsabilidades y tareas y su deseo de continuar con su estilo de vida anterior".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2023-10-19','Ana: llamada de Jesús, Res. Virgen de la Piedad de El Torno (927 17 50 94 / jesusi6@hotmail.com): María HA FALLECIDO esta madrugada a las 3:30 h. ········ No había dejado dicho su deseo en caso de fallecimiento (entierro, incineración o localidad). ····· Llamará a las dos sobrinas de las que tenemos el contacto para comunicarlo y preguntar. ··············· Le envío copia de la Póliza de Decesos - OCASO, para facilitar al tanatorio del pueblo. ····························· Correo de Jesús: "HE CONSEGUIDO HABLAR CON LA SOBRINA ISABEL CABALLERO, ME DICE QUE ESTA EN BARCELONA Y QUE HABLARA CON LA FAMILIA PARA SABER QUE HACER Y TAMBIEN ME DICE QUE TIENE UN NICHO EN BADAJOZ. ESTOY A LA ESPERA DE PODER HABLAR CON MAITE QUE ME DICE ISABEL QUE ES TRABAJADORA SOCIAL. LA HE LLAMADO DOS VECES Y NO ME LO COJE."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-10-19','-Pregunto a su padre por su estado en Ctro. penitenciario: Amalia, Albert está muy bien, una paradoja, pero estando donde está, se encuentra animado e ilusionado con sus estudios de geografía y historia. Quizá sea, en éste momento, donde mejor pueda encontrarse, El centro de Mérida es penoso y ahí se está encontrando a personas de nivel intelectual y están congeniando muy bien. Gracias por tu interés por su estado. Saludos cordiales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-10-19','Ana: Correo-respuesta de Marisol Tafur, TS ESM (mariasoledad.tafur@salud-juntaex.es): "En principio estaba programado para el martes pasado, pero no pudo ser. Lo hacen hoy, pero no te lo he comentado antes por si acaso hoy pasara algo por lo que tampoco ingresara. Pero si todo va bien, se activa el protocolo hoy para el ingreso en la UHB. Cuando esté ingresada te lo confirmo." ······································ Mi respuesta: "Gracias por informar. Espero que pueda ser hoy, pues con este temporal el riesgo de derrumbe es mayor."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2023-10-18','Ana: Correo de Ana Benavente, TS ESM (anamaria.benavente@salud-juntaex.es): "el Dr. Mora me ha dicho que os haga saber que de María Antonia Bernardo Piris le falta información, en el sentido de que no sabemos si toma bien el tratamiento, si está bien en el piso, etc. Si te parece hablamos de esto más detenidamente por teléfono, puesto que es una paciente compleja."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2023-10-19','Ana: Llamo a Ana Benavente, TS ESM-Plas. (74955 / 74924 - viernes): ha vuelto a tener cita con el Dr. Mora el día 17/10. Según nota de evolución de la misma: Estuvo "hosca al trato, nada colaboradora, respondiendo prácticamente con monosílabos", "Conocemos por otras fuentes que está intentando litigar contra la institución sanitaria y judicial". "Refiere tomar la medicación tal y como se le tiene prescrita". "Compruebo que ha sacado la medicación el día que le correspondía.", "si aumentan síntomas, se indicará ingreso" ····················· Pido que me envíen la nota de la consulta. ····· Lo consultará al Dr. Mora. ··············· Desde que le dieron el Alta Terapéutica en el Piso Supervisado y se fue a vivir a piso compartido desde la CTAEx no se puede garantizar la toma adecuada de medicación. Los seguimientos del Progr. de Apoyo Comunitarios sólo podían ser puntuales y actualmente al no renovarse el convenio, desde 31 de agosto no contamos con el apoyo de las educadoras del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='CAPILLA'and apellido2='CAPITA'),'2023-10-19','EXITUS Llega la noticia de su fallecimiento, de manera indirecta, a través del Área Económica. Tras hacer, Teresa (3), las averiguaciones pertinentes, se confirma el óbito. Tuvo lugar, según el centro, el 12/09/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2023-10-19','EXITUS El centro informa de su fallecimiento. El óbito tuvo lugar el 19/10/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='VELASCO'and apellido2='CAPERUZA'),'2023-10-19','Buenos dias Teresa, soy Yolanda Bardera, compñera de los servicios sociales de Monesterio, te escribo en relación al expediente de Fernando Velasco Caperuza, ha vuelto a agradir a un nuevo compañero en la residencia y esto hay que ponerle alguna solución y/o alternativa más acertada para Fernando y para el resto. Te he llamado pero me ha resultado imposible. Si puedes llamame tu. Gracias P.D. Te mando una de las denuncias, la otra que es de hace un rato no me ha llegado aún.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2023-10-19','-Amalia : información obtenida del hno. de Mercedes por el tema de la vivieda en común en Cordoba. Bernabé Perez Pinna , no tiene abierto expediente en Servicios Sociales ni en dependencia. Percibe Prestación por Incapacidad Pte. como os comenté por información del INSS. En Junta de Andalucía me confirman que está empadronado actualmente en la vivienda sito en Ronda de los Tejares , la dirección que aparece en el documento de Hacienda que os he pasado .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2023-10-19','Ana: Raquel Árias, Psicóloga Casa Familiar Virgen de la Montaña (psicologiacf-caceres@cruzblanca.org): Nos remite el PAI y pide se lo devolvamos firmado. ··········· *Subo al portafirmas digital. ················ Valoración del Fisioterapeuta: "Tiene muchos problemas de atención y muchísima pereza para trabajar. Está más torpe y lento, menos participativo, muy distraído y desganado. Está cada vez más vago, le cuesta mucho hacer cualquier ejercicio, asistir a la terapias, levantarse del sillón, etc.". Enfermería: "Se encuentra en seguimiento por: - El programa PADDI (Programa de atención dental a discapacitados intelectuales.) - MAP: Luis Méndez Gallego.", "permanece estable", "no ha precisado de atención sanitaria programada" "No ha necesitado actuación de emergencias ni acudir al servicio de urgencias". ··········· Auxiliar: "Aunque se le supervisa el residente es autónomo para la ducha, el afeitado, el lavado de dientes y la hidratación cutánea.", "Tiene autonomía para vestirse y desvestirse", "Es autónomo en la alimentación", "No precisa de ayudas técnicas en la deambulación. Camina con normalidad y no suele oponerse en la movilidad de actividades.", "Es participativo en las actividades que se desarrollan en cualquier ámbito." ······· Psiólogo: "En la esfera afectiva refiere eutimia, aunque aparecen episodios de llanto puntuales (malestar emocional) relacionados con el grupo primario (Familiares), ya que no pueden cubrir las demandas de Antonio. A lo largo de este año han aparecido varios episodios de llanto en los que verbaliza echar de menos a su familia.", "Deterioro cognitivo moderado", "Presenta graves problemas significativos de atención y concentración. Muestra interés por la realización de tareas que se le encomiendan pero tiene graves dificultades de concentración para mantener la atención en estas, siendo necesaria una constante orientación", "Permanece desorientado temporalmente. No conoce día, mes y año en el que vive. -Orientación espacial: Conoce perfectamente donde se encuentra. Dentro de la casa se orienta correctamente aunque fuera sale siempre acompañado.", "Permanece bien adaptado y con buen ajuste psicosocial. Se adapta correctamente a horarios y normas, además de responder de forma adecuada a la supervisión. Por las mañanas el residente se demora en exceso durante la realización de ABDV, siendo necesaria una continua estimulación para que este baje a desayunar a la hora estipulada" ········· T.O.: "No se observan cambios significativos en este residente. Antonio es independiente en las actividades básicas de la vida diaria y continúa realizando las mismas actividades instrumentales." ········· TS: "Es un residente con pocos cambios, su relación con el resto de compañeros y con los trabajadores es buena y estable. Determinados días se muestra más sensible, con pensamiento de su familia o por influencia e algún otro residente. Suele ser fácil de herir en sus sentimientos o con falta de madured a la hora de críticas o manipulaciones. No existe una relación familiar para poder crear objetivos de comunicación con la misma. De hecho las llamadas suelen ser del residente a sus primas y poco frecuentes, debido a la falta dedisponibilidad de las mismas. Este año como dato positivo, ha recibido visitas de ambas primas, y llamadas.", "Está muy entretenido con su nuevo móvil, que sorprendentemente maneja muy bien. Su conexión con la realidad es un poco infantil, idealizando un futuro con una residente de otro centro a quien apenas conoce y no parece corresponderle, e irse a vivir a su pueblo donde ya no tiene casa ni vive ningún familiar"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2023-10-19','Ana: Raquel Árias, Psicóloga Casa Familiar Virgen de la Montaña (psicologiacf-caceres@cruzblanca.org): Nos remite el Informe del PAI y pide se lo devolvamos firmado. ··········· *Subo al portafirmas digital. ················ Valoraciones: AUXILIAR: "Es dependiente en la ducha, se seca el solo pero hay que ayudarlo. Se le afeita y se le da la crema en la cara. El cepillado de dientes lo realiza el solo con supervisión.", "Deambula solo por la casa sin supervisión, sin embargo cuando salimos de paseo necesita ir de la mano, se le dice que vaya solo pero cuando pasa un momento se agarra a la mano del cuidador u otro residente por miedo a caerse.", "Le gusta mucho participar tanto de las fiestas que se hacen en el centro cantando y bailando como en las actividades que se realizan fuera del centro." ···· Enfermería: "Ha tenido consulta telefónica con su MAP para valoración de higado graso y anemia.Y consulta telefónica con la psiquiatra, Dra. Gómez del Castillo.", "No ha precisado atención de urgencias.", "Alejandro se mantiene estable a nivel sanitario" ····· Fisioterapeuta: "Su valoración sigue siendo la misma", "En general tiene buena movilidad y amplitud de movimiento. Se siguen observando estereotipias en miembros superiores y tartamudeo cuando se pone nervioso o está ansioso.", "Hay cierta pérdida de su capacidad física y funcional. La movilidad es lenta, torpe y muy descoordinada, con continuas pérdidas equilibrio. En ciertos ejercicios observamos falta de destreza motora, falta de control motor.", "En la esfera afectiva manifiesta eutimia, aunque aparecen episodios de labilidad emocional e irascibilidad. Esto episodios se han mantenido estables a lo largo de últimos años. Reconocimiento adecuado de emociones tanto en sí mismo como en los demás. No gestión adecuada de emociones. Baja tolerancia a la frustración.", "Se adapta correctamente a horarios pero no responde de forma adecuada a la supervisión y a normas. En ocasiones muestra una conducta desafiante ante los trabajadores. No realiza las actividades que se le requieren dentro del centro, refiere que no son de su agrado" ······ TO: "No se producen cambios significativos en el área de terapia ocupacional desde la última valoración. Continúa siendo independiente en las AVDB. No existen cambios en cuanto a la participación en actividades." ········ TS: "Alejandro mantiene contacto con sus hermanos, a través de llamadas los lunes y otras llamadas que realiza como premio en el programa de apoyo conductual. Generalmente elige a su hermano/a, y puntualmente pide hablar con sus tías, sobre todo con Belén. Cristo vino recientemente a visitarle, con personal del centro donde reside.", "Alejandro apenas posee habilidades sociales, no respeta el espacio interpersonal, los turnos, la privacidad, etc. y suele mostrarse cariñoso, sobre todo con los trabajadores, pero su comportamiento en estos últimos meses, ha incrementado el número de incidencias" "Los incidentes con otros compañeros no han cedido con respecto al semestre anterior, incluso puede aparentar agresividad con los trabajadores en momentos puntuales, por lo general es participativo y cariñoso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-10-19','Ana: Lourdes, Secc. Ecca., remite a la Residencia la autorización bancaria ya firmada y tramitada por el banco, para que le carguen en cuenta el cobro de la plaza, la fianza asociada al ingreso (300€) y los gastos que vaya generando (peluquería, podología, farmacia...)','2');
