insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-10-19','Ana: Llamada de Cristina Donoso, Psiquiatra ESM-CC (54605): Ha llamado al padre de Carlos y éste le ha dicho que él ya no es el tutor, por eso me llama. Explica que Carlos es paciente de Salud mental, las últimas citas a las que asistió fueron en Junio y Octubre de 2022. Pero a las sucesivas citas programadas este 2023 (marzo, mayo y agosto) no se ha presentado. La medicación dejó de tomarla de forma voluntaria, a pesar de que le dijeron que debía seguir tomándola. ······ *Me enviará Informe de Seguimiento y programarán nueva cita para Diciembre. *Si el Convenio con Futuex volviera a estar en vigor iría acompañado de la Educacora correspondiente. ···························································· Le envío correo a Cristina Donos (cristina.donoso@salud-juntaex.es): "En relación con la conversación mantenida hace unos minutos, acabo de releer, esta vez entero, el TESTIMONIO DE AUTO DE NOMBRAMIENTO de Curador relativo a CARLOS GONZÁLEZ LEO. Y aunque en el fallo no especifica nada más que lo que hemos hablado por teléfono, en la página 5, a mitad de la página, dice literalmente: “Dicha curatela será de naturaleza representativa en el ámbito patrimonial y para las decisiones médicas de trascendencia en el ámbito personal”. Yo entiendo que es de transcendencia para su bienestar, la necesidad que indicas de que retome el seguimiento en el Servicio de Psiquiatría y el tratamiento de mantenimiento. Adjunto el Testimonio del Auto para que podáis unirlo al Expediente y tener en cuenta este punto a la hora de intervenir con él. Cuando hable con él también utilizaré este argumento, además del principal de que queremos que esté bien y que para ello también se le ha nombrado Curador."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-10-19','Ana: Nos envían desde la residencia (a.corral@grupociudadjardin.com): "solo para comunicarte que la Sñra. Joaquina Mayoral tiene mañana consulta en Cáceres, le acompañara la chica que conocemos de otras ocasiones y no tiene problema en esperar cuando se le pueda abonar el acompañamiento." La cita en Psiquiatría - ESM a las 10:50 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-10-19','Ana: Llamo a Ventura (682 483 126): El día 1 - 8 de noviembre se va con la ONCE a Málaga. ········· La Directora General de las ONCE le ha dicho que puede ir a todos los viajes que se organicen desde de la ONCE. ········ En cuanto al frigorífico se lo va a pensar y mañana me dirá cuál prefiere. ··························· Ha firmado él los CI para las Vacunas de la Gripe y del COVID.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-16','miguel,desde la interposición de la 2º demanda de ejecución del laudo y para lo que nos pididóle nombraramos como abogado por el turno de oficio, y así lo hicimos, pues era una estrategia de él para intentar la deuda reconocida a la tutelada por el laudo y la perdida de la 1º ejecución. Nos pidió y así le remiti en septiembre poder apud acta el 14-9-23 a su procuradora. Por tanto desde finales de julio no había vuelto a saber nada de él. Hasta que la semana pasada Mª Granada(abogada de la contraparte) se puso en contacto con nosotros y nos remitió las resoluciones del juzgado y por 2º vez instaban a la Ctaex a pagar las costas del procedimiento de 1º intento de ejecución del Laudo (nuestro abogado no nos lo ha comunicado).. Mantengo un contacto continuo vía email y telefónico con la abogada de la contraparte Maria Granada analizando el modus operandi de nuestro abogado, jugando con los tiempos, no notificandonos en tiempo y forma, asesorandonos mal para seguir recurriendo cuando desde la interposicisión de la demanda estaba mal planteado el asunto, etc --------------------------------------------- Dos email de Jorge (abogado) tras casi 3 meses sin dar señales: Buenas tardes Miguel, Dado que la comunicación la vengo teniendo contigo, te adjunto para el expediente y para aprobar el gasto del asunto de CARMEN LEAL. Adjunto para ello dos facturas PROFORMA, una de abogado (la mía) y otra de procuradora. Podrás comprobar que la procuradora se ajusta a aranceles, marcado por ley., Por mi parte me ajusto a lo presupuestado, a lo que simplemente se le ha añadido el asunto que se ha tenido que sumar por el arbitraje. En este caso te recuerdo que los asuntos que se han llevado y que se manda en proforma son: 1. - Extrajudiciales de Carmen leal 2. - Nombramiento ante el TSJ de árbitro según contrato. 3. - Proceso de Arbitraje. 4. - Apertura de proceso de ejecución de laudo que ha acabado en archivo. En donde se incluye todo el proceso que HASTA LA FECHA hay en dicho proceso. Y digo esto porque estamos expectante en la ejecución de las costas como ya te había comentado. A todo esto, se le sumará el asunto de que hemos tenido que iniciar nuevo proceso judicial para la ejecución, proceso que ya ha sido admitido a trámite y te adjunto DECRETO de ello o los trabajos que haya que realizar desde la fecha de hoy. como sabes, la intención de cubrir lo devengado hasta el momento, es también defender posiciones ante un posible embargo, Con todo ello, adjunto: -proformas: 1.180.42 euros procuradora; 2.420,00 euros abogado. (seuo) *destacar en precio que mucho inferior a las costas judiciales pedidas de contrario, dado que el precio que se ha puesto a Carmen es ventajoso con respecto a los costes de tasación. Si bien los criterios orientadores no son tarifas de mercado, sí que son tarifa media de este despacho, pero el precio final dado a la tutelada es con "descuento". - Decreto admisión de nuevo proceso de ejecución. Se puede comprobar cómo en este proceso no han puesto duda en la admisión a trámite y siquiera nos han requerido subsanación de poder (cada Juzgado va como quiere). Quedo a tu disposición para cualquier duda, aclaración o sugerencia y a la espera de que me digas sobre forma de pago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-18','miguel, en relación a la interposición del 2º intento de ejecución en el juzgado, donde nuestro abogado Jorge en julio interpuso la demanda (antes de resolverse la 1º ejecución para intentar, según dijo, compensar la deuda de perder el juicio con lo que se le debía a la tutelada) Voy presencial al colegio de abogadso tras intento infructuoso por email y telefónico y me confirman que van a resolver que la tutelada no tiene derecho a la asistencia gratuita. Tendré que desistir del procedimiento ante lo costoso que fue el primero, unido a la falta de información de nuestro abogado (no nos remitió hoja de encargo del laudo y 1º ejecución y tampoco de éste, pese a las reiteradas peticiones) Tras consultar con la abogada de la contra parte Maria Granada, constatamos que nuestro abogado Jorge, no nos ha informado en tiempo y forma (no mandaba la documentación completa, ej: demanda y documentos que la acompañaban, o mandaba tarde la información) Mª Granada me aconseja que le reclamemos por mala praxis.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-18','miguel, mi contestación al abogado a su email con la minuta que nos pasa: Buenas tardes Jorge, no hagas por ahora ninguna gestión ya que estamos estudiando la situación de la tutelada, lo cual incluye su situación económica. No hagas alegaciones. En cuanto a la proforma tuya y de la Cristina la procuradora la vemos incorrecta, pues en tu caso no incluye todos los trámites hasta la finalización de la ejecución. Y en el caso de Cristina vemos 60€ en copias no justificadas. Por otro lado nos parecen excesivas en comparación con las hojas de encargos que nos remitisteis en 2021. Aprovecho para pediros la factura del arbitro del anterior procedimiento, la cual envió la proforma pero no nunca llegó la factura. Necesito que hoy mismo a ser posible a parte de modificar los documentos que os indico, me remitáis la hoja de encargo por el procedimiento de 2º intento de ejecución del laudo. Sé que os acogisteis al artículo 28 de la ley de asistencia gratuita pero necesitamos saber cuánto sería el importe de vuestros honorarios casos de que no aceptasen la misma. Mandádmela si es posible entre esta tarde y mañana temprano porque tenemos reunión en la Comisión sobre este asunto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-18','miguel, nueva contestación del abogado Jorge: Buenas tardes Miguel, En referencia a mi proforma. Adjunto proforma en donde pongo detalle que me pides. En referencia a los importes, procedo a explicar el asunto: En Hoja de Encargo, para iniciar y como sabes, se ha realizado inicialmente en un proceso de desahucio. Lamentablemente, tras analizar el asunto y trasladar las recomendaciones oportunas, se decidió que dicho proceso presupuestado no era posible en la forma procesal indicada. Así, en vez de iniciar un proceso de desahucio inicial, se ha tenido que iniciar otro proceso. Por ello, y por la buena fe y transparencia que en todo momento he mostrado, lo que hago es una analogía del proceso que se había presupuestado sobre el proceso que se ha tenido que realizar. Me explico: La extrajudicial se vino a realizar y es un coste asumido, que se absorbe en el proceso de desahucio. El proceso de desahucio no ha sido posible iniciarlo tal y como se había indicado. Como sabes, el proceso de desahucio es una demanda en proceso sumario, casi como una ejecución, para interesar el desahucio. Sin embargo, en el presente proceso, para tener dicho título, he tenido que realizar un proceso entero de arbitraje y, posteriormente iniciar la demanda ejecutiva. Por consideración, todos los trámites procesales, sobrevenidos en la causa, y que no son propios del proceso, no los presupuestos aparte. Así, el proceso de desahucio en su ejecución se ha realizado completo. Toda vez que se ha iniciado en demanda de laudo, hemos impugnado oposición e incluso se han realizado los escritos de recursos y nulidades por medio de la causa que conoces. Por ello, el presupuesto es de 1200 euros más iva = 1452 euros. A este proceso de desahucio, se le suma que se ha iniciado la reclamación económica de las rentas. Es una acción independiente pero que se acumula en el proceso, aunque no deja de tener "preocupaciones/trámites" propios. Esto se había presupuestado en 200 euros más iva, y si se recuperaba cantidad, pongamos que se cobran 20.000 euros, mi derecho de cobro sería el 10% de 20.000 recuperado más iva. Dado que se han realizado todos los trámites, pero no se ha podido reclamar cantidad por haberse impedido en la resolución judicial, solo se cobra el trámite presupuestado. Dejando lo otro pendiente. Esto te lo pongo en la proforma, según presupuesto firmado IMPORTES QUE HAY SU SUMAR IVA = 1694 euros presupuestados, aceptados y devengados. Ahora bien, hay que comprender que lo presupuestado era el trámite de desahucio, pero es que en la presente causa además se ha tenido que hacer un trámite de nombramiento de árbitro, sin el cual, no se podría iniciar el arbitraje Todo conforme dice el contrato de manera desafortunada. Este trámite es un proceso verbal, sin cuantía determinada y que podría tener un presupuesto mayor, no obstante lo presupuesto como una jurisdicción voluntaria por haber tenido que celebrar vistilla y juicio en el TSJ de Extremadura para que se nombre el árbitro. El asunto es sobrevenido toda vez que el contrato impide saber la junta arbitral a la que se acoge. Y no había sido objeto de presupuesto detallado por motivo de que se había presupuestado un desahucio "ordinario". Por ello se ha pedido 600 euros más iva (lo que es una jurisdicción voluntaria). total iva inc. 726 euros (seuo) En cualquier razón, espero que puedas entender que en todo momento se ha estado explicado el proceso que se debe seguir y los giros de decisiones que se han tenido que tomar para adaptarnos al caso. Además, como te había indicado, El presupuesto y la proforma es muy inferior a lo que estaría estandarizado en mercado por este trabajo. Pero por orgullo profesional mantengo lo que se había pactado a sabiendas de la particularidad del caso y de los constantes giros que se han tenido que hacer en el proceso. Con ello, entiendo que no hay nada sorpresivo en la proforma, que se viene a cobrar el proceso que se había presupuestado de la manera en la que se había aceptado, incluso haciendo otro más largo y laborioso. Únicamente, se le ha aumentado la necesidad de incluir OTRO PROCESO que se tuvo que emprender de inicio. Finalmente, te aseguro y sabes que este asunto me ha roto en horas más de lo que he pasado en proforma. Aunque comprendo que me pidáis explicación si hay personal que no comprende el trabajo que hay detrás de un proceso como el que se ha llevado, aunque como se dice en la hoja de encargo, se contrata un servicio no el resultado que, pese a todo el esfuerzo y entendiendo que el derecho nos ampara, no ha salido como queríamos. Eso sí,procedo a detallar en la proforma los datos que se me han pedido y que, para quedar claro y vuestra tranquilidad, es el trabajo realizado hasta el momento en los procesos indicados en proforma. Aclarado el asunto de las alegaciones, quedo pendiente de que se me indique cómo proceder en el asunto. En todo caso, mañana hablamos al teléfono para poder aclarar una serie de conceptos necesarios que percibo puede no haber quedado claro. Ahora bien, sin perjuicio de que se me indique alguna forma de pago necesaria, vuelvo a recordar que lanzar ahora la proforma era una defensa de asegurar el cobro del servicio prestado y devengado, ante el riesgo de que pudiéramos sufrir un embargo. En todo caso, espero haber aclarado los conceptos y los importes. En nada se han alejado de lo presupuestado y aceptado (debiendo ver claro que los importes no incluían el iva) y que se ha encargado la necesidad de un proceso que no había sido contemplado (por analogía) en el presupuesto inicial. Por lo que entiendo que procede aceptar y asumir el abono de la proforma de la manera que se me indique, y, a la vista de la situación, asegurarme el posible abono del dinero. Finalmente decir, que desde el 2021, con tan buena fe se ha procedido, que en ningún momento se ha reclamado el dinero inicial que se debería haber abonado a la firma de hoja de encargo. Para cualquier otra aclaración quedo a tu disposición,adjunto proforma igual pero con detalle solicitado en cuerpo del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-19','miguel, envío email a la procuradora del procedimiento 2º intento de ejecución del laudo para que en el día de hoy desista del procedimiento y me remita justificante lexnet. Los motivos que tenemos en la Ctaex: -De este 2º proced ejecucion: no tiene derecho al turno de oficio con el nuevo coste que representa, ya que el primero que perdimos se irá a cerca de 10.000€, y no logramos echar a la inquilina ni que le pagara. Es un procedimiento que perderemos pues de nuevo ha planteado mal la demanda pues el demandante no es Carmen Leal sino la Ctaex en nombre de Carmen Leal. Como no tengo intención de hablar con este abogado, analizando su modo operandi y a mi entender su mala praxis, y ante mis falta de contestación, recibo nuevo email del abogado Jorge Calvo: Buenas tardes Miguel, Me da la sensación de que hay cosas que no se me están diciendo y que, donde nunca ha habido ni hay sitio para ello, hay desconfianza en el trato que siempre hemos tenido. Pero lo que no es de recibo ni se puede permitir, es el hecho de que se envíen escritos a la Procuradora para su presentación en el Juzgado, sin que se me informe. Siendo el director técnico del asunto, la procuradora no puede presentar escritos sin mi autorización y conocimiento. Mucho menos presentar un escrito que no va firmado por letrado, cuando la firma es obligada en dicho escrito. Respeto cualquier decisión que se tome, pero desde luego espero que las formas sean las correctas en todo momento. Te he llamado en varias ocasiones (ayer al término de la mañana y esta mañana) y estoy a la espera de que me contestes o se me indique, espero que el respeto entre profesionales, como algo mínimo, se mantenga. ------------------------------------------------------ miguel, mi contestación: Buenas tardes, en el escrito no se menciona la dirección letrada. El cliente tiene derecho a desistir de un procedimiento sin tener que dar explicaciones, pues es un derecho. Aprovechamos para requerir des parte al seguro de responsabilidad civil en relación a la ejecución del laudo 333/22 del juzgado de 1º instancia nº5, respecto a los fallos cometidos en el mismo, y nos remitas justificante de apertura de incidencia. En cuanto al procedimiento ETJ Ejecución de títulos judiciales 176/23 del Juzgado de 1º instancia nº7 de Badajoz, al no existir presupuesto previo al mismo, necesitamos nos remitáis y justifiquéis qué honorarios estimáis? Necesitamos nos remitáis todo lo actuado en este último procedimiento. ----------------------------------------------------------- Y otro email que manda el abogado Jorge (el abogado) por la tarde: Por partes Miguel, El hecho de que quieras quedar constancia escrita, lo respeto, pero tras dos años trabajando juntos, agradecería poder recibir tus palabras al teléfono. En todo caso, mañana me pasaré en persona por las oficinas de Mérida. El siniestro ya está dado, aunque no asumo, como indicas, el fallo en el proceso. De hecho, hemos hablado largo y detenidamente sobre lo que ha ocurrido en el proceso, incluso he mandado escritos al respecto para que se pueda hacer el mejor seguimiento por la comisión. Lamento que no haya salido como queríamos el proceso. Esto no es una cuestión personal, es profesional, y entiendo las posturas que deban tomarse. Lo que me desconcierta es que no me estás dando instrucciones de nada y se me trata como el enemigo, cuando, hasta que me digas lo contrario, sigo siendo el abogado de Carmen Leal. En referencia al escrito que has mandado a la procuradora: Nadie niega el derecho a rogar el desistimiento. Pero la postulación en el proceso requiere de firma de letrado. No se ha negado que se haga lo que el cliente quiere, lo que estoy indicando es que no entiendo el motivo por el que no se me ha indicado cómo proceder. Si quieres que lo presentemos, únicamente me tienes que dar la orden expresa de ello y se queda presentado; como hasta el momento se ha hecho. Ante todo he demostrado profesionalidad y continuaré haciéndolo. Y lo que he pedido en mi anterior email, es recibir lo mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2023-10-20','Ana: Correo de Esther Díaz, Adtvo. de la Residencia Ntra. Sra. de la Luz, de Malpartida de Plasencia (administracion@residencialaluz.com) al ctutelar@: "Buenos días, me comenta la directora que Doña Guadalupe Barragán precisa visitar al dentista para que la extraiga algunas piezas. Necesitamos su autorización y que nos indiquen la forma de proceder ante esta situación." ···················································· Respuesta desde mi correo: "Si es un tratamiento bucodental que cubre la seguridad social (sólo extracción de piezas) pueden pedir cita al médico de atención primaria y que éste le derive al especialista, de forma preferente si es necesario. Si necesita otros tratamientos, deben enviarnos presupuesto al ctutelar@salud-juntaex.es de la clínica dental elegida a tal fin. El acompañamiento se realizará de la forma habitual que vienen haciendo para otras consultas médicas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-20','miguel, los modelos de desistimiento de este último procedimiento (que me remitió la abogada Mª Granada 667876533, quién me está ayudando y aconsejando)uno era para lo presentara la procuradora y que al no haberlo presentado, le remito el otro donde la Ctaex (firmado por la Gerente), donde la Ctaex insta al juzgado para que desista del procedimiento. El motivo de las prisas es porque van a notificar la demanda a la otra parte quién aunque desistamos puede oponerse o pedir las costas procesales del procedimiento... Teniendo en cuenta que hasta este lunes Jorge (abogado) no nos ha notificado el decreto de aceptación de demanda y orden de traslado a la otra parte para su contestación, y que el miercoles me confirman el colegio de abogados que no tiene derecho al turno de oficio... ----------------------------------------------------------- miguel, contesto al email de ayer del abogado, indicandole nuestros motivos para desistir y renunciar a que siga representandonos(no le incluyo que ya hemos pagado las costas procesales a la otra parte la semana pasada, pese que él no nos había notificado nada, y tampoco sobre su mala praxis alargando plazos, no dando toda la información, animandonos para alegar y recurrir a sabiendas de que estaba perdido el 1º procedimiento...): Buenos días Jorge, desde la Comisión Tutelar de Adultos necesitamos nos indiques referencia de la incidencia a tu seguro de responsabilidad y/o justificante del mismo, basado en los fallos importantes que hemos detectado en el mismo pues a la demanda de ejecución no se acompañó justificante de comunicación del laudo y como ya indicó el juzgado suponía desestimar la pretensión de esta parte. El resto de trámites que ahora se pretenden cobrar y cuya hoja de encargo nunca se remitió los entendemos innecesarios. En cuanto al 2º procedimiento Cristina, la procuradora no nos remitió ayer el requerimiento de petición de desistimiento al juzgado, que tal como ya hablamos la tutelada no puede asumir el coste de un nuevo procedimiento. No va a ser concedido la justicia gratuita a la misma, con el perjuicio, incluido posibles costas que dicho procedimiento puede suponer ya que la demanda está mal planteada de nuevo. Os requerimos de nuevo para que Cristina nos remita esta mañana justificante Lexnet de petición al juzgado de dicho desistimiento. Por otra parte a parte del justificante de desestimiento del procedimiento falta nos remitais: 1.-Factura del arbitro del primer procedimiento. 2.-Proforma modificada de la procuradora del primer procedimiento. 3.-Proforma de abogado y procuradora de los segunda ejecución. Aprovecho para indicarte que no podeis utilizar analogías en la primera y única hoja de encargo porque fue un procedimiento no tramitado en su totalidad y distinto del segundo, por lo que os requerimos identificación de procedimiento, trámites realizados y justificados y honorarios que correspondan. Queremos y os requerimos de nuevo para agilizar todo lo solicitado. No estaré hoy en la oficina y entiendo no es necesario reunión al respecto pues nuestra queja se basa en que si estaba mal planteada la demanda, no era necesario trámites como alegaciones y recursos planteados que suponen un coste innecesario a sabiendas que el fallo inicial de planteamiento de la demanda era nulo de pleno derecho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ANGEL'and edp.apellido1='IGLESIAS'and apellido2='RODRIGUEZ'),'2023-10-20','Ana: Guardo en el expte. digital la ACEPTACIÓN PIA y el ANEXO de Prestación Ecca. Vinculada a SAR, firmados digitalmente por la Representante Legal. ***** Pendiente de que desde la Secc. Ecca. me traigan el ALTA DE TERCEROS para registrar todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2023-10-20','Ana: Correo de Sonia Leo, Directora Res. Virgen de la Montaña (virgendelamontana@grupociudadjardin.com) de ayer por la tarde: "Le comunico la baja por fallecimiento de la tutelada Dña. Isidora Leal Román." ·············· Respondo poniendo en copia a María, Aux. Secc. Ecca., y Julio, Aux. Secc. Soc. ································································································································································································ Escribo a Pilar Cerrillo, TS Centros Mayores Ciudad Jardín (calidad@grupociudadjardin.com): "En relación al fallecimiento de ISIDORA LEAL ROMAN, ¿comunicas tú el fallecimiento al Departamento de Pensiones de Suiza? Si no, para apuntármelo yo y cuando tenga al menso el certificado médico de defunción comunicarlo. Ya me dices." ··················· Pilar responde que ellas se encargan de comunicarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2023-10-20','Ana: Correo de Ana Benavente, TS ESM (anamaria.benavente@salud-juntaex.es): Envía nota de evolución de la última consulta de Mª Antonia con el Dr. Mora. Guardo en expediente digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-10-20','Ana: Tras recibir el CERTIFICADO DE INGRESO en CENTRO, envío correo a los A. Jurídicos: "Os reenvío CERTFICADO DE INGRESO en centro y Contrato Residencial para que comuniquéis el ingreso de Mª PILAR DÍEZ SANTIAGO en residencia de la Localidad de Hernán Pérez. Además de por su cambio de domicilio, porque en su sentencia autorizaba el internamiento si fuera necesario. Dice textualmente: “…así como los necesarios para proceder al ingreso hospitalario o internamiento en centro adecuado a sus circunstancias si fuera oportuno, cuando su estado o su salud así lo requieran” "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2023-10-20','Ana: Envío correo a Jesús, Res. El Torno (jesusi6@hotmail.com): "He intentado contactar contigo (927 17 50 94) y con Mayte Mellado (670 634 081), sobrina lejana del marido de María, sin éxito. Supongo que a María será enterrada en su nicho en propiedad de Badajoz. Ya me dices cuando puedas." ························································ Correo-respuesta de Jesús - Res.: "TODO SOLUCIONADO SE ACABA DE ENTERRAR EN BADAJOZ . HA SIDO UN POCO CAOS. PERO ACABO DE HABLAR CON LA FUNERARIA Y HAN TERMINADO A LAS 11. Y POR CIERTO NO SE HA PRESENTADO NADIE DE LOS FAMILIARES."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-10-20','Ana: Reenvío a Alberto, Jefe S. Ecca. y a los A. Jurídicos: el correo de Laura, TS - IMAS (laura.dominguez@ayto-caceres.es): "Buenos días Ana! Viene Montaña y me dice que tiene una deuda pendiente con el banco, que si por favor te lo puedo hacer llegar. Asi que aqui te adjunto los documentos que ella me trae. También me dice que le siguen embargando de la pensión 100€ del juzgado por el tema de la pensión, pero dice que ya esa deuda ya la tendría finalizada, ya que eran 1900€. Te adjunto la carta que le enviaron del juzgado a ver si se lo podeis mirar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-10-20','Ana: Llamada de Pilar Martín, en relación a la solicitud de ingreso den CRR de Sergio Solanilla Luján, puesto que no se trata de una emergencia social, hay que solicitarlo a través de dependencia y no está valorado. *Me enviará la solicitud para que la pongamos a la firma. ················· Aprovecho para recordarle los incidentes que protagonizó en la Casa de la Misericordia (indico que lea el documento enviado) y que lo hable con el Psiquiatra para que lo tenga en cuenta en la próximas consultas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2023-10-06','Ana: llamada de Estrella, TS UME-CSS. han hablado con la madre de Alfonso desde el Equipo Tto. Asertivo Comunitario (ETAC): A parte de mantener el mismo estilo de vida nada saludable, les informa que está delirando. *Reconoce que ella le proporciona los porros, porque si no, "le monta un pollo" y tiene miedo a sus reacciones. ·············· Van a ingresarlo en UME e intentarán trabajar hábitos con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-20','miguel, recibo email del abogado Jorge Calvo, remitiendo la referencia del incidente abierto del procedimiento de la 1º ejecución del laudo. Me reenvía de la aseguradora Catalana Occidente el email:Jose Luis Gomez >jlgomez@alkora.es> Buenos días, Jorge, Te confirmo que hemos aperturado de forma interna siniestro con número de referencia 2023005148. Del mismo modo, hemos comunicado siniestro en Catalana Occidente cuya referencia 33296658, dejamos anotada junto con la nuestra en el asunto del presente correo de cara a que puedas tenerlas en cuenta en futuras comunicaciones. Estamos pendientes de designación de tramitador por lo que tan pronto como tenga noticias, te informo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-20','miguel, Mª Granada 667876533 me envía email confirmandome que la inquilina la ha llamado porque le ha llegado la demanda. Por otro lado Jorge (abogado) sigue alargando pedir el desistimiento del caso: Buenos días Miguel, A fin de que quede claro. El último trámite realizado en la nueva ejecución es la solicitud de embargo de las cantidades de las costas que en el otro proceso puede querer cobrar la demandada. Con desistimiento se pierde dicho trámite. Además tenemos decreto de lanzamiento pero sin fecha lanzamiento. Con todo ello y siendo conocedor de todo derecho. me das orden expresa de desistir de la causa? (Escrito desde el móvil disculpa la falta de signos) Se quiere desde la comisión mi renuncia en el primer procedimiento? Ruego se me indique de manera expresa dado que en el email recibido no he detectado la orden hacia mí -abogado- En referencia al seguro estoy a espera me den indicaciones para poder trasladaros sin problema alguno. ----------------------------------------------------- jorge me reenvia el email del gestor, tramitador de siniestros Jose Luis Gomez >jlgomez@alkora.es>: Buenos días, Jorge, Te confirmo que hemos aperturado de forma interna siniestro con número de referencia 2023005148. Del mismo modo, hemos comunicado siniestro en Catalana Occidente cuya referencia 33296658, dejamos anotada junto con la nuestra en el asunto del presente correo de cara a que puedas tenerlas en cuenta en futuras comunicaciones. ------------------------------------------------------- Contesto a Maria Granada: Gracias, Maria, efectivamente únicamente remiti a la procuradora el documento y la pedí que me enviara justificante Lexnet, nada más…A partir de ahí comenzaron los mensajes de este hombre A lo de la reunión ya le he dicho por email que ni estoy en la oficina ni veo razones para ninguna reunión… Como ves me pregunta Jorge si le estoy pidiendo renunciar al primer procedimiento, el cual ya está finalizado… Simplemente le tengo que indicar que presente la procuradora el escrito que se le ha remido no?. A esta hora de hoy sólo me ha enviado la incidencia del seguro que te transmito aquí por si ves algo que no cuadre, que me reenvía del gestor de siniestros…: ---Lo que no sé ahora es qué tramites tengo yo que hacer con el gestor de siniestro o él de oficio estudia el caso y ya esta?…---','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-10-20','miguel, llega la apertura de juicio oral del procedimiento DPA DILIGENCIAS PREVIAS PROC. ABREVIADO 0001717 /2021 del jzdo nº3 de Badajoz, siendo su abogado Jose Fernando Garcia Espinosa, por hechos del 6-10-21 daños en la vía publica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2023-10-17','Ana: Llamada de Montaña, TS SSASB: Isabel ha vuelto a ir a su despacho a pedirle que le haga el testamento. Montaña le recuerda que debe acudir al Notario. Ella dice que no quiere pagar un notario. ········ Acordamos que llamaré yo a la Residencia para hablar tanto con Ana, Directora, como con Isaebel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2023-10-20','Ana: Llamo a Ana, directora de la Res. de Torrecillas de la Tiesa (927 33 80 76 // Directo de Ana: 680 35 10 25): La hermana de Isabel últimamente la está llamando mucho, agobiando a Isabel, diciéndole que si no es ella la tutora la Junta se va a quedar con el dinero. *Isabel no quiere que su hermana ejerza el cargo. ··· La semana pasada le llamó todos los días. ···· Les digo que si las llamadas a Isabel la perjudican, se puede restringir, por ejemplo a una a la semana. ········· La hermana le ha dicho que el testamento lo tiene que hacer en Plasencia y que le tiene que acompañar ella, pero Isabel así no quiere. ············· *Acordamos que lo harán en un notario de las inmediaciones (posiblemente Trujillo). Le acompañarán desde el centro, seguramente Ana, Directora. Cuando pidan cita al Notario, le facilitarán los números de los asesores jurídicos, por si éste quiere llamarlos en relación a la medida de Isabel. ······ Solicitarán presupuesto a la notaría y lo enviarán al ctutelar@ ················ Hablará con Isabel y si lo ven conveniente y ella quiere, me avisarán para que hable yo también con ella. ····················································································· Envío correo a los A. Jurídicos - CTAEx: "Sólo comunicaros que ISABEL MUÑOZ MELCHOR quiere hacer testamento. Desde la Residencia en que reside pedirán cita en Notaría. Cuando lo hagan les facilitarán vuestros números por si quien hablar con vosotros. Tanto la Directora de la Residencia, como la Trabajadora Social del SSASB, como yo, pensamos que Isabel puede testar." ························ Respuesta de Ángel, A. Jurídico: "En principio su sentencia de incapacitación no se lo impide. Por tanto, puede, si el Notario así lo considera."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='TORES'and apellido2='NUÑEZ'),'2023-10-20','Ana: Envío correo a Emilia Almodóvar, TS, y a Rosa Bravo - CSS: "Creo que ya lo sabíais, pero por si acaso, os reenvío CEDULA DE CITACIÓN relativa a JULIÁN TORES NUÑEZ, para la revisión de sus medidas judiciales de apoyo. La comparecencia es el próximo lunes a las 12:15. Espero que desde el centro se pueda organizar el desplazamiento y acompañamiento sin problema."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-20','miguel,recibo email de Jorge (abogado) con copia a su procuradora (Cristina) donde por fin la da orden de desistimiento: Buenas tardes Cristina, Releído el mensaje recibido esta mañana por Miguel, y atendiendo a la orden que nos da de desistimiento. A fin de dar efectivo cumplimiento de la orden del cliente, te adjunto escrito desistimiento que ha remitido el propio cliente en donde lo quedo firmado digitalmente a fin de que no adolezca de falta de firma letrada por la postulación necesaria en la causa. Adjunto en copia a Migue para su tranquilidad y mejor seguimiento, quedando sin efecto el último email que le he enviado, dado que leído atentamente el email recibido por su parte, atiendo a su orden expresa de desistimiento. Por supuesto, asumir la orden expresa del cliente no implica que acepte la premisa que indica de que la ejecución está mal planteada. Te ruego le puedas remitir entrada lexnet a miguel en cuanto la tengamos presentada. Muchas gracias por tu trabajo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-20','miguel, contestación de la abogada Maria Granada 667876533: Las costas nunca se podían haber embargado, y él sigue por ahí. Así que a ese respecto NO se pierde nada con desistir. Qué más da tener decreto de lanzamiento si se va a oponer la contraria y si lo gana....otras costas más que abonar. EN el mio también existía lanzamiento. Entiendo que aún no ha presentado el desistimiento, ya que te lo pregunta. Claro que debe desistir, porque está mal la demanda y se puede perder si se dan cuenta. Si hubiera presentado el desistimiento cuando se lo mandaste hubiera estado en el juzgado presentado antes del dia de hoy....y al ser antes de la notificación de la demanda, se hubiera archivado ese proceso sin más y sin costas. Al haberle notificado ya la demanda hoy a la contraria, pues me ha llamado para decírmelo, ahora el juzgado le va a dar traslado a ella..y ya veremos que opina el abogado que le turne. Porque lo mismo se arriesga a decir que no al desistir porque se de cuenta del erro que hay y querrá ganarlo, con costas. Ya ha vuelto a causar otro daño al no haber presentado el escrito cuando lo mandaste. Ahora que esperar qué dice la otra parte. Yo insisto en la idea del desistimiento a la vista de cómo ha presentado la demanda. Así que deberás ponérselo expresamente para que le conste y lo presente. Pero puedes preguntarle por qué no lo ha presentado ya, desde que tuvo conocimiento por la procuradora del escrito, porque es obvio que es vuestra decisión, la de desistir. No comprendo. Con este retraso ha impedido archivarlo sin dar opción a tener que preguntar a la otra parte. Por eso te decía yo que era urgente su presentación y te lo mandé tan rápido. Al primer procedimiento, el 333/2022 no tiene que renunciar, pues ya está acabado. No tiene sentido. Ya no se pueden presentar más escritos en dicha causa. Está archivada definitivamente por el juzgado. Y si, debes decirle que presente el escrito que le has remitido a la procuradora, sin más, tal cual. Si quiere presentar alguna modificación que te la consulte antes. Desgraciadamente ya tiene la demandada notificada desde hoy la demandada. Yo si me llama porque le notifiquen el desistimiento antes de tramitar lo de abogado de oficio, le diré a ella que acepte el desistimiento sin más. Respecto a lo del siniestro, no se sabe en qué términos ni cuando ha dado parte del mismo, pero bueno, de momento, habrá que quedar a la espera y que a resuelva el seguro y la decisión que tome. Esa decisión te la tiene que comunicar él, indudablemente. Porque a él se la comunica el seguro cuando tome la decisión. Espero que haya dado bien el parte a la compañía. Vosotros directamente no podéis preguntar. Es importante que lo haya dado bien, para que la compañía de seguro lo vea claro y os indemniza sin tener que ir a juicio. No entiendo que ponga que no asume el fallo.... nada más que hay ver que lo perdió y por no acompañar un documento a la demanda. De quién es el fallo entonces?? Me da miedo pensar cómo ha podido hacer el escrito al seguro. Yo te pasaré los datos de nuestro seguro...por si quieres llamar y con los datos del siniestro preguntarles a ellos directamente. Respecto a si sigue siendo el abogado de carmen, en el primero..ya está acabado...pero aún así ponle expresamente que no presente ningún escrito más en dicho asunto. Y que tiene que presentar el desistimiento en esta segunda ejecución, si aún no lo ha presentado. Y que te tiene que notificar lo que resuelvan en dicha causa para estudiar qué paso dar. Y que cuando lo presente y os mande sus honorarios, tomaréis la decisión que corresponda. Porque hasta que resuelva el juzgado el desistimiento, no merece la pena contratar a otro abogado pues incrementaría los honorarios de manera absurda para vosotros. ------------------------------------------------------- Jorge, como sabéis la obligación de esta Comisión es velar por los intereses de los tutelados, y en eso se basa nuestro trabajo y no en otros motivos, y menos en motivos personales. El primer procedimiento no se tenía que haber interpuesto porque el contrato de alquiler decía claramente que se sometía al tribunal de arbitraje. Se cometieron errores también en la presentación de la demanda del laudo al no acreditar desde su interposición el testimonio que después te fue remitido. Por último los dos procedimientos de ejecución tienen defectos en su demanda, en la primera ejecución al no acompañar de documento esencial que es la comunicación del laudo y en esta segunda ejecución demanda la parte demandante no es Carmen Leal sino la Comisión Tutelar de Adultos en nombre de Carmen Leal. Se hubiera perdido con seguridad el caso. Además de que ya nos han confirmado que no le conceden el derecho a la asistencia gratuita en el Colegio de Abogados, y ya se te comentó que no podía afrontar un nuevo gasto semejante al primer procedimiento. Ayer os solicitamos que desistieseis del procedimiento en el mismo día, esperemos que este retraso de ayer a hoy, todavía no hayan notificado a la otra parte la demanda pues podríamos encontrarnos en el mismo problema que nos reclame su abogado daños y perjuicios en vez de haberse archivado la causa, que era la pretensión de esta Comisión, y de cuyo retraso sois responsables. En cuanto al primer procedimiento está finalizado y por tanto debéis notificarnos cualquier trámite que hayáis realizado y por supuesto no realicéis con respecto al mismo ninguna actuación más pues. Enviadme el justificante Lexnet en cuanto esté presentado la orden de desistimiento. Quedamos a la espera de que nos remitáis vuestros honorarios para su estudio y la factura del árbitro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-10-20','Ana: Llamo a Ventura (682 483 126): como no sabe qué frigorífico elegir, va a ir a verlos otra vez esta tarde y el lunes me dirá. ········ *Esta mañana le han puesto las vacunas. ·········· Dice que también ha estado hablando hoy con "Consoli", la anterior D-Gerente del Sepad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-20','miguel, envío email a Alberto, Amalia, Maite y Angel: Hola a todos, el abogado por fin hace un rato ha accedido a pedir el desistimiento del procedimiento. He apuntado todo en la intranet. Hay dos procedimientos de ejecución: -El 1º lo perdimos y hemos pagado las costas. El abogado y la procuradora no han mandado un encargo o proforma (previo a la factura) correctos. Le he pedido de parte al seguro ante sus continuos errores en los procedimientos. -El 2º es el desistimiento que desde ayer le insistí que hiciera y que si lo hubiera hecho el caso se habría archivado. El problema es que hoy le ha llegado la comunicación para contestar la demanda a la inquilina y ello supone que el abogado avispado que lo coja puede meternos otra vez costas procesales. Os adjunto email explicativo y último que envío al abogado y procuradora debajo con el que doy por finalizado este asunto. Queda en un plazo de 5 años (desde que dictaron el laudo arbitral, que es como una sentencia ) para que busquemos otro abogado o un mediador… Buen finde, y si os quedan dudas lo hablamos. Habrá que esperar que resuelve el seguro de responsabilidad civil del abogado en el primer procedimiento, del cual no sabemos qué ha comunicado él, ni podemos contactar directamente con la compañía aseguradora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-10-20','Ana: Llamo a Felisi (614 361 144): sin éxito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2023-10-20','Ana: Envío mail a Mai Masegosa, Jefa Secc. Acceso a RR.MM (margarita.masegosa@salud-juntaex.es): "En relación a MARÍA LUISA MONTAÑA ALISEDA, con DNI 08688575, quería pedirte que, cuando puedas, consultes y nos informes en qué posición está en la lista de traslado. Ella reside en la Residencia Cervantes de Cáceres e ingresó vía decreto por emergencia social."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-10-20','-Amalia : ponga para registrar a Julio , cambio PIA para solictar SAD municipal de Zafra. Se ha averiguado el seguro del hogar de LIberti , se archiva la poliza. LLamo para informar del fregadero. Se ha devuelto seguro de coche de M. Madrileña. No hay que aceptar el pto. del abogado , lo ha averiguado EStrella .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-10-20','Ana: correo de Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es): "Te comunico que tal vez venga el tío de Enrique algún día del fin de semana a sacarlo de pase a domicilio, volviendo a pernoctar al centro ya que según su Psiquiatra es beneficioso terapéuticamente para el paciente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2023-10-23','TERESA EMAIL DE LA DIRECTORA DEL CENTRO Sobre la petición del padre y del propio tutelado de realizar estudios de administración, informarte que visto su expediente, Juan Jose finalizó el curso 2021/22 una Formación Profesional en Servicios Administrativos, en la localidad de Trujillo. Desde el Centro Ocupacional están trabajando con él en la búsqueda de empleo (alta en el SESPE con su titulación, alta en bolsas de trabajo de empresas que contemplen en sus plantillas la contratación de personas con discapacidad, etc.) Estamos en contacto con academias para conocer cursos, para este año, relacionados con su titulación y pueda realizarlos. Eloy, su padre, está informado igualmente y lo que nos propone es que su hijo se matricule en el grado superior de administración. También se ha acordado que Juan José se pueda ir a casa cada 15 días. Si hasta ahora no lo ha hecho es porque el padre o Juan José no lo pide. Nosotros tenemos como norma estar abiertos a las peticiones de las familias sobre los días que quieren irse a casa, pero en ningún momento tomamos la iniciativa para que no se sientan presionados. Con respecto a la presión que siente con el compañero, también estamos haciendo gestiones con el SEPAD para cambio a vivienda tutelada, pero no es fácil ya que en la vivienda actualmente no hay plazas vacantes. Desde nuestra Asociación, se están poniendo todos los medios que están a nuestro alcance para atender la demanda de Juan José y de su padre, y sobre todo para que el tutelado se encuentre cómodo en nuestros Servicios, no obstante, si ambos persisten en el cambio de centro por proximidad geográfica del domicilio familiar, seréis vosotros quienes decidáis lo mejor para él','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='VELASCO'and apellido2='CAPERUZA'),'2023-10-23','TERESA ARCHIVO AUTO POR EL CUAL TIENE QUE ABANDAONAR LA RESIDENCIA EN LA QUE SE ENCUENTRA ACUTALMENTE SE LO PASO A ANA MORENO PARA QUE LE DEN PLAZA EN OTRA RESIDENCIA Y CUMPLIR EL AUTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2023-10-23','Ana: Respuesta de Mai Masegosa, Jefa Secc. Acceso a RR.MM (margarita.masegosa@salud-juntaex.es): "por vía decreto es difícil ya que se tiene que dar la circunstancia que no existan peticiones por dependencia, deberian valorarla" ··················· Respondo: "Está valorada, pero sólo dio GRADO I en septiembre de 2020. No creemos que a día de hoy dé más grado, por eso no hemos vuelto a pedir revisión" ································································································································································································· Escribo a Minerva, TS CR Cervantes (minerva.salvador@salud-juntaex.es): "La respuesta que me dan en la Secc. de Mayores en relación al Traslado de María Luisa Montaña Aliseda es que “vía decreto es difícil ya que se tiene que dar la circunstancia que no existan peticiones por dependencia”. Como ella no ingresó por Dependencia lo tiene difícil a menos que la vuelvan a valorar y dé más grado. ¿Pensáis que podría dar grado II? Ya me decís. Si fuera el caso solicitaríamos revisión de grado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2023-10-23','Ana: Envío a Raquel Árias, Psicóloga Casa Familiar Virgen de la Montaña (psicologiacf-caceres@cruzblanca.org) el PAI firmado digitalmente por la Representante Legal.','2');
