insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2023-10-23','Ana: Envío correo a la RRMM Santa Catalina de Calzadilla (residenciasantacatalina@gmail.com): "Adjunto la Autorización para el Sistema Personalizado de Dosificación de Medicación de la Farmacia relativo a EMILIANA SANCHEZ BERMEJO. Aprovecho para preguntar qué tal sigue Emiliana y recordar que ante cualquier otra cuestión, no duden en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS MARIA'and edp.apellido1='GRANDE'and apellido2='VICARIO'),'2023-10-23','Ana: Envio a Sonia Generelo, Directora de la Res. Virgen de la Montaña - Grupo Ciudad Jardín (virgendelamontana@grupociudadjardin.com): el CI para las vacunas de la GRIPE y Recuerdo de COVID firmado digitalmente por la Representante Legal.','2');
