insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-10-20','Ana: me remiten desde el ESM-CC (equiposaludmental.caceres@salud-juntaex.es), con copia a la Dra. Cristina Donoso, Psiquiatra (cristina.donoso@salud-juntaex.es): "Adjunto remito informe de la psiquiatra CRISTINA DONOSO JIMÉNEZ con relación al paciente CARLOS GONZÁLEZ LEO, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura en virtud de Auto 15/2023, de 3 marzo de 2023. Así como la próxima cita de revisión con la doctora para el día 14 de Diciembre de 2023." ·························· Según el INFORME: "Dx de retraso madurativo. T. del comportamiento, T. del control de impulsos y rasgos límites de la personalidad" ··········· En cuanto al tratamiento, tenía pautada, ademá de otra medicació oral, Trevicta 250 MG, IM cada 3 meses. ············ Al final del informe dice que a la próxima cita programada "deberá acudir acompañado por responsable de la Comisión Tutelar".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2023-10-19','EXITUS El centro comunica su fallecimiento. Se entiende que el óbito se produce el 18/10/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2023-10-23','TERESA RECIBO LLAMADA DE RAQUEL 654691289 LA AXULIAR DE SAD Y ME COMENTA QUE DIEGO HA VENIDO DEL HOSPITAL CON MUCHA MEDICACION, NO CONTRLA ESFINTE Y ETA TODO EL DIA DORMIDO CON LO CUAL NECESITA UNA SUPERVISION CASI CONTINUA LA CUAL NO SE LE PUEDE OFRECER EN EL DOMICILIO LO HA LLEVADO EL SABADO AL HOSPITAL Y CONSIDERAN QUE TIENE EXCESIVA MEIDCACION PERO NO PUEDEN MODIFICAR LO QUE LE PAUTA EL PSIQUIATRA LE INDICO HABLER CON SU MEDICO DE CABECERA Y CON EQUIOPO DE SALU MENTAL PARA AJUSTAR MEDICACION SI CONTINUA EN ESE ESTADO HABRA QUE PLANTEAR INGRESO EN RESIDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FE'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2023-10-20','TERESA ENVIO EMAIL A PETICION DE JOSE ORTIZ autocareortizz@hotmail.com Buenas tardes Tras conversación telefónica paso a detallarle lo que necesito me envíe para tramitar su petición. Solicitud en la que exponga la petición de dinero, cantidad y motivo. Declaración de Mª Fe en la que manifiesta el deseo de pagar la operación para su hermana Juana Presupuesto de la operación Cualquier otro documento que estime oportuno a fin de justificar el pago de la operación por parte de la persona a cargo de esta comisión tutelar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FE'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2023-10-20','TERESA Ayer hable con el taxista 659 632 998que es el teléfono desde el que nos habían estado llamando Don José Ortiz. Hoy he hablado con Juana 601 62 41 31, hermana de Mª Fé y nos solicita que le paguemos con el dinero de su hermana un operación de cataratas por importe de 900€ Le indico que nos lo solicite por escrito junto con el consentimiento de su hermana y el presupuesto de dicha operación','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-10-23','Ana: Correo de Leire Sanz, TS de la Res. Ciudad Jardín (t.socialcanovas@grupociudadjardin.com): "Te quería hacer una consulta, me preguntan desde DIRECCIÓN, si podemos deshacernos de la llave de la Casa que tenemos porque ya han cambiado la cerradura y para que la quiere María." ····································· Contesto con copia a los A. Jurídicos: "Entiendo que si la cerradura de la casa de MARÍA JIMÉNEZ PICÓN se ha cambiado y tenéis constancia de este cambio (factura o algo que así lo demuestre), podréis deshaceros de la llave sin problemas, no obstante, dados los antecedentes, pongo en copia a mis compañeros, Ángel y Miguel, Asesores Jurídicos, por si tienen que añadir algo más." ·················· *Respuesta de Ángel, A. Jurídico: "¿Disponen de la copia de la nueva llave? Si no es así, solicítenle copia a quien ha indicado que se ha procedido al cambio de cerradura, para que os la faciliten. Hasta entonces, no os deshagáis de la llave que disponéis."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2023-10-23','TERESA SE REGISTRO REVISION PIA SOLICITANDO TRASLADO A CENTRO DE BADJOZ POR ACERCAMIENTO FAMILIAR YA QUE ASI NOS LO SOLICITAN DESDE EL CENTRO EN EL QUE SE ENCUETRA AHORA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2023-10-23','TERESA SE SOLICITA REVISION PIA PARA TRASLADO A PETICION DE LA INTERESADA POR ACERCAMIENTO FAMILIAR A CACERES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2023-10-23','Ana: Tras llamar a Ana, Residencia, envío correo al ctutelar@ a la atención de la secc. ecca: "Os vuelvo a reenviar el correo de la directora de la residencia de Torrecillas de la Tiesa. Ya me lo han aclarado, Isabel quiere ir a pasar la mañana a Plasencia para acudir al Cementerio a llevar flores antes del día de los difuntos y después ir también a la Ermita de la Virgen del Puerto, siente devoción por esta Virgen. Por mi parte, si es viable, no hay problema. El taxista la llevará, se quedará por allí toda la mañana y la traerá de vuelta. El coste asciende a 150€. Si se acepta, porfa, contestarle directamente a la directora de la residencia, tenéis el correo en el hilo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-10-16','miguel, me llama Damian 687217049, pregunta por dos cartas que envió la semana pasada, el día 11-10-23 al antiguo Gerente José Vicente. Le comento que a la Ctaex no ha llegado nada. Comenta que una carta contradice a la otra, que él se ve capacitado para recuerperar su curatelada. Que no le comente nada a Amalia porque quería informarse y el director del Crr no podía atenderle. Le comento que el expte de revisión de medidas de apoyo ha sido trasladado desde Cáceres a los juzgados de Mérida y que todavía no nos ha asignado juzgado y procedimiento. Le explico también, que mañana iremos al jzgado con la Gerente para hacer el poder apud acta para la solcitud de la venta del piso de Málaga, que se va a tramitar desde Mérida. Me pregunta por la llave, que si su prima nos la devolvió, le he dicho que no, y que queremos que la siga teniendo para cualquier imprevisto(arreglos, para el informe del tasador cuando vaya...) Me insiste en la compra de inmueble en Mérida: quién lo elige él o nosotros...le digo que eso lo tiene que ver con la parte económica y social. En definitiva se ve que quiere le vendamos la casa y compremos otra y recuerperar su capacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-10-23','TERESA LLAMO A PABLO PARA VER COMO SE ENCUETRA ME DICE QUE A IDO POR SU ASIGNAICON Y QUE HA COMPRADO COMIDA Y HA CARGADO EL MOVIL LE PREGUNTO POR LA VIVIENDA Y DICE QUE ESTA BIEN ME DICE QUE CON EL DINERO QUE LE DOY LE DA PARA POCO TIENE CITA EN SALUD MENTAL EN CACERES EL 8 DE NOVIEBRE, HAY QUE CAMBIAR DE EQUIPO PARA QUE LO VEN EN CASTUERA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2023-10-23','miguel, ante la pregunta de Tere de si sabemos algo de fiscalía o del juzgado de los posibles abusos comentados por la tutelada. Llamo a Pedro de Fiscalía 924552452 y traslado la conversación vía email a Tere: Buenos días, he hablado con Pedro de Fiscalía(es un administrativo), que me ha confirmado que recibieron mi email, y que ya está la documentación en manos del fiscal, entre la cual le digo no hay esta vez que sepamos denuncia firme, pero sí en ocasiones anteriores. Les he traslado la inquietud de la parte social en el sentido de que al haber vuelto ya a la vivienda corre un riesgo importante. Le he indicado que le diga al fiscal que si quiere entrevistar a la tutelada la buscaríamos quién la acompañara al juzgado, y que puede contrastar lo que dice la tutelada con su hijo, que habitualmente nos traslada lo mismo que su madre. También le digo que en caso que decidan una orden de alejamiento que porfavor le diga al fiscal que intente que sea el hermano el que abandone la vivienda. Cuando sepan algo me lo dirán. Quedo a la espera que nos comuniquen algo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-10-23','Ana: Llamo a Carlos (644 949 205): Se aceptará la ampliación del SAD un día más a la semana. ······· Aún está pendiente el arreglo de la lavadora, llamaré al Seguro para dar parte. Él dice que ha ido a la oficina de Reale, pero no le hacen caso. ··············· En cuanto al Seguimiento en Psiquiatría, mantiene que él acordó dejar el Tto. de forma pautada con a Dra. Wendolyne y así lo hizo... Dice que tiene un informe de Alta y que me lo va a enviar. ·················· Llamo a REALE SEGUROS (900 455 900) para abrir parte de Seguro de Hogar (Nº: 2023/1462336). *Su seguro no cubre las averías en electrodomésticos, pero sí cubre el traslado y visita del Técnico. Cuando acuda debe abonar 40€ de verificación del trabajo que posteriormente se le descontarán del total del arreglo. La empresa de la que acudirán es ACTEIN SERVICIOS S.L. ················ *Solicito el extra de 40€ a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2023-10-23','miguel, me llaman de la notaria de Monesterio, confirmando que ya se ha firamdo la delcaración de herederos, pendiente únicamente de nuestra ratificación. Lo han remitido por correo corporativo a la notaria de Mérida (vía signo) para nuestra ratificación. Hablar con la notaria para ratificarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-10-23','Ana: Envío correo a Carolina, Directora CRR (direccion.crrplasencia@grupo5.net): "Te reenvío correo de mi compañero Ángel, Asesor Jurídico, con Citación a la que debe acudir Isabel Cano Blázquez como testigo (26/10, a las 9:15). ¿Sería posible que la acompañaseis? Como sabéis seguimos sin el Apoyo del Convenio entre la Consejería y Futuex, dicen que quizá para diciembre…. Confírmalo cuando puedas, por favor." ·················· Carolina confirma que le acompañarán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-10-23','Ana: Respondo al correo de Guadalupe Cortes, TS SAD IMAS (guadalupe.cortes@ayto-caceres.es): "Vamos por partes: - Nos parece bien la ampliación del Servicio de Ayuda a Domicilio que proponéis. Lo que no me queda del todo claro es si será algo temporal (por la circunstancia coyuntural) o se mantendrá después, ya me dirás. - En cuanto a la lavadora, sinceramente, ya no me acordaba que esto estaba en el aire, pues es una de las gestiones de las que había encargado la educadora de Futuex y Carlos no me ha vuelto a decir nada al respecto. Decirte que he abierto un parte en el Seguro de Hogar. Si bien no le cubre la reparación de electrodomésticos, sí el traslado y servicio de valoración del Técnico. Así que le llamarán para ir a ver la lavadora esta semana. Él ya lo sabe. *La factura se abonará después. - En cuanto a la amiga que me dijo que le ayuda, a mí me dijo que le daría parte de su asignación semanal para que le fuera a hacer la compra, no que le diera su asignación semanal completa (75€). No estoy segura de que se lo haya dicho todo. Y de esto se me ha pasado preguntarle hoy, la verdad. - En cuanto a su diagnóstico de Salud Mental, sí, viene mal en el Informe del hospital, me lo enviaron la semana pasada tras haberlo solicitado. No obstante, precisamente el jueves pasado, hablé con su Psiquiatra de referencia. No se presentó a las últimas citas (anteriores a aceptarse el cargo) Ni ella sabía que estaba ya a cargo de la CTAEx, ni yo sabía que él había estado en seguimiento tantos años en Salud Mental. Me ha envido informe y nueva citación para el día 14 de diciembre. A Carlos también le ha llegado y a este no le ha gustado ni un pelo que l e vuelvan a citar porque no quiere ir. *El tratamiento farmacológico, al parecer, también lo abandonó voluntariamente. Iremos viendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2023-10-23','TERESA HABLO CON M ELENA SE ENCUENTRA BIEN Y TRANQUILA NO QUIERE IRSE A LA RESIDENCIA Y DICE QEU SU HERMANO NO EL HACE NADA QUE NO QUEIRE QUE LE HAGAN NADA A SU HERMANO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2023-10-23','Ana: Correo de Sonia Leo, Directora Res. Virgen de la Montaña: "Adjunto certificado de defunción de Dña. Isidora Leal Román fallecida el 19/10/2023. Se llamo a su seguro facilitando su número de póliza y no hubo ninguna incidencia. tal y como nos indicas, traspasaremos la cuestión económica pendiente al correo facilitado." ······································· El Cdo. que envían es el Certificado Médico, no el de registro. Se lo reenvío igualmente al María, Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-10-24','Ana: Llamada de Julián Álvarez Delgado - Gerente de COCEMFE (gerencia@cocemfecaceres.org / 927 23 90 28 / 654 18 19 64): Tomás HA FALLECIDO. Ayer estaba bien, por la noche tuvo unas décimas de fiebre.······ El Forense no cree procedente hacer la autopsia, no ve motivos para hacerla. Cree que puede haber sido una SEPSIS por Infección de orina o una broncoaspiración, pues esta mañana tenía un poco de vómito negro. Están en Urgencias - HSPA. ······························ Llamo yo a MAPFRE - Seguro Decesos (924 81 09 10), salta todo el tiempo y buzón de voz. ······ Estrella, secc. ecca. llamará a otro contacto que tiene ella. ···································· En cuanto a la hermana de Tomás, Soledad, estuvo con las otras compañeras del RR a verlo el domingo. ·················· Julián llamará a NACE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-10-24','Ana: Tras llamada de Ventura, elige el frigorífico de Carrefour. ························ Llamo al nº que viene en el presupuesto (914 908 900). Pasan mi contacto a la tienda para que me devuelvan la llamada a lo largo de la mañana. ··························· Como no me llaman, llamo yo a la tienda del Carrefour (927 62 98 99): facilito los datos del cliente y del presupuesto así como los números de Estrella y Lourdes, Secc. Ecca. CTAEx, que a su vez se los pasarán al departamento correspondiente. ····· Llamarán a lo largo de la mañana de hoy o de mañana. ·············· Envío mail a Estrella y Lourdes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-10-24','Ana: Reenvío a Alberto, Jefe Secc. Ecca. dos correos: 1- de la residencia con carta informativa de modificación Plan de Pensiones Iberdrola. 2- de Merche, tía del hijo de Victor Manuel en relación a las cuentas del B. Santander y la necesidad de cerrar las mismas. ··························································································································································································· Envío mail a Iberdrola, a la dirección indicada en la carta (prejub@iberdrola.es): "...En relación a D. VICTOR MANUEL BLANCO POVEDA, cuyo cargo de CURATELA REPRESENTATIVA ostenta la CTAEx, en virtud de Auto nº 42/2023, de fecha 18 de abril de 2023, adjunto: - Certificado de BASES Y CUOTAS DE COTIZACIÓN DE REGÍMENES Y SISTEMAS ESPECIALES por ustedes solicitado - Carta – solicitud de dicho Certificado recibida - Testimonio de Aceptación del Cargo de Curatela Representativa Así mismo, SOLICITAMOS: - Nos remitan copia del CONTRATO DE PREJUBILACIÓN Y CONVENIO ESPECIAL del que es titular D. Víctor Manuel - A partir de ahora, los certificados/comunicaciones que emitan nos sean remitidos a nombre de la Comisión Tutelar de Adultos, Avda. de las Américas, nº 4, CP 06800 – Mérida. Siendo éste el domicilio a efectos de comunicaciones. Al objeto de poder llevar a cabo adecuadamente las funciones judicialmente encomendadas. Rogamos nos remitan confirmación de haber recibido este email así como el certificado adjunto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-10-16','TERESA ME COMUNICA M JESUS QUE NO LE DAN PLAZA EN LA CASA DE LA MUJER. LE COMETNO DE UN CENTRO QUE EXISTE EN SALAMANCA. A TRAVES DE LOS SERVICIOS SOCIALES LE GESTIONAN LA DOCUMENTACION PARA INGRESAR EN EL CENTRO ESTA A LA ESPERA DE QUE LE ACEPTEN PUES NO QUIER SEUGUR VIVIENDAO CON SU TIA PUES COMENTA QEU NO TIENE EL PISO EN CONDICONES PARA VIVIR. COMENTA QUE SU TIA ETA TODO EL DIA ACOSTADA Y QUE NO LIMPIA, TAMPOCO PERMITE QEU LIMPIE ELLA. ME MANDA CORREO CON LAS FOTOS DEL PISO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-10-24','EXITUS El centro informa de su fallecimiento. El óbito tuvo lugar el 24/10/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-10-24','Ana: Llamada de Guadalupe Cortés Terradillos, TS SAD-IMAS CC (927 21 23 35): a día de hoy se le puede ampliar a Carlos el SAD a 3 días/semana. Cuando mejore, el serv. se le reducirá a 2 días, si el acepta mantenerlo así (al principio sólo aceptó un día). ················· Por otra parte, ayer abrí parte al seguro de la lavadora, pero olvidé abrir otro por las cisternas. ·········· Llamo a Reale Seguro:','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-10-24','miguel, envío poder apud acta (emitido hoy en los jzdos de Mérida) para la solicitud de autorización de venta al abogado Enrique Perianes 2914@icaba.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERMINA'and edp.apellido1='SERRANO'and apellido2='MOCHOLI'),'2023-10-24','Ana: Envío correo a Rosa Bravo, CSS (rosamaria.bravop@salud-juntaex.es) con los CI para Biopsia Ginecológica e Inclusión en Lista de Espera Quirúrgica para biopsia vulvar (x lesiones en ambos labios mayores), firmados y sellados por la Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-10-05','Ana: correo de Sara, TS R.M. Banium Residencial (TrabajadoraSocialBanium@hotmail.com): "Informar que la usuaria Concepción Barbero Sánchez tiene consulta con el servicio de traumatología del Hospital Virgen del Puerto para una revisión de su evolución tras las recientes intervenciones, en la mañana de hoy. Para poder acudir a la consulta se le ha solicitado acompañamiento privado. Por lo que en los próximos días se les adjuntara una declaración firmada con el importe del acompañamiento." ······················ Pido que la declaración jurada la remitan directamente a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-10-24','Ana: Tras llamada de Estrella, TS CSS (24146) reenvío correo del día 15 a Alberto, recordando esta consulta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-10-25','Ana: Llamada de José Manuel (681 368 017): dice que el sábado tuvo que llamar a Urgencias y pedir una ambulancia que le llevó al HSPA. Se encontraba muy mal, con malestar y dolor. Le pusieron un enema. Las recomendaciones de comer mucha fruta y verdura y caminar, no las sigue, dice que no es capaz. ················ El día 31 tiene un juicio por agresión a otro hombre del barrio. Dice que sólo le dio unos puñetazos en la cabeza, que en la car no le toco... *Dice que tiene claro que no va a volver a pegar a nadie, por mucho que le provoquen. ············· Dice que quiere irse a vivir a la Residencia Cervantes (hace un par de semanas decía que no quería ir a una residencia de mayores). Después dice que por qué no se busca otra casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-10-25','Ana: Envío correo a Julio, Aux. Adtvo. CTAEx: " Adjunto “COMUNICACIÓN DE CAMBIO DE DATOS DEL EXPEDIENTE DE DEPENDENCIA”, comunicando cambio de domicilio y contacto, para que, cuando puedas, la remitas por REGISTRO a la Gerencia Territorial del SEPAD de Cáceres. Código de buzón: A11030403"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-25','miguel, ante la falta de comunicación de nuevo del abogado y la procuradora Jorge y Cristina, llamamos (Inés) al jzdo nº7 Badajoz, para que nos confirme si fue presentado el desistimiento. Le confirman que sí, que tras presentar el nuestro el viernes presentó la procuradora la orden de desistimiento. Hoy martes el juzgado comenzará a notificar el mismo, pero a nosotros no puesto que hemos intervenido a través de procurador y abogado, por lo que deberían de notificar la aceptación de dicho desistimiento a ellos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-10-25','Ana: correo de Maite, Jefa CTAEx, a Alberto, Jefe S. Ecca.: "Tras hablar con Ana respecto a las situaciones de Isabel y Ceferino, hemos decidido lo siguiente: ISABEL CANO: Se adelantan 180 € de su extra de 2024, ( se restarían de la cantidad asignada para ese año). Hay que autorizar para que lo retiren de su cuenta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-10-25','Ana: correo de Maite, Jefa CTAEx, a Alberto, Jefe S. Ecca.: "Tras hablar con Ana respecto a las situaciones de Isabel y Ceferino, hemos decidido lo siguiente: CEFERINO MARISCAL: Le quedan 700 € de su extra anual. Le vamos a quitar 500. Por tanto sólo dispondrá de 200 € hasta final de año. Los 500 de la penalización se descontarán de su extra para 2024. Haremos un escrito para informarle de todo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2023-10-25','Ana: Raquel Arias, Psicóloga Casa Familiar Virgen de la Montaña (psicologiacf-caceres@cruzblanca.org) me remite el PAI y pide se lo devolvamos firmado. ··········· Lo subo al portafirmas digital. ·············· En el PAI se recoge, por áreas Auxiliar: Requiere supervisión así como iniciaciones y apoyo para la ducha. Tiene control de esfínteres. Autónomo para comer. Le gustan mucho la salidas al aire libre. Es muy cariñoso, pero demanda demasiados besos y abrazos, lo cuál produce agobio y rechazo de otros residentes, llegando a generarse conflictos. ················· Enermería: "Diagnosticado de: - Trastorno adaptativo mixto con alteración de la conducta y alteraciones emocionales. - Retraso Mental Moderado", "en seguimiento por: - Programa PADDI - Médico de Atención Primaria - Psiquiatría - Neurología". "No ha necesitado actuación de emergencia, ni ha precisado acudir al servicio de urgencias hospitalarias.". "Después de la última revisión del PAI de Alberto, en la que se le notaba totalmente adormilado, aletargado, enlentecido... La psiquiatra modifica el tratamiento" "...está mucho mejor, más despierto e interactúa con los demás más activamente." "Tiene un patrón de sueño normal. Duerme durante toda la noche, con episodios esporádicos de enuresis nocturna." "Dieta normal.", "Come todo tipo de alimentos". ··········· Fisioterapia: "Cada vez tiene más cifosis dorsal, debido a que se mantiene continuamente en esa postura mirándose la barriga. No conseguimos corregir dicha postura.", "está sufriendo un deterioro mental que conlleva a un deterioro físico y funcional, que se está viendo aumentado con el paso del tiempo.", "mantiene su capacidad física para realizar las actividades de la vida diaria." "Tiene una marcha funcional y no necesita apoyos ni ayuda. Sube y baja escaleras correctamente". ···· Psicología: "En la esfera afectiva manifiesta eutimia, aunque es habitual en el residente una gran labilidad emocional, pasando de unas emociones a otras sin necesidad de estímulos externos conocidos" "Sintomatología de carácter ansioso en la cual el residente presenta niveles elevados de ansiedad, acompañado de agitación psicomotriz y verbalizaciones de temas recurrentes" "Actualmente presenta alteraciones de conducta caracterizadas por una conducta compulsiva y estereotipada, las cuales se dan frecuentemente (más de 2/3 veces a la semana)" "...agresiones tanto a residentes como a trabajadores." "No realiza las actividades de forma adecuada debido a problemas de atención inestable." ······· TO: "No se producen cambios significativos" "OCIO Participa en las actividades de ocio organizadas. Su comportamiento en éstas suele ser bueno. Le gustan dichas actividades" ····· TS: "FAMILIA Alberto ha tenido poca relación este año con su madre y hermana. En el PAI anterior, parecía que había mejorado la regularidad de videollamadas y llamadas, pero se puede constatar una bajada significativa" "Su relación con trabajadores y compañeros es regular, no ha generado amistad" "Es muy sensible al ruido y le agota estar en sala".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-10-25','Ana: Llamada de Felisi (614 361 144). Hace 3 semanas dejó la relación con Jesús. ·········· Está pendiente de que se apruebe el presupuesto de las gafas (nuevos presupuestos de ópticas de Arroyo de la Luz). Teresa, TS CTAEx los pasó a S. Ecca. junto con presupuestos de Aitor. ·········· Quiere pintar la casa, pues desde que se quedaron su hijo con la pareja sola, quedaron sucias. *Acordamos que podrá pedir presupuesto para primavera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-10-25','miguel, llega Auto que me envía la estimación de la orden de alejamiento, la abogada Gemma Alvarez >gemmaalvarezmar@gmail.com>: En relación al asunto de Maria Jesús Cruz Esperilla. Adjunto auto que acuerda una orden de protección a su favor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2023-10-25','miguel, asiste presentcialmente Tere al juicio por supuestos abusos del hermano procedimiento DPA 642/2023 del jzdo nº1 Zafra. No nos nombran abogado de oficio, mientras que el hermano-denunciado sí asiste con abogado. No me dan acceso por videoconferencia. Resuelven orden de alejamiento y tendrá que desocupar la vivienda el hermano','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='MARQUEZ'and apellido2='CABEZA'),'2023-10-25','-Amalia : escribo a Eva , Raquel y Maite : se le ha concedido plaza residencial en Olivenza a Vicente Márquez Cabezas. El traslado está previsto para el día 31 de Octubre . Desde el CRR comunicarán la baja correspondiente a la Sección de Salud Mental . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-10-25','Escribo al CADEX : como te comentaba vía telefónica , he contactado con Carmen para indicarle fecha y hora de la cita en CADEX y motivarla para que asista, pero se niega a ir. Os lo comunico a los efectos oportunos . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2023-10-25','Ana: Llamada de Ana Benavente, TS ESM (74955), están en su despacho Pilar y su pareja, Jesús. Pilar expresa que su madre es la que maneja desde hace años el dinero, ella no saca nada. Dice también que la maltrataba, "he vivido un infierno", "se lo queda siempre todo y está yendo otra vez a Cáceres al Juzgado". Acepta el apoyo de la CTAEx. ···· Actualmente están viviendo en Cedillo pero se quieren mudar a Zarza de Granadilla. Me facilitan sus teléfonos (Pilar: 613 33 66 47) y Jesús (722 14 55 10). ····· Les facilito el mío directo. Cuando se trasladen me lo comunicarán y darán la nueva dirección. ······· En cuanto a sus cuentas le explico que se intentará quitar a su madre de las mimas, se anularán las tarjetas y se le autorizará una asignación semanal. De momento Jesús es quien abona el alquiler y los suministros. ········ Pilar, NO sabe leer ni escribir. ···· Ahora mismo se ha quedado sin seguimiento en Psiquiatría, tienen que reasignarle un facultativo, pues ya no está quien le atendía, pero mantienen el seguimiento con la TS. ········································································· Envío correo a Alberto e Icíar, S.Ecca: "Ya he contactado con PILAR JIMÉNEZ AGUILAR y con la Trabajadora Social de referencia actual de Salud Mental. Vamos por partes: - El DNI lo llevará mañana al despacho de la TS para que nos lo envíe escaneado a color. - Podéis proceder a DAR DE BAJA LAS TARJETAS BANCARIAS, a la mayor brevedad. Al parecer las tiene la madre que es la que saca y se queda el dinero. - La cuenta hay que BLOQUEARLA YA! No sé si habrá cobrado hoy la PNC ni si la madre habrá retirado ya el dinero. Ojalá y que estemos a tiempo. - No sé si se ha podido quitar a la madre de la cuenta, si esto no se consigue, habrá que abrirle una para ella sola y cambiar la pensión a la nueva. - Ya no viven Plasencia, están viviendo en Cedillo, pero en los próximos días quieren trasladarse a Zarza de Granadilla (he mirado en Internet y a priori allí hay oficina de Unicaja) - Haremos una autorización de retirada de efectivo semana. Alberto, ¿qué te parecería 80€/semana y después reajustar si es necesario? Ya me dices. - Por último, habrá que hacerle SEGURO DE DECESOS." ··································································································································································································· Correo-respuesta de Alberto: "ANA: HOY HA COBRADO SU PENSIÓN Y ALGUIEN LA HA SACADO EN SU TOTALIDAD. EL SALDO HOY ES DE 12 €....X LO TANTO, HASTA DICIEMBRE NO PODEMOS FACILIAR UN SOLO € A TUTELADA. ANA: ICIAR HA PUESTO A LA FIRMA LA CANCELACIÓN DE TARJETAS O CUALQUIER OTRO SISTEMA DE REINTEGRO ESTA MAÑÁNA...EN CUANTO NOS LO FIRME GERENTE SE ENVIA...PERO YA NO PODEMOS HACER NADA PARA ESTE MES...TEN ESTO EN CUENTA. ANA: LA MADRE YA NO ESTÁ EN CCC Y CUANDO MANDEMOS EL ESCRITO, EN TEORÍA, YA NO PODRÁ SACAR DINERO SIN AUTORIACIÓN...QUIEN SEA, SE HA APROVECHADO DE LA LIBRETA DE AHORRO O TARJETA. ANA: DURANTE MUCHO TIEMPO TENEMOS QUE SER CONSCIENTES DE QUE NO NOS PODEMOS PLANTEAR NI EL MÁS MÍNIMO EXTRA ICIAR: HACEMOS REINTEGRO PERMANENTE DE 80 €/SEMANA (347 €/MES) A PARTIR DEL 01/12/2023 ---- TEN EN CUENTA QUE TENEMOS QUE ESTAR SEGUROS DE QUE LA CCC YA ESTÁ TOTALMENTE BLINDADA. ICIAR: TENEMOS QUE ASEGURARNOS DE QUE NO HAY NINGÚN RECIBO EN ESTA CCC (PARA SABER SI PODEMOS MANTENER ESTE NIVEL DE REINTEGRO) ESTRELLA: COMIENZA TRÁMITES SEGURO DECESO....XFA, TEN EN CUENTA QUE TIENE UNA PNC BÁSICA Y QUE NO PODRÍA COMENZAR A PAGAR HASTA DICIEMBRE DE 2023 (ESTE MES NO TIENE SALDO)" ···················· Informo a Ana Benavente, TS ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2023-10-25','Ana: Llamada de Raquel, TS del SSASB de Guadalupe (605 429 865) Juan sigue acudiendo a su despacho a pedir llamarnos y solicitar dinero y más dinero. ··· Cuando han llamado antes mi teléfono estaba ocupado. ··········· *Echa mucho en falta el seguimiento y apoyo de la educadora de Futuex. Pues le ayudaba con la gestión y buen uso del dinero. ····· Raquel dice que ella no puede garantizar que no pida un extra y no se lo gaste en la máquinas. ···························· ··························· Tras nueva llamada de Raquel y Juan con manos libres, envío correo a Alberto, Jefe S. Ecca: "He recibido llamada de Juan, desde el despacho de la TS. Como ya no tenemos apoyo de Futuex para estas cuestiones, no tenemos tampoco garantías de nada, pero expresa que necestia: - 1 Manta gruega - Botas - Ropa: o Pantalones de pana o Camisetas de invierno o Camisas o Abrigo Lo compra en el mercado del pueblo la semana que viene y se compromete a llevarle recibos/facturas a la Trabajadora Social para que nos las envíe. *Podemos asociar esta justificación a futuros extras, si no cumple, se le pueden reducir/denegar otros hasta que vuelta a tener Educadora que se encargue de estos apoyos. Pide 200€, si ves que es mucho, se le puede autorizar algo menos. Sería para retirarlo el próximo lunes junto con su asignación semanal habitual."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-10-25','Ana: Tras llamada de Estrella, TS ESM (24146), ENVÍO correo a Alberto, Jefe S. Ecca; Julio, Aux. Adtvo.; y Maite, Jefa CTAEx: "En relación a GUADALUPE GIL CABELLO, comunicar que HA INGRESADO EN UME – C. SOCIOSANITARIO DE PLASENCIA: - Julio, por favor, ¿podrías actualizarlo en la base de datos? - Alberto, en el centro, por su puesto, URGEN para que hagamos la AUTORIZACIÓN GENERAL DE CENTROS para que puedan retiar efectivo para tabaco yo otros gastos de bolsillo. Creen que con 200€/mes, sería suficiente, así que podéis establecer este límite. o En este caso no se llegó a limitar la cuenta. Si ha cobrado hoy, es probable que tenga la pensión íntegra. Ahora será buen momento para sanear la cuenta. o En principio la idea es que no regrese a su domicilio, no reúne criterios mínimos de habitabilidad y el tejado se está derrumbando. La casa era de los padres. Su hermano también falleció y que sepamos no hay más herederos. Entiendo que se puede proceder a dar de baja los suministros. o Que sepamos, no tiene Seguro de Decesos, habría que hacérselo o En la Unidad que está no abona plaza."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-10-25','Ana: Llamada de Aitor, desde el teléfono de su madre (614 361 144). Dice que lleva 2 días sin consumir, que sería un buen momento para ingresar en el Centro de Montijo. Lo está pensando... ····· Pregunta por los presupuestos para ropa y teléfono móvil. ······· Estamos pendiente de la respuesta de la secc. ecca. Volveremos a preguntar. ································ También pregunta si ha llegado la resolución del Jdo. Dice que quiere que le quitén la tutela, ponerse a trabajar y manejar él todo su dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-10-25','Ana: Llamada de Doroteo, expresa que sigue bien en el centro. Que en Plasencia hace más frío que en Cáceres. ······· Ayer acudió a la clínica dental a Cáceres, se hizo el empaste que le faltaba. De momento ya ha terminado. ······· Dice que tiene pendiente ponerse 2 piezas (implantes) pero que lo dejará ya para más adelante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-10-25','Ana: Llamo a REALE SEGUROS (900 455 900) comunico la avería en las dos cisternas, que pierden agua. *Me indican que el Seguro como tal no lo cubre, pero que tiene una "GARANTÍA DE BRICOLAJE", entra el desplazamiento y la mano de obra. Pero él tendría que tener allí el material. *Dado el caso, facilitarán mi número para que me llamen a mí primero de la empresa y pedir que lleven ellos el material y nos pasen factura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-10-25','-Amalia:Escribo al TS del pueblo ( Juan Carlos Gallardo ) : se ha solicitado C. Ocupacional , la pondrán en lista pero del centro que le corresponda por residencia y no en otro área. Se ha solicitado Internamiento involuntario en plaza residencial en centro de discapacidad via judicial , aún sin respuesta. Antonia percibe 2 prestaciones , PFHC Y P. ORFANDAD . La PFHC se le envía por transferencia a la cuenta de la madre para cubrir gastos de manutención de Antonia . La otra se le ahorra para gastos extraordinarios . Si le enviamos las 2 , la familia no va a facilitar que Antonia ingrese en centro para seguir percibiendo esa ayuda económica. Esperaremos a la respuesta judicial para hacer cambios en ese aspecto. EL resto de miembros de la familia perciben distintas prestaciones económicas , desde la Comisión se administran sólo las cuentas de la persona tutelada . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='GONZALEZ'and apellido2='ESCASO'),'2023-10-25','Me comenta la directora del centro que al final Sandra no empieza ahora las prácticas. El empresario, por organización y demás, hasta febrero no puede tener a nadie de prácticas, por lo que os haremos llegar, más adelante, el nuevo convenio con la modificación de las fechas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2023-10-25','-Email de Angel , juridico: Vamos a intentar varias opciones. Solicitar al Ayuntamiento de Córdoba, la división de la liquidación correspondiente al ibi de esa vivienda, para que a Mercedes le giren sólo su parte (50%). Necesito que me enviéis los cargos en cuenta correspondientes a estos ibis que hemos abonado recientemente. Al hermano habría que reclamarle judicialmente su parte (50%), pero me temo que poco vamos a sacar, debido a que esa parte está en ejecución por el Juzgado de Córdoba, que no nos ha querido informar al respecto, con lo que intuyo que su economía no estará muy boyante. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2023-10-26','Ana: Correo de Lourdes, S. Ecca, a Ana, Res. de Torrecillas de la Tiesa(anatdelat@hotmail.com): "Buenos días, ya tiene en la tarjeta los 150€ para poder retirarlos. Si, necesitamos la factura del taxi, para poder justificar el gasto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-10-26','Ángel: En relación con el juicio, por los supuestos abusos cometidos por la pareja de su madre, hablo con el Abogado, Pedro Ruíz Peña (686558488, pedroruiz@icac.es) y me dice que el juicio se ha celebrado, sin nuestra presencia, a pesar de haber solicitado videoconferncia y estar esperando desde la hora citada. Han condenado a la pareja de la madre al pago de 600 euros. Nos enviará la sentencia. Sigue vigente la orden de alejamiento. ······················································································· Correo del Abogado, Pedro Ruiz (pedroruiz@icac.es) a Ángel, A. Jurídico: "LA SENTENCIA QUE VA A SALIR PROXIMAMENTE REFERENTA A ISABEL MARÍA CABO SERA: EL CONDENADO ABONARÁ A ISABEL MARIA CON 600 EUROS EN REPARACION DEL DAÑO CAUSADO. ES CONDENADO A 1 AÑO Y 6 MESAS DE PRISION ISABEL TIENE UNA ORDEN DE PROTECCION DE 2 AÑOS EN LA CUAL NO SE PODRA ACERCAR A ELLA A 100 METROS Y NO DEBE COMUNICARSE CON ELLA POR NINGUN MEDIO O PROCEDIMIENTO. ADEMAS ES CONDENADO EN COSTAS."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2023-10-26','Ana: Correo de Anabel Galván, TS SSASB - Vegas Altas I (ssb025vegasaltas@madrigalejo.es): "tal y como quedamos, adjunto el presupuesto de albañilería necesario para solucionar los problemas de accesibilidad de la casa de Josefa. Por favor, intentar dar el permiso lo antes posible, pues en este tiempo los resbalones y caídas suelen ser más frecuentes." ·············· Se lo reenvío a Alberto, Jefe Secc. Ecca. indicando que la obra es necesaria y que hay fotos en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2023-10-26','Ana: Llamo de Raquel, TS del SSASB de Guadalupe (605 429 865) varias veces a lo largo de la mañana, para confirmar que se autoriza a Juan el extra solicitado, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-10-26','Ana: Llamada de Manuel, Fontanero de Fissa, el que han avisado del seguro (682 566 242 // Fissa - Oficina: 927 104 125), acudirá hoy mismo al domicilio de Carlos, le facilito el número de Carlos para que quede con él. ······································· Llamada de Carlos, ya le han arreglado el grifo de la lavadora y las cisternas. ·················· María, Secc. Ecca., avisa a Pedro, Técnico de la lavadora, para que vaya a arreglarla una vez arreglado el grifo. ··························· Llamo a Fissa (927 104 125): Enviarán la factura con el número de cuenta al ctutelar@','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-10-26','Ana: Pregunto a Estrella Durán, TS UME-CSS (estrella.duranc@salud-juntaex.es) por la estancia de Conchi en el CRR y si finalmente le dieron el alta. ································ Respuesta de Estrella: "Conchi se fue de alta al CRR el día 26 del mes pasado, disculpa que no te comunicara...., pero siento decirte que ingresó ayer de nuevo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='VELASCO'and apellido2='CAPERUZA'),'2023-10-26','TERESA Se archiva Resolución de Traslado de Fernando Velasco Caperuza por orden judicial. El señor se encuentra en RM MUNICIPAL DE MONESTERIO Teléfonos de contacto : 685406278 Yolanda (TS AYTO) 604399978 M.ª Ángeles (Gerente del Centro)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2023-10-26','Ana: llamada de Estrella, TS UME-CSS (24146): Alfonso no quiere estar allí en el CSS, dice que como siga mucho tiempo allí "se ahorca". Él no quiere residir en Extremadura, quiere irse a vivir a Madrid. Las opciones de recursos residenciales en Extr. que le han dado (Piso CRPS, por ejemplo) las rechaza. *NO RECONOCE/ACEPTA la ENFERMEDAD. ······ Plantean la posibilidad de que se fuera a vivir a algún RR de Madrid. Le digo que desde aquí no tenemos esa opción, como no fuera a una entidad privada que no podría permitirse. Y, como saben, el proceso tendría que ser al revés. Una vez residiera (empadronado) en Madrid tendrían que solicitar los recursos por la vías correspondientes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-10-26','miguel, hablo con Inés del Ayto de Piedras Albas 927390252: Pregunto por la resolución de este expediente, y le comento que él tiene pocos ahorros y sólo cobra una pensión de jubilación de poco importe. Reside en la Residencia de San Pedro de Alcantara de Cáceres. La posibilidad de ejecución subsidiaria es complicada por la capacidad económica del ayto. El origen de este expte es por la denuncia de una vecina. Inés me va a enviar la resolución del expte, y comentará con el Alcalde la situación a solucionar. Nuestro curatelado tiene 76 años y me comenta Inés, que cree que tiene una sobrina (que podría ser en un futuro posible heredera) ************************************************************ envío email a parte económica (Alberto), parte social (Maite y Ana), y a Angel: Buenos días, he hablado con el ayto de Piedras Albas en relación al expte de ruina del curatelado Martin Quiros Berrocal para preguntar por el estado del procedimiento y para indicarles que no podemos hacer frente ni a la demolición ni al arreglo. El importe que en su día envió el técnico ascendía a unos 38.000€. Según me comentó la parte económica, tiene ahorrados menos de 6.000€. Tiene una pensión por jubilación de unos 761€. Reside en la Residencia para mayores San Pedro de Alcantara de Cáceres. Tiene 76 años, y me comentan desde el ayto que tiene una sobrina como posible heredera algún día. Me comenta que este expte se debió a una denuncia de una vecina colindante, que no lograba contactar con nosotros, según me indican. Van a hablarlo en el ayto, pero en principio es complicada la ejecución subsidiaria por parte de ellos (con o sin procedimiento sancionador a nuestro curatelado por no solucionar esto voluntariamente), debido a que el presupuesto del ayto es pequeño y tienen más viviendas en mal estado, y si todos solicitan la ejecución subsidiaria no podrían afrontarlo. Esperemos que no reclamen vía judicial y un juzgado estime responsabilidad subsidiaria de la junta de Extremadura, lo cual no sería justo porque no disponemos de partida presupuestaria. Si se os ocurre alguna solución, todas las ideas son bienvenidas. *************************************************** Contesto al ayto, confirmando recibir el email con la resolución: Recibido Inés. Gracias. Quedamos a la espera de posibles soluciones del ayuntamiento ante la falta de capacidad económica del curatelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2023-10-26','Buenos días, ya se ha hecho el cambio de la pensión a la cuenta que indicaba la seguridad social __8410.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-10-26','miguel, conforme indicaciones del abogado Enrique Perianes envío email a la prima de Damian, Alicia Cueto >aliciaasimas@gmail.com>, para que solicite tasación del inmueble: Buenos días Alicia, necesitamos que contratar los servicios de una empresa tasadora de Málaga para tasar ya la vivienda de Damian. Entrega esta documentación adjunta al tasador. Y remítenos importe de sus honorarios. Entendemos que el importe de la tasación no debería superar los 400€. Los datos identificativos de la finca de Málaga son secc15, nº 6497, Tomo 1864; Libro 74; Folio 162, Alta 6. Referencia Catastral 9931101UF6693S0157YI. Cualquier duda dímelo. La vivienda se adjudicará a aquel comprador que superando la cifra que indique el tasador elija Damian.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-10-26','Ana: Nos envían desde la residencia (a.corral@grupociudadjardin.com) DECLARACIÓN JURADA de acompañamiento autorizado previamente por mí, era necesario. ·············· Envío correo a las compañeras de S. Ecca. al ctutelar@: "os paso DECLARACIÓN JURADA QUE HABRÁ QUE ABONAR cuando por fin tengamos acceso a las cuentas. Me dice Inés que NO TENEMOS TODAVÍA LA FIRMEZA, pues al parecer la propia Joaquina RECURRIÓ LA SENTENCIA… no sé cómo vamos a poder hacer ni con el pago de la residencia, en la que ya ingresó involuntariamente, ni con este otro pago…. Antes sólo era Curatela para la SALUD, por lo que no se controlaban sus cuentas. Ahora es CURATELA REPRESENTATIVA y hay que gestionar también su patrimonio. Guardad este documento y anotaros que hay que abonarlo en cuanto se pueda. Pongo en copia a Alberto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-10-26','Ana: Correo de Carolina, Directora del CRR-Plas (direccion.crrplasencia@grupo5.net): "Estabamos gestionando una situación de cirisis respecto a Ceferino que ocurrió ayer. Ceferino ayer agredió física y verbalmente a un trabajador del turno de tarde. Hemos procedido a una expulsión temporal de 5 días y solicitado la definitiva, o como alternativa el cambio de recurso. El trabajador ha sido dado de baja y va a interponer una denuncia contra Ceferino El pago del hotel (La Despensa, pensión completa) obviamente correrá de sus extras, por lo que seguimos restando dinero... Os adjunto el informe de lo ocurrido que he enviado al SEPAD, cuando termine de solucionar la situación, hablamos tranquilamente si os parece" ············································· Respondo: "acabo de leerlo e informar a Maite. Gracias por informar. Lo cierto es que nos sorprende esta reacción, al menos desde que nosotras trabajamos aquí, nunca había mostrado ni hetero ni autoagresividad, o no habíamos tenido constancia de ello. Agradeceríamos, si fuera posible, nos enviaseis la denuncia, para tenerlo en el expediente y si llegara el caso, enviarlo al Juzgado. Entendemos vuestras propuesta de expulsión definitiva del recurso. Quedamos a la espera de respuesta de la Unidad de Programas Asistenciales del SEPAD."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2023-10-27','Ana: Llamo a Cristina, TS - CSS (24205): Confirma que Jairo tiene el Alta Hospitalaria por parte del Dr. Herrero desde hace tiempo por encontrase estable a nivel psicopatológico, pero que NO tiene capacidad para vivir de forma independiente. ········· De nuevo, un año más, manifestó querer matricularse en la Escueal de Idioamas y en la Universidad, pero cuando ya había pasado el plazo. ·············· La petición de irse a vivir sólo la mantuvo varias semanas, cuando le dijeron que entonces podía buscar piso y números para llamar, no llegó a hacerlo y dejó de insistir. *Cristina, por indicación del Dr. Herrero no le lleva la contraria para que no se descompense, pues además saben que a la hora de materializar sus peticiones, no las lleva a cabo. ·············· Ahora de lo que está pendiente es de la ropa de temporada que está comprando poco a poco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2023-10-27','Ana: Ante la petición de Puerto, hija de Mª Jesús (puertopaniagua@hotmail.com / 661 273 204), de comprarle ropa a su madre (mediante llamada a Estrella, CTAEx, y correo-e al ctutelar@), llamo a Cristina, TS CSS-Plas. y respondo a su correo: "Acabo de hablar con Cristina, Trabajadora Social del Centro Sociosanitario. A ella aún no le han pasado nota las Lenceras del centro indicando la ropa y/o calzado que necesita su madre. Consultará a ellas y a tu madre al respecto, y en función de esto se pondrá en contacto con usted para comunicarle qué necesita y/o desea, exactamente. Con estas indicaciones usted deberá aportar presupuesto de gastos del establecimiento en el que quiera adquirirlo, y una vez se haya aprobado dicho gasto, se procederá, o bien a abonar las facturas mediante transferencia bancaria desde la CTAEx o bien a facilitarle la cuantía necesaria en metálico desde el centro para que lo pueda abonar usted. Las facturas serán imprescindibles para justificar el gasto. Como sabe desde la CTAEx se realizan declaraciones anuales al Juzgado. Pongo en copia a Cristina, Trabajadora Social. Ante cualquier otra cuestión, no dude en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-10-27','Ana: Correo-respuesta de Ángel, A. Jurídico, a la consulta de Alberto, Jefe S. Ecca: "La transferencia permanente de 300 euros al mes, se corresponde con la pensión de alimentos decretada en la Sentencia de divorcio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2023-10-27','Ana: Subo al portafirmas el CI para la administración de las vacunas de la GRIPE y el recordatorio de COVID.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2023-10-27','-Amalia : llama la madre , va a enviar solicitud de autorización judicial para comprarse un piso con ascensor donde vivir con sus padres. Estos viven en un 4º sin ascensor y ya tienen mas de 80 años. Lo compraría para él , daría una entrada y financiaria el resto con su pensión. Se lo reenviaré cuando llegue a los juridicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-10-27','Ana: Llamada de Felisi (614 361 144) llama más que nada para desahogarse. Dice tanto su hijo como su expareja "son unos viciosos" y "han hecho cosas muy gordas que no está bien". Dice que Aitor a veces le "ayuda" en casa pero otras veces no hace nada y le da mucho trabajo. Además a veces le habla fatal y le da muchas voces. Le gustaría que su hijo estuviera en un centro y fuera a casa los fines de semana y las fiestas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-10-27','Ana: María, Secc. Ecca, llama a J. Manuel y le comunica que se acepta el último presupuesto de TV de 43 pulgadas de Electrocash que envió. ·········· *Le ponen como condición no volver a pedir nada más hasta febrero de 2024.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2023-10-27','-AMALIA : se le han autorizado 290€ para ropa , su hermana va ir a llevarsela y me enviará facturas. No se aceptarán que haga él la transferencia desde el centro , esta será la última vez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ANGEL'and edp.apellido1='IGLESIAS'and apellido2='RODRIGUEZ'),'2023-10-27','Ana: Envío correo a Ana María Alonso, Res. Mayores de Galisteo (tosalana@hotmail.com):"En relación a PEDRO ÁNGEL IGLESIAS RODRÍGUEZ, ya me han traído del banco el Alta de Terceros, documento que me faltaba para poder remitir por registro la ACEPTACIÓN DE LA PRESTACIÓN VINCULADA, pero acabo de darme cuenta de que en nuestro expediente no tenemos la siguiente documentación que también se requiere aportar: - Copia del contrato del servicio con el centro residencial acreditado. El contrato irá a nombre y firmado por el/ la solicitante. En caso de tener que percibir atrasos, copia compulsada de las facturas de los meses por los que solicitan los atrasos y justificante bancario del pago de estas. - Facturas de la residencia y justificantes de pago del banco o caja si la persona tiene derecho a cobrar atrasos. ¿Serías tan amable de enviármelo para poder registrarlo todo junto?" ······································ A última hora, Ana María me envía imágenes de las facturas y del contrato nuevo. No obstante, en esta imagen no se puede incluir los datos de la D. Gerente el el contrato. Le llamaré el lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-10-27','miguel, enviamos por lexnet al juzgado la solicitud de internamiento involuntario. Envío justificante de lexnet a Amalia y magdalena sanchez morcillo >nenasan65@hotmail.com>, trabajadora social del ayto de Oliva de Merida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2023-10-27','TERESA • SE ACUERDA ASUMIR GASTO 1.200 € X PAGO INTERNA (SE JUSTIFICARÁ CON INFORME SOCIAL QUE INCLUYA RECOMENDACIÓN PSIQUIATRA). • SE ACUERDA 100 €/SEMANA EN CONCEPTO ALIMENTACIÓN/PTOS LIMPIEZA/FARMACIA...ETC. • SE ACUERDA MANTENERA LA DEPENDENCIA (SAD) A PESAR DEL COPAGO YA QUE ASÍ SE PRESTA UN ALIVIO A LA "INTERNA". • SE REVISARÁ ESTA SITUACIÓN EN 6 MESES, MÁXIMO UN AÑO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-10-27','Amalia .Me ha llamado Elena la ts del ssasb de Zafra (924554601). Va a hacer visita a domicilio para valorar qué limpieza integral necesita la casa , si es integral o con dos auxiliares sería necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-10-27','Ana: Envío correo al ctutelar@: "He recibido llamada de Carlos Glez. Leo, muy nervioso y preocupado porque ha recibido una carta de Naturgi diciendo que le van a cortar la luz por recibos impagados. Tenéis un correo suyo en el ctutler@ con imágenes de la carta. ¿Podéis por favor mirar qué ha pasado e intentar solucionarlo lo antes posible, por favor??" ················································· Envío correo a Guadalupe, TS SAD - IMAS CC: "Antes de contestarte al asunto de tu correo, comunicarte un par de cosillas: - Carlos me ha avisado de que tiene cita en Traumatología el martes 31 a las 9:30. Ya habló con el médico y le solicitaron la ambulancia. - Los arreglos pendientes en el domicilio (cisternas, grifo de lavadora y lavadora) ya los han realizado. En respuesta a tu correo: - El menaje de cocina que necesita, ¿sería posible que la Auxiliar de SAD, dentro de su horario de atención a Carlos, le acompañe a pedir presupuesto? Al igual que en el caso del frigorífico del otro usuario, necesitamos presupuesto para que se dé la autorización de compra y se abone mediante transferencia desde la Sección Económica de la CTAEx. - En cuanto a los productos de limpieza, pediré, al igual que en otras ocasiones, que se autorice la retirada de 20€ a tal fin, para el día que me indiquéis."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-10-27','MIGUEL : Buenos días, adjunto justificante de remisión de solicitud al juzgado del internamiento involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-10-27','Ana: Tras recibir correo-respuesta de Yessica, TS del Comedor Soc. - Cáritas Plas. (ydearriba@caritasplasencia.org), envío correo a la S. Ecca: "Ana: Envío correo-respuesta a Yessica, TS del Comedor Soc. - Cáritas Plas. (ydearriba@caritasplasencia.org): "Os reenvío correo de la TS del Comedor Social de Cáritas – Plasencia, con solicitud de compra de nuevo móvil para ÁNGEL FÉLIX MAILLO SANTIBAÑEZ, por haber quedado el suyo inutilizado. Leed porfa el hilo. Puesto que no adjunta presupuesto específico, ¿podríais llamar directamente y que os den precio de uno con similares características, sencillito, y que os manden el presupuesto o la factura proforma directamente? Por mi parte si es viable, ok."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-10-27','Ana: Tras llamar a Gema, Res. Grupo Asoma, envío correo respuesta a Alberto e Icíar: "Los 175€ corresponden a la Prestación Económica Vinculada al Servicio de Residencia que está percibiendo por la Ley de Dependencia. Adjunto la resolución. Así que sí, va a ser un ingreso permanente. Por otra parte, he hablado con Gema, Directora de la Residencia y me aclara las siguientes cuestiones: - Los recibos de telefonía se pueden dar de baja ABSOLUTAMENTE TODOS, él, por su deterioro cognitivo galopante, ya ni siquiera puede hablar y no usa móviles, menos un fijo. - El recibo de HELVETIA, está casi segura que es el SEGURO DE DECESOS, para que se lo digáis a Estrella. - Y el RECIBO CRUZ ROJA Localización: 25 €/mes, se corresponde al servicio de localización con reloj, para cuando podía salir a pasear, que a veces se desorientaba. Ya tampoco puede salir solo. Está pendientes de darlo de baja ella, pero no lo ha hecho aún porque la TS del pueblo, que es a través de la que se gestiona, está de baja. En cuanto se incorpore ésta lo comunicará."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-10-27','-Amalia ; pongo a Julio para registrar activación PIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2023-10-27','Ana: Envío a Raquel Arias, Psicóloga Casa Familiar Virgen de la Montaña (psicologiacf-caceres@cruzblanca.org) el PAI firmado por la D. Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2023-10-27','-Amalia : tengo las 2 solicitudes de cambio de cuenta firmadas a la espera del Modelo Alta 3º para registrar al INSS a través de la OAC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-10-30','Ana: Nuevo correo de Azucena, cuñada de Juanjo: "Hola tadabia no se sabe nada de lo de juanjose por estos ya no se aguanta más todo el día pidiendo dinero no se donde echa el sullo estos es inportptable en casa no hace nada en casa y siempre que le decimos algo da para reñir con el estos no se aguanta necesita ya que aga algo ya yo aguanto más lo siento"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2023-10-30','Ana: nuevo correo de Puerto, hija, al ctutelar@: "Buenas tardes: la ropa que necesita mi madre se la he comprado ya, a su gusto y según sus necesidades, cuando me emitan una factura que falta se la enviaré a la CTAEX para que proceda a su abono si es posible ya... y sino pues no pasa nada para la próxima vez ya se realizará con los presupuestos que informa. Elegiremos las prendas mi madre y yo, y nos coordinaremos con la Trabajadora Social del sociosanitario. Por otro lado, los gastos de peluquería y podología quién los cubre? se le podría prestar en el centro de forma regular? lo digo porque se lo estoy proporcionando yo (desde el 2020)... o también hay que solicitar presupuesto y luego aportar factura? " ···················································· Mi respuesta, con copia a Cristina, TS (cristina.hernandezca@salud-juntaex.es): "En la sección económica se valorará si se abonan o nos las facturas que remitas, pues ese gasto no se había autorizado previamente. En cuanto a los servicios de podología y peluquería, como ya te indicó Cristina, TS del Centro Sociosanitario, se le incluirá en el listado de personas que requieren estos servicios para que lo atiendan regularmente, en función de sus necesidades (como imagino que se hacía con anterioridad a 2020…). Los gastos de estos servicios los cubre ella. Si fueran otros servicios, ajenos a los que gestiona el propio centro, sí que habría que aportar presupuesto previo y factura a posteriori para justificar el gasto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-10-30','Ana: Correo de Icíar, S. Ecca: "Los 300 €, según el abogado, es lo que pasa mensualmente a su hijo, hasta marzo lo pasaba también a la exmujer pero ya no."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2023-10-30','Ana: Envío correo a Tensi, TS SSASB (ssbtensi@riberosdeltajo.es): "Adjunto el CONSENTIMIENTO INFORMADO para la administración de las vacunas de la GRIPE y Recuerdo de COVID, firmado digitalmente por la Vicepresidenta de la CTAEx", aprovecho también para preguntarle cómo sigue.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ANGEL'and edp.apellido1='IGLESIAS'and apellido2='RODRIGUEZ'),'2023-10-30','Ana: Llamo a Ana Mª Alonso, Res. de Galisteo (927 452 400): Volverá a enviarme copia del contrato con los datos de la D. Gerente. ·································· Una vez recibido, subo al portafirmas el Contrato de la Residencia Ntra. Sra. de la Asunción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-10-30','Ana: Llamo a Raquel - Res. Almaraz (927 544 085): consultará en el Ayto. si podemos hacer transferencia para los gastos de bolsillo de Flora, pues en Almaraz sólo hay oficina de Santander, donde no se le va a abrir cuenta a Flora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-10-30','Ana: Llamada de José Manuel (681 368 017): mañana a las 10 h tiene el JUICIO por agresión a otro hombre en barrio. ···· El juicio es en el Jdo. de 1ª instancia e instrucción Nº6 - Procedimiento "Delitos Leves 12/2023. Sala de vistas nº 3. ····················· Inés llama al Jdo. NO HACE FALTA QUE ACUDA NADIE DESDE LA CTAEx. ··· Se lo comunico a José Manuel. ···················· José Manuel dice que necesita productos de limpieza. Consultaré a la Guadalupe, TS IMAS. ······················· Recibo el INFORME ESM, pero en éste no alude a los puntos solicitados en el oficio de solicitud del mismo para la revisión de la medida judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-10-30','Ana: Llamada de Ana Benavente, TS ESM-Plas.: Carmen sigue sin la Tarjeta de Transporte, no saben qué ha pasado. La van a solicitar de nuevo por "PERDIDA". ·········· Subo la solicitud al portafirmas digital. ···································· Por otra parte, han vuelto a ingresar a su madre en la Res. de Mayores, está delicada. ··· Su hijo se ha quedado solo en casa y está preocupado por si no tiene dinero. ······ María Secc. Ecca. mirará a qué cuenta se están haciendo las transferencias mensuales en concepto de manutención del hijo (si a la de Benita, madre, o del hijo). ··························· María, S. Ecca. me informa que la transferencia de 150€/mes se le hace a Benita. ·········································································· Envío correo a Ana Benavente (anamaria.benavente@salud-juntaex.es): "- El documento está subido al portafirmas digital, pero aún no me lo han devuelto firmado. En cuanto lo tenga te lo hago llegar. - La transferencia que te comenté de 300€, fue una puntual de principios de este verano. La que se hace periódica en concepto de manutención por el hijo es de 150€/mes, pero se hace a la cuenta de Benita, madre de Carmen. Necesitaríamos la cuenta del hijo y los datos del mismo, para que pudieran hacerle a él directamente esta transferencia. No obstante, sería bueno que él, además de recibir las ayudas contingencia o lo que le pueda corresponder, buscara algún empleo. Que yo sepa las formación profesional que comenzó la abandonó."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-10-30','Ana: Tras hablar con Alberto y Lourdes, S. Ecca., pues le han vuelto a cobrar 600€ en Movistar, llamamos a la tienda de Movistar, pero no nos cogen el teléfono. Llamo a Odair, su amigo (622 19 73 32), que habla con Ventura. Nos vuelve a llamar confirmando que esta tarde irán a Yoigo para cambiarse de compañía. ··· Cuando tenga línea en Yoigo nos llamarán para confirmar y que devolvamos todos los recibos de Movistar. ································································································································· En cuanto al frigorífico, no hemos recibido la factura con nº de cuenta del Carrefour para hacer la transferencia. *Estrella, S. Ecca, llamará mañana de nuevo al Carrefour, pues hoy no le han podido pasar con el departamento correspondiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-10-31','Ana: Envío a Ana Benavente, TS ESM Plas (anamaria.benavente@salud-juntaex.es): "Aquí tienes la solicitud de sustitución de tarjeta de transporte ordinaria por pérdida firmada digitalmente por la Vicepresidenta de la CTAEx." ································································································································ Llamada de Ana Benavente, TS ESM-Plas. (74955): Ha hablado con Estrella, TS del SSASB de la localidad en que reside el hijo de Carmen. *Consideran que no se le debe transferir directamente a él dinero, pues no están seguras de que lo vaya a gestionar bien. De momento se le van a tramitar ciertas ayudas desde el SSASB. ····· Tiene reconocido grado de discapacidad, pero van a valorar si presenta necesidades de apoyo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ANGEL'and edp.apellido1='IGLESIAS'and apellido2='RODRIGUEZ'),'2023-10-31','Ana: Envío correo a Ana María Alonso, Res. Mayores de Galisteo (tosalana@hotmail.com): "Adjunto el contrato de la Residencia firmado digitalmente por la Vicepresidenta y, Presidenta por delegación, de la CTAEx." ········································································ Envío a Julio, Aux. Adtvo. CTAEx: "Adjunto las siguiente documentación relativa a PEDRO ÁNGEL IGLESIAS RODRÍGUEZ, - Aceptación PIA de PRESTACIÓN ECONÓMICA VINCULADA AL SERVICIO DE ATENCIÓN RESIDENCIAL firmado por la Vicepresidenta de la CTAEx - ANEXO Informativo firmado - ALTA DE TERCEROS - Contrato Residencia - Facturas mensuales residencia - DNI de la Vicepresidenta de la CTAEx - Decreto de Nombramiento de Directora Gerente del SEPAD - Resolución de Delegación de funciones de Presidencia - CTAEx para remitir por SIREX a: S.E.P.A.D Sección de Dependencia V"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-10-31','En el día de hoy a las 21:30h se realiza traslado de la paciente tutelada por su Comisión Dña. Emilia Morales Botello con DNI nº: 80066765Q al Servicio de Urgencias del Hospital de Mérida. Atentamente, Julia Marina Barrero, médico del CSS de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2023-10-31','Buenos días, acabo de hacerle el seguro de deceso a Joaquin con Santa Lucía. Se lo he domiciliado en Ibercaja en la cuenta que acaba en 6300. Cuando tenga la póliza os la remito. La otra póliza que está con su hermano tiene pendiente de pagar dos recibos. Así con la póliza nueva, lo tenemos controlado. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2023-10-31','Solito a la OAC : Para registrar al INSS de Badajoz : se adjuntan solicitudes , sentencia y modelo de Alta a Terceros ,para el cambio de Nº de cuenta de las pensiones de JOAQUIN MONTAÑO MONTAÑO del que la Comisón Tutelar ha sido nombrada como Defensa Judicial . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='FLORES'and apellido2='MERIN'),'2023-10-31','CIERRE EXPTE. DEFENSA JUDICAL Si bien el Jzdo. n.º 1 de Villafranca de los Barros dejó sin E/ la tutela que D. José Prado Rodríguez, Auto n.º 229/21, de 26 de octubre, venía ejerciendo sobre Dña. Pilar, nombrando, así mismo, defensor judicial, Decreto de 29 de octubre de 2021, a la CTAEx, no es menos cierto que desde entonces el procedimiento quedó en el limbo judicial.***************** Se abre nuevo expte. de defensa judicial, una vez el Jzdo. ha decidido retomar el asunto tras demanda presentada por fiscalía.************************El presente, se cierra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-10-31','Ana: Llamada de J. Manuel. Ya está en el Jdo. ············· En cuanto a la demanda de dinero para productos de limpieza, envío correo a Lourdes Pérez Ortega - TS SAD IMAS-CC(lourdes.perez@ayto-caceres.es // 927 21 23 35 Ext: 4425): "...¿Sería posible, que cuando la Auxiliar de SAD, detecte que ya es necesario comprar productos de limpieza nos lo hagáis saber? José Manuel es muy demandante, y ya ha pedido varias veces dinero para productos de limpieza aún sin ser necesario. Le dije que esta decisión estará supeditada a que la Auxiliar corrobore esta necesidad. Ya me dices cuando puedas." ······························································································································································································· Tras recibir nueva llamada de José Manuel escribo a los A. Jurídicos, con copia a Inés y Maite, Jefa CTAEx: "Me ha llamado JOSÉ MANUEL ROMERO MEDIAVILLA, doce que ha ido al juicio que tenía esta mañana (Jdo. 1ª Instancia nº 6 de Cáceres. Nº Procedimiento: Delitos Leves 12/2023). Ayer llamó Inés y le dijeron que no hacía falta que fuerais. Pues bien, hoy al explicar él que está tutelado y entregarles la documentación al respecto, han suspendido el juicio y le han dicho que tiene que ir la CTAEx sí o sí. ¿Podríais llamar o hacer lo que corresponda, porfa?" ······························································································································································································· Tras recibir correo de Irene Pérez Conejo - Educadora Soc. - Fundación Sorapán de Rieros (iperez.fsr@gmail.com / 615 774 873), la llamo: J.Manuel ha comenzado a asistir como usuario a su centro de inclusión social. Trabajan con Salud Mental. Realizan actividades de Ocio Saludable, intentan que escojan cosas que les gusten. Hoy ha asistido al taller de "Expresarte", está trabajando con cuero. Con todo lo que hagan realizarán una exposición en diciembre. Todas las actividades tienen un componente lúdico. Firmó un compromiso de asistencia y participación con unas normas básicas que tiene que cumplir. *Además tienen como REQUISITOS: No consumo de alcohol ni otras drogas. Durante las actividades tampoco pueden fumar. ··············· Le derivó el Dr. Molina, Psiquiatra de ESM, le ha enviado informe y puesto en antecedentes. ··································· Le explico que la tarjeta de transporte que demanda comprar tiene que comprarla con su asignación mensual. ········· Me informa que harán también una comida de navidad, pero los usuarios abonarán una cantidad simbólica (3-4 €). Acordamos que también tendrá que abonarlo de su asignación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2023-10-31','Ana: Llamada de Ana Benavente, TS ESM-Plas: Dice que Guadalupe quiere pedir traslado a la Residencia Pública de Jaraíz de la Vera, lleva mucho tiempo demandándoselo a al Psiquiatra. ···· Me enviará la solicitud de Revisión del PIA - Tiene Grado II.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2023-10-31','Hola, te estaba intentando llamar. Emi no está ingresada. La llevamos anoche para valoración tras un intento autolítico, y volvió en unas horas. Lleva dos o tres días muy agitada. De hecho, ha vuelto a romper las gafas... Realmente, es un caso muy grave. No acaba de estabilizarse mínimamente. Ahora mismo está en su unidad, controlada','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2023-10-31','miguel, llega físicamente Resolución archivando las actuaciones del expte sancionador LSA-5207P','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2023-10-30','miguel, llega desestimación del jzdo nº1 de Villafranca de los Barros a la comunicación para unir al procedimiento X59 Revisión de medidas Aunque ya se lo comuniqué por email a Escalona el 3-10-23 el ingreso en la UHB, le remito informe de ingreso y denegación del jzdo nº1 de Villafranca a la comunicación de dicho ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-10-31','Ana: Correo de Belén, Sol Catering (belen@solcatering.es): "Le comento un problemilla que hemos tenido con el menú de Ventura Gómez García (usuario del servicio de comida a domicilio). Ayer nos llamó una señora diciendo que era su asistente social y que anulaba el servicio de catering porque ella le iba hacer la comida. Y nosotros nos fiamos de sus palabras y no se le realizó la comida que se entregaba en el día de hoy para toda la semana. Y esta mañana nos ha llamado el propio Ventura diciendo que esa señora que llamó ayer no era nadie para anularlo que él se iba de viaje pero llegaba el domingo al mediodía y no iba a tener comida para entonces. No sabemos si tenéis conocimiento de este tema" ·············· Llamo a Belén, entiendo que la llamada la hizo Ana, Aux. de SAD de Ventura (L-X-V de 8:00 - 10:00), con la mejor intención, pues Ventura finalmente se va a Benalmádena con la ONCE, desde mañana día 1 hasta el Domingo 5. ·················· Llamo a Ventura: para hoy dice que tiene comida. Acordamos que el domingo encargará algo de comer en algún sitio cuando llegue del viaje. Y propondré a Guadalupe, TS IMAS, que la Aux. SAD, le prepare algo de comer para el lunes y martes. *A partir del martes volverá a recibir el cáterin. ··········· Llamo a Guadalupe (927 21 23 35, Ext. 4422) y se lo propongo. No cree que haya problemas. Hablará con la Auxiliar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-10-31','Ana: Tras hablar con Ana, Res. (677116846 / alamoseras@gmail.com): "Tal y como hemos acordado mediante conversación telefónica, te envío el modelo de declaración jurada para que nos lo hagáis llegar cumplimentado tras el acompañamiento que realizarán el próximo viernes día 3 a la Consulta de Enfermería del Equipo de Salud Mental. Recordad incluir el número de cuenta bancaria para que desde la Sección Económica de la CTAEx puedan abonarle el servicio mediante transferencia a la persona que lo haga." ···· El precio del acompañamiento rondará los 50€, no me sabe decir exactamente. ················································· La CITA EN PSIQUIATRÍA será el día 15 de diciembre. *Si vuelve a funcionar el Progr-Convenio con Futuex, pediré a Toni que le acompañen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2023-11-02','TEREA CONRE RESPECTO A LA CAPACIDAD DE CONDUCIR Es una curatela asistencial, con una discapacidad del 65%, esquizofrénico, trastorno ansioso evitativo, trastorno psicótico con alteraciones conductuales. La sentencia no se pronuncia sobre si puede o no conducir. Como en otros casos, en los medicamentos que tome, algo dirá al respecto. Estamos como siempre, si toma la medicación, está ok. Si recoge la sentencia que desde hacía tiempo, presentaba ausencia de tratamiento y control médico, que aconsejaba acudiera a su médico de cabecera con el fin de comenzar o gestionar su asistencia. No sé si va al médico o no. Y para el caso que vaya, si dice algo al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2023-11-02','Ana: Llamo a Montse, TS Mancomunidad de Sierra de Gata (927 14 34 11): No obtengo respuesta. ···························· Llamo a Perales del Puerto (927 514 164), pero me dicen que hoy no trabaja. Que llame mañana a partir de las 10h. ··························································································································································································· Envío a Registro (oac.merida.san@juntaex.es): "Adjunto: - Oficio-solicitud de Informe Social para revisión de medidas de apoyo, relativo a SANDRA SANDÍN HERNÁNDEZ, cuyo cargo de Curador ostenta la CTAEx - Testimonio de la Aceptación el Cargo de Curador Para remitir a la MANCOMUNIDAD SIERRA DE GATA, a la Atención de Trabajadora Social, Montserrat Alcón Alcón, a la siguiente dirección: C/ Mayor, 3, 1º CP: 10850 – Hoyos (CÁCERES)" ···································································································································································································· En la sentencia actual nombra a la CTAEx para "administrar sus bienes o gestión de sus intereses económicos, necesitando supervisión para la toma de decisiones en cuanto a la realización de actividades complejas e inusuales".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2023-10-26','Ana: En relación a la revisión de las Medidas Judiciales, llamo a Montse, TS Mancomunidad de Sierra de Gata (927 14 34 11): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2023-10-31','TEREA INGREA DAVID ESTEVEZ POR TRASLADO EN AL RESIDENCIA DOMU VI DE BADAJOZ atcliente.cbadajoz@domusvi.es At. Cliente Ciudad de Badajoz Atención al Cliente DomusVi Ciudad de Badajoz Tel. +34 924 286 530 C/ Castillo de Puebla de Alcocer, 16 06006 Badajoz','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2023-10-31','TERESA Buenos días Teresa, quería comentarte que el sábado Sebastián se fue a dar un paseo como de costumbre y lo trajo la guardia civil porque se lo encontraron andando por la autovía. Dice que fue a ver como estaba el campo y siguió andando dirección Aceuchal por la carretera pero decidió darse la vuelta y se metió en la autovía. Manifiesta que lo tiene que ver el psiquiatra que no está bien y como se le meta algo en la cabeza no va a parar. Estamos hablando con psiquiatría para que le revise.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-11-02','TERESA Te escribo para informarte que hoy van a realizar una salida al domicilio familiar de Remedios Chaves a Jerez de los Caballeros como parte de la intervención que sus psicólogos están haciendo con ella. Serán ellos Pedro y Eduardo, quienes la acompañen. Reme en las últimas semanas ha tenido, entre un ingreso hospitalario, varios intentos de ingesta, alguno consumado como dos pilas de mando a distancia estando en el hospital a la espera de darle el alta, una chincheta en el centro,…Por todo esto, nos gustaría hablar contigo y explicarte por donde va a ir la línea de trabajo a partir de estos hechos , que nos hacen replantear nuevas hipótesis y líneas de trabajo para minimizar el riesgo tan alto que tiene de sufrir “daño”. Que te parecería una llamada telefónica en la que estén los psicólogos de Reme y yo, el jueves por ejemplo??','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='MARQUEZ'and apellido2='CABEZA'),'2023-11-02','Amalia : Vicente se ha trasladado a la R.M. Virgen de Guadalupe en Olivenza , estaba en CRR . De su pensión , el copago de la plaza va a ser de 685,21€ . Le quedaría 97,89€ para gastos de bolsillo . Habría que hacer la autorización bancaria para que pueda sacarla del 1 al 5 de cada mes . El quiere 150€/mes Tiene bastante dinero ahorrado , el pto. mensual quedaría bien así . Seguro decesos ,gastos de farmacia , extras .. y demás se irán cubriendo de los ahorros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-11-02','-Amalia . Está ingresada en hospital , se va a contratar acompñamiento hospitalario. Gracia , considera que es mejor que vaya alguna auxiliara de la R. M que la conoce mejor que empresa externa . Va a poner unas horas al día para cubrir merienda y cena unos 50€ al día . He pedido facturas semanales para pagarlas . Está en H . Perpetuo Socorro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-11-02','Amalia : hablo con Ana REFOLIO para pedirle el pto. del cuarto de Juana : 924245276','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-11-02','Ana: Envío correo a Carolina, Directora del CRR (direccion.crrplasencia@grupo5.net): "Esta consulta no es urgente, pero ya me ha llamado varias veces al respecto Maribel, hermana de Conchi Fdez. Muñoz. Sólo necesitaríamos saber si Conchi, en la última estancia que ha pasado en vuestro recurso, que por cierto, fue una pena que no saliera bien, verbalizó en algún momento querer transferir dinero a sus hermanas para ayudarles a costear los desplazamientos cada vez que acuden a visitarle a Plasencia. Ya me dices cuando puedas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2023-11-02','miguel, el abogado Pablo Garrote me remite 4 facturas de la notaria relacionadas con la declaración de herederos. Le pido que me las aclare y me remita qué se ha firmado. Al tiempo solicito por internet certificado de nacimeinto del tutelado y hablo con registro civil de Calera de Leon que me dan el email secretaria@caleradeleon.es, a la que remito email para que me remita el certificado de nacimiento original a la oficina','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-11-02','miguel, tras ver la sentencia con Angel, entendemos que no es necesario autorización judicial si llega el momento de necesidad de vender. Me llama la vecina Mª Jesus(colindante) 626200435, le comento que nuestro curatelado no tiene capacidad de más de unos 6.000€, y ella me comenta que podría conseguir un presupuesto (ella es aparejadora) pero que con ese dinero como mucho llegaría para derrumbre, pero no para retirada de los escombros. Le comento que al ayto ya le comenté que podían ejecutar subsidiariamente, o bien que teniendo en cuenta que allí no hay posibilidades de vender (según me dijo Inés del Ayto de Piedras Albas), que expropien o subasten (si previamente ejecutan subsidiariamente) Quedo a la espera de la respuesta de Mª Jesús la vecina para saber si incorporo o no al escrito de contestación del ayto que me comunicaron vía email el 26-10-23 dicho presupuesto de derrumbe y retirada de escombros, junto con el informe económico acreditativa de la capacidad económica del curatelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-11-02','Ana: Envío correo a Alberto y a María, Secc. Ecca.: "Con respecto a este asunto que teníamos pendiente, hablé con Paula, TO del CRR. Ella sí considera que las visitas que realizan las hermanas a Conchi son positivas para ella. Por otra parte consulté también en el C. Sociosanitario, tanto si la visitas se siguen realizando, como la conveniencia de las mismas y si Conchi está dispuesta a facilitar dinero a sus hermanas a tal fin. Confirmaros que la visitan con regularidad y que a Conchi le viene bien. Pero no había verbalizado el querer facilitarles una ayuda a sus hermanas a tal fin cuando se lo preguntaron. NO han querido volver a preguntárselo. Considerando que es ella la que debería de demandarlo. Pero, como ha vuelto a pasar una temporada en el CRR, tras la insistencia de la hermana, que dice que a ellas sí se lo ha verbalizado y que cuando a Conchi le haces una pregunta directa, que no se espera, se queda callada pues no sabe cómo reaccionar, he vuelto a consultar a la dirección del CRR y la respuesta es esta: “ella nunca se niega a pagar la gasolina a sus hermanas para que vengan a verla”. Dada esta última respuesta, entiendo que, ya que puede permitírselo y las visitas son beneficiosas para ella, habría que hacer las transferencias de 20€/mes, solicitando, eso sí, que desde el centro nos confirmen que siguen visitándola de forma regular. Pongo en copia a María, que es la que estaba ya pendiente de este asunto. El número de Maribel Fernández Muñoz, hermana de Conchi, para confirmarle que se le hará la transferencia y para que facilite el número de cuenta a tal fin es: 682 733 187"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-11-02','Ana: Envío correo a Belén, Sol Catering (belen@solcatering.es): "El martes, tras hablar contigo, hablé con la Trabajadora Social del Servicio de Ayuda a Domicilio del IMAS y con el propio Ventura. En principio está organizado para que la Auxiliar le ayude a adquirir y preparar y algo de alimentos cuando regrese de su viaje. De modo que no será necesario que le llevéis comida para esos dos días (Lunes y martes). *Pero sí solicitamos, por favor, que se reestablezca el servicio de cáterin tal y como lo ha estado percibiendo a partir del mismo martes día 7 de noviembre. Ante cualquier otra cuestión, no dudéis en poneros en contacto." ····································· Comunico a la secc. económica que esta semana no deben pasar factura el catering.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2023-11-02','Tlf. contacto: 618756139 Marisol; 650047613 Francisco. -- Paso la solicitud para la autorizacion judicial para comprar piso a Miguel .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-11-02','Ana: Envío correo a Carolina, Directora CRR: "tal y como habíamos acorado previamente, adjunto ESCRITO firmado por la actual presidenta de la CTAEx, en que se le indica la sanción y los motivos de la misma, para que se la entreguéis cuando podáis y consideréis que es el mejor momento. Aprovecho para preguntarte por el propio Ceferino, cómo ha ido la expulsión y si habéis notado algún efecto/respuesta positiva en él tras la misma. Por cierto, ¿qué tal está el trabajador al que agredió? Esperamos que evolucione positivamente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-11-02','Nos gustaría informar a la Comisión Tutelar que en la mañana de hoy se ha puesto en contacto con nuestra Entidad María Jesús Merino, forense del Instituto de Medicina Legal, para indicarnos que va a comenzar el procedimiento de José Mª Rodríguez Moya para la nueva sentencia de medidas de apoyo según la nueva ley vigente. Para ello, tiene cita con ella el lunes día 6 de noviembre a las 9:15h. Si os parece correcto, realizaremos el acompañamiento y posteriormente os explicaremos todos los detalles de dicha cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-10-28','27/10/2023 Expediente Amalia .Me ha llamado Elena la ts del ssasb de Zafra (924554601). Va a hacer visita a domicilio para valorar qué limpieza integral necesita la casa , si es integral o con dos auxiliares sería necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-10-31','Ana: Llamada de Carlos (644 949 205): Ha ido al Traumatólogo, finalmente en autobús. Le han quitado la férula. Le han dicho que está todo bien. Tendrá una nueva revisión antes de que acabe el año. Dice que incluso le han dicho que puede coger la bici. Que ya puede hacer vida normal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-11-02','Ana: Llamada de Carlos, lo ha pensado bien y YA NO ACEPTA LA AMPLIACIÓN DEL SAD A 3 DÍAS EN SEMANA. Quiere mantener sólo un día en semana dos horas, como hasta ahora (los miércoles de 8:00 - 10:00 h.). Mañana van a visitarle Carlos y Guadalupe, TS SAD y dice que se lo dirá a ellos también.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2023-11-02','Ana: Llamo a Lola, TS - Residencia Plena Inclusión Cabeza del Buey (690 04 14 05), varias veces a lo largo de la mañana, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MONTAÑA'and apellido2='SANTOS'),'2023-10-31','EXITUS El centro informa de su fallecimiento. El óbito tuvo lugar el 31/10/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-11-02','Ana: Envío nuevo mail a Iberdrola, a la dirección indicada en la carta recibida (prejub@iberdrola.es): "En relación a este correo remitido a fecha de 24 de octubre (que reenvío), rogaría nos confirmaran recepción del mismo. Así mismo, necesitaríamos saber cómo debemos proceder para solicitar el cambio de domiciliación de sus ingresos por contrato de prejubilación, pues se ha procedido a abrírsele una nueva cuenta en otra entidad bancaria. Quedo a la espera de respuesta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-11-02','Buenos días Helena , he hablado con Pepa ,me dice que una tal Ana , que es amiga suya ha ido con su hijo y ya ha tirado lo que tenía allí. No quiere que vaya nadie a su casa , no creo que te abra a tí tampoco , y mucho menos a ninguna empresa de limpieza . Nos va a ser muy difícil trabajar con esta señora , no acepta las medidas de apoyo , desconfía de todo el mundo . Esperemos que la delegada tutelar pueda incorporarse pronto , parece que a ella sí le abrió. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2023-11-03','-Amalia : Hablo con ella para que entienda la conveniencia de dejar el móvil durante las terapias , no quiere . Le vuelvo a insistir en la necesidad de que se distancie de M. Angel y no quiere.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2023-11-03','Buenos días, desde la parte jurídica si se aprueba la operación económica, se estudiará si hay o no inconvenientes en la venta y futura, compra, no renunciando si nos queda dudas a solicitar autorización judicial. Si bien la sentencia establece únicamente nuestra asistencia, y por tanto no necesitamos autorización judicial para una venta y una compra, pero dada la importancia de la operación, por ejemplo de una solicitud de hipoteca…solicitaríamos autorización judicial. Lógicamente a priori no puedo decir qué documentación concreta necesitamos hasta ver nota simple, saber si hay derramas de comunidad, deudas pendientes sobre la vivienda (hipotecas, ibis si n pagar…)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-11-03','Amalia : llega resolucion aprobada la PFHC . Fecha de efectos 01/01/2023 , 453,30€ / mes . Importe bruto 4079,70€ Aviso a S. eco para limitar el dinero . Le envi a Edurdo por email la resolucion. Si no reune requisitos para orfandad , le tengo que solicitar PNC , es más ventajosa.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-11-03','Ana: Llamada de Carlos y Marisa, Aux. SAD, con manos libres. ··············· Tras la llamada envío correo a la S. Ecca: "En relación a CARLOS GONZÁLEZ LEO, he hablado con el Servicio de Ayuda a Domicilio. No tiene casi nada de productos de limpieza en casa y necesitan comprar un poco de todo (incluido palo de fregona y mocho…). Habría que autorizar 30 € para que retire el próximo miércoles que va la Auxiliar del Servicio a su domicilio, le acompañará a retirarlo y a comprar los productos que necestia. Confirmarme por favor cuando se haga." ········································ Hablo con Guadalupe, TS SAD-IMAS CC (927 21 23 35, Ext. 4422): Han visitado a Carlos, finalmente el servicio se mantendrá cómo esta, Miércoles de 8 - 10:00 h. No acepta la ampliación, ni siquiera a 3 días. ······· También le ha dicho que sólo quiere el SAD mientras haya Serv. de Catering (hasta 31 diciembre), sino se dará de baja. *No es lo que acordé yo con él, pero lo iremos trabajando en estos 2 meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-11-03','Ana: Llamada de José Manuel (681 368 017): dice que ha hecho lista de los productos que necesita con la Aux. SAD. *Le indico que nos lo deben confirmar desde el propio SAD. Dice que llamará a Lourdes, TS SAD - IMAS. ················································································· Correo-respuesta de Lourdes, TS SAD IMAS-CC (lourdes.perez@ayto-caceres.es // 927 212 335 Ext 4425): "podemos colaborar con vosotros en esta tarea de manera temporal hasta que vuelva el profesional que realiza los seguimientos . Hablare con la auxiliar, para que me diga cuando José Manuel lo necesite y te pongo un mensaje ok ?" "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-11-03','-Amalia . escribo a S. eco Buenos días , adjunto resolución aprobatoria de PFHC solicitada para Eduardo. Este chico no tiene Gº de discapacidad , sin embargo en Seguridad Social sí han aceptado la prestación. Acordaros que en PNC ya han venido denegadas si no alcanzan el 65% según marca la nueva Ley 8/2021. Cada organismo hace una interpretación de la ley diferente . Tiene efectos desde el 01/01/23 , con una cuantía de 453.30€/mes , con un primer pago de 4079€. Habría que bloquear esa cuenta , para que no pueda acceder a esa cantidad de dinero . Estaba percibiendo de la anterior prestación , Ingreso Mínimo Vital ( IMIVI ) , en torno a 460€ , o algo más , creo que se le podría poner un límite de unos 480€. Necesitaría que me deis un pantallazo de su cuenta , quiero ver hasta cuando han abonado IMIVI , porque se puede haber generado un cobro indebido. En su día le pedí Prestación Familiar + P. Orfandad , que son compatibles. La última vino denegada porque el padre era Guardia Civil . Es de Clases Pasivas y no reúne los requisitos que se necesitan para esa prestación. No voy a tramitar PNC aunque es más ventajosa que la PFHC al ser 14 pagas , pq en PNC no lo van a aceptar al no tener el 65% G.D. Una vez que tengamos bloqueada la cuenta le informaré a él de todo . He intentado hablar con S.Social para aclarar el cobro indebido que va a generarse sin éxito. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2023-11-03','Ana: Llamo a Montse, TS de Hoyos - Mancomunidad de Sierra de Gata (927 14 34 11 // Perales del Puerto 927 514 164): está reunida. Le pasara nota cuando salga. ······························ Tras hablar con con Montse, TS, le envío un correo (malcon@sierradegata.es): "Tal y como hemos acordado mediante conversación telefónica, en relación a SANDRA SANDIN HERNÁNDEZ, cuyo cargo de CURATELA ostenta la CTAEx, solicitamos INFORME SOCIAL, para remitir al Jdo. para el procedimiento de revisión de las medidas judiciales de apoyo. (Olvidé comentarte que justo ayer remití por registro a la Mancomunidad Oficio-solicitud del mismo). Adjunto: - Testimonio de Aceptación del cargo de Curador por las CTAEx - Testimonio de Auto de Remoción y Nombramiento (en la parte dispositiva expresa “…haberse atribuido al Curador funciones de administración del patrimonio”) - Testimonio de Sentencia de Incapacitación (en el fallo “…para administrar sus bienes o gestión de sus intereses económicos, necesitando supervisión para la toma de decisiones en cuanto la realización de actividades complejas o inusuales..) - Decreto de tramitación de expediente de la revisión de las medidas de apoyo vigentes a la fecha (Sí nos lo han enviado ya. - En la parte dispositiva requiere contestemos también sobre si: “manifieste si solicita se le nombre curador de la demandada o propone a otra persona o familiar de la demandada para dicho cargo.”) - Copia del oficio remitido ayer por registro. Ante cualquier cuestión no dudes en contactar"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-11-03','Ana: Llamada de Laura Pulido, TS EVD (24121 // laura.pulido@salud-juntaex.es): Ha ido a valorar a Santos. Ingresó de forma involuntaria por emergencia social vía decreto en la Res. de Montehermoso. ··········· Pregunta si procede a tramitar el mantenimiento de la plaza o el traslado a la Res. de Ahigal. ········ Al preguntarle a él, dice que él lo que quiere es volver a su casa. ······················· Llamo a PIEDAD CABEZAS GARCIA TS SSB Ahigal (670 293 045): no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-11-03','Ana: Llamada de Laura Pulido, TS EVD (24121 // laura.pulido@salud-juntaex.es): Ha ido a valorar a Santos. Ingresó de forma involuntaria por emergencia social vía decreto en la Res. de Montehermoso. ··········· Pregunta si procede a tramitar el mantenimiento de la plaza o el traslado a la Res. de Ahigal. ········ Al preguntarle a él, dice que él lo que quiere es volver a su casa. ·······················','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-03','-Amalia : LLega cdo. Gº discapacidad , le dan el 52%.Lo archivo en su expediente. LLega documento en el que se compromete a la compra de la vivienda . Envia documentacion del sexologo de Andalucía , guardo escaneado una copia en su expediente y remito los originales al CRR de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2023-09-05','Ana: Correo de Ana, Res. (anatdelat@hotmail.com): "Nos acaban de llamar a la Residencia de mayores de Torrecillas de la Tiesa del hospital Quironsalud Clideba de Badajoz para informarnos que el día 21 de septiembre tiene la usuaria el preoperatorio para su operación de varices. Tendría que estar en el hospital ese mismo día a las 9:55h. Y nos han comentado que la operación sería el dia 22 o 23 del mismo mes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2023-11-03','Ana: Llamo a Lola, TS - Residencia Plena Inclusión Cabeza del Buey (690 04 14 05): Ana Mª se está adatando bastante bien al centro. Las primeras noches le costó dormir, pero ya las pasa mucho mejor, de vez en cuanto hace alguna mala, pero más puntual. Al principio estaba ella sola en una habitación pero ya duerme en habitación compartida. El primer día, al poco de llegar, cuando vio el césped se tumbó en el mismo y pasó varias horas allí tumbada al son muy relajada. Les sorprendió su buena reacción y acogida hacia l@s profesionales. Sonríe mucho. ···· En el C. Día está "genial", le gusta jugar con muñecas y plastilina. *Le han preparado "su rincón de juego" y le han comprado juguetes. "A veces se pone caprichosa y se enfada cuando no la entienden". A penas habla, pero a veces expresa con mucha claridad ciertas palabras como "tomate" (le gusta la pasta a la boloñesa) o "jarabe médico" (que demanda cuando se encuentra mal, como ayer por ejemplo). ············· En cuanto a la familia, le han llamado ya un par de veces, tanto la madre como la abuela, pero le ponen el manos libre y ella no quiere cuentas. ········································· En cuanto tengamos acceso a cuentas (o información sobre la misma), solicitaré PNC. *No nos consta valoración de dependencia, si no se le ha tramitado la solicitaré también. ···················· *Por otra parte, necesita toallas, zapatillas, ropa interior y algunas cosillas más. *Intentarán comprarlo en el centro y nos pasarán la factura, para que cuando se pueda se le abone al centro. ································································································································································································ Envío coreo a Icíar y al ctutelar@: "..., sé que aún está en fase de inventario. Icíar, porfa, cuando tengamos información de sus cuentas (supongo que tendrá una en la que le habrán ingresado la prestación familiar como menor de edad – 2 pagos al año), por favor, facilítamelo para que pueda solicitarle la PNC. A día de hoy no tiene ingresos. Resto de compis, puesto que necesitas cositas básicas y no tiene dinero (zapatillas, toallas, ropa interior…) van a intentar comprárselo en el centro (Cabeza del Buey) y nos pasarán a posteriori la factura para abonarlo cuando se pueda. Si cuando tengamos acceso a las cuentas, tiene dinero, perfecto, sino cuando haya ahorrado un mínimo para ello."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-11-03','Ana: Correo-respuesta de IBEDROLA (prejub@iberdrola.es): "Acusamos recibo de la documentación. En lo que respecta al cambio de domiciliación bancaria para solicitar el cambio se debe cumplimentar el impreso adjunto y enviarlo junto con una fotocopia del DNI en vigor del Sr. Blanco Poveda." ·························· *Reenvío a Alberto e Icíar, S. Ecca. "En cuanto a la gestión para el cambio de cuenta, me envía este documento. ¿Os encargáis vosotros, verdad? Sino decírmelo y lo hago yo." ··· Se trata de un formulario de comunicación de datos de cuenta bancaria sencillo, sólo requiere los datos de la cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-11-06','Ana: Recibimos escrito de PNC, solicitando nuevo ALTA DE TERCEROS, debido a la absorción de Liberbank por Unicaja. ·························· Cumplimento el modelo y se lo entrego a las compañeras de S. Ecca. para cuando vayan a banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-11-06','Ana: María, S. Ecca. confirma que en estos meses a Javier no han llegado a pasarle por el banco ningún cobro que no corresponda a los suministros de su vivienda (lo que ya tenía domiciliado). Por tanto, lo que dijo de que le habían robado los datos y habían domiciliado pagos en su cuenta, fue fruto de su descompensación psicopatológica. ······························· Se lo comunico por mail a Ana Mª Benavente, TS ESM-Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-11-06','Ana: Guardo en el expediente digital el INFORME DE PSIQUIATRÍA - ESM que solicité. Consulta 13/10. ········ En el mismo, la Dra. Cristina Donoso Jiménez, expresa que solicitó cambio de Psiquiatra, es la segunda vez que le atiende. *"Persiste su demanda de que le hagamos un informe para que le quiten la curatela. Le explico la situación pero no lo acepta. Refiere que ha contratado abogado privado a tal fin. Se muestra querulante y no manifiesta conciencia de enfermedad, aunque acepta el tratamiento. Se va disconforme y refiere que va a solicitar cambio de psiquiatra." "Tratamiento igual: XEPLION 100 mg. 1 ampolla cada 28 días." ···· Último inyectable administrado el día 13/10/23. ······· Obligado al tto. por sentencia judicial. Jdo. de lo Penal 2 de CC. Ejecutoria 16/2015. Proc. Abreviado 278/2014. Liquidación de condena 1/11/2026. ······ Al final del informe expresa literalmente: "El juzgado debe ordenar que el curador acompañe al paciente a las consultas. EL PACIENTE DEBE VENIR ACOMPAÑADO. UNA PERSONA DEBE RESPONSABILIZARSE DE QUE ACUDE A PONERSE EL INYECTABLE. ······· Próxima revisión en 3-4 meses. ··························································································································································································· Escribo a los A. Jurídicos CTAEx en relación a esta sentencia, si no la tenemos sería conveniente solicitarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-11-06','Ana: María, S. Ecca, me confirma que ya está preparada la Autorización para la retirada del extra de los 30€ para productos de limpieza el miércoles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-11-06','Ana: Nuevo correo del sábado de Azucena, Cuñada de Juanjo al ctutelar@ (azuydavid153@gmail.com // 625 367 302) preguntando por el ingreso de Juanjo. Dice que no aguanta más. ·············· Contesto que las gestiones por nuestra parte están hechas, pero la asignación de plazas no depende de nosotras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-11-06','-Amalia : escribo a los juridicos y a los Jefes de sección ante la necesidad de comunicar la situación al juzgado. Buenos días , ya hemos hablado varias veces de este caso , considero necesario comunicar la situación al juzgado y que tomen la medida que consideren más adecuada . Eduardo está incapacitado para la esfera personal y patrimonial . Según su sentencia , la médico forense determinó que padece trastorno mental por trastorno psicótico afilial y deterioro cognitivo. Eduardo no está de acuerdo con este sentencia , que según comenta, llegó a recurrir. No acepta la ayuda que podamos ofrecerle en ningún aspecto ni personal , patrimonial ... Se han mantenido con él varias entrevistas personales en la sede del SEPAD sólo cuando él las ha demandado , se le ha atendido sin cita para dar toda la facilidad posible. Pero no acepta cuando la demanda viene desde la Comisión , negándose a recibir también a la delegada tutelar de apoyo . En estos meses se ha intentado sin éxito que acuda a un centro de salud , no está tomando la medicación ni tiene conciencia de enfermedad .Desconocemos si pudiera estar descompensado , no acude a ningún médico . Contacté con la madre telefónicamente en varias ocasiones para que nos informase de consultas o pruebas médicas de las que pudiera disponer y me indicó que nunca lo llevó a ningún especialista. Eduardo sigue viviendo en la calle , en una tienda de campaña que tiene puesta en unos soportales en la Avda. Lusitania en Mérida . Es por todo ello por lo que considero que sería necesario comunicar la situación al Juzgado , por si estima oportuno un internamiento involuntario en la Unidad de Psiquiatría del Hospital General de Mérida para valoración y posible compensación si fuera el caso, de su patología . Se ha intentado ayudarle a buscar otra alternativa habitacional , en coordinación con la Trabajadora Social del SSASB de Mérida . Todo ello sin éxito , lo único que está dispuesto a recibir en una vivienda de promoción pública . La solicitó en 2 ocasiones . Contactamos con el Servicio de VPP de Mérida que nos informaron que la misma había sido denegada , no consideran que cumpla los requisitos necesarios . Se le han expuesto diferentes alternativas, todas ellas denegadas: - El recurso del Centro Residencial de Rehabilitación para personas con patología mental lo ha descartado, ya que no asume que padece ninguna patología mental. - En el centro de transeúntes Padre Cristóbal no tienen plaza en la actualidad ni tampoco el Centro Hermano en Badajoz, nos dan la alternativa de ocupar una plaza en el Centro de Emergencia Bravo Murillo de Badajoz. Se lo comentamos a Eduardo y tampoco quiere este recurso. - Se le propone como alternativa habitacional alquilar una habitación en el Hostal el Torero pero tampoco está de acuerdo argumentando que está muy lejos de Mérida y que no quiere gastar ahí su dinero. -Se le informa que existen ayudas para alquiler de una vivienda , aunque son mínimas , pero para poder tramitarlo necesitaría un contrato de alquiler. No existen alquileres en Mérida que se adapten a la prestación que percibe , actualmente tiene aprobada la Prestación Familiar por Hijo a Cargo de 453,30€ mensuales. Los recursos económicos son insuficientes para pagar piso , suministros y manutención. No quiere otra localidad que no sea Mérida y tampoco está dispuesto a compartir piso de alquiler con nadie más . Por todo ello , y a pesar de no tener informes médicos dado que según la madre no ha ido nunca a especialistas y él se niega a ir , solicito se comunique la situación de Eduardo al juzgado . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-10-09','Ana: Teresa Nogueira, Novaforma (trabajadorasocial.novaforma@gmail.com), me envía INFORME SOCIAL. En el mismo expresa: "Se considera que sería conveniente descontextualizar a Juan José de su entorno familiar (Ingreso en recurso residencial), con el fin de velar por su interés y bienestar, ya que se considera que su situación familiar le sitúa en una situación de vulnerabilidad y desprotección, pues no tiene familiares que velen por sus intereses, siendo una situación de urgencia social que mantenida en el tiempo puede desencadenar en una situación de emergencia social" ··················· En el texto del correo, en relación al ingreso de forma voluntaria expresa: "...yo llegado el momento no veo claro que se vaya a ningún sitio aunque haríamos lo imposible por tratar de convencerlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='LEAL'and apellido2='PARRA'),'2023-11-06','-Amalia: el caso ya ha entrado en CTAEX. Hablé con Beli de Arroyo , su tf 678085402 . Padece EMG , estuvo ingresado en CSS Mérida. Vive con su padre que es consumidor . Me dice la TS que el fiscal le ha dicho que solicite el internamiento involuntario desde el SSASB .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='ALMANSA'and apellido2='REDONDO'),'2023-11-06','EXITUS El centro informa de su fallecimiento, acaecido el 03/11/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2023-09-28','Ana: Emilia, TS CSS-Plas. envía a Maite INFORME DE PSQUIATRÍA. ······· Guardado en el expte. ·············· En el mismo, la Dra. Rosa Mª Fdez. Barrera, expone: "JUICIO CLÍNICO: TRASTORNO ESQUIZOAFECTIVO TIPO BIPOLAR" "CONTINUARÁ EN RÉGIMEN DE HOSPITALIZACIÓN EN LA UNIDAD DE REHABILITACIÓN." ····· "El paciente se encuentra estable a nivel psicopatológico, no alteraciones mayores de la esfera afectiva, no descompensación psicopatológica actual, cierto enlentecimiento cognitivo" "Buen nivel de actividad y participación en talleres y grupos" "Buen funcionamiento fuera del centro y buenas relaciones sociales"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-11-03','Ana: Desde la Secc. de acceso a RR. de Salud Mental, informan que van a trasladar a Ceferino al CRR de Don Benito. Aún no está la Resolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-11-06','Ana: Envío correo a Alberto, Jefe Secc. Ecca.: "En relación a MIGUEL ÁNGEL RAMOS ANDRES, finalmente, tras el recurso que interpuso Ángel, le han concedido la PFHC (453,30 €/mes). Ya le han hecho ingreso en su cuenta bancaria. Está demandando, como es lógico, su asignación. Dadas sus dificultades para administrarse adecuadamente, entiendo que deberían ser retiradas semanales. Habrá que valorar cuánto se le puede dar. *Como sabes esta prestación no tiene pagas extras. Desde la sección económica proponemos 80€/semana. En la actualidad está viviendo en un Piso Okupa. Ya me dices."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESSICA ESPERANZA'and edp.apellido1='LEON'and apellido2='ENCINAS'),'2023-11-06','Ana: Llamada de Isabel Cuesta, Jefa Secc. Menores - SSTT CC (64835): Le informo que ya se ha aceptado el cargo de Jessica. Ahora estamos en fase de inventario. ·········· En relación a ingreso en centro, le informo de que aún no le han asignado plaza, pero están en ello en la Secc. de Discapacidad. ·············· En cuanto a la posibilidad de que continúe en C. PROA (podría estar en el Sist. Educativo hasta los 21 años), dice que no está segura de que sea buena idea, en tanto que Jessica lleva muy mal los cambios y los traslados son de carácter semanal y ella se pone muy nerviosa/inquieta cada que llega el momento: patalea, no quiere subir y/o bajar de la furgoneta. Por prescripción médica le dan 1 mg de Loracepan, pero el viernes pasado le sentó muy mal (no es la primera vez que le ocurre). ·············· Lo valoraremos y hablaremos también con C. PROA al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-11-06','Tiene una piedra que le está obstruyendo el intestino, y le está provocando además de la obstrucción, los vómitos. Descartan la intervención quirúrgica. He hablado con el familiar ante un posible deceso a corto plazo, y me comenta que Mª Luisa tiene un nicho en propiedad en el cementerio de Higuera de Vargas, por tanto, entiendo que desearía ser velada y enterrada en su pueblo. La compañía aseguradora es Ocaso. Supongo que tendrá al día el pago de los recibos del seguro. Tengo el teléfono de contacto de los familiares (sobrinos), pero no he sido capaz de contactar con ninguno. Te voy contando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2023-11-06','Ana: Maite y yo llamamos a Cristina, TS - CSS (24205), en relación a la venta de uno de los inmuebles de Martín, pero no obtenemos respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-11-06','Ana: Llamo a PIEDAD CABEZAS GARCIA TS SSB Ahigal (670 293 045): en relación al a posibilidad de pedirle plaza en su pueblo, Ahigal, dice que es contraproducente, pues Santos se iría a su casa. ·················· Llamada de Laura Pulido, TS EVD (24121 // laura.pulido@salud-juntaex.es): confirmo que lo más adecuado es le MANTENIMIENTO DE LA PLAZA en la que está. Mañana me remitirán la ACEPTACIÓN PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2023-11-06','Amalia : al contactar con el centro penitenciario de Huelva nos comunican que Rafael desde el día 03/10/2023 se encuentra en Topas (Salamanca), es su centro de destino. Igual que en el traslado anterior no comunican los traslados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2023-11-06','TERESA ENVIO ESCRITO SOLITANCIO VISITEN LA VIVIENDA QUE LINDA CON CANDIDO PARA QUE VEAN EL ESTADO EN EL QUE SE ENCUENTRA Y LOS DAÑOS QUE LE ETA CAUSANDO.,...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-11-07','Ana: Inés, Adtva. Secc. Jurídica, facilita copia de la Sentencia 9/2015. Se le impuso, entre otras (prohibición de acercarse a su madre, prohibición de tenencia de armas, trabajos en beneficio de la comunidad), la "medida de internamiento en centro psiquiátrico por el tiempo de 22 meses" + "medida de seguridad de libertad vigilada consistente en seguir un TRATAMIENTO MÉDICO EXTERNO a su patología", por múltiples delitos de Violencia Doméstica hacia su madre, padre y hermana, delitos de amenaza y "violencia psicológica habitual".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-11-07','-Amalia : pongo a registro el PIA y la documentación , se ha pedido CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-11-07','Ana: Correo de Estrella Durán, TS CSS Plas. (estrella.duranc@salud-juntaex.es): "Te comunico que se va hoy de alta Desideria Barbero Bueno, y seguirá viniendo a Hospitalización Parcial lunes y jueves."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2023-11-02','miguel, llega email de la asesoría Otelso Asesoramiento Global Miguel Mariscal >miguel@otelso.com> : Me comunico con Vds. para informarles que obra en la Notaría de D. Alberto Saenz de Santamaría, de Cáceres toda la documentación relativa para la aceptación de herencia por el fallecimiento de dª Silvia Valcarcel Vidal, al objeto que la Comisión tutelar realice los trámites oportunos en favor de Dª Sonia Valcarcel Vidal. El oficial que está al cargo de la documentación en dicha notaría es Miguel Harto y su teléfono 927-870170, por si tienen que comunicar con dicha notaría para fija la fecha de firma de aceptación a la que tendrá que personarse alguien en representación de Sonia. Quedo atento a sus comentarios o lo que pudiera necesitar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2023-11-07','miguel, contesto a la asesoria Otelso Miguel Mariscal >miguel@otelso.com>: Buenos días, en su día hablamos con notaria de Norberto Santa Maria de Cáceres, quien nos indicó que se iba a firmar la escritura de herencia y después se ratificaría en Mérida. La forma de proceder ya se habló con él. Este tipo de escrituras se firma en la notaria y son ratificadas por la Comisión Tutelar de Adultos en la notaria de Mérida de Don Gonzalo Fernández Pugnaire, para lo cual deberán remitirle desde aquella notaria la escritura vía telemática a correo corporativo del notario, siendo la persona de contacto de la notaria joseluis@romeroleal24.com, tlfno 924317761, ext 13. Estamos a la espera de que previo a dicha firma, la notaria nos remita el borrador de la escritura que se firmará para comprobar la misma. Por tanto, pueden hablar con la notaria para que su hermana Concepción actúe como mandataria verbal y una vez firmada tramite la misma, ya que en su día nos comunicó que tenían una cuenta común para tramitar todo. Quedamos por tanto pendientes del borrador de dicha escritura por parte de la notaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2023-11-07','TERESA HABLO CON LIDIA TS DE LA CASA MISERICORDIA 927674303 YA QUE SU HERMANO DEMANDA ENTAR EN LA VIVIENDA DE ANTONIO PARA VER EL ESTADO EN EL QEU SE ENCUENTRA TRAS LAS ULTIAS LLUVIA COMO EN ETA OCASION NO CONTAMOS CON FUTUEX VA A INTENTAR COODINARSE CON EL CENTRO DE ALCUESCAR PARA EL TEMA DE FACILITARLE LA LLAVE Y QUE AL DEVUELVA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2023-11-07','-Amalia , escribo a Sandra : consultado con la Jefa de Sección , aceptamos que pase a ser socio de la entidad si él así lo ha demandado . Podéis cargarlo en su cuenta . Con respecto a la baja en C.O . cuando empiece con la formación , tendréis que solicitar la baja por incompatibilidad con la formación , no esperar a los 45 días por falta de asistencia . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2023-11-07','AEXPAINBA : Informaros que Juan José Murillo Romano ha sido seleccionado en una formación financiada por la Fundación ONCE y organizada por Fundación Magdalena Moriche sobre RAEES. En esta formación, los primeros 6 meses el alumnado seleccionado cobrará una beca formativa de 9 euros al día. Este dinero no tendrá que declararlo al SEPAD. A partir de estos 6 meses, pasará a trabajar durante un año. Cobrará el 75% del sueldo mínimo interprofesional. De este sueldo, el 50% estará destinado, según SEPAD, a la vivienda tutelada. Actualmente Juan José se encuentra en centro ocupacional de la Entidad. Este curso formativo le coincide con tal servicio pero Juanjo ha decidido querer hacer este curso, pues para él es una oportunidad laboral. A los 45 días de falta injustificada, centro ocupacional le dará de baja en dicho servicio y a partir de ese momento sólo estará en RAEES. Antes de que termine la formación, la idea es volver a solicitar centro ocupacional. Desde la Entidad, nos gustaría que Juanjo pueda ser a partir de ahora socio, pues el usuario quiere hacerlo y cuenta actualmente con el dinero para ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-07','Ana: Correo-respuesta de Carmen Santos, hermana de Enrique (maluker6@hotmail.com): "Hablé con él hace unos días, que le llamé y me contó. Voy en unos días a Plasencia, si puedo le llevo al perro para que se puedan ver. Le oí bastante mal, a ver si poco a poco va encontrando rutina y tranquilidad, porque estaba excesivamente verborreico, cabreado y con un discurso también en su línea de intenciones de manipulación. Esperamos los hermanos que todo vaya a mejor para él. El día 10 firmamos la herencia de mi madre ante el notario, estarás al tanto." ············································· Correo-respuesta de Miguel, A. Jurídico, en relación a la herencia: "estamos al corriente y en contacto con asesoria Teficon (Alvaro) y la abogada Ana Iglesias. La escritura la ratificaremos en Mérida cuando sea necesario."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-11-06','Ana: Correo de Icíar: "Hemos solicitado la cancelación de la cuenta del BBVA de Montaña, van a quedar 19 € sobrantes y me piden desde el banco que tiene que pasar Montaña a firmar la cancelación y a retirar los 19 €. No sé si tú hablas con esta señora. Desde el banco la han llamado, pero no contesta, y a mí también me sale el contestador."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-11-07','Ana: Llamada de Carlos (644 949 205): Le han dado comida en la Asociación CRESI (Obra social), que colabora con el Banco de Alimento. Acude el primer martes de vez al mes. ························ La Aux., Marisa, le ha acompañado a la Asociación y a comprar alimentos. ············· *Le han cambiado el día de SAD, a los MARTES de 8:00 a 10:00h. ······························································································································································································· Envío correo a Amadora Pérez, Gerente de Sol Catering (amadora@solcatering.es): "En relación a D. CARLOS GONZÁLEZ LEO, cuyo cargo de Curador ejerce la CTAEx, queríamos solicitar PRESPUESTO DE SERVICIO DE CENAS, para ser valorado por la sección económica. En caso de ser viable se podría contratar dicho servicio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-11-07','Ana: Llamo a Montaña (692 84 12 19): Se le nota muy bien ánimos y parece estable. ····· Mañana acudirá a la oficina del BBVA a firmar la cancelación y retirar los 19€ que quedan. ················· En cuanto a la convivencia con sus padres dice que sigue bien. ········ Le explico que el programa de Apoyo Comunitario finalmente no volverá a ponerse en marcha hasta diciembre, por lo que posponemos hasta entonces tanto su derivación al mismo como la posibilidad de independizarse de nuevo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESSICA ESPERANZA'and edp.apellido1='LEON'and apellido2='ENCINAS'),'2023-09-29','Ana: Reunión de COORDINACIÓN con Sist. Protección de Menores - Isabel Cuesta, Jefa Secc. SS.TT.CC y educadores del CAM Isabel de Moctezuma (Caminomorisco) con carácter previo a la aceptación de cargo. ·················· Jessica lleva en el CAM desde 2015 (ingresó con 9 años). Desde entonces no ha ido nunca al domicilio familiar. ········ Fue fruto de una relación entre dos jóvenes también procedentes del Sist. de Protecc. de Menores. - Indicios de posibles abusos por parte del padre. ····· Éste está cumpliendo condena en C. Penitenciario. ················· Jessica presenta TRASTORNO DEL ESPECTRO AUTISTA / RETRASO MADURATIVO. ··········· Asiste a C. PROA - CC. ············· La relación con la familia es escasa, pero van a visitarla semanalmente, los domingos. ············· Los cambios le cuestan mucho, hay que avisarla con antelación e insistirle mucho para que se haga a la idea. ······································· Tiene reconocido Grado II de Dependencia y un grado de 76% de Discapacidad. ·················· Ha dado perfil RAE. ···· Cuando cumpla la mayoría de edad se le tramitará plaza en centro. ·············· Recibe Tto. de T.O. por Habilitación Funcional en DOWN. ················· Su edad mental es de 3-4 años. ·········· Suele tener más afinidad con los hombres que con las mujeres. ········· No lectoescritura adquirida. ··········· Presenta cierta autonomía para el aseo personal. vestirse y hacer la cama. ············· Le encanta los juegos de mesa y las manualidades. ···························· *Acordamos que cuando se le haya asignado centro coordinarán una reunión con los profesionales de éste para preparar mejor su llegada, acogida y atención. Le facilitarán más información del día a día y el modo de funcionar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2023-11-07','TERESA HABLO A PETICION DE JOSE TS (685398572) CON ESTEFANIA DIRECTOA DE LA RESIDENCIA 675516505 POR EL ASUNTO DEL EMPADRONAMIENTO YA QUE JOSE LLEVA UN AÑO EN AL RESDIDENCIA. LE HE EXPLICADO QUE JOSE TIENE UNA VIVIENDA SOCIAL CON DERECHO A COMPRA Y ES REQUISITO ESTAR EMPADORADONA EN ELLA PARA NO PERDERLA, ME COMENTA QUE NO HAY PROBLEMA QUE INFORMA AL AYUTAMIENOT DE LA SITUACION Y SE LE MANTIENE EL EMPADRONAMIENTO EN LA LOCALIDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2023-11-07','Ana: Llamada de la Res. (649 033 920), me pasan con Isabel: Expresa que ella no quiere gastarse dinero en Notaría para hacer el testamento. Pregunta si no es suficiente con escribirlo en un papel y firmarlo ella. Le explico que así no puede ser. ······ Dice que ella no tiene tierras, ni propiedades ni mucho dinero, pero que su hermana no deja de insistirle en que si no hace el testamento el día que fallezca la Junta se quedará con todo el dinero. *Le explico que eso no es así y que si no quiere hacer testamento no tienen por qué hacerlo, no es obligatorio. ······ Dice que eso mismo le explicó en su día Gloria, Ed. Futuex y que ahora se queda más tranquila. ··············· Se lo va a pensar y si decide hacerlo finalmente se lo dirá a la directora para pedir presupuesto a Notaría para que nos lo envíen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2023-11-07','Amalia ; respuesta del INSS por el tema del pago del cobro indebido . Se aceptó el planteamiento del INSS pero aún no han hecho ninguna decucción. "No tiene ninguna deducción en su pensión, es normal suelen tardar unos meses en empezar hacer las deducciones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-11-07','Ana: Llamada de Rosana, Directora Centro (699 198 186): Siguen sin tener dinero y necesita para tabaco y pequeños gastos de bolsillo (algún café/refresco de vez en cuando). De momento tanto la directora, como otras profesionales del centro y su pareja cuando fue a verla le han regalado tabaco. ···· *Seguimos sin la firmeza de la sentencia. En el Jdo. informaron a Inés, S. Jurídica, de que la recurrió. ······················ Por otra parte, dice que está muy bien. Le saluda y sonríe cuando llega. Acepta las normas de funcionamiento. Cuando fue su pareja cumplió con la hora de regreso al centro. *Dice que parece una persona distinta a cuando llegó. ··············· Envío correo Alberto, Maite, Julio y A. Jurídicos CTAEx: "En relación a JOAQUINA MAYORAL PIZARRO, me han llamado desde la residencia Amada Corral de Alcuéscar, donde ingresó de manera involuntaria. Explico: Me temo que NO TENEMOS TODAVÍA LA FIRMEZA, pues al parecer la propia Joaquina RECURRIÓ LA SENTENCIA según me informó Inés, pero no sé cómo vamos a poder hacer ni con el pago de la residencia, en la que ya ingresó de manera no voluntaria, ni con el resto de gastos. Ya teníamos aceptado este cargo con anterioridad, pero antes sólo era Curatela para la SALUD, por lo que no se controlaban sus cuentas. Ahora es CURATELA REPRESENTATIVA y hay que gestionar también su patrimonio. NO TENEMOS ACCESO A LAS CUENTAS y no tiene dinero. La directora y otras profesionales de la residencia le están regalando paquetes de tabaco, pero esto no puede seguir así. Entiendo que si la sentencia era válida para el ingreso, también lo será para poder acceder a sus cuentas, ¿no es así? Ya me decís si hay alguna forma de hacerlo/solucionarlo, porque también se debe un acompañamiento hospitalario y en los próximos días tiene que volver a acompañarle a otra cita médica. Es perceptora de una PENSION A FAVOR DE FAMILIARES de 502,40 € En teoría , a día de hoy. ella podría ir al banco a sacar dinero, pero no queremos que lo sepa por el riesgo de que vuelva a sacarlo y gastárselo todo. En su pueblo, Miajadas, ha dejado varias deudas también que con el tiempo, cuando sea posible, habrá que saldar. *Julio, porfa, cuando puedas, modifica la dirección en la base de datos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-11-07','-Amalia : pregunto por email sobre la posibilidad de que exista un cobro indebido al INSS Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2023-09-29','Ana: Reunión de COORDINACIÓN con Sist. Protección de Menores - Isabel Cuesta, Jefa Secc. SS.TT.CC y educadores del CAM Isabel de Mostezuma (Caminomorisco) con carácter previo a la aceptación de cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-07','Amalia: Miguel nos escribe ésto ; he enviado a la abogada propuesta de acuerdo para el abandono voluntariamente de la inquilina, previo acredite no dispone de capacidad económica. Dicho acuerdo deberá ser firmado por la inquilina, Carmen y la Comisión Tutelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-07','miguel, envío email tras reunión con parte económica y social aceptando una mediación para acuerdo de desocupación, sin reclamación de deudas (si acredita la inquilina incapacidad económica) y si es aceptado por nuestra tutelada: Buenos días Maria, tras valorar las opciones del asunto del piso de Carmen Leal, creemos que la opción más rápida y eficaz, pasaría por como comentamos un acuerdo de abandono de la vivienda sin reclamación por ambas partes. Para ello necesitaría, para incluir en el expediente que la inquilina acreditase que la unidad económica (ignoro quienes forman parte de la misma) no dispone de capacidad económica para asumir el abono de las cantidades adeudadas. También necesitaría si te parece bien, que el acuerdo lo redactases tú y si hay que abonar alguna cantidad me indicases el importe de dicha gestión de intermediación. Dicho acuerdo se lo daríamos a Carmen Leal para que si está de acuerdo lo firmase por ella y por la representante de la Comisión Tutelar de Adultos. Te llamo el jueves, y ya concertamos día para acercarme a saludarte. -------------------------------------------------- recibo email de Maria Granada: Hola Miguel. He llamado esta tarde a esta señora. Justo salía de correos, me ha dicho, y le he pedido que me lea lo que había recogido y era la notificación del archivo. A vosotros también os la han debido notificar a través de la procuradora. Le he comentado la posibilidad de llegar a un acuerdo y me he sorprendido, la verdad, porque lo primero que me ha dicho es que no tiene donde irse. Yo le he intentado convencer de que tarde o temprano, y más temprano que tarde se irá de ahí, que si no acepta, vais a hacer las acciones necesarias para echarla y encima con reclamación de cantidad. Y no le he visto interés, la verdad. De hecho ni me ha preguntado por qué se ha archivado la causa. Lo mismo ya está en contacto con el letrado que le hayan turnado. En fin, le he dicho que tiene de plazo hasta el viernes para pensárselo. Ya te contaré qué me contesta. Aunque la veo aferrada a la casa. No me lo esperaba con la opción que le he propuesto. Si dice que sí, ya te digo lo que cobraría por redactar, que sería poca cantidad. Para cualquier cosa aquí estoy. --------------------------------------------------------','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-08','miguel, envío email a la parte social, económica y a Angel: Buenos días, os ajunto email de la abogada Maria Granada (ex abogada de la inquilina que ganó el caso), donde indica que la inquilina no va a querer abandonar la casa. Os recuerdo que aunque pedí al abogado Jorge Calvo y su procuradora Cristina que desistiesen del caso, no me han mandado ningún documento (desistimiento, archivo del procedimiento por el juzgado, sus minutas…) Estamos pendiente en este 2º procedimiento si el abogado de la otra parte se opone al desistimiento (por presentar el mismo tarde el abogado Jorge Calvo…en cuyo caso le pediré de incidencia a su seguro de responsabilidad civil…tal como ya hice con el 1º procedimiento y de cuya resolución por la aseguradora estamos pendientes de que el abogado Jorge nos notifique, y cuyas minutas de nuestro abogado Jorge y su procuradora Cristina están sin abonar, tanto del 1º como del 2º procedimiento, y cuyos importes de honorarios todavía no nos han comunicado). Por tanto habrá que buscar otro abogado, esta vez será de confianza. He pensado en uno que trabaja habitualmente con nosotros y se ajustará seguro en precio…Enrique Perianes, aunque es de Mérida. Me acercaré esta tarde a saludar y dar las gracias por sus gestiones a esta abogada, sin la cual no nos habríamos quitado de encima a nuestro abogado Jorge. -------------------------------------------------------- nuevo email de la abogada Maria Granada que reenvio a la parte social, económica y Angel: Hola Miguel. Pues la verdad es que esta señora tiene muchísima cara, y como le ha ido bien hasta ahora, querrá estirar la situación a máximo. Yo intenté convencerla por todos los medios, pero insistía en que no tenía dónde ir. Le dije que al final se iba a ir, y que se aprovechara de esa oferta....pero nada, y lo peor que la vi muy segura, no dudó en ningún momento. Me dijo que la casa estaba en mal estado, con ratas, cucarachas...y le dije que entonces era mejor buscar otra vivienda. A ver qué me dice el viernes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2023-11-08','miguel, solicitamos vía lexnet autorizacion judicial para entrega de dinero para la compra de vehículo por la sobrina','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-07','miguel, el abogado nuestro Enrique Perianes, me remite la documentación de la demanda y documentos que la acompañan de solicitud de autrorización judicial de venta del piso de Damian de Málaga. Me pide le vayamos facilitando la atasación del inmueble. Reenvío a la prima de Damian con copia a este y a la abogada Rocio (que le tramitó el desahucio en Malaga)email para recordarle nos faciliten dicha tasación. Recibo de ayer y hoy muhcos emails de Damian, desestabilizado, en decisiones contrapuestas de venta sí/no. Finalmente esta mañana ha enviado varios emails comunicando continuemos con el procedimiento con normalidad. Le escribo para recordarle siga el protocolo establecido con Amalia, y para que esté tranquilo. Me facilita el teléfono de una amiga por si falla su prima Alicia en buscar un tasador, teniendo en cuenta que la llave la tiene dicha prima Alicia. La amiga se llama Lidia 622911155. Le contesto que vamos a esperar que contesta su prima antes. ----------------------------------------------------- nuevo email de Damian: Le facilito un número que he encontrado por internet de un tasador.670408961 a ver si le sirve.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2023-11-08','Ana: llamada de Ana Benavente, pone el manos libres, está en su despacho Mª Ángeles, la hermana de Isabel. Por un lado dice que quiere ser ella "la tutora" de Isabel y por otro que quiere que su hermana haga testamento en una notaría de Plasencia, pues así se lo ha recomendado un funcionario del Jdo. que conoce. ··············· Le explico que ayer precisamente hablé con su hermana Isabel al respecto. ····· Si ella decide hacer testamento lo hará en una localidad cercana a su lugar de residencia y le acompañarán desde el centro. ····· En cuanto a ser ella la tutora, le indico que debe solicitarlo en el Jdo. por escrito. ······················ Está un tanto alterada y no se le entiende muy bien al hablar. ····· Mientras hablamos acude la Psiquiatra a preguntar por ella, pues se ha pasado ya la hora de su cita, como no acuda pasará a la siguiente persona - Por tanto Mª Ángeles también es paciente de Salud Mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRIADO'and apellido2='RODRIGUEZ'),'2023-11-08','Ana: Correo de José Aº Pulido, TS SSASB - Sierra de Montánchez (tsocial1@mancomunidadsierrademontanchez.es): adjunta Informe Médico e Informe Social, solicitados para la revisión de las Medidas Judiciales de Apoyo de Mª Jesús. ············· Los guardo en el expediten digital y los envío a los A. Jurídicos. ······················ En la VALORACIÓN Y PROPUESTA del Informe Social: "Discapacitada de 65 años, viviendo en Piso Tutelado , carente de familiares directos y tutelada hasta la fecha por la CTAJEX. Se considera procedente el que la Comisión Tutelar de adultos de la Junta de Extremadura, asuma la curatela de doña María Jesús, en el desempeño de las actividades que más dificultades suponen para la discapacitada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERMINA'and edp.apellido1='SERRANO'and apellido2='MOCHOLI'),'2023-11-08','Ana: Envío correo a Rosa Bravo, CSS (rosamaria.bravop@salud-juntaex.es): "Adjunto, de nuevo, pues ya te los envié, a fecha de 24/10, los siguientes documentos: - Solicitud de Inclusión en lista de espera para biopsia vulvar - Consentimiento Informado a tal fin Relativos a FERMINA SERRANO MOCHOLI, firmados por la Vicepresidenta de la CTAEx."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-11-08','Ana: Llamada de José Manuel (627 788 797): Ha acudido a la MAP, le ha recetado una medicación financiada por la seguridad social para dejar de fumar. Ya la ha retirado de la farmacia. ·············· Por otra parte dice que está en lista de espera, de nuevo, para Fisioterapia. ·································· En cuanto a su asistencia a F. Sorapán de Rieros, dice que está contento. Participa en el Taller de Cocina el primer marte de cada mes. Y todos los martes a "Arte y expresión", taller en que está haciendo una cartera de cuero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-11-08','Amalia : escribo a los jurídicos y jefes de sección: Buenas , en el caso de Eduardo , veo conveniente comunicar al Juzgado la situación en la que se encuentra y la imposibilidad de poder ejercer el cargo asignado por el juzgado .       Si te parece en la comunicación que hagas , puedes copiar y pegar el email que os he enviado anteriormente , lo he hecho extenso para dejar constancia de toda la problemática . Incluida la económica , ayer mismo protagonizó una trifulca en la entidad bancaria , no acepta límite económico alguno y saca el dinero que va necesitando para comer al día ; le han robado varias veces en la calle y por eso no quiere tener encima mucha cantidad de dinero.       Podrías indicar también que no podemos solicitar un internamiento involuntario por lo que comentas al no disponer de informes médicos que lo avalen .        Eduardo se niega a ir al Centro de Salud ni al ESM ,no tienen conciencia de enfermedad ni tiene adherencia al tratamiento . He contactado con el Centro de Salud de la zona donde tiene instalada su tienda de campaña para solicitar que un médico se desplace hasta allí y pueda valorar su situación sanitaria , por si estuviese descompensado y activar 112 . Estoy esperando respuesta , iban a comentarlo al Centro de Salud de la zona de San Luis en Mérida ,que es dónde él tiene asignado su centro de salud , sigue empadronado en la casa de la madre a pesar de que hace años que no vive allí . Seguimos ..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-11-08','Miguel : no es posible solicitar internamiento : Buenos días, creo deberíamos de comentar estos dos casos, pues ninguno de los dos cumple el requisito de internamiento involuntario establecido en el art 763 LEC se denomina “internamiento no voluntario por razón de trastorno psíquico”. A mi entender, ninguno de los dos cumple dichos requisitos, pues no se puede aportar informes médicos, ante lo cual en caso de alteración de conductas sólo puede activarse el 112, y por tanto sólo nos queda desde la Comisión Tutelar remitir a modo de comunicación al juzgado un informe social (por la alarma social que supone el comportamiento y situación de cada uno)2.-Eduardo Caballero Paez: se quiere lo lleven a la UHB para que le hagan pruebas y le asignen un tratamiento. Aquí tampoco veo posible un internamiento involuntario. Lo único que podemos hacer, en mi opinión, es que la parte social elaboréis un informe lo más detallado posible y enviarlo a sus respectivos juzgados. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-11-08','Amalia ; escribo a todas las secciones para comunicar su fallecimiento . Buenos días , ha fallecido Mª Luisa Espinar del Arco , esta Sñra . estaba ingresada en R.M. Puente Real en Badajoz . Llevaba una semana ingresada en H.P.S . donde ha fallecido. Se está gestionando el sepelio , el seguro de decesos no incluía el nicho . Se va a comprar aparte , nos van a enviar pto. en torno a unos 600€ , tiene dinero . Julio , por favor , cuando puedes dar de baja en la base a esta Sra.. He solicitado cdo. decesos , cuando me lo remitan te lo paso. Sección eco , quedan por abonar facturas de la R. Mayores y el acompañamiento de estos días de hospital . Ya he pedido facturas y en cuanto se abonen se puede proceder con la declaración final de cuentas. Miguel , esta Sña . es la que hemos gestionado temas con Hacienda , acordaros, es la que hemos tenido tantos problemas con una de las pensiones de Alemania que Hacienda incluía como ingresos y desde Alemania insistía en que se ingresaba en una cuenta en la que no aparecía . Tiene sobrinos en Alemania y aquí en Badajoz . Sus pertenencias , incluida las llaves de su casa me las van a enviar a la Comisión . Desconocemos si ha dejado testamento , seguramente sí . Los sobrinos van a empezar a preguntar ,por eso os lo comunico a todos. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-11-08','Ana: Correo de Manuel - TO, Técnico PIA - EVD CC (manuel.casado@salud-juntaex.es): "Adjunto la ACEPTACIÓN PIA de JOSE BLAS CAÑAS LOZANO, con solicitud de centro residencial de discapacidad acorde a su perfil, con el fin de ser firmado y registrado, para procesar la petición." ·························· Subo el documento al portafirmas digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='BUENO'and apellido2='SANTOS'),'2023-11-08','REVISIÓN DE MEDIDAS JUDICIALES DE APOYO Mediante Sentencia n.º 87/23, de 25 de abril, dictada por el Jzdo. de 1.ª Inst. e Inst. nº. 2 de Mérida, se decretan medidas judiciales de apoyo nombrando Curador Representativo a la CTAEx.***************************************************Se procede a la modificación del procedimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-11-08','Ana: Mª Victoria Gía, Aux. Adtvo. EVD - Plas. (mv.garcia@salud-juntaex.es), me remite ACEPTACION PIA para MANTENIMIENTO DEL SAR + ANEXO INFORMATIVO OBLIGACIONES. ·················· Los subo al portafirmas digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='CRESPO'and apellido2='PEREZ'),'2023-11-08','Ana: Envío correo a Rosa Bravo, Adtvo. CSS (rosamaria.bravop@salud-juntaex.es): "Te reenvío citación judicial referente a la revisión de medidas judiciales de Angel Crespo Pérez. La cita es el próximo 18/12/23 a las 12:15 h. Confío en que no haya inconveniente en realizar acampamiento desde el centro. Confírmame cuando puedas." ······················· Respuesta de Rosa: "De momento creo que no tenemos ningún problema para acompañar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-11-08','Ana: correo de Belén, Sol Catering (belen@solcatering.es): "Tenemos servicio de cenas que se entregará igual que el de comidas, los martes al mediodía lo de toda la semana. Adjunto los modelos de cenas que tenemos disponibles actualmente, aunque van variando según la época del año. El precio es de 5€ /días, más 1,5€/semanal por gastos de embalaje y gestión." ································ Reenvío a Alberto, Jefe S. Ecca. para que me diga si es viable y si se aprueba.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-11-03','Ana: Llamada de Miguel Ángel, ya tiene nuevo teléfono y tarjeta (658 544 068): sigue viviendo en el piso Okupa. Dice que fue al TS de SSASB a solicitar la REAG. - Le informo que ya le aprobaron la PFHC (estimaron la reclamación), en cuanto comiencen a ingresársela le podrá hacer autorización de retirada de efectivo periódica. ······················ Por otra parte, dice que a partir de día 8/03/24, ya podría ir a su pueblo (finaliza la medida judicial) Pero a partir del día 9/03/24 tendrá que cumplir arresto domiciliario.....','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-11-08','EXITUS La fecha de fallecimiento queda a expensas de la recepción del Cº de defunción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-11-08','Buenos días Amalia, debemos comunicar tanto a sus entidades bancarias como al juzgado que corresponda el certificado de defunción cuanto te lo envíe la residencia. En cuanto a las pertenencias de ella no debe venir a la Ctaex sino permanecer en la residencia hasta que les confirmemos que hayamos remitido la rendición final de cuentas al juzgado, donde podrán pasar a por ellas quienes acrediten ser herederos. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-11-08','Ana: Estrella, S. Ecca. me confirma que el viernes Miguel Ángel podrá acudir a retirar su asignación semanal (80€/semana). Llamo a Miguel Ángel (658 544 068), para comunicárselo. Pero "el teléfono no está disponible". ····· Llamo al móvil de un amigo desde el que me llamó ayer (680 157 774): Su amigo me dice que no está ahora con él, pero que se lo dirá mañana cuando acudan al comedor. ·································································································································································································· Escribo a los A. Jurídicos: "Miguel Ángel Ramos Andrés, dice que tiene que cumplir ARRESTO DOMICILIARIO a partir del 9/03/2024. ¿Nosotros no tenemos información al respecto, no? Cuanto me llamó no tenía a mano el documento del Juzgado. No sé si hay alguna forma de averiguar algo más al respecto. Ya me decís cuando podáis." ································································································································································································ Respuesta de Ángel, A. Jurídico CTAEx: "En relación a esa ejecutoria 253/2022, se suspendió por 2 años la pena privativa de libertad, supeditada a que no volviera a delinquir. No obstante, como dice Miguel, mejor que nos envíen la resolución judicial a la que hace referencia, para tener certeza de a cuál se refiere."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-11-08','miguel, adjunto sentencia y ejecución de sentencia del procedimiento por quebrantamiento de condena, diligencias urgentes/juicio rápido 22/2022 donde le condenan hasta el 2027 a tratamiento médico. Envío email a Ana con copia a Angel: Hola Ana, creo que el motivo es esta sentencia, cuyo cumplimiento llega al 2027… A ver si te pueden dar algún dato más (jzdo, procedimiento…), pues el expediente está repleto de ejecuciones de sentencia, aunque creo que las demás ya están cumplidas. Ya nos dices…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-11-08','Ana: Tras llamada de Raquel, Res. Catalina Curiel, envío correo a Alberto, J. Secc. Ecca.: "En relación a la asignación de Flora Gutiérrez García, me acaban de llamar de la Residencia Catalina Curiel de Almaraz (927 544 085), lo de la transferencia no va a poder ser, lo han consultado en el Ayto. Así pues: Acudirán de forma presencial a retirar el reintegro acumulado cada 3 meses a la Oficina Bancaria de Navalmoral de la Mata. Cuando se les confirme que está hecha y enviada la autorización acudirán por primera vez este mes. Después en febrero y así sucesivamente en la horquilla de días que se le indique (por ejemplo del 1-15 o como veáis). Nos enviarán los datos de las personas que harán los acompañamientos a Flora a tal fin. Dado que las retiradas serán espaciadas, que se tienen que desplazar a otra localidad y a veces surgen dificultades en las oficinas bancarias, creo que sería conveniente que se le mande la copia de la autorización bancaria para que la tengan custodiada en la residencia y la lleven consigo cada vez que vayan al banco. La dirección de correo para remitírsela es: rvadillo@residenciacatalinacuriel.es En cuanto al taxi para ir a Navalmoral, aviarán unos días antes comunicando el desplazamiento y a posteriori, como siempre, remitirán factura con número de cuenta." ···························································································································· Por otra parte, Raquel también comunica que Flora necesita ropa, dado que según su última rendición Flora tiene dinero en su cuenta enviarán correo con presupuesto aproximado. ···· En Almaraz no hay tienda, lo adquirirán en el Mercadillo. Intentarán que les den al menos nota para justificar el gasto. ······························································································································································································· Envío correo a los A. Jurídicos: "FLORA GUTIÉRREZ GARCÍA, insiste en querer vender su vivienda de Badajoz. No sé si había iniciado algo o si requerís ponerlos en contacto con ella o con la responsable de la Residencia en que reside en la actualidad. Os facilito el contacto por si acaso: Residencia Catalina Curiel de Almaraz (927 544 085 // rvadillo@residenciacatalinacuriel.es)" ------------------------------------------------------- Miguel, mi contestacion a Ana y Angel: Hola Ana, necesito que hables con el centro donde estaba residiendo Modesta Garcia Piñero, madre de Flora, porque la notaria no contesta hace meses y tenían que haberles llamado a dos de los trabajadores para que asistiesen como testigos a la firma de la declaración de herederos de Modesta. Posteriormente las hermanas podrán firmar en una notaria de Cataluña las renuncias a la herencia. Ya digo, que está todo parado desde la notaria. He intentado que me contesten en varias ocasiones sin éxito. En la intranet está todo apuntado. Por favor, habla con el centro, creo que era el CSS de Plasencia y me dices,… porque si está firmado podremos continuar… ······························································································································································································ Respuesta de Ángel, A. Jurídico: "Flora tiene una vivienda en copropiedad con Modesta García Piñero. Ambas son propietarias, en pleno dominio, del 50%, respectivamente. Además, está hipotecada. Por lo que no puede venderla. Os envío nota simple del Registro de la Propiedad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-11-08','Ana: Correo del PAF (programafamilia@tajosalor.es) "hemos acompañado a Aitor a sacar el dinero para la ropa, a hacer la compra semanal y cuando hemos quedado para ir a comprar la ropa a Cáceres (lo acordado era que ellos cogían el bus y nosotras les esperábamos en Cáceres para acompañarles) nos ha dicho que de eso nada, que él iba a ir con un amigo y su madre se quedaba en casa. No hemos podido hacer nada, se pone súper agresivo. Está fatal. Se ha comprometido a traer los tickets pero sinceramente, no sabemos si lo hará, ni siquiera sabemos si comprará o se gastará el dinero en lo que quiera. En cuanto a la compra semanal os adjuntamos el ticket." ·································· Renvío el tique a la Secc. Ecca. ················ Respondo al PAF. Cuando podamos nos reuniremos Mayte, Teresa y yo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-11-08','Ana: Llama Felisi (614 361 144) con necesidad de hablar y desahogarse. Su hijo sigue hablándole mal "cuando se le va la pinza". Quiere volver a las clases de Arroyo de la Luz, pero en el PAF la han dicho que no hay buenas combinaciones de autobús. ··· Se lamenta de que en Casar tenía mejor vida que en su pueblo, porque tenía amigas de las clases. ············· Hoy Aitor no ha cumplido con el acuerdo del PAF, para ir con las profesionales a comprar la ropa a Cáceres. Se ha ido solo con un amigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-11-08','Ana: Correo de Diana, actual Directora de la Res. Ciudad Jardín - Parque del Príncipe (parquedelprincipe@grupociudadjardin.com): "Buenos días Ana, soy Diana me encuentro ahora en el puesto de Arantxa, quería comunicarte el ultimo altercado que hemos tenido con la familia de MARÍA JIMENEZ PICÓN; La semana pasada nos reclamo los dientes de su tía Isabel (la hermana de Maria) y nos acuso de habérselos tirado,cuando le conteste que ellas son las que se encargan de eso no nos dejan tocar nada, me soltó que la llave para el robo había salido de aquí, le dije que yo eso no tenia que hablar con ella...al llegar Daniel al centro le increpo en la entrada con lo mismo, paso al despacho y estaba fuera de si acusándonos otra vez que la llave había salido de aquí, Daniel le contesto que no le iba a permitir que siguiese acusándonos pero Ella no se retracto en ninguno momento, ya Daniel dijo que si Ella pensaba así no tenia nada que hablar con Ella. Solo te lo cuento a modo de información." ···································· Reenvío a los A. Jurídicos para su conocimiento y guardo en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-06-22','contestacion de Pilar de la notaria: Buenos días Miguel. Ellas pueden pedir cita en la Notaria que les convenga y hacer la renuncia. Tienen que hacer una escritura de RENUNCIA PURA Y SIMPLE Una vez firmadas que pidan que nos remitan copia electrónica a nuestro Notario (DON FRANCISCO DE ASIS JIMENEZ VELASCO o DON JUAN LUIIS MANCHA MORENO). Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-06-22','miguel, envio email a las hermanas de Flora: juanamaria_gutierrez@hotmail.com; modes.gutierrez@yahoo.es Buenas tardes, adjunto email de Pilar de la notaria de Plasencia. Para renunciar a la herencia de vuestra madre tenéis que acercaros a una notaria cercana a vosotras y que os preparen y firmad una escritura de RENUNCIA PURA Y SIMPLE. Una vez que lo firméis decidle que envíen copia electrónica a la notaria de Plasencia (DON FRANCISCO DE ASIS JIMENEZ VELASCO o DON JUAN LUIIS MANCHA MORENO). La factura del importe de dichas renuncias decidles que las remitan a ctutelar@salud-juntaex.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-06-22','miguel, contestacion de la hermana de Flora: JUANA MARIA GUTIERREZ GARCIA >juanamaria_gutierrez@hotmail.com> Hola. Ya fuimos a una notaría, y no lo aceptan. Nos exigen últimas voluntades o bien declaración de herederos, ademas de lo que usted nos envió. Estamos en un bucle. Atentemente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-06-23','miguel, envio email a la notaria de Plasencia (Pilar mplgonzalez@despacho.notariado.org) Buenos días, las hermanas de Flora Gutierrez Garcia conforme indican en el email de debajo no podrán renunciar a la herencia hasta que esté hecha la declaración de herederos en vuestra notaria, por lo que confírmame si se puede firmar ya dicha declaración de herederos. Creo que había testigos disponibles del centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-10-13','miguel, envio email a la notaria al no recibir respuesta sobre si se ha firmado o no declaración de herederos... mplgonzalez@despacho.notariado.org Buenos días, necesitamos saber en qué estado se encuentra esta herencia. En su día sus hermanas querías renunciar a la herencia, pero estaba pendiente de firmarse la declaración de herederos, está firmada ya? Si es así qué necesitan para proceder a formalizar la escritura de adjudicación de herencia que sería ratificada por esta Comisión Tutelar de Adultos. Les adjunto nota simple y en cuanto a las cuentas bancarias que dejó su madre fallecida Modesta Garcia Piñero eran: 1.- Era titular junto con su hija Flora de la Cuenta nº 0182 2874 070201531924 de BBVA en la oficina de Badajoz , cuyo saldo a fecha de 30 de diciembre de 2020 era de 16.691,19€ 2.- Era titular de la Cuenta nº ES39 2048 1150 4634 00021974 de Liberbank cuyo saldo a fecha de 25 de noviembre de 2020 era de 188€ Quedo pendiente de su respuesta. --------------------------------------------------- Se lo reenvío a Ana y Angel: Hola compañeros, he enviado email a la notaria de Plasencia a ver cómo van los trámites de la herencia la madre Modesta. Adjunto debajo email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='GARCIA'and apellido2='AMBROSIO'),'2023-11-08','TERESA ARCHIVO RESOLUCION DESESTIMATORIO DE REVISION DE GRADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2023-11-08','Ana Mariscal pregunta por el caso : te envíe por mail la sentencia de medidas de apoyo provisional de Manuela Plata Macedo, sé que ha pasado poco tiempo, pero me gustaría comentarte que la situación está empeorando. Cómo te comenté en un mes han fallecido dos hermanos y desde el mes de Agosto se fue a vivir una sobrina con ella por lo que la convivencia no está siendo buena para ambas. De hecho, en salud mental le han adelantado las citas para ajustarle la medicación. Te recuerdo que tiene SAD municipal y según nos manifiesta la auxiliar de ayuda a domicilio , están todo el día discutiendo y está repercutiendo de forma negativa que la sobrina viva con ella. En dos entrevistas mantenidas con ellas de manera conjunta en el despacho, la sobrina refiere que Manoli la acosa, la persigue y le quita dinero. Mi percepción es que no entiende que su tía tiene una discapacidad y trastorno por lo que le da voces continuamente y no la trata bien por lo que se está resintiendo en su comportamiento ya que yo la tengo en seguimiento y la veo todos los lunes, que es cuando voy a Gevora. La semana pasada, la vieron las compañeras del Programa de Familia de Poblados, tanto la psicóloga y la educadora y ambas también han comprobado que desde que la sobrina se fue a vivir con Manoli ha repercutido negativamente. Te recuerdo que sigue pendiente de valoración de CADEX, dependencia tiene un Grado I y desde salud mental se había propuesto que comenzara a asistir por las tardes a AEMIS. Si te escribo es porque me preocupa el caso ya que sé que ella pide dinero a la gente de la pedanía y a fecha de hoy 06 de noviembre solo tiene 180€ en el banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2023-11-08','-Amalia : escribo a Ana : Ya tiene expediente abierto y justo hoy día 8 se ha escrito al juzgado solicitando testimonio de la aceptación del cargo para poder empezar a intervenir . Indicanos tu direccion para solicitar I.social para inventario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-11-09','MEDIDAS JUDICIALES DE APOYO Mediante Auto n.º 163/23, de 19 de septiembre, dictado por el Jzdo. de 1.ª Inst. n.º 1 de Cáceres, se constituyen las medidas judiciales de apoyo para D. Ventura. Se concretan en una Curatela Representativa.**********************************Se cierra este expte. de defensa judicial y se mantiene, y se continúa su tramitación normal, el expte. numeral 21/T/2013.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-11-09','MEDIDAS JUDICIALES DE APOYO Mediante Auto n.º 163/23, de 19 de septiembre, dictado por el Jzdo. de 1.ª Inst. n.º 1 de Cáceres, se constituyen las medidas judiciales de apoyo para D. Ventura. Se concretan en una Curatela Representativa.**********************************Se cierra este expte. de defensa judicial y se mantiene, y se continúa su tramitación normal, el expte. numeral 21/T/2013.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-11-09','miguel, me preguntan desde el juzgado nº2 de Trujillo si está o no ya ingresada esta curatela representativa. Veo el apunte de Ana del 25-10-23 confirmando que está en la UME del CSS Plasencia. Me indica que la señora ha pedido abogado de oficio para impugnar la resolución judicial por lo que todavía no es firme por lo que quedamos pendiente cuando se resuelva el procedimiento de revisión de medidas para saber si continuamos o no ejerciendo su cargo. Traslado esta información a la parte social, jurídica y economica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-11-09','miguel, envío email a la parte económica, social y jurídica de la conversación telefónica con el jzdo º2 de Trujillo: Buenos días, acaba de confirmarme el juzgado nº2 de Trujillo que la resolución judicial del procedimiento de revisión de medidas es firme y que nos la envían mañana 10-11-23.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-11-09','Amalia : He recibido respuesta de la TS del Ctro. de Salud de San Luis , Eva . Ha hablado con la doctora de Eduardo . Lo vió en consulta en septiembre de este año , fue a solicitar recetas . Lo encuentra tranquilo , no da problemas , es por ello que no da lugar ningún internamiento . Si vive en la calle es porque quiere .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-11-09','miguel, llamo sin éxito a la notaria de Plasencia de Juan Luis Mancha Moreno, Francisco de Asís Jiménez Velasco 927-411447. Envío email a Pilar mplgonzalez@despacho.notariado.org; jlmancha@notariado.org; fdeasis@notariado.org: Buenos días, llevamos mucho tiempo intentando contactar con Pilar (vía telefónica, email) sin éxito con su notaria. Necesitamos que alguien se ponga en contacto con esta Comisión Tutelar de Adultos de una persona tutelada, Flora Garcia Gutierrez, porque necesitamos agilizar una herencia que llevamos meses sin saber si se firmó la declaración de herederos, previa necesaria a la herencia de su madre fallecida Modesta Garcia Piñero (y donde las otras dos herederas, hermanas de la tutelada, que viven en Cataluña, ya se pusieron en contacto con su notaria para renunciar a la herencia) Tenemos que saber si se ha firmado algo, necesitamos nos indiquen qué escritura se ha firmado, fecha, notario y protocolo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-11-09','miguel, recibo email de la abogada MARIA JOSE MARTIN MORENO >mmartinmoreno@icac.es> por el Proced. División Herencia 484/2019 Juzg. nº 2 de Coria: Soy Mª José Martín, la abogada de José Manuel y Juliana Moreno Carlos. Todavía continúa la tramitación del procedimiento de División de Herencia 484/2019 del Juzgado de 1ª Instancia nº 2 de Coria. El Juzgado ha nombrado contador partidor para la adjudicación de herencia, y ha pedido provisión de fondos 1548,80 € correspondiéndole a José Manuel abonar la cantidad de 516,26 € (adjunto la resolución) Dicha cantidad se tiene que consignar en la cuenta del Juzgado Banco Santander ES55 0049 3569 9200 0500 1274 Concepto: 1151 0000 42 0484 2019. Mi teléfono es 666753922. **************************************************** Tras hablar con la abogada, envio email a la parte económica, social y Angel: Buenos días, he recibido este email de nuestra abogada en el procedimiento que lleva al menos 2 años dando vueltas en el jzdo nº2 de Coria (huelga, 3 abogados de oficio lleva la parte contraria...) Os recuerdo que se trata de una herencia compuesta sólo por una vivienda donde los padres dejaron el uso y habitación a nuestro curatelado y su hermano lo impugnó, y al no llegar a un acuerdo la ley exige se nombre un contador partidor para asignar al hermano la legítima. Evidentemente el hermano no va a poder usar la vivienda en vida de nuestro curatelado que es quién tiene el derecho de usarla. Alberto: Necesito que hagáis el ingreso de 516,26 €, en la cuenta Banco Santander ES55 0049 3569 9200 0500 1274; Concepto: 1151 0000 42 0484 2019. Cuando la tengáis hecha envíame por favor el justificante de transferencia para enviárselo a nuestra abogada','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-11-09','miguel, recibo email de la notaria: Buenos días. El acta de herederos está pendiente de firmarse . Yo hable con una de las hermanas por telefono porque ellas querían renunciar a la herencia y les comente que tenían que ir a una Notaria a formalizar la renuncia, para que una vez hecha, solo se declarara heredera a Flora la hija. A fecha de hoy no hemos recibido las renuncias y consecuentemente no se ha iniciado el expediente, Si ellas renuncian ,la única heredera es Flora y por tanto es la comisión tutelar la que tiene que instar el requerimiento. Sin renuncian después las hermanas, tendria que hacer el requerimiento cualquiera de las hermanas de Flora. Yo había quedado a la espera de que las hermanas tramitaran las renuncias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-11-09','miguel, recibo email de Pilar de la notaria de Plasencia mplgonzalez@despacho.notariado.org> El acta de herederos está pendiente de firmarse . Yo hable con una de las hermanas por telefono porque ellas querían renunciar a la herencia y les comente que tenían que ir a una Notaria a formalizar la renuncia, para que una vez hecha, solo se declarara heredera a Flora la hija. A fecha de hoy no hemos recibido las renuncias y consecuentemente no se ha iniciado el expediente, Si ellas renuncian ,la única heredera es Flora y por tanto es la comisión tutelar la que tiene que instar el requerimiento. Sin renuncian después las hermanas, tendria que hacer el requerimiento cualquiera de las hermanas de Flora. Yo había quedado a la espera de que las hermanas tramitaran las renuncias. *********************************************** Me llama Pilar de la notaria de Plasencia y envío email a las hermanas de Flora (Juana y Modesta con lo que me pide) Buenos días, me indica la notaria que para hacer la declaración de herederos (pues no existe testamento) es necesario que le hubieseis enviado ya las renuncias de herencia hechas en cualquier notaria cercanas a vosotras. Recordad que es necesario que la declaración de herederos aparezca sólo Flora, por ser la heredera que quedará como única. Ese es el motivo por el que tenéis que enviarle antes la renuncia… El importe de dichas renuncias nos lo tenéis que enviar a la Comisión Tutelar de Adultos También tenéis que remitir a Pilar vuestros certificados de nacimiento (que lo podéis solicitar en cualquier registro civil cercano en Cataluña, aunque hubieseis nacido en Gipuzkoa País Vasco?) Y vuestra fotocopia del Dni por ambas caras. Os adjunto el email de Pilar de la notaria, y tenéis que remitírselo a ella. Por favor agilizad los trámites pues llevamos mucho tiempo y vuestra hermana se está impacientando. Me da fallos el email de Juana y no me deja enviarle el email, por lo que te ruego Modesta se lo comuniques.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-09','miguel, recibo email de la asesoría, Álvaro Domínguez >direccion@grupoteficon.es>;con copia a la abogada ANA IGLESIAS AVILA >anaiglesias@icac.es> y a la hermana del curatelado Carmen santos gp >maluker6@hotmail.com> Buenos días Miguel, He estado hablando con Carmen al respecto el tema que comenta de los seguros. Adjunto remito el certificado de registro de los seguros donde se detallan lo que comenté en emails anteriores: 2 seguros de accidente y 1 seguro de la Caixa (Adeslas). Pongo en copia a Carmen, hermana de Enrique. Su teléfono es 606 70 49 73. Ya le he comentado que lo suyo sería que se acercara a la Caixa para ver si existe alguna indemnización que tuvieran que cobrar por el fallecimiento de su madre. Que lleve el documento adjunto y le digan en el banco si procede. ******************************************************** mi contestación: Buenos días Carmen, mi nombre es Miguel, y pertenezco al gabinete técnico jurídico de la Comisión Tutelar de Adultos. La documentación que nos remite Alvaro no nos sirve porque es el certificado de últimas voluntades y de seguros donde figura un número de póliza y las aseguradoras, pero lo que necesitamos es saber el contenido de esas pólizas para lo cual alguno de los herederos tendría que solicitarlas y comprobar quiénes son los beneficiarios de las mismas. Tras eso, deberán indicarles en cada aseguradora los pasos a seguir (por ejemplo: aportar la escritura de herencia, firmar un documento privado por todos los beneficiarios indicando que están de acuerdo en el desbloqueo, y que el reparto se hará en la cuenta titularidad de cada uno (para lo cual tendrán que aportar seguramente certificado de titularidad de cada uno) En caso de que en alguno de los seguros aparezca beneficiario nuestro curatelado representativo, ruego nos lo comuniquen para tramitar conjuntamente con el resto de beneficiarios, el desbloqueo y reparto de lo que haya que repartir. Quedo a su disposición para cualquier aclaración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-11-09','Amalia : se adjunta PIA de Juana de los Remedios Palomo para registrar a Dependencia. Se ha pedido CO en Aprosuba 3 pq es donde hay plaza libre . El documento inicial de solicitud de centro por decreto no se llegó a enviar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-11-09','miguel, recibo contestación por email de la hermana de la tutelada, JUANA MARIA GUTIERREZ GARCIA >juanamaria_gutierrez@hotmail.com> : Buenos días. Como ya le comenté en mi último mail, consultamos en una notaría de Granollers. Nos dijeron que no podían hacer tal trámite si antes no había documento de últimas voluntades de nuestra madre o bien testamento. Nos vemos en un callejón sin salida. Tenemos preparado los certificados de nacimiento desde hace meses. Sinceramente no sabemos cómo hacerlo. Si ustedes encuentran alguna solución legal para nuestra renuncia no duden que esa es nuestra opción. Gracias por su dedicación. ***************************************************** miguel, envío email a Pilar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-09','miguel, hablo por tlfno (junto a Amalia) con Alicia (prima de Damian): se compromete a enviarnos a ctutelar la semana que viene un par de presupuestos de tasadoras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2023-11-09','miguel, llama el cuñado Alejandro (653770998) que ha hablado anteriormente con Angel. Nos enviará a ctutelar todo lo que tiene de los padres fallecidos de la tutelada. Insiste que el impuesto de sucesiones del padre cumple el mes que viene y que el de la madre está prescrito porque fallecio hace muchos años. Habló con la notaria de Fuente de Cantos de Teresa Moñino, con su oficial (924-500029), pero no ha entregado documentación todavía alli. Hay que hacer herencia de los padres fallecidos, y dos hermanos (1 premurió, y tiene un hijo y estaba divorciado; y 1h que murió soltero entre el fallecimiento de la madre y el padre) Quedamos pendiente de recibir la documentación que tenga para saber qué trámites hay que hacer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-10','miguel, Rocío Gracián me envía email: Te paso el teléfono de una tasadora de confianza. Es Agente de la Propiedad Inmobiliaria. Se llama Pilar Carril Barrientos. Teléfono 659514277','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-11-10','Buenos días, os adjunto domiciliaciones de josefa. El seguro de mutua madrileña está devuelto. era de un coche. Liberty. seguro de vivienda que se mantiene. Lo cambio a nombre de ella? Axa. me confirman que la póliza está anulada, he vuelto a pedir información.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2023-11-10','-Amalia : contacto via email con TS del ESM de Caceres para ir gestionando la solicitud de CRR .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2023-11-10','miguel, me llama Lorenzo, hermano del tutelado, 678731543, para comunicarme que la herencia se ha firmado el 8-11-23 en la notaria de Almendralejo de Inmaculada Molina Pilar. Envío email a Alberto y Tere, para solicitar información económica del tutelado a la parte económica y explicarles cuál es la situación: Buenos días, Alberto, necesito que me indiques el saldo actual de Adolfo y cuánto puede invertir en gastos de una herencia de su madre ya firmada el 8-11-2023 en la notaria de Inmaculada Molina Pilar. Su hermano Lorenzo tiene un abogado de confianza, Paco Vela de Villafranca, que va a tener que hacer muchas gestiones: Solicitar al juzgado la aprobación de la herencia y autorización de venta (en principio creo que de 2 fincas). Parece ser que la herencia no ha dejado liquido. En próximos días, llegará la factura de notaria, y yo tendré que ratificarla en Mérida. El impuesto de sucesiones ya se liquidó en 2020 cuando falleció la madre, pero quedan pendientes la plusvalía de la herencia y de la futuras ventas+ gastos notaria de la herencia y la futura venta+gastos de inscripción en el registro de la propiedad+tasación+honorarios de abogado y procurador, ibis, etc. Por otro lado Lorenzo su hermano acreditará en la escritura de venta, cuando llegue el momento los gastos que ha adelantado estos años para que sean descontados de la parte que tenga que recibir Adolfo. Ya le he indicado que todos los gastos de Adolfo nos lo envíen previamente, y las facturas a su nombre. Por otra parte, le he dicho a Lorenzo que le diga al abogado Paco Vela (de Villafranca) que inste al juzgado a que de oficio inicie el procedimiento de revisión de medidas de Adolfo conforme ordena la ley 8/21. Ya le he dicho que nosotros no podemos, y tiene que ser el juzgado de oficio. (Según me dijo este abogado es preciso antes de que aprueben la herencia, o ventas los juzgados de allí obligan a la revisión de medidas de apoyo, lo que tarden en hacerlo depende del juzgado). Quedo a la espera a que Alberto me indique qué ingresos, saldo y gastos tiene Adolfo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-11-10','-Amalia ; hablo con PFHC y con Jefe seccion IMV . Las 2 prestaciones son compatibles, lo que ocurrirá cuando casen datos es que IMV se va a disminuir no saben por cúanto quedaría . Como IMV tiene en cuenta los ingresos del año anterior , el montante de 4000€ que le han dado por PFHC no peligra para este año pero sí para el siguiente . Cuando casen datos se generará un cobro indebido . Para pedir que IMV se regularice lo antes posible ,casan datos en noviembre , y evitar que esté percibiendo los 565€ mensuales hasta entonces , tengo que remitir una declaración jurada en enero de 2024 a : INSS BADAJOZ DEPARTAMENTO DE RECLAMACIONES Y REVISIONES IMV Hacer una declaración jurada con sus ingresos durante 2023 y así lo regularizarían antes . Si no se hace ésto , ellos seguirán ingresando IMV con la misma cuantía y en Noviembre cuando casen datos nos enviarán un documento con el cobro indebido . Habría dos formas de abonarlo descontandolo de la mensualidad o haciendo un pago directo de la deuda en Tesorería. Seguramente le den de IMV la diferencia entre PFHC y ésa, unos 100€ al mes . Lo mejor es esperar a Enero , regularizar las pensiones , ver con cuanto se quedaría del montante de la PFHC y ya teniendo los datos actualizados subirle la asignación mensual. Si quedara dinero para pagar fianza de alquiler y quisiera compartir piso con alguien se podría gestionar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTIAN'and edp.apellido1='CARRASCO'and apellido2='BLANDON'),'2023-11-10','Ángel: Asistimos a la declaración que se le ha tomado a Cristian en el Juzgado de Zafra (DPA 685/23). Reconoce que tuvo relaciones sexuales con la menor, Daniela del Carmen. Fueron consentidas. Él pensaba que podían mantenerlas porque no era ilegal, a partir de los 13 años es cuando no se podía. Han dictado orden de alejamiento a menos de 200 metros y a no comunicarse con ella por cualquier medio. A partir de hoy se va a vivir con su tía, en Monesterio, porque en el domicilio familiar no puede quedarse, al ser vecino de Daniela. He hablado con la madre, va a empezar a buscarse otro piso de alquiler donde pueda vivir con su hijo. Queda pendiente la celebración del juicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-11-10','Buenos días. En el copia y pega del expediente que os hemos enviado hay dos notas simples del registro de la propiedad de la vivienda, la cual es la que José María quiere vender. Hay también un informe social en el que se explica la situación de la vivienda (propietarios, deudas, etc.). También os hemos enviado una copia de testamento de la herencia en la que se dice quiénes son los propietarios y en el manifiesta que José María es el principal heredero. No tenemos conocimiento que exista ningún comprador. Desde la Entidad estuvimos investigando acerca de las deudas y la documentación que tenemos os la hemos enviado. El motivo de que no tengamos más información al respecto es debido a que Futuex se iba a encargar de este caso, ya que iban a ser sus representantes por comisión tutelar. Cualquier cosa en la os podamos ayudar nos decís. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-11-10','miguel, mi respuestas a la parte económica y la social (Alberto, Maites y Amalia) y Angel: Buenos días, en el email viene una nota simple, no dos, de Manuela Moya Cordero (madre del curatelado?. Se trata de la nota simple del rgtro de la propiedad nº1 Badajoz, C/ Santa Marina nº1, (suponemos nº52 según testamenteo)Bajo, Izquierda, Badajoz. Desconocemos que otros bienes pueda tener la herencia, (más viviendas, cuentas….) y qué deudas pues hay procedimientos de ejecución judicial…deudas con el Oar… Dejó dos hijas: Isidora, Mª Isabel. Por el testamento se desprende que: “con cargo al tercio de mejora, y si con este no bastase, con cargo al tercio libre de disposición, lega a su nieto José Maria el piso…, sustituyéndolo para el sólo caso de la premoriencia por la madre del legatario, Doña Maria Isabel Rodriguez Moya, a quien sustituye,…,por sus descendientes. Instituye herederas universales por partes iguales a sus hijas Isidora y Mª Isabel, con derecho de sustitución para sus respectivos descendientes en caso de premoriencia y el de acrecer en su caso” Al tratarse de una curatela que únicamente requiere por sentencia nuestra asistencia, entiendo que no necesitamos abogado y solicitud de autorización de venta judicial. Por tanto, la decisión más lógica teniendo en cuenta la complejidad de la operación (legado, herencia, localización de bienes, y de documentación, y posibles deudas), de hacer la herencia, y preparar la venta, lo suyo es delegarla en un abogado o gestoría previo presupuesto. Alberto: necesito saber qué ingresos, gastos y saldo actual dispone este curatelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2023-11-10','-Amalia : hay que hacer solicitud de centro por decreto ( plaza residencial ) +Informe de HOFA indicando que pierde la plaza en menores para que sea emergencia social + informes del CEE y se lo entrego a Maribel Mesa . No tiene Gº dependencia reconocido , bajó del 1 al 0 . Acude a CEE Los Angeles incluido residencia de L a V . Los FS se va a pisos HOFA en Badajoz . Quieren que dejemos ya esa plaza . Regina tiene 19 años , el proximo abril cumpliría 20 . En el CEE puede estar hasta los 21.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-11-10','tf Ana . 686753132 No quiere trabajar con ella ,a veces va y le ayuda por caridad . Pepa tiene miedo a las noches sola , teme que entre en la casa Fco. Este señor trabajó con su marido , Ana piensa que les robó . Habría que pedir Aut. judicial de internamiento involuntario en R. M .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTOS'and edp.apellido1='GARCIA'and apellido2='ESTEBAN'),'2023-11-09','Ana: Envío a Julio, CTAEx, ACEPTACION PIA para MANTENIMIENTO DEL SAR + ANEXO INFORMATIVO OBLIGACIONES, para que le dé REGISTRO de ENTRADA a Sección de Dependencia V - PLASENCIA - BUZÓN de Registro A11030404','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-11-09','Ana: Envío a Julio, CTAEx, la ACEPTACIÓN PIA dcon solicitud de centro residencial de discapacidad acorde a su perfil, para que lo remita por REGISTRO a la GERENCIA TERRITORIAL DE CÁCERES - CÓDIGO REGISTRO SIREX: A11030403','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-11-13','Ana: en relación al correo de Mónica, Ed. PP.SS. (educacion.pisosplasencia@grupo5.net) del día 6/11, proponiendo cambio de compañía de telefonía y a un contrato de prepago, le reenvío la respuesta de Alberto: "NO CREO QUE DEBAMOS AUTORIZAR DOMICILIACIÓN...LUEGO COMIENZAS LAS LLAMADAS DESDE LAS COMPAÑIAS PARA UN NUEVO MÓVIL, NUEVAS TARIFAS, MÁS GIGAS...YA SABES. ESTA PERSONA TIENE DINERO, A DÍA DE HOY. QUE BUSQUEN OTRA COMPAÑIA QUE TENGA PREPAGO Y MEJOR COBERTURA (NO SE, JAZZTEL, VODAFONE, MOVISTAR...)... EL TEMA DEL SEGURO NO SE COMO FUNCIONA, PERO SE PUEDE PAGAR UN SEGURO A TODO RIESGO DE UNA VEZ PARA 3 AÑOS O MÁS" ·································································································································································································· A petición de Miguel, A. Jurídico, consulto a Rosa Bravo, Adtvo. CSS-Plas. si llegaron a ir como testigos 2 trabajadores/as del CSS, para la firma de la Declaración de Herederos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-11-13','Ana: Llamada de Miguel Ángel (658 544 068): dice que ahora está en Badajoz, que se ha ido porque los compañeros del piso Okupa se querían quedar con su dinero, que de hecho le han robado parte del mismo. ··· *De momento está en SITUACIÓN DE CALLE. ··· Acudió al Albergue de Cáritas (C/Bravo Murillo) pero no hay plazas, le han puesto en lista de espera. ······· Dice que acudirá al Comedor Social de la C/ Martín Cansado. ······························ *Pido a Estrella, Secc. Ecca., que envíe la Autorización Bancaria para retirada de asignación semanal a la oficina de Unicaja de la Avda. de Europa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-11-13','miguel, respondo a Ana, copia a Angel: Buenos días, se trata de una hipoteca a 10 años desde el 2002, y por tanto ya cancelada económicamente, finalizó en 2012. Era de la entidad UCI (los conozco, cuando llegue el momento les diré que emitan el certificado y hagan los trámites de la cancelación registral) Estoy a la espera a ver que se decidan en notaria de Plasencia (las hermanas no pueden renunciar en Cataluña si no se firma antes la declaración de herederos y la notaria de Plasencia pide se firme antes dichas renuncias. Estamos intentando la tercera vía, que es que se requiere dicha declaración de herederos por su tutor, y pasado un plazo legal dicha declaración de herederos sería plenamente eficaz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-11-13','miguel, reenvío a la abogada justificante d etrasnferencia de la provisión de fondos del contador partidor solicitada: Buenos días Maria José, te adjunto justificante de transferencia solicitado de la provisión de fondos del contador partidor del procedimiento de División de Herencia 484/2019 del Juzgado de 1ª Instancia nº 2 de Coria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-13','miguel, recibo email de Enrique Perianes (abogado) porque el juzgado nos da 10 días para subsanar la falta de presentación de la tasación. Pongo email a Alicia Cuetos (la prima de Damian)Alicia Cueto >aliciaasimas@gmail.com>: Buenos días Alicia, necesitamos que rápidamente en menos de 10 días esté tasada la vivienda porque me ha comunicado esta mañana el abogado, que el juzgado da 10 días para subsanar la falta de presentación de la tasación. Es por eso que necesitamos nos mandes dos presupuestos y sobre la marcha decidamos qué tasador va a tasarla. Confirmame antes del jueves ambos prespuestos, para evitar tener que gestionarlo desde aquí. Por otra parte me han recomendado a esta tasadora por si quieres preguntar también Pilar Carril Barrientos. Teléfono 659514277','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-10','miguel, recibo email de Enrique Perianes (abogado) Buenas tardes Miguel. Te mando diligencia de ordenación del Juzgado mandando subsanar la demanda en el sentido de aportar una valoración del inmueble. Es un proceso habitual, que ya te adelanté. Nos dan diez días. No tengo idea del procedimiento que seguís vosotros para buscar un perito que valore las fincas. Si entiendes que en diez días no es posible valorar por un perito el inmueble, me lo comentas y lo intento buscar yo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-11-13','TERESA En relación a Marta me gustaría comentarte algunas novedades: 1. Se ha independizado con su novio, lleva con él desde este verano aproximadamente y aparentemente está bien. El novio con su padre fueron a casa de la madre para hablar con ella y para ayudar a Marta a recoger todas sus cosas. Y en principio existe una relación cordial entre todos. Ahora la dirección es C/SILVA de Cabeza del Buey. 2. Se inscribió a un curso de peluquería y estética de Mancomunidad de municipios de la Serena, y la han seleccionado junto a otras dos compañeras del centro ocupacional. El curso se va ha llevar a cabo en Monterrubio de la Serena, una localidad cercana que está a unos 30km, en principio de 8:30h a 14:30h. Mañana viernes día 10, va junto a sus compañeras y una monitora de nuestro centro, a una reunión inicial, donde le darán más detalles. También estamos valorando posibles medios para que se desplace hasta Monterrubio, cuando tengamos más información os cuento. 3. A su abuela le dio un ictus y estuvo ingresada en el hospital un tiempo. Ahora ya está de vuelta en su residencia habitual, le han quedado secuelas, pero dentro de lo que cabe está bien. El tiempo que ha estado la abuela peor, Marta lo ha pasado mal. Ha faltado algunos días porque iba al hospital a quedarse con ella, o ha visitarla, y lo hemos entendido perfectamente y esas faltas las hemos considerado justificadas. Ahora que ya ha vuelto todo a la normalidad, Marta acude al centro como siempre, todos los días y realiza sus actividades sin problema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-11-13','TERESA Nos ha llamado Felisi muy nerviosa porque al parecer Aitor el sábado le pegó a Jesús (que parece ser que ha vuelto con Felisi), nos dice que quiere ir a denunciar a Aitor para que se vaya de casa porque ella no puede seguir así, según nos cuenta hay voces continuamente, golpes, puñetazos en las paredes, insultos… Lo ponemos en vuestro conocimiento para que toméis las medidas oportunas, si es que se puede hacer algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-11-13','TERESA A Reme le han dado el alta. La pila aún no la ha expulsado pero sigue teniendo un buen progreso y se espera que en la próxima deposición o la siguiente la expulse, según las imágenes que se observan en las ecografías. Hay que vigilar que sea así aquí en la entidad. Ante cualquier contratiempo o pasados 7 días sin expulsarla, hay que acudir al hospital de nuevo. Esperemos que no haya que acudir de nuevo al hospital, ante esa posibilidad…se queda ya sin acompañamiento? o Podría costearse “algo”? Creemos que sigue habiendo mucho riesgo de que vuelva a ingerir en los próximos días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2023-11-13','TERESA Buenos días Pues la llave no aparece Como hay que cambiar el bombín vamos a esperar a que se incorporen las educadoras del programa de apoyo que nos han dicho que contaremos con ellas en diciembre Igual la educadora sabe dónde está la llave pues la última visita acompaño la educadora al hermano de Antonio. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-11-13','Ana: Envío a Julio, CTAEx, para que remita por REGISTRO a la Secretaría de SSSS, Inclusión, Infancia y Familia, el ALTA DE TERCEROS que nos habían solicitado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-11-06','Ana: Correo de Carolina, Directora CRR-Plas. (direccion.crrplasencia@grupo5.net): "• Isabel realizó la retirada de dinero extra para el movil y ya se lo compró. Es consciente de que ya no realizará viajes al pueblo en lo que queda de año. Es probable que sea su madre la que venga (asumiendo su madre el gasto). En la última semana ha verbalizado en diferentes contextos la percepción de aumento de peso y la preocupación por esto, refiere que vomita en ocasiones. Estamos trabajando sobre ésto"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-11-06','Ana: Correo de Carolina, Directora CRR-Plas. (direccion.crrplasencia@grupo5.net): "• Ceferino, le entregamos la carta con la penalización por la tarjeta. Consciente de que el pago del hotel durante la expulsión también es de sus extras, por lo que no le queda dinero. Respecto a la denuncia del trabajador no os la puedo hacer llegar porque es a nivel personal e información confidencial. No creo que llegue a trámite según le informó la policia al trabajador. No obstante si tengo más información os la haré llegar. Como sabeis solicitamos el traslado de oficio, a mi no me han confirmado nada aún pero él verbaliza que el SEPAD le ha dicho que será en menos de 10 días."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-11-09','Ana: Raquel, Enfermera Secc. Acceso RR. Salud Mental entrega a Maite la Resolución de concesión de plaza en CRR de Olivenza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-11-13','miguel, contestación de Alberto (parte económica): MIGUEL: • SALDO HOY: 36.469,10 € • INGRESOS: PN ORFANDAD ABSOLUTA: 832,80 € X 14. • OTROS INGRESOS: GRUPO SIFU SIFU EXTREMADURA: 366 €/MES (CALCULADO EN LOS ÚLTIMOS 5 MESES YA QUE SON IMPORTES MUY IRREGULARES EN SU CUANTÍA). • GASTOS MENSUALES APROXIMADOS: AMALIA: LOS GASTOS SON SUPERIORES A INGRESOS...HABRÍA QUE VER EL PORQUE!!! • SITUACIÓN ECO (MIGUEL): TIENE SALDO SUFICIENTE PARA ASUMIR GASTOS ASOCIADOS A LA TRAMITACIÓN DE LA HERENCIA-VENTA...PERO MEJOR SI CONTAMOS CON PRESUPUESTOS PREVIOS. LOS AJUSTES ECO QUE HAYA QUE HACER YA SON COSA DE AMALIA Y MÍA. AMALIA: • OTROS INGRESOS GRUPO SIFU EXTREMADURA: AMALIA: ENTIENDO QUE PODEMOS CONTAR CON ESTOS INGRESOS COMO ALGO PERMANENTE....EL CÁLCULO DE LOS MISMOS DURANTE LOS ÚLTIMOS 5 MESES DA UNA MEDIA MENSUAL DE 366 €/MES---ESTE INGRESO ES EL QUE HACE QUE LOS INGRESOS SEAN SUPERIORES A LOS GASTOS (SI NO CONTAMOS CON ESTE INGRESO HAY QUE HACER AJUSTES). • HAY QUE AJUSTAR COSTE CENTRO PORQUE NO ME QUEDA CLARO: ENTIENDO QUE LE COBRAN TAMBIÉN LAS PAGAS EXTRAS...PERO NO HAY FORMA DE SABER CUAL ES LA MENSUALIDAD: 575...624...842...X 12...X 14...NECESITAMOS SABER CON EXACTITUD EL COSTE DEL CENTRO EN CÓMPUTO MENSUAL Y ANUAL.----IMAGINO QUE VARÍA TANTO PORQUE TENDRÁN EN CUENTA LOS INGRESOS DE GRUPO SIFU. Valor Observaciones Importe 05/06/2023 AEXPAINBA 837455 00076 -575,63 04/07/2023 AEXPAINBA 837455 00076 -1.137,56 01/08/2023 AEXPAINBA 837455 00076 -624,60 12/09/2023 ASOC EXTRE837455 00076 -624,60 20/10/2023 ASOC EXTRE837455 00076 -842,40 • FUNDACIÓN MAGDALENA MORICHE: LE COBRAN DESDE SIEMPRE 90 €/MES: 2 CUESTIONES: o ES NECESARIO MANTENER ESTE GASTO? o ESTE GASTOS SI PUEDE MANTENERLO AHORA...PERO SI LOS INGRESOS DE NÓMINA GRUPO SIFU DESAPARECIESEN YA NO PODRÍA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2023-11-13','Amalia : remito informes a PIlar Martin ESM para la busqueda de recurso: siguiendo con la línea del email que te envié la semana pasada , se adjuntan informes del Centro Penitenciario Psiquiátrico de Sevilla para la búsqueda de recurso residencial para personas con enfermedad mental ante la externalización de Gustavo prevista para febrero de 2024. A este chico se le está atendiendo desde ese Equipo. Como te comenté , a dado un sin grado en dependencia . Quedamos pendiente de la respuesta . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-11-13','-Amalia : en respuesta a email de Alberto que envía su ficha de ingresos y gastos le expongo : Buenas , efectivamente de momento sigue con ese contrato laboral , del que se entrega el 50% al centro según marca el decreto de ingresos en centros. De las pensiones se abona por copago de la plaza el 75% de lo que percibe , pero tienen en cuenta los ingresos de las 14 pagas . Los ingresos son superiores a los gastos , hay que tener en cuenta los ingresos por trabajo que se mantienen. Los 90€ que se abonan , es por ser socio de la entidad , gracias a ese abono tiene acceso entre otros servicios a orientación laboral y búsqueda de empleo . Se tienen que seguir abonando . Si dejara de trabajar , anularíamos esa cuota . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2023-11-13','-dIRECTOR CRR: Esta mañana ha estado en el CRR la policía nacional, concretamente de la unidad de atención a la familia y mujer, para solicitarme información sobre Almudena y la relación que pueda tener con Miguel Angel, no me han dado mas información sobre el motivo de la visita, sin embargo, entiendo que no es por una denuncia sino un simple aviso, tal vez del a través del 016. Su objetivo ha sido recabar información para valorar un posible abuso sobre Almudena. Tras darle la información muestran su apoyo y ofrecimiento a apoyarnos en caso de que podamos detectar alguna evidencia de que pueda haber en torno al abuso para poder interponer denuncia. Un saludo y buen fin de semana','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-13','miguel, recibo email de Maria Granada (exabogada de la inquilina) Buenos días Miguel. Nada, esta mujer no me cogió el teléfono en la mañana del viernes. Luego me llamó y me dijo que no. Me pareció raro que no me preguntara nada más yo supongo que algo tiene en la cabeza....o ganar tiempo. Yo le dije que al final la iban a echar y no sería muy tarde. Pero no me dijo nada más. Esta mañana han ingresado a mi marido en el hospital. Acabo de llegar y me vuelvo ahora otra vez, si necesitas algo, dímelo, que te contestaré cuando llegue a casa. La cita esta semana me temo que no podrá ser. Lo siento mucho. ---------------------------------------------------------- miguel, email de Enrique Perianes: Buenas tardes Miguel. Llámame sin problemas cuando quieras (615104594). Los procesos de ejecución de resoluciones arbitrales se deberían minutar por el criterio 119.2, (50 % de la escala), pero seguro que llegamos a un acuerdo. Mañana le llamaré... --------------------------------------------------------- mi contestacion a Maria Granada: Hola Maria, ya me lo imaginaba. Estamos hablando con un abogado y estamos perdidos con el tema de honorarios. Cual es el tope mínimo que crees que podemos pedir por tramitar la ejecución del laudo, teniendo en cuenta que no disponemos de capacidad económica (ya que seguimos pendientes de saber el resultado de la aseguradora de Jorge Calvo)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-11-13','miguel, llamo a Mª Jesús, porque estamos pendientes de si ella consigue el presupuesto para cerrar el escrito de contestación al ayto sobre que opcion elegimos para la ejecución de la obra ruinosa. La llamaré el miercoles y con lo que sea cerraré el escrito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-11-10','Amalia : registrado a a Dependencia de Zafra el PIA de Fco. Casillas .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='MARQUEZ'and apellido2='CABEZA'),'2023-11-13','El pago de 701,31 es por el día que entro, más el mes que lo pasamos del 1 al 5 de cada mes, pero la cuota de él será todos los meses de 685,21 y lo que le queda de copago todos los meses para el son 97,89. También puede ser que algún mes se le pase el recibo de farmacia que no le entre por la seguridad social, de algo que necesite y no se le cubra, pero lo normal será que se le pase solo la cuota de la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2023-11-13','-Amalia : reenvío al CRPS la documentación que nos han remitido firmada para que inicie tto. allí . Irá desde el CRR en bus .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-11-13','TERESA Hola Tras visita a Zalamea para ver a Pablo hemos acordado 1, con el establecimiento DIA: ira una vez por semana a hacer la compra, la supervisara el encargado para que haga una compra adecuada y mensualmente nos pasara los tiket para que abonemos por transferencia. Le hemos puesto de limite semana 70€ 2, Con el estanco: ira una vez por semana a recoger una tarrina de tabaco de liar, la forma de pago se hará a través de la educadora del programa de apoyo en vistas de que en diciembre vamos a contar con ella y es la forma que acepta el estanco. Le hemos puesto un limite de 13€ semanales 3, la recarga del móvil que son 5€ al mes la venia haciendo la educadora, vamos a seguir igual 4, hasta que contemos con la educadora se anulan los reintegros, una vez contemos con ella habrá que hacer un reintegro mensual para pagar el tabaco, la recarga de teléfono y el tema de la bombona será a cada cierto tiempo pues solo la usa para cocinar no usa el calentador. Con respecto a ir a un centro en unas ocasiones manifiesta que se quiere ir y en otras no…. el problema es que como consume alcohol es complicado que nos lo acepten en mayores que es el único sitio que podemos solicitar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS CARLOS'and edp.apellido1='FRADE'and apellido2='PARRA'),'2023-11-13','-Amalia : Para el carnet de conducir , Angel dice que la sentencia de incapacitación no se lo prohíbe. Tiene una discapacidad del 65%, con trastorno mental, esquizofrénico residual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-11-14','miguel, recibo email de Pilar de la notaria: Buenos días Miguel, le he enviado un email a Juana para que pidan los certificados de nacimiento y me los envíen.- Las copias de los Dni ya las tengo. Quedo a la espera de me respondan. ***Quedo a la espera que Pilar de la Notaria me avise para firmar la declaración de herederos en Plasencia****','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-13','miguel, email de Mª Granada: Esta señora es que tiene MUCHA cara. Yo le planteé lo que era no deber esa cantidad..........pero supongo que como nunca va a tener nada a su nombre.....le da igual. Una profesional, vamos. Respecto al tema de honorarios.....si me indicas en qué estáis perdidos intentaré responderte. Al ser un tema particular, el abogado puede establecer sus honorarios libremente con vosotros....siempre que los aceptéis. Ya sabes la importancia de hacer bien una hoja de encargo. Yo tengo un amigo de mi plena confianza, si quieres le pregunto cuánto llevaría. Si es de mi parte hará buen precio. Siempre lo ha hecho, y es muy profesional. Pero no digo nada, sólo te lo ofrezco por si no os cuadra ninguno. Según los honorarios del ICABA saldría mi minuta, pero eso para el propio cliente es una barbaridad. Un mínimo no te puedo decir porque el precio es libre, y hay de todo. Yo preguntaría a la Aseguradora, pues algo ya deben contestar. Ya que veo que Jorge ha desconectado de vosotros. ************************************************** Otro email de Mª Granada: Por cierto....creo que lo mismo lo que quiere es acceder a las ayudas que pone la diligencia que le dieron junto a la demanda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTIBALIZ'and edp.apellido1='MENDEZ'and apellido2='CARRASCO'),'2023-11-14','-Amalia : registro petición de documentación al CADEX , se lo pasaré a la Luz .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-14','miguel, respondo a Maria Granada: Buenos días Maria, muchas gracias por tu información. El abogado de tu confianza te diré si hace falta pues estoy a la espera de que otro abogado me de presupuesto. Por otra parte necesito tramitar una herencia y una posterior venta, documentación tengo poca y necesito un abogado y/o gestoría para tramitarlo que se ajuste en presupuesto en Badajoz, me recomiendas alguno en concreto? Te lo diría a ti pero imagino que va a ser poca cuantía y mucho trabajo pues buscamos entre 1.000 y 1.500€ en gastos por tramitar el total de la operación (recabar documentación, firmar en notaria herencia, liquidación de impuesto de sucesiones, posterior aprobación judicial de la herencia, y recabar documentación para solicitar autorización judicial de venta y tramitación de procedimiento judicial)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-11-13','miguel, recibí ayer emails de la Abogada Eva, Eva Mª. Pérez Escarmena >eperezescarmena@icac.es>, solicitando haga el poder para la procuradora para el miercoles 15-11-2023. La llamo y comento que en próximos días, en cuanto me de cita Marta la secretaria de la gerente, firmaremos el poder apud acta. Tambien me comenta que han arreglado el tejado y la exmujer del tutelado está adelantando dinero al constructor para los arreglos más urgentes (y entre ellos han llegado al acuerdo que cuando nosotros estemos autorizados al gasto extraordinario y paguemos al constructor, éste arreglará cuentas con la exmujer del tutelado)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-11-13','Ana: Correo de Diana, actual Directora de la Res. Ciudad Jardín - Parque del Príncipe (parquedelprincipe@grupociudadjardin.com): "acaba de venir la policía Nacional al centro porque la sobrina de Isabel Jimenez y María Jimenez ha denunciado a un compañero por, según ella, malos tratos a sus tías. Como comprenderás esta situación se esta volviendo insostenible aquí en el centro para todos , ya esta afectando a compañeros que vienen a hacer su trabajo lo mejor posible y se encuentran con esto. No se hasta que punto puede denunciar ella en nombre de María, cuando sois vosotros los que tenéis la tutela de ella. Te escribo a modo de información,y por si vosotros tenéis que hacer algo respecto a este tema." ······································ a los A. Jurídicos CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-11-14','miguel, hablamos Amalia y yo con Carlos del jzdo de 1º instancia e instrucción nº2 de Zafra, que está conociendo del procedimiento de Internamiento Involuntario de la tutelada, que se encuentra en la Morera actualmente residiendo, y por tanto el jzdo nº4 de Badajoz se inhibió. El actual procedimiento es ITR 666/23 (proced origen del jzdo de 1º instancia e instrucción nº4 de Badajoz, Medidas Cautelares 802/23)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-11-14','miguel, email que reenvía Ana de Rosa del CSS de Plasencia Rosa Maria Bravo Pacheco >rosamaria.bravop@salud-juntaex.es>: Buenos días Ana: Lo de los testigos de Modesta García Piñero estamos esperando que nos aviséis. Iban a ir la Trabajadora Social y alguien más. Ya me dices ************************************************ mi contestación a Ana y a Rosa del CSS: Buenos días, me ha escrito esta mañana Pilar de la notaria de Plasencia de Don Juan Luis Mancha Moreno y Don Francisco de Asís Jiménez Velasco, tlfno 927-411447 e email mplgonzalez@despacho.notariado.org, por si os queréis poner en contacto con ella directamente. Va a preparar la declaración de herederos para lo cual queda pendiente que las hermanas le remitan sus certificados de nacimiento. Parece ser que el retraso se ha debido a que las hermanas que están en Cataluña y quieren renunciar a la herencia, no las dejan firmar dichas renuncias hasta que no se firme en Plasencia la Declaración de Herederos. Mientras Pilar de la notaria de Plasencia, estaba esperando a que primero se firmaran dichas renuncias de herencia de la madre (Modesta). Finalmente las renuncias a la herencia se hará después de firmar la declaración de herederos, cuya fecha de firma no se sabe hasta que no tenga toda la documentación la notaria y puedan asistir los testigos. También tendremos que ir desde la Comisión ese día a ratificar dicha Declaración de Herederos, según me dijo Pilar. Por tanto cuando tenga toda la documentación Pilar entiendo que nos avisará para que pasemos a firmar los testigos y la Comisión Tutelar de Adultos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2023-11-14','EXITUS Según su certificado de defunción, el fallecimiento tuvo lugar el 06/11/2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-11-14','-Amalia , escribo a Rosa : nos encargamos nosotros de comprobar que te ingresaran ese dinero ( dependencia ) . Si fué así , haremos el pago del cobro indebido que te reclaman .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-11-14','Ana: Estrella, TS CSS: Guadalupe acude bastante a su despacho. Le ha dicho que quiere hablar con la CTAEx y pedir un abogado para que le suspendan el internamiento. ······· Está comiendo bien y ha cogido algo de peso. ······ No tiene conciencia de enfermedad ni de la situación en la que vivía, ella no lo ve como un problema. ············ Estrella le ha explicado qué es un CRR y la conveniencia de que tras el CSS ingresara en el mismo, pero ella no quiere. ············· Le preocupa que se está haciendo amiga de Enrique Santos Gía-Puente y éste la insta a quejarse, poner reclamaciones... ·················· Intentarán llamarme para que hable con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-11-14','Ana: Llamada de José Manuel (627 788 797): Ya le ha llegado la nueva cita del Juicio, 17/01/24 a kas 10:00 h. ···················· Hoy va a retirar el dinero autorizado para los productos de limpieza y las sábanas (50€). Petri, Aux., no le va acompañar, dice que es mejor que invierta el tiempo en limpiar la casa, que está muy sucia. ························· **Ya ha dejado de tomar las pastillas para dejar de fumar, dice que no puede dejar el tabaco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-11-14','Ana: Llama desde el teléfono de un amigo. Dice que necesita ropa. Pedirá presupuesto en un sitio barato y lo enviará a través de la TS del Comedor Social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2023-11-14','Ana: Llamada de Jose: la dueña del hotel no quiere poner la calefacción, por lo que él pone el radiador que se compró el año pasado todo el tiempo que necesita. ············· Han vuelto al hotel de Inspección de Turismo y van a cerrar otras habitaciones. ·············· Cuando vuelva el programa de Futuex, pediré que la Educadora le ayude de nuevo a buscar otro hostal/pensión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-11-14','Ana: llamada de Sole, TS Comedor Social - Hijas de la Caridad de BA (681 246 337). ······· Ha tenido hoy la primera entrevista con Miguel Ángel. ····· Éste le ha dicho que su idea es volver a su pueblo (Aliseda) cuando finalice la medida de alejamiento que tiene hacia su madre, que será en marzo. Hasta entonces quiere estar en BA. ········· Han acordado que acudirá al Albergue de Emergencia Social de Caritas (C/ Bravo Murillo) a las 17 h. ·········· La asistencia a este recurso es requisito previo al posterior ingreso en Centro Hermano - Cáritas. ··········· Como le ha dicho que está sin medicación, le ha dicho que acuda directamente a Urgencias del Hospital, para que le vea un Psiquiatra y puedan ajustar tratamiento y recetarle lo correspondiente. ········· Sole dice que se nota el conocimiento y manejo que tiene de todos los recursos sociales y sanitarios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2023-11-14','Ana: correo de Sheila, Directora del CRR -CC (crr@grupociudadjardin.com) al ctutelar@: "Buenos días, tras realizar las extracciones de las piezas dentarias y dentro del trabajo orientado a la higiene y cuidado de salud bucodental, procedemos a trasladar dos presupuestos para la adquisición de la prótesis dentaria de la persona usuaria Martin Miguel Miranda Hernández."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-11-14','-Amalia : nos informan que la tienda de campaña ya no está en la calle . Le llamo por tf. para averiguar y no tenía idea de eso.Se está quedando en un local de ocupa , dice que solo . No desvela el sitio .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-11-14','Ana: Corro del PAF (programafamilia@tajosalor.es) "Adjunto remito los tickets justificantes de la compra de ropa de Aitor. Como veréis, de los 200€ que le ingresasteis solamente ha gastado unos 120, los otros 80 dice que lo ha gastado en caprichos: comprar golosinas, montar a caballo…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-11-14','Ana: Correo de Miguel, A. Jurídico CTAEx: "mañana se hará una vista para tratar los gastos extraordinarios del arreglo del edificio del tutelado. Me pide la abogada que le enviemos algún informe que indique que el tutelado no está en condiciones de ser trasladado al juzgado para declarar. Puedes conseguir algún informe del centro que acredite su situación personal y enfermedad?" ·········································· Tras llamar a Gema, Directora Residencia Cedillo, envío correo-respuesta a Miguel: "Acabo de hablar con la Directora de la Residencia. Para empezar, me dice que desde que Julián Ramón ingresó en su centro hasta ahora, ha mejorado mucho su estado de salud al recibir los cuidados y atenciones que necesitaba. A día de hoy no tendría ningún impedimento físico para desplazarse en taxi hasta el Juzgado correspondiente. Por otra parte, a nivel cognitivo él está bastante bien y podría acudir en este sentido también a la comparecencia sin problemas. En cuanto a informes, el más reciente que tienen es del Equipo Salud Mental de febrero del 2020, no es reciente. Y no hay ni pueden conseguir más informes para mañana a primera hora. En la propia residencia, al ser pequeñita tampoco tienen Médico propio ni Trabajadora Social. Pero como digo, Julián podría acudir al Juzgado. Si finalmente se aplaza la vista, dímelo para que se pueda llamar un taxi con tiempo y organizar el traslado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-14','miguel, envío email a Enrique Perianes (se ha cortado la llamada): Del otro expediente de ejecución del Laudo de Carmen Leal, necesito veas a cuánto puedes ajustarte en presupuesto porque pese a que el laudo habla que se le deben 29.000€ a la tutelada en aquel momento(+el tiempo transcurrido a fecha actual) y que la inquilina se va a declarar insolvente…pues la hemos tanteado a través de ex abogada contraria que ganó el caso (lleva perdidos contando con los honorarios de las partes+ arbitro cerca de 10.000€) y no le va a quedar casi capacidad económica a nuestra tutelada. Ya intentamos, abogado de oficio, que nos fue denegado, en el 2º intento de ejecución (al que nombramos por el artículo 28 de la ley de asistencia gratuita al mismo abogado que nos representó en la primera, y al que tuvimos que ordenar que desistiese del 2º procedimiento, pues seguía cometiendo fallos esenciales en el procedimiento que te comentaré por teléfono, como es la incorrecta interposición de la demanda de ejecución, pues puso a la tutelada en vez de a la Comisión Tutelar de Adultos en nombre de Carmen Leal). Es por eso que necesitamos abogado de confianza ajustado a presupuesto porque la inquilina ya ha dicho a su ex abogada que no quiere llegar a un acuerdo, ni abandonar la vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-14','miguel, tras recibir dos presupuestos de Alicia la prima, la envio email para que solicite presupuestos de tasadores o me indique si éstos estarían visados. Llamo a Pilar Carril pilarcarril12@gmail.com> 659514277, que me había recomendado Rocio Gracian y me dice que sí me puede enviar mañana el presupuesto, asi que le envío la información catastral, nota simple, etc. ********************************************** Llamo a Enrique Perianes para explicarle todo lo anterior pero se corta, le llamaré mañana a las 9h: Del expediente de Damian, me tienes que confirmar si te serviría la tasación hecha por la agente de la propiedad inmobiliaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-15','miguel, recibo email de Álvaro Domínguez >direccion@grupoteficon.es> Buenos días Miguel, ¿Se firmó correctamente las escrituras en Mérida tal y como estaba previsto? Entiendo que está todo bien. Por otra parte, por el tema del vehículo llegaron a un acuerdo el resto de los hermanos de vender el vehículo que aparece en la herencia a un concesionario, el cual ha aceptado el trato. Para el cambio de titularidad sólo se puede realizar a una única persona y se tomó como heredera legítima a María Carmen Santos García Puente. Es por ello que necesitamos la renuncia por parte de Enrique a dicho vehículo para proceder al trámite del cambio de titularidad en Tráfico. Luego, una vez que se realice la venta del vehículo (creo recordar que sería de 8.000 €), ingresarían a partes iguales la parte de cada uno de los herederos por parte del concesionario (vamos a intentar que sea así), si no fuera el caso se lo ingresarían a Carmen y ella realizaría las transferencias a cada uno de sus hermanos. Eso ya lo veríamos. Así pues, envío en documento adjunto de la renuncia por parte de Enrique para que me la firme en su nombre. ------------------------------------------------------ Mi contestación con copia a la hermana Carmen santos gp >maluker6@hotmail.com> y la abogada ANA IGLESIAS AVILA >anaiglesias@icac.es>: Buenos días, varias cuestiones: 1.- Necesitamos nos remitan copia de la escritura para saber qué se ha firmado (junto nos indiquen persona de contacto y teléfono en la notaria para cualquier necesidad que tengamos a la hora de ratificar de Mérida). 2.-La factura de la notaria (y de cualquier otro trámite como es inscripción del registro, etc) la parte del tutelado tendrá que venir a su nombre. 3.-Antes de firmar la renuncia, necesitamos un documento de quién vaya a recibir el ingreso y a favor de quién se ha producido el ingreso, indicando que se compromete al ingreso de la parte que corresponda a favor del tutelado y en qué plazo. 4.-Seguimos esperando las pólizas de los seguros para saber los beneficiarios y en qué han quedado para el desbloqueo y reparto de dichas cantidades. En cuanto tengamos esta información hablaremos con la notaria de Mérida para preparen la ratificación, tal como ya indicamos en los anteriores emails.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-11-15','Ana: envío a Marisa Olivera, TS ESM - Coria (maria.olivera@salud-juntaex.es): "Aquí tienes el Consentimiento de Derivación a Recurso Residencial, relativo a Julia Morón Hernández, firmado digitalmente por la Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-11-14','Ana: Llamada de Marisa, TS del ESM - Coria (70858): Están en su despacho Julia y su padre. Quiere solicitar de nuevo ingreso en CRR, como no tiene grado de dependencia reconocido, lo solicitarán por emergencia social. ······ La ve tranquila y estable. ········· Me enviará el Consentimiento de Derivación a RR. Residencial para la firma por la Representante Legal. ······················ *Próximas citas: Psiquiatría: 21/11/23 y Enfermería: 21/11/23. ····· Le informo de que la Ed. del Prog. Apoyo - Futuex, no podrá acompañarla. Hasta diciembre no entrará de nuevo en funcionamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2023-11-15','Ana: Llamo a Teresa, Novaforma (662 337 460): Felipe está dispuesto a vender la casa, pues sólo le trae disgustos cada vez que alguien abre la puerta y entra. Además sólo suele ir una vez al año, no le merece la pena. ············ Harán un documento por escrito que firmará Felipe, expresándolo, y se lo enviarán a Ángel, A. Jurídico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-11-15','Ana: Llamo a Teresa Nogueira, Novaforma (662 337 460): Ya le ha avisado Maribel, TS Secc. Acceso RR. Discapacidad: conceden a Juanjo plaza en Fuente de Cantos. ·············· Acordamos que se lo comunicarán ellas a Sara y a la cuñada. Con Juanjo hablarán en persona en el C.O. para exponérselo con calma y apoyarle en este proceso de cambio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-11-03','Ana: Llamada de Estrella, TS CSS Plas: Guadalupe ha dicho que de tener que ingresar en algún centro aceptaría que fuera en la residencia de mayores cercana a su pueblo, pero creen que LO HA DICHO SÓLO PARA QUE LE DEN EL ALTA. Ella quiere regresar a su casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2023-11-03','Ana: Llamada de Fco. desde el teléfono de un amigo. Dice que se quiere ir a Londres. ····· *Cuesta bastante entenderle, no es habitual. Le pregunto si ha consumido algo, expresa "no te voy a mentir, de ven en cuando me fumo un porro". ······· Me comunica las próximas citase en el ECA: el día 19 con el Médico y el día 9 con la Psicóloga. Quiere hacer tto. ambulatorio para que le dejen ver a su hija. ·················· Al preguntarle de nuevo por el consumo dice que cuando le hagan la analítica "si queda algo será residual".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-11-13','Ana: Correo del PAF (programafamilia@tajosalor.es): "Nos ha llamado Felisi muy nerviosa porque al parecer Aitor el sábado le pegó a Jesús (que parece ser que ha vuelto con Felisi), nos dice que quiere ir a denunciar a Aitor para que se vaya de casa porque ella no puede seguir así, según nos cuenta hay voces continuamente, golpes, puñetazos en las paredes, insultos… Lo ponemos en vuestro conocimiento para que toméis las medidas oportunas, si es que se puede hacer algo." ··································· Respuesta de Teresa, TS CTAEx: "Lo ideal es que denuncie a ver si si el juez hace algo porque ya ves el caso que nos hacen desde la comisión" ························· *Respuesta del PAF: "Pues sí, sería lo suyo. Nosotras no podemos acompañarle, al estar tutelada no nos lo permiten. No sé como lo hacéis otras veces." ··························· Respuesta de Teresa, CTAEx: "No entiendo porque no os dejan que la acompañéis ya que nadie puede poner la denuncia por ella. Nosotros no podemos denunciar por ella ya que es un acto personalísimo que solo puede hacer la persona, independientemente de su situación jurídica ya que es ella la que tiene conocimiento de los hechos que ocurren. En otros casos acompaña la trabajadora social y no han tenido problema no sé porque ahí o dicen eso… y mas tratando de una persona con discapacidad…. Podría acompañarle Jesus? Nosotros podemos volver a comunicar una vez más la situación al juzgado pero ya ves que no da ningún resutado…. Ya me dices si finalmente pone la denuncia" ···································· *Teresa solicita a los A. Jurídicos que llamen al Cuartel de la Guardia Civil para que permitan a Felisi interponer la denuncia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-15','miguel, contestación de Alvaro de la Asesoría y Ana Iglesias (abogada)con copia a la notaria Marta Iglesias Rivera (Notaria) >mirivera@despacho.notariado.org> y a mi: 1.- Necesitamos nos remitan copia de la escritura para saber qué se ha firmado (junto nos indiquen persona de contacto y teléfono en la notaria para cualquier necesidad que tengamos a la hora de ratificar de Mérida). El viernes, 10 de noviembre, cuando se firmó las escrituras lo enviaron directamente desde la notaría de Plasencia al email que solicitó en emails anteriores a la notaría de Mérida. No obstante, pongo en copia a Marta, Oficial de la Notaría de Plasencia que realizó dichas escrituras para cualquier cuestión. 2.-La factura de la notaria (y de cualquier otro trámite como es inscripción del registro, etc) la parte del tutelado tendrá que venir a su nombre. Sí, la factura de notaría serán individuales por cada heredero, según comentamos durante la firma del viernes 10 de noviembre con la oficial de notaría. 3.-Antes de firmar la renuncia, necesitamos un documento de quién vaya a recibir el ingreso y a favor de quién se ha producido el ingreso, indicando que se compromete al ingreso de la parte que corresponda a favor del tutelado y en qué plazo. Está pendiente de lo que he comentado en el email anterior: o el concesionario realiza a partes iguales a cada uno de los herederos o si se lo ingresan a su hermana Carmen, ella posteriormente realizaría las transferencias. Carmen, por favor, contacta con el concesionario para ver cómo lo quieren hacer al respecto y dependiendo de lo que digan, pues procedemos. Completamente de acuerdo en que se debe redactar un documento, o bien con Carmen o bien con el taller, para poder vender. 4.-Seguimos esperando las pólizas de los seguros para saber los beneficiarios y en qué han quedado para el desbloqueo y reparto de dichas cantidades. Ya comuniqué a Carmen este tema y lo tienen que ver directamente con ella. Nosotros únicamente tenemos los certificados de los bancos que es lo que hemos incluido en la herencia. Carmen al estar en copia de estos emails, esperamos que nos reenvíe toda la documentación. ------------------------------------------------------------ Mi contestación: Buenos días, quedamos pendientes entonces a la contestación de Carmen: -Cómo se va a proceder en la cuestión del desembolso de los seguros. Necesitamos ver las pólizas. -En cuanto al vehiculo, necesitaremos ver el documento de encargo al concesionario para saber el precio de venta, qué importe corresponde al tutelado y plazo en que se va a proceder a la venta. En cuanto a la ratificación, independientemente de que la escritura se halla enviado a la notaria, la Comisión Tutelar necesita verla previamente antes de ir a la notaria con lo que insisto que se me remita a este email copia de la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-11-15','Ana: Correo de Ana Montaña Álamo, Residencia Riolobos (alamoseras@gmail.com): "soy Montaña compañera de Ana Setien, comentarte que después de varios días de comportamientos extraños en José Manuel se ha decidido mandarlo a urgencias con el resultado de ingreso en el ala de psiquiatría del Hospital Virgen del Puerto de Plasencia a día de hoy. Ha sido acompañado por una de las personas que se dedican a estos extras, y le ha acompañado en el traslado de la ambulancia, aparte de las horas que ha permanecido en el servicio de urgencias, ha tenido que tomar un taxi para regresar a Riolobos. Te envío las dos declaraciones juradas del día 3 y la de hoy. Mi número de teléfono es 615470728, por si necesitas alguna aclaración." ····························· Reenvío las declaraciones juradas a la S. Ecca. para que abonen ambos acompañamientos: Urgencias y Consulta de Enfermería-ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-15','miguel, informo a la parte social y económica: Buenos días, os informo y dejo en la intranet todo. Se ha firmado ya la herencia que estaba pendiente del curatelado representativo Enrique Santos Garcia Puente, procederé a ratificarla lo antes posible Quedan dos cuestiones: -La venta de un vehiculo -El desbloqueo y reparto de unos seguros. De ambas cuestiones no tengo información, con lo que estoy a la espera que la hermana de Enrique, Carmen, me envíe la documentación, pues sólo me ha mandado documento para la renuncia del vehículo, lo cual no me cuadra, pues tenía que ser documento de venta…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-15','miguel, envío nuevo email a la Alvaro (Asesoria), Ana Iglesias (abogada) y su hermana Carmen: En cuanto al vehículo veo que se lo va a adjudicar Carmen y por tanto tendrá que abonar la parte correspondiente a cada hermano. Si se fuera a hacer venta en un taller o concesionario se haría una compraventa no una renuncia. Quedo pendiente se nos indique cuál de las dos opciones se ha elegido y cómo se procederá el pago y porqué importe a Enrique.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-11-15','Ana: Correo de Gema Morato, Directora de la Res. Grupo Asoma - Cedillo (gemamg.asoma@gmail.com): "Adjunto remito la declaración jurada del acompañamiento que ha realizada a Cáceres una compañera de la Residencia de Cedillo con Victor Manuel Blanco Poveda para que se le haga la transferencia. Adjunto las tarifas por acompañamiento a residentes que tenemos establecida en la residencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2023-11-15','Ana: Llamada de Pilar y Jesús, su pareja (613 33 66 47): El día 27 tienen cita de nuevo con Ana Benavente, TS ESM. *Aún no tienen cita con la nueva Psiquiatra. ····· De momento siguen viviendo en CEREZO. ········· Pilar manifiesta tener miedo de su madre, teme que si se la encuentra en el banco en Plasencia ésta le vaya a pegar, pues quiere su dinero para ella. Dice "me tenía engañada como una niña". ·················· *La semana que viene volverán a llamar para confirmar en qué oficina de Unicaja sacarán el dinero a partir del día 27 (cuando Pilar ya haya cobrado) para que las compañeras de S. Ecca. envíen la autorización.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-15','miguel, comunico vía email a la prima Alicia que ya hemos contratado una tasación: Buenos días Alicia, ya hemos encargado la tasación por importe bastante inferior a tus presupuestos. En principio nos comentan que no hace falta visitar la vivienda. Te vamos informando si hace falta alguna cuestión. ------------------------------------------------ Recibo email de la tasadora Pilar Carril, pilar carril >pilarcarril12@gmail.com> Buenos Dias, primero agradecerle la confianza y en segundo lugar , mi forma de proceder es provisión de fondos de la totalidad del informe en la cuenta ES692103 0182 12 003005529 Y aproximadamente a la semana del ingreso, si tengo verificación les mando todo el dictamen , por correo a portes debidos o mediante e- mail o ambos. No es necesario, la visita de la vivienda salvo que existan reformas importantes a considerar A la espera de sus noticias ------------------------------------------ Envio email a la parte económica: Buenos días, necesito que hagáis el ingreso lo antes posible de 450€ a este número de cuenta ES692103 0182 12 003005529 y en concepto: finca 6497 rgtro Málaga 15, Damian Granados, si no cabe todo poned el nombre de Damian. Enviadme justificante','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='LEAL'and apellido2='PARRA'),'2023-11-13','-Amalia , me escribe Taciana , psiquiatra UHB. Solicita que firmemos el documento para derivación a CRR .De momento está ingresado a la espera de pasar a UME. Le contesto : Fco. Javier es una curatela reciente , el cargo se ha aceptado el 23 de octubre. Puedes remitirme por email el documento a firmar para poder solicitar la derivación a CRR y te lo reenvío firmado . Hablé con la TS de la localidad y el caso es complejo . Según sentencia el médico forense establece que padece esquizofrenia , consumo de cannabis e inteligencia límite . La TS verbalizó en el juicio , que el chico no tiene adherencia a tto. ,se lee literalmente en la sentencia que " escucha voces que le dicen que mate a su padre y a él " . Se une a todo ello un entorno familiar nada favorable , el padre es toxicómano. Tiene 65% G.D. Y un Gº II de dependencia . Ya ha tenido otros ingresos en CSS de Mérida. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-11-15','miguel, pongo en portafirmas el recurso a la resolución por obra ruinosa del Ayto de Piedras Albas, donde incluyo el presupuesto que me envía la vecina afectada y perito, Mª Jesús. En él solicito la ejecución subsidiaria por la falta de capacidad liquida del curatelado (pocos ingresos y ahorros). El importe del presupuesto del albañil que sólo recoge algunas actuaciones a realizar es de casi 18.000€. Lo enviaremos mañana pues nos dieron 15 días hábiles para contestar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-11-15','Ana: Llamada de Javier (641 086 409): dice que quiere irse a Mataró. Que buscará allí una habitación, pedirá la tarjeta sanitaria y el médico. ···· Tras razonar con él, acordamos que 1º ingresará en el CRR de Mérida, ya le han aceptado el ingreso, pero ha de esperar a que quede plaza libre. ···· Una vez esté adaptado al recurso se podrá comenzar a plantear y organizar bien el traslado con el apoyo de los profesionales del centro.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-11-15','Ana: Llamada de Javier (641 086 409): dice que quiere irse a Mataró. Que buscará allí una habitación, pedirá la tarjeta sanitaria y el médico. ···· Tras razonar con él, acordamos que 1º ingresará en el CRR de Mérida, ya le han aceptado el ingreso, pero ha de esperar a que quede plaza libre. ···· Una vez esté adaptado al recurso se podrá comenzar a plantear y organizar bien el traslado con el apoyo de los profesionales del centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-11-15','miguel, envio email a la parte económica y la social: Buenos días, en el expediente/propiedades e intranet dejo explicado el expte de obra ruinosa. Mañana que cumple el plazo de 15 días que nos dio el Ayto de Piedras Albas para que decidamos en demoler o rehabilitar y ante la falta de capacidad liquida del curatelado, intenté a través de la vecina afectada que es perito obtuviese un presupuesto de un albañil, que me ha llegado esta mañana de cerca de 18.000€ para el arreglo de lo más urgente. Ya he puesto a la firma y enviaremos mañana la contestación a la resolución de la alcaldía indicando que no elegimos ninguna de las opciones sino que solicitemos que lo hagan ellos mediante una ejecución subsidiaria. Lógicamente le acredito el informe de la parte económica, las propiedades catastrales que tiene y el presupuesto del albañil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-11-13','Ana: Llamada de Ana Benavente, Javier ha estado en su despacho. De nuevo quiere marcharse a Mataró. ········ Por otra parte, ya tuvo lugar la subcomisión y han aceptado el ingreso de Javier en CRR - Mérida. Ahora debe espera a que quede plaza. ··········· A acordado con Javier que me llame el miércoles. Está muy suspicaz, por lo que no le diré nada de la conversación con Ana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-15','miguel, envio email a Amalia y Alberto: Hola, ya tenemos dos posibles abogados para solicitar de nuevo la ejecución del laudo para desahuciar a la inquilina, a la cual como ya os comenté intentamos se fuese por las buenas y se ha negado. Estoy negociando con los abogados el importe de honorarios y necesito saber cuál es el tope que tenemos teniendo en cuenta que está pendiente de si tenemos que abonar los aproximadamente 4000 a 5000€ de nuestro exabogado. Os recuerdo que le hice reclamar a su seguro de responsabilidad civil por su negligente actuación y sigo a la espera de sus noticias. Amalia, entiendo que debes de comentarlo a la tutelada...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-11-15','Ana: Llamada de Sergio (640 654 89): dice que en el centro está "más o menos". Está esperando por la solicitud que hizo en el ESM de plaza en CRR. Le explico que estos procesos llevan tu tiempo y ahora debe tener paciencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-11-15','Ana: Llamo a Felisi (614 361 144), distintas veces a lo largo de la mañana, sin éxito. Da todo y después se corta la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2023-11-15','Amalia : Me llama por tf Gloria de PFHC . Tienen que dar de baja la Prestación actual que está a titularidad de su hermano Damián . Como es trimestral no perderá esos meses de cuantía que se abonarán en la nueva cuenta que se le ha facilitado . Tenemos hasta 31 diciembre para presentar o bien la PFHC con el cambio de titularidad si se ha recibido la sentencia nombrando a la CTAEX . O en otro caso , tienen que hacerla desde el CSS Mérida como guardador , si no llega la sentencia para que en Enero del 24 pueda percibir de nuevo la PFHC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-11-15','miguel, recibo email de la vecina Mª Jesús MARIA JESUS GARCIA MARTINEZ >mjgarciamar@gmail.com> Hola Miguel, Ya he conseguido abrirlo, es que en el móvil no lo podía ver. Tienes que contar que falta la gestión de residuos, que eso es en función del escombro que salga, puede variar entre 3.000-5.000€. A ver si conseguimos que esto se pueda ejecutar. ------------------------------ Mi contestación: Perfecto, adjunto tu email junto al presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2023-11-15','Ana: Llamo a Ana Triguero - Res. FEMAR (605 89 01 24) , en relación a la carta de precios y la subida de precios que tendrá lugar a partir de 2024, pues Valentina no puede asumir esta subida (Usuarios con dependencia grado II: 1.480€): No le llega con sus ingresos para abonar la plaza con este coste. De prestación vinculada sólo percibe 124€7mes. Ana me informa que *otros usuarios que perciben la prestación vinculada mínima perciben 175€. ····· Consultaré en Dependencia mañana. ············ Después llamaré a Ana Triguero o a Pilar, Directora de la Res. FEMAR (639 585 489)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2023-11-15','miguel, está citado para revisión forense mañana 16-11-23, Tere me envía email indicando que no cree que vaya a asitir y me envía un email de puño y letra donde el curatelado asistencial está descompensado. Envío email a Inés con copia a Tere: Hola Inés, en relación a la citación que tiene Tomás Carvajal mañana con el Forense pon un oficio al juzgado indicando: “ el Tutelado está descompensado, no podemos asegurar la asistencia a su citación con el Forense. Adjuntamos documento remitido por el mismo a la trabajadora social de la Comisión. Solicitamos que si lo estima oportuno este juzgado dicte de oficio las medidas que considere oportuno para asegurar la asistencia del tutelado cuando se le precise, como puede ser la intervención de los cuerpos de seguridad del Estado”','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-11-15','miguel, nuevo email de la vecina Maria Jesús: Hola Miguel, Ya he conseguido abrirlo, es que en el móvil no lo podía ver. Tienes que contar que falta la gestión de residuos, que eso es en función del escombro que salga, puede variar entre 3.000-5.000€. A ver si conseguimos que esto se pueda ejecutar. ------------------------------------------ La envío email: Perfecto, adjunto tu email junto al presupuesto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSE'and edp.apellido1='MOLINA'and apellido2='SALAZAR'),'2023-11-15','-Amalia : sigue ingresada en CSS Merida. Se envia modelo alta 3º a PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-11-15','-Amalia : La ayuda para alquiler de vivienda que se le solicitó no será aprobada por falta de presupuestos para estas ayudas ,se agotaron en abril de 2023. Se le pide que vaya buscando otra solución ,no tiene para pagar el alquiler . Me comenta que hay una amiga que estaría dispuesta a que viviera con ella . Comunicaremos ya a la dueña la baja en el alquiler para que en diciembre se marche. Hablo con la TS del comedor social ,no la va a volve a aceptar allí por su falta de respeto al gritarle. Cree que los alimentos se los tiene que proporcionar la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2023-11-16','Ana: Tras llamar a Pilar, Directora de la Res. FEMAR (639 585 489) envío correo a Alberto y Lourdes, S. Ecca.; A. Jurídicos; y Maite, Jefa CTAEx.: "En relación a VALENTINA FERNÁNDEZ TREJO, residente en la Residencia de Mayores FEMAR de Logrosán desde 2005, sin más apoyos familiares ni sociales de ningún tipo, presenta discapacidad intelectual y ocupa una plaza privada. Percibe: - P. Orfandad Absoluta: 832,80 € x 14 PAGAS - P.F.H.C.: 453,30 € x 12 - Prestación económica vinculada al servicio: 150 € x 12 (Es lo que le corresponde según su grado – II) Hemos recibido carta de la residencia con la subida de precios correspondiente al próximo año 2024 ( Usuarios con dependencia grado II: 1.480 euros) Y aunque a día de hoy le llegaría, justito, para abonarlo, para el resto de gastos personales habría que tirar de ahorros (que tampoco son muy elevados) con las consiguientes consecuencias). *Ni en el centro ni en la sección social consideramos conveniente cambiarla de residencia y sacarla de su entorno. Ha vivido en esta localidad toda su vida y en el recurso lleva cerca de 20 años. Considera a los profesionales del recursos y a otros residentes su familia. Pues además desde que falleció su padre no tiene a nadie más. *Aunque está pedida desde hace tiempo plaza pública en el mismo centro, al tener grado II es más difícil de acceder, pues son pocas plazas y tiene prioridad quienes tienen grado III. Ángel y Miguel, en su día creo que ya abordamos este asunto. La Herencia no debe estar hecha, pero le corresponde como herencia la vivienda familiar ubicada en Logrosán (en la que entraron okupas en su día) y una cerca. ¿Podría hacerse la herencia y poner a la venta ambas propiedades?? Para la cerca en la residencia conocen un posible comprador. Para la vivienda podrían preguntar." ·········································································· *Respuesta de Ángel, A. Jurídico: "En la Nota simple del Registro de la Propiedad de Logrosán, indica que le vivienda sita en Calle Horno, 5, de esa localidad, pertenece al 50%, al padre y a Valentina. Habría que hacer la herencia del padre y luego la venta. Me pongo con ello…" ······························································································································ Respuesta de Alberto, Jefe S. Ecca: "EN LA NUEVA SITUACIÓN LOS GASTOS SON SUPERIORES A LOS INGRESOS...ES CIERTO QUE, SI LOS GASTOS SON SIMILARES A LOS DE LOS ÚLTIMOS 12 MESES, ESA EVOLUCIÓN NEGATIVA VA A SER PEQUEÑA (-700 €/AÑO APROX.). TIENE SALDO SUFICIENTE PARA SOPORTAR ESTA NUEVA SITUACIÓN, PERO EN MI OPINIÓN NO ES LO DESEABLE."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-11-16','-Amalia : contacto con Gracia , está organizando ella el tema de la lápida , la familia se ha desentendido . Me va a enviar documentación que va a llevar allí la prima . La poliza de seguro cubre la comunicación al INSS de la pensión. Yo voy a enviarlo por email a la dirección de Alemania también .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-11-16','Ana: correo de Sara, TS R.M. Banium Residencial (TrabajadoraSocialBanium@hotmail.com): "notificamos citación medica recibida en el día de hoy para la usuaria Concepción, con dni 00361205-J. Deberá acudir con acompañamiento privado el próximo día 21 de noviembre a las 12:20 al Hospital Virgen del Puerto citada por el servicio de Radiología para continuar con las revisiones pertinentes tras las IQ de cadera. No podemos calcular el importe ya que no sabemos a que hora recogera la ambulancia a la usuaria ni cuanto durará la consulta y el retorno." ····························· Pido a las compañeras de S. Ecca. que miren la situación económica y respondan a Sara. ···························· Respuesta de Lourdes, S. Ecca. a Sara: "...puede asumir el acompañamiento para el hospital del día 21 de noviembre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-11-16','miguel, envío email a la abogada Eva Eva Mª. Pérez Escarmena >eperezescarmena@icac.es> Buenos días Eva, que tal la vista de ayer? Se suspendió? Te confirmo que el martes día 21-11-23 firmaremos el poder apud acta a favor de tu procuradora poder a favor de la procuradora Doña Asunción Pacheco Ponciano N.º colegiada 104 del Colegio de Cáceres Dime si lo ponemos dirigido al de primera instancia que corresponda de Valencia de Alcantara, procedimiento de solicitud de gastos extraordinarios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-14','miguel, recibo email de Maria Granada: Buenos dias Miguel. El abogado se llama Juan Pablo Serrano Muñoz. Teléfono 646740735. Espero que sea de tu agrado. Yo tengo plena confianza en él. Por la cuantía conmigo no vas a tener problema nunca. La minuta que pasé en su día fue alta porque era para la parte contraria. Te aseguro que no es problema conmigo. Yo llevaría este asunto, pero es que con mi marido hospitalizado no me encuentro capacitada para coger un asunto nuevo, porque me gusta hacer todo bien y dándolo todo. Espero que haya otra oportunidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-11-16','-Amalia : reenvío por email a la dirección que nos facilitan para el cdo. de vida de Alemania el cdo.defunción y comunico su fallecimiento . Me responden indicando que lo pasará a la entidad correspondiente . adjunto respuesta : post@drv-rheinland.de ​ Amalia Diaz Gonzalez ​ Sehr geehrte Dame, sehr geehrter Herr, Wir bestätigen den Eingang Ihrer E-Mail. Sie wird der zuständigen Stelle in der Deutschen Rentenversicherung Rheinland zugeleitet. Wir werden Ihr Anliegen schnellstmöglich bearbeiten. Bitte beachten Sie dazu Folgendes: Bei unverschlüsselter Datenübermittlung per E-Mail kann weder die Vertraulichkeit Ihrer Daten noch die Authentizität des Absenders gewährleistet werden. Sollten Sie per E-Mail personenbezogene Daten, Änderungswünsche für den Versicherungsverlauf oder sonstige Anträge an die Deutsche Rentenversicherung Rheinland mitgeteilt haben, werden wir Sie daher regelmäßig auffordern, diese Anliegen schriftlich an uns zu richten. Aus dem gleichen Grund werden wir Ihnen auf Ihre E-Mails in der Regel auf dem Postweg antworten. Wir bitten um Verständnis für die dadurch verursachte Verzögerung. Mit freundlichen Grüßen Ihre Deutsche Rentenversicherung Rheinland','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-11-16','-Amalia : He contactado con la agente de OCASO que ha llevado el decesos . Tf. Natividad Fdez. 667436655. Tiene pendiente entregar a Gracia documentación , entre ella el cdo. defunción. Los abogados comunicarán la baja y el cdo. al INSS para la baja de las pensiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2023-11-16','Ana: envío a Julio, Aux. CTAEx: "te mando lo que te he comentado antes: - Oficio remitiendo documentación - CI Cirugía - Solicitud inclusión en lista de espera quirúrgica Relativos a Antonia Bravo Patilla para dar REGISTRO y remitir también en papel por correo certificado a la Asociación Vera – Plena Inclusión"','2');
