insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2023-11-16','Ana: Sí esta valorada por Dependencia: Grado III, nivel 2 desde 2008. ·················· Plaza RAE por Dependencia. Resolución guardada en expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-11-16','miguel, contesto a email de Ana con copia a la parte social y económica Hola, efectivamente debe ser el ingreso lo que impugna. Si os fijáis en el testimonio de medidas de apoyo, incluía su internamiento. Así que quedamos a la espera, si nos notifican algo desde el juzgado, mientras seguimos ejerciendo normalmente el cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2023-11-16','TERESA ME LLAMA ESTEFANIA PARA COMUNICARME LA EXPUSLIN DE JOSE ARCHIVO INFORME DONDE COMUNICA LOS MOTIVOS DE LA EXPULSION HABLO CON JOSE GIRALDO PARA INFORMARLE DE LA SITUAICON, PROPONE HABLAR CON LA RESIDENCIA DE AZUAGA PARA VER SI HAY PLAZA Y PODEMO INGRESALO ALLI','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-11-16','miguel, envío encargo para tramitar la herencia a Joaquin de Menaya joaquin@menayaasesores.es: Hola Joaquín, adjunto junto con documentación 1, 3 que nos han remitido, las sentencias de incapacitación y nombramiento a la Comisión Tutelar de Adultos. Echad un vistazo y me decís lo que haga falta, porque desde el centro en que está sólo nos han remitido esto con lo que cualquier otra documentación tendremos que pedirla. Una vez que lo tengáis todo, necesitaré un presupuestos y provisión de fondos a hacer. **************************************************** Envío email a la parte social y económica: Hola, ya he mandado a Menaya asesores la documentación de Jose Maria Rodriguez Moya para que tramiten la herencia. Es una curatela y en principio no necesita autorizaciones judiciales a través de abogado. Como tiene dinero suficiente vamos a delegar estos trámites. Amalia, para la documentación que puedan necesitar necesitaremos una persona de contacto del centro o familiar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-16','miguel, envio email al abogado JUAN PABLO SERRANO MUÑOZ >3116@icaba.com> recomendo por Maria Granada: Buenas tardes Juan Pablo, te adjunto conforme hemos hablado el laudo arbitral para pedirte presupuesto lo más ajustado posible para solicitar ejecución de dicho laudo arbitral. Te rogamos discreción, pues tal como conoce Maria Granada (exabogada de la parte contraria), tuvimos que renunciar a nuestro abogado por continuos fallos del procedimientos, en los dos intentos de ejecución que hizo. Quedo a la espera de un presupuesto lo más ajustado, pues nos han denegado abogado de oficio. ************************************* me contesta que me pasará el presupuesto cuando pueda y le contesto: Gracias, disculpa las prisas pero lo necesito antes del lunes porque el martes iré al juzgado para hacer el poder apud acta al procurador que sea designado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-16','miguel, envío justificante de transferencia a Pilar Carril la tasadora: Buenas tardes Pilar, adjunto justificante de transferencia. Por favor, cuanto antes envíame dicha tasación porque tenemos 10 días para presentarlo en el juzgado, según nos comunicó el abogado este lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-11-16','Hola, ya he mandado a Menaya asesores la documentación de Jose Maria Rodriguez Moya para que tramiten la herencia. Es una curatela y en principio no necesita autorizaciones judiciales a través de abogado. Como tiene dinero suficiente vamos a delegar estos trámites. Amalia, para la documentación que puedan necesitar necesitaremos una persona de contacto del centro o familiar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-11-16','Amalia : escribo a Miguel: desde el juzgado me indicaron ayer que quedaban pendiente la resolución judicial de un informe social actualizado con la situación en La Morera. El TS lo va a hacer la semana que viene y te lo entregaré para que lo remitas al juzgado . Independientemente de ese informe social , hoy he llamado a la familia para hablar con ellos y con Antonia . Se ha puesto a gritar diciendo que" interna no quiere estar ".. Se lo he comentado también a Carlos del juzgado , con esa actitud aunque ingresara de forma involuntaria al ser centros abiertos va a fugarse al día siguiente . Sólo quiere asistir a Centro Ocupacional pero volver todos los días a su casa . De momento se pone en lista de espera para este recurso. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2023-11-16','Juana Bueno TF: 696110603.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2023-11-16','-TS del Centro La Luz : Adjunto te envío documento que hemos recibido en relación a CRÍSTOFER FIGUEROA RASTROLLO. En él, aparece reflejado que el CADEX le ha otorgado perfil de Residencia de Apoyo Limitado y se adjunta la solicitud de elección de centros. Si tengo que hacer algo al respecto, dímelo. ------------------Tienes que remitirnos la solicitud de ingreso en centro con los 4 que quiere elegir y la pondremos a firma de la Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-17','miguel,el abogado JUAN PABLO SERRANO MUÑOZ >3116@icaba.com> me remite el siguiente presupuesto para ejecutar el laudo: PRESUPUESTO EJECUCIÓN LAUDO ARBITRAL -Por Ejecución sin oposición………….200 euros ( + IVA 21%) -Si se formulase oposición………..…..300 euros (+ IVA 21%) ------------------------------------------------------- Buenos días, por favor envíame los datos de tu procurador/a porque el martes haremos el apud acta. Te ruego que hables con Maria Granada, que fue la abogada de la contra parte y ganó el caso la vez anterior, para que te comente el caso. Cualquier duda hablamos. Juan Pablo, necesito presupuesto también de tu procurador lo más ajustado posible. --------------------------------------------------------- envío email a Alberto, Maite y Amalia: Buenos días, ya tengo un presupuesto ajustado para el trámite de la ejecución del laudo de Carmen Leal. Estoy a la espera que me envíe presupuesto de su procurador y el martes quiero hacerle el poder apud acta. Amalia coméntaselo a Carmen Leal. Como sabéis seguimos pendiente de abonar o no al antiguo abogado Jorge Calvo sus honorarios, que desconocemos y que estamos pendiente de saber por él lo que resuelva su seguro de responsabilidad civil ante sus continuas actuaciones negligentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-11-17','miguel, Amalia me envia email de la directora del centro para la documentación para el trámite de herencia que tramitará la asesoria Menaya: Sandra Sánchez >ssanchez@inteligencialimite.org> -------------------------------------------------- envío email a la directora del centro Sandra Sánchez >ssanchez@inteligencialimite.org> y Amalia Buenos días, hemos dejado a la asesoría Menaya el encargo para que procedan a tramitar la herencia del curatelado Jose Maria Rodriguez Moya. Cualquier duda o documentación que le haga falta a la asesoría, o bien ellos o bien nosotros le pediremos la información o documentación que sea necesaria','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-16','miguel, recibo email de Amalia de un tasador José María Gonzalez Ruíz >josemariagonzalezr@gmail.com> Buenas tardes Amalia, soy tasador inmobiliario en Málaga y familiar de Damian con interés en vender su vivienda en calle Dan, barriada Cortijo de Torres. Tengo por su parte, el encargo de valorar su vivienda y me comenta que su prima por parte paterna, dispone de llaves. Si les parece oportuno, que contacte conmigo para la valoración. Quedo a la espera de instrucciones para colaborar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-17','miguel, contesto a Amalia: Te remito este email para que puedas concretar las acciones de peritaje del piso. Damián también me ha escrito indicando lo mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-17','miguel, contesto a Amalia Buenos días, el encargo y transferencia fue realizado ayer a Pilar Carril por la mita de precio que mandó su prima Alicia. Puedes verlo en el expediente. En pocos días tendré la tasación, y enviada a su abogado Enrique Perianes. A su prima ya le envié un email indicando que hemos seleccionado a otra perito. Hemos tenido que actuar con urgencia porque nos queda unos 6 días para entregar la tasación al juzgado (nos dieron 10 días para subsanar su aportación) Te adjunto el presupuestos de ella y la transferencia hecha ayer. ------------------------------------------------- Contesto a Amalia y al tasador Buenos días José Maria, soy la persona de contacto de la Comisión que estoy gestionando los trámites de venta. Actualmente el abogado está gestionando en el juzgado los trámites de venta, para lo cual va a aportar la tasación. La tasación ya está encargada, no tiene que gestionar nada. Su prima Alicia lo sabe pues le envié un email el otro día. En cuanto a la venta puede remitirnos un presupuesto de cuánto serán sus honorarios, pues compararemos honorarios entre inmobiliarias. Como sabe Damian es una persona curatelada por la junta de Extremadura y no es el interlocutor con el que hay que hablar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-11-17','miguel, contesto a Amalia con copia a Maite: Buenos días, quedo pendiente del informe donde se recojan todas las incidencias para enviárselo al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2023-11-17','Ana: Reenvío a Ángel, A. Jurídicos, correo de Ana Castillo Foronda TS - FUNDACIÓN AUTISMO SUR (teayudamos@autismosur.es): "Me comentan del Juzgado de Instrucción nº11 de Málaga que el procedimiento de revisión de tutela de Alexandru aún no está incoado. Deberíamos rellenar el documento adjunto solicitando la revisión de las medidas, lo debe rellenar y firmar el tutor legal y adjuntando informe médico y social para que las revisen y abran el procedimiento, acudiendo personalmente al registro del decanato, allí lo recogen y sellan con fecha de registro. Cualquier cuestión me comentas." ··················································· Respuesta de Ángel a TS - Autismo Sur: "En relación con su correo electrónico, le indicamos, En lo concerniente al inicio del expediente de jurisdicción voluntaria para la revisión de las medidas judiciales acordadas, conforme a Nota de Servicio 3/2022, de fecha, 24 de agosto de 2022, emitida por la Fiscalía Superior de Extremadura, las revisiones de medias de apoyo deben adoptarse conforme a las previsiones de las conclusiones alcanzadas en reunión conjunta del Consejo General del Poder Judicial y Fiscalía General del Estado, de 9 y 10 de junio de 2022. En dichas conclusiones, se señala expresamente que la iniciativa para la revisión, debe ser judicial, sin que proceda esperar a que sea el Ministerio Fiscal quien la solicite en todos los casos. El Ministerio Fiscal, conforme a la conclusión 4ª de las conclusiones mencionadas llevará cabo las solicitudes de revisión en aquellos supuestos en los que tenga conocimiento, a través de sus propias Diligencias Preprocesales Civiles de un procedimiento sin revisar. Igualmente, la Disposición Transitoria quinta, Revisión de las medidas ya acordadas, de la Ley 8/2021, de 2 de junio, por la que se reforma la legislación civil y procesal para el apoyo a las personas con discapacidad en el ejercicio de su capacidad jurídica, dispone que la revisión se realizará por parte de la autoridad judicial de oficio o a instancia del Ministerio Fiscal en un plazo máximo de tres años."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-16','Ana: correo de Estrella, TS CSS-Plas: "Te comunico que Enrique Santos comenzará a salir de pase media hora todos los días fuera del centro, por recomendación de su Psiquiatra."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-11-17','Buenas, desde el juzgado me indicaron ayer que quedaban pendiente la resolución judicial de un informe social actualizado con la situación en La Morera. El TS lo va a hacer la semana que viene y te lo entregaré para que lo remitas al juzgado . Independientemente de ese informe social , hoy he llamado a la familia para hablar con ellos y con Antonia . Se ha puesto a gritar diciendo que" interna no quiere estar ".. Se lo he comentado también a Carlos del juzgado , con esa actitud aunque ingresara de forma involuntaria al ser centros abiertos va a fugarse al día siguiente . Sólo quiere asistir a Centro Ocupacional pero volver todos los días a su casa . De momento se pone en lista de espera para este recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-11-17','Ana: Lourdes, S. Ecca. me informa de la dificultad para abonar la plaza de Concepción. Pero también informa "que según ITT aparece que tiene un depósito de 18.660€" ···· Según Informe Social, la residencia perdió las plazas T3, pero como Concepción no tiene apoyos familiares y está bien adaptada e integrada en la residencia, se decidió que se mantuviera en el mismo centro con plaza privada (1606 €). Con sus ingresos no llega para abonarla: Pensión de Jubilación: 578,50 € x 14 pagas, Pensión de Jubilación de Francia: 72,20 € x 12 y Prestación Vinculada SAR - Dependencia: 715,07 € x 12. ··········································································· Respuesta a Lourdes con copia a Alberto y Maite, Jefes CTAEx: "Buenos días Lourdes, gracias. No has adjuntado el Excel, pero no es necesario, ya he mirado yo la rendición anual y el Informe Social y he hecho cuentas. Según Informe Social, la residencia perdió las plazas T3, pero como Concepción no tiene apoyos familiares y está bien adaptada e integrada en la residencia, se decidió que se mantuviera en el mismo centro con plaza privada (1606 €). Es cierto que con sus ingresos no llega para abonar la plaza: - Pensión de Jubilación: 578,50 € x 14 pagas - Pensión de Jubilación de Francia: 72,20 € x 12 - Prestación Vinculada SAR - Dependencia: 715,07 € x 12. Pero también es cierto que dada su edad (87 años), su estado de salud, su nulas relaciones familiares y su integración en el centro (está bien adaptada y recibe el cariño de los profesionales con los que lleva desde 2017). No consideramos conveniente desde la secc. social el cambiarla de recurso. ¿Sería posible rescatar el depósito que indica Lourdes que tiene para seguir afrontando sus gastos?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-11-17','Ana: En relación al correo de Guadalupe Cortés, TS IMAS - SAD indicando la dificultad de la Aux. de SAD para solicitar presupuesto para menaje para Carlos, contesto con copia a la S. Ecca: " Buenos días Guadalupe, Gracias de nuevo por informar. La solicitud del NIF de la CTAEx no se había dado porque las facturas no van a nombre de la CTAEx, la factura debe ir a nombre de Carlos con el DNI de Carlos. Debe haber habido un malentendido o por parte de la Auxiliar o por parte del establecimiento al que haya acudido. No obstante, reenvío este correo a mis compañeras de la sección económica, para que si es posible se autorice un extra, como indicáis, para adquirir toallas, cazuelas y sartenes. No sé si con 50€ podría tener suficiente. Compis de Sección Económica: ¿sería posible autorizar un extra de 50€ para Carlos en estos conceptos y qué después nos envíen la factura/ticket? Podéis leer el hilo para mayor aclaración."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-11-17','-Amalia , dos gestiones últimas realizadas : + en el area juridica he elaborado informe para comunicar su situación al juzgado . Miguel lo presentará en estos días. +en el area económica , se le ha quitado la libreta bancaria que se ha bloqueado para que no tenga acceso a los 4000€ y se le ha hecho tarjeta prepago . LImite mensual de 450€ , el importe actual de PFHC. Sacará libremente , suele hacerlo de 20€ cada día . En enero cuando se regularice IMV se le puede subir la asignación a 100€ más que es lo que venía percibiendo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2023-11-16','TERESA TELEFONO DE SU HERMANO LUIS 641415819','2');
