insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-17','tf699634246 -689024423 direccion : C/ vista hermosa nº 5 Bajo A','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-11-17','miguel, hablo con Maria Jesús (la vecina), me comenta que ha hablado con el tecnico del ayto de Piedras Albas y seguramente nos van a denegar el recurso, y portanto nos instarán al cumplimiento del arreglo. Además la insta a que tendrá que pedir un proyecto de obra visado. Por tanto el Ayto no está por la labor de buscar una solución. Al sólo disponer de unos 60000€ para arreglo, a ella se le ocurre una solución intermedia, que yo le aconsejo se la plantee a la fiscal pues sería adelantar los 6000€ el curatelado para lo más urgente y cederle el bien a ella en compensación a los daños, donde aun así no quedaría compensado todo lo que se le debe, y como dice ella es un curatelado de 76 años y desconocemos quién heredará esos bienes. Yo le he planteado buscar un abogado (le ayudaría yo a buscarlo porque ella no conoce ninguno) y que plante en el juzgado el arreglo de la vivienda, solicitando como medida cautelar los 6000€ y en la resolución que se le ceda el terreno. Lógicamente ella no quiere asumir las costas procesales, por lo que el abogado se tendría que comprometer a pasar unas costas al curatelado muy ajustadas, que éste pudiera asumir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-11-17','miguel, informo a la parte económica y social: Buenos días, como sabéis ayer presentamos recurso contra la declaración de obra ruinosa del Ayto de Piedras Albas, que podéis ver en el expte e intranet. Hoy me ha llamado la vecina que ha hablado con el técnico del ayto que le pide a parte de todos los aportado un proyecto… Ya le he dicho que no podemos asumirlo. Nos propone con 6000€ arreglar lo más urgente y que se le ceda el terreno y ella poco a poco lo arreglaría. Al tratarse de un curatelado bastaría su consentimiento. Le he dicho que hable con los juzgados competentes, que son los de Cáceres y en concreto con la fiscal para que la asesore. Mi opinión es que lo solicite vía judicial, y en medidas cautelares solicite los 6000€, que en la resolución se le ceda el terreno y las costas que solicite las pague el curatelado, pero que hable con el abogado para que pase muy poca cuantía, pues no hay dinero. La ayudaremos a buscar un abogado pues ella no conoce ninguno. De todas formas estos pasos informativos, son a expensas de la resolución a nuestro recurso por parte del Ayuntamiento de Piedras Albas. Para vuestra información…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-11-17','miguel, tras hablar de nuevo con Maria Jesús (vecina) envio email a la parte económica y social: Hola, al final la vecina y técnico de obra tras hablar con el ayto y confirmarle que necesitamos proyecto de obra, y que nos lo comunicarán, va a hacer dos fases: 1.-Hacer el proyecto y tirar un muro que el justificante será la contestación del ayto de piedras albas(requiere urgencia porque se le cae todo sobre su casa) 2.-Solicitará vía judicial que se le ceda la propiedad. Ella nos irá guiando con el presupuesto de que disponemos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-17','miguel, email de Damian: Este es el número de la comunidad García Prieto en malaga que pago 80 euros que va con el agua y es el siguiente 952336000.me han informado en gestión tributaria que hay que liquidar la plusvalía.mis escrituras ponía un pequeño pago al banco hipotecario de una cláusula que había que liquidar viene en las escrituras un pequeño dinero que no se líquido cuando pasaron las escrituras a mi nombre.las escrituras las tiene mi prima.el IBI y también hay que pasarlo a la persona que se lo venda pago 55 euros de IBI cada 3 o 4 meses el último recibo del año me lo pasan el 5 de diciembre.ke facilito la página web de gestión tributaria ayuntamiento de Málaga donde se puede liquidar la plusvalía es cdmalaga.eu y el número de correo electrónico es gestrisam@malaga.eu.gracias lo hago para ayudar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-11-17','Ana: Tras habla con Maribel, hermana de Conchi (682 733 187), bastante alterada. ······ Llamo a Estrella, TS CSS (24146): se acuerdo que no volverán a encargar ninguna compra a Maribel (ni de productos de higiene ni nada). ································· Envío correo a Alberto: "En relación a Concepción Fernández Muñoz, con plaza en CRR y actualmente ingresada en Unidad de Media Estancia del C. Sociosanitario, se le ha agotado el dinero que llevaba del CRR. Puesto que la estancia se está alargando más de lo previsto, y de hecho, se están planteando que no regrese al CRR, al no haber evolución positiva, es NECESARIO QUE REMITÁIS LA AUTORIZACIÓN GENERAL DE CENTRO para que puedan retirar dinero para artículos de aseo personal, tabaco y demás gastos de bolsillo. Indicad por favor la cuantía máxima mensual (por supuesto como máximo lo que tenía autorizado en el CRR)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-11-17','miguel, recibo email de Eva: Buenos días Miguel Ángel, la vista se celebró y el Ministerio Fiscal informó favorablemente para la autorización del gasto extraordinario. Cuando tengáis el poder me lo enviáis que la procuradora lo presenta. El procedimiento es el 203/2023 de Jurisdicción Voluntaria ante el Juzgado de Primera Instancia e Instrucción Nº1 de Valencia de Alcántara. -------------------------------------------------------- La contesto: Gracias. El martes sin falta te envío el poder.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-17','miguel, nuevo email de Damian El número de teléfono de gestión tributaria ayuntamiento de Málaga es 951929292.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2023-11-17','Buenas, su hno. Juan solicita a través de la TS de Villagonzalo ( guadalupecastuera@hotmail.com ) un extra para diciembre de 300€ para ropa y comida . No sé como están sus cuentas , ya me decís . Saludos . AVISAR A SU HNO JUAN 924366582','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-17','miguel, Juan Pablo me envia presupuesto de la procuradora PRESUPUESTO PARA LA EJECUCION DE UN LAUDO ARBITRAL. SERIA DE 250 E. ------------------------------------- Se lo reenvío a la parte económica y social','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2023-11-17','Ana: Envío a Julio, Aux. CTAEx: "Te envío para remitir al EQUIPO DE SALUD MENTAL DE CÁCERES, los siguiente documentos en relación a JESÚS ROMERO PÉREZ: - Oficio-solicitud de Informe de Psiquiatría para la revisión de las medidas judiciales de apoyo - Testimonio de aceptación del cargo de tutor"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-11-17','Ana: Comunico a Carlos que, según informa el Jefe de secc. ecca. (correo de 09/11/23) NO ES VIABLE CONTRATAR EL CATERING PARA LAS CENAS. ····· Acepta la situación. Marisa, la Aux. de SAD le ayudará a preparar las cenas. ······· Acordamos que, puesto que a 31 de diciembre finaliza el cáterin municipal gratuito, de cara a enero se bajará la asignación a 55€ para poder contratar el cáterin privado para las comidas. *Volveremos a hablarlo a mediados de diciembre para concretar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-11-17','Ana: Envío correo a Estrella Durán, TS CSS: "A petición de Alberto, Jefe de Secc. Económica, os recuerdo que el gasto mensual máximo permitido para GUADALUPE GIL CABELLO, son 200€. Ha visto en los movimientos bancarios que habéis retirado 300€ y me ha pedido que lo recuerde. Al hecho de que no tiene dinero hay que sumar un embargo que hemos recibido… aún no sabemos de qué…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-11-17','Ana: Correo de Ángel, A. Jurídico: "...conseguí hablar con el Abogado para que continuara realizando esta gestión, abonándole una cantidad simbólica. Se lo comenté a Iciar y Alberto" ·························· Respuesta de Alberto, Jefe S. Ecca: "COMO LE ABONAMOS EL IMPORTE...HAS QUEDADO EN ALGO CON EL ABOGADO...ES POR ESTABLECER EL PRECIO Y UNA FORMA LO MÁS PERMANENTE POSIBLE DE ABONARLO" ··········· Ángel escribirá al Abogado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-17','miguel, Ana la abogada se acerca al registro civil y comprueba que está inscrita la incapacitación pero no nuestro cargo. Envio email a Ines: Hola Inés, necesito que hables con el juzgado nº2 de Plasencia y les soliciten libren oficio al registro de Salamanca para que nos inscriban como curadores representativos. Sin eso no puedo ratificar una herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-11-20','miguel, el tutelado me envía email Manuel >manueldominguezmartin58@gmail.com> Soy Manuel Domínguez Martín,estoy tutelado por la comisión, ya e ablado con usted en otra ocasión,mi DNI es 76033085f,le comento, voy a ir a pedir a la seguridad social la incapacidad permanente, si me la deniegan tengo que denunciar, me ara falta un abogado.usted puede llevar mi caso? ----------------------------------------------------- Se lo reenvio a Ana y Angel a ver si saben algo...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-11-20','miguel, enviamos comunicacion de su situación al juzgado adjuntando la documentación de Amalia (revisado por ella) sobre la imposibilidad de intervención con él por la Ctaex','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-11-20','Ana: En relación al correo de Paula, TO CRR-Plas., envío correo a Estrella Durán y Rosa Bravo, CSS, con copia a TO y Dirección del CRR: "Estrella y Rosa, en relación al correo de Paula, que podéis leer en el hilo, referente a CONCEPCIÓN FERNÁNDEZ MUÑOZ, os escribo para comunicar que se autoriza abonar ese importe (9,95 €) a los profesionales del CRR para reponer el dinero invertido en “bolsas grandes de almacenamiento”, cuando lleven las bolsas con la ropa y efectos personales de Conchi al C. Sociosanitario. Así pues os solicitamos, que por favor, hagáis entrega de ello, y adjuntéis a mis compañeras de sección económica el ticket justificativo de dicho gasto. *Por cierto, me confirman que hoy mismo os harán llegar la AUTORIZACIÓN GENERAL DE CENTROS pendiente. Ojalá y que la evolución de Conchi sea positiva o al menos que no vaya a peor."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-11-20','Ana: respuesta de Estrella, TS CSS, a mi correo del viernes: "Vale, lo anotamos en la autorización para que no vuelva a pasar..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-11-20','Buenos días, Amalia. Soy Eduardo Caballero Paez. Recuerdas la última conversación que tuvimos acerca de poder disponer de mi dinero en todo momento y no tenerlo bajo supervisión? Pues la última vez que he estado en el SEPAD he hablado con tu compañera Maite, le explique la situación y ella me dijo que debía pedir cita previa para hablar con vosotras. Y yo lo entendí, si no tocasen un tema tan importante como mi economía y hacer un mal uso de la misma manipulándola hasta el punto de bloquear mi cuenta personal y no disponer de efectivo? Te imaginas que yo fuese al juzgado o a tu banco para que bloqueen tu cuenta bancaria o le dijese a un juez amigo que interviniese siguiendo la misma linea para putearte y cuestionarte a cada momento como persona? Seguro que no te agradaría, verdad? Pues esto es exactamente lo que ocurre aquí. Espero que tanto la juez como Vds corrijan su postura. Atentamente. PD: Si tenéis comunicación directa con la juez, indicarle de paso que abra una línea de investigación contra la persona o personas responsables que se estan dedicando a hacer esta campaña destructiva ideada y planificada contra mí, para evitar así que toda esta situación anómala llegue a producirse.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-20','miguel, recibo email de Alvaro de la Asesoría: Buenos días Miguel, Adjunto remito la declaración de Carmen donde indica que va a ser la titular del vehículo, pero únicamente para el cambio de titularidad para su posterior venta. Ahí se expresa igualmente que el importe de la venta del vehículo será repartido por iguales partes a cada uno de los herederos. Por favor, confírmame qué está todo ok, para realizar el primer cambio de nombre, que es de la madre a su hija Carmen. Luego, quedará pendiente de realizar el segundo cambio que será de Carmen al nuevo comprador. --------------------------------------------------------- mi contestación a Alvaro de la asesoría, con copia a la abogada y la hermana: Buenos días, no podemos todavía dar la conformidad a la transmisión del vehículo pues no ha sido ratificada la escritura (de todas formas vemos algunos defectos en el mismo pues no concreta quien asume los gastos de cambio de titularidad, cuanto será el importe de venta del vehículo y plazo en que se hará la venta, junto a las condiciones del vendedor, que habría que adjuntar). Por otra parte, seguimos esperando se nos aclare, cómo se ha acordado van a hacer para presentar las escrituras en los bancos para el reparto del dinero adjudicado en las cuentas indicadas en la herencia. También seguimos pendientes, se nos remitan las pólizas del seguro, y si los beneficiarios ya están al habla con alguien de la aseguradora, para que coordinemos actuaciones. Les informo que procedemos a solicitar al juzgado inste al registro civil a inscribir nuestro cargo para que podamos ratificar. Mientras no esté ratificada la escritura no podemos firmar nada del vehículo (del cual nos informaremos, pues como te comenté por teléfono se produce una doble transmisión haciéndolo así lo cual no es jurídica y fiscalmente coherente)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-11-20','miguel, email de Amalia: Buenas, os paso email de Eduardo , hay más . Le voy a pasar su sentencia para que se dirija al juzgado si así lo considera . Y nos reenvía email de Eduardo Eduardo Caballero >ecaball99@gmail.com> Buenos días. Soy Eduardo Caballero Paez. Le escribo para comunicarle sobre el tema de la tarjeta. Y como comprenderá he recibido la noticia del "detalle" a través del banco que no puedo disponer de mi dinero, cuando Vd. me dijo que una vez llegada la tarjeta si podría. Me he enterado de cuál es el "detalle" principal y me parece una broma de muy mal gusto perpetrada por Vds. como colaboradores y la responsable de que todo esto se lleve a cabo. Quiero disponer de mi dinero y de mi vida en todo momento sin tener que depender de Vds, ni de nadie se llame juez o lo que sea. Al magistrado lo ha manipulado o sobornado alguien, para que actue de manera improcedente contra mi. Quiero que la policia investigue, localice y detenga a esa persona. Y una vez detenida sea puesta a disposición judicial no para que salga por la otra puerta con fianza de por medio. Indiquenmé quien es la persona responsable que está influenciando o me veré obligado a denunciar y acusarles de complicidad ante un delito perpetrado de tipo económico. Quiero nombre y apellidos de la persona o personas alocadas cuya ocurrencia consiste en intervenir directamente mi economía e influir sobre mis asuntos personales en general, pretendiendo manipular las instituciones y causarme un perjuicio directo. Esas personas son acosadoras, manipuladoras y delincuentes bajo mi punto de vista. Son gente obsesiva y perturbada dispuesta a llevar a cabo un acoso permanente contra una persona a la que atacan indiscriminadamente. Estos perfiles se asocian más con seres de personalidad tipo narcisista que cuestionan todo del otro en lugar de revisar sus acciones alocadas e injustificadas para causar molestias al vecino. Alguien aquí ha hablado más de la cuenta sobre mi y ha soltado demasiadas estupideces, y esa es la verdadera razón de lo ocurrido actualmente. Todas ellas han llegado al juzgado de guardia generando un clima de confusión alrededor porque esto a alguien le ha interesado que se produjera. Eso es una evidencia y contraponer eso es faltar a la realidad y crear todo un montaje alrededor. La persona que monta toda esta película es la que tiene problemas de tipo psicológico y no es precisamente la que envía este mensaje. Los responsables de los que les hablo se han dedicado precisamente a esto. Quiero respuestas YA! ------------------------------------------------------------Mi contestación con copia a Ines: Inés, si todavía no has enviado la comunicado al juzgado lo que te envié, adjuntale el email de Amalia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IVAN'and edp.apellido1='CINTAS'and apellido2='OLIVA'),'2023-11-20','TERESA RECIBO LLAMADA DEL SSAB DEL MERDIA, GUADALUPE TS 924 38 74 07 ME COMENTA QUE LA CONCEJALA LE PREGUNGA POR ESTE CASO YA QUE HAY QUEJAS VECINALES PARECE SER QUE YA SE HA CELBBRADO EL JUICIO PERO A FECHA DE HOY SEGUIMOS SIENDO DEFENSORES JUDICIALES COMENTA EL JUEZ HA ORDENADO EL INGRESO INVOLUNTARIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-11-14','miguel, tras confirmarme la guardia civil que sí que podrá poner una denuncia contra su hijo Aitor. Envío email a la parte social y jurídica: Hola, desde el cuartel me confirman que esperen a la semana que viene a que ellos llamen a las del programa asistencial para que se acerquen de nuevo. Parece ser que ayer se acercaron sin Felisi. El día que las citen tienen que acercarse con Felisi. Ya le he dicho al guardia, que si necesitan una autorización nuestra que se la haríamos sobre la marcha','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2023-11-20','Ana: Su Centro de Salud es el de Plaza de Argel, de Cáceres y su Médico de A.P. el Dr. Fco. J. Serrano Guerra Librero. ································································································· *Envío a Julio, CTAEx, para que envío por REGISTRO-SIREX al centro de saluld oficio solicitando INFORME MÉDICO para la revisión de las medidas judiciales de apoyo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-11-20','miguel, recibo email de Tere Miguel seguimos en las mismas, no le dejan poner a Felisi la denuncia acompañada del programa del familia. Y de Ana: Miguel, ¿habéis llegado a hablar con la Guardia Civil? Se me ocurre que quizá podéis enviar algo por escrito. Yo creo que como al final no ponga denuncia la situación se va a mantener igual. Y con respecto a la orden de alejamiento ¿es normal que tarde? Así desde luego no se protege a las víctimas… Y de nuevo de Tere Yo en el caso de M Elena puso la denuncia y la misma semana le tomo declaración la jueza y ese mismo día tenia la orden de alejamiento hasta que se celebre el juico ------------------------------------------------------- mi contestacion a las dos: Hola, Tere, en el email del 14-11-23 te indiqué que tenían que esperar a que la guardia civil la citara, que estaban liados por fiestas creo. Que espere y mañana llamaré yo a la guardia civil de nuevo, para que me den dia…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-11-20','Maite: ha llamado Nieves, trabajadora social en Mentalia. La familia de José María quiere visitarlo en Navidad. Fueron en noviembre y les dijimos que si iban en esa fecha sería difícil que pudieran volver en Navidad por el gasto que supone. He quedado con ella en que lo valoraremos pero sólo dos noches para que sea más barato, y teniendo en cuenta que cobra la extra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2023-11-20','miguel, llamo al juzgado nº1 de Jerez para preguntar por la documentación de honorarios de un abogado que han remitido y por la otra vía Curro nos remite honorarios de abogado y procurador del procedimiento 71/2018. Envio email a la parte económica, social, jurídica: Hola, ya he hablado con el juzgado y subido todo a su expediente. Me confirma el juzgado que no es ETJ Ejecución de Titulos Judiciales 371/13 (que ya está finalizado) y Curro por error lo ha adjuntado… Sino que es el ETJ Ejecución de Titulos Judiciales 71/18, y nos dan traslado por 10 días por si nos oponemos o no a los honorarios. (procedimiento origen monitorio nº 432/17) Como no vamos a oponernos y ya se recogen los interereses, resolverán incluyendo todo. Al estar tutelado desde el 2019 he preguntado y no hay más procedimientos después de este. Alberto los importes por honorarios que reclaman son abogado 477,95€ y procurador 179,98€=total 657,93€, para que cuando te lo digamos podáis abonarlos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-11-20','Ana: Envío correo a Lourdes, S. Ecca.: "En relación al EXTRA PARA ROPA que solicita JULIA MORÓN HERNÁNDEZ, tal y como hemo acordado, le autorizamos 80€ con la CONDICIÓN DE NO SOLICITAR NINGÚN EXTRA PARA NAVIDAD. Irá a retirarlo el próximo miércoles día 22 en la sucursal de su pueblo. Ya le he informado de todo y acepta dicho acuerdo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2023-11-20','Gracia : He conseguido localizar al sobrino de Alemania y heredero junto a su hermana de los bienes de María Luisa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2023-11-20','Ana: En relación al correo del viernes de Miguel, A. Jurídico, respondo: "Si lees bien el REQUERIMIENTO, lo que pide son los datos del CENTRO DE SALUD y del MÉDICO DE ATENCIÓN PRIMARIA (“CABECERA”), ni nos pide informe social ni nos pide que solicitemos nosotros el informe Médico. Aquí van los datos que solicitan: CENTRO DE SALUD ZONA CENTRO Av. de España, 2, 10004 Cáceres Médico de Atención Primaria: EMILIO MARÍA RUÍZ JARILLO" ······························································································································································································· Aunque aún no nos lo piden, a instancias de Miguel, A. Jurídico, envío correo a Sheila, Directora del CRR-CC (crr@grupociudadjardin.com): "En relación al procedimiento judicial de revisión de medidas de apoyo, os solicitamos INFORME DE CENTRO relativo a D. JUAN MARIO SAN ROMÁN BLASCO, en que indiquéis aquellos aspectos en los que consideráis que Juan Mario necesita de apoyos en su día a día, para que el Juez los tenga en cuanta en la nueva sentencia de provisión de medidas de apoyo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2023-11-20','-Amalia : Nos remiten desde el Ctro. La Luz el documento que remite el SEPAD con el cambio de perfil a RAL y el documento de elección de centros. Actualmente está en la UHDAC , él quiere pedir La LUz , desde UHDAC también consideran bueno Ap3 por estar en Badajoz donde viven su madre y hnos. LO pongo a firma de la Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2023-11-20','TS del CEntro La Luz : Aprovechando la coyuntura, informarte de que Gregorio, continúa trabajando y su nómina se la siguen ingresando en una cuenta que él se ha debido de hacer a través de Correos. Ese dinero, suponemos que lo tiene ahorrado, pero no tenemos control sobre él. Por otra parte, en marzo de 2023 se negó a realizarse una analítica de control para la consulta que tenía programada con Neurología. Refería no querer hacérsela "porque ya se hace muchas". A su vez, también se negó a asistir a la consulta programada con Neurología en abril de 2023 porque según él "le modifican la medicación y el cambio le viene mal". El pasado día 25 octubre se realizó analítica solicitada por su médico de familia. Posteriormente, el 10 de noviembre tuvo consulta con dicho médico. En esta consulta, le informaron que los resultados de la analítica salían alterados (Ácido valproico (Depakine) lo tiene bajo, en 29 y tendría que estar como mínimo en 50). Esto puede ser como consecuencia de no estar tomándose la medicación de forma correcta. Gregorio afirma que en ocasiones no se toma la medicación durante los fines de semana. Su médico le indicó que era importante que retomara la consulta con Neurología. De nuevo, Gregorio volvió a manifestar su negativa a asistir a dicha consulta, con lo cual decidió no volverlo a derivar y fue el mismo médico de familia quien le ajustó el tratamiento. Te informo de todo esto, porque a la médico forense también se le informó de ello, y creemos que es importante que se tenga en cuenta de cara a su comparecencia en relación a su revisión de medidas. Iris Calero - Trabajadora Social','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-20','-EL CRR enviará informe al juzgado , ya tienen la citación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRIADO'and apellido2='RODRIGUEZ'),'2023-11-20','Ana: Respondo al correo de Miguel, A. Jurídico, del día 9: "Miguel, como puedes leer, tanto en el Informe Médico como en el Informe Social, MARIA JESUS CRIADO RODRIGUEZ, no presenta enfermedad ni dificultad a nivel físico/movilidad para trasladarse al Juzgado a la comparecencia. Lo que sí puede precisar es acompañamiento, que en función de la fecha que sea se lo podremos pedir a Futuex o a la residencia para que busquen a alguien para que le acompañe de forma privada abonando el “servicio de acompañamiento”.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES MARIA'and edp.apellido1='ALVAREZ'and apellido2='CARRASCO'),'2023-11-20','-Correo del CSS Merida: Adjunto te remito la siguiente documentación: Informe social de Inés M.ª Álvarez Carrasco. Copia del DNI. Copia de la tarjeta sanitaria. Movimientos bancarios.       Inés M.ª tiene una cuenta bancaria en Ibercaja, en la cual está como cotitular su hermana Montserrat, quien era su tutora legal. Como podrás comprobar, a pesar de saber que ya no es la representante de la paciente, Montserrat continúa realizando retiradas de efectivo en cajero y tiene domiciliados recibos de una compañía eléctrica.       Teniendo esto en cuenta, considero que es URGENTE que esta persona deje de tener acceso a los ingresos económicos de Inés M.ª.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-11-20','Ana: Correo de Javier Pecero, Director CRR-Mérida, Grupo 5 (direccion.crrmerida@grupo5.net) a mí y a la secc. ecca.: "Buenas tardes, hoy hemos tenido la entrevista de Javier Agudo para ingreso en el CRR de Mérida. Todo ha ido bastante bien, por lo que hemos acordado el ingreso para el día 27 de noviembre. Según nos dice le queda poco dinero para lo que le resta del mes, por lo que necesitaría que se le autorizase para que pudieses sacar dinero del banco ese mismo día o el día siguiente. La planificación que hemos realizado (orientativa para las primeras semanas) es: INGRESOS EN EL CENTRO 300€ ASIGNACIÓN 155€ repartidos de manera semana TABACO 93€ repartidos semanales, 1,5 paquetes de liar (1,5€), librillo (1€) + filtros (0,5€) MEDICACIÓN 0€ HIGIENE 10€ EXTRAS 42€ OBTENCIÓN DE INGRESO EN EL CENTRO 300€ que sacará del banco previa autorización por la comisión tutelar Por tanto seria conveniente que pudieses sacar la parte proporcional para la primera semana, siendo esto una cantidad aproximada de 75€. Y estipular para a partir de diciembre la cantidad de 300€. En caso de que hubiese modificación os comentamos Un saludo" ····························· Respondo a todos: "Por mi parte ok a la propuesta. Lo que habría que determinar si lo saca el mismo día del ingreso en Plasencia, antes del traslado o ya en Mérida al día siguiente. Ante cualquier cuestión estamos en contacto Javier." ········································ Respuesta de Javier: "Perfecto, por nuestra parte no habría problema en sacarlo en Mérida ya que llegara sobre las 11.30 de y podríamos acompañarle, en caso de no poder ser por cualquier motivo, con seguridad lo haríamos al día siguiente. De todos modos, cuanto lo tengáis definido me decís."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-11-20','Ana: En relación al correo pendiente de Carolina, Directora CRR: "informaros que Ceferino proximamente se marchará a Olivenza por el traslado que solicitamos. El traslado se realizará en furgoneta-taxi para poder realizar su mudanza, a él le han dado un presupuesto de 301€. Ya nos decís que os parece y cómo realizamos el pago (transferencia - metálico) En caso de ser en metálico habría que conceder un extra de unos 50 €, ya que aqui en el recurso solo le quedan 250 € de extras anuales. Estamos en contacto." ···························· Respondo. "Mañana si puedo te llamo. El traslado puede abonarse mediante transferencia bancaria, pongo en copia a mis compañeras de la sección económica para que sepan que hay que abonarlo cuando nos hagáis llegar, bien vosotras, bien desde el nuevo CRR, la factura de dicho servicio de taxi. En cuanto a la fecha de traslado, ¿habéis hablado y acordado con el CRR de Olivenza el día en que tendrá lugar? Ya me dices cuando puedas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2023-11-20','Ana: A instancias de Miguel, A. Jurídico, envío correo a Sheila, Directora del CRR-CC (crr@grupociudadjardin.com): "En relación al procedimiento judicial de revisión de medidas de apoyo, os solicitamos INFORME DE CENTRO relativo a D. JUAN MARIO SAN ROMÁN BLASCO, en que indiquéis aquellos aspectos en los que consideráis que Juan Mario necesita de apoyos en su día a día, para que el Juez los tenga en cuanta en la nueva sentencia de provisión de medidas de apoyo."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2023-11-21','-Nos comenta desde el CADEX que tenía cita el dia 15/11/23 y que no se presentó , no teníamos conocimiento de esta cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2023-11-17','TERESA Buenos días acabo de recoger este documento de la casa de Jose González Fernandez , al parecer el día 8 de noviembre una trabajadora social de vivienda ha estado en la casa para hablar con él , y al no estar en casa pues le han dejado esa nota, en ese día han visitado todas las casas de la junta .... puedes hablar con la compañera de vivienda ? Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2023-11-21','miguel, envio email al abogado Pablo Garrote porque no me acaba de llegar el certificado de nacimiento que me dijo que enviaba','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-21','miguel, contesto a email de Alvaro de la Asesoria que pregunta cuando ratificaré, y le indico que cuando esté modificado el certificado de nacimiento, que está incorrectamente inscrito. **************************************************** Llega físicamente el certificado de nacimiento ***************************************************** Envío email a Inés, para que reclame al jzdo que nos nombró, de orden al registro civil para que inscriba correctamente que el cargo de curador representativo lo ejerce la Ctaex','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2023-11-21','Ana: Correo de ayer de Sheila, Directora CRR (crr@grupociudadjardin.com) al equipo de Secc. Salud Mental - UPA, y a mí: "Trasladamos para conocimiento las incidencias de la última semana relacionadas con el estado y consumo de tóxicos de la persona usuaria Juan Mario San Román Blasco. El consumo de alcohol continúa siendo a diario sin éxito en las intervenciones que desde el CRR se continúan implementando, siendo cada vez más acusado su deterioro y aumentando las estrategias y herramientas para conseguir dinero e invertirlo en el consumo, con el consecuente riesgo para su salud y conflictos con el resto de personas usuarias del centro." ············ Guardo registro de incidencias en el expte. digital. ·············································································· Respuesta de Eva Paredes, Psicóloga UPA: "gracias por la información. Vemos que la situación no deja de empeorar, continuamente corriendo riesgos muy grandes para su salud e incumpliendo las normas de no consumo y de tratamiento rehabilitador del CRR, etc. Todo esto está comprometiendo el poder permanecer en la plaza del CRR. No se si habéis considerado la posibilidad de solicitarle una consulta con su psiquiatra que revise su situación psicopatológica ante este empeoramiento y valorar la posibilidad de algún ingreso en UME, o Unidad de Alcoholismo del CSS de Plasencia... Estaremos pendientes de si da alguno de estos pasos y sus resultados, o si continúa con este consumo habrá que valorar la posible salida de CRR." ········································································································································ Respondo a todas con copia a Maite, Jefa Secc. CTAEx: "Gracias Sheila por informar. Estamos totalmente de acuerdo en las apreciaciones y propuestas que hace Eva, consideramos necesario valoración en Psiquiatría, tanto de su estado a nivel psicopatológico como de la posibilidad de ingreso en las unidades que indica. Lo que no vemos tan claro es la opción de salir del CRR sin un recurso alternativo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-11-21','miguel, llamo a la guardia civil 927-375014 y la sargento me confirma que quedó ayer que la llamara Raquel, para que le dijera si iban a ir y no lo han hecho, ni la han llamado ni han ido. La Sargento habia quedado que fueran hoy a las 10h.Me dice que va a llamar a Raquel y preguntarle si van a ir. Llamo a Tere para explicarle que tiene que confirmar si van a ir o no hoy (ya que según la Sargento Felisi tan pronto quiere denunciar como que no). En caso de que no vayan a denunciar, la sargento se lo comunicará a Fiscalía, todo lo que sabe, para que ésta intervenga. En caso de que vayan a ir me pide que le enviemos al email de la Comandancia,una Autorización. Doy los datos a Tere y la envío email con copia a Ana: Hola, tras conversación con Tere y con la Sargento de la Guardia Civil, y conforme hemos quedado te adjunto el teléfono de la comandancia y el email de la Comandancia para que envíes la autorización en caso de que vayan a denunciar: Tlfno 927-375014 Email: cc-pto-navasmadrono@guardiacivil.org','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2023-11-21','Ana: Llamada de Pilar, Directora Res. Logrosán (639 58 54 89). María, TS le ha informado que el padre de Valentina tenía dinero cuando falleció, pero posiblemente como no se hizo la DECLARACIÓN DE HEREDEROS, bloquearían su cuenta bancaria. ·················· Llamo a María, TS del Ayto. Logrosán (927 36 00 22): No consigo contactar. ··············· Envío coreo a A. Jurídicos CTAEx: "He recibido llamada de Pilar, Directora Residencia de Logrosán (639 58 54 89). Dice que María, TS del Ayto, le ha informado que el padre de Valentina tenía dinero cuando falleció, pero posiblemente como no se hizo la DECLARACIÓN DE HEREDEROS, bloquearían su cuenta bancaria. Yo no sé si a las cuentas que se refieren son otras en las que estuviera él sólo como titular, pues en el inventario constan varias en que ambos eran titulares. En la rendición de este año siguen apareciendo 3, dos de ellas junto a su padre como titular (entiendo que son las mismas y que con las fusiones de entidades bancarias han cambiado la numeración) Ángel, como dijiste que te ponías a ello, te lo comunico más que nada para que lo tengas en cuenta, por si acaso." ······························································································································································································· Ana: Envío correo a Ángel, A. Jurídico: "Te reenvío correo con notas simples relativas a las propiedades de VALENTINA FERNÁNDEZ TREJO y su padre, que me hacen llegar desde la Residencia FEMAR."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-11-21','-Amalia : está pendiente de revisión de medidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2023-11-21','Ana: Tras hablar con Jesús, pareja de Pilar (613 33 66 47), envío correo a Icíar, S. Ecca.: "hay que hacer la primera autorización de retirada de efectivo (Asignación de 80€/mes) para la próxima semana que ya habrá cobrado, dejándolo abierto de lunes a viernes en la oficina de AHIGAL. Creo que os comenté que tienen intención de mudarse a otra localidad, pero de momento siguen en ésta viviendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-11-21','ADOPCIÓN DE MEDIDAS JUDICIALES DE APOYO Mediante Auto n.º 92/23, de 18 de julio, dictado el Jzdo. de 1.ª Inst. e Inst n.º 2 de Trujillo, se adoptan medidas judiciales de apoyo en la figura de Curador Representativo.***El expte. físico pasa del armario de las curatelas/CA (04/C/17) al de las tutelas/CR (04/cr/17).******Se procede a la modificación del expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2023-11-21','miguel, solicito certificado de nacimiento (para ratificar la herencia cuando llegue) Envío email a Alberto y Tere: Buenos días Alberto, han enviado la factura de la notaria tal como te indiqué en el email de debajo. Mira a ver con qué saldo cuenta para la tramitación de la herencia, ya que necesitaremos la intervención de abogado para la aprobación judicial de herencia y venta, y resto de trámites como inscribir en el registro de la propiedad…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-11-21','TERESA Buenos días! Acabamos de entrar ahora ya que hoy trabajamos por la tarde. Hemos hablado con la sargento y nos dice que no va a detener a Aitor y que ve un peligro la denuncia ya que Aitor quedaría en casa con Felisi. Nos dice que va a comunicarlo hoy mismo a la fiscalía y desde allí nos pedirán un informe para que contemos toda la situación. Nos dicen que les parece más seguro ya que Aitor no se enterará. A nosotras también nos parece buena idea. Seguimos hablando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2023-11-21','Ana: Tras llamada de Pilar, Directora del Hogar San Vicente de Paúl (671 016 615 // direccion.hgsvplasencia@gmail.com), tal y como acordamos: 1- Envía correo a ctutelar@ a la A/A de Estrella, S. Ecca: "Mª del Carmen Matillas Jiménez comienza su tratamiento de ortodoncia hoy, día 21 de Noviembre, por lo que, tal y como se acordó con el odontólogo, se tiene que abonar el primer 50% de dicho tratamiento" ·············· 2- Envío a Pilar Póliza de Seguro de Hogar, para que den parte del "latiguillo" del inodoro de la vivienda de Mª Carmen que se ha roto. ······························ 3- Envío correo a Alberto: "Esta mañana he recibido llanada de Pilar, TS y Directora del Hogar San Vicente de Paúl, Plasencia. Entre otras cosas, quieren solicitar CITA PRESENCIAL para MARÍA DEL CARMEN JIMÉNEZ MATILLA. Uno de sus principales miedos es no tener dinero para cubrir sus necesidades y esto le genera mucha ansiedad. Aunque allí siempre le tranquilizan transmitiéndole que para eso está la CTAEx, que puede estar tranquila, lleva ya bastante tiempo haciendo esta demanda. Al parecer, al principio, cuando se aceptó el cargo, hicieron lo mismo, le atendieron presencialmente explicándole la situación de sus cuentas y mostrándoles movimientos. Por lo que piden volver a hacer lo mismo. Entienden que las próximas fechas son complicadas y plantean el poder hacerlo después de las navidades. ¿Te parece dar cita lunes o jueves a partir de la última semana se enero (a partir del 27)? Los días 11, 15 o 18 de enero también podría ser. Porque entiendo que querrás que esté yo, ¿no es así?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-11-21','TERESA Buenos días! Acabamos de entrar ahora ya que hoy trabajamos por la tarde. Hemos hablado con la sargento y nos dice que no va a detener a Aitor y que ve un peligro la denuncia ya que Aitor quedaría en casa con Felisi. Nos dice que va a comunicarlo hoy mismo a la fiscalía y desde allí nos pedirán un informe para que contemos toda la situación. Nos dicen que les parece más seguro ya que Aitor no se enterará. A nosotras también nos parece buena idea. Seguimos hablando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-11-21','miguel, Inés ha intentado vía telefónica y por email varias veces solicitar al juzgado que dé orden al registro civil para que inscriban que la Ctaex es quién ejerce el cargo de tutor. *************************************************** Me llama Coro para decirme que el despacho de José Lavado le confirma que el Auto que se estaba modificando en el juzgado sigue pendiente y que no sabe cuándo lo van a dictar. Le doy los datos de procedimiento de nombramiento a la Ctaex y juzgado para que vaya y pida emitan lo antes posible que den orden al registro civil de Badajoz para que éste inscriba que la Ctaex es el tutor de Isabel Moreno','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2023-11-21','Ana: Llamo a la Notaría de Trujillo - Lourdes Pérez Cortés (927 32 03 64): las líneas están ocupadas. ·········· Envío un correo (lpcortes@notariado.org): "Desde el Gabinete Técnico de la Comisión Tutelar de Adultos, queremos solicitar presupuesto para hacer el testamento en su notaría una persona cuyo cargo ostenta la Comisión Tutelar (CTAEx): Dª ISABEL MUÑOZ MELCHOR, con DNI 11762962A. Una vez nos lo hagan llegar y sea aprobado el mismo por parte de la sección económica de la CTAEx, procederemos a solicitar cita a tal fin. Ante cualquier cuestión, no duden en contactar, ya sea conmigo o con cualquiera de los Asesores Jurídicos de la CTAEx: Ángel (924 00 31 90) o Miguel (924 00 38 09)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-21','miguel, hacemos el poder apud acta. Y se lo envío por email al abogado Juan Pablo Serrano Muñoz >3116@icaba.com>: Buenos días Juan Pablo, adjunto el poder apud acta a favor de la procuradora para el procedimiento de ejecución del laudo. También te adjunto sentencia de incapacitación y acuerdo de aceptación del cargo de tutor por la Comisión Tutelar. Cualquier documentación o información que necesites dimelo. Por favor, habla con Maria Granada para que te informe y aclare la operación para que no haya errores. Recuerda que quién demanda es la Comisión Tutelar de Adultos en nombre de Carmen Leal Benito (incapacitada y tutelada por la Comisión Tutelar de Adultos)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-11-21','miguel, hacemos el poder apud acta en los jzdos de Mérida y se lo envío a la abogada Eva Mª. Pérez Escarmena >eperezescarmena@icac.es>: Buenos días Eva, adjunto poder apud acta. Envíame la documentación del procedimiento que vaya habiendo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-11-21','Ana: envío coreo a la Secc. Ecca. con copia a Rosana (a.corral@grupociudadjardin.com): "Os reenvío correo de la Residencia Amada Corral con DECLARACIÓN JURADA de nuevo acompañamiento realizado a JOAQUINA MAYORA PIZARRO y que hay que abonar (40€), en cuanto tengáis acceso a las cuentas (no sé si tenéis ya) hay que abonar éste y el otro que se dejó a deber. Ya iremos viendo porque además de pagar la residencia también, en cuanto se pueda, hay que ver el resto deudas que tenía e ir solventando poco a poco…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-11-16','miguel, Amalia me envía email de la directora del centro para cualquier duda de la herencia: Buenas, te paso contacto de la directora del centro . Sandra Sánchez >ssanchez@inteligencialimite.org>','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-11-21','Ana: Llamada de José Manuel desde Ba. Dice que ha ido a pasar el día con su amiga Sonia Valcárcel (también a cargo de la CTAEx). Se ha ido sin dinero, pues ya ha gastado su asignación semanal y ha intentado sacar en una oficina bancaria de Ba. Le han dado un número pin para sacar dinero con la cartilla, pero no ha funcionado. Pide que se le haga una autorización, se le explica que ya no es posible (son las 13:50 h) y aunque lo fuera ese gato extra no está autorizado, ya le explicaron que hasta enero-febrero no puede pedir más extras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MONROY'and apellido2='LLERA'),'2023-11-21','Amalia : llega citación judicial para medidas judiciales de apoyo aviso a RM La Granadilla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-11-21','Ana: Correo de Alberto, J. Secc. Ecca.: "SALDO 21/11/2023: 13.910,67 €------HACE 1 AÑO: 16.855,36 €--------HACE 2 AÑOS: 19.666,90 € EVOLUCIÓN SALDO BANCARIO: DEL HISTORIO SE OBSERVA QUE DURANTE LOS ÚLTIMOS 2 AÑOS HA PERDIDO 6.000 € APROX., ESTO ES 3.000 €/AÑO. PREVISIÓN PARA 2024: -3.300 €/AÑO, SI LA SITUACIÓN ES MÁS O MENOS SIMILAR A LA DE 2023. SI LOS ACOMPAÑAMIENTOS SE DISPARAN O APARECEN GASTOS IMPREVISTOS ESTE IMPORTE SERÍA SUPERIOR EN DICHAS CUANTIAS. GASTOS: NO HAY GASTOS RELEVANTES, EXCEPTO EL COSTE DEL CENTRO 1.670 €/MES. ······ OBSERVACIONES: SALDO HOY + DEPOSITO: 13.900 + 18.600: 32.500€---SI CADA AÑO GASTAMOS -3.500 €----TENDRÍAMOS PARA 9 AÑOS APROX. ANTES DE DEJAR LAS CUENTAS A "0". ANA: NO SABEMOS LA FECHA DE CADUCIDAD DE ESTA PERSONA PERO LA DE SU DINERO SI. VAMOS A INTENTAR RECUPERAR LOS DEPÓSITOS Y MANTENER ESTA SITUACIÓN TODO EL TIEMPO QUE SEA POSIBLE"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESSICA ESPERANZA'and edp.apellido1='LEON'and apellido2='ENCINAS'),'2023-11-21','Ana: Correo de Isabel Cuesta, SS.TT. - Equipo Acogimiento Residencial - Menores - CC (isabel.cuesta@salud-juntaex.es): " en el día de hoy ingresa Jéssica León Encinas en el Centro de Mensajeros de la Paz de Nuñomoral. Acaba de llamarnos Esther (Tr.S) de Proa por el tema de la permanencia de la niña en el CEE, le hemos dicho que hable contigo Maite. En el día de ayer realizaron la reunión de coordinación entre los Equipos Educativos de Mensajeros de la Paz y el Centro de Menores. La niña no ha dejado de llorar desde ayer, cuando supo del traslado al nuevo centro. Esperemos que se vaya adaptando bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-11-21','Ana: Llamo a Teresa Nogueira, Novaforma (662 337 460): están todavía esperando, pues la familia y el propio Juanjo han pedido una semana. Como son 15 días para el ingreso, estamos en plazo. ··················· Cree que finalmente va a rechazar la plaza, pues ni Juanjo quiere irse de Cáceres ni el hermano ni la cuñada quieren realmente. ····································································································································································································· Llamo a Rosa Res. - Fuente de Cantos (623 250 542): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2023-11-21','Ana: Correo-respuesta de Julio, Aux. CTAEx: "lo registro a la gerencia de área porque los Centros de Salud no tienen buzón propio ... Te lo digo por si tarda en llegar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2023-11-21','Ana: Respondo al correo-consulta de Tensi, TS, sobre el abono del servicio de podología: "Dependiendo de cada caso, si la persona tiene autorizado suficiente dinero de bolsillo, a veces lo paga ella directamente. En algunas residencia, le pasan directamente el cobro por la cuenta. Otra opción sería pagar varios recibos a la vez (los que se acuerden) directamente al Podólogo mediante transferencia bancaria, para lo que necesitaríamos además del número de cuenta, las facturas de los servicios para justificar el gasto. *Pongo en copia a las compañeras de la Sección Económica para que se pongan en contacto contigo y en función del caso acordar una forma u otra. Compis, en el hilo viene los datos de contacto de Tensi. Tensi, si quieres llamar tú directamente estos son los teléfono de las compañeras que suelen llevar los pagos: - Lourdes: 924 00 85 48 - Estrella: 924 00 85 43"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-21','miguel, email de la hermana Carmen santos gp >maluker6@hotmail.com> Hola Miguel, me pasan de la Caixa la póliza de seguro de vida que queríais. Soy hermana de Enrique Santos García-Puente. Saludos María del Carmen Santos García-Puente Tel 606704973','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='COLIN'and apellido2='PEREZ'),'2023-11-22','miguel, me llama el denunciante por supuesto delito de hurto, para preguntar por el procedimiento (movil 637566292) Llamo al jzdo nº3 de Mérida y pregunto por las Diligencias Previas Procedimiento Abreviado 28/23 y me dicen que se ha transformado en Proced Delito Leve 83/23 y que han comunicado la vista para 31-1-23. Al sepad le consta el recibi el 9-11-23 y el denunciante Antonio Pacheco (trabajador del CSS) se lo han notificado a su domicilio de Cáceres. Llamo a Antonio para informarle. Envío email a Inés, y a la parte social para que estemos pendientes de la vista','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-11-22','miguel, recibo email de menaya Menayaasesores (joaquin) >joaquin@menayaasesores.es> DOCUMENTACIÓN NECESARIA PARA HACER PRESUPUESTO: •DNI o certificado de empadronamiento de la persona fallecida. •DNI de todos los herederos. (HERMANO Y TÍA) •Certificado de últimas voluntades. (LO SOLICITAMOS NOSOTROS) •Certificado de seguros de vida. . (LO SOLICITAMOS NOSOTROS) •Certificado bancario de saldos en cuentas corrientes y depósitos donde consten los saldos de las cuentas donde estuviera como titular antes del fallecimiento, indicando los titulares y los movimientos del año anterior al fallecimiento. Fotocopia de la cartilla del banco donde consten los titulares y el movimiento a la fecha del fallecimiento. •Certificado de defunción. (LO SOLICITAMOS NOSOTROS) •Escritura de propiedad de inmuebles o terrenos. •Recibos del pago del IBI de dicha propiedad. (Urbana) •Facturas de los gastos que se le han ocasionado como consecuencia del sepelio. Deben ser originales y ha de constar el pago de las mismas. •Fotocopia DNI testigos. •Fotocopia compulsada certificado minusvalía (VEO QUE EN LA DOCUMENTACION ESTÁ). •Si hubiera testamento, será necesario para tramitar la herencia. •Si no hubiera testamento, será necesario: - Libro de familia original o certificado de nacimiento de los descendientes y el certificado de defunción de alguno de los descendientes si también hubiera fallecido. - Certificado de matrimonio del fallecido o fe de soltería Presupuesto: 1º.- Tramitación de la liquidación del impuesto de sucesiones, cálculo del impuesto y autoliquidación del mismo con presentación del impreso en la administración correspondiente o, alternativamente, solicitud al organismo competente para que proceda a liquidar el impuesto y revisión de la liquidación efectuada con realización de alegaciones en caso necesario. 2º.- Tramitación completa del acta notarial de declaración de herederos ab-intestato, por no existir testamento. 3º.- Intervención y asesoramiento en el inventario de bienes y valoración de los mismos y en su caso, redacción del cuaderno particional, para su presentación en la Junta de Extremadura. 4º.- Inscripción de bienes en los distintos registros de la propiedad. 5º.- Se advierte de manera expresa, los honorarios presupuestados no incluyen el pago del Impuesto sobre el Incremento de Valor de los Bienes de Naturaleza Urbana (plusvalía) del Ayuntamiento correspondiente, será presentado a liquidar, pero será a los mandantes a quienes les llegará las cartas de pago, haciéndose ellos cargo del reembolso de dicho impuesto. De igual modo, los honorarios presupuestados no incluyen ni la cuota del impuesto, gastos de notaría ni los gastos devengados en los distintos Registro. En concepto de pago por las cantidades devengadas en la tramitación del expediente completo asciende a la cantidad de MIL QUINIENTOS EUROS (1.500 €) MÁS IVA. Por cualquier otra intervención compleja distinta a las anteriores se calculará la minuta de honorarios conforme los Criterios Orientadores del Ilustre Colegio Provincial de Abogados de Badajoz. Cualquier trámite distinto de los realizados hasta la obtención de la sentencia en primera instancia se minutarán, a parte aplicando a la cantidad acordada por primera instancia, los porcentajes previstos en los Criterios Orientadores del Ilustre Colegio Provincial de Abogados de Badajoz, ya sea un posible recurso de apelación o de cualquier otro tipo y la ejecución de la sentencia ------------------------------------------------------ Reenvío email a Sandra del Centro, Sandra Sánchez >ssanchez@inteligencialimite.org>, con copia a Amalia Buenos días Sandra, me remiten de la gestoría que va a tramitar la herencia de Jose Maria la documentación que necesitan para realizar la gestión. Por favor remíteles dicha documentación directamente con copia a mi cuando la tengas. La persona de contacto es Joaquin, Menayaasesores (joaquin) >joaquin@menayaasesores.es> Teléfono 924-220588. ------------------------------------------------------- Contesto a Joaquin Menayaasesores (joaquin) >joaquin@menayaasesores.es>: Gracias Joaquín, reenvío tu email para que recaben la documentación y te la remitan. En cuanto esté todo y sepamos presupuesto vuestro os haremos la transferencia del importe que nos indiquéis','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-11-22','miguel, recibo email del abogado Enrique Perianes, adjuntando escritos de subsanación al juzgado aportando la tasación para el procedimiento autorización de venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-11-22','miguel, Tere nos reenvía a la parte jurídica email de Ana Mª Arroyo Montaño del Plena Inclusión de Zafra: social@plenainclusionzafra.org >social@plenainclusionzafra.org> Buenos días Teresa!! Remedios de nuevo, tuvo una ingesta ayer por la tarde: una pieza de dominó. Se le acompañó al hospital y finalmente decidieron darle el alta a la espera de que la expulsase la pieza por si misma aquí en el centro. No sabemos cómo evolucionará…esperemos que bien y no necesite ingreso ni ninguna otra intervención. Si necesitase volver y quedarse en hospital…podría tener acompañamiento?? Duración de horas aproximadas?? Y con respecto a las intervenciones, ha surgido en más ocasiones de este tipo con Reme, que al llegar al hospital, han informado al acompañante (casi siempre ha sido el coordinador de residencia) de la necesidad de firmar el consentimiento para realizar pruebas o intervenciones más invasivas para extraer el objeto. El coordinador siempre muestra su rechazo al firmar cualquier tipo de documento de ese tipo por miedo a hacerlo responsable y sufrir consecuencias de algún tipo si las cosas no van bien. Sabemos que desde la comisión tenéis esa responsabilidad delegada en las entidades como guardadores de hecho, pero si Lola no está en el centro y teniendo en cuenta que no vive en Zafra, la situación se dificulta y se demora en el tiempo hasta poder conseguir esa firma… habría posibilidad de que tuviéramos documento por vuestra parte en la que se autoriza a esa firma sin perjuicio al trabajador que acompañe en ese momento?? O podéis asesorarnos vosotros, sobre la mejor actuación en estos casos?? Entendemos que no tener una firma a tiempo también podría ser “perjudicial” en nuestro papel de guardadores. Entendemos que sería para cualquier representado por vuestra parte aunque el caso de Reme es tan particular y tan recurrente que es el que más preocupa en este momento. --------------------------------------------------------- mi contestación: Buenos días, en casos urgentes como este, la persona que le acompañe firma la autorización que corresponda para su intervención conforme las indicaciones que los facultativos del hospital indiquen, a expensas que posteriormente se nos remita a la Comisión Tutelar para que dicha autorización sea ratificada por nuestra Gerente. Recuerda al centro que no somos guardadores de hecho sino curadores representativos o asistenciales (antiguas tutelas y curatelas) No deben preocuparse de responsabilidades, ya que están firmando una autorización para una intervención urgente que les he requerido por el facultativo del hospital y que para su tranquilidad después nos pueden enviar para ser ratificada por la Comisión Tutelar de Adultos. En fin…a medida que vaya teniendo más información sobre la evolución de Reme te iré contando, seguimos en contacto!!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='LEAL'and apellido2='PARRA'),'2023-11-22','-Amalia , escribe la psiquiatra de la UHB , le vamos a reenviar firmada tb por la gerente la solicitud de CRR . Sobre su estado me comenta: Está algo más estabilizado pero mi idea es que pase tiempo en CSS (UME / URH). Tiene la valoración para acceder al CSS mañana a las 12:30 horas. Muchas gracias Amalia por la rapidez en la respuesta Saludos Dra. Taciana Valverde Calvo FEA Psiquiatría UHB de Mérida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2023-11-22','Ana: Envío correo a Isabel Mª Cuesta, TS SSTT CC - Equipo de Acogida de Menores (isabel.cuesta@salud-juntaex.es): "Quería preguntarte por la Resolución del Grado de Dependencia de Ana María, imagino que la valoraron en Málaga, porque en SIDEX no la tienen subida y la necesito para solicitar el complemento de 3ª persona de PNC. ¿Podríais comprobar si la tenéis en el expediente y, en tal caso, enviármela? Gracias de antemano. Seguimos en contacto." ···································································································································· Cumplimento y subo al portafirmas digital la SOLICITUD DE PNC.','2');
