insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='MARQUEZ'and apellido2='CABEZA'),'2023-11-22','-Amalia , escribo a Lourdes. A ver el extra mensual de 97€ se va a cambiar y se sube a 150€ al mes , es fumador y no le llega con los 97€ Y para Navidad pidió sólo 150€ que Alberto ya autorizó . Tiene ahorros para poder hacer estos cambios. Doy OK parte social .','2');
