insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2023-11-23','TERESA Buenos días Teresa , informarte sobre Aarón ya que es tutelado y justo te envie los informes de él el otro día. Ayer tuvieron que ser llevarle al hospital Don Benito y esta mañana también se lo van a llevar al hospital por conductas muy agresivas agresivas hacia sus compañeros y trabajadores. Concretamente ayer agredió a dos compañeros de su módulo y esta mañana ha ido por el mismo camino. Cualquier cosa me dices, gracias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-11-22','TERESA Deciros que hoy ha sido el último día que acompañamos a la familia. Hasta ahora lo hacíamos porque es una familia que conocemos de toda la vida, ( a pesar de que no entre en nuestras funciones el acompañamiento a tutelados) pero no estamos dispuestas a aguantar faltas de respeto ni voces de Aitor. Además, él nos ha expresado que no quiere que trabajemos con él y puesto que nuestro programa es voluntario, vamos a dejar de hacerlo. Además demanda independencia, un alquiler para vivir solo. La cita de Felisi es la única, que sepamos, que tiene pendiente. Aitor está pendiente de recibir la del CEDEX y la de Salud Mental, como la perdió, tendrá que volver a solicitarla en el médico de atención primaria para que vuelvan a derivarle, si es que quiere ir. Cualquier duda que tengáis no dudéis en decirnos, estamos a vuestra disposición.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-11-23','miguel, llega citación por sirex para 17-1-24 LEV JUICIO SOBRE DELITOS LEVES 0000012 /2023, del jzdo nº6 de Cáceres. Envío email a Ana, Inés, con copia a Angel: Buenos días, Inés, por favor, solicita al juzgado nombren abogado de oficio para la citación del día 17-1-24. Solicita también que si se precisa nuestra asistencia sea por videoconferencia. Y coordina con Ana por favor la asistencia de José Manuel ese día, recuérdaselo más adelante.','2');
