insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2023-11-23','TERESA RECIBO LAMADA DE LA TS DEL CENTRO DE SALUD 41610 Y ME INFORMAR QUE RAMON NO HA IDO A PONERSE EL INYECTABLE YO LE LLAME LA SEMANA PASADA PARA AVISARLE Y ME DIJO QUE SI SE LO HABIA PUESTO INTENTO CONTACTAR CON EL PERO NO ME COGE EL TELEFNO 623441939 LLAMO A SU HERMNAO LUIS 641415819 Y LE DIGO QUE ME PASE CON EL LE INDICO QUE TIENE QUE IR A PONERSE EL INYECTABLE DE LO CONTRARIO NO PODRA SACAR SU ASINGANCION EL LUNES A LO CUAL RESPONDE DE MANERA AGRESIVA E INSULTANDO LE COMUNICO A LA TS QUE ESTA COMPLICADO QEU VAYA A PONERSE EL INYECTABLE, ABORDAREMOS DE NUEVO EL TEMA CUANDO CONTEMOS CON LA EDUCADORA EN DICIEMBRE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-11-23','-Angel : Antonia puede resolver al contrato, con 30 días de antelación. Tiene una penalización, por resolver el contrato antes del año firmado, de 119 euros. Si me lo confirmas, voy preparando la renuncia para enviársela al arrendador.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-11-23','TERESA RECIBO LLAMADA DE PAULA EN RELACION A JUCIO POR ABUSO SEXUAL SUCEDIDO CUANDO ESTE EN EL CENTRO DE MENORES PEDRO DE VALVIDA TIENE UNA CITACION EL PROXIMO 6 DE FEBRERO A LAS 9:00 HORAS EN MERIDA DEBE IR ACOMPAÑADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-11-23','Ana: Envío a la S. Ecca.: "Os reenvío correo con carta informativa de la VACACIONES DE NAVIDAD de la ONCE que le han concedido a Ventura Gómez García, al igual que el año pasado. Esto está hablado y autorizado. Habría que abonarlo. He leído la carta, pero no me termina de quedar clara la cuantía, pues no sé si le corresponde algún descuento. Quizá vosotras lo veis con más claridad. No obstante, según indicación de la TS, si tenéis dudas podéis poneros en contacto con: - Cristian: CRDR@once.es // 927 62 74 80"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-11-23','Ana: Llamada de Carlos (644 949 205): solicita extra para Navidad de entre 200 - 250 € parar retirar la semana del 18 de diciembre. ······ Envío correo a Alberto, Jefe S. Ecca, solicitando el extra. ····························································· Carlos también me informa que está con una chica que se llama Bea, tiene un niño de 7 años y una niña de 4 años. ···· Viven en la barriada de San Blas. ············································· La pierna va bien. ································································ Está participando en la Asociación Oncológica del Cáncer como VOLUNTARIO. Están llevando cosas a los hospitales y visitarán a niñ@s hospitalizados. ······························································································································· *Le ha llamado Guadalupe, TS del SAD - IMAS: Le han confirmado que le dan de baja tanto en el SAD como en el Catering Municipal por mal uso de los mismos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2023-11-23','Ana: Nos avisa Miguel, Vigilante Seguridad, que ha acudido de forma presencial Abraham, hijo de Pilar, y otro Sr. que no se quiere identificar. Dicen que no se irán hasta que se les haya atendido. ······ Se le recuerda que hay un protocolo y no se le va a atender sin cita previa. Abraham lo sabe porque se lo he dicho en alguna ocasión. ················· Llamo por teléfono Abraham, quien enseguida me pasa con Fernando Agorreta, Abogado (631 17 19 18). Expresan que lo que quieren solicitar es que Abraham pueda acudir a retirar la asignación quincenal, él sólo, sin necesidad de que acuda su madre, la cuál dice estar actualmente muy mal físicamente y lo pasa mal cada vez que tienen que acudir. ······························· Tras valorarlo con Maite, envío mail a Alberto planteando esta opción. A partir de diciembre solicitaremos a Futuex que intensifiquen el seguimiento en el domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2023-11-23','Ana: A petición de Estrella, S. Ecaa, envío correo a Belén Pavón: "Me dicen las compañeras de las sección económica qué de qué cuantía estamos hablando, para que se pueda autorizar un EXTRA PARA NAVIDAD. Por favor, indícales sí se haría mediante reintegro, como en el extra de verano, y confirma la oficina dónde tendría que enviar la autorización. Si no te importa escribe directamente a Estrella, de la Sección Económica: estrella.guerrero@salud-juntaex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2023-11-24','-Amalia : le envio por email : antoniaremediol@gmail.com el cdo. pensiones para que le puedan dar los alimentos. De momento seguimos con el alquiler , es posible que en Enero vuelva a trabajar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2023-11-24','miguel, llega email de Alberto con copia a la parte económica, social y juridica: AREA JURÍDICA: SABEMOS ALGO DEL TEMA DEL EMBARGO QUE IBAMOS A RECURRIR: EMB. JUDICIAL 06931601E-JUZ.EMB.MECAN. X 11.453,58 € DE FECHA 24/11/2021. ESTRELLA: ESTA TUTELADA TIENE DECESO CON OCASO, PERO APARECE UN CARGO DE REALE SEGUROS...XFA AVERIGUA DE QUE SE TRATA: 09/01/2023 REALE SEGU466781 44285G302214 -250,26 ANA: NO HAY PROBLEMA EN MODIFICAR EL REINTEGRO...YO TENGO UNA DUDA PERSONAL: HE VISTO, X CASUALIDAD, UNA SENTENCIA DONDE DICE QUE EL HIJO TIENE ESQUIZOFRENIA RESIDUAL...ENTENDEMOS QUE DE TODAS FORMAS ESTA PERSONA ESTÁ CAPACITADA PARA MANETAR ESTOS REINTEGROS DE FORMA QUE SU MADRE SEA BENEFICIARIA. MARIA: SI ANA NO TIENE INCONVENIENTE ALGUNO, MODIFICAS EL REINTEGRO PERMANENTE PARA QUE PUEDA SACAR EL DINERO EL HIJO DE LA TUTELADA. D. ABRAHAM MENDO GARCÍA (28944285G)...275 €/QUINCENA. MARIA: NO VEO RENDICIÓN ANUAL POSTERIOR AL 2015 ----------------------------------------------------- mi contestación: Buenos días, de este expediente había dos cuestiones: 1.-Carmen Miñarro de una asesoría nos pidió durante mucho tiempo la enviaramos certificado de nacimiento correctamente inscrito en el registro civil de Madrid, para inscribir unas escrituras creo que era de servihabitat, en el registro de la propiedad. Inés puedes hacer un filtrado para ver si finalmente se lo enviamos? No lo recuerdo… 2.-Tengo apuntado del tema del embargo un único apunte en la intranet del 11-3-22, que es lo único que sé…pues creo que no me llegastes a contestar Alberto…: “miguel, llega email del abogado Luis Fernando Agorreta Blázquez : Muy señor mio:le adjunto embargo efectuado a Doña Pilar Garcia Moreno por importe de 11.453 euros con fecha 24 de Noviembre de 2021, en los autos de ejecucion de titulos judiciales seguidos en el Juzgado de Primera Instancia nº 4 de Cáceres, y Auto despachando ejecucion con fecha 5 de Septiembre de 2008.En el siguiente email le adjunto poliza de préstamo que ha dado lugar a la ejecucion y le explicito motivos de oposicion. Doña Pilar estuvoi casada en régimen de gananciales.El presupuesto del pleito para honorarios de Letrado y Derechos de Procurador ascenderia a unos 975 euros. Atentamente FERNANDO AGORRETA BLAZQUEZ - Abogado- 631 171 918 ******************************************* reenvio email a Alberto: Buenos días, hay un abogado que se ha puesto en contacto en relación a la tutelada, que pretende impugnar un embargo cuyo origen es un ptmo del que no teníamos conocimiento. El procedimiento origen es del 2008… El embargo como verás en el email de más abajo es de 11.453 euros. Este abogado nos propone tramitarlo, siendo sus honorarios unos 975 euros. Mi pregunta es, hay dinero para asumir el gasto de abogado? Mira las cuentas a ver si le han cargado algo los últimos meses.” A fecha de hoy no sé nada más, y desconozco si Angel sabrá algo… Si queréis que ponga en marcha algo decídmelo para hablar con aquel abogado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-11-24','miguel, llega email de Maria Jesús la vecina MARIA JESUS GARCIA MARTINEZ >mjgarciamar@gmail.com>:Te he llamado un par de veces pero no te he localizado. Hablé con el ayuntamiento de nuevo y me dijo que iban a ver lo que habías enviado y que te contestarán. Creo que hay que esperar a la contestación a ver que dicen, porque será lo único que vamos a tener de manera oficial. El tema de proyecto de demolición, lo ha dicho el técnico (de forma verbal), pero en lo que el ayuntamiento mandó, lo único que he visto es que tenéis un plazo de dos meses para demoler, no pone nada mas. Si puedes avisarme cuando recibas algo del ayuntamiento para ver como actuar, te lo agradecería. ----------------------------------------- La llamo y quedamos que cuando me notifiquen del Ayto la avisaré','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2023-11-24','-Amalia : hablo con Manoli para plantearle la opción de que Regina siga en HOFA hasta los 21 en plaza a parte de menores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-11-23','TERESA ENVIO CONSENTIMIENTO INFORMADO A PETICION DE LA TS POR EMAIL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESSICA ESPERANZA'and edp.apellido1='LEON'and apellido2='ENCINAS'),'2023-11-24','Maite: he hablado con Mónica ,trabajdora social de Mensajero de la Paz Nuñomoral. Jésica llegó al centro el martes 21. Estuvo todo el día llorando, pero hoy está tranquila. Hemos hablado sobre las visitas de la familia. Han acordado que los martes será la llamada telefónica y lo viernes la visita presencial. De momento será en el centro y cuando le den permiso para ir al pueblo será bajo la supervisión de la educadora. En princpio la familia no ha puesto problema. Respecto a que permnezca en el CEE de los Angeles en Cáceres, estamos de acuerdo que no va a ser beneficioso para ella, ya que lo pasa muy mal en los traslados y la tienen que medicar. La frecuencia es semanal. Por otra parte, el transporte de educación llega hasta Pinofranqueado pero el centro no puede recogerla y llevarla en transporte propio. Haremos renuncia a su continuidad en el CEE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='VALERO'and apellido2='AGUEDO'),'2023-11-24','PLAN DE INTERVENCION : INGRESOS: AMALIA: YA SE HA TRAMITADO PFHC PARA + 18 AÑOS CON DISCAPACIDAD . TENGO QUE ADJUNTAR DOCUMENTACIÓN QUE NOS RECLAMA EL INSS Y NO TARDARÁN EN RESOLVER . LA PFHC QUE VENÍA PERCIBIENDO COMO - 18 AÑOS PODÉIS DECIRME QUÉ AÑOS SE HA INGRESADO EN LA CUENTA QUE TERMINA EN... 61254? HAY UN COBRO INDEBIDO GENERADO POR LA MADRE Y ES A ÉSTA A LA QUE YA SE LO HA RECLAMADO EL INSS , DUDO QUE LO ABONE PORQUE ES INSOLVENTE. GASTOS: RESIDENCIA: ACTUALMENTE Y SEGÚN INFORME SOCIAL RESIDE EN CENTRO ACOGIDA ANA BOLAÑOS DE OLIVENZA...AMALIA, DUDAS:      CENTRO: VA A SEGUIR EN ESTE CENTRO DE MENORES O VA A CAMBIAR??? HE CONTACTADO CON EL DIRECTOR Y POR EL MOMENTO NO HABRÍA PROBLEMAS EN QUE SIGUIESE EN ESE CENTRO . NO HAY COPAGO DE LA PLAZA Y TODO LO CUBRIRÁ EL CENTRO SALVO ALGÚN EXTRA QUE SE PUDIERA NECESITAR POR EJ. PARA ALGÚN VIAJE O ROPA QUE INTENTARÁN NO PEDIR PARA PERMITIR MÁS AHORRO. NATALIA ACUDE A DIARIO A BADAJOZ DONDE ESTÁ MATRICULADA EN UN CURSO DE F.P. COSTE CENTRO: IMPORTE?...A DÍA DE HOY Y CON LA POCA INFORMACIÓN BANCARIA, NO HAY CARGOS X ESTE CONCEPTO. NO HAY COPAGO , NO SE ABONARÁ NADA POR CENTRO . ASIGNACIÓN: ESTABLECEMOS? NO , LO CUBRIRÁN DESDE EL CENTRO , SÓLO PEDIRÁN SI SURGE ALGÚN EXTRA. OTROS GASTOS: MÓVIL (CONTRATO/PREPAGO???) TIENE TF DE PREPAGO , DE MOMENTO NO NOS PIDEN NADA . , OTROS. A DÍA DE HOY NO LOS PUEDO CUANTIFICAR. NO CREO QUE HAYA MÁS GASTOS. SEGURO DECESO: PUEDES HABLAR CON CENTRO PARA CONFIRMAR SI TIENE O NO...Y SI PROCEDE FORMALIZAMOS. NO TIENE , HAY QUE HACERLE UN SEGURO DE DECESOS A SU NOMBRE. PARA SECCIÓN ECO : NECESITAMOS ENVIAR AL DIRECTOR DEL CAMP ANA BOLAÑOS , COMO GUARDADOR DE HECHO LA AUTORIZACIÓN QUE SE ENVÍA A OTROS CENTROS PARA QUE PUEDA RETIRAR DINERO EN EL CASO QUE LO NECESITE. PREVIAMENTE CONTACTARÁ CONMIGO SI SE DIERA EL CASO PARA COORDINARNOS. PARA JULIO :NECESITAMOS ENVIAR AL DIRECTOR DEL CAMP ANA BOLAÑOS , COMO GUARDADOR DE HECHO LA AUTORIZACIÓN QUE SE ENVÍA A OTROS CENTROS PARA AUTORIZACIÓNES DE SALIDAS . LOS DATOS DEL DIRECTOR SON : JUAN ANTONIO ARAGON JIMENEZ , DNI 09184142N. REGISTRO PARA PFHC LA SOLICITUD DEMANDADA SENTENCIA , CESE DE J.V Y NOMBRAMIENTO DE ESTRELLA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-11-24','Amalia : se le puede enviar algo de extra para diciembre , igual la mitad de la pensión , sobre 250€. Tiene que mantener algo de ahorro para pagar S. decesos y lo que llegó de IBI y los impuestos del ayuntamiento del pueblo por su solar.','2');
