insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2023-11-27','Ana: A petición de Miguel, A. Jurídico, envío correo a Modesto, Res. Sierra de San Pedro (administracion@centrodemayoressierradesanpedro.es): "En relación a JUAN SANGUINO LANCHO, a requerimiento del Juzgado, necesitamos que nos hagáis llegar a la mayor brevedad un Certificado de Ingreso en Centro, en que se indique la fecha en que ingresó y que a día de hoy continúa residiendo en el recurso." ································ Correo respuesta a toda la secc. jurídica: "Sí, Juan Sanguino Lancho sigue residiendo en Residencia de Mayores de Sierra de San Pedro, sito en: CTRA. NACIONAL 630, KM. 582, de Casas de Don Antonio. CP: 10162 – Cáceres. *Ya he solicitado nos envíen el Certificado de Ingreso en centro con fecha de residencia a día de hoy."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2023-11-27','Ana: Tras hablar con Diana Arroyo, TS Ud. Att. al Estudiante - UEX (618 381 887 / darrpan@unex.es), le envío correo: "Tal y como hemos acordado, para poder solicitar la BECA de la ONCE para personas opositoras con Discapacidad, te envío: - Testimonio de Auto de Remoción del Cargo y Nombramiento de la CTAEx como CURADORA de Sandra Sandín Hernández. - Testimonio de Aceptación del cargo Una vez haya recabado la firma en el documento de Declaración Jurada que me vas a enviar, te lo hago llegar. El resto de documentación, si puedo, que espero que sí, hoy mismo la solicito al INSS." ··································· Envío nuevo correo a Diana, TS UEX: "Te adjunto: - la Declaración Jurada firmada por la presidenta de la CTAEx - El DNI de la Presidenta por Delegación - Decreto Nombramiento Directora Gerente del SEPAD - Resolución Delegación de Funciones – Presidencia CTAEx Ante cualquier otra cuestión, ya sabes cómo contactar."','2');
