insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2023-11-27','Te reenvío correo de Pilar Martín, TS ESM-CC. Su número directo es: 54612','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-11-27','Ana: Llamada de José Manuel (627 788 797): quiere ingresar en URA - CSS Plas. ······· Pilar Martín, TS ESM, le ha dicho que primero tiene que ingresar en UHB. Pero él ha ido a urgencias este fin de semana y no le han querido ingresar porque no había cama. *Se enfadó, se puso agresivo y dio un puñetazo en la pared. *Tuvieron que avisar a Seguridad para que le echaran de allí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2023-11-27','TERESA NOS COMUNICA CORO LA CHICA QUE LAS TAREAS DEL HOGAR EN CASA DE CANDIDO QUE YA NO PUEDE CONTINUAR HABLO CON LA EMPRESA SERVICIOS DEL FRESNO Y CONTRATO LOS SERVICIOS DE LIMPIEZA PARA EMPEZAR EN DICIEMBRE IRA LOS MARTES DE 10:30 A 12:30','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESSICA ESPERANZA'and edp.apellido1='LEON'and apellido2='ENCINAS'),'2023-11-27','Ana: Hablo con Mónica, TS de Mensajero de la Paz - Nuñomoral: Lloró mucho el primer día, pero desde el día siguiente se ha ido adaptando muy bien. Está totalmente adaptada ya al centro, juega al fútbol, que le encanta, participa en las actividades y en los talleres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-11-27','Ana: A petición de Ángel, A. Jurídico, envío correo a Diana, Directora, y Leyre, TS, de la Res. solicitando informe actualizado para remitir al Jdo. ········································ Envío correo a Ángel, A. Jurídico y Alberto, Jefe Secc. Ecca: "Adjunto INFORME SOCIAL, no ha habido variación en su situación en los últimos 2 meses, y así lo hago constar. Adjunto también en PDF los dos últimos correos de la Directora de la Residencia comunicando la nuevas incidencias relacionadas con la sobrina y que han tenido lugar durante este mes de noviembre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2023-11-27','TERESA ME LALMA MANUEL PRIMO DE TOMAS 697723974. SOLICITA DINERO EXTRA PARA COMPRARLE COMIDA PARA NAVIDA Y CAMBIAR LAS RUEDAS DEL COCHE DE TOMAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='GUISADO'and apellido2='GONZALEZ'),'2023-11-27','Amalia : esta Sra. es de las nuevas, se encuentra en CSS Mérida. Solicitan que le remitamos la autorización para que puedan retirar algo de dinero al mes , será poco. Tiene domiciliado en su cuenta : -S. decesos ( OCASO ) -2 TRASTEROS para recoger sus muebles , se dejó el alquiler . 150€ al mes . -66% COPAGO de la plaza, está en URH. Es soltera , tiene una prestación en favor de familiares de 1231€ y 23000 de ahorro. Padece tno. psicotico y un GºIII dependencia. De momento no se ha solicitado R.Mayores pq la Sra. no quiere , pero sería el recurso indicado. Tiene un hno. con el que no tiene ninguna relación. Hay una amiga que la visita a menudo de la Zarza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2023-11-27','-Amalia: LLamo a Antonio , de Inversiones ANTOPA S.L. dueño de los trasteros .Tf . 660051842 y email inversionesyactivos@gmail.com. En un mes tendrá 2 trasteros libres de 12 y 18 metros y uno de 8m. El metro es a 12€ al mes . Está ubicada en Meirda ,por la rotanda de 3 fuentes , Ctra. de Cácers ,los está haciendo nuevos. Valorar si cogemos esto. TRASTEROS para recoger sus muebles , se dejó el alquiler . 150€ al mes . -66% COPAGO de la plaza, está en URH. -------------------------- Después de estudiar los precios de los trasteros +mudanza ... económicamente se queda igual que mantener el piso que tiene y los muebles estarían mejor conservados . De momento se queda así .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESSICA ESPERANZA'and edp.apellido1='LEON'and apellido2='ENCINAS'),'2023-11-27','Maite: he enviado por correo electrónico al CEE PROA escrito comunicando la baja de Jéssica. Lo he subido a su expediente. Buenos días, Soy Maite Gómez, de la Comisión Tutelar de Adultos. Hablé con Esther sobre la posibilidad de que Jéssica León Encinas continuase en vuestro centro y , como hasta ahora, los fines de semana fuese a su centro de referencia , que ha pasado a ser Mensajeros de la Paz en la localidad de Nuñomoral. Debido a lo difícil que supone para ella realizar el viaje semanal y ante la imposibilidad de facilitar el transporte hasta el mencionado centro, comunicamos su baja en el CEE. Gracias Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='LEAL'and apellido2='PARRA'),'2023-11-27','-Amalia : Ingresará en CSS , a la URH directamente,el 14 diciembre. Ha llamado su madre, Ana Mª , tf 633613809 , hace 1 año que no teine relación con el hijo . Nos pide un chandal y 1 movil que su hijo le ha pedido. Cuando ingrese en CSS iremos viendo qué necesita y qué se puede comprar. De momento la cuenta la tiene a 0 y allí no es necesario el movil. No hay copago en CSS . Nos irá informando Lola .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-11-27','Ana: en relación a los escritos con solicitudes de Juan José, Maite remite a Sheila el escrito de respuesta que se emite de desde el Gabinete Técnico CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-11-21','Ana: Correo de Sheila, directora CRR-CC (crr@grupociudadjardin.com): "Adjunto dos solicitudes que la persona tutelada Juan José Bergantiño insiste en enviaros para vuestra valoración. Ambas solicitudes han sido planteadas al Terapeuta Ocupacional, especificándole este que ninguna se ajusta a necesidades reales. Una de las solicitudes esta relacionada con la compra de una mancuernas de 30Kg, debido a su estado de salud se le ha especificado que sería mejor no realizar ejercicios pesados. La otra solicitud va en relación a viajar varios días en las fechas navideñas, este viaje no está planificado con nadie de su familia y no tienen finalidad alguna, su única intención es pasar unos días fuera del CRR sin supervisión." ······················· Mi respuesta: "Gracias por hacernos llegar sus solicitudes y, sobre todo, la valoración que hacéis desde el recurso al respecto. A lo largo del día de hoy, o mañana si hoy no fuera posible, os enviaremos un escrito-respuesta para que podáis entregársela a Juan José Bergantiño y, si lo consideráis, abordar de nuevo este asunto con él. Pongo en copia a Maite, Jefa de Sección para que pueda leer los escritos de Juanjo y tu correo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-11-27','TERESA Empezamos la semana que una nueva ingesta. Esta vez ha sido unas gomas pequeñas que le ha arrancado a sus propias gafas. Se consultó, ayer, en el centro de salud, y al ser piezas tan pequeñas. La recomendación fue observarla y controlar las heces para ver si las expulsaba. (el pincho de plástico de la semana pasada aún no sabemos si lo ha expulsado) Hemos estado valorando la posibilidad, que nos planteabas el otro día, de solicitar ingreso en psiquiatría y lo vemos acertado teniendo en cuenta la frecuencia y el número de ingestas que está teniendo. Creemos que puede ser de gran ayuda que vosotros, desde comisión, al igual que ocurre con los familiares, hagáis la petición. Hemos pensado que aunque sea por escrito y nosotros mismos lo presentemos a su psiquiatra aquí en Zafra, pero con el respaldo vuestro y vuestra petición igual lo ven más oportuno hacerlo. Sabes que las peticiones de ingreso por nuestra parte, no son siempre favorables.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-11-27','Ana: Tras hablar con Mª Carmen, TS del HSPA, comunicando que a Ventura le darán esta misma tarde el alta al habérsele resuelto solo el Derrame Pleural, envío correo a Guadalupe Cortés, TS SAD - IMAS: "Tan sólo comunicaros que esta misma tarde darán el alta en el hospital según me ha comunicado Mª Carmen, la compañera del mismo. Por tanto puede reestablecérsele a Ventura el servicio de SAD."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-11-27','Ana: Hablo con Ángel, A. Jurídico, sobre la solicitud de Internamiento de Aitor. Desde que acudió a la cita con el Médico Forense no hemos vuelto a saber nada al respecto. ······································································································································ Correo de Ángel: "he hablado con el Juzgado de Primera Instancia nº 3, de Cáceres, que está llevando el internamiento involuntario que pedimos para Aitor (INTERNAMIENTO 608/2023). Nos van a enviar por Lexnet, citación para comparecencia, el próximo 21/12/23, a las 11.30, junto con el informe del ILM."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-11-28','Buenas , os paso email de la gestoría de Josefa Moya , parece que se ha dado cuenta que este caso no le va a compensar económicamente y que el pto. que pedía no lo íbamos a aceptar. Ya no tenemos que responderle .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2023-11-28','TERESA ENVIO ESCRITO A VIVIENA JUSTIFICANDO LA AUSSENCIA TEMPORAL DE JOSE DE LA VIVIENDA YA QUE ACTUALENTE ESTA EN RESIDENCIA LE HAN EXPULADO DE LA DE MEDINA DE LAS TORRES Y A TRAVES DE JOSE EL TS DE MONESTERIO HA SOLICITADO PLAZA EN FUENTE ATENOS DE AZUAGA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2023-11-28','Ana: Remito al REGISTRO (oac.merida.san@juntaex.es): "Adjunto remito la siguiente documentación relativa a Dª SANDRA SADÍN HERNÁNDEZ, cuyo cargo de CURATELA ostenta la CTAEx, para darle registro y remitir a la Dirección Provincial del INSS de Cáceres (Av. de España, 14, 10001 Cáceres): - Oficio Solicitud de Certificado de Prestaciones e Informe de Situación Actual - DNI de la solicitante - DNI de la Representante Legal – Presidenta de la CTAEx - Decreto de Nombramiento de Directora Gerente del SEPAD - Resolución de Delegación de Compentencias (Presidencia de la CTAEx) - Testimonio del auto de remoción y nombramiento - Testimonio de Acuerdo de Aceptación del cargo Ante cualquier cuestión, no dudéis en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-28','miguel, envío email a la aseguradora para conocer el estado del siniestro (el procedimiento de ejecución, Jose Luis Gomez >jlgomez@alkora.es>...(desde el 20-10-23 que se aperturó la incidencia) Buenas tardes, podría informe sobre el siniestro abajo referenciado? La Comisión Tutelar de Adultos, está legitimada para preguntar por este siniestro al ser la representante de la tutelada Carmen Leal Benito, cuyo aceptación del cargo adjunto. Solicito que cualquier información que tengan que remitir nos la hagan directamente a nosotros como representantes de la afectada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2023-11-28','Ana: Envío a los A. Jurídicos el Certificado de Ingreso en Centro que me ha remitido Modesto, Res. Sierra San Pedro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-11-28','Ana: Correo de Teresa, TS CTAEx: "Me ha llamado la madre de Jose que cuando se lo van a llevar… La pobre mujer…. Dice que ha cogido la tutela la junta pero que allí no va nadie y que ella no puede con el…. Le he dicho que ya le llamaran para informarla cuando sepamos donde tiene plaza. Te dejo su teléfono: 927 24 89 86" ················································ Mi respuesta. "A ver si pronto le dan centro y él acepta ir… le dieron Mérida a los pocos meses de aceptar el cargo y lo rechazó… Yo hasta ahora he hablado siempre con su hermano, de la madre no tenía el contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-11-28','Ana: Tras hablar con Chelo, Dependencia, la semana pasada, localizan la Resolución del Grado y la suben al SIREX, que no estaba subida. ·············· Descargo, guardo en el expediente digital y se la envío a Íciar, S. Ecca. para la gestión del Seguro que tenía hecho Víctor Manuel a tal fin.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2023-11-27','Ana: Correo de Icíar, S. Ecca.: "te informo que la hermana de Pilar sacó el sábado 25 la pensión y la paga de la cuenta de Pilar, le han dejado 70 €. Yo ya había enviado la utorización para que retiraran hoy los 80 €, pero va a ser que no. He hablado con Pilar y su pareja para comentárselo, también hablaré con el banco porque, en teoría, habían solicitado cancelación de tarjetas y libretas. No sé, qué podemos hacer porque ellas no van a devolver el dinero, abrir otra cuenta supongo, en fin…" ··············································· Reenvío el correo de Icíar a: Alberto, Maite y A. Jurídicos: "Por favor, leed en el hilo el correo de Icíar, yo sinceramente no sé que podemos hacer, pero está totalmente desprotegida esta mujer. ¿Se le pueden pedir responsabilidades al banco o algo?? ¿Podemos comunicarlo al Juzgado?? No sé el qué pero ALGO TENEMOS QUE HACER!!" ························································ Nuevo correo de Icíar: "He hablado con Unicaja Ahigal y me comenta como que la libreta no estaba cancelada, que se encargaba él (a buenas horas!!). Yo le mandé la solicitud de cancelación de tarjetas y libretas a Juana Heras y ella lo enviaba a la oficina de Plasencia, que es la sucursal origen de la cuenta, y se les habrá pasado…" ································ Correo de Miguel, A. Jurídico: "necesitamos un informe económico lo más detallado posible y Ana, si lo consideras incluso social que indique la desprotección a esta mujer. Si son hechos constitutivos de posible delito hay que comunicarlo a fiscalía."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-11-27','Ana: Correo de ayer de Carolina, Directora CRR (direccion.crrplasencia@grupo5.net): "que ayer día 26 de noviembre, Isabel Cano acude al servicio de urgencias médicas por infección de orina y dolor de riñón en taxi. Al llegar al centro de salud nos llama por teléfono llorando, refiere que el taxista le ha tocado los pechos sin su consentimiento y le ha acariciado, proponiéndola después tomar unas bebidas energéticas. Mantienen conversación por whatsap en la que él le dice que por whatsap no sigan hablando que mejor le llame por teléfono. Las profesionales del recurso acuden al centro de salud dónde se encuentra ella. Vuelve a narrar la misma situación, el médico que le atiende al considerar que no ha habido agresión no realiza parte médico ni ninguna acción, sólo recomendándola denunciar. Se le acompaña a la Policia Nacional, donde se interpone denuncia, se adjunta. Se intensifican los apoyos para apoyarla, ella se siente en todo momento acompañada por los profesionales y dentro de la gravedad de lo ocurrido tranquila y satisfecha con la decisión que ha tomado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRIADO'and apellido2='RODRIGUEZ'),'2023-11-29','Ana: correo de Gloria, Res, al ctutelar@: "Buenos dias, soy Gloria Mayoral, la Directora de los Pisos Tutelados donde reside Maria Jesus Criado Rodriguez. Me comenta , que necesitaría para navidad dinero para poder comprarse regalos y ropa que necesita. Me pongo en contacto Con vosotros, para a ver si podeis hacer el favor de mandarla una autorización extra para que pudiese ir a sacarlo a la banca unicaja, que es donde tiene su cuenta. Yo creo que unos 300 euros la iban a poner muy contenta, pero si vosotros creéis que es mucho, ( aunque es un señora que le gusta comprase cosita de calidad), pues decidid vosotros y ya esta. Ella va a estar muy agradecida, puesto que en estas fechas, ella se pone muy melancólica porque todas sus compañeras se van con los familiares y ella se queda solina con nosotras. Bueno no me enrollo más. Un Saludo , espero alguna contestación. Mi telefono es 600518493" ·································· Doy OK a esta solicitud, caso de ser viable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-29','Ana: Puesto que aún no se le ha dado respuesta a Estrella Durán, TS, respondo a sus correos con copia a Alberto y resto Secc. Ecca: "Por lo que veo Enrique ha acudido solo al banco y ha retirado dinero sin autorización previa desde aquí, quiero decir, en el banco se lo han dado sin más. Pongo en copia a Alberto, jefe de secc. económica para que esté al corriente. Lo que decía Alberto, jefe de secc., al final de su correo (de fecha 17/10), que te reenvié, era que con la AUTORIZACIÓN GENERAL DE CENTROS se os autorizada a retirar 60€/semana además de extras para gastos de aseo u otras cuestiones que consideréis necesarias y cuyo gasto sea coherente. Dijo textualmente: “Por tanto, podéis hacer uso de un máximo de 60€ semana para tabaco y otros gastos de bolsillo. Y para otros artículos necesarios, coherentes, podéis hacer uso de la AUTORIZACIÓN." Por tanto entiendo, a no ser qué Alberto diga otra cosa, que podéis administrarle esos 400€ que habéis guardado en admisión a razón de 60€/semana y adquirir algún otro artículo que consideréis necesario. ALBERTO: entiendo que podéis comprobar los movimientos bancarios y si consideráis enviad escrito al banco. Ya lo veis vosotros." ······························································································································································································ Remito a Julio, Aux. CTAEx: "Cuando puedas, por favor, remite por REGISTRO el siguiente documento relativo a ENRIQUE SANTOS GARCÍA-PUENTE, a la UNIDAD DE ACCESO Y VALORACIÓN DE DEPENDENCIA: - Desistimiento de solicitud de revisión de la situación de dependencia" ·································································································································································································· Envío nuevo correo a Estrella Durán, TS UME: "Tenía pendiente aún este correo de la semana pasada de la hermana de Enrique Santos García-Puente. En relación a la cuestiones sobre las que pregunta, me las puedes aclarar, yo las desconozco todas y no sé si son como ella dice: - ¿Realmente necesita ropa como para ir al pueblo a por ella? - En relación a los dolores de espalda que menciona, ¿le ha llegado a ver el médico del centro y/o derivar a especialista? - ¿Su Psiquiatra le ha dado un pase para ir en Navidad a casa él solo? Lee porfa lo que ha puesto a continuación su hermana. Por cierto, nos ha llegado comunicación del Juzgado sobre el escrito que ha enviado uno de sus hermanos. Creo que ya te comenté en su día que su hermana me lo dijo, que tanto ella como su hermano habían enviado sendos escritos al Juzgado. Esto sólo para vuestro conocimiento." ······························································ *Respuesta de Estrella: "A ver la ropa de invierno tampoco es totalmente necesaria porque ya se ha comprado un abrigo, pero bueno podría ir a coger algún jersey, sudadera y pantalones más gruesos.... Con relación a los dolores de espalda, hoy por primera vez me ha preguntado a mí y no he oído nada al respecto de esa demanda...Ahora lo comento en la reunión de unidad con el Médico Somático... Lo del pase de su Psiquiatra para ir a casa en Navidad no es cierto, lo que no entiendo es cómo su hermana cree todo lo que él dice...." ······················· Respondo al correo de Carmen, hermana, informando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-27','Ana: Correos de Estrella Durán, TS UME: "Podéis aclarar cuánto dinero puede sacar Enrique Santos al mes? Acaba de salir al banco para sacar dinero, quiere sacar 500 euros para que tenga para el mes para gastos de tabaco y bolsillo y además se quiere comprar un abrigo, un reloj, dos camisas y una camiseta. Le hemos dicho que solo compre lo que es necesario que es el abrigo y el reloj Ya nos decís....la asignación mensual porque en un correo anterior vuestro, no me queda muy claro....." ·············· ". Al hilo de este tema, el banco sí le ha dado los 500 euros. Se ha gastado 100 euros en un abrigo y le guardamos aquí en Admisión los 400 restantes para compra de tabaco y gastos de bolsillo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2023-11-29','Ana: Correo de Diana Arroyo, TS Ud. Att. al Estudiante - UEX (618 381 887 / darrpan@unex.es): "Nos dicen desde F. ONCE que tenemos plazo de 5 días para enviar toda la documentación, vamos a intentarlo, de no ser posible lo solicitaremos el curso que viene." ··· Le confirmo que los documentos ya están pedidos. Ahora ya depende de lo que tarden en el INSSS. ································· Nuevo correo de Diana: "Si ya están pedidos imagino que pronto te los darán, Escribí a F.ONCE cuando envié la solicitud de Sandra pero no habían leído el correo, hablé ayer con ellos lo van a a consuktar con el equipo y van a intentar alargar el plazo para ella. Hoy me dirán en lo que han quedado." ················ *Diana confirma que excepcionalmente le han ampliado en plazo en la ONCE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-11-29','Ana: Correo de Paula, TO CRR (tocupacional.crrplasencia@grupo5.net): "hemos enviado por correo certificado un documento de consentimiento informado para que rellenar. Es en relación a la cirugía que tiene pendiente para retirar la placa metálica y tornillos del codo. En cuanto sea posible os agradeceríamos que nos la reenviéis firmada." ··························· Respuesta de Paula al preguntarle por Isabel: "respecto a Isabel se le van ofreciendo apoyos, verbaliza malestar pero, al menos hasta ahora, parece estar manejando la situación (también hay otras circunstancias a su alrededor: la posible operación, la salida de Cefe del CRR, próxima visita de su madre...)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-11-29','Ana: Correo de Paula, TO CRR (tocupacional.crrplasencia@grupo5.net): "se concreta el traslado a Olivenza para mañana jueves. Los datos del taxista y la cantidad que le supone el traslado hasta allí son los siguientes: ES2001820395830201739692 su nombre es Roberto y la cantidad son 270 Euros; su teléfono es 611141629 por si necesitáis algún otro dato y para contactar para factura o similares." ·································· Tras llamar al taxista, envío correo a Julio, Amalia y S. Ecca, CTAEx: "Os reenvío correo del CRR de Plasencia. Leed por favor lo subrayado en amarillo en el hilo relativo a Ceferino Mariscal Crespo. Julio, porfa, a partir de mañana, cuando puedas, modifica la dirección de en la base de datos. Amalia, porfa, cuando puedas, pásame los datos de contacto del CRR Olivenza (Directora y T.O. o quien mejor consideres para). Hago seguimiento hasta adaptación, después ya te lo paso. Secc. Económica: Ya he hablado con el taxista. Remitirá hoy mismo la factura, pues ya la tiene preparada. No obstante, como veis el traslado será mañana. A partir de mañana, cuando podáis, abonarla por favor."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-11-29','Ana: Envío correo a Maite, Jefa Secc. y Teresa, TS - CTAEx: "No quiero ser pesada, pero me reitero en la necesidad convocar reunión y enviar escritos/informes a Fiscalía/Juzgado, para que puedan valorar la situación y el ingreso de Aitor en centro. Me ha vuelto a llamar Felisa desesperada, ya no puede más, dice que no aguanta vivir más con su hijo. Las últimas expresiones que le ha dicho éste son: “Ojalá te mueras”, “está vieja y fea”… además de seguir extorsionándola con el dinero (que ya no le queda). En cuanto saca dinero él se lo exige. La convivencia cada día es peor y ella se siente sola y desprotegida ante esta situación. Ya sé que tiene cita para la comparecencia el día 21, pero mientras tanto ella sigue así. Y quizá hay que aportar más cosas para que las tenga en cuenta el Juez, porque como se guíe sólo o principalmente por la valoración del Médico Forense me da a mí que se va a quedar la situación tal cual…" ······························· Respuesta de Maite: "Como hablamos vamos a pedir el ingreso por situación de emergencia social. Hay que pedir el informe a los servicio sociales. Dime quien es la trabajadora social y hablo con ella." ··························· Mi respuesta: "si el Juez Autoriza es perfecta esta opción, yo lo demás lo planteo para comunicar la situación al Juzgado que cada vez es peor… La Trabajadora Social de Navas del Madroño es Isabel: 607 600 864" ····································································································································································································· Correo de Maite, Jefa de Secc. a Jurídico, Teresa, TS y a mí: "La situación de Aitor , y en consecuencia de Felisi cada vez es más preocupante. Vamos a intentar ( otra vez), aprovechando que tiene la vista el 21 de diciembre, que nos autoricen el internamiento involuntario. Desde la parte social solicitaremos ingreso en centro de atención a personas con discapacidad por situación de emergencia social, para poder agilizarlo. Para ello pediremos informe social a los servicios sociales y elaboraremos uno complementario. Angel/ Miguel , hablad con la guardia civil de Navas para que nos envíen o informen sobre lo que ellos comunicaron a fiscalía cuando Felisi quiso hacer la denuncia. No sé si se podrán pedir medidas cautelares. Cuando tengamos los informes hay que enviarlo al juzgado. Tenemos que estar pendientes de que tienen en cuenta la documentación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-11-29','Ana: Envío correo a Maite, Jefa Secc. y Teresa, TS - CTAEx: "No quiero ser pesada, pero me reitero en la necesidad convocar reunión y enviar escritos/informes a Fiscalía/Juzgado, para que puedan valorar la situación y el ingreso de Aitor en centro. Me ha vuelto a llamar Felisa desesperada, ya no puede más, dice que no aguanta vivir más con su hijo. Las últimas expresiones que le ha dicho éste son: “Ojalá te mueras”, “está vieja y fea”… además de seguir extorsionándola con el dinero (que ya no le queda). En cuanto saca dinero él se lo exige. La convivencia cada día es peor y ella se siente sola y desprotegida ante esta situación. Ya sé que tiene cita para la comparecencia el día 21, pero mientras tanto ella sigue así. Y quizá hay que aportar más cosas para que las tenga en cuenta el Juez, porque como se guíe sólo o principalmente por la valoración del Médico Forense me da a mí que se va a quedar la situación tal cual…"','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-11-29','miguel, contestación del gestor de siniestros José Luis Gomez de la correduría de seguros: Buenas tardes, Lamentablemente, por LOPD, únicamente podemos trasladar información al letrado y al Colegio tomador de la póliza. En cualquier caso, de haber alguna novedad, informaremos de inmediato a Jorge para que traslade la información. ------------------------------------------------------- mi contestación: Y en caso de que el abogado no facilite información al respecto, cómo podemos saber acerca del trámite y resolución de la incidencia? ----------------------------------------------------------- contestación de José Luis Gómez de la Correduría de Seguros: Buenos días, Miguel, De no facilitaros información, debéis dirigiros directamente a Catalana Occidente, como compañía aseguradora ---------------------------------------------------- Envío email a Mª Granada a ver si me puede facilitar los datos de contacto de Catalana Occidente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2023-11-29','miguel, la parte económica hace la transferencia a la notaria y me envían justificante. Envío justificante a la notaria de Almendralejo de Inmaculada, CARMEN MARIA >cmmarquez@despacho.notariado.org>, Jose Antonio Mancha >jamancha@despacho.notariado.org>: Buenos días, adjunto justificante de transferencia de la escritura de herencia firmada. Ya le he dicho a su hermano Lorenzo que pase a por la escritura original. Necesitaría me enviaran a este email copia simple de dicha escritura. Pasaré a ratificarla a la notaria de Mérida de Don Gonzalo Fdez Pugnaire en cuanto tengamos un certificado de nacimiento que incluya el cargo de tutor de Adolfo por la Ctaex ---------------------------------------------- Envío email a su hermano LORENZO GARCIZ >lorenzogarcia1950@hotmail.com>: Buenos días Lorenzo, ya puedes hablar con la notaria, recoger las escrituras y llevarlas al abogado. No me han enviado copia simple de dichas escrituras como te comenté para saber qué se ha firmado exactamente. Por otro lado sigo pendiente me envíes físicamente el certificado literal de nacimiento de tu hermano original del registro civil para poder ratificar dichas escrituras en la notaria de Mérida, en caso de que esté todo correcto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2023-11-20','Ana: Correo de Diana Arroyo, TS UEX (darrpan@unex.es) "Te escribo desde la Universidad de Extremadura para hablar contigo sobre Sandra Sandín. Soy la trabajadora social de la Unidad de Atención al Estudiante y trabajamos con estudiantes universitarios con discapacidad desde que inician sus estudios y hasta que se insertan en el mercado laboral. Han salido unas becas de la F: ONCE y Sandra podría optar a una, el plazo finaliza el 27 de nov. Tengo que consultarte algunas cuestiones. ····mi tlf es el 618 381 887"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-11-29','miguel, llegan facturas de la abogada Eva Mª. Pérez Escarmena >eperezescarmena@icac.es> para el pago al ayto de residuos las facturas que le corresponde abonar a Julian Ramón Civantos, la del Ayuntamiento de la tasa de residuos que es de importe inferior a 200€ podéis abonarla antes de que se pase el plazo, próximo día 20 de diciembre para evitar pagar recargos. Las otras cuando autorice el Juzgado. --------------------------------------------------- Reenvío a Alberto: Hola Alberto, me envía la abogada la factura del ayto de residuos. Recuerda que la abogada nos está tramitando la autorización judicial para los gastos extraordinarios de arreglo de su vivienda y el edificio… Ojo! Dice que habrá más facturas más adelante: “las facturas que le corresponde abonar a Julian Ramón Civantos, la del Ayuntamiento de la tasa de residuos que es de importe inferior a 200€ podéis abonarla antes de que se pase el plazo, próximo día 20 de diciembre para evitar pagar recargos. Las otras cuando autorice el Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESPERANZA'and edp.apellido1='CORDERO'and apellido2='GONZALEZ'),'2023-11-29','ARCHIVO EXPTE. Mediante Auto n.º 365/23, de 19 de septiembre, dictado por el Jzdo. de 1.ª Inst. n.º 4 de Badajoz, se reintegra la capacidad de Dña. Esperanza. Al mismo tiempo no se dictan medidas judiciales de apoyo de ningún tipo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-11-29','Ana: Envío correo a la S. Jurídica: "Éste es el documento que envíe a Iberdrola como TESTIMINIO DE ACEPTACIÓN DEL CARGO, así lo tenemos en su correspondiente carpeta en el expediente digital. La respuesta que me dan es que no es el Testimonio, que es una DILIGENCIA DE ORDENACIÓN. Y así es, una diligencia en cuyo punto 4 indica “Asimismo se hace constar que se tiene por aceptado el cargo de curador a la COMISION TUTELAR DE ADULTOS DE LA JUNTA DE EXTREMADURA, a la que se le enviará testimonio de la presente junto con el auto declarado firme”. Al tenerlo como testimonio da lugar a error." ···························································· Redacto OFICIO para remitir documentación y solicitar la copia del contrato de prejubilación a Iberdrola y lo subo al portafirmas para que lo firme la D-Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-11-29','TERESA Me ha llamando Manuel (623247979) para decirme que no entra en la comunidad terapéutica porque ha dado restos de marihuana, que hasta el día 17 no puede entrar. Dice que su padre no lo quiere en casa y que se va a un albergue hasta que pueda entrar en la comunidad terapéutica. Le he dicho que le pida a su padre los 200€ del mes de diciembre y con ese dinero viva en el albergue.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-11-29','-Amalia : hablo con ASINDE para contratar el servicio , por 300€ me dirá las horas que puede dar . Le enviaré documentación de Camila .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-11-29','AMALIA/ALBERTO: SE DECIDE BUSCAR EMPRES CON UN COSTE MÁXIMO DE 300 €/MES ESTO ESTÁ CONDICIONADO A NO EXTRAS + NO SUBIDA REINTEGRO. Se lo digo a Ana que la acompaña al banco.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-11-29','Ana: Tras recibir llamada de Estrella Durán, TS CSS - UME, envío correo a Alberto: "Acabo de hablar con Estrella, TS del CSS, ALBERTO NÚÑEZ BONO, necesita unas plantillas especiales y unas zapatillas. Ambas cosas ascienden a 200 €, por lo que solicitan un EXTRA en estos conceptos. Puesto que es necesario por su salud, por mi parte OK al mismo. Por favor, si dais ok, avisad directamente a Estrella Durán, TS (24146) sobre cuando pueden ir a retirarlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-11-29','Ana: Tras llamada de Ángel Félix (643 574 997), envío correo a Alberto, Jefe S. Ecca: "He recibido llamada de Ángel Félix Maillo Santibañez (643 574 997): solicita un EXTRA PARA NAVIDAD DE 200 €. Por mi parte si es viable, ok. Sería en la misma oficina de Plasencia de ocasiones anteriores. PIde se le confirme si se acepta y en tal caso, cuándo puede ir a retirarlo. Por favor, si es posible, comunicárselo en el número anotado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-11-30','Ana: Envío a Julio, Aux. CTAEx: "te envío el oficio para REGISTRAR y remitir a IBERDROLA por correo postal certificado, junto con la siguiente documentación: - Certificado de BASES Y CUOTAS DE COTIZACIÓN DE REGÍMENES Y SISTEMAS ESPECIALES por ustedes solicitado (ya remitido en mail previo a fecha de 24/10/2023, pero que vuelven a requerirle mediante carta enviada a su domicilio) - Carta – solicitud de dicho Certificado recibida - Testimonio de Firmeza de Auto de medidas judiciales de apoyo y nombramiento - Testimonio de Auto de Medidas Judiciales de apoyo y aceptación del Cargo de Curatela Representativa - DNI – Representante Legal - Decreto de Nombramiento de Directora Gerente del SEPAD - Resolución por la que se delega la Presidencia de la Comisión Tutelar de Adultos Va todo detallado en el oficio también. Cuando esté registrado, me lo pasas para que lo remita a Iberdrola por mail también." ········································ Una vez registrado, lo envío todo a IBEDROLA (prejub@iberdrola.es).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2023-11-30','Ana: En relación al correo de ayer de Paula, TO - CRR Plas, envío correo a Alberto, J. Secc. Ecca.: "Desde el CRR de Plasencia, me dicen literalmente esto: “Por otro lado, comentaros respecto M. Angeles Santos Urbano, que nos llamó su padre para decirnos que habían ingresado en su cuenta una cantidad (unos 900 euros) que creía que correspondían a la pensión y la extra de su hija. Por si queréis comprobarlo y enmendarlo en su caso.”, a mí no me queda muy claro, a ver si podéis comprobar las cuentas, averiguar y ver si hay alguna anomalía."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-11-30','TERESA Buenos días! Si, ayer estaba en Mérida en unas Jornadas y no te contesté. Si, Manuel en la analítica el resultado fue positivo y no ingresó. Se le ha dado nueva fecha de ingreso el 13/12. Está poniendo problemas para ingresar en esa fecha. La próxima semana se le ha citado en nuestro ECA para realizar analítica. Si hablas con él, coméntale la importancia de que ingrese el día 13.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2023-11-30','Amalia , la han llamado del CADEX para que acuda a la cita y no quiere ir . Le contesto a Susana del Cadex , que la estoy llamando yo también y no coge ni el tf. No tiene conciencia de enfermedad y no acepta la ayuda de esta Comisión , yo le he pedido la cita , si no quiere ir no podemos obligarla . Puedes sustituir la cita . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-11-30','Ana: correo de Sara, TS R.M. Banium Residencial (TrabajadoraSocialBanium@hotmail.com): "Este correo es para informar que Concepción ha tenido que ser derivada al Hospital Virgen del Puerto con acompañamiento privado en la mañana de hoy tras tirarse la misma usuaria al suelo y hacerse daño en el miembro superior izquierdo. Ha sido derivada por orden de la médico del consultorio de Baños de Montemayor. Además de esto, se le ha informado al acompañamiento que, en caso de quedar ingresada, el servicio era solo para acompañarla y no para quedarse durante el ingreso si este se llegase a producir. En los próximos días adjuntaremos desde el centro residencial Banium informe de salud. Ya que se observa que desde que la usuaria se ha recuperado de las operaciones de ambas caderas, se levanta sola del sillón o de la silla y se tira al suelo cuando ella considera. En esta ocasión se ha levantado durante la noche. Así mismo, recordamos que el centro Residencial Banium es un centro libre de sujeciones, y en este caso la barandilla no es una solución para Concepción ya que puede saltarla en cualquier momento y ser aún más perjudicial. Durante el día el centro dispone de una sala con vigilancia en la que ella se encuentra. Por lo que se están tomando las medidas posibles para intentar minimizar los riesgos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-11-30','Me pongo en contacto contigo para comunicarte que he recibido la llamada de una abogada de oficio que se le ha asignado a la pareja de Juana Palomo, solicitando información y documentación sobre ella. Por lo visto, la intención tanto de Juana como de este señor es solicitar la curatela de Juana por parte de José. Según refiere se le asignó el caso en septiembre y no consigue que tanto Juana como José le faciliten la documentación que les solicita y que les aclare cuál es la situación de Juana. Por mi parte, no le he facilitado documentación alguna. Le he explicado que ella está curatelada por vosotros y le he puesto al tanto de su situación muy por encima, la cual desconocía. Ella misma se ha dado cuenta que es inviable lo que ellos piden, pero aun así le he orientado a que contacte contigo. Como no he sabido decirle cuando es el mejor momento para que te pueda llamar, te voy a facilitar su teléfono para que de esta forma seas tú quien contactes con ella cuando tú lo consideres. Se llama: Abdona Cortés. Su teléfono es: 636312452.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2023-11-30','Ana: Correo de Manuel Casado, TO - EVD CC (manuel.casado@salud-juntaex.es): "Comentarte que desde discapacidad me informan que la aceptación PIA con solicitud de centro debe ser tramitada como servicio de promoción, al tratarse de un grado I. Por lo que adjunto la aceptación con la solicitud de centro tal y como me dicen que debe ser hecha. Por lo que debería ser firmada de nuevo por la Directora Gerente. Disculpad la incidencia." ········································ Envío a Julio, Aux. CTAEx, la nueva aceptación PIA ya firmada para que le dé registro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-11-30','Me pongo en contacto contigo para comunicarte que he recibido la llamada de una abogada de oficio que se le ha asignado a la pareja de Juana Palomo, solicitando información y documentación sobre ella. Por lo visto, la intención tanto de Juana como de este señor es solicitar la curatela de Juana por parte de José. Según refiere se le asignó el caso en septiembre y no consigue que tanto Juana como José le faciliten la documentación que les solicita y que les aclare cuál es la situación de Juana. Por mi parte, no le he facilitado documentación alguna. Le he explicado que ella está curatelada por vosotros y le he puesto al tanto de su situación muy por encima, la cual desconocía. Ella misma se ha dado cuenta que es inviable lo que ellos piden, pero aun así le he orientado a que contacte contigo. Como no he sabido decirle cuando es el mejor momento para que te pueda llamar, te voy a facilitar su teléfono para que de esta forma seas tú quien contactes con ella cuando tú lo consideres. Se llama: Abdona Cortés. Su teléfono es: 636312452.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-11-30','Ana: Envío correo-respuesta a María Barroso, CRR Olivenza:(MBARROSO@caseresidencial.es): "Buenas tardes María, Ya he pedido a la sección económica que remitan la autorización a la sucursal de Olivenza. Ayer finalmente me fue imposible llamaros y hoy me da que no me va a dar tiempo, tengo otras cuestiones urgentes por terminar. Mañana intento llamaros. Espero que el viaje y la llegada de Ceferino a vuestro recurso haya ido bien y que la adaptación sea adecuada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-11-30','miguel, recibo email de José Santiago Lavado >2981@icaba.com>porque han denegado nuestra solicitud para den orden a instar modificación del certif nacimiento al rgtro civil: Adjunto notificación recibida del Juzgado de Villafranca, que ha sido inadmitido porque no se identificado correctamente el procedimiento. Os informo que, para hacerlo bien, deben remitirlo a ese juzgado, pero indicando que el procedimiento es : DECLARACION DE INCAPACIDAD N.º 56/2001. SENTENCIA N.º 129/2001.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-30','miguel, me llama la hermana de Enrique, Carmen que es TS de Salud Mental en Canarias. Me informa a nivel personal y patrimonial de la vida de Enrique. Está convencida de que Enrique no puede volver a vivir sólo, ni tampoco en un centro abierto (como un CRR), por su bien y por el de los demás, y lo justifica con muchisimas situaciones extremas vividas en el pueblo (como un intento de violación a dos menores no denunciado, sacar un cuchillo y amenazar) Manifiesta que Enrique es un gran manipulador y lo demostró en el juicio de nombramiento a la Ctaex y donde ya venía apoyado por la psiquiatra y convenció al forense y la juez. Y ellos de camino al jzdo les amenazó diciendo que se preparasen que no sabían como era él, demostrando lo manipulador que es. Me pregunta cuándo, cómo y quiénes formarán parte de la subcomisión que estudiará el caso, donde ella no quiere que esté por su falta de profesionalidad la psiquiatra Mariví. Me confirma que no hay denuncias interpuestas por familiares, vecinos, etc. Habla muy mal de la psquiatra Mariví y de la Juez que conoció del caso de la remoción de su hermano Ricardo (con el que no se hablan ella y su hno Nacho), de las que pone en duda su profesionalidad al creer a Enrique (que a su vez los tenía amenazados a la familia. Siendo el trámite en el que se nombró a la Ctaex cuando falleció su madre que estaba enferma) En definitiva, el juez nos ha dado 5 días para contestar al escrito de su hno Nacho de octubre, que según me confirma Ana Ts no nos oponemos y apoyamos, y así se lo hago saber a su hna Carmen, quién me buscará cuando vengan a casa de la madre en diciembre documentación del hno. Me confirma que no hay informes médicos porque Mariví (psiquiatra coordinadora del Centro de Salud Mental Plasencia)nunca los ha facilitado. Carmen pensaba que tenía el certificado de discapacidad pero compruebo en el expte que nunca acudió a la cita y renunció al mismo Enrique en 2007. Por tanto para contestar al jzdo no tenemos denuncias, informes médicos, certificado de discapacidad y sólo 2 informes sociales del inventario y de septiembre de este año. Pido a Carmen que todo lo que me cuenta lo refleje en un escrito para enviarlo al juzgado junto con el informe social de sept de 23 y pediré que de oficio el jzdo pida los informes de salud mental. Carmen me enviará también lo que encuentre en relación con lo que aporto al jzdo nº2 Plasencia (que nos nombró y ahora nos pide informemos). En cuanto al tema patrimonial-Se firmó la herencia de su madre que estamos pendientes de ratificar y hemos solicitado al jzdo inste al rgtro civil incluya a la Ctaex como curador de Enrique para poder ratificar la misma. En dicha herencia hay dos viviendas en Salamanca en común con varios tíos de ellos y que no hay relación con lo que será complicado su mantenimiento y venta. Ha intentado cancelar las cuentas del Santander donde figuran en común con dichos tíos y no les dejan. En dichas cuentas casi no queda dinero, y peligra entren en mora, amen de que será necesario aportar dinero para la administración y mantenimiento de las mismas. En cuanto a la vivienda de la madre: la vienda de Enrique la hizo dentro del mismo solar que la vivienda familiar, su abuelo, para alejar a Enrique, por tanto forma parte de la herencia y cuando se venda debería venderse todo(salvo que lo donen a Enrique, previa segregación legal si fuera posible, con el sobrecoste que supondría y teniendo en cuenta que Enrique debe residir permanentemente en un centro) Quedaban pendiente dos cosas: 1.-Los 3 seguros que aparecían en el certificado de últimas voluntades: me confirma Carmen que ninguno supone dinero, ni beneficiarios porque eran del coche, de hogar?...Me envía póliza del coche 2.-Venta del coche: la asesoría insistió que hay que poner a nombre de un hno el coche para hacer los trámites de transmisión y posterior venta en tráfico. Carmen me confirma que se pondría a su nombre y que ella haría la venta en un concesionario y pedirá 8.000€. Me enviará el contrato de compraventa con el concesionario y el compromiso de ingreso directamente y proporcionalmente a cada uno de los 5 hnos. Quedo pendiente a que el lunes me haya remido un escrito explicando y justificando porque es necesario su hno quede ingresado permanentemente (habla de amenazas con cuchillo de su hno, intento de violación a dos menores, que se droga) De la psiquiatra y la secretaria del ayto habla muy mal porque apoyan al hno y le enviaban bizum de dinero que este utilizaba para drogarse... Cuando me envíe el escrito lo comunicaré todo al jzdo. ------------------------------------------------------ Envío a Ana y Maite esta información para su conocimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='TARANGO'and apellido2='DOMINGO'),'2023-12-01','Ana: Envío a la OFICINA DE ASISTENCIA A LA CIUDADANÍA (oac.merida.san@juntaex.es) : "Adjunto Oficio-Solicitud de Certificado Actualizado de Prestación Familiar por Hijo a Cargo, relativo a MANUEL TARANGO DOMINGO, cuyo cargo ostenta la CTAEx, para darle registro y remitir a la Dirección Provincial del INSS de Cáceres, junto a la siguiente documentación: - Testimonio de acuerdo de aceptación del cargo Ante cualquier cuestión, no dudéis en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2023-11-29','Ana: Llamada de Jairo, mismo discurso de las últimas veces de querer independizarse e ir a vivir solo a un piso. ·············· De entrada rechaza el cambio de recurso a CRR, pero finalmente dice que si no le queda otra lo aceptaría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-12-01','miguel, mando a Carmen, la hna, el nº de cuenta que me indica Alberto... Buenos días Carmen, el nº de cuenta de Enrique para el futuro ingreso de la venta del coche es UNICAJA: ES09 2103 7114 0100 3009 8794 Recuerda que tienes que modificar y enviarme el documento de compromiso incluyendo el importe de venta y el documento que firmes con el concesionario. En cuanto pueda ratificar la herencia la Comisión firmará todos los documentos… Insistiremos al juzgado para que inste al registro civil a incluir el cargo que ejerce la Comisión. --------------------------------------------- En cuanto a la documentación que me adjunta incluido un escrito dirigido al jzdo nº2 de Plasencia, la pregunto: Perfecto, incluiré toda esta documentación a lo que envíe al jzdo. Quedo a la espera de otro escrito o aporto este que envías de 11-10-23? Este escrito lo enviastes al jzdo? Tienes el justificante de registro de salida?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-12-01','miguel, hablo con Mª Jesus, y tras no quedar claro qué pide el ayto, llama ella a Inés(técnico del Ayto Piedras Albas) que la confirma que no nos van a contestar y que tenemos que enviar un proyecto visado con lo que vamos a hacer. La solución planteada por Mª Jesús es hacer una especie de presupuesto de lo que va a hacer, y lo planteará en 2 fases, previo proyecto de obra visado por el Colegio de Madrid, que será más rápido que el de Extremadura: 1ª Se ajustará a los 6.000€ que tiene Martin, donde las tasas por visas al menos serán 700€ y demolerá lo que pueda. 2ª No habrá dinero para hacerla. Y cuando el Ayto la reclame se le justificará que Martin será insolvente y se les volverá a insitir que ejerzan la ejecución subsidiaria sobre los bienes de Martin. Me enviará borrador de lo que va a hacer Mª Jesús. Yo le envío dni y aceptación del cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2023-12-01','miguel, recibo testimonio de Teresa Muelas (abogada) con la aprobación de herencia y autorización de venta, y la contesto con copia a Amelia, Teresa Muelas >mtmuelas@icaguadalajara.org>; "melitonarodrigo@hotmail.es": Buenos días Teresa, gracias por la información. Ya podéis inscribir las escrituras en el registro de la propiedad junto con este testimonio. Teresa, no recuerdo ya si se te debe algo. Si es así envíanos factura. Amelia, ya podéis proceder a la venta, si es preciso contratando los servicios de una inmobiliaria, a partir del precio que indica el Auto judicial. Por otra parte, no pidieron en Caixabank certificado de titularidad de la cuenta de Raúl, y al estar la cuenta bloqueada no lo hemos podido solicitar, por lo que enviamos un email a la oficina de Mérida de Sergio con copia a la de allí de David para que lo soliciten de oficio ellos. Amelia si tienes posibilidad comprueba que ya esté todo para que procedan al desembolso del dinero de Sergio y Raúl.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2023-12-01','miguel, recibo testimonio de Teresa Muelas (abogada) con la aprobación de herencia y autorización de venta, y la contesto con copia a Amelia, Teresa Muelas ; "melitonarodrigo@hotmail.es": Buenos días Teresa, gracias por la información. Ya podéis inscribir las escrituras en el registro de la propiedad junto con este testimonio. Teresa, no recuerdo ya si se te debe algo. Si es así envíanos factura. Amelia, ya podéis proceder a la venta, si es preciso contratando los servicios de una inmobiliaria, a partir del precio que indica el Auto judicial. Por otra parte, no pidieron en Caixabank certificado de titularidad de la cuenta de Raúl, y al estar la cuenta bloqueada no lo hemos podido solicitar, por lo que enviamos un email a la oficina de Mérida de Sergio con copia a la de allí de David para que lo soliciten de oficio ellos. Amelia si tienes posibilidad comprueba que ya esté todo para que procedan al desembolso del dinero de Sergio y Raúl.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-12-01','miguel, recibo email de Damian: Acabamos de hablar hace un momento le facilito el número de la inmobiliaria de Málaga que ha vendido pisos por mi barriada en cortijo de torres.estan María y Rocío las que llevan la inmobiliaria este es el número 952311939','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='TARANGO'and apellido2='DOMINGO'),'2023-12-01','Ana: Hablo con Cristina Hdez, TS CSS y le envío mail (/ cristina.hernandezca@salud-juntaex.es): "Tal y como hemos acordado mediante conversación telefónica, te reenvío el correo de mi compañero Ángel con documento de solicitud de informe. Cuando tengas el Informe Social envíaselo a él la semana que viene."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-12-01','miguel, Eva la abogada me envía Auto no firme autorizando el gasto extraordinario por importe de 25.402,74€ Reenvío el Auto a Alberto y Ana: Hola Alberto, mira por favor qué saldo tiene actualmente Julian, porque ya han autorizado al arreglo de la vivienda, conforme Auto que adjunto y que todavía no es firme.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-11-29','Ana: Correo de Mónica, Ed. PP.SS. (educacion.pisosplasencia@grupo5.net): "Te escribo para informarte de la situación de ayer de Carmen Solana. Ayer por la tarde decidimos que subiese de forma temporal (o no) al CRR tras detectar un mal uso de la medicación psiquiátrica, que junto al nacimiento de su nieta y una gripe dificultaban la intervención en piso y no podíamos garantizar su bienestar teniendo en cuenta la situación de vulnerabilidad en la que se encuentra. Ya hemos informado también a su madre, Benita, pero queríamos facilitaros toda la información. Como todo ha ocurrido recientemente, no sabemos si este cambio a CRR será temporal o definitivo, os informaré cuando lo sepa. Cualquier cosa que necesites comentarme, puedes seguir utilizando esta vía, o bien el correo de terapia ocupacional."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-12-01','Ana: Llamada de Felisi. De nuevo se desahoga y cuenta lo más que sigue la situación, cada día está más desesperada con la actitud y comportamiento de su hijo en casa y hacia ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-11-29','Ana: Correo de Maite, Jefa de Secc. a Jurídico, Teresa, TS y a mí: "La situación de Aitor , y en consecuencia de Felisi cada vez es más preocupante. Vamos a intentar ( otra vez), aprovechando que tiene la vista el 21 de diciembre, que nos autoricen el internamiento involuntario. Desde la parte social solicitaremos ingreso en centro de atención a personas con discapacidad por situación de emergencia social, para poder agilizarlo. Para ello pediremos informe social a los servicios sociales y elaboraremos uno complementario. Angel/ Miguel , hablad con la guardia civil de Navas para que nos envíen o informen sobre lo que ellos comunicaron a fiscalía cuando Felisi quiso hacer la denuncia. No sé si se podrán pedir medidas cautelares. Cuando tengamos los informes hay que enviarlo al juzgado. Tenemos que estar pendientes de que tienen en cuenta la documentación."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-11-29','Ana: Correo de Maite, Jefa de Secc. a Jurídico, Teresa, TS y a mí: "La situación de Aitor , y en consecuencia de Felisi cada vez es más preocupante. Vamos a intentar ( otra vez), aprovechando que tiene la vista el 21 de diciembre, que nos autoricen el internamiento involuntario. Desde la parte social solicitaremos ingreso en centro de atención a personas con discapacidad por situación de emergencia social, para poder agilizarlo. Para ello pediremos informe social a los servicios sociales y elaboraremos uno complementario. Angel/ Miguel , hablad con la guardia civil de Navas para que nos envíen o informen sobre lo que ellos comunicaron a fiscalía cuando Felisi quiso hacer la denuncia. No sé si se podrán pedir medidas cautelares. Cuando tengamos los informes hay que enviarlo al juzgado. Tenemos que estar pendientes de que tienen en cuenta la documentación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2023-12-01','-Amalia : solicita 150€ , avisarla a su nuevo TF. 627129372','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2023-12-01','Buenas, Lourdes el pago del extra puedes hacerlo para diciembre en la fecha que quieras , será el único que tenga . No me creo que sea para comida cuando se le dan 600 € al mes para cubrir todo y ahí viven dos personas . Pero no nos cuenta la verdad , para quitarlo del medio antes de que venga el mogollón puedes ponerlo para la primera semana de diciembre . Los 90 del catering los cargaban en su cuenta directamente desde el ayuntamiento. Saludos. ------------------------------​ ​ ​LOURDES: OK A EXTRA DICIEMBRE (ROPA-COMIDA) X 300 €...LO MÁS AVANZADO DICIEMBRE POSIBLE (SALVO QUE AMALIA DIGA LO CONTRARIO) AMALIA: SALVO QUE DIGAS LO CONTRARIO RETRASAMOS EL PAGO DEL EXTRA DICIEMBRE, PARA QUE LO ASOCIEN A "NAVIDAD"...SI TU VES QUE ES NECESARIO HACERLO ANTES...INDÍCALE A LOURDES LA FECHA. AMALIA/LOURDES: ESTAMOS PAGANDO 600 € A HERMANO + AYUDA DOMICILIO X 812 € ......NO SE ESTÁ ABONANDO NADA QUE TENGA QUE VER CON CÁTERING X 90 € (AL MENOS DESDE 07/2023 Y X LA CCC DEL TUTELADO). MARIA: XFA, ACABA LA RENDICIÓN ANUAL QUE TENIA EN CURSO OSCAR...TEN EN CUENTA QUE SE HAN CANCELADO??? (HABLA CON ESTRELLA PARA CONFIRMARLO), LAS CCC DE IBERCAJA Y QUE ÚNICAMENTE ESTÁ OPERATIVA LA CCC BANCA PUEYO. De: MARIA LOURDES CORTES MARQUEZ >marialourdes.cortes@salud-juntaex.es> Enviado: lunes, 20 de noviembre de 2023 14:05 Pas de Ibercaja canceladas. TRES PENSIONES 563,15€ 465,70€ 679,79€ Y GASTOS FIJOS 812€ AYUDA A DOMICILIO 600€ TRANSF A HERMANO 90€ CATERING.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-11-30','Ana: Llamamos Maite y yo a Azucena, cuñada de Juanjo, exponiendo los beneficios que tendrían tanto para Juanjo como para el resto de familia si Juanjo ingresa y que además puede probar y si después no se adaptara podría volver a casa. ··· Finalmente dice que hablará con él y mañana o el lunes a mucho tardar responderá.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-11-30','Ana: Llamamos Maite y yo a Azucena, cuñada de Juanjo, exponiendo los beneficios que tendrían tanto para Juanjo como para el resto de familia si Juanjo ingresa y que además puede probar y si después no se adaptara podría volver a casa. ··· Finalmente dice que hablará con él y mañana o el lunes a mucho tardar responderá.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2023-12-01','Buenas , disculpa , efectivamente tengo ese email ,pero no lo he recordado ... estoy de extras de Navidad hasta la coronilla ! qué horror ! Lo llamo para dar el OK a los 300€ . Ha pedido una subida mensual que he denegado yo directamente porque no se le va a dar nada más. Los 90€ del catering he confirmado con el Ayto. que se están cargando pero en la cuenta de su hermano Juan . Se queda así , ya se le dan a él 600€ al mes .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='REY'and apellido2='COLOMBO'),'2023-12-01','Sí Amalia. A Antonio ya le vio la médico forense por videollamada y hemos recibido la citación para que comparezca el próximo día 12 de diciembre de 2023 a las 10:30. Como él está gravemente afectado, hice un escrito solicitando que la comparecencia sea por videollamada. (Ahora que lo pienso, me surge la duda de si os lo tenía que haber dicho a vosotros para que fueseis vosotros quien lo solicitaseis). Desde el Juzgado aún no me han contestado. Tengo pensado llamar al juzgado más adelante para ver que me dicen al respecto. Pensaba que al recibir nosotros la citación, a vosotros también se os hubiera comunicado. A partir de ahora, según reciba las citaciones te las voy a comunicar para que estés al tanto. Te adjunto: Citación recibida. Solicitud de comparecencia por videollamada presentada en el Juzgado. Sobre la solicitud del informe social no tengo constancia de ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-12-01','Ana: Correo de Azucena, Cuñada de Juanjo al ctutelar@ (azuydavid153@gmail.com // 625 367 302) diciendo que Juanjo ha dicho que sí quiere ingresar. Plantea algunas dudas, le contesto diciendo que la llamaré más tarde. ····································· Maite habla con Maribel y Belén y con Rosa, Directora del Centro de Fuente de Cantos. Se acuerda el ingreso para el día 12/12. Intentaremos que llegue sobre las 12 - 12:15 h. ····························· *Llamo a Azucena, cuñada, no obtengo respuesta. ····································································· *Llamo a Teresa, TS NOVAFORMA: Le extraña que Juanjo haya dicho que sí, pues le ha visto estas mañana y éste no le ha dicho nada. ··························· Intentará hablar con Azucena y con un hermano de otro residente que es taxista para preguntarle si puede hacer el servicio. ································ Vuelvo a llamar a Azucena:','1');
