insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2023-12-01','Ana: Correo de Azucena, Cuñada de Juanjo al ctutelar@ (azuydavid153@gmail.com // 625 367 302) diciendo que Juanjo ha dicho que sí quiere ingresar. Plantea algunas dudas, le contesto diciendo que la llamaré más tarde. ····································· Maite habla con Maribel y Belén y con Rosa, Directora del Centro de Fuente de Cantos. Se acuerda el ingreso para el día 12/12. Intentaremos que llegue sobre las 12 - 12:15 h. ····························· *Llamo a Azucena, cuñada, no obtengo respuesta. ····································································· *Llamo a Teresa, TS NOVAFORMA: Le extraña que Juanjo haya dicho que sí, pues le ha visto estas mañana y éste no le ha dicho nada. ··························· Intentará hablar con Azucena y con un hermano de otro residente que es taxista para preguntarle si puede hacer el servicio. ································ Vuelvo a llamar a Azucena, de nuevo, tras varios tonos salta el buzón de voz. Dejo mensajes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2023-12-01','miguel, hablo con Estefanía (abogada de Gijón)985170250 que lleva el caso Envío email a Alberto y Tere con lo hablado con la abogada: Buenos días, vamos a intentar poner en marcha la herencia para que se firme en la notaria de herrera del duque lo antes posible. Acabo de hablar con la abogada y me comenta que se reúne el martes con la exnuera para que la ponga al día de ingresos y gastos de la vivienda de Madrid. Parece ser que está viviendo un sobrino de ella. Todo se está ingresando en una cuenta y de ahí intentaremos se paguen los gastos que vaya orignando la herencia. Voy a preparar un email con la información que tenemos para que la complete la abogada y la exnuera para enviarlo a la notaria y comiencen a preparar la adjudicación de herencia. Una vez finalice buscaremos abogado que pida autorización judicial de aprobación de herencia y autorización de venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-12-01','ASINDE : En cuanto al presupuesto, por los 300€ podemos realizar 18h/mes (00:55 minutos/día).','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-12-01','Ana: Correo de Estrella Durán, TS CSS: "Como sabrás hoy se celebra el día de la Discapacidad y varios de nuestros pacientes han participado en las actividades organizadas por el Ayuntamiento de Plasencia, entre otras una Batucada perteneciente a Placeat. En dicha Batucada ha podido intervenir Alejandro Núñez Bono y nos han pedido desde Placeat el vídeo en el que aparece Alejandro interviniendo. Le hemos dicho que necesitábamos vuestro permiso." ···························· Mi respuesta: "En este caso, cono las modificaciones legislativas, si él entiende los términos para lo que se autoriza, no habría ningún problema con qué el mismo firmara una autorización al respecto. No obstante, pongo en copia a mis compañeros jurídicos para que confirmen si es así. Ángel y Miguel, porfa, confirmad o aclararle a Estrella, por si se me escapa algo a mí."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2023-12-04','miguel, recibo email de Tere con copia a Alberto: Hola Han pasado 12 meses desde que se envió la declaración de herederos y aun no se he hecho nada? Esta mujer no tenia dinero para asumir el pago de los impuestos que generaba los inmuebles que tiene y decimos no pagarlos y pagar solo la residencia en al que esta para tener cubiertas sus necesidades básicas hasta que se resolviera la herencia que ya podría hacer frente al los pagos con el dinero que cogiera Tenía una cuenta en el BBVA que es donde le cargaban los impuestos y suministros etc, la cual a día de hoy imagino que se encortara en números rojo pues no se ha vuelto a hacer nada. ALBERTO: necesito saber si podemos hacer frente al pago de la prótesis del ojo para hablar con la dirección del centro -------------------------------------------------------- mi contestación: Buenos días, el viernes hablé con la abogada de Gijón, y mañana Martes se reunirá con la exnuera (su clienta)para preparar todo lo que necesita la notaria para preparar la herencia, recordad que ya están liquidados los impuestos de sucesiones, salvo el del hijo de Alfonsa, Agustin que está prescrito. Todo lo ha gestionado esta abogado y es la que siempre ha tenido la información y ha ido haciendo todas las gestiones como el impuesto de sucesiones que correspondían… Se ha alargado por culpa de la notaria y después porque la abogada dice no ha tenido tiempo de continuar… La estoy preparando un email con toda la documentación de que disponemos (fotocopias) para que mañana lo una a los ingresos y gastos que la exnuera está gestionando de la vivienda de Madrid (dinero que está yendo a una cuenta que se incluirá en la escritura de herencia). En dicha herencia la exnuera justificará los gastos que ha ido teniendo para compensarlos en el momento del reparto. Una vez que esté firmada contrataremos un abogado de Extremadura para consiga autorización judicial de aprobación de herencia y autorización de venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2023-12-04','miguel, tal como quedé el viernes con Estefanía (abogada de Gijón) recapitulo todo lo que tenemos y se lo digo para montar la herencia. Buenos días Estefanía, de la reclamación a la aseguradora para el desembolso, eso se ingresó en la cuenta común, donde también se hacen los ingresos-gastos de la vivienda de Madrid? La documentación que veo en el expte virtual (no originales) es la siguiente: 1.-Catastro de Alfonsa, Agustín y Juan Felipe 2.-Nota simple de la finca de Talarrubias (no tengo la de Madrid). La finca de Tarrubias sigue apareciendo al 100% a nombre de Mariano Rodriguez Paniagua. 3.-Ibi de Madrid del 2019. 4.-Escritura de herencia del padre fallecido. 5.-Declaración de herederos de Juan Felipe y de Agustín. 6.-Liquidación del impuesto de sucesiones de Juan Felipe (faltaría el de Agustín). 7.-Certificado de nacimiento de Alfonsa + Certificados de Defunción del marido Mariano y los dos hijos de Alfonsa, Juan Felipe y Agustín. 8.-Certificado de Bankia con las cuentas de titularidad común de Alfonsa y su Marido. Necesitaría que me enviaras la nota simple de la vivienda de Madrid. Yo preguntaré a mis compañeros si hay algún gasto de la herencia (impuestos, etc) que esté asumiendo Alfonsa. Quedo a la espera me digas qué falta y dónde están los originales que hagan falta para preparar la herencia. ------------------------------------------ Envío email a Alberto y Tere para que me confirmen qué gastos ha asumido Alfonsa desde fecha de fallecimiento del hijo Juan Felipe hasta ahora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2023-12-04','miguel, me pregunta Tere: Hola como va la herencia de Jose Antonio? Hace ya tres años que falleció la madre y aun no ha podido coger el dinero que tiene en el banco ------------------------------------------------------ envio email a inmaculada@delcidyvillafaina.com Buenos días, en relación a la herencia de José Delgado Rodriguez, desconocemos si presentansteis la resolución judicial en el banco para el desbloqueo y reparto del dinero…Creo que no había nada más que repartir. Puedes confirmarme ambas cuestiones? Si no es así por favor proceded a la presentación de la documentación que requiera la entidad bancaria para que finalicemos el desembolso del dinero. Adjunto la resolución judicial, junto a la firmeza-testimonio dictada por el juzgado hace meses. --------------------------------- Contesto a Tere: Hola Tere, pregunto a la gestoría a ver porqué no está hecho el desembolso…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2023-12-04','miguel, recibo email Sandra Sánchez >ssanchez@inteligencialimite.org> Informaros que esta mañana, un conocido de la comunidad donde José María tiene su propiedad, ha solicitado que la presidenta pueda darle un mensaje importante al usuario. Se lo que comentado a José María y me ha dado permiso para llamar a la presidenta. Nos informa que las denuncias por impago de la comunidad han sido aceptadas en el juzgado y saldrá publicado en el DOE. La deuda oscila en más de 16.000 euros. La comunidad quiere enviarle una carta informativa al usuario para que sea conocedor tanto de la demanda como de la deuda. La comunidad desconoce quiénes son los herederos de la casa, pues han ido al registro de la propiedad y no han conseguido información porque no hay nada. Se le ofrece la dirección de la Entidad para que nos llegue dicha información. En cuanto la tengamos, os la haremos llegar. ------------------------------------------------------ mi contestación: Hola Sandra, dicha carta de deuda envíamela que la estudiaremos. Como van los trámites de recopilación de documentación para la herencia? Recuerda en ponerme en copia lo que remitas a la Asesoría Menaya','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2023-12-04','miguel Lorenzo (hno) me adelanta el cerificado de nacimeinto y le pido me envíe el original por carta. Él va a recoger la escritura de herencia original d ela notaria y la va a llevar al abogada. Le digo que le diga al abogado me llame para coordinar todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2023-12-04','Hablo con Ana , TS , vamos a empezar la gestion por : -enviar delegada tutelar , les pasaré su tf para que se coordinen. -averiguar con CADEX si pueden darle otra cita. -Desbloquear las cuentas los meses de diciembre y enero y en febrero ya habrá un pto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-12-04','tf hermano mayor Pedro : 640831790 Quiere extra de Navidad , subir la asignación y que se la pasemos a la cuenta de la madre en Banca Pueyo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-12-05','miguel, envío a la perito la autorización solicitada para tramitar la obra de la vivienda del curatelado en Piedras Albas: Buenos días Maria Jesús, se me olvidó quitar el subrayado amarillo. Te envío la autorización firmada y modificada, si necesitas algo más dimelo. Quedo pendiente me envíes el presupuesto del albañil para sea firmado por la representante de la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2023-12-05','Amalia , empiezo plan de intervención con las siguientes cuestiones : el tema del CADEX : " dado que ahora las citas de CADEX se hacen a través del call center, por teléfono, la chica aceptó la cita y confirmó asistencia pero no se presentó. Retomaremos el expediente y se le citará de nuevo estoy pendiente y cuando se haga te lo comunico para que estés pendiente y no vuelva a faltar." bancos : se le han autorizado 600€ para los meses de diciembre y Enero , le guardamos unos 50€ para empezar a cubrir gastos , el primero de ellos el de Seguro Decesos. Puede ir a retirarlo durante los primeros 10 días del mes. Delegada Tutelar , ya está hecha la derivación .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2023-12-05','Hablo con Iris , la abogada de oficio le dió a entender que no seguiría con el caso de remoción de tutela para Jose.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2023-12-05','- Amalia : le han subido IMV cuantia mensual 176,18€ . Hay un cobro indebido de 330€ que tenemos que abonar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-12-05','ASINDE : En cuanto al presupuesto, por los 300€ podemos realizar 18h/mes (00:55 minutos/día). Eliminar Incidencia Modificar Incidencia 29/11/2023 Expediente -Amalia : hablo con ASINDE para contratar el servicio , por 300€ me dirá las horas que puede dar . Le enviaré documentación de Camila .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2023-12-05','miguel, llega email donde el jzdo de zafra nº2 da 5 días para alegaciones. Hablo con Carlos del Jzdo y pongo email a Amalia (parte social y jurídica) Hola Amalia, el juzgado nos da 5 días para alegaciones, pues me dice Carlos del jzdo nº2 Zafra (924-554641), que tras la conversación que mantuvimos tu y yo porque no les quedaba claro si pedíamos un internamiento, una revisión de medidas, etc. Dice que quedaste con él en enviar un informe indicando cuál es la mejor opción, centro de día, un Internamiento… Tenemos que enviarle en los próximos 5 días dicho escrito o denegarán el Internamiento involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2023-12-07','TERESA ENVIO POR REGISTRO SOLICITUD DE TRASLADO DE CENTRO POR DEPENDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2023-12-07','TERESA ENVIO POR REGISTRO SOLICITUD DE DEPENCIA PARA TRASLADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-12-07','TERESA ENVIO POR REGISTRO SOLICITUD TARJETA DE TRANSPORTE POR PERDIDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-12-12','Ana: Correo-respuesta de Raquel Gómez, Enfermera Secc. Acceso a RR Salud Mental, a Marisa Olivera, TS ESM-Coria, por la derivación de Julia para CRR: "Según la instrucción para acceder a los Centros Residenciales de Salud Mental es imprescindible tener reconocida situación de dependencia siendo al menos imprescindible el Grado I, por tanto la derivación presentada para su valoración por la Comisión no puede ser aceptada hasta no solicitar una nueva revisión de la valoración de dependencia. Si no procede dicha revisión tendrá que esperar hasta que su situación cambie." ············································································································ Mi respuesta a toda la Secc. y Marisa: "Estoy de acuerdo con Marisa en todo lo que plantea. Tenemos un grave problemas con estos perfiles… aunque hayan pasado casi dos años desde la anterior valoración, Julia no va a dar grado de Dependencia en la actualidad. Ya incluso nos pusieron muchos problemas para valorarla la vez anterior, conocen perfectamente el caso y saben que no da grado. La vez anterior pudo ingresar en CRR, si no recuerdo mal, como emergencia social. No entiendo por qué en esta ocasión no es posible por la misma vía. Estamos de nuevo ante una persona que “NO DA PERFIL PARA NINGÚN RECURSO” y en el domicilio familiar no recibe los apoyos y la atención que necesita. Si bien es cierto que la vez anterior no funcionó, consideramos que sería positivo darle una nueva oportunidad. Pongo en copia a Maite, Jefa de Sección." ··········································································· *Respuesta de Raquel Gómez - Secc. S.M.: "En relación a como pudo ser su ingreso la otra vez, como indica la instrucción en situación de emergencia social pueden ingresar siempre que esté pendiente la valoración por dependencia, ya que este trámite muchas veces se alarga. En el otro ingreso estaba en trámite la solicitud, pero en esta ocasión hay una valoración finalizada, resultando ser sin grado, lo cual impide su acceso a estas plazas gestionadas por la ley de dependencia. No sabemos cual sería la alternativa a esta situación, pero está claro que habría que buscarle un recurso que no se imprescindible el requisito del grado de dependencia. No sabemos si una alternativa para ella podría ser tratamiento en CRPS con estancia en piso de apoyo, al ser recursos del SES no hace falta grado de dependencia. Si obtenemos más información al respecto os lo vamos comunicando." ·································································································································································································· correo de Marisa Olivera, TS ESM (maria.olivera@salud-juntaex.es): ", al CRPS hay que derivarlo desde el ESM. Desde aquí, hasta el momento, no se ha considerado derivarla a dicho recurso. Esta mañana he intentado hablar con la Subdirectora de Salud Mental, para que conozca el problema del que estamos hablando. Aunque estos recursos sean del SEPAD, los usuarios son pacientes de la red de Salud Mental. Estaba reunida y ha quedado en llamarme."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2023-12-12','TERESA Te solicito autorización de salida de Nerea al domicilio familiar, a casa de su madre. La fecha prevista de salida el día 20 y la de regreso irá en función del comportamiento de Nerea, si todo va bien hasta Reyes. SE AUTORIZA SALIDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MORA'and apellido2='GARCIA MORA'),'2023-12-12','TERESA ENVIO POR REGISTRO SOLICITUD DE INFORME SOCIAL PARA INVENTARIO YA QUE NO INFORMAN QUE EN EL CENTRO QUE ESTABA HA SIDO EXPULSADO Y ESTA VIVIENDO EN LA ALBERGUE DE DON BENITO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-11-22','Ana: Correo PAF: "hoy ha sido el último día que acompañamos a la familia. Hasta ahora lo hacíamos porque es una familia que conocemos de toda la vida, ( a pesar de que no entre en nuestras funciones el acompañamiento a tutelados) pero no estamos dispuestas a aguantar faltas de respeto ni voces de Aitor. Además, él nos ha expresado que no quiere que trabajemos con él y puesto que nuestro programa es voluntario, vamos a dejar de hacerlo. Además demanda independencia, un alquiler para vivir solo. La cita de Felisi es la única, que sepamos, que tiene pendiente. Aitor está pendiente de recibir la del CEDEX y la de Salud Mental, como la perdió, tendrá que volver a solicitarla en el médico de atención primaria para que vuelvan a derivarle, si es que quiere ir. Cualquier duda que tengáis no dudéis en decirnos, estamos a vuestra disposición"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-12-12','Ana: Envío correo a Toni, Futuex: "Os escribo en relación a FELISA FELIPE TEOMIRO y su hijo AITOR MORENO FELIPE. No sé para qué día tenéis programada la visita, pero es urgente que acuda la educadora. Desde el programa de familia se han negado ya a intervenir por problemas con Aitor, y aunque finalmente la semana pasada acompañaron a Felisi al cajero y accedieron a acompañarles a hacer la compra al Covirán (donde se niegan a darle los alimentos si no acuden acompañados) ahora es Aitor el que no quiere que le acompañen ellas… este chico lo pone todo patas arribas… ya sabéis, que en nuestra opinión, debería de estar en un centro, donde apoyen a diario con la toma de medicación, establezcan unos horarios, rutinas y unos hábitos saludables en general. Así como un ocupación. **Necesitamos: - que le acompañéis para hacer la compra al supermercado, ESTÁN SIN COMIDA. - Gestionéis un taxi (se abonará mediante transferencia, como suele ser habitual) y le acompañéis a la citación para comparecencia, el próximo 21/12/23, a las 11.30 en el Juzgado de 1ª Instancia nº 3 de Cáceres. Es precisamente sobre el procedimiento de ingreso involuntario. - Si en estos días, conforme vayáis viendo y valorando, podéis, elaborad informe de la situación actual (graves problemas de convivencia, consumo, extorsión a su madre para que le dé dinero para consumo… Todo esto nos lo cuenta Felisi por teléfono, que está desesperada). Sumado todo a la claudicación de los recursos de proximidad en el apoyo por las conductas y actitud de Aitor… cada día es más grave la situación. El Informe se intentará hacer llegar al Juzgado para que lo tengan en cuenta el día de la vista. - Por otra parte, Aitor perdió su tarjeta bancaria. Tiene otra ya que podría recoger, pero es en la oficina de Trujillo. Pero nos encontramos con el problema de que no tiene medios para ir. La única opción que se nos ocurre es que le acompañéis también en taxi (quizá así la educadora nueva se pueda ganar su confianza), pues podrá volver a retirar dinero (aunque no le dé buen uso, esperamos que así al menos esté algo más tranquilo y no se lo exija a su madre…). ¿Podríais por favor proponérselo y gestionar el taxi en tal caso?"','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-12-12','Ana: Envío correo a Toni, Futuex: "Os escribo en relación a FELISA FELIPE TEOMIRO y su hijo AITOR MORENO FELIPE. No sé para qué día tenéis programada la visita, pero es urgente que acuda la educadora. Desde el programa de familia se han negado ya a intervenir por problemas con Aitor, y aunque finalmente la semana pasada acompañaron a Felisi al cajero y accedieron a acompañarles a hacer la compra al Covirán (donde se niegan a darle los alimentos si no acuden acompañados) ahora es Aitor el que no quiere que le acompañen ellas… este chico lo pone todo patas arribas… ya sabéis, que en nuestra opinión, debería de estar en un centro, donde apoyen a diario con la toma de medicación, establezcan unos horarios, rutinas y unos hábitos saludables en general. Así como un ocupación. **Necesitamos: - que le acompañéis para hacer la compra al supermercado, ESTÁN SIN COMIDA. - Gestionéis un taxi (se abonará mediante transferencia, como suele ser habitual) y le acompañéis a la citación para comparecencia, el próximo 21/12/23, a las 11.30 en el Juzgado de 1ª Instancia nº 3 de Cáceres. Es precisamente sobre el procedimiento de ingreso involuntario. - Si en estos días, conforme vayáis viendo y valorando, podéis, elaborad informe de la situación actual (graves problemas de convivencia, consumo, extorsión a su madre para que le dé dinero para consumo… Todo esto nos lo cuenta Felisi por teléfono, que está desesperada). Sumado todo a la claudicación de los recursos de proximidad en el apoyo por las conductas y actitud de Aitor… cada día es más grave la situación. El Informe se intentará hacer llegar al Juzgado para que lo tengan en cuenta el día de la vista. - Por otra parte, Aitor perdió su tarjeta bancaria. Tiene otra ya que podría recoger, pero es en la oficina de Trujillo. Pero nos encontramos con el problema de que no tiene medios para ir. La única opción que se nos ocurre es que le acompañéis también en taxi (quizá así la educadora nueva se pueda ganar su confianza), pues podrá volver a retirar dinero (aunque no le dé buen uso, esperamos que así al menos esté algo más tranquilo y no se lo exija a su madre…). ¿Podríais por favor proponérselo y gestionar el taxi en tal caso?" ·············································································· Correo de Toni-Futuex: "Justo como dices, estan siendo dias muy estresantes, para intentar reactivar todo y que las compañeras que empiezan nuevas, tengan toda la información de cara al abordaje de los seguimientos. Justo hoy, va para alla la nueva educadora, pero vamos a ciegas, ya que ni el telefono de Aitor ni el de Felisi conseguimos contactar ayer.. salian apagados o como si no tuvieran linea.. a ver que nos encontramos ya que como dices la situación es muy complicada. Haremos lo que solicitas de contactar con taxista, para vista del dia 21 y para ir a recoger tarjeta. Lo de la compra a ver si puede hacerse hoy mismo. Y el informe lo haremos, a ver si ayudara en el algo al procedimiento. Al respecto de sacar dinero Felisi, con la tarjeta monedero, ella tiene el pin supongo no? o el programa de familia?? He ido a buscar lo que teniamos al respecto y nada. Virginia no nos ha dejado nada, al respecto del numero pin de la tarjeta monedero, por esto te lo comento." ······················ Mi respuesta: "Perfecto Toni, gracias. Sabemos por Aitor que Nieves ya está con ellos, jeje. A ver qué tal. *En cuanto a los números de teléfono, disculpa, porque al menos yo no caí en facilitarte los números nuevos, pues ambos han cambiado…. Aitor: 613 694 469 Felisi: 614 361 144"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-12-12','Ana: Envío correo a Toni, Futuex: "Os escribo en relación a FELISA FELIPE TEOMIRO y su hijo AITOR MORENO FELIPE. No sé para qué día tenéis programada la visita, pero es urgente que acuda la educadora. Desde el programa de familia se han negado ya a intervenir por problemas con Aitor, y aunque finalmente la semana pasada acompañaron a Felisi al cajero y accedieron a acompañarles a hacer la compra al Covirán (donde se niegan a darle los alimentos si no acuden acompañados) ahora es Aitor el que no quiere que le acompañen ellas… este chico lo pone todo patas arribas… ya sabéis, que en nuestra opinión, debería de estar en un centro, donde apoyen a diario con la toma de medicación, establezcan unos horarios, rutinas y unos hábitos saludables en general. Así como un ocupación. **Necesitamos: - que le acompañéis para hacer la compra al supermercado, ESTÁN SIN COMIDA. - Gestionéis un taxi (se abonará mediante transferencia, como suele ser habitual) y le acompañéis a la citación para comparecencia, el próximo 21/12/23, a las 11.30 en el Juzgado de 1ª Instancia nº 3 de Cáceres. Es precisamente sobre el procedimiento de ingreso involuntario. - Si en estos días, conforme vayáis viendo y valorando, podéis, elaborad informe de la situación actual (graves problemas de convivencia, consumo, extorsión a su madre para que le dé dinero para consumo… Todo esto nos lo cuenta Felisi por teléfono, que está desesperada). Sumado todo a la claudicación de los recursos de proximidad en el apoyo por las conductas y actitud de Aitor… cada día es más grave la situación. El Informe se intentará hacer llegar al Juzgado para que lo tengan en cuenta el día de la vista. - Por otra parte, Aitor perdió su tarjeta bancaria. Tiene otra ya que podría recoger, pero es en la oficina de Trujillo. Pero nos encontramos con el problema de que no tiene medios para ir. La única opción que se nos ocurre es que le acompañéis también en taxi (quizá así la educadora nueva se pueda ganar su confianza), pues podrá volver a retirar dinero (aunque no le dé buen uso, esperamos que así al menos esté algo más tranquilo y no se lo exija a su madre…). ¿Podríais por favor proponérselo y gestionar el taxi en tal caso?" ························································ Correo de Toni-Futuex: "Justo como dices, estan siendo dias muy estresantes, para intentar reactivar todo y que las compañeras que empiezan nuevas, tengan toda la información de cara al abordaje de los seguimientos. Justo hoy, va para alla la nueva educadora, pero vamos a ciegas, ya que ni el telefono de Aitor ni el de Felisi conseguimos contactar ayer.. salian apagados o como si no tuvieran linea.. a ver que nos encontramos ya que como dices la situación es muy complicada. Haremos lo que solicitas de contactar con taxista, para vista del dia 21 y para ir a recoger tarjeta. Lo de la compra a ver si puede hacerse hoy mismo. Y el informe lo haremos, a ver si ayudara en el algo al procedimiento. Al respecto de sacar dinero Felisi, con la tarjeta monedero, ella tiene el pin supongo no? o el programa de familia?? He ido a buscar lo que teniamos al respecto y nada. Virginia no nos ha dejado nada, al respecto del numero pin de la tarjeta monedero, por esto te lo comento." ······················ Mi respuesta: "Perfecto Toni, gracias. Sabemos por Aitor que Nieves ya está con ellos, jeje. A ver qué tal. *En cuanto a los números de teléfono, disculpa, porque al menos yo no caí en facilitarte los números nuevos, pues ambos han cambiado…. Aitor: 613 694 469 Felisi: 614 361 144"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-12-12','miguel, recibo email de Damian: Le facilito el número de la inmobiliaria de Mérida para después comprar aquí 824630197.la chica se llama nuria.y la inmobiliaria tecnocasa.gracias buena tarde','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2023-12-12','Ana: En relación al correo de Diana Arroyo, TS Ud. Att. al Estudiante - UEX (618 381 887 / darrpan@unex.es): "me han llamado des F.ONCE estan valorando las solicitudes y Sandra no tiene muchas opciones de beca. Sandra podría matricularse en una academia de unos 100 €/mes más o menos? Me gustaría, si puedes, que me llames." ············· Llamo a Diana y acordamos que facilitará a la Academia mi contacto para que me envíen un presupuesto a nombre de Sandra, para que pueda valorarse y aprobarse desde la S. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2023-12-12','Ana: Correo de ayer (festivo local)de Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es) al ctutelar: "Como sabréis se ha jubilado Rosa Bravo, eficiente auxiliar administrativo que controlaba el tema de sacar dinero a tutelados, por lo que agradecería que me indicaseis lo siguiente: Carlos Alberto Vicente Calderero, la entidad bancaria donde podemos sacarle dinero y la cantidad mensual asignada. Tenemos autorización vuestra, pero no refleja ni el número de cuenta, ni la cantidad asignada, ni siquiera el nombre y apellidos del tutelado, es una general para todos los tutelados."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2023-12-12','Ana: Correo de ayer (festivo local)de Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es) al ctutelar: "Como sabréis se ha jubilado Rosa Bravo, eficiente auxiliar administrativo que controlaba el tema de sacar dinero a tutelados, por lo que agradecería que me indicaseis lo siguiente: Yolanda Caldera Martín, la entidad bancaria y la cantidad mensual asignada. También tenemos autorización con su nombre, pero sin número de cuenta ni cantidad mensual asignada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-12-12','Ana: correo de ayer de Sara, TS R.M. Banium Residencial (TrabajadoraSocialBanium@hotmail.com): "El siguiente correo es para informar que hemos tenido que reprogramar un a consulta para Concepción Barbero Sánchez, la cual nos dirán la fecha en los proximos días. Es para una radiografía y la revisión pertinente de traumatología. Este correo es para: • Solicitar permiso para el servicio de acompañamiento. Además de esto, me gustaría plantear la siguientes cuestiones: • La usuaria va a tener que acudir a más revisiones de traumatología programadas para las que se deberá solicitar acompañamiento y no sé si ella puede permitirse esto, para ver que otras opciones nos ofrecen en caso de que no se autorice el acompañamiento por falta de dinero. • Ir informando que el centro residencial tiene previsión de subir las tarifas mensuales a principios de año. Cuando el centro residencial Banium dejo de tener plazas sociosanitarias tipo T3, se hizo un cálculo estimado con el coste del servicio en ese momento para ver si la usuaria tenía solvencia o no. Con estos últimos gastos inesperados, no sé si la usuaria Concepción Barbero Sánchez podrá continuar abonando la cuantía de la tarifa mensual de una plaza privada. En relación a los temas anteriormente mencionados me mantengo a la espera de que me autoricen el acompañamiento y valoren la situación de Concepción." ···························· Mi respuesta: "Gracias por informar. Necesitaríamos saber los costes exactos de las distintas cuestiones para pasárselo al Jefe de Sección Económica y que éste nos confirme la viabilidad. De no ser así, te llamaré para valorar alternativas. Por cierto, entiendo que Concepción continúa ingresada, ¿verdad? ¿cómo sigue?" ······································· Llamada de Sara, TS Res. Banium (927 488 017): Aún no saben la cuantía de la subida de la plaza. Nos lo comunicarán en cuanto lo sepan. ···· Por otra parte Conchi ya está de vuelta en la residencia, le dieron el alta, pero con la fractura del brazo ahora tendrá que asistir a varias citas para radiografías y a Traumatología. *El coste medio de los acompañamientos, variará en función del tiempo que tarden, la media está en 60€/mes. ·········· Puesto que de momento tiene dinero en la cuenta, se autorizarán. ········ *Mientras pueda seguir permaneciendo en la Res no la cambiaremos. Tiene 87 años, Grado III de Dependencia. Percibe la Prestación Vinculada al SAR. ····· Ella no desea cambiar, está bien adaptada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2023-12-12','Ana: correo de Ángel Luis Blanco, Psiquiatra UHB-Plas (angeluis.blanco@salud-juntaex.es): "...Tenemos ingresada en la unidad una paciente incapacitada LUISA REY CAMPON, tutelada por esa comisión. Está en tratamiento con Quetiapina desde hace años, pero al cumplir 75 años no se le puede prescribir, salvo un protocolo sobre uso compasivo que exige firma del tutor legal de la paciente. Desearía me indicara quien firma y como dicho consentimiento. La paciente está pendiente de alta en esta UHB, pero no podemos prescribir la medicación ambulatoria sin ese documento (que se lo adjunto). Si lo firman y me lo mandan escaneado lo reboto a la inspección médica para la autorización." ···························· Respondo: "...La persona que firma el documento es la DIRECTORA GERENTE DEL SEPAD, que ejerce la Presidencia por Delegación de la CTAEx. Adjunto documentos que lo acreditan. Adjunto el consentimiento informado firmado y sellado debidamente. Por cierto, mi teléfono directo es el que aparece en la firma y el corto es el 68414. Ante cualquier otra cuestión no dudes en volver a contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-12-12','Ana: Correo de Pilar Martín, ESM (pilar.martinp@salud-juntaex.es): "mira lo de José Manuel Romero Mediavilla, para seguimiento con el gabinete vuestro sobre el asunto de los juzgados, es por lo de su solicitud de CRR." ···························· Mi respuesta: "hablo con mis compañeros Asesores Jurídicos. Pero lo último que me dijo él (la semana anterior al puente) es que había solicitado ingreso en URH del Sociosanitario de Plasencia… *De todos modos si desde la Sección de Acceso a recursos de salud mental han emitido un informe diciendo que José Manuel no puede acceder a ningún CRR, entiendo que por mucho que diga el Juez, no puede ingresar en esos recursos. De hecho yo creo que no han contestado, no porque aún lo tengan pendiente, sino porque se han dado por comunicados de esta nueva situación y listo. No obstante su sentencia de incapacitación está en vías de revisión. No sé si por ahí se podrá mover algo." ··················································································· Llamada de José Manuel: no dice nada de los ingresos, ni el que ha vuelto a pedir a Pilar Martín para CRR. ············· Dice que le han autorizado los 50€ para la cena de Nochebuena con su hijo. Pero que necesita otro EXTRA, porque se ha endeudado de nuevo en barrio. Debe 150€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2023-12-12','Ana: Correo de Estrella Duran, TS CSS-Plas., al ctutelar@ con copia a mi correo: Mañana pasará nuestro ordenanza por Ibercaja a sacar dinero al tutelado, Cristofer Figueroa Rastrollo, la autorización que tenemos es para extraer al mes 300 euros. Tendrá que sacar 40 euros más para comprarse una máquina de afeitar, para que enviéis la autorización extraordinaria al banco."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2023-12-12','TERESA hará el Curso de formación de Atención Socio-sanitaria a personas en domicilio con Certificado de Profesionalidad, del 13 de diciembre 2023 al 24 de junio de 2024, organizado por el Centro de Formación para el empleo de Don Benito (SEXPE).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2023-12-12','Ana: correos de ayer (festivo local) de Sheila, Directora del CRR -CC (crr@grupociudadjardin.com) al ctutelar@: " Comunicar el fallecimiento de la madre de la persona tutelada Martin Miguel Miranda Hernández. Victoria Hernandez era residente en la residencia Cervantes de Cáceres, Falleció el viernes y lleva en cámara en el tanatorio San pedro de Alcántara de Cáceres, desde dicho día. Según se nos desde el mismo la fallecida no tenía seguro de decesos y están a la espera de saber como proceder. Al no tener más familia, aún no se ha comunicado el fallecimiento a Martin, ante la falta de información y viabilidad por su estado de gestionar lo necesario para el entierro el sólo, y ante la falta de conocimiento del procedimiento, será esta mañana cuando se procederá a comunicar el mismo y acompañarle al tanatorio en caso de solicitar ver a su madre. Estamos intentando contactar con vosotros/as vía telefónica (sin éxito hasta el momento) para resolver algunas dudas y poder gestionar y ofrecer a Martin una mejor comunicación de la situación ." ······· "Tras diferentes gestiones realizadas confirmamos que finalmente la póliza de decesos que tiene Martin, cubre a su madre también. Motivo por el cual se inician los trámites pertinentes para el entierro de la misma. Estamos a la espera de comunicación de fecha y hora. Martin será acompañado por personal del centro para depedir el cuerpo de su madre ya que no conta mas familia." ······························ Mi respuesta: "Disculpa las molestias, pero ayer fue festivo local en Mérida y no trabajamos. Supongo recibirías mi correo-respuesta automatizado. ¿Qué tal está Martín? Siento la pérdida. Es una triste noticia. Desde la Residencia Cervantes también nos han comunicado el fallecimiento, pues Victoriana Hernández también estaba a cargo de la CTAEx. Gracias por haberos encargado de las gestiones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2023-12-12','Ana: correo de ayer (festivo local) de Minerva, TS CR Cervantes (minerva.salvador@salud-juntaex.es): "comunicarte que la residente Victoriana Hernández García ha fallecido el pasado 8 de diciembre." ····················· Lo comunico a Julio y María - CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2023-12-12','Ana: Correo de Raquel, Residencia de Almaraz (rvadillo@residenciacatalinacuriel.es): "Te escribo referente a Flora Gutiérrez García, tenemos una factura del taxi que se utilizo el día 15 de noviembre para sacar la asignación mensual para que se le abone, siento mandarla tan tarde pero hasta ahora no la ha mandado el taxista." ············· Lo reenvío a la sección económica para que la abonen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-12-12','Ana: Correo de Gema, Directora Res (gemamg.asoma@gmail.com): "Comentarte que a Victor le quedan 15 euros de su dinero, estoy llamándote pero me da todo el rato como número ocupado, solo quería preguntarte cómo podemos hacer para que me mandeis de alguna manera dinero para sus gastos porque el miércoles viene el podólogo, tengo que pagar los 15 euros que es lo que cuesta y ya se queda sin liquidez." ····················· Mi respuesta: "En relación a la asignación de Victor Manuel, entiendo que hay dos opciones: 1- Que os hagan transferencia periódica a vuestra cuenta bancaria (no se si es viable, así se hace con otros residentes) 2- O se puede enviar una autorización a la oficina bancaria para que podáis acompañarle a retirar el efectivo Eso sí, necesitamos que nos hagáis un “presupuesto” aproximado de los gastos medios mensuales que tiene."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2023-12-12','Ana: correo de Lourdes, Secc. Ecca.: "Ya está abonada la factura de farmacia del mes de noviembre. Te la envío, porque sale de las cantidades que se suelen pagar. Hay un medicamento que cuesta 97€- Solo es a nivel informativo.-" ··································································································································································································· Envío correo a Ana, Res. Torrecillas de la Tiesa (anatdelat@hotmail.com): "En relación a la factura de farmacia, que ya está abonada, me comentan las compañeras que le ha extrañado un gasto elevado (97 €) no habitual. Por el nombre entiendo que es algo para úlceras. ¿Podrías confirmarnos si es un medicamento que necesita de forma puntual o si será habitual su uso? Más que nada por la cuestión económica, pues varía bastante el gasto mensual. Aprovecho para decirte que llamé sin éxito en distintas ocasiones a la Notaría de Trujillo, por lo que el día 21 de noviembre les remití un correo solicitando presupuesto y cita, pero aún no me han dado respuesta. Intentaré volver a contactar a lo largo de esta semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-12-12','Ana: Correo de ayer, festivo local, de Mª José, actual Directora Res (residencia_mayores@hervas.es): "Soy María José, de la Residencia de Mayores de Hervás , dónde actualmente reside Eugenia. me he intentado poner en contacto con usted por teléfono, pero no lo he conseguido. Eugenia insiste que no le están ingresando en su cuenta corriente la paga que tenia asignada, y está preguntando en el SEPE, Seguridad Social etc. , No sé que contestarle, porque tampoco sé que clase de paga recibía. Le agradecería si usted puede ayudarme para tranquilizarla se pusiera en contacto con nosotros." ········································ Llamo a Mª José (927 473 410): Explico que Eugenia percibe el SUBUSIDIO PR DESEMPLEO para mayores de 52 años. ····· Confirmarán si ha renovado la demanda de empleo y sino le acompañarán a inscribirse de nuevo como demandante. ··························· Pido a la secc. ecca. que comprueben si han dejado de ingresarle el subsidio.','2');
