insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-12-12','Ana: Envío correo a A. Jurídicos: "A ver, no sé si podéis averiguar algo. Me llama una tal Luisa (642 365 635), “amiga” de MIGUEL ÁNGEL RAMOS ANDRÉS, del piso Okupa en que está ahora en Badajoz… dice que ha habido un incendio en el campo de fútbol y que le ha detenido la policía municipal acusándolo como autor de dicho incendio. Ella insiste en que él no ha sido… Dice que van a celebrar un juicio rápido. ¿Podríais consultar a la Policía Municipal de Badajoz?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2023-12-13','TERESA ENVIO POR REGISTRO PIA SOLICITANDO TRASLADO DE CENTRO A LA SECCION DE VILLANUEVA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2023-12-13','Ana: Correo de ayer de Sheila, Directora CRR (crr@grupociudadjardin.com): "El miércoles día 5 de Diciembre se le requisaron en su cuarto, al entrar de la calle con una mochila, 5 latas de cerveza ya vacías, y una lata de bebida energética. No hubo alteración de conducta que conllevara la necesidad de activación de protocolo para traslado y valoración. A pesar de ello, se encuentra con lenguaje desorganizado, negación a acudir a citas con psicóloga y terapeuta, la ropa que se adquirió la semana pasada ya no se encuentra en el centro, expresando éste haberla vendido para obtener dinero. Esta semana, son varios los días que a las 7:45h de la mañana, se le observa saliendo del supermercado cercano al centro con una lata de cerveza. Se aprecia olor al alcohol en las interacciones con él a diario. No puede seguir indicaciones ni participar en talleres debido a su estado actual de consumo. En la consulta de la enfermera de salud mental se vuelve a intentar la posibilidad de acudir al CEDEX, negando éste su participación y no reconociendo el consumo. Desde el CRR manifestamos la preocupación por su salud, su integridad, las dificultades para poder intervenir, la ausencia de conciencia sobre su propio consumo y estado, así como solicitamos traslado a un recurso mas adaptado a las necesidades actuales." ··········································································· Mi respuesta: "Gracias por informar, entendemos perfectamente vuestra preocupación, no obstante, en cuanto al "traslado a un recurso más adaptado a las necesidades actuales" que solicitáis, acabamos de hablar en equipo de este caso y no encontramos solución. Entendemos que por su perfil, Trastorno Mental Grave y consumo de Alcohol, lo más adecuado sería ingreso en la Unidad de Alcoholismo Hospitalaria del C. Sociosanitario de Plasencia, pero la derivación se realiza desde el ECA (antiguos CEDEX) a los que como decís, no quiere asistir y el ingreso en dicha unidad, si no me equivoco, también requiere la voluntariedad de la persona. La otra opción que contemplamos son las Comunidades Terapéuticas, pero supongo que tendríamos las mismas dificultades de acceso que con la UAH. Uno de los principales problemas es la falta de conciencia de su adicción y su estado de salud. Sinceramente, no sabemos si sería procedente abordar esta cuestión en Subcomisión, porque de entrada no vemos alternativa. Pongo en copia a Maite, Jefa de Sección, y a las compañeras de la Sección de Salud Mental, a ver qué opciones ven ellas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-12-13','Ana: Llamada de Sergio (640 654 897): pregunta dónde están sus pagas extras y el resto de su dinero (remanente de su pensión tras abonar el centro y su asignación). *Le explico que está en su cuenta bancaria que se administra desde la CTAEx. Y el funcionamiento. ······· Quiere solicitar algún extra, pensará primero bien el concepto y la cuantía. *Le recuerdo que se valorará con el centro y el Jefe de Secc. Ecca. deberá dar el visto bueno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-12-13','Ana: Se autoriza transferencia periódica de 20€/mes a Maribel, hermana de Conchi, para ayudar a costear el traslado de sus visitas periódicas. ·········· María, Secc. Ecca, se encarga y confirmará a Maribel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2023-12-13','TERESA HALBO CON MARIA TS DEL EQUIPO DE SALUD MENTAL DE ZAFRA 45970 ESTA AL TANTO DE LA SITUACION Y ME FACILITA EL TELEFONO DE ISALBEL 45960 ENFERMERA DE SALUD MENTAL PARA PLANTEARLE LA NECESISDAD DE INFORME DEL PSIQUIATRA QUE APOYE LA SOLICITUD DE INGRESO INVOLUNTARIO ME LO ENVIARA POR EMAIL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='CEDILLO'),'2023-12-14','SIDEX : Perfecto, si Rosa estupenda, sisi sigue Isabel, y ya os comente q con la chica de los fines de semana y festivos ya no esta sola ningun dia mucho tiempo, hablamos por aqui con cualquier cosa, gracias y saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2023-12-13','Ana: Respuesta de Ana, directora Res: "Lo referente a los 97€ que aparecen en la factura son las medias de comprensión que le mandó el cirujano, por lo que es de forma puntual."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-12-13','Miguel : Buenos días, me ha llamado Grego de los Servicios Jurídicos de la Banca Pueyo (924846008)para saber: 1.-El resultado del internamiento involuntario de Justa ya que estaban pendientes del mismo para continuar la ejecución hipotecaria de la vivienda. Desconocemos si en Audiencia han confirmado o no el auto dictado en Marzo autorizando el internamiento ya que lo único que nos ha llegado es que se devuelve al juzgado de 1º instancia la resolución firme de la Audiencia para su cumplimiento. En caso de que se confirme el internamiento habrá que pensar qué vamos a hacer con los muebles de la casa, e ir buscandole un centro de mayores. He pedido a Inés a ver si puede conseguir la resolución dictada por la Audiencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-12-13','Amalia : la solicitud de centro residencial ya la hice pero no pude presentarla , sin la autorización judicial que autorice el internamiento involuntario no es válida . Lo veo complicado , Justa amenaza con intento autolítico si se le obliga a ingresar en centro . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-12-13','Buenas , os reenvío email de Rosa en referencia al vehículo , que al parecer ya está a su nombre . Era parte de la herencia de Blas . Con respecto al pago del taller y mientras la S. jurídica no indique otra cosa se ha determinado no abonar hasta que no esté totalmente liquidado el tema de la herencia , para que podamos determinar exactamente con lo que cuenta esta Sra. Ángel , quedamos a la espera de que nos indiques el fin de ese proceso. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-12-13','Ana: Correo de Toni, Futuex: "...al respecto del seguimiento que se hizo ayer: La educadora se acerca este día al domicilio para ver cómo están y cuál es la situación actual. Al llegar, Felisi y Aitor la reciben, bien. Aitor está muy sucio pero sí se nota que está bastante descuidado, en la cocina hay desorden y mal olor. Le comentan a la educadora que tienen que hacer una compra, pues llevan tiempo sin poder hacer una (cerca de un mes, asegura Aitor). Aitor comenta a la educadora que ha estado hablando con Teresa y que le ha dicho que la compra de esta semana puede ser de 150 euros en vez de 100, la educadora le pregunta si estáseguro de eso y él llama a Teresa en el momento para corroborarlo, quien efectivamente dice que puede ser así en esta ocasión debido al tiempo que llevan sin poder hacerlo. La educadora pregunta a Aitor si va a ir a hacer la compra, él dice que le duelen mucho las piernas y que por favor vaya ella con su madre. Aceptan pero le dice que tendrá que ayudar después a descargar y a colocar la compra. De camino a hacer la compra, Felisi cuenta que la situación con su hijo es muy difícil y que ella no se ve capaz de poder más con él y su estilo de vida (sobre todo por el consumo). Dice que lleva dos semanas sin ver a su pareja porque un día Aitor llegó a casa después de haber consumido y le agredió (según ella cuenta, no sabemos si será cierto). También asegura llevar unos días mejor con su hijo (buena relación). Tiene un poco de miedo por lo que pueda pasar el día 21 en la cita judicial por el ingreso involuntario de Aitor en un centro, porque ella sabe que no puede sostener la situación pero no quiere decir delante de él esto, y por eso prefiere no hablarlo mucho en su presencia. Como ha pasado otras veces, ella tiene mucho miedo a las reacciones de Aitor y a su vez, también cierta dependencia. Al llegar a la tienda de alimentación, nos comentan los responsables que tienen un ticket de noviembre que no ha sido abonado, de 100 euros, la educadora les pide hacerle una foto para poder reportarlo de nuevo y que se proceda al ingreso. Aitor, pide a la educadora poder sacar parte de su asignación desde la cuenta de su madre, que se lo ingresen a ella, pero se le dice que lo mejor es que vayan cuanto antes a recoger su tarjeta bancaria a Trujillo, donde hay que realizar dicha gestión. Se organiza esta salida para el viernes 15 por la mañana, para ir en taxi los dos hasta allí." "Sobre las citas pendientes, Felisi comenta que tiene pendiente el ginecólogo y el dentista."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2023-12-13','TERESA Ramón fatal, acostado el hermano dice que le da miedo despertarlo.. que ayer estuvo con un hacha por la calle atemorizando a los vecinos (según el hermano que vive con el) bueno en la planta baja... Ramón esta en la segunda planta, que tiene la casa fatal.. y en fin, muy mal lo que nos cuentan. La compañera a ido a salud mental a comunicar esto.. a ver si obtenemos algo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2023-12-14','TERESA , hay unas llaves aquí de la vivienda de Antonio Hidalgo Romo.. luego con todo el parón y que no hemos tenido reuniones, pues no os las hemos hecho llegar. El viernes veo a las educadoras nuevas de Cáceres, si te parece se las entrego, para que vaya a Alcuescar y vea la vivienda con el hermano?? Lo que no tenemos ahora mismo es el contacto, teléfono o dirección del hermano de Antonio, si me lo puedes pasar la semana que viene, pueden quedar con el?? LE PASO EL CONTACTO DE LA CASA MISERICORDIA PARA QUE SE COODIRNEN CON ANTONIO Y SU HERMANO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2023-12-14','Ana: Envío correo a Maite y Julio - CTAEx: "Acabo de enterarme por nuestra compañera María que FÉLIX FIGUEROA MARTÍN, está residiendo en el CRR de Don Benito. - Julio: porfa, cuando puedas cámbialo en la base de datos. Maite, ¿a ti te habían dicho algo desde la Sección de Salud Mental? Desde que en marzo me facilitaron la solicitud de traslado para su firma, nadie me ha vuelto a decir nada, ni desde la sección ni desde el CRR de Cáceres ni desde el de Don Benito… No tenemos la resolución de la nueva plaza y no sé cuándo ha tenido lugar el traslado e ingreso en nuevo centro" ·································································· *Se autoriza un extra de 200€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-12-14','Ana: Llamada de Julia, pregunta si se sabe ya algo de la solicitud de plaza en CRR, Le explico la dificultad con la que nos hemos encontrado y que se van a valorar otras alternativas. Tendrá que tener paciencia. ·············· Me pasa con su madre para que se lo explique también a ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-12-14','Ana: Llamada de Maribel, hermana de Conchi (682 733 187), le confirmo que se ha autorizado los 20€/mes para apoyar en el gasto de las visitas periódica a su hermana. *Le llamará mi compañera María para que facilite en nº cuenta. Dice que será el de su hermana Ana que es la que tiene el coche.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2023-12-14','Ana: Respondo al correo de Estrella Gómez, TS del SSASB Malpartida de CC (ssb@malpartidadecaceres.es) planteando una serie de cuestiones y la petición de la abuela de Ana María de cambio de centro a uno más cercano: "- El cargo de CURATELA REPRESENTATIVA de Ana María, ya está aceptado por la CTAEx. - La PNC, la solicité a fecha de 22 de noviembre, una vez tuve toda la documentación necesaria. Ahora toca esperar, ya sabes que tienen 3 meses para resolver. - Ana María ingresó con carácter de urgencia en el primer centro que fue posible (donde había plazas). Desde menores, por los motivos que fuera, no llevaron a cabo con tiempo todas las acciones del protocolo, de modo que no se había solicitado plaza con la suficiente antelación antes de cumplir la mayoría de edad. No obstante, el centro en el que está es un centro que funciona fenomenal y se ha adaptado muy bien. - En cuanto a la solicitud de traslado, por un lado, no se puede solicitar hasta que haya pasado un año de su ingreso en el centro actual. Por otro, llegado el momento, si la abuela lo sigue demandando, habrá que valorar detenidamente la conveniencia o no de un nuevo cambio de recurso residencial. - En cuanto la posibilidad de organizar una visita al domicilio familiar, tendría que valorarlo con: o El equipo social, pues el cargo es muy reciente y no sabemos realmente cómo podría afectar a Ana María. *No obstante, en el informe de seguimiento del Centro Dulce Nombre de María de Málaga de finales de Agosto de 2023, se recoge textualmente: “Desde que falleció su tía, las vacaciones se han modificado, ya que la abuela es muy mayor para atender a Ana, por lo que va una vez al año con una educadora y vuelve en el mismo día”. Por tanto entiendo que en caso de realizarse debería ser con en este mismo formato. o La sección económica, pues la cuenta que tenía inicialmente Ana Mª era en el Banco Santander y ha costado mucho obtener información sobre la misma y su saldo, que no es elevado, pero tendría para asumir el gasto. Las compañeras suelen tener muchos problemas para operar con este banco, pero podríamos ver si habría forma de hacer transferencia a la nueva cuenta y si fuera procedente, organizar una visita." ·························································································································································································· Envío correo a Alberto e Icíar, S. Ecca. "he visto que tenemos saldo de la cuenta del B. Santander (1.846,75 €). ¿Sería posible solicitar transferencia de eses dinero a la nueva cuenta? Creo que ya lo teníais planteado, pero no estoy segura. Ana María está sin dinero para ningún tipo de gasto desde que está en el centro, si bien es cierto que no le falta de nada porque le proporcionan lo que necesita en el centro sería conveniente que e pudieran ir sufragando sus gastos. Por otra parte, estamos valorando que pueda acudir de visita (ida y vuelta en el día) al domicilio familiar (abuela y hermanos) y eso sí que no lo pueden costear desde el centro. Pongo en copia a Tere sólo para su conocimiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-11-29','Ana: Corre de Alberto, Jefe S. Ecca: "MARIA: OK AL REINTEGRO "EXTRA NAVIDAD" X 200 €...ITENTA QUE LO COBRE DESPUÉS DEL PUENTE (PARA QUE LO ASOCIE A NAVIDAD)...Y SI TIENE QUE SE ANTES, TAMBIÉN VALE."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2023-12-13','TERESA Buenas tardes Teresa. Como hablamos la semana pasada, le solicité un informe a la médica de familia de Idelfonso, me lo ha facilitado esta semana. Según me comenta, Idelfonso ha cambiado el último mes de médico, él ha solicitado el cambio en el cupo con otra médica en la misma localidad; Ahora es Marta Corraliza Morcillo su médica. Me comenta Marta, telefónicamente, que tan solo lo ha atendido una vez y que está pendiente de que vuelva a consulta para hacer un seguimiento, pero no ha asistido, esto hace ya varias semanas. Si que me comenta que ha tenido una cita con la psiquiatra recientemente y ha asistido, aunque, desconocemos si hay alguna anterior en las que no haya asistido, o lo que han tratado en dichas consultas. (te adjunto el informe de Marta)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2023-12-14','TERESA He contactado con salud mental y he conseguido hablar con la psiquiatra de Ildefonso. Nos emplaza a la comisión a acudir a cita junto con Ildefonso para hablar de la situación y exponerle las consecuencias de sus actos…..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-12-14','Ana: Respondo correo a Beatriz, TS C. Penitenciario Ba (beatriz.TS.12742@dgip.mir.es): "Gracias por contactar e informar. Encantada. Efectivamente, la CTAEx ejercer el cargo de Curatela Representativa de Miguel Ángel Ramos Andrés. Tiene reconocida Prestación Familiar por Hijo a Cargo y sí, 47% Discapacidad por el CADEX, así como Grado I de Dependencia por el SEPAD- Te adjunto toda la documentación para vuestro expediente. ¿Podéis por favor informarnos del motivo de su ingreso en Centro Penitenciario y si fuera posible facilitarnos la Sentencia? Solicito a la sección económica el ingreso en cuenta peculio. No sé si se le autorizará la misma cuantía que tenía asignada de forma semanal. Te confirmo en cuanto sepa." ·································· Nuevo correo de Beatriz, TS C.P.: "El interno lo va llevar mi compañera Cristina, yo le al ingreso. Te comento que a como compañera ( no oficialmente, porque lo tendrías que pedir por escrito al director) te puedo decir que el interno ingresa preventivo, no ha habido juicio aún, acusado de homicidio. ". ······························································································································································································· Envío correo a Alberto, A. Jurídicos y Julio: "Como podéis ver en el correo de más abajo, MIGUEL ÁNGEL RAMOS ANDRÉS, ha ingresado en el C. PENITENCIARIO de Badajoz. - Alberto, hay que hacer transferencia periódica a cuenta peculio. ¿Te parece mantenerle la asignación semanal de 80 €? O se la bajamos un poco, no sé cuánto se le está dando a otros internos. Es perceptor de PFHC, recientemente, antes no cobraba nada, por lo que aún no tiene ahorros. Pero ya sabemos que el economato es bastante caro. - Julio, por favor, modifica cuando puedas el domicilio en la base de datos. - Miguel y Ángel: de forma extraoficial, me informan que “el interno ingresa preventivo, no ha habido juicio aún, acusado de homicidio.“ ¿Podéis pedir documentación al respecto al Juzgado o a la Dirección del Centro Penitenciario?" ······································································································································· Correo de Ángel a Subdirección del CP (SubRegimen.Badajoz@dgip.mir.es): "Nos dirigimos al Centro Penitenciario de Badajoz, desde la Comisión Tutelar de Adultos de Extremadura, en representación de nuestro curatelado, D. Miguel Ángel Ramos Andrés, que ha ingresado en este centro, según el correo recibido. Carecemos de información, ni de los motivos por los que ha ingresado. Por lo expuesto, les solicitamos nos informen del Juzgado que ha determinado el ingreso, el procedimiento judicial, así como cualquier otra información/documentación que consideren pertinentey de la que dispongan." ········································································································································ Respuesta de Alberto: "ESTE HOMBRE NO TIENE SALDO EN CUENTA. ..... • SE LE PUEDEN MANTENER LOS 80 €/SEMANA: SI ----- PERO NO DEBERIAMOS DE ACCEDER A NI UN SÓLO EXTRA QUE PUDIERA SOLICITARNOS A PARTIR DE ESTE MOMENTO (ESTO ES OPINIÓN), PARA HACERLE ALGO DE AHORRO PARA CUANDO SALGA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='LEAL'and apellido2='PARRA'),'2023-12-14','-Ingresa en CSS Mérida . Pido la autorización para sacar dinero desde el CSS y llamaré a la familia para que le lleven ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-12-14','Buenas tardes Hemos recibido en la Sección de Dependencia de Zafra, el documento de revisión PIA de MARIA JOSEFA MOYA GARCÍA, cuyo tutor es la Comisión Tutelar de Adultos, y la cual tiene reconocido Grado I, según baremo de Dependencia, pero no está disfrutando de ninguna prestación, porque se le resolvió una "NO ACPEPTACIÖN PIA" en el año 2022, porque no aceptó la PEVSAD por el copago que le suponía. En el momento actual, al retomar sus datos, le corresponderían de 20 a 37 horas conforme al intervalo recogido en el Decreto 675/2023, para el grado I. Al estar viviendo en Zafra, le podemos solicitar el Servicio de Ayuda a Domicilio, por el Convenio existente entre el Sepad y el Ayuntamiento de Zafra, y quedaría en lista de espera hasta que haya horas libres, y paralelamente, le podemos tramitar la Prestación Económica Vinculada al Servicio de Ayuda a Domicilio, con la cuantía de 122,50 a 226,64 horas al mes, de modo que: -Para 20 horas          122,50 euros al mes -Para 25 horas          153,13 euros al mes -Para 30 horas          183,76 euros al mes -Para 35 horas          214,39 euros al mes -Para 37 horas          226,64 euros al mes Yo les enviaré la documentación relativa al PIA, para que la firmen y la remitan a la Sección de Dependencia de Zafra, junto con el contrato y Alta a Terceros, en el caso de que quieran que tramitemos también la PEVSAD. Para cualquier duda o aclaración que necesiten pueden contactar conmigo en este correo o en el teléfono, 924018779. Seguimos en contacto para poder dar respuesta a la revisión PIA solicitada. gracias. Un saludo--------------------- Pido a ASINDE PTO.con 37 horas .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2023-12-14','Ana: Llamada de Isabel de Cáceres, madre de Alfonso (680 784 490): Ha pedido a la Dra. Rosa, Psiquiatra CSS, le van a autorizar un PASE DE SALIDA para ir a pasar las fiestas a Leganés con otro hijo. Pide EXTRA para el viaje, cumpleaños (día 31/12) y una zapatillas, las tiene rotas (calza el nº 47, por lo que son más caras). ························ Expresa la necesidad de que su hijo se DESINTOXIQUE de la gran adicción que tiene a los PORROS y de ingresar, cuando le den el alta, en un recurso residencial (CRR). ········································································································································ Envío correo a Alberto, Jefe Secc.: "Me ha llamado Isabel de Cáceres, madre de Alfonso Marín de Cáceres (680 784 490), la Dra. Rosa, Psiquiatra CSS, le va a autorizar un PASE DE SALIDA para ir a pasar las fiestas a Leganés con otro hijo. Pide EXTRA para el viaje, cumpleaños ( es el día 31/12) y una zapatillas, las tiene rotas (calza el nº 47, por lo que son más caras). ¿Sería posible autorizar entre 450 y 500 €? Se abonaría mediante transferencia a la madre, como en otras ocasiones. Si es posible que se lo confirmen las compis, porfi" ······························································································································································································· Correo-respuesta de Alberto: "MARIA: OK A EXTRA NAVIDAD X 450 € ---- XFA, HABLA CON MADRE TUTELADO (Dª ISABEL - TFONO.: 680 784 490) Y QUE TE FACILITE LOS DATOS PARA HACERLE LA TRANSFERENCIA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-12-14','Ana: correo de Sara, TS R.M. Banium Residencial (TrabajadoraSocialBanium@hotmail.com) al ctutelar@ y a mí: "Acaban de llamar del hospital Virgen del Puerto para informarnos que Concepción Barbero Sánchez tiene consulta el próximo día 29 de diciembre. Solicitamos permiso para poder llamar al acompañamiento privado. El importe está en 12€ la hora y hasta ahora viene siendo un coste total de 60€ por acompañamiento. A su vez estamos pendientes de enviarles la declaración jurada del acompañamiento del día de hoy." ····································· Contesto con copia a ctutelar@: "Por mi parte ok a este acompañamiento, salvo que mis compañeras de la sección económica, creo que es viable. Compañeras de la sección económica, porfa, cuando podáis confirmarnos a Sara y a mí que es así."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-12-14','Buenas, gracias por el informe de gastos . Opino igual , con estos gastos no es viable subir la asignación. Sí sería necesario comprar esos zapatos ortopédicos que necesita , si tiene algo de ahorros propongo que se le haga un reintegro extra de 150€ para que pueda comprarlos . No he autorizado el contrato con Vodafone ,pero no le daría de baja , al estar sola en la casa tiene que tener una línea de tf . Mejor esperar a la respuesta judicial y si autoriza el internamiento lo cancelamos entonces. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-12-14','Miguel : Grego de servicios jurídicos de Banca Pueyo ha escrito hoy a su procurador para que agilice en juzgado la resolución del internamiento. En cuanto lo tengan nos lo mandaran si no lo hace antes el juzgado. A partir de ahí si dan el internamiento, Banca Pueyo pondrá en marcha de nuevo la ejecución hipotecaria, que tardará unos meses me dice hasta la subasta. El procedimiento es de 2014 y Justa dejó de pagar la hipoteca el 16-3-2013.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2023-12-14','Amalia : contesto a su hijo Jorge que nos ha solicitado subir la asignación : Buenos días , por protección de datos no le puedo dar información sobre los ingresos y gastos de su madre . He derivado su solicitud a la Sección económica de esta comisión , han detallado todos sus gastos con la siguiente conclusión : OPINIÓN ECO: YO NO AUMENTARÍA REINTEGRO ALGUNO...(al reintegro que se le da hay que sumar VODAFONE, IBERDROLA, OCASO, IMPUESTOS... ). Con los ingresos de su madre , se cubren todos esos gastos y se le da un reintegro mensual . No es viable subir la asignación . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2023-12-15','Ana: Envío correo a Sheila, Directora CRR (crr@grupociudadjardin.com): "En relación a JUAN MARIO SAN ROMÁN BLASCO, el Juzgado nos requiere informe de la situación actual. Yo os envíe correo solicitándolo a fecha de 20/11/23, imagino que no os ha sido posible aún, pero agradeceríamos que nos lo hicieseis llegar a la mayor brevedad. Igualmente, si tenéis Informes Médicos recientes, de las últimas consultas de especialistas (incluido Salud Mental) agradecería nos los aportaseis también. Por otra parte, estoy pensando, que ya que se va a revisar su sentencia, igual es buen momento para que hagáis constar en el informe, las incidencias que nos habéis ido comunicando y la necesidad de que accediera a Unidad Especializada de Alcoholismo y Psiquiatría: “Unidad de Alcoholismo Hospitalaria”, si es que estáis de acuerdo en ello." ··········································································· Envío a Julio, Aux. Adtvo. CTAEx: "En relación con JUAN MARIO SAN ROMÁN BLASCO, cuanto puedas, porfa, remite por SIREX el oficio solicitud junto con la siguiente documentación, al EQUIPO DE SALUD MENTAL DE CÁCERES: - Testimonio de Aceptación del cargo. - Requerimiento del Juzgado de 1ª Instancia de Cáceres". ··············································· Nuevo correo a Julio: "...cuanto puedas, porfa, remite por SIREX el oficio solicitud junto con la siguiente documentación, al CENTRO DE SALUD ZONA CENTRO DE CÁCERES..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2023-10-30','Ana: correo respuesta de Alberto, Jefe Secc. Ecca: "ANA: DADO QUE VA A ESTAR EN LA UME DEL CSS DE PLASENCIA, NO VA A TENER COSTE DE CENTRO + ADEMÁS NO SE VA A ABONAR A LA MADRE LA MANUTENCIÓN DE 490 €/MES ---- EL CSS PLASENCIA PODRÍA DISPONER DE MUCHO DINERO ----SI QUIERES LO NEGOCIAS TU CON EL CSS, TENIENDO COMO LÍMITE LOS 490 QUE LE ESTAMOS DANDO A LA MADRE, AUNQUE A MI ME PARECERÍA MUCHÍSIMO SI QUISIERAN GASTARSE TODO ESE DINERO. MARIA: YA TIENES HECHA LA AUTORIZACIÓN GENERAL CSS PLASENCIA + CON RESPECTO A MANUTENCIÓN A MADRE NO HAY QUE HACER NADA (LAS TRANSFERENCIAS DESDE HACE MESESE SON PUNTUALES)...ASEGÚRATE XFA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-12-14','Ana: Llamada de Felisi (614 361 144): Está contenta con Nieves, nueva Educadora - Futuex que ha ido a visitarlos. Aprovecha para desahogarse de nuevo con respecto a la situación de su hijo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-12-15','Ana: Llamada de Felisi (614 361 144): ya no puede más con su hijo, dice que tiene muchas deudas en el pueblo y le pide a ella el dinero para abonarlas. Además lo último que le ha dicho es que esa casa es suya y la va a echar a la calle. ·················· Hoy Nieves, Ed. Futuex, les acompañará a ambos al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MORA'and apellido2='GARCIA MORA'),'2023-12-15','TERESA LLAMOA MARGARTIA 633836411 MARGARITAGMP79@GMAIL.COM ME INFORMA QUE SU PRIMO SE ENCUENTA EN LA CASA DE ACOGIDA DE CARITAS DE DON BENITO TS JUAN CARLOS 686 81 26 13 COMENTA QUE ESTE CENTRO ES TEMPORAL POR LO TANTO HAY QUE SOLICITARLE CENTRO EN DON BENITO TAMBIEN HAY QUE PEDIR REVISION DE GRADO DE DEPENDENCIA ESTA PENDIENTE DE RECIBIR INFORME SOCIAL PARA HACER INVENTARIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-12-12','Ana: Llamada de Carlos, pregunta por el extra que ha solicitado por Navidad. Aún no tenemos respuesta de Alberto. Volverá a llamar a finales de semana. ······················· Mañana tiene cita con la Psiquiatra (se la han adelantado un día). Le acompañará Mamen, nueva Ed.- Futuex, ya ha contactado con él y éste se lo ha dicho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-12-15','Ana: Reenvío correo de solicitud de extra a Alberto, Jefe S. Ecca., pues Carlos no deja de preguntar a María y a mí, y aún no tenemos respuesta. ·················· Respuesta de Alberto: "MARIA: OK A REINTEGRO EXTRA NAVIDAD X 225 € ENTRE EL 18 Y EL 22 DICIEMBRE 2023.......MARIA, LE LLAMAS DIRECTAMENTE A EL Carlos González Leo (644 949 205)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-12-15','Ana: Llamo a Cristina, TS C. Penitenciario de BA (924 28 91 00), como está en módulos hablo con Beatriz, compañera TS. En principio, en la Acogida, él demandaba los 80 €. Le explico que dado a la escasa cuantía de su prestación, si se le concede dicha cantidad no podrá solicitar ningún extra. Si es adecuada o no la asignación dependerá de lo que fume. Lo que es caro es comprar a través del DEMANDADERO, el ECONOMATO no es caro. Hay productos como el café, que son más baratos. ··· Lo hablará con Cristina para que lo valore y me llame.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MORA'and apellido2='GARCIA MORA'),'2023-12-15','TERESA CORREO DE MARGARITA Buenos días Teresa, puedes avisarme cuando la cuenta este desbloqueada qué desde las 8:30 h tengo a José Luis revuelto q quiere ir al banco haber si su cuenta está ya bien. Yo llame a la interventora Antonia Horrillo para decirle que lo vais a desbloquear, pero no pude contactar con ella fue con otra chica que cogió el mensaje. Ayer tarde noche, tuve una reunión con Juan Carlos trabajador social y le puse al dia de nuestra conversación ,le pase su número de tlf, por si lo llamas y no coincides con él tienen ahora mucho jaleo en los colegios con charlas preventivas contra las drogas a los adolescentes . Crees q el informe que consta de dos hojas puede valerte para pasarle la revisión, tengo que hacerme del documento que dice q tiene cirrosis pero todavia no nos ha llegado la cita de Digestivo, y la pierna de una fractura tiene necrosis y cojea eso si puedo pedirlo a mis tias si lo necesitaras, o incluso hablar con el médico de familia ,si pudiera hacerle una exploración y hacer un informe porque las secuelas se ven a simple vista. Me vas asesorando y pidiendo la documentación que se necesite para qué José Luis pueda estar atendido lo mejor posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MORA'and apellido2='GARCIA MORA'),'2023-12-15','TERESA Buenos días Teresa, puedes avisarme cuando la cuenta este desbloqueada qué desde las 8:30 h tengo a José Luis revuelto q quiere ir al banco haber si su cuenta está ya bien. Yo llame a la interventora Antonia Horrillo para decirle que lo vais a desbloquear, pero no pude contactar con ella fue con otra chica que cogió el mensaje. Ayer tarde noche, tuve una reunión con Juan Carlos trabajador social y le puse al dia de nuestra conversación ,le pase su número de tlf, por si lo llamas y no coincides con él tienen ahora mucho jaleo en los colegios con charlas preventivas contra las drogas a los adolescentes . Crees q el informe que consta de dos hojas puede valerte para pasarle la revisión, tengo que hacerme del documento que dice q tiene cirrosis pero todavia no nos ha llegado la cita de Digestivo, y la pierna de una fractura tiene necrosis y cojea eso si puedo pedirlo a mis tias si lo necesitaras, o incluso hablar con el médico de familia ,si pudiera hacerle una exploración y hacer un informe porque las secuelas se ven a simple vista. Me vas asesorando y pidiendo la documentación que se necesite para qué José Luis pueda estar atendido lo mejor posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-12-15','Ana: Llamo a Mª José, actual responsable Res. Hervás (927 473 410): Las compañeras de la Secc. Ecca. me han confirmado que este mes no le han ingresado el subsidio. ·**El miércoles le acompañaron al SEXPE y al SEPE. Al parecer le habrán enviado notificación previa pero a la Res. de Cáceres. Tenía que acudir a justiciar que no tiene rentas. *Ya está todo arreglado. En enero le ingresarán las dos mensualidades, la de diciembre y enero. ············· El 19 de abril le corresponde la Renovación de la Demanda de Empleo. - Lo hace de forma anual. ············· El 18 de diciembre tiene que pedir cita en SEPE constatar que sigue sin percibir ningún tipo de ingreso. ········· También le acompañarán a modificar sus dirección para que reciba las notificaciones en el centro. ···························· En cuanto al empadronamiento le indico que puede ir también a empadronarse. Puesto que su curatela es de tipo ecca. no se requiere la firma de la Presidenta de CTAEx. ···································· Por otra parte me informan que fue a visitarla Clara, nueva Educadora de Futuex, estuvo reunida con la Enfermera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-12-15','miguel, recibo varios emails de Damian contradiciendose no que no quiere vender y finalmente sí. Dice en los emails que su prima le había convencido para no vender pero que sí quiere y que le retiremos la llave a la prima. Me envía email de una inmobiliaria de un primo: Este es su número y es de confianza se llama José María 625380980.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2023-12-15','Ana: correo pendiente del martes del E.S.M.- CC (equiposaludmental.caceres@salud-juntaex.es): "Adjunto remito informe de seguimiento del psiquiatra ENRIQUE GOENAGA PALANCARES con relación al paciente JESÚS ROMERO PÉREZ, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura, en virtud de Sentencia 225/2016 de 16 de mayo 2016" ······················ Guardo informe en el expte. digital. ····· En el mismo dice literalmente, a fecha de 2/01/2019, fecha en la que acudió acompañado de Teófilo, TS del CRPS, "Desde el punto de vista clínico el paciente se encuentra estable y asintomático. Por todo ello, acordamos, en el momento actual, que estaría indicado una revisión de la tutela hacia una curatela (económica y cuestiones de salud). En julio 2023: "Más activo, algo más despierto, más cansado... buena relación familiar con padre y hermano". ·········································································· *Reenvío informe a la secc. jurídica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2023-12-15','Amalia le han suspendido la PNC porque su Declaración Anual no se había entregado. La enviaron a la ultima dirección que tenían , de Ctro. Penitenciario en Madrid en lugar de a la dirección del Rpte. legal y por ahí se habrá extraviado .Ya está gestionado y empezará a percibir en febrero , con carácter retroactivo, todas las mensualidades que le correspondan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-12-15','miguel, me escribe el primo de Damian José María Gonzalez Ruíz >josemariagonzalezr@gmail.com>: Buenas tardes, soy José Maria González gerente/comercial de Ayala hogar inmobiliaria. Estaría interesado en la comercialización de la vivienda de Damian. Mi teléfono de contacto seria 952088959 y 625380980 c/ Salvador Noriega n°7, Málaga.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-12-15','Ana: Envío correo a Estrella Durán, TS UME - CSS Plas: "a requerimiento del Juzgado, necesitamos que nos hagas llegar, en cuanto te sea posible, INFORME SOCIAL de su “situación personal y asistencial “actual. Fecha y motivo de ingreso, actitudes y comportamientos, intervención que se está llevando a cabo y aquello que consideres. La petición la hacen en relación a escritos que han recibido de uno de los hermanos (Sé que la hermana también les ha escrito, nos lo envió ella y si no recuerdo mal te informé al respecto, pero de ella no nos han preguntado ni enviado nada aún). Tanto uno como otro solicitan que, por su propio bien y el de terceros, Enrique no vuelva a vivir sólo en su domicilio, sino en recurso residencial adecuado… por lo que entiendo sería conveniente expresar criterio técnico al respecto. Te envío adjuntos los documentos que nos han hecho llegar. A nuestro escrito, además de tu informe, adjuntaremos el Informe que en su día redactó la TS del Valdeobispo, escritos del Veterinario y solicitud de informes de actuaciones que remití a la Guardia Civil y de la que no he tenido respuesta." ········································································································································· Envío correo-respuesta a A. Jurídicos en relación a los requerimientos del Jdo: "En relación a ENRIQUE SANTOS GARCÍA PUENTE, en mi opinión, lo primero que hemos de aclarar al Juzgado, es que nosotros hemos empezado a intervenir una vez se ha remitido el Inventario al Juzgado, pues desconocíamos cuál era la situación hasta ese momento. El cargo se aceptó a fecha de 16/12/2022. De ahí para atrás este Gabinete Técnico desconoce los hechos acaecidos. Ahora: - He solicitado a Estrella Durán, TS C. Sociosanitario, Informe Social en que expresa la “situación personal y asistencial” actual de Enrique, dado que está ingresado en la Unidad de Media Estancia. Que por cierto me acaba de llamar y dice que ella no es la que debe redactar el Informe, que por lo que dice el requerimiento deberían ser o la Psiquiatra o la Psicóloga y que se lo va a pasar a ellas. - Adjunto: o Oficio-solicitud de Informe de Actuaciones que remitimos a la Guardia Civil, tal y como me indicaron que hiciera cuando hablé con ellos por teléfono y al que no han contestado. Se le puede decir al Jdo. que lo soliciten ellos directamente ya que no hemos tenido respuesta. o Correos remitido (y mi respuesta) por la TS de los Servicios Sociales de Atención Social Básica de Valdeobispo, remitido a petición del Ayto, en que narra una serie de incidencias y que nos dirigieron al Gabinete Técnico de la CTAEx y al Equipo de Salud Mental de Plasencia, del que Enrique es paciente, con carácter previo a su ingreso en la UHB y posteriormente en UME. o Informe Social de la TS de los Servicios Sociales de Atención Social Básica de Valdeobispo, donde también expresa la necesidad de ingreso en centro, de fecha 01/O9/2023. o Informe de Alta del Servicio de Psiquiatría – Unidad de Hospitalización Breve, y derivación al C. Sociosanitario a la Unidad de Media Estancia, de fecha 05/09/2023 o Correo y Acta de Inspección Veterinaria de CARLOS LOPEZ DE BERNARDI, Veterinario de Salud Pública del Centro de Salud Plasencia II (Sur) con incidencias acaecidas durante la visita."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2023-12-15','Ana: Envío correo-respuesta a S. Jurídica y pongo en copia a Julio: "La base de datos no está actualizada en este punto. Julio, creí habértelo dicho en su día, pero es posible que no… cuando puedas haz el cambio, porfa. JOSÉ MANUEL MORENO CARLOS reside desde el día 4/07/2023 en CENTRO RESIDENCIAL PARA MAYORES de la localidad de RIOLOBOS, provincia de Cáceres. Ya me decís si tengo que pedir Informe." ······························································································································································································ Ana: Envío correo a Ana Montaña Álamo, Residencia Riolobos (alamoseras@gmail.com): "¿Qué tal sigue Carlos? Entre cosa y cosa, este último mes ha sido una locura y no te he vuelto a preguntar ni llamé al hospital, no sé si le dieron el alta o continúa hospitalizado, ya me dices cuando puedas." ····················· Respuesta de Ana: "Hablé este lunes pasado con su Psiquiatra y que va lenta la estabilización."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2023-12-18','Ana: Reenvío a Alberto, Jefe Secc. Ecca., correo de Felisa Custodio, TS CAMF (trabajadora_social_alcuescar@imserso.es): "la residente tutelada me ha preguntado si sería posible aumentarle la asignación mensual de dinero de libre disposición. Hemos consultado la base de datos de la Seguridad Social y no aparece como deudora y el Administrador del CAMF me dice que está al día en los recibos. He consensuado con Carmen tener 50 euros de libre disposición, más los 20 euros del teléfono, en total 70 euros por estos gastos al mes. A ver que os parece." ····························································································································································································· Respuesta de Alberto: "ANA: VARIAS CUESTIONES: • TIENE UN SALDO PEQUEÑO, EN TORNO A LOS 2.500 € (ES CIERTO QUE HA PASADO X TRATAMIENTO DENTAL HACE POCO). • TIENE GASTOS NO CONTROLABLES X NOSOTROS, PERO SI CONTROLADOS X TUTELADA/CENTRO: FARMACIA.... • ES PROBABLE QUE EN ALGÚN MOMENTO APAREZCA ALGÚN EMBARGO...TENGO ANOTADO: MIGUEL NOS INDICA QUE HAY SENTENCIA X IMPAGO PLANETA AGOSTINI QUE POSIBLEMENTE DE LUGAR A EMBARGO X 809,20 € • PODEMOS SUBIR ESA ASIGNACIÓN A LOS 70 €/MES Y DENTRO DE 1 AÑO, LO REVISAMOS. ESTRELLA: MODIFICAMOS REINTEGRO PERMANENTE QUE PASA A 70 €/MES (ANTERIOR 30 €/MES. ESTRELLA: EL SEGURO DECESO OCASO ES MUY CARO...34,35 €/MES...CUAL ES EL MOTIVO???" ······················ Informo de la subida con condición de revisión anual a Felisa Custodio, TS CAMF.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AVILA'and apellido2='RAMOS'),'2023-12-15','Ana: Teresa me pasa para seguimiento el EXPTE. Fco. reside en la RESIDENCIA DE MAYORES DE SANTA ANA, localidad de Santa Ana (CC). Paloma es la Directora (menapaloma@gmail.com). ················· Fco. tiene 67 años. Percibe una pensión de JUBILACION PROCEDENTE DE IPA = 943,01 €. ············· No está valorado por discapacidad ni por dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2023-12-18','Ana: correo-respuesta de Ángel Luis Blanco, Psiquiatra UHB-Plas (angeluis.blanco@salud-juntaex.es): "Ya lo reboté a la inspección Médica. Hoy se va de alta la paciente a su residencia"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-12-18','Ana: Correo de Sara Gía, TS Banium Residencial (TrabajadoraSocialBanium@hotmail.com) "Te adjunto la resolución de grado III de dependencia de Concepción Barbero Sánchez. A su vez, informar que se le ha solicitado acompañamiento para la consulta médica que tiene mañana programada a las 11:30. No sabemos la exactitud del importe, pero los últimos acompañamientos han sido alrededor de 60€. Pongo en copia a comisión para que puedan prever el coste."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-12-13','Ana: Correo de Gema Morato, Directora Res. Grupo Asoma (gemamg.asoma@gmail.com): "Adjunto remito informe médico de consulta de oftalmología de Julián Ramón de ayer. Tiene catarata y tiene que operarse"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2023-12-18','Ana: María, Secc. Ecca., me comunica que le ha llamado Ana, la otra hermana de Valentina, que lo han pensado bien y no quieren que se les haga la transferencia periódica de los 20€ para contribuir al gasto de traslado para visitar a su Conchi.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2023-12-18','Ana: María, Secc. Ecca., me comunica que le ha llamado Ana (630 346 052), la otra hermana de Conchi, que lo han pensado bien y no quieren que se les haga la transferencia periódica de los 20€ para contribuir al gasto de traslado para visitar a su Conchi, dice que ya se apañarán para asumir el gasto. La insistencia venía por parte de Maribel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2023-12-18','Ana: Reenvío a Alberto, Jefe S. Ecca., correo de Mª Piedad Tapia, Titular de la Academia de Oposiciones Hélade (academiahelade@gmail.com), con presupuesto para Sandra. "Conforme a lo solicitado, se adjunta en formato pdf y firmado digitalmente, informe sobre coste mensual de la preparación en la Academia HÈLADE de las oposiciones de acceso al Cuerpo de Gestión Procesal y Administrativa de la Administración de Justicia por parte de doña Sandra Sandín Hernández, con indicación del tiempo aproximado de preparación. Se indica que, como se hace constar en el informa, el temario para la preparación, en el caso concreto de Sandra, le sería entregado gratuitamente, asumiendo la Academia su coste. Para la inscripción en el centro, de estar finalmente interesada, basta con remitir, rellenada y firmada digitalmente (o manualmente y escaneada, en su caso), la FICHA DE INSCRIPCIÓN QUE SE ADJUNTA -en formato pdf y word-, señalando en tal caso como fecha de incorporación el día 1 del mes siguiente a la remisión de la Ficha. No se olviden de firmar, en tal caso, en el reverso de la Ficha de Inscripción, en los dos espacios destinados al efecto, por ser necesario conforme a la normativa de Protección de datos personales." ································· Por mi parte ok. Sandra no tiene apenas gastos y puede ser una gran oportunidad para ella. ····························································································································································································· Cumplimento y subo al portafirmas la FICHA DE INSCRIPCIÓN. ······························································································································································································· Envío correo a Toni-Futuex: "En relación a SANDRA SANDÍN HERNÁNDEZ, no sé si la habéis visitado ya desde que se haya retomado el programa. Pero por si no es así, os actualizo un poco la situación: - Finalizó la carrera de Derecho - Se le ha solicitado BECA de la ONCE para opositar, pero lo más seguro es que no se la concedan, pues no tiene apenas puntos para ello. - Igualmente, acabo de pasar presupuesto de la Academia de Oposiciones HÉLADE, que creo no habrá problemas para aprobar, es una muy buena oportunidad para ella. - Diana, Trabajadora Social del Servicio de Atención al Estudiante de la UEx, le está apoyando en todas estas cuestiones, te paso su número por si os fuera necesario: 618 381 887 Consideramos sería positivo le hagáis visitas, con mayor periodicidad que antes y le apoyéis en esta nueva etapa como opositora que comenzará a principios del mes que viene (enero de 2024)." ·································································································································································································· Respuesta de Alberto: "ANA: OK A PPTO PREPARACIÓN OPOSICIONES 105 €/MES (DURANTE 28 MESES APROX). IMPORTANTE: SI HAY CUESTIONES SOBREVENIDAS DE IMPORTANCIA ECONÓMICA RELEVANTE HABRÍA QUE REVISAR ESTO...MOTIVO: SÓLO TIENE UNA PRXHCARGO. ANA: QUE TUTELADA/PADRE NOS INFORMEN SI DEJA DE ASISTIR A ACADEMIA. ESTRELLA: GESTIONAMOS PAGO DE ACADEMIA COMO NOS INDIQUE ANA (CON LÍMITE 105 €/MES)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-12-18','Ana: Toni-Futuex, me comunica que Manuel ingresó la semana pasada en La Comunidad Terapéutica La Garrovilla en Mérida. No está segura si fue el jueves 14 o el viernes 15.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-12-18','Ana: Envío correo a María Barroso, CRR Olivenza:(MBARROSO@caseresidencial.es) y (MSERVAN@caseresidencial.es): "Sólo quería preguntaros qué tal está Ceferino, cómo se está adaptando al recurso y al nuevo entorno. Ya me decís cuando podáis." ································································· Respuesta de María Barroso: "A día de hoy Cefe se está adaptando bien. Va vinculando con algunos compañeros nuevos y retomando vínculos con algunos conocidos. El contacto con los profesionales es adecuado y respetuoso. No está presentando excesivas demandas con temas económicos y se está ajustando bien a las asignaciones de tabaco y dinero que traía establecidas de Plasencia. Está participando en las sesiones que le establecemos los profesionales, no tanto en la asistencia a programas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='TARANGO'and apellido2='DOMINGO'),'2023-12-18','Ana: Recibimos Cdo. actualizado de PFHC solicitado previamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-12-18','Ana: Correo-respuesta de Gema Morato: "En cuanto a la forma de enviar dinero para Victor es complicada las dos opciones, la primera porque no puedo facilitar un número de cuenta para hacer la transferencia y la segunda con la autorización bancaria también es complicada porque Victor está fisicamente y psicológicamente muy dependiente, anteriormente realizaban el envío de dinero mediante giro postal. Victor Manuel es complicado hacerle un presupuesto porque no todos los meses tiene los mismos gastos, por ejemplo de farmacia no todos los meses paga lo mismo, hay meses que tiene podología y peluquería, los acompañamientos a Cáceres cuando va a consulta, incluyendo todo podria gastar unos 250-300 euros al mes, esa sería la cantidad mensual." ··········································· Llamo a Gema (639 694 905 // fijo de la residencia: 927 590 145): Han tenido que llevar a Víctor al Hospital de CC. No sabe si lo van a dejar ingresado. ················· Van a necesitar un cinturón de sujeción, pues se mueve mucho y hay riesgo de caída. Pedirán presupuesto y factura a la ortopedia. *Se abonará mediante transferencia. ······························· *Aún no se ha abonado el acompañamiento (hace más de un mes). María Secc. Ecca. se encargará. ·························· *Mañana enviarán la declaración Jurada del acompañamiento de hoy al hospital. ················· También enviarán factura del taxi. ···························· Puesto que necesita ropa, intentarán comprarla en la tienda de Valencia de Alcántara (lugar más cercano) y enviarán factura para abono mediante transferencia. ··························· Para gastos de bolsillo enviarán correo al ctutelar, dada el estado de salud de Víctor y la imposibilidad de que él acuda al banco, indicarán datos de trabajadoras del centro para que excepcionalmente puedan retirarlo sin que él acuda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-12-18','Ana: A instancia de Estrella, Secc. Ecca, llamo a Carlos. No sabe el nº de cuenta para domiciliar la cuota mensual de la comunidad de vecinos. Tampoco sabe si el agua lo abonan de forma conjunta en la comunidad. Ni si el IBI lo abonaba su padre. Intentará averiguarlo todo. Le explico que pediré el apoyo de Mamen, nueva educadora de Futuex para estas gestiones. ························· Hablo con sus vecinas Isabel y Carmen, quienes le ayudan en todo lo que pueden.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-12-18','Ana: Correo de Raúl Gil, Subdirector de Régimen, de C. Penitenciario de Ba (SubRegimen.Badajoz@dgip.mir.es / 924 28 91 05 ): "En relación a su curatelado Miguel Ángel Ramos Andrés, le informo que ha ingresado el martes 12 de diciembre, a disposición del Juzgado de Instrucción Nº 4 de Badajoz, en virtud de las Diligencias Previas 2162/2023 por un presunto delito de Homicidio en grado de tentativa. A este respecto tiene prevista una comparecencia por el sistema de Videoconferencia el próximo 26 de diciembre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2023-12-19','Ana: correo de Ángela Bueno, Directora Asuntos Sociales - PLACEAT (directora@placeat.org): "acaba de contactar con nosotros la familia de la pareja de María, para solicitar autorización para llevarse a María a pasar las vacaciones de Navidad con ellos. Habitualmente así lo hacen tanto en verano como en Navidad. Se la llevan a la localidad de Hervás para pasar las fiestas en familia. La recogerían el domingo 24 y la traerían al centro el día 6 de enero."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2023-12-19','Ana: Contactos de Sandra: 600 721 776 y el de su padre (Alejandro) 648 217 116.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-12-19','Ana: Envío correo a Toni-Futuex: "creo que no te dije que a CARLOS GONZÁLEZ LEO, le hicieron seguimiento y visitas varias desde el IMAS por los servicios de SAD y Cáterin asociado al primero, y resolvieron darle de baja en ambos por no estar cumpliendo las normas de funcionamiento de los mismos. A veces tiraba la comida (comprobado por la auxiliar), otras veces decía él que se llevaba la comida a casa de la pareja y además en casa no estaba, había indicios de no estar residiendo en la casa y él confirmó que era así. Finalmente le dieron de baja. Para el próximo año podría solicitarse de nuevo. Por otra parte, ayer hablé con él, Mamen va a tener que tener mucha paciencia y tacto, algo que había hablado con los vecinos le había descolocado, pues decía que la había bloqueado en su móvil y que no quería saber nada más de ella. Finalmente, tras la conversación, parece que entró en razón y dijo que la desbloqueaba. Acordamos de hecho que os pediría que le acompañe Mamen a varias cuestiones: - A hacer una buena compra de alimentos para estas fechas (se le han autorizado 225 € que podrá retirar desde hoy hasta el día 29) - Al OAR para averiguar cómo se ha estado abonando el IBI de aquí para atrás, él no sabe decirnos, y que les faciliten lo necesario para domiciliar el pago en la nueva cuenta bancaria (enviádnoslo en cuanto podáis, porfa) - Puesto que ha habido dificultades con la entidad bancaria en la que estaba, se le han domiciliado en la nueva varias cosas (electricidad y seguros entre ellas), pero necesitamos averiguar el nº de cuenta de la COMUNIDA DE VECINOS para domiciliar la cuota también y averiguar si la factura del agua está incluida en esta cuota de comunidad. Sino, también necesitamos información para domiciliar los recibos del agua. - Solicitud de presupuestos de Cáterin para contratación de COMIDA Y CENA a partir de enero (en esto no sé si volverá a cambiar de idea, pues ya le expliqué que en tal caso habría que bajarle la asignación y él aceptaba, veremos) Tenemos muchas dudas sobre el funcionamiento de Carlos, así que, por favor, en la medida de lo posible INTENSIFICAD EL SEGUMIENTO. No sabemos si todo lo que dice es verdad y cambia mucho su discurso… Me temo que no va a ser sencilla la intervención con él."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-12-19','Ana: Correo de IBERDROLA (prejub@iberdrola.es): "Una vez acreditada la curatela de D. Victor Manuel Blanco Poveda, le confirmamos que, a partir de ahora, nos dirigiremos directamente a ustedes como contacto del Sr. Blanco Poveda en la dirección que nos informan. En cuanto a su solicitud, adjuntamos copia del contrato de prejubilación firmado del Sr. Blanco Poveda así como de la Resolución sobre alta en Convenio Especial que nos hizo llegar en su día. En cuanto a la copia del Convenio Especial, le informamos que es un Convenio suscrito directamente por D. Victor Manuel Blanco Poveda con la Seguridad Social por lo que deberán dirigirse a dicho Ente para obtener mayor documentación. Asimismo, les confirmamos que procedemos a tramitar el cambio de domiciliación bancaria según nos solicitaron en correo adjunto. Contraseña en correo aparte." ············ "Contraseña: POVEDA2023" ························ Reenvío a Alberto y guardo documentos y correo en su expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-12-19','TERESA Lleva un par de semanas bien, estable, tranquila, más participativa en las actividades que se le proponen como por ejemplo la hipoterapia. Continua con sus llamadas semanales a la familia y ha tenido visita familiar por petición de Reme a la madre y tías , aquí en Zafra, durante el puente…ha respondido bien y no ha habido ningún “sobresalto” como podíamos “temer” dadas las conductas de las semana anteriores y el impacto emocional que en ella supone ese contacto. Empieza a manifestar su inquietud por las navidades y su deseo de estar con la familia. La familia, en la llamada con ella de la semana pasada, recibe esta demanda de Reme y empiezan a valorar la posibilidad de que si sigue así, podría ir a casa a pasar algún día con su correspondiente noche sin concretar nada más y así se lo dicen a ella. Ante esta posibilidad, los psicólogos que están en la llamada apoyando a Reme, les orientan acerca de esa posible visita al domicilio, que: -Se os informaría y se pediría consentimiento por vuestra parte -Que en caso afirmativo, se recomienda la eliminación total de objetos y otros estímulos en la estancia donde pasa la noche. -Acompañamiento por una persona durante toda la noche -Acompañamiento al WC durante el día y la noche -Retirada de cualquier objeto susceptible de ingesta de su alcance, en la casa -Mucha supervisión durante el día Acuerdan valorarlo en familia y darnos una propuesta para valoración conjunta por vuestra parte. Valorada por nuestra parte esta petición de Reme, y tras la llamada de Bele, la tía de Reme, en el día de hoy, para solicitar autorización para pasar la Nochebuena allí y volver el día de Navidad, valoramos que el objetivo de esta salida podría ser que La satisfacción de demandas y de necesidades emocionales, expresadas explícitamente por Reme, podrían actuar como prevención de ingestas en la entidad, por evitación de sentimientos frustrados. Aquí te dejo por hoy esta propuesta, que sabemos que hay que reposar…y hablamos tranquilamente sobre ella, teniendo en cuenta también la evolución de Reme en estos días. SE AUTORIZA LA SALIDA CON LA FAMILIA PARA LAS FIESTAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='HERRERO'and apellido2='GARCIA'),'2023-12-19','Ana: Correo de Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com): "...Aprovecho para solicitar dinero para los gastos personales de Joaquín (peluquería, cafés, podología,etc.) 300 €." ···························· *Se autorizan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2023-12-19','Ana: Correo de Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com): "Adjunto Ausencia voluntaria para firmar para que Mª Antonia Bravo Patilla pueda disfrutar de unos días en familia en su domicilio familiar. Se irá con su hermano José Manuel como todos los años. La salida es del 24 al 31 de diciembre. Solicito 100 € para su viaje y 200 € para sus gastos personales (peluquería, podología, esteticien, etc.). Solicito 300 € ingresados en la cuenta habitual." ············ Se autoriza el gasto. ······························· Cumplimento y subo al portafirmas el documento de Ausencia Voluntaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-12-20','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Comunicar el ingreso en la UHB de Cáceres de la persona usuaria Consuelo Nevado Pacheco por reagudización de la sintomatología de su patología de base, a fecha viernes 15 de Diciembre de 2023."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-12-18','Ana: Correo de Estrella Durán, TS UME-CSS Plas: "...comunicar que le vamos a pedir un CRR por emergencia social a Gudalupe" ··········· Pregunto a Estrella si ya acepta este ingreso: ············ Su respuesta: "A ver ella no ha aceptado, pero creo que lo va a hacer. Yo cuando se lo propuse no dijo que no, y cuando vea que es CRR o es permanecer aquí, yo creo que lo aceptará...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-12-19','miguel, ya he enviado la autorización, encargo a la arquitecta vecina, y presupuesto del albañil firmados.Quedo pendiente de que la arquitecta vise el proyecto y obtenga las licencias necesarias para comenzar la obra. Me irá avisando de los importes a ir desembolsando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2023-12-19','miguel, tras más de 2 meses sin noticias del abogado y la procuradora, enviamos a ICABA (Coleg Abogados Badajoz) solicitud de intervención para intermedien en la resolución del seguro de responsabilidad civil, abran expte disciplinario si fuese preciso al abogado Jorge Calvo, intercedan en los honorarios que emita y nos remita la documentación obrante del procedimiento del laudo y las dos ejecuciones. Dependiendo del resultado pondremos la misma queja o no ante el Colegio de Procuradores contra Cristina Soto, la cual no nos remitió nada acerca del desistimiento, ni cumplió en tiempo y forma lo que se le solicitó','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2023-12-19','Ana: Envío correo a Lola, TS Plena Inclusión Cabeza del Buey (directorarail@plenainclusioncabezadelbuey.org): "¿Qué tal sigue Ana María? Ya sé que hablaste con Estrella, compañera del Casar de Cáceres, no sé si finalmente se podrá organizar una visita de ida y vuelta para pasar un día con su familia en estas fechas. Lo hablamos si quieres mañana con calma, que ahora no dejan de entrar llamadas y tengo que terminar otras cosas. Por otra parte, la compañera que realiza el INVENTARIO para enviarlo al JUZGADO está pendiente de recibir el INFORME SOCIAL que se os solicitó de oficio, para poder terminarlo y enviarlo. Agradecería nos lo hicierais llegar a la mayor brevedad. Adjunto el oficio que se envió en su día. Gracias de antemano y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2023-12-19','Ana: Correo de Estrella Durán, TS UME-CSS Plas (estrella.duranc@salud-juntaex.es): "le habéis pedido a Guadalupe un complemento a su PNC, ya que veo que tiene un 75% de discapacidad." ····················· Mi respuesta: "No se lo he pedido porque la valoraron de DEPENDENCIA y dio “SIN GRADO” hace justo un año, a fecha de 23/12/2022."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2023-12-19','Ana: Ana Benavente, TS ESM, me informa que las plazas de la Res. de Jaraíz son de válidos. Aún no tienen plazas por Dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='ESTEBAN'and apellido2='CORRAL'),'2023-12-19','TERESA RECIBO LLAMADA DE LA TS ME COMUNCIA QUE HA FALLECIDO EL PADRE CON LO CUAL PODEMOS SOLICITAR ORFANDAD TAMBIEN ME COMENTA QUE TIENE SOSOPECHA DE QEU UNA EXCULADA QUEIRE SOLICITAR LA REMOCION DE LA TUTELA Y EL PADRE QUEDO DICHO QUE NO QUERIA QUE NADIE FUER TUTOR DE JUAN PABLO PUES NO HAY BUENA RELACION SE SOSPECHA QUE PUEDE HABER INTERES ECONOMICO YA QUE NUNCA SE HAN PRECOUPADO POR JUNA PABLO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2023-12-20','Ana: Envío correo a Cristina, Ed. Vera (educadorasocial@asociacionvera.com): "Adjunto el documento de Ausencia Voluntaria firmado digitalmente por la Presidenta de la CTAEx."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2023-12-20','Ana: Envío a Mª Piedad Tapia Madrigual, Academia HÉLADE (academiahelade@gmail.com): "Adjunto ficha de inscripción para la preparación en la Academia HÈLADE de las oposiciones de acceso al Cuerpo de Gestión Procesal y Administrativa de la Administración de Justicia por parte de doña Sandra Sandín Hernández, firmado digitalmente por la Presidenta de la Comisión Tutelar de Adultos. Del abono se encargarán mis compañeras de la sección económica, mediante transferencia mensual al número de cuenta bancaria indicado en el presupuesto. Ante cualquier cuestión, no dude contactar." ··········································································· Envío a Estrella, Secc. Ecca.: "Como puedes ver en el documento adjunto (que también adjuntaba Alberto: “El pago de las clases se efectuará, con carácter mensual, mediante el ingreso en la cuenta bancaria con IBAN ES33.2100.3850.7713.0041.6473”, de CAIXABANK. Habrá que hacer transferencia periódica mensual a primeros de cada mes a partir de enero de 2024." ········································································ Envío correo a Toni-Futuex con copia a Diana, TS UEX: "comunicarte que se ha aprobado el presupuesto para que pueda acudir a la Academia HÈLADE a preparar las oposiciones de acceso al Cuerpo de Gestión Procesal y Administrativa de la Administración de Justicia. Será formación online a partir de enero. Tendrá una duración aproximada de 28 meses. Ya he remitido a la academia la ficha de inscripción firmada por la Presidenta de la CTAEx. Por favor, que la Educadora asignada para el apoyo y seguimiento, se lo comunique y, tal y como hablamos, e indiqué en correo anterior, que esté pendiente y la apoye también en este aspecto tan relevante para ella. Pongo en copia a Diana, TS de la UEx, precursora de este proyecto vital de Sandra, quién ha estado y está muy implicada en su apoyo académico y futuro laboral."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2023-12-15','Ana: Correo-respuesta de Alberto, jefe secc. ecca: "ANA: TEMA BANCO SANTANDER...IMPOSIBLE COMPROMETERNOS PARA CUALQUIER OPERACIÓN CON ESA ENTIDAD..."ADEMÁS" TENEMOS PENDIENTE ACUDIR A OFICINA CON "LA JEFA" (y esto tb puede tardar)...DE TODAS FORMAS LO VAMOS A INTENTAR...TE VAMOS DICIENDO. YA TENEMOS UNICAJA + TU YA HAS PEIDO PN INVALIDEZ NO CONTRIBUTIVA...EN CUANTO COMIENCE COBRO, ICIAR HABLA CON CENTRO PARA QUE CARGEN COSTE Y, EN LA MEDIDA DE LO POSIBLE, CANCELEMOS LAS DEUDAS QUE STÁ GENERANDO. ESA VISITA, QUE ES LO URGENTE, NO PUEDO DAR UNA SOLUCIÓN A COMO ABONARLA...A DÍA DE HOY...LO QUE SI PODEMOS ES COMPROMETERNOS CON CENTRO A ABONARLA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-12-20','Ana: Llamada de Felisi (614 361 144): vuelve a desahogarse por si situación. Mañana su hijo acudirá a la cita en el Jdo. ···· Está muy contenta con Nieves, la nueva educadora de Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-12-20','Ana: Llamada de José Manuel, está en el autobús de camino a Badajoz que va a pasar el día. ······ Quiere pedir un aire acondicionado y va a pedir y enviar presupuestos, le digo que se espere por lo menos hasta marzo o abril. Y ya sabe que se tiene que autorizar por el Jefe de Secc. Ecca. ····································· Envío correo a Toni-Futuex, pidiendo que la Educadora le acompañe a la cita en Neurología el día 22/12/23.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-12-20','miguel, llega email de la notaria de los Santos de Maimona (Nacho)jaduro@despacho.notariado.org Buenos días, Miguel. Adjunto Copia Simple de la escritura de Compraventa firmada ayer, día 19 de diciembre de 2023, con el número 984 de Protocolo, para su ratificación por parte de la Comisión Tutelar de Adultos. Te recuerdo que las otras dos escrituras de Compraventa de María Isabel Moreno Follarat, de fechas 9 de mayo y 10 de octubre de 2023, respectivamente, se encuentran aún pendientes de ratificación. Debido al tiempo ya transcurrido, los otorgantes las escrituras están ya muy impacientes pues no pueden inscribirlas en el Registro de la Propiedad mientras no estén ratificadas. Por todo ello rogamos agilices al máximo los trámites. ------------------------------------------------------------ Mi contestación: Buenos días, gracias Nacho. Seguimos insistiendo al juzgado para que inste al registro civil a inscribir nuestro cargo para que el notario de Mérida, Don Gonzalo Fdez Pugnaire nos autorice a ratificar todas las escrituras. --------------------------------------------------------- Envío email a Inés con copia a Angel: Buenos días Inés, deja pedido antes de irte porfa de nuevo a los juzgados para que insten a los registros civiles inscriban nuestro cargo. Han vuelto a firmar otra venta de Isabel Moreno Follarat…Ya no sé ni cuántas escrituras tendré que ratificar…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2023-12-20','Ana: Tras llamada de Jesús, pareja de Pilar (641 09 29 14), preocupado, envío correo a Alberto, Icíar, Ángel y Miguel - CTAEx: "¿es posible RECORDAR AL BANCO la situación de esta señora a cargo de la CTAEx, la limitación de su cuenta bancaria y que sus FAMILIARES NO DEBERÍAN PODER SACAR dinero por ningún medio sin la autorización de este Gabinete Técnico?? **NO puede volver a pasar lo del mes pasado, que aun habiendo enviado los escritos a banco y habiendo hablado Icíar por teléfono, la hermana sacó la paga del mes y la extra… por favor, si es posible llamar o escribir o lo que sea necesario al banco para que no vuelva a ocurrir. Miguel y Ángel: ¿sería posible enviar comunicado al Juzgado de este incidente? Desde que hemos dado con Pilar y hemos empezado a intervenir en los dos meses consecutivos la madre y hermana le han dejado sin dinero, como ya venían haciendo al parecer con anterioridad." ······························································································································································································ Correo-respuesta de Alberto: "ICIAR: MAÑANA LO VEMOS DE NUEVO...Y LO VE MIGUEL CON NOSOTROS. MIGUEL: SE SOLICITÓ BAJA MADRE COMO AUTORIZADA...X LO TANTO YA NO ES UNA CUESTIÓN ÉTICA, SINO LEGAL."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2023-12-20','Ana: Llamo al CRPS de Cáceres (927 23 21 06): el actual TS es Jorge Rojo y la Coordinadora es Ana Belén Roncero. Ninguno de los dos se encuentra hoy. ························','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2023-12-20','Ana: Llamo al CRPS de Cáceres (927 23 21 06): el actual TS es Jorge Rojo y la Coordinadora es Ana Belén Roncero. Ninguno de los dos se encuentra hoy. ························ Llamo a Jesús (633 447 172): comienza a divagar sobre su situación actual, su medicación, gestiones, "errores" económicos, su vida ordenada, hábitos saludables, las conferencias que da y los libros que escribe, sus apoyos incondicionales (amigos), etc... ····· Me facilita contactos de sus hermanos: Julián Romero Pérez, residente en la localidad e Plasencia: 611 08 85 41 y Zacarías Romero Pérez, residente en Salamanca: 629 80 95 80. ··· *Con su padre ha vuelto a distanciarse un poco, es un señor mayor que reside en una Residencia de Mayores de Talavera de la Reina, con carácter recio y complicado. ·········································································································································· Tras llamar a los hermanos, envío correo respuesta a Miguel con copia a Ángel e Inés - S. Jurídica: "Jesús Romero Pérez continúa residiendo en la C/ Godoy 4, 3º A de Cáceres. Estos son los datos de sus familiares directos: - Padre: D. Zacarías Romero Chamorro. En la actualidad reside en una residencia de mayores de Mayores de Talavera de la Reina. Ya es mayor, presenta carácter recio y complicado y a penas mantienen relación en la actualidad. - Hermanos: o D. Julián Romero Pérez  DNI: 11783612E  Fecha y lugar de Nacimiento: 1/11/1976 - Plasencia  Domicilio: C/ San Ginés, 2, 4º D. Talavera de la Reina.  Teléfono: 611 08 85 41 o D. Zacarías Romero Pérez  DNI:  Fecha:  Domicilio: - Salamanca  Teléfono: 629 80 95 80 Con Zacarías no he logrado contactar. Puedo volver a intentarlo mañana y sino intentarlo vosotros si queréis. Porque con Jesús también he hablado y no sabe decirme ni siquiera el domicilio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2023-12-20','Ana: Llamada de Raquel, TS del SSASB de Guadalupe (605 429 865) me pasa con Juan, quien solicita extra para navidades. *A parte de esto dice que la medicación le agota. ···························· Envío correo a la secc. ecca.: "Juan Chamorro Holguín solicita extra para las Navidades. Por mi parte se le puede aprobar la misma cuantía que el año pasado. Si fuera posible para este viernes, fantástico, sino para que los retire el martes que viene junto con su asignación semanal periódica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2023-12-19','Buenos días, Amalia. Os comunicamos que José María Vicho Alfonso ha sido trasladado al Hospital Psiquiátrico Penitenciario de Sevilla, ayer día 19 por la tarde. No mandéis más transferencias a nuestro centro y lo que tuviera en peculio lo mandamos nosotros a Sevilla. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2023-12-20','Ana: Correo de Camen Vega, Res. Banium Residencial (residencialbanium@villatermal.com): "queríamos comunicar que Concepción Barbero Sánchez tiene consulta de revisión Traumatología en Plasencia el día 29 de Diciembre y cómo necesita acompañamiento, solicitamos que nos den el visto bueno para llamar a dicho servicio para ese día. Sin otro particular, reciban un cordial saludo. Carmen Vega" ······························ Pido a Lourdes, S. Ecca. que compruebe si es viable y le confirme directamente a Carmen. ········································· Respuesta de Lourdes al centro: "Buenos días, entendemos que el acompañamiento será sobre unos 60€???? Si es así, si puede asumir este gasto, enviad acompañamiento una vez realizado el servicio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-12-21','Ana: Correo de Toni-Futuex: "...Por cierto Carlos Gonzalez Leo, sigue un poco enfurruñado y no coje el teléfono a la compi... sabemos que es un casa difícil, seguro que se le termina pasando.. porque en realidad la compañera no hizo nada, fue una dependienta de una tienda de confianza para el, que la interpeló y le quiso comentar algo en privado (preguntar si se toma la medicación porque lo nota alterado) y Carlos lo asumió como una falta de confianza, pero en lugar de enfadarse con la dependienta la tomó con la compañera.. en fin, esto es asi aveces. Tranquilidad y paciencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-12-18','Ana: Reenvío a Alberto correo de Ana Benavente (anamaria.benavente@salud-juntaex.es): "Estoy con Carmen Solana en la consulta. Refiere que su madre y su hijo necesitan algo extra de dinero, aunque fueran cincuenta euros para cada uno. La madre para comprar ropa y su hijo para desplazarse a casa de la abuela, que vive en Móstoles y para el regreso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2023-12-21','-Amalia : Quedo pendiente de la decisión que se tome desde menores . Si deciden que tiene que abandonar la plaza en HOFA pediré que nos lo den por escrito para utilizar el mismo para justificar la solicitud de plaza por emergencia social . Necesitaremos tb algún informe de HOFA , se pide que sea de SSASB pero en este caso no tiene sentido , no es usuaria de SS.SS. La solicitud de centro la tengo firmada desde el 1 de Noviembre en su expediente a la espera de la respuesta final de menores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2023-12-21','Ana: En relación a la petición de Carmen de dinero para su hijo y su madre, finalmente se aprueban 75€ para cada uno. ······· Estrella Secc. Ecca. se encarga de la gestión. ··········· Informo a Ana Benavente (anamaria.benavente@salud-juntaex.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2023-12-21','-Amalia : contacto con ASINDE para ampliar el contrato para el mes que viene a 37 horas por un copago de 320€ al mes y por Dependencia tendria PVSAD por unos 220€ . Pido el contrato para entregarlo junto al PIA y el resto de documentación y enviarlo a Dependencia Zafra .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2023-12-21','Ana: Correo de Res. Padre Damián - Plasenzuela (residenciaplasenzuela21@gmail.com) al ctutelar@: "Se procede a reenviar correo electrónico, enviado al Juzgado de Primera Instancia e Instrucción nº. 1 de Trujillo, para informar sobre Doña Rosa Marín Laureano (DNI: 00.066.159-B), residente que está tutelada por la Comisión Tutelar de Adultos." ··············· Guardo informe en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2023-12-20','Ana: Correo de Aurora Balaguer, Aux. Adtva. ESM-CC (aurora.balaguer@salud-juntaex.es): "Adjunto remito informe de la psiquiatra CRISTINA DONOSO JIMÉNEZ de 14/12/23, con relación al paciente CARLOS GONZÁLEZ LEO cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura en virtud de Auto 15/2023, de 3 marzo de 2023." ··················· Guardo en el expte. digital. ················· Al final del mismo se indica: "En estos momentos no toma tratamiento farmacológico y se muestra reticente a reiniciarlo. Dada la ausencia de psicopatología grave aguda, acordamos pautar medicación de rescate en caso de crisis y mantener seguimiento." ··· "Si ansiedad/inquietud importante/ insomnio: 1 comprimido Olanzapina 10 mg" ···· "Próxima cita de revisión en 2-3 meses"','2');
