insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2023-12-21','-Amalia : Desde el CSS registran la PFHC como guardadores no somos aun curadores . Registro Electrónico General Estimado/a Sr./Sra. JOAQUÍN MONTAÑO Su solicitud de registro con número de registro REGAGE23e00086222366 presentada por MARIA DE LOS ANGELES GALINDO a fecha 20/12/2023 09:14:15, ha pasado a ser tramitada por la oficina de registro Registro de la Dirección Provincial del Inss de Badajoz a fecha 20/12/2023 16:31:40.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2023-12-21','Ana: En relación al corro de Telesforo Merino, Preparador Academia HÈLADE, respondo: "Antes de nada, darte la gracias por la implicación en el caso de Sandra, es una gran oportunidad para ella. En cuanto al usuario y contraseña al Aula Virtual, si no os importa, tenéis que enviarlo todo de nuevo a la propia Sandra, para que pueda conectarse y tener acceso a todo. Ten en cuenta que el cargo que ejerce la CTAEx, es una Curatela de tipo ADMISTRATIVO y, sólo para las cuestiones económicas (de ahí que hubiera que autorizarse desde este Gabinete Técnico) y para gestiones puntuales/trascendentes. Por lo demás Sandra tiene capacidad para ello. No obstante recibe seguimiento y apoyo de una educadora que le visita periódicamente. Te proporciono el correo de Sandra: sandrasandin1993@gmail.com . En la ficha si no me equivoco, aparece su número, no obstante, te lo anoto también: 600 721 776 Y en cuanto a la autorización para el grupo de WhatsApp, de acuerdo a la normativa vigente, y dado el tipo de Curatela, es ella misma la que debe dar la autorización. Acabo de hablar con ella y le he dicho que le enviareis todo a su corre electrónico y también os había facilitado su número. Pongo en copia a Diana, para que esté al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-12-21','Ana: Carolina, Directora CRR-Plasencia, comunica a Lourdes, Secc. Ecca.: "Finalmente, no se realizará la salida del centro, tras no cumplir con las normas del Centro, (INGESTA …) No obstante, su madre ira a pasar el día con ella el 29 de diciembre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2023-12-21','Amalia : escribo a Reme : Buenas Reme , qué tal ? hablé hace unos días con Bartolomé , me dijo que quería ingresar en Residencia de Mayores , me sorprendió bastante. Te ha comentado algo ? No he querido mover nada al respeco porque puede ser una idea fugaz. Me llamó cuando estaba sólo , le pregunté si Alonso seguía viviendo con él y me dijo que sí ,pero que ahora pasaba más tiempo fuera y que había cosas que no le gustaban . Vamos hablando , si se consiguiera ingresar sería la respuesta más idónea a sus necesidades . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-12-21','TERESA Teresa…ya hemos hablado hoy con la enfermera de salud mental al respecto de este asunto. Nos dice que Leticia, psiquiatra de Reme no vuelve a estará disponible hasta la semana del 8 de enero y que durante esta semana podemos ir sin cita a exponerle el caso de nuevo y hacerle la petición de traslado de Reme a UDHAC, no obstante dicen que suelen comunicarse con frecuencia con Soraya y no les ha dicho ella nada al respecto. Si ella pudiera decirlo también, creo que sería beneficioso. Por cierto, mañana ya no estaré por el centro y quería saber si habéis tenido tiempo de valorar la salida de Reme el día 4 par aquedar ya errado esto antes de irme. Muchas gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2023-12-21','Ana: Envío correo a Ana Castillo Foronda TS - FUNDACIÓN AUTISMO SUR (teayudamos@autismosur.es): "Adjunto citación para reconocimiento relativo a Costi Alexandru Rizea, entiendo que no habrá ningún impedimento para que lo acompañéis. Ya me vais informando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2023-12-21','Ana: Correo de Teresa a la Secc. Ecca: "Manuel está en la comunidad terapéutica de la Garrovilla Hay que hacer autorización para que retire 200€ con acompañamiento en la primera semana de cada mes, empezamos en enero Los monitores que le acompañan son Angela Villalobos Riola: 09164617-Z Gaspar Fernández Romero: 08807663C. Tomás Suarez Gamero: 76242570 P. María González Barrero: 09209382-H Creo que ya se hizo pero para estar seguras hay que anular la transferencia permanente que se le hacia a su padre por importe de 200€ mensuales."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-12-21','Ana: Correo de IBERDROLA (prejub@iberdrola.es): "Hemos recibido una solicitud de actualización de sus datos personales. Le informamos que hemos procedido a efectuar dicha actualización en las bases de datos de Iberdrola. Para más información sobre el tratamiento de sus datos personales consulte el aviso de privacidad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-12-22','Ana: En relación al correo de Verónica Alonso, TS SSASB Moraleja (ssbase.vallearrago@salud-juntaex.es) "...necesitamos que nos digáis si continua interesada en ocupar plaza en nuestro centro residencial municipal o desiste de su solicitud. Queremos adelantarnos para poder gestionar la lista y no tener que ampliar los plazos después en el caso de que no siga interesada." ································· Llamo al CR Las Eras de Hernán Pérez (927 44 51 67 / rmhernanperez@mensajerospazex.es): Estela, Directora no está, pero me informan que Pilar está totalmente adaptada, muy contenta con su compañera de cuarto, se pasa el día cantando y verbaliza que no se quiere ir del centro y que allí "ha encontrado la paz". ···························································································································································································· Respondo a Verónica: "...contestando a tu consulta, Pilar ya no está interesada en ocupar plaza en el Centro Residencial Municipal de vuestra localidad. Y por parte de este Gabinete Técnico tampoco creemos conveniente realizar este cambio de recurso dadas las circunstancias." ········································································································································ *Conversación con Verónica, TS SSASB - Moraleja (927 515 075): Ha acudido a los SSASB Nadia, Educadora del Prog-Convenio FUTUEX. Solicitan acudir con la anterior Aux. de SAD al domicilio de Pilar a recoger ropa y calzado. La Aux. que la atendía ya no trabaja en el Ayto. y las que hay no conocen a Pilar ni su casa. **Acordamos que enviaré una autorización para que la Educadora pueda entrar a buscar la cosas que Pilar Necesita. ························ Aprovecho para consultarle por la SOLICITUD que realizan desde el C. Penitenciario para que el hijo pueda ir a vivir a la casa de su madre. **Me informa de lo mal y destrozada que dejó la casa la última vez que estuvo en el domicilio, cuando propinó la última paliza a Pilar. Sacó y tiró al suelo toda la ropa de los armarios, rompió cristales de las ventanas, arrancó y tiró una lámpara del techo, rompió la mesa del salón... Además, antes de ingresar en la residencia Pilar verbalizó que al irse le daba miedo que su hijo Jorge fuera a meterse en su casa. Ella no quiere.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2023-12-22','Buenos días Amalia. El motivo del presente es informarte que a RAFAEL CACHO GARCIA hemos acordado en Junta Tto. 14/12/23, solicitar el traslado de Rafael a un Centro que cuente con programa PAIEM (Enfermedad Mental) acorde a sus características ya que observamos que sería más conveniente para él, ha pasado por varios módulos y su situación de vulnerabilidad le genera problemas de abuso por parte de otros internos. Además de solicitarnos Rafael directamente ser trasladado de este centro. Cuando tengamos la resolución del traslado os informaremos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES MARIA'and edp.apellido1='ALVAREZ'and apellido2='CARRASCO'),'2023-12-22','-Amalia , pregunto en PFHC por la gestion de las pensiones , no tienen nada , me piden que vuelva a reenviar la documentación. Escribo a registro OAC :se adjunta documentación de nuestra curatelada INES MARIA ALVAREZ CARRASCO para registrar al CAISS de Badajoz ( Ronda del Pilar, 15 ) para la gestión de pensiones. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-12-22','Ana: Tras hablar con Cristina, TS C. Penitenciario BA (924 28 91 00), envío correo a Estrella, Secc. Ecca. con copia al ctutelar@: "Pongo en copia al resto de compis, por si hoy no pudiera hacerse que lo haga sin falta el martes la que pueda. Pero si se hace hoy mejor. Acabo de hablar con Cristina, Trabajadora Social del C. Penitenciario. **Hemos acordado que se haga una transferencia periódica a la cuenta peculio de 40€/ semana. Como bien sabes los datos que necesitas son el NIS y el DNI del interno: - NIS: 2022003378 - DNI: 76060862T" ····························· Cristina también me informa que Miguel Ángel va a pasar al Módulo Terapéutico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-12-22','Ana: Envío correo a los A. Jurídicos con copia a Maite: "En relación a ENRIQUE SANTOS GARCÍA-PUENTE, y todos estos documentos que ya os remití el viernes pasado, añado (ADJUNTO) el INFORME DEL SERVICIO DE PSIQUIATRÍA DEL C. SOCIOSANITARIO remitido hoy mismo para que lo unáis también a la respuesta al Juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2023-12-22','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Buenos días: Nos informan del alta de Consuelo Nevado Pacheco en la UHB de Cáceres. A lo largo de la mañana se acudirá a su recogida. Os seguiremos informando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESSICA ESPERANZA'and edp.apellido1='LEON'and apellido2='ENCINAS'),'2023-12-22','Ana: Correo al ctutelar a través del formulario de contacto (inf.saludextremadura@salud-juntaex.es): "Soy Abogado y represento a la madre de JESSICA ESPERANZA LEON ENCINAS, y quisiera que nos remitieran la resolución del Juzgado núm. 5 de PLASENCIA, dictado en el procedimiento AMD 0000244/2022, así como que me informen de quién es la trabajadora Social de la que depende. SAludos Correo Electrónico y/o Teléfono de Contacto: estanislaomartinabogados@gmail.com Soy Abogado y represento a la madre de JESSICA ESPERANZA LEON ENCINAS, y quisiera que nos remitieran la resolución del Juzgado núm. 5 de PLASENCIA, dictado en el procedimiento AMD 0000244/2022, así como que me informen de quién es la trabajadora Social de la que depende. SAludos Correo Electrónico y/o Teléfono de Contacto: estanislaomartinabogados@gmail.com" ··············································································· Respondo desde mi cuenta de correo: "Buenas tardes Estanislao, Soy Ana, Trabajadora Social que de forma transitoria está llevando el expediente de Jessica. Después continuará el seguimiento y las intervenciones necesarias mi compañera Teresa. Pongo en copia a mis compañeros Asesores Jurídicos, Angel y Miguel en relación a la otra cuestión que plantea."','2');
