insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='TORES'and apellido2='NUÑEZ'),'2023-12-22','Ana: Envío correo a Emilia Almodóvar, TS CSS Plas (emilia.almodovar@salud-juntaex.es): "Te reenvío correo con CITACIÓN – MÉDICO FORENSE para JULIAN TORES NUÑEZ, supongo que también la habréis recibido. Subrayo en amarillo en el hilo. Entiendo que no habrá problemas para su acompañamiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='SANCHEZ'and apellido2='MORENO'),'2023-12-22','Amalia, solicito a Futuex visita indicando : ha llamado su hermana Petri ( 675268201) y su marido Inocente Jiménez Jara ( 618051207) , por favor cuando podáis le hacéis una visita y los llamáis a ellos para que estén en el domicilio . Quieren contarnos algunas necesidades de Remedios','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2023-12-24','miguel, llega email de Damian: Lo siento pero yo me tiran mis raíces y quiero volver a mi casa una vez que me revise el kadett y después el juez y volver a mi domicilio yo aquí estoy muy solo.es mi dicision.me da igual lo que me haya gastado de dinero el próximo 30 de diciembre es el aniversario de la muerte de mi madre y yo quiero irme a mi tierra.yo tengo el papel firmado con el director hasta el 31 de diciembre. *************************************** Lo que haya que pagarle al abogado yo quiero a ver si me quitan la curatela y hacer mi vida en malaga ********************************************* He discutido con mi prima y ya no me hace cambiar de parecer y me he llevado un malrato siga con la venta del piso no voy a estropear su trabajo por las discusiones con mi prima. ************************************************** Yo estoy muy bien pero estas fechas con el aniversario de la muerte de mi madre el 30 de diciembre me hacen sentir mal disculpe usted pero hay momentos en que tenemos malos momentos pero ya superado ***************************************************** La relación con mi prima me hace cambiar de parecer.me descontrola.y pierdo el norte pero se recuperarlo me digo a mi mismo arriba Damián que ha sido un fallo de control de impulsos y que se siga con la venta del piso.porque tengo que comprender que no tengo que hacer caso con la voz que me habla mi prima yo tengo que estar tranquilo ********************************************** Ya estoy más tranquilo tengo que pensar que voy a vender mi piso en malaga porque aquí en Mérida es una ciudad para comprarme un piso y las personas son muy respetuosas y vivir aquí me da una estabilidad emocional y mental. ************************************************** Después de la cena iré a la misa del Gallo para pedir por todos vosotros y que tengáis una nochebuena feliz y salud para ustedes y todos los compañeros suyos de la comisión.y yo hacia adelante.feliz día de Nochebuena os deseo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2023-12-27','miguel, recibo email de la hermana Marisol Garcia Ramirez >marisolgarram@gmail.com> Buenas tardes Miguel: Encantado de saludarle, soy la hermana de Jose Antonio García Ramirez, en relación a los datos que nos ha solicitado Amalia Díaz para tramitar la solicitud para la compra de una vivienda a nombre de Jose Antonio, solicité a Vendedor los siguientes datos para agilizar los trámites; - Datos del vendedor acreditando la venta de la vivienda. - Dirección. - Precio Vivienda - Nota simple - Último Recibo Comunidad. - Último Recibo Contribución. - Borrador Contrato de Arras - Cláusula " pendiente autorización judicial" - Plazos ( Pendientes de detallar) Sin embargo para que puedan redactar el Borrador del Contrato de Arras ( Confirmar si es necesario ) nos solicita la asesoría del Vendedor; la Sentencia de la representación Judicial para hacer las indicaciones correspondientes en el contrato. Agradecería nos facilitarán dicho dato. Quedo a la espera de sus noticias, ¡¡Felices Fiestas!! Marisol García Ramirez Teléfono: 618 75 61 39 ************************************************ mi contestación con copia a Amalia: Buenos días, adjunto testimonio acreditativo del cargo que ostenta la Comisión Tutelar de Adultos. Recordarles que no habrá ningún documento vinculante hasta que el juzgado conteste si está o no de acuerdo con dicha compra para lo cual deberán remitirnos el contrato de arras acompañado de nota simple, último recibo de Ibi, y comunidad de propietarios y cualquier otro documento acreditativo de cargas como hipoteca, deudas con ayuntamiento, Oar…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2023-12-12','email de Alberto a la parte social, Amalia y jurídica Miguel: TOD@S: SE ACUERDA QUE SE VA A SOLICITAR AUTORIZACIÓN JUDICIAL. A TAL EFECTO MIGUEL VA A HABLAR CON MARISOL (HERMANA TUTELADO) PARA PEDIRLE TODOS LOS DATOS NECESARIOS PARA HACER SOLICITUD AUTORIZACIÓN: • DATOS INMUEBLE. • PRECIO. • HIPOTECA. • OTROS AMALIA: LE VA A PEDIR MÁS INFORMACIÓN A MARISOL (HERMANA). IMPORTANTE: TENER CLARO QUE LA COMPRA ES DEL HIJO Y NO DE PADRES O HERMANA ******************************************** contestación de parte jurídica Miguel: Perfecto, quedo pendiente a que Amalia me avise de que haya hablado ya con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2023-12-27','TERESA Soy Pedro, el Enfermero de Plena Inclusión Cabeza del Buey. Adjunto te envío el informe de Eugenio de la Biopsia que se le realizó en consulta de Cirugía y cuyos resultados recogimos en consulta el pasado día 22 de Diciembre . Los resultados ,no son buenos es un Carcinoma Infiltrante , estoy pendiente ya de que me envien el preoperatorio completo que se lo realizaré yo aquí en Cabeza del Buey y la Resonancia en Don Benito .... Durante este mes ,mañana día 27 se le va a realizar una ecografía y a principios del mes de Enero tiene Planificada tres consultas , de Preanestesia ya , para la intervención, de Digestivo de Control y de Nefrología .... Quedo a vuestra disposición para todo aquello que consideréis oportuno y por supuesto para que quien quiera estar de la Comisión que nos acompañe a las consultas que estimes necesario. La comisión de Tumores ha propuesto el tratamiento quirúrgico de la lesión. Cuando queráis este es mi correo y mi teléfono 6900405068. Te adjunto informe y resumen de historial y tratamiento . Un saludo Pedro Sánchez Vaquerizo Villalba DUE Plena Inclusion Cabeza del Buey Col 5609','2');
