insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2023-12-27','Ana: Correo de Gema, Directora Res (gemamg.asoma@gmail.com) al ctutelar@ con copia a mí: "Ya tengo los 250 euros de Victor Manuel Blanco Poveda para sus gastos. Tenéis que volver a hablar con la directora del banco Santander porque le han dicho a mi compañera que no pueden hacer los pagos de los acompañamientos que hicieron Hermelinda y Roseli, y supongo que la factura del taxi a lo mejor tampoco, porque necesitan la firma de alguno de vosotros de la comisión, cree que le ha dicho el nombre de Estrella y que le teníamos que mandar un informe médico porque tiene un seguro de dependencia, yo os comento lo que nos han dicho, intentar solucionarlo en cuanto podáis para que mis compañeras puedan cobrar dicho acompañamiento. Gracias por todo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2023-12-29','Ana: Envío correo a Isabel, directora de la Res. Municipal de los Santos de Maimona (rmayores@lossantosdemaimona.org): "Llevo un rato intentando contactar en el número que indicas (924 029 563) y no lo consigo. No obstante, puede comunicar por aquí la incidencia concreta. Si el problema es una deuda con la peluquera, como dices en uno de los correos, podéis hacer llegar la/s factura/s a mis compañeras de la sección económica a la dirección ctutelar@salud-juntaex.es indicando en el asunto que son factura pendientes de abono y ellas se encargarán de hacer la gestión para abonarlo mediante transferencia bancaria. Si esto no fuera posible, explicarnos cuál es la situación para poder buscar alternativa. Aprovecho para preguntarte qué tal sigue Arturo y, así mismo, comunicarte que, una vez transcurrido el periodo de adaptación, el seguimiento a partir de este próximo 2024 lo realizará mi compañera Teresa, Trabajadora Social que lleva esta zona de Badajoz. La pongo en copia para que esté al corriente." ····················································· Respuesta de Isabel: "Pues el problema que hay es que la peluquera ha enviado correos y no ha recibido respuesta. No obstante le indico de nuevo las direcciones para que proceda como indicas y en caso de no tener respuesta que te llame por teléfono. Arturo está muy bien la verdad. Muy integrado en el centro y bien de salud."','2');
