insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-12-29','Ana: Envío correo a las compañeras de S. Ecca: "Me acaba llamar un Coordinador de la ONCE, Román (667 133 087). Ventura está precisamente de vacaciones con un programa de la misma entidad. Les ha trasladado a todos los monitores su preocupación de no haber podido retirar su asignación económica de esta semana por no estar en Cáceres, cree que entonces ya la pierde y se ha agobiado. Por favor, ¿podríais escribir al banco para que la semana que viene Ventura pueda retirar su asignación de la semana que viene más la asignación de esta semana que no ha retirado?" ····································· Llamo a Ventura (682 483 126) varias veces, pero no obtengo respuesta. ···················· Llamo a Román y le solicito que se lo transmitan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-12-29','Ana: Tras llamada de Julia envío coreo a Secc. Ecca. al ctutelar@: "Me ha llamado Julia Morón Hernández. Sé que su situación económica es muy precaria. Pero pide un EXTRA para poder comprar un regalito a su sobrino y otro a su madre. Por favor, mirar si es posible darle 40 – 50 €. Si se puede bien y si no se puede no se puede. Como yo la semana que viene no voy a estar y ella tiene el número de Lourdes, dice que la llamará a ella para que le confirme. Ya le decís lo que sea."','2');
