insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2023-12-29','miguel, Tere me reenvía Ejecutoria 123/23 del jzdo de lo Penal 1 contra el tutelado Llamo al juzgado y me dan el teléfono de los servicios comunes de ejecución (924388764 y 924388765) que son los que tienen la competencia para decirnos cuánto pagar y cómo. Lo reenvío a Alberto y parte social: Buenas tardes, Alberto necesitamos saber qué saldo disponible tiene esta curatela representativa porque va a tener que abonar unos 4.720€+540€ El lunes me confirmarán en el servicio común de ejecución del juzgado. Les he llamado pero hoy no me lo cogen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2023-12-29','TERESA Hoy me he reunido con Ati en Zafra a petición de la psiquiatra por la quejas que hemos recibido a través de la alcaldesa y un informa que nos ha remitido la Olga la trabajadora social. Ati manifiesta que el también tiene quejas del pueblo y que se quiere marchar, ahora quiere vivir en Zafra Tiene de nuevo cita con la psiquiatra el próximo día 9 Hemos acordado que si se encuentra mal el mismo activara el 112 ya que le hemos propuesto que ingrese unos días en la UHB de Llerena y no quiere. Le he planteado retomar los acompañamientos a domicilio para que le ayuden con la búsqueda de un nuevo piso y le parece bien, le he recordado que le retiramos el apoyo por el comportamiento que estaba teniendo con la educadora lo cual el niega que haya sucedido Te planteo la opción de que la educadora quede con Ildefonso en zafra para la búsqueda de piso de alquiler Te facilito el teléfono de Ildefonso 672568386','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-12-29','Ana: Redacto Autorización y una vez recabada de la firma se la envío a Toni-Futuex y a Verónica, TS de SSASB Moraleja: "Adjunto la autorización para que NADIA, Educadora, pueda recoger las llaves y acceder al domicilio de Pilar Díez a recoger las pertenencias que necesita y llevárselas a ella a la residencia. Disculpad el retraso, pues como sabéis he estado enferma y esta mañana no he llegado a más. Espero que para la semana que viene se pueda gestionar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2024-01-02','miguel, en relación a la ejecutoria 0000123/2023 del jzdo de lo penal nº1 de Mérida, hablo con el servicio común de ejecución (SCE) 924-388764 y 924-388765, donde me confirman que hay pendiente de abonar el importe de 4.590,23€. Envío email a la parte social y Alberto (parte económica): Buenos días, de la curatela representativa de Francisco Javier Giraldo Becerra, he hablado con el servicio común de ejecución de Mérida que me informa que hay que abonar el importe de 4.590,23€ en la cuenta: IBAN ES55-0049-3569-9200-0500-1274 Concepto: 0392.0000.78.0123.23','2');
