insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2024-01-02','miguel, recibimos email den ctutelar del abogado de la sobrina Raquel: Buenos días: Como hemos hablado, les escribo como abogado de la familia de Doña Virgilia Barrios García (DNI 02471886-F), la cual falleció (les adjunto autorización de su hija), y en cuya tramitación de herencia, se ha observado que en dos cuentas en las que eran cotitulares Doña Nemesia y Doña Virgilia, por parte del tutor de Doña Nemesia se hicieron transferencias a cuenta privativa de la misma, cuando el tutor podría disponer (en beneficio de su tutelado) del 50% de dichas cuentas, en ningún caso del otro 50% titularidad de otra persona. El tutor que nos consta es Don José Vicente Granado Granado, solicitamos nos confirmen si sigue siendo el actual tutor. Les indico la información que hemos podido obtener de importes, fechas y números de cuenta: -Depósito a plazo fijo 2048 1041 87 2600027907 se pasan 31.000 euros a la cuenta ES17 2048 1041 8230 0007 5074 el 28/09/2020, y dicho día se transfiere dicho importe a la cuenta 1086 3400080307. -El día 08/10/2020 se traspasan 15.000 euros de la cuenta ES17 2048 1041 8230 0007 5074 a la cuenta 1086 3400080307. Tanto el depósito a plazo fijo terminado en 7907 como la cuenta terminada en 5074 están al 50% entre Doña Nemesia y Doña Virgilia, por lo que no son correctas las transferencias indicadas de 31.000 y 15.000 euros. Solicitamos realicen las comprobaciones pertinentes y quedo a su disposición para cualquier aclaración. Gracias, saludos Antonio Rivas 87607-ICAM Tlf 918106375 – 645107197 ********************************************************* mi contestación: Buenas tardes, les confirmamos que la Comisión Tutelar de Adultos actualmente ejerce el cargo de tutor de Doña Nemesia García Paniagua conforme nombramiento del cargo de tutor del Juzgado de 1º instancia e instrucción nº2 de Plasencia, procedimiento incapacitación 426/2009, cuyo cargo fue aceptado por esta Comisión el 30-6-2010.. Conforme al cumplimiento de la ley de protección de datos esta Comisión Tutelar de Adultos no puede facilitar información a terceros, debiéndo dirigir su reclamación al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-01-03','Amalia : escribe Pilar Martin : TENGO A L PACIENTE Y ME DICE QUE NO QUIERE RECURSO RESIDENCIAL (NI CRR, NI PISO SUPERVISADO). EL PROBLEMA ES COMO SABES QUE SON CENTROS ABIERTOS, Y SE NECESITA LA VOLUNTARIEDAD DEL PACIENTE. POR OTRA PARTE, ADEMÁS CASO DE QUERE INGRESAR TENEMOS EL PROBLEMA DE NO TENER GRADO DE DEPENDENCIA . PERO SE NIEGA A SOLICITARLO DE NUEVO. ME DICE QUE NECESITA PONERSE EN CONTACTO CON VOSOTROS PARA VER EL TEMA ECONÓMICO. CUMPLE LA PENA EL 15 DE FEBRERO. INTENTA PONERTE EN CONTACTO CON EL PACIENTE, (SU MÓVIL ES EL 695-76-58-58), Y SU PROPUESTA ES IR AL PISO DEL QUE TIENE ¼ DE PROPIEDAD QUE OSTENTA JUNTO CON SUS HERMANOS Y DE LOS QUE DICE TIENE PERMISO . AHORA EL PISO SE ENCUENTRA VACÍO Y SEGÚN REFIERE EN BUENAS CONDICIONES. YO ESTOY HASTA EL 5 Y LUEGO NO ME INCORPORO NUEVAMENTE HASTA EL 23.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-01-03','-Percibe P. Orfandad Clases Pasivas 763€ al mes . Se le puede quedar 163€ para domiciliar agua , luz. S.decesos con Santa Lucía lo abona la madre . Se le daria un reintegro de 600€ al mes .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-01-03','Maite: He pasado la renuncia a la plaza de RAL en Fuente de Cantos a la sección de acceso a recursos de discapacidad. Teresa de Novaforma, ha contactado con esta sección y ha cofirmado que no quería ingresar. También la he enviado al centro Francisco de Asuar y he hablado con Rosa la directora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2024-01-03','miguel, nos envia de nuevo email el abogado ANTONIO RIVAS ARROYO >letrasycasas@icam.es>, tlfno 645107197 de la sobrina Raquel a ctutelar y a mi: Buenos días: Más que pedirles información, lo que deben hacer es verificar si se han dispuesto de cantidades de un tercero diferente de su tutelado (por error o por otro motivo), y, en su caso, proceder a la devolución, por lo que no es necesario que nos faciliten información que pueda estar protegida, ya que los herederos de Doña Virgilia se han visto privados de un dinero de su madre que no van a dar por perdido, por lo que les insisto revisen el expediente para resolverlo de forma amistosa. Gracias, saludos Antonio Rivas 87607-ICAM Tlf 918106375 – 645107197 -------------------------------------- mi contestación: Buenos días, como ya se le ha indicado deben dirigirse al juzgado para solicitar cualquier tipo de información. En base a la ley de protección de datos no se les puede facilitar la información solicitada','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2024-01-03','Buenos días , me indica mi compañero que ha hablado con usted y quería saber cómo van algunos trámites de Josefa . Ya le indiqué en el último email que le envié que he activado dependencia , lo tenía inactivo , y le han concedido prestación vinculada a Servicio de Ayuda a Domicilio . Hace un mes que se inició el servicio con una chica colombiana que es la única persona que ella acepta , se ha contratado por empresa de Ayuda a Domicilio acreditada por el SEPAD. Al principio con menos horas y con la ayuda que le va a dar el SEPAD ,se han doblado las mismas . Se van a reanudar las visitas al domicilio con la Delegada tutelar . Todo lo que tenemos que gestionar con Josefa se está haciendo directamente con ella. Agradecemos toda la información que nos ha facilitado al inicio de la intervención , sin embargo , por protección de datos, ya no podremos darle más detalles sobre la misma . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-01-04','-AMALIA . REGISTRO SOLICITUD DE CENTRO DE DISCAPACIDAD POR MADEX Y EMERGENCIA SOCIAL . ESCANEO LA DOCUMENTACION EN SU CARPETA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2024-01-04','miguel, me confirma la notaria de Mérida, José Luis, que el lunes 8 puedo firmar la ratificación (intentaré también la firma de la ratificación de herencia de Enrique Santos) Se lo digo a Lorenzo el hermano del tutelado. Y le pido hable con el abogado Paco Vela para presupuesto y datos del procurador para vaya moviendo la demanda de solicitud de autorización de la venta que quiere hacer. Contestación de Lorenzo: Hola Miguel he hablado con paco vela , me ha dicho que le llame para concretar , dígale que a hablado conmigo. Tlf 619549406(Paco Vela) Llamo al abogado sin éxito.','2');
