insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-01-04','Buenas tardes, Amalia. Tal y como te comuniqué, Regina está pasando la primera parte de la navidad con Maica. Al haber concretado hoy con Elvira (educadora de Los Ängeles) la fecha definitiva en la que se irá con ella, te adjunto el comunicado diferenciando ambos periodos. Feliz entrada de año. REGINA REINA LARA, acogida en el recurso sito en C/ Rota 41 de Badajoz y gestionado por Asociación HOFA, disfrutará de permiso en C/ REYES CATÓLICOS 1A VALVERDE DE LEGANES (Badajoz) del 21 de diciembre de 2023 al 2 de enero de de 2024 con Dª MARIA DEL CARMEN GONZÁLEZ CORDERAS DNI 80052778 J y del 2 de al 8 de enero de 2024 con ELVIRA BOTE RUIZ DNI 27320007D EN CALLE RAMON Y CAJAL 139 DE SANTA AMALIA (Badajoz) , quienes serán responsables de la misma durante estos periodos, por considerarse beneficioso para su evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-01-02','Maite: ha llamado JOsé Manuel, ha hbalado con MAría. Tiene un problema en casa, el techo del baño de la vecina de abajo se ha desprendido un poco y ninguno de los dos puede usar el baño. Nos pide irse a unb hostal hasta que se arregle. YO he hablado con el hermano para confirmar la información y es así. El ha buscado un hostal, ha enviado el presupuesto y lo hemos contratado por 7 noches. 230€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-01-05','Maite. María ha hablado con José MAnuel. Sólo ha dormido dos noches en el hostal.Dice que está más agusto en su casa. LO seguirá usando pero sólo para ducharse y usa el baño....','2');
