insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2023-12-27','Ana: Correo de Ayto. Moraleja (info@moraleja.es) con las fotos que Verónica, TS, indicó que enviaría: "Le adjuntamos las fotografías que nos solicitaron vía telefónica, en las que se puede apreciar las condiciones higiénicas en las que se encontraba el domicilio de María Pilar Díez Santiago cuando convivía con su hijo." ·············· En las imágenes, además del desorden y pésimoas condiciones sanitarias, se observan cristales y mobiliario de madera rotos.','2');
