insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2024-01-09','Ana: Envío correo a Maite, TS del C. Penitenciario de CC (trabajosocialcpcaceres@dgip.mir.es): "En relación a la consulta planteada sobre vuestro interno, JORGE BARROSO DÍEZ, hijo de Mª PILAR DÍEZ SANTIAGO, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura (CTAEx), comunicaros que Pilar NO desea permitir que su hijo resida en la vivienda 100% de su propiedad, dados los antecedentes de maltrato de Jorge hacia su madre y los destrozos perpetrados por el mismo en la vivienda. Justo antes de ingresar en la residencia Pilar verbalizó el miedo que tenía de que su hijo pudiera entrar en su casa durante su ausencia de la misma y volver a destrozarla. Contamos en nuestro expediente con imágenes de cómo dejó la casa la última vez que vivió en ella. Por todo lo expuesto, y principalmente atendiendo a la voluntad de Mª Pilar, desde este Equipo Técnico de la CTAEx, consideramos que Jorge tendrá que buscar otra alternativa a su salida del C. Penitenciario, pues no se va a permitir que resida en casa de su madre. Ante cualquier cuestión, no dudéis en volver a contactar."','2');
