insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-01-09','Ana: En relación al correo de Toni-Futuex, remito correo a la Secc. Ecca., ctutelar@ con copia a Toni: "Os reenvío correo de Toni, Futuex, en relación a FELISA FELIPE TEOMIRO y AITOR MORENO FELIPE, con los tickets de las compras de las dos últimas semanas que entiendo que hay que pagar (comprobarlo primero y si no se ha abonado aún, por favor, haced la transferencia a la tienda a la mayor brevedad). Por otra parte, os traslado la propuesta que hace Toni (podéis leer en el hilo). ¿Se podría hacer una transferencia periódica de los 100€ semanales (o transferencia mensual con la cuantía proporcional ) en concepto de manutención/comida de la cuenta de Aitor a la de Felisi, y cargar la tarjeta monedero de Felisi semanalmente para que ésta pueda retirarlo con el apoyo de la Educadora de Futuex y hacer la comprar? En el Supermercado cada vez le están poniendo más inconvenientes para retirar los productos y que se abone a posteriori mediante transferencia. Esto sería una medida temporal, hasta que Aitor tenga plaza en centro residencial. Ya nos decís cuando podáis. Pongo en copia a Teresa, para que pueda leerlo a su vuelta de vacaciones y estar así al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-01-09','Ana: En relación al correo de Toni-Futuex, remito correo a la Secc. Ecca., ctutelar@ con copia a Toni: "Os reenvío correo de Toni, Futuex, en relación a FELISA FELIPE TEOMIRO y AITOR MORENO FELIPE, con los tickets de las compras de las dos últimas semanas que entiendo que hay que pagar (comprobarlo primero y si no se ha abonado aún, por favor, haced la transferencia a la tienda a la mayor brevedad). Por otra parte, os traslado la propuesta que hace Toni (podéis leer en el hilo). ¿Se podría hacer una transferencia periódica de los 100€ semanales (o transferencia mensual con la cuantía proporcional ) en concepto de manutención/comida de la cuenta de Aitor a la de Felisi, y cargar la tarjeta monedero de Felisi semanalmente para que ésta pueda retirarlo con el apoyo de la Educadora de Futuex y hacer la comprar? En el Supermercado cada vez le están poniendo más inconvenientes para retirar los productos y que se abone a posteriori mediante transferencia. Esto sería una medida temporal, hasta que Aitor tenga plaza en centro residencial. Ya nos decís cuando podáis. Pongo en copia a Teresa, para que pueda leerlo a su vuelta de vacaciones y estar así al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2024-01-09','Ana: Llamo a Isabel, Directora de la Res. Municipal de Los Santos de Maimona (924 029 563): pero no obtengo respuesta. ·············································································· Correo de Rosa Mª, Peluquera de Los Santos de Maimona (rosapelu1986@gmail.com), "Soy la peluquera de los Santos, me debe un corte de pelo, son 7 euros. Me lo puede hacer por bizum a este número. 650124160 . Gracias" ····················· Le respondo: "Desde la sección económica de la Comisión Tutelar de Adultos se gestiona el dinero y la cuenta bancaria de D. Arturo José Rocha Merchán, pero no tenemos la posibilidad de hacer Bizzun. He intentado contactar con Isabel, la Directora de la Residencia para ver de qué otra forma se puede hacer el abono, pero no consigo contactar, la pongo también en copia para que me llame cuando pueda o me facilite otro número de contacto. La única opción más inmediata que le podemos ofrecer es que nos facilite un número de cuenta bancaria y hacerle una transferencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-01-09','Ana: envío correo a Alberto, Maite y Toni-Futuex: "En relación a los presupuestos que nos envía Toni-Futuex, relativos a José Manuel Romero Mediavilla. De los presupuestos de Cáterin, el más económico y que, además, es el que prefiere José Manuel es el “A Mesa y Mantel”. Así que por mi parte, ok al mismo. *Como podéis leer en el hilo, hay que tener en cuenta para el cálculo que hay añadir el suplemento por desplazamiento al domicilio de los días que le entreguen la comida que es de 2€/día. Pero como esto no me quedaba claro, no sé los días que reparten, ni si estaba incluido los fines de semana en el BONO MENSUAL, he llamado al Cáterin y me explican que el bono es para todos los días de mes, incluido fines de semana y reparten la comida a diario excepto el domingo (el sábado llevan el menú doble para sábado y domingo) por lo que el coste incrementaría. En cuanto al presupuesto del altavoz, me lo dijo antes de mis vacaciones y le recordé que ya se le había dicho desde la sección económica, cuando se aprobó y compró la TV, que no podía pedir ningún extra hasta febrero (excepto el extra de navidad que se le concedió). Pero él insistió en que lo iba a enviar igualmente. Por parte de la sección social la respuesta es NO." ·································································································································································································· Llamada de José Manuel con quejas y exigencias al poco de empezar a hablar, dado el tono y la actitud se le avisa y finaliza la conversación con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-12-27','Ana: Correo de Toni-Futuex: "También se ha gestionado una cita en CEDEX para Aitor Moreno Felipe, y se pretende durante los próximos días actualizar sus datos personales en el SES."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2024-01-09','Ana: En relación al correo pendiente de Toni-Futuex, recibido en mi ausencia: "También se ha hecho visita al domicilio de José Blas Cañas Lozano, se encontraban su madre y él. Teodora le ha pedido que vaya a comprarle la medicación a la farmacia pero dice que José no tenía mucha intención, la educadora le propone ir juntos y él dice que sí, que prefiere ir acompañado. Salen para hacer esta gestión, mientras José le habla de su día a día en el C.O de Down y lo que suele hacer con su pareja, Fátima. La educadora le pregunta por la relación con su madre, dice que ya no tienen conflictos, la educadora le aconseja hacer caso a su madre y ser más responsable con las tareas del hogar, él parece estar dispuesto. Le pregunta si a él le gustaría estar en un centro o en casa, él dice que en casa pero también dice que le gusta el centro de Novaforma, y que conoce gente allí. Al volver a casa, José ayuda a colocar las medicinas de su madre. Quedan en ir pronto a recargar el abono mensual del autobús urbano. Teodora sigue insistiendo en la necesidad de que la asignación de José sea más alta porque tiene que pagar todo ella sola. Y solicita que su hijo se vaya un centro. Se solicita extra de 20 euros en la asignación presupuestaria de José Blas Cañas Lozano por petición del mismo para pagar una ficha de inscripción del balonmano, deporte que practica habitualmente. Se considera apropiado al tratarse de una actividad deportiva saludable para él. La educadora acompañaría a José a la retirada de este dinero para asegurar que se utiliza con dicho fin. Se solicita que pueda ser entre el día 18 y 29 de este mes con el propósito de proceder al pago de la inscripción antes del mes de enero, considerada fecha límite para que José pueda continuar jugando a este deporte." ········································································ Reenvío correo a Alberto, Jefe Secc. Ecca., y escribo con copia a Toni: "En relación a JOSÉ BLÁS CAÑAS LOZANO, como puedes leer en el hilo, solicitaron en diciembre (cuando y o estaba enferma) extra de 20€ para la inscripción en Balomnano, supongo que lo habrá abonado igualmente (se lo habrán prestado sus familiares) pero en mi opinión hay que concedérselo. Por otra parte la madre, que en su día no quería que se aportara nada de dinero, ahora dice que la asignación es baja y tiene que abonarlo casi todo ella, ¿podrías valorar una subida en concepto de manutención? Pongo en copia a Toni, Futuex, para que esté al corriente. Por cierto Toni, en cuanto al ingreso en Centro, rechazó hace algo más de un año plaza en Mérida y en el centro que él quiere, Novaforma, no es posible su ingreso, no hay plazas y si quedara alguna, al tener sólo Grado I de Dependencia sería muy difícil su acceso, las personas con más grado se le ponen siempre por delante en la lista de espera."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-01-09','Ana: llamada de Jesús, pareja de Pilar. Pilar ya lleva 3 semana pudiendo retirar su asignación. Por otra parte, han encontrado una casa en Ahigal por 200€/mes más fianza de otros 200€, pero el dueño quiere hablar con alguien de la CTAEx antes. ································ Jesús solicita una aportación para los gastos de Pilar, planteamos entre 150 - 200 €/mes, consultaré a Alberto, Jefe S. Ecca. ······································································································································· Llamo a Pedro Martín Panadero, propietario vivienda de Ahigal (66 22 78 621). Me enviará el contrato a mi correo. El contrato irá a nombre tanto de Pilar como de Jesús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-01-10','Ana: Envío correo a Alberto, Jefe S. Ecca: "En relación con PILAR JIMÉNEZ AGUILAR, va a mudarse a vivir con su pareja, Jesús, a la localidad de Ahigal. Ya han encontrado casa por 200€/mes, más el primer mes otros 200€ de fianza. He hablado con el propietario y van a hacer todo por lo legal en la gestoría, pondrán el contrato a nombre de los dos y nos lo enviarán para su revisión y firma por la D. Gerente. Pongo en copia a Ángel para su conocimiento. (Ángel, en cuanto lo reciba te lo envío) En cuanto a la aportación de ella a los gastos comunes, hablando con ellos planteamos que aporte ahora 200€ para que abonen a partes iguales la fianza y mensualidad y a partir del mes siguiente entre 150-200€ (ya calculas tú) para alquiler y suministros. Jesús propone que se le haga la transferencia periódica a él para que desde su cuenta le haga la transferencia al dueño. Posiblemente haya que reajustar asignación semanal. También habrá que ver si hay oficina bancaria en Ahigal o si la asignación la sigue sacando en Plasencia como hace ahora." ································································································································································································ Correo de Ana Benavente, TS ESM (anamaria.benavente@salud-juntaex.es): "Tenía citada hoy a Pilar Jiménez Aguilar, y no ha venido. No consigo contactar con ella. ¿ Qué teléfonos tienes de ella o de la pareja ?." ··························· Mi respuesta: "Pues precisamente ayer estuve hablando con Jesús. Te paso los que tengo: 641 09 29 14 / 613 33 66 47 (desde éste último es desde el que me llamó ayer) Ya me dices."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIO'and edp.apellido1='PILO'and apellido2='PRADA'),'2024-01-10','ARCHIVO DEL EXPTE. Mediante Auto n.º 298/23, de 4 de julio, dictado por el Jzdo. de 1.ª Inst. n.º 4, de Badajoz, se dispone, como adecuada y suficiente, la guarda de hecho que ha venido ejerciendo D. Manuel Pilo Redondo (hijo de D. Gregorio).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-01-10','Ana: Correo de Jessica, Cáterin A mesa y mantel (ccamesaymantel@gmail.com): "Desde A Mesa y Mantel nos ponemos en contacto para dar presupuesto del servicio a domicilio de menú diario para José Manuel Romero. El bono más económico que tenemos es el mensual, incluye primer y segundo plato elaborado de manera casera a diario, este tiene un coste aproximado de 5,25€/día. Este precio se vería incrementado en 2€ al día por desplazamiento por llevarlo a su domicilio, sólo se cobrará los desplazamientos realizados, que no son el mes completo, hay que restar el desplazamiento de todos los domingos y el de algún sábado que cerremos el establecimiento, en esos casos se llevará comida doble el dia anterior. El bono tiene un coste de 158€ más desplazamientos, se abonaría cada factura mensual mediante transferencia bancaria. Adjunto algunos ejemplos de menús semanales que elaboramos además del cuadrante de precios y bonos disponibles por si les interesa otro que no sea el mensual, quedo a su disposición para cualquier duda que pueda surgir." ·················· Lo reenvío a Alberto y Maite, Jefes Secc. CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2023-11-24','Ana: REGISTRADA solicitud de PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2024-01-10','Ana: En relación al coreo de Sonia, Asindi, y a petición de Ángel, A. Jurídico, envío correo a Neni, Magdalena Casitllo - TS CAMP Don Benito (magdalena.castillo@salud-juntaex.es): "En ausencia de mi compañera Teresa, te escribo yo para solicitarte CERTIFICADO DE INGRESO EN CENTRO (con fecha de ingreso e indicación de permanencia en la actualidad) relativo a AARÓN ROSADO ALARCÓN, cuyo cargo ostenta la CTAEx, para remitir al Juzgado." ·········································································· Envío correo a Sonia Bernabé, TS y Directora de Asindi (trabajosocial@asindi.e.telefonica.net): "A petición de Ángel, Asesor Jurídico, os solicito que nos enviéis la carta del Juzgado que os iban a entregar para Aarón, si es que aún estáis a tiempo de recogerla." ···································· *Envío a Ángel, carta que me facilita Sonia. ································· Respuesta de Ángel, A. Jurídicio, a Sonia, Miguel y a mí: "En relación con la carta recibida por Aaron desde la Comisión Provincial de Asistencia Jurídica gratuita, se trata del reconocimiento del derecho de asistencia jurídica gratuita y confirma la designación de Letrada que en su día hizo el Colegio de Abogados de Cáceres, en el procedimiento DP230/2021, seguido en el Juzgado de Primera Instancia e Instrucción nº 6, de Cáceres. Sin embargo, este Juzgado, dictó Auto de sobreseimiento y archivo de este procedimiento, con fecha, 7/10/22. Por lo expuesto, queda sin efecto la designación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2024-01-09','Ana: Correo de ayer de Sonia Bernabé a Miguel, A. Jurídico, y a mí: "os escribo para informaros que el viernes nos entregaban una carta desde el Juzgado para Aaron Rosado Alarcón. La compañera indicó al cartero que actualmente no reside en la residencia de ASINDI, pero que si podía retenerla hasta hoy lunes os preguntaríamos qué hacer al respecto. Si queréis la podemos recoger y os la mandamos escaneada. Imagino que habrá que comunicar el cambio de dirección al Juzgado de Cáceres."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-01-10','Ana: Llamada de José Manuel (691 715 673): dice que Icíar le ha dicho que no puede comprar ahora ropa en la rebajas. Le digo que en estos momentos hay otras cuestiones qe son prioritarias. ·············· En cuanto a la contratación Seguro de Hogar, le informo que mis compañeras de S. Ecca. están en ello. ·············· Le informo que estamos pendiente de aprobación por parte del Jefe S. Ecca., del Presupuesto de Cáterin de A mesa y mantel. ················· Dice que ha retomado la asistencia al Embarcadero, a la actividad de cuero y que asistirá también a Informática. Quiere que se abone la tarjeta de transporte. Le indico que primero tendría que demostrar que acude regularmente y nos lo tendrán que comunicar desde la Asociación. ··············· *También dice que el Psiquiatra le va a derivar, de nuevo, por emergencia social a CRR. ······························ Por último me comunica que se deben muchos recibos de la comunidad de vecinos. Pero que él no sabe el número de cuenta ni tiene el teléfono de la presidenta, su hermano sí. ·········································································································································· Envío correo a José Luis, hermano de José Manuel: "Como supongo sabrás, se deben muchos recibos de la comunidad de vecinos en que reside tu hermano José Manuel. Debe haber habido algún problema a raíz de la fusión de las entidades bancarias o algo así, porque antes estaba domiciliado, y por tanto, se abonaba periódicamente. Pero para poder solucionarlo necesitaríamos el número de cuenta bancaria de la comunidad o bien el contacto de la Presidenta de la misma para poder pedírselo. ¿Podrías facilitarnos alguna de las dos cosas?" ····························································································································································································· Correo de Toni-Futuex con incidencias de las últimas semanas y la actual y precaria situación de José Manuel. ·· Guardo en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2024-01-10','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com) a mí y al ctutelar@: "Informar de que la persona usuaria ANTONIA CANELEDA DEL RIO solicita un extra de 200€ para compra de ropa." ················· Respondo a ambos correos: "Por mi parte, si es viable, ok a este presupuesto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2024-01-10','Ana: Correo de Sonia Bernabé - TS y Directora - Asindi (trabajosocial@asindi.e.telefonica.net): "remito la distribución de las visitas a la familia de los hermanos Hernández Castaño. He hablado con la madre y me dice que están muy acatarrados en casa, que prefiere que este mes no vayan para prevenir que se puedan contagiar. Entonces irían en Febrero después de los carnavales. Luego lo hablo con Justo y Roberto para explicárselo y su madre también les llama y se lo traslada para que estén tranquilos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2024-01-10','Ana: Correo de Sonia Bernabé - TS y Directora - Asindi (trabajosocial@asindi.e.telefonica.net): "remito la distribución de las visitas a la familia de los hermanos Hernández Castaño. He hablado con la madre y me dice que están muy acatarrados en casa, que prefiere que este mes no vayan para prevenir que se puedan contagiar. Entonces irían en Febrero después de los carnavales. Luego lo hablo con Justo y Roberto para explicárselo y su madre también les llama y se lo traslada para que estén tranquilos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2024-01-10','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "estamos en contacto con el hermano de los hermanos Rodriguez Alcántara porque no se ven desde verano y, tanto Isabel como Ignacio, nos solicitan que quieren verlos. Joaquín, que es el hermano que vive en Plasencia nos ha dicho que pueden ir un día de enero, siempre que coincida en fin de semana. El tema del transporte sería en taxi, como en otras ocasiones, y lo asumen entre los dos hermanos. Voy a llamar o a poner un correo a Estrella para que me confirme el tema económico."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2024-01-10','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "estamos en contacto con el hermano de los hermanos Rodriguez Alcántara porque no se ven desde verano y, tanto Isabel como Ignacio, nos solicitan que quieren verlos. Joaquín, que es el hermano que vive en Plasencia nos ha dicho que pueden ir un día de enero, siempre que coincida en fin de semana. El tema del transporte sería en taxi, como en otras ocasiones, y lo asumen entre los dos hermanos. Voy a llamar o a poner un correo a Estrella para que me confirme el tema económico."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2024-01-10','Ana: Correo de Melania Servan, CRR Olivenza (MSERVAN@caseresidencial.es): "Estoy en sesión con vuestro tutelado Ceferino Mariscal Crespo. Me está comentando que quiere recibir dinero extra para realizar una serie de compras ( una TV para su habitación, una play…etc ). Este chico me comenta que cuando estaba en Plasencia le concedían el extra anualmente y desde el centro gestionaban las peticiones sin necesidad de tener que estar pidiendo cantidades extras cada cierto tiempo. No sé cómo tenéis pensado hacerlo ahora, si continuamos con este proceder o como lo hacemos siempre. Me gustaría aclararlo cuanto antes puesto que él lleva con este tema semanas… jjj Si preferís tratarlo por llamada telefónica, estoy a vuestra disposición." ······························ Respondo con copia a Amalia y Alberto, CTAEx: "Lo de los extras anuales es una “prueba piloto” de administración económica que se está llevando a cabo en el CRR de Plasencia mediante acuerdo entre el equipo técnico de éste y el Jefe de la Sección Económica, por tanto, entiendo que es el Alberto, el propio Jefe el que tiene que decidir si seguir haciéndolo así en el caso de Ceferino en vuestro recurso. Le pongo en copia para que pueda valorarlo y dar una respuesta. Alberto, por favor, lee el hilo y nos dices. Por otra parte, puesto que ya hace un mes que Ceferino está en Olivenza, y según me informó María Barroso el 18 de diciembre, la adaptación está siendo adecuada, una vez esté resuelta esta cuestión del extra, continuará ya Amalia haciendo el seguimiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2024-01-10','Ana: Correo de Lourdes, S. Ecca. del día 5: "Ventura hizo el cambio de compañía de telefonía, en el mes de diciembre cambió a YOIGO. Al entrar en la cuenta para comprobarlo, siguen apareciendo dos facturas el día 4 de enero, por importe de 97,68€ de Telefónica España, y 11,25€ Telefónica Móviles. He llamado a Odair, 622197332, amigo de Ventura, quien lo acompañó a realizar el cambio, asegura que ya hicieron todos los trámites y que no deberían cargar ningún recibo más. Le indico que voy a devolver los recibos, y me dice que sin problema, que no se va a quedar sin línea. Espero al lunes, para ver el recibo de Yoigo que aún no está cargado, y una vez emitido, devuelvo los dos de telefónica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-01-10','Ana: Reenvío a la Secc. Ecca. correo de Puerto, TS del Valdeobispo (ssb5@mancomunidadvalledelalagon.es), indicando que habrá que re-domiciliar: "Buenos días: según me informa el Alcalde del Ayto de Valdeobispo, el recibo de agua-basura de la vivienda de Enrique ha sido devuelto por falta de fondos en la cuenta. Te adjunto el recibo a los efectos oportunos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2024-01-10','Amalia : envio a Julio para que registre a Dependencia , aceptación PIA , la PVS con el contrato ASINDE y la aceptación SAD municipal para que la pongan en lista de espera . Aunque va a ser más complicado pq ella quiere que vaya la chica colombiana que conoce. Queda registrado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2024-01-02','Ana: Correo de Pilar, Directora del Hogar San Vicente de Paúl (direccion.hgsvplasencia@gmail.com): "Les informamos que Mª del Carmen Matillas Jiménez participará mañana en la Actividad "Viaje a Badajoz" que llevará a cabo el Hogar San Vicente de Paúl."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-01-10','Ana: Envío correo a la S. Ecca, ctutelar@: "He recibido llamada de Ángel Félix Maillo Santibáñez (643 622 174), solicita EXTRA de 100€ por el cumpleaños de su hermana que es el próximo viernes 13 y otras cosillas que necesita. Por mi parte, si es viable, ok al mismo. Si podéis por favor, confirmarle vosotras directamente, que no consigo ponerme al día... Sino decírmelo y ya le llamo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-01-11','Ana: Envío a Ángel, A. Jurídico, el Cdo. de Ingreso en centro que me remite Magdalena del CAMP.','1');
