insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-01-11','Ana: Reenvío a Ángel, A. Jurídico, el borrador del contrato de arrendamiento de la vivienda que nos remite Pedro Martín Paniagua, propietario de la casa de Ahigal (ryoga.hibiki.330@gmail.com) para que lo revise y dé respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-01-11','Ana: Dado que Alberto, Jefe Secc. Ecca. está de baja, tomamos la decisión en la S. Social. ··········· Maite, Jefa, remite correo a María, S. Ecca: "Vamos a contratar el catering para José Manuel. El que aparece abajo ‘’ A Mesa y Mantel’’. Hay que hablar con la encargada Jéssica, es la que escribe el correo de abajo, para contratar el bono de 10 días inicialmente que cuesta 58 € mas los 2 € diarios de desplazamiento. A ver si pueden empezar hoy. El teléfono es: 927 62 95 31." ·············· María hace las gestiones. *Empezarán a llevarle la comida hoy mismo. ····························································································································· Envío a Toni-Futuex, correo-respuesta a su correo de ayer. "Precisamente hablé con él tanto el martes como el miércoles, día que también llamó a María e Icíar, con las que también habló... Ayer escribí a su hermano para pedir que nos envíe el número de cuenta de la comunidad de vecinos o bien el nº de la Presidenta de la misma para poder contactar con ella y solicitárselo. Debe haber sido algún error a consecuencia de las fusiones de las entidades bancarias, porque como veis y sabéis estaba domiciliado con anterioridad. En cuanto al cáterin, ya está contratado en A mesa y mantel. Hoy mismo le llevan la comida por primera vez. *Decirte, eso sí, que como estamos pendiente de si ingresa o no en recurso (se va a intentar en C. Sociosanitario), sólo se ha contratado el bono de 10 días, si es necesario después se renovará. Iremos viendo." ···································································································································································································· Llamo a Lourdes Pérez Ortega, TS - IMAS (927 212 335 Ext 4425) varias veces, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2024-01-11','Ana: Correo de Jesús (susiyesli@gmail.com), al ctutelar@: "me ha concedido por ayudas al alquiler de la vivienda la cantidad de 3000 € de los cuales la Junta me ha depositado en la cuenta 1500 €, y he de presentar documentación extra para que se me concedan los otros 1500 €. En ello estoy tras el período navideño." ································································································································································································ Recibimos Informe SOAP del Dr. Francisco J Serrano Guerra Librero - MAP- C. Salud Plaza Argel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-01-11','Te informo de que, Antonio Pereo superó con éxito la entrevista personal y será trasladado al CRR de Plasencia el próximo miércoles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-01-11','Ana: Correo de Lourdes, Secc. Ecca: "Ya está avisado Angel Félix, se autoriza el extra para que retire la próxima semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2024-01-11','Ana: Correo de la S. Ecca. a Sheila, CRR-CC (crr@grupociudadjardin.com): "Buenos días, se acepta la solicitud del extra de 200€ para ropa, una realizada la compra deben enviarnos los justificante para archivarlo en su expediente, como justificantes del extra. Puede pasar a retirarlo durante la próxima semana, del 15 a 19 de enero, cuando mejor les venga."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2024-01-10','Ana: Correo de Carmen Vega, Directora de Banium Residencial (residencialbanium@villatermal.com): "sólo queríamos informarles que el Centro Residencial Banium va a cambiar sus precios a partir del mes de Febrero pasando en el caso de Concepción Barbero Sánchez a pagar una cuota de 1.737,84€ (IVA Incluido) correspondiente al Grado III en habitación doble. (Actualmente paga 1670,24€). Cualquier duda que tengan o consulta al respecto pueden hacerlo a través de este correo o al teléfono 683 379 329."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2024-01-11','Ana: Correo de S. Ecca: "Se modifica la cuota del centro para 2024 , recordaros que ya tiene en su cuenta los 18.660€ que tenía en fondos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-01-11','REGINA REINA LARA, acogida en el recurso sito en C/ Rota 41 de Badajoz y gestionado por Asociación HOFA, disfrutará de permiso en ARGUELLO CARVAJAL, 35. 1A (Badajoz) del 12 al 14 de enero de 2024 con estancia y pernocta el sábado 13 de enero en C/ Luis de Morales 20 de Puebla de Sancho Pérez Badajoz) con D ALEJANDRO GUERRERO FERNÁNDEZ (TRABAJADOR DEL CEE LOS ÁNGELES) CON DNI 34782885 P Y CON AMANDA PÉREZ GALEAS DNI 80090731 Q quienes serán responsables de la misma durante este periodo, por considerarse beneficioso para su evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-01-08','Ana: correo de Lourdes, Secc. Ecca., a Alberto, Maite y a mí: "Buenos días, recibo llamada de la madre de Mari Carmen Solana Chanclón. Explica que por problemas de huesos, no puede vivir en su casa, y está ingresada en Residencia de Brozas, que le supone una cuota mensual de 900€, dinero del que no dispone, en suficiente. Necesita una ayuda de unos 300€, y pregunta si es posible que su hija pudiera aportar algo. Deja su teléfono para que habléis con ella, y de las explicaciones que se necesiten. 628 88 79 28 BENITA CHANCLON" ························ *Esperaremos a que reincorpore Alberto, jefe S. Ecca. para valorarlo en equipo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2024-01-11','Ana: Correo de Mª Jesús Gía Mnez (mjgarciamar@gmail.com) a Miguel, A. Jurídico - CTAEx: "Te paso la factura por el importe que aprobasteis, para el proyecto de demolición. Todavía sigue en el colegio de arquitectos, me han dicho que en estas fechas va todo más lento, pero que la semana que viene esperan poder visarlo, en cuanto lo tenga te lo paso, junto con el justificante de presentación del ayuntamiento de Piedras Albas. Como sé que te vas la semana que viene de vacaciones, te paso la factura antes de que te vayas." ······································· Miguel le remite a Alberto, Jefe S. Ecca: "del expediente de Martin Quiros Berrocal van a empezar pronto las obras. Necesito que hagáis este abono lo antes posible porque urge."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2024-01-11','Ana: Conversación con Ismael, Cuñando de Isabel, marido de su hermana Beatriz (618 60 88 45): Domiciliaremos el seguro de decesos de Isabel en su cuenta. ······· Con respecto a las visitas a Trujillo de Isabel quiere informarnos de que, aunque come en casa de su hermana y sí pernocta en el Hotel/Hostal, durante el día a veces acude a casa de su madre y la pareja de éste está allí. *Para los siguientes viajes a Trujillo solicitaremos seguimiento a Futuex. ························································································································································································ Envío correo a Estrella, S. Ecca: "He hablado con Ismael, marido de la hermana de Isabel Cano Blázquez. Hasta ahora su hermana ha estado abonando el Seguro de Decesos de Isabel en la compañía Santa Lucía. Te paso todos los datos que me ha facilitado para solicitar el cambio de domiciliación bancaria a la cuenta de Isabel, que nos envíen también la póliza, y a ser posible, se ponga a la propia Isabel como TOMADORA. Nº Póliza: 149 008 283 Tomadora: Beatriz Cano Blázquez (hermana de Isabel) Cuota: 13 € apróx. Contacto y nº de la Oficina de Santa Lucía de Trujillo: Pablo – 638 48 78 27"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='MARTIN'and apellido2='VELASCO'),'2024-01-12','Amalia : Hablo con Mª Jesus , TS del CS San Roque , es la que inició el expediente. Está en D. Judicial cuando pase a curatela contactaré con ella para el P. Intervencion EXt 42428 La está ayudando una congregacion religiosa de la zona de S.Saavedra , la acompañan a las citas médicas.. a través del programa Suerte llama a suerte de esta congregación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2024-01-12','Ana: Respondo al correo de Ángela, sobrina de Arturo: "¿tienes algún número directo de la directora? Las veces que he intentado hablar con ella llamando al número del centro que ella misma nos ha facilitado en un correo ha sido sin éxito. Hoy tengo anotado en la agenda para volver a intentarlo. Por otra parte, voy a intentar dejar esto resuelto, pero ya no soy yo la TS de referencia de Arturo, sino mi compañera Teresa: teresa.blancoparra@salud-juntaex.es / 924 00 38 04 El acompañamiento a las citas médicas, se puede realizar con personal de confianzan de la residencia, (por ejemplo auxiliar o alguien del pueblo que suela colaborar en estos casos) y se le abona el servicio mediante transferencia. Sólo tendrían que enviarnos una declaración jurada firmada por la persona que lo realiza indicando los datos y nº de cuenta bancaria de la misma. Suelen cobrar en torno a 8 – 10€/h, dependiendo de cada localidad. Y el desplazamiento habría que hacerlo en taxi, contratando así mismo uno de confianza de la localidad. También se abonaría mediante transferencia aportando factura a nombre de Arturo con nº de cuenta. Por último, para la compra de ropa, y creo que esto ya se explicó en su día, tendrían que enviarnos presupuesto de la tienda donde se quiere adquirir a nombre de tu tío y se abonaría mediante transferencia igualmente. Si esto no fuera posible, por no existir establecimiento en esta localidad, excepcionalmente se podría autorizar un reintegro. En cuanto a la asignación para gastos de bolsillo, se puede autorizar un reintegro semanal/quincenal o mensual en la sucursal de Ibercaja de Los Santos de Maimona, para abonar entre otros los gastos de podología y peluquería, pero necesitamos que nos indiquen presupuesto aproximado de gastos. En cuanto nos digáis mis compañeras de la sección económica, una vez lo apruebe el jefe de la misma enviarían autorización al banco. Pongo en copia a Isabel, Directora de la Residencia, para que esté al corriente." ······································································································································ Llamo a la Residencia Municipal Anotio Zapata - Los Santos M. (924 57 15 35) me intentan pasar con Isabel, Directora, sin éxito. ·················· Llamo al número que nos facilitó Isabel (924 029 563): tampoco obtengo respuesta. ·········································································································································· Envío correo a la secc. ecca: "Porfa, cuando podáis alguna mirarme la situación económica de Arturo Rocha Merchán: saldo actual, cuota que abona al centro y si tiene otros gastos. No pongo en pie por qué no se le llegó a hacer autorización de reintegro periódico para gatos de bolsillo y habrá que hacerle una. Enviarán presupuesto aproximado de gastos de bolsillo desde el centro." ···························································································································································································· Respuesta de Isabel, Directora al correo enviado a Ángela y a ella: "Entendido todo. Nos pondremos en contacto con Teresa, gracias. Con respecto a los acompañamientos, si la familia no pudiera, se actuaría de esta manera. Hay veces que la persona aporta su propio coche y en función de ello, cobra el servicio. ENTIENDO QUE TAMBIÉN SE PODRÍA HACER NO??? En cuanto a la ropa, si hay un comercio próximo a la residencia. Aquí lo ideal sería que Ángela se acercara una de las veces que venga a ver a su tío y pidiera presupuesto de la ropa que desde el centro se le indicara. Aquí es complejo salir, por el trabajo que hay. De cara al pago de Podóloga y Peluquera, ellas contactarían en este caso con Teresa para el abono por transferencia, por tanto, gastos de bolsillo no tendría." ········································································· Reenvío a la Secc. Ecca. correo de la peluquera Rosa María Corrales (rosapelu1986@gmail.com) con nº cuenta para abonar corte de pelo mediante transferencia. ································································ Respuesta de Lourdes: "Con la transferencia de 7€ para el pago de la peluquería nos van a cobrar de comisiones 3,50€. En otras ocasiones, se le ha planteado a la peluquería hacer un bono de unas 5 sesiones, serían 35e, pero igualmente la comisión sería de 3,50€." ······································ Mi respuesta: "Acabo de hablarlo con Maite, ¿lo del bono de 5 cortes de pelo era en este mismo pueblo con esta misma peluquera? Si es así y podéis planteárselo (no tengo número, pero el correo está en el hilo) perfecto. Si no, de momento, por no retrasar más el pago, se abonan esos 7 € y se trata, de nuevo, de hablar la semana que viene con la Directora de la Residencia para que este señor retire una asignación para abonar este tipo de gastos, que sería lo ideal." ·························································································································································································· Situación Ecca. actual: "• El saldo actual es de 14.585,21€. • Su pensión es de 832,80€ (x14) • La cuota del centro es de 624,60€ • Como extras en este año, o ha tenido unos 10 recibos de OAR, con un importe de +-23€, desde noviembre no han vuelto a pasar nada. o Un servicio de podología por importe de 40e en diciembre de 2023. o Un pago de taxi, por importe de 262,30€ en mayo de 2023."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2023-12-21','miguel, tras hablar con el jzgdo de Villafranca pasarme con alguien de registo civil me comenta que le envíe un email: Buenos días Clara, conforme conversación telefónica le adjunto el nombramiento y aceptación del cargo de Tutor de Doña Isabel Moreno Follarat. Necesitamos nos remita el certificado donde quede identificado que la Comisión Tutelar de Adultos ejerce el cargo de Tutor y conforme qué procedimiento, y sentencia… Ruego nos haga llegar por carta certificada dicho certificado a la siguiente dirección: Comisión Tutelar de Adultos (SEPAD) Consejería de Salud y Servicios Sociales Junta de Extremadura Avda de las Américas nº4, 1º planta. 06800, Mérida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2024-01-08','miguel, envío de nuevo email al email que me indicaron mixto1.villafrancadelosbarros@justicia.es: Buenas tardes, necesitaría me confirmaran si han remitido ya el certificado de anotación del cargo de tutor sección 4º Rgtro Civil, que recoja que esta Comisión Tutelar de Adultos es quien ejerce el cargo de tutor de Doña Maria Isabel Moreno Follarat. Les recuerdo que la carta certificada habrán de remitirla, a la siguiente dirección: Comisión Tutelar de Adultos (SEPAD) Consejería de Salud y Servicios Sociales Junta de Extremadura Avda de las Américas nº4, 1º planta. 06800, Mérida Les rogamos la remitan lo antes posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2024-01-12','miguel, me llama Coro 618817695 y me dice que va a darle el tfno a una trabajadora del centro donde está su hna que habitualmente va al jzdo para ver si puede conseguir el certificado que a fecha de hoy siguen sin enviar desde el rgtro civil de Villafranca. ------------------------------------------------------------ Me llama Maria Cadenas, trabajadora social de la Residencia de la Providencia (por indicación de la hna de Coro, Pepa)824903608, María Cadenas >trabajadorasocial@providencia.es>: Tras hablar con ella quedamos en que le envíe los dos emails, el de solicitud de certificado del rgtro civil acreditativo del cargo de tutor de la Ctaex y el de la solicitud de modificación y/o subsanación del Auto de venta que dictaron y fue presentado por el despacho de Santiago Lavado y que fue solicitado hace cerca de 1 año y siguen sin contestar: Buenos días Maria, te adjunto la documentación remitida al registro civil, como verás en los emails de debajo. Te envío también otro email para preguntes por el auto que tenía que modificar el juzgado autorizando las ventas de los bienes inmuebles hace cerca de un año que fueron solicitados. Quedo pendiente de tu respuesta. ------------------------------------------------ Maria, este es el 2º email en relación a la tutelada Maria Isabel Moreno Follarat. Pregunta en el juzgado con este documento, cuánto falta para que nos envíen la resolución firme de esta solicitud que se hizo hace casi un año por el despacho de Santiago Lavado --------------------------------------------------------- Me llama de nuevo Maria Cadenas quién dice haber hablado con Alba del Jzdo quien le indica que en 7-10-23 dictaron diligencia denegando la solicitud de modificación del auto por que se dirigió a un procedimiento que no es el correcto. Llamo a Alba del Jzdo quién me confirma que hay que solicitarlo de nuevo correctamente. Envío email a José Santiago 2981@icaba.com y al procurador Pedro Miranda Redondo predondo@badajoz.cgpe.net Buenos días José, pongo en copia al procurador D. Pedro Miranda Redondo. Acabo de hablar con el juzgado nº1 de Villafranca quien me comunica que el motivo de que desestimaran la solicitud de modificación del Auto de autorización de ventas de inmuebles de la tutelada Maria Isabel Moreno Follarat, es debido a que el contenido de la solicitud era incorrecta ya que no se corresponde con el procedimiento judicial en que se dictó el Auto a modificar. Por favor trasládelo a su despacho para que lo redacten correctamente y lo soliciten de nuevo lo antes posible al juzgado. ---------------------------------------------- En cuanto al certif del rgtro civil lo lleva Clara y hasta el lunes no va según me dice Maria Cadenas, así que el lunes preguntará ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-01-12','Ana: Llamada de José Manuel (627 788 797): Ha estado en su casa un albañil, cree que del seguro de unos de los vecinos. Le ha dicho que la avería es de su casa, algo no hicieron bien con la tubería la última vez que estuvieron los albañiles. ······································· *En cuanto al ingreso en centro, me manifiesta que si no le conceden ingreso en CRR, estaría dispuesto a ingresar una temporada en el CSS, pero en UME o URA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-01-11','Ana: Llamada de Carlos, denota bastante ansiedad, muy enfadado con las vecinas del barrio y propietarias de la Tapicería (Isabel y su hermana), dice que se meten donde nos las llaman y que le retuvieron contra su voluntad en la tienda para que hablara con Mamen, Educadora de Futuex. ··· En cuanto a ésta, dice que siente que le trata como un niño pequeño, que no le deja opinar ni decidir. En la tienda de telefonía no le dejó casi hablar. *Le digo que se lo comunicaré a su coordinadora para que le tenga más en cuenta y no vuelva a ocurrir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2024-01-10','Ana: conversación con Estrella, TS CSS: Me comunica que Conchi va a pasar a la Unidad de Larga Estancia. ····· En cuanto a mi consulta de si procede derivarla al Programa de Apoyo Comunitario - Futuex, lo han valorado en el Equipo Técnico y creen que le puede venir bien. ············· En cuanto pueda haré la derivación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-01-10','Ana: Llamada de Juan José (643 641 375): Sigue acudiendo al laboratorio de la Asociación de la Politécnica. ·················· Ya le ha visitado Nieves, Ed. de Futuex. Todo bien. Enviará presupuesto para mesas de salón, que se le ha roto y para zapatillas. ···························· Dice que ha subido todo mucho, el Butano a 30€, pide una subida de asignación. ········· Cuando cobre a final de mes y veamos cuánto ha subido su pensión, la sección económica valorará cuánto se le puede aumentar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-01-12','Ana: Envío correo a Alberto, jefe S. Ecca: "En relación a JUAN JOSÉ GLEZ. CARRERO, dada la subida del precio de todo (entre otras cosas Butano a 30€) solicita una subida de su asignación. No especifica cuantía. De momento tiene 67€/semana para gastos de bolsillo. Ya me dices en cuánto se le puede incrementar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2024-01-12','AMALA . Miguel solicita I.social y eco para el juzgado para solicitar autorización para hipoteca , no la necesita para la compra al ser curatela. Le he pasado uno del IMSS Badajoz que le sirve . Queda pte. enviarle el Cdo. empadronamiento que he pedido a la hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-01-10','Ana: Llamada de Carlos. Dice que le han dado un cheque de 150€ de Caritas para la adquisición en tienda de artículos de ropa. Ya se ha comprado algunas cosas pero aún le queda 71 €. Fue a comprar la ropa acompañado de Mamen, Ed. Futuex. ························ *Pide Subida de asignación de 5€, le digo que en función de la subida de la pensión podremos valorarlo a final de mes. ································· Me cuenta que estando yo de vacaciones un primo suyo, que iba con otros chicos, le agredió. Ha enviado fotos, informe médico y denuncia. Lo guardaré en el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-01-12','Ana: Tras hablar con Jesús, envío correo a Ángel, Asesor Jurídico (pues faltaba nº cuenta en el contrato): "Aquí tienes el número de cuenta de Jesús: ES50 2103 7679 5700 1002 2400 Porfa, confirma tú a Pedro y envíale el contrato firmado" ······························································································································································································· Envío correo a Icíar y a Maite: "Tal y como hablamos ayer, y tras confirmar con Maite y con Ángel, te confirmo que Pilar Jiménez Aguilar, a partir del mes de febrero se trasladará a vivir a la casa que va a alquilar junto a su pareja en Ahigal. Ella abonará la mitad del coste del alquiler 100 € + 50€ para aportar al gastos de suministros. Para ello será necesario que hagáis una TRANSFERENCIA PERIÓDICA MENSUAL de los 150€ a Jesus Veliz Fernández, pareja de Pilar, desde la que él abonará todos los gastos a Pedro, propietario de la vivienda. Tal y como dijimos ayer al hacer los cálculos, será necesario reducir la asignación de Pilar, a partir del mismo mes de febrero de 80 a 70€/semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2024-01-12','miguel, email de la abogada Eva Mª. Pérez Escarmena >eperezescarmena@icac.es>: Buenos días Miguel, en relación al tutelado Julián Ramón Civantos te adjunto las cartas de pago del ayuntamiento correspondientes a la licencia de obra. Cantidad que estaba pendiente de abonar a María Eugenia la ex esposa del tutelado. Las cartas de pago son totales de la comunidad María Eugenia abonó el importe correspondiente a la mitad de licencia de obras y tasas municipales que se corresponde con el justificante de transferencia por importe de 964,70€, del que ya disponéis. No obstante, os lo adjunto también en este correo. ----------------------------------------------------------- mi contestación: Hola Eva, sólo falta entonces por pagar 964,70€ no? No entiendo entonces los otros dos justificantes de transferencias…Lo que estamos esperando es el documento del Ayuntamiento que acredite esos 964,70€ para hacer la transferencia. ---------------------------------------------------------- contestacion de la abogada: Hola de nuevo, tal y como te explico en el correo anterior no hay como tal justificante de esa cantidad en concreto ya que se dispone de una carta de pago para toda la comunidad. Pagando cada propietario parte de esta cantidad. No obstante el justificante bancario acredita que Maria Eugenia realizó en su día el pago de la licencia en nombre de su ex esposo -------------------------------------------------------- mi contestación: Hola Eva, confírmame si los datos de ella para la transferencia son: Mº Eugenia Copero Sánchez, nif 07424745T, cuenta nº ES 02-2103-2687-4800-3000-0971; importe 964,70€ De todas formas no me cuadra que la suma de lo abonado por tasas al ayuntamiento eran 640,31+1289,09=1.929,40€/4 vecinos=482,35€ cada vecino y el tutelado va a pagar el doble…Esto es porque el de debajo no paga? Confírmame si es así, y dime por favor cuándo vas a reclamar el importe debido al del piso de debajo, pues tenemos que empezar a reclamarle ya, vía judicial si es preciso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-01-12','Ana: Correo-respuesta de Estrella, S. Ecca. a Azucena, cuñada de Juanjo: "Sí, se le autoriza los 100 € para ropa de invierno. Comentarte que ya no se le volverá autorizar otro extra hasta el verano. A partir del martes 16 de enero puede ir a retirarlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-01-15','miguel, envio email a Estrella del CSS Buenos días Estrella, según nos comunicó mi compañera Ana Trabajadora Social, tenemos que ponernos en contacto contigo. Adjunto providencia requiriéndonos el juzgado para que identifiquemos si Enrique Santos Garcia Puente sigue interno, por lo que necesitamos un justificante del Centro indicando desde cuándo se encuentra interno y cómo llegó allí, por orden judicial, o por derivación de la UHB o ESM. Indícanos también si se comunicó al juzgado dicho internamiento o si éste os comunicó algo porque quieren identificar el número de procedimiento de internamiento involuntario. Desde la Comisión no hemos iniciado procedimiento de internamiento involuntario. Y sabemos que está pendiente de una Subcomisión, sabes algo de cuándo será? -------------------------------------------------------- Envío email a Angel y Maite (Ana de vacaciones): Buenos días, adjunto email que he enviado al correo que te dio el viernes Ana. La derivación conforme dice Ana y veo en la intranet… Agosto 23…lo movió creo que Ana Benavente del ESM junto a la Dra Gomez… Desde la Comisión Tutelar de Adultos no hemos iniciado procedimiento de internamiento involuntario como podéis ver en el expte y la intranet. Sólo hemos estado comunicando incidencias estos meses y contestaciones a requerimiento del juzgado dentro del procedimiento de revisión de medidas de apoyo que se dictó por el jzdo de Plasencia. Por otro lado estaba pendiente de una Subcomisión de la cual no sé nada. A ver si desde el CSS nos pueden aclarar algo de si ha habido comunicación al juzgado y si éste dictó una resolución, o confirmó dicho internamiento involuntario... Os he puesto en copia porque sólo estaré hoy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-01-12','contestacion de Ana a la providencia de requerimiento judicial: Ángel! Fue ingreso involuntario, pero practicado por Psiquiatría, primero en UHB y de ahí le derivaron a UME al C. Sociosanitario, sigue allí, pendiente de subcomisión sociosanitaria. Si necesitas algún documento o más infor, pregúntale a Estrella, TS del Socio: estrella.duranc@salud-juntaex.es / 24146','2');
