insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2024-01-15','-Amalia : por el momento lo llevará Ana , luego pasará a mi zona . Ha llamado Ceferino para ver si se le aprobaba el extra anual . Me confirman desde el CRR que era el siguiente : En cuanto a Ceferino, creo recordar que el extra anual fue de 3500 euros. Esta cantidad se repartía en dos periodos (es decir él sacaba 1750 a principio de año y otros 1750 en Julio). Esta cantidad recogía el dinero para vacaciones de verano, aparatos o dispositivos relacionados con su ocupación haciendo música, aparatos o dispositivos de ocio y la compra de ropa, calzado y otros necesarios. Alberto de S. eco tendrá que dar respuesta para ver si se le autoriza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-01-15','-Amalia ; el miercoles pasa al CRR Plasencia . Se traslada desde el CSS en su furgoneta. El extra es de 300€ al mes . Quedamos pte. el extra anual. Respecto al extra anual con Antonio, como bien dices, al no conocerle es complicado estipular el extra anual. Generalmente está relacionado con sus intereses y necesidades. En cuanto tengamos una idea te decimos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='SORIANO'and apellido2='LEAL'),'2024-01-15','-Amalia : Su madre le ha comprado un movil de contrato , el tf es 613713360','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2024-01-16','TERESA CORREO DEL AYUNTAMIENTO DE TRUJILLO Os escribo en relación a Felipe Rodríguez Solís, que está tutelado por vosotros. Ha fallecido uno de sus hermanos, el que ejerció la tutela del mismo y cuidaba de él. Hay un problema con la vivienda y corre bastante prisa que os pongáis en contacto con una de sus hermanas, Mª Carmen Rodríguez Solís, porque el tutelado tiene que realizar algún trámite ya que el próximo 1 de febrero se cumplen dos meses desde el fallecimiento de su hermano y podría perder los derechos sobre la vivienda en que reside. El teléfono de contacto de su hermana Mª Carmen es 693751866. Mi teléfono es 927659391 (extensión 3). Os envío nota simple del Registro, por si os aclara algo. Un saludo. Mercedes Prieto Sánchez Trabajadora Social del SSASB de Trujillo HABLO CON LA HERMANA Y LE FACILITO EL TELEFNO DE ANGEL PARA QUE LE EXPLIQUE LA SITUACION Y VER COMO SOLICITAR LA ANULACION DE LA CLAUSULA, TIENEN DE PLAZO HATA EL UNO DE FEBRERO PARA SOLICITAR LA ANULACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2024-01-16','TERESA mañana operan, como estaba previsto hace un tiempo, a Isabel Cano de la placa del codo. Ha sido hoy cuando nos han avisado, por lo que procedemos a comunicároslo inmediatamente. Previsiblemente pasará en el hospital una noche y al día siguiente regresará a CRR. Está contenta y un poco nerviosa, dentro de lo normal en estas circunstancias. Os iremos contando cómo va todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2024-01-17','TERESA Procedo a informaros que el día de la Intervención es el 24 de Enero de 2024 ,ingresará a las 7:30 h de la mañana por urgencias del Hospital Don Benito Villanueva ,según me indican desde el Hospital ese día es el Primero en el parte de Quirofano . Desde este momento ,ya para el tema de apoyos que necesite durante el ingreso hospitalario la persona de referencia es Lola la Trabajadora Social . Yo ya me he puesto a disposición del Centro por si necesitan cualquier cosa ,mi confianza en el personal auxiliar es plena . Esperemos que todo transcurra sin incidencias y se haga el mínimo daño posible y pronto esté de vuelta . Un saludo y gracias por la diligencia y la atención a Eugenio , buena coordinación y buen equipo,ahora ya ,esperemos quede en buenas manos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2023-12-27','TERESA La pasada semana se acompaña a la cita en el ESM de Zafra a Javier. La doctora le mantiene la medicación, le va bien. El día 29 le toca el inyectable. Ha venido con su padre en ambulancia, mientras esperan se va con ambos a tomar un café.Javier, su padre, cuenta que sigue habiendo consumo, reducido porque no dispone del dinero que le gustaría, pero lo hay en cuanto puede. En casa es un caos, no limpia, no se asea, no ayuda a nada… La medicación la va tomando más o menos, pero hay días que se las salta, su padre ya no puede controlarle eso porque no le hace ni caso. Cuenta que ha tenido momentos en los que se esnifaba las pastillas, ahora cree que no lo hace. Comentaba también su padre que se está encargando él de pagar la denuncia por la agresión a la trabajadora en Mérida. Pide que, por favor, lo haga la comisión desde la cuenta de Javier. No sabemos porque no lo paga con la asignacion mensual, que se recibe, o si tendria que replantearse eso, para pagar la denuncia o como mejor valoreis. Se adjuntan las imágenes que ha enviado sobre el requerimiento, donde aparece cuantía, número de cuenta y toda la información necesaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2023-12-28','TERESA Estoy pendiente de que me envíen de Radiodiagnóstico el consentimiento informado para la TAC de Eugenio . El consentimiento,ha de firmarlo el tutor legal del paciente ,como sabéis . Paso a informaros de las consultas de Enero: Viernes 5 de Enero 9:45 h TAC en Hospital Don Benito. Viernes 5 Enero 2024 11:00h Digestivo CEXT Hospital Don Benito. Viernes 12 Enero 2024 Consulta Anestesiología y Reanimación 13:00h Hospital Don Benito ( Preoperatorio) ,aquí habrá que firmar los consentimientos de la intervención y se valorará el riesgo quirúrgico de la misma ,se puede preguntar al anestesista sobre aquello que se considere oportuno por parte de las familias / representantes legales . Martes 16 Enero 2024 11:30 h Nefrología Hospital Don Benito Villanueva . Ayer día 27 estuve con el en Hospital Siberia Serena a Ecografía . Mi teléfono de empresa es 690040568 y si es de necesidad el particular 680517737 . Cómo sabéis ,y si no os resumo Eugenio tiene una suma de patologías que lo hacen un paciente con un futuro incierto a corto medio plazo . Además de su enfermedad crónica hepática ,se le suma su insuficiencia renal crónica ,ambas en seguimiento por los respectivos especialistas del SES que lo están tratando a lo cual se le suma su polimedicacion debido a los trastornos de conducta asociados a su discapacidad .Les remitiré los respectivos informes de las actuaciones y actos clínicos que recibe el paciente y las comunicaciones que me transmitan los facultativos que lo asistan','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2024-01-18','TERESA Hola Teresa, te escribo porque Bea está empeñada, como ya te habrá sin duda comentado ella misma, en hacerse depilación láser. Desde aquí no se la va a estar llevando para hacérsela. Tendrá que ser, si se lo autorizáis, cuando vaya saliendo de pase. Así que yo te lo comento porque ella me lo pide; ni sé precios ni nada, aunque sí sé que hay medicación con la que no se puede hacer, y ella toma algunas cosas, evidentemente; pero miedo me da decírselo, porque es muy capaz de dejar de tomársela para poderse depilar. No sé qué perspectivas habrá de una posible alta, ni de qué manera se podrá hacer, sinceramente. Ella está convencida de que va a poder volver a su piso. Como tú ya sabes de sobra, es una persona muy complicada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2024-01-18','TERESA Comunicarte que, con relación a Sebastián Paredes Dicha y al informe de evolución de fecha 4 de enero, en el día de hoy en torno a las 12:40 hemos sido informados en el Centro, por parte de un familiar de otro residente, que el mismo se encontraba caminando por la N-630 en dirección a la localidad de Almendralejo. Inicialmente hemos intentado contactar con él a través de su teléfono móvil, resultando infructuoso; no atendía la llamada a pesar de dar los tonos adecuadamente. Seguidamente, por parte de esta Dirección, se ha contactado telefónicamente con el Puesto de la Guardia Civil de Villafranca de los Barros para informarles de la situación. Han dado aviso a sus efectivos, quienes una vez lo han localizado han contactado telefónicamente, exponiendo que no podían trasladarlo sin su consentimiento. Han facilitado en el transcurso de la conversación con él que desde esta Dirección se le pudiera orientar para que fuera acompañado al Centro por dichos efectivos. Su intención era continuar en dirección Badajoz. Finalmente, han podido acompañarlo de regreso al Centro, habiendo llegado con él a un acuerdo. Una vez en el Centro, tras valoración por parte del Médico ha sido derivado al Servicio de Urgencias del Hospital de Mérida. Muestra su disconformidad con permanecer en este Centro, y en estos momentos, trabajar el campo es su único centro de interés, llevándole a incurrir repetidamente en conductas de riesgo para él. Entiendo que es importante valorar su situación actual y el recurso más adecuado a sus necesidades actuales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2024-01-18','Buenas , se aprueba la nueva propuesta económica : OK A SUBIR REINTEGRO A 600 €/MES DESDE 01/02/2024 + UN MÁXIMO DE 452 € EN JUNIO Y 452 € EN DICIEMBRE + NO SE AUTORIZARÁ NINGÚN EXTRA DISTINTO DURANTE 2024. Podéis gestionarlo para empezar en febrero. Con respecto a la consulta del tf , su hna. le ha regalado uno . Tiene un contrato de 8/9€ al mes máximo domiciliado.','2');
