insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='VALERO'and apellido2='AGUEDO'),'2024-01-18','Amalia : informo sobre sus gastos a S. eco. Natalia está en un centro de menores , hablé con el director y no hay copago en estas plazas . Además intentarán cubrir desde el centro todos los gastos que sean posible , incluido los reintegros . Sólo van a solicitar algún gasto extra como este de dentista que ellos no pueden cubrir . Iciar confirmó que le han ingresado la retroactividad de la prestación que le tramité . " Le he comprobado la cuenta y el 11 de diciembre le han entrado 906,60 € de la TGSS" Cuenta con esos ahorros y los ingresos mensuales de la prestación. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2024-01-19','Angel : Para las rentas que deban actualizarse en 2023, como es el caso, puesto que cumple el año en diciembre de 2023, la subida está limitada al 2%, aplicable a partir de febrero del 24. Para este año 2024, la subida está limitada al 3%. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='GONZALEZ'and apellido2='ESCASO'),'2024-01-19','Amalia: en carpeta pensiones de su expediente está el documento suspension pension . Pendiente que enviemos a PNC nominas de 2023( pedidas al centro ) y D. Renta ( pedida a Estrella )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2024-01-19','Buenos días, La revisión de medidas de Damián, determinó que no se mantenga ninguna medida de apoyo al mismo y por lo tanto, se deniega el establecimiento de medidas de apoyo. Os envío la sentencia, de fecha, 10/01/2024. La sentencia no es firme. Julio, una vez sea firme, hay que archivar este procedimiento. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-01-22','Ana: correo de Estrella Durán, TS CSS - Plas. a Miguel el viernes 19: "Como sabréis, ayer ingresó en este centro socio-sanitario de Plasencia, José Manuel Romero Mediavilla. Éste venía acompañado por una Educadora Social de Futuex, Nieves. Nos informó de que el martes día 23 de este mes tiene un juicio en Cáceres. Yo le pedí que fuese la Fundación quien lo acompañara, ya que no disponemos de conductor para hacer el servicio. Contesta que tenemos que ponerlo en vuestro conocimiento que ella no dispone en este tipo de cuestiones. Mi teléfono es 927428800." ···························· Hablamos con Estrella hoy y con Toni-Futuex. Finalmente José Manuel acudirá en taxi y le acompañará Clara, Ed. Futuex de Plasencia. Ella gestionará también un taxi. ···················· Ante el desconocimiento del nº de Jdo, nº de procedimiento y más información al respecto, Ángel, A. Jurídico realiza varias llamadas. ···· Finalmente envío correo a Estrella - CSS y Toi-FUTUEX: "En relación al supuesto juicio de José Manuel Romero Mediavilla de mañana, nuestro compañero Ángel, Asesor Jurídico, ha estado llamando insistentemente al nº de teléfono que le ha facilitado José Luis, hermano de José Manuel, para informarse del juicio rápido, pero no ha obtenido ninguna respuesta. Por tanto, y siguiendo indicación de Ángel, se ha decidido que José Manuel no acuda mañana al Juzgado y esperar a que le vuelvan a citar. Pues tampoco sabemos si debe llevar abogado ni si debe estar presente el Asesor Jurídico del Gabinete Técnico de la CTAEx. No nos parece conveniente realizar ese desplazamiento desde Plasencia a Cáceres y retorno, con su correspondiente gasto, para que pueda ocurrir como en ocasiones pasadas que se lo ha pospuesto por dichos motivos. Ante cualquier otra cuestión, seguimos en contacto." ·········· Nuevo correo a Estrella y Toni: "Os cuento novedades, Ángel finalmente, llamando a la Oficina de Denuncias de la Policía y al Juzgado de Guardia, ha conseguido averiguado que se trata del Juzgado de Instrucción nº 2 de Cáceres. Puesto que ingresó la semana pasada en el C. Sociosanitario, le han pedido que lo comunique por escrito al Juzgado y suspenderán el juicio hasta nueva citación. Estrella, por favor, remítenos Certificado de Ingreso en UME para poder adjuntarlo al escrito." ······························································································································· Tras hablar de la situación ecca. de José Manuel con Estrella, TS CSS, envío nuevo correo a Toni-Futuex: "Desde el C. Sociosanitario nos comunican que en estos momentos andan muy justos de personal y como José Manuel es autónomo y cuenta con el apoyo de vuestro Programa, solicitan que la educadora le acompañe al banco a retirar su asignación (excepcionalmente mañana de 80 €, pues ya se ha gastado el reintegro quincenal y allí no lo quieren tener sin tabaco) y luego de forma mensual, se va a enviar autorización mensual a la Oficina de Alfonso VIII de Plasencia, abierta del 1 – 10 de cada mes, para que retire 300€/mes y los entregue en Admisión del C. Sociosanitario para que se lo administren. Confírmame porfa que mañana podrá ir la educadora con él. Y disculpa la premura."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2024-01-22','Amalia : Natalia está en un centro de menores , hablé con el director y no hay copago en estas plazas . Además intentarán cubrir desde el centro todos los gastos que sean posible , incluido los reintegros . Sólo van a solicitar algún gasto extra como este de dentista que ellos no pueden cubrir . Iciar confirmó que le han ingresado la retroactividad de la prestación que le tramité . " Le he comprobado la cuenta y el 11 de diciembre le han entrado 906,60 € de la TGSS" Cuenta con esos ahorros y los ingresos mensuales de la prestación. Se autoriza el tto. dental .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-01-22','Buenas tardes, a continuación informamos, sobre gestiones relativas a Gustavo Castaño, (envio a ambas ya que no sé con exactitud a quien corresponde el caso) Se realizó visita al domicilio donde residirá Gustavo Castaño a mediados de febrero (a partir del 15) cuando vuelva a Cáceres después de su estancia en la cárcel. La visita al domicilio de Gustavo ha sido para comprobar en qué estado se encuentra y qué mobiliario hace falta para que sea un espacio habitable en el momento que vuelva Gustavo. Se adjunta información sobre esto donde se especifica todo lo observado acompañado de las fotos tomadas a todas las estancias de la vivienda. Esta pendiente recabar información de presupuestos para mobiliario, ya que lo ha realizado su madre, es bastante elevado (en torno a 2000 euros, en diferentes muebles y electrodomésticos) Hace pocos dias, comunica la madre de Gustavo que a su vuelta definitiva a Cáceres será necesario contratar a un notario para gestionar las escrituras del domicilio donde va a residir. Esta vivienda fue comprada por ella hace mucho tiempo y la puso a nombre de sus cuatro hijos, pero en ese momento tanto Gustavo como su hermano eran menores, por lo que no tenían ningún tipo de poder. Quieren que ambos consten como propietarios en las escrituras, por ello va a realizar esta gestión con un notario de cara a la vuelta de Gustavo el 15 de febrero. Pide a la educadora que le explique a Gustavo de qué se trata esto y le convenza, dice que es muy desconfiado. Se le indica que se traslada a la comision puesto que se trata de un asunto júridico que deberan considerar los profesionales especificos de dicha comisión. Para visitar el docmicilio se quedó con la persona que trabaja limpiando en el domicilio de la madre de Gustavo y tambien este inmueble, para ir a visitar la vivienda donde residirá Gustavo a partir del 15 de febrero cuando vuelva del centro penitenciario de Sevilla. El domicilio está ubicado en la C. Ramiro de Maeztu, número 12, 4D, es una vivienda familiar, anteriormente residía uno de los hermanos de Gustavo pero hace 3 años aproximadamente se mudó y por eso está vacía actualmente. La vivienda está en muy buen estado, pero está sin amueblar y hace falta una limpieza profunda debido a que lleva mucho tiempo cerrado. De esta limpieza se encargará Toñi, que ya trabaja con la madre desde hace más de 10 años. Es necesario también pintar las paredes, algo que ya han gestionado entre ellas dos con un pintor que conocen, será la madre la que se haga cargo de estos gastos, así como también será ella quien le compré un sofá y le dé una televisión, una mesa y todo lo relacionado con ropa de cama y toallas. Segun indican, habría que presupuestar varios electrodomésticos de uso habitual además de la cama, segun el criterio de la familila, Los electrodomésticos que faltan en la casa y serían necesarios son: un frigorífico, una lavadora, un microondas y la vitrocerámica, además de la cama (somier y colchón). Los más importante además de hacer el espacio habitable con el mobiliario es gestionar el servicio de ayuda a domicilio y un catering. Respecto al catering, hablando la otra vez con Gustavo conocía los servicios del catering Mesa y Mantel, que ya se ha trabajado anteriormente con ellos y es de los más económicos, por lo que se propone este catering (se adjuntara presupuesto). En cuanto al SAD, hablando con Toñi ha comentado que ha trabajado anteriormente para el IMAS, plantea la posibilidad de hablar con las coordinadora y preguntarles si es posible darle a ella de alta para trabajar en el domicilio de Gustavo. Se valora favorable esta propuesta pero desconocemos en absoluto si es viable y si tiene la formacion pertinent (creemos que ha trabajado con anterioridad en el sad)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-01-22','Ana: Envío correo al PAF (programafamilia@tajosalor.es): "1º Comunicaros que Aitor, si no surge nada raro, ingresará con Autorización Judicial de Internamiento Involuntario en el Centro de Plena Inclusión Mérida. Será a partir de la semana que viene, pero aún no nos han confirmado fecha. Os lo confirmaré. Por tanto, una vez haya ingresado, si lo consideráis en el programa oportuno, podréis retomar vuestra intervención con Felisa. 2º a petición de mi compañero Ángel, Asesor Jurídico, y tal y como pide el Juzgado, os solicito Informe relativo a Felisi, en los términos indicados a continuación, para presentar en el procedimiento de Revisión de Medidas Judiciales de Apoyo: “Discapacidad que presenta. Ámbitos y extensión que resulten afectados por su discapacidad y necesidad de apoyo. Situación familiar y asistencial. Cualquier consideración que estimen conveniente sobre él en razón al procedimiento judicial de revisión de medidas de apoyo.” Os lo solicitamos a vosotras puesto que, entendemos que sois el recurso de proximidad que mejor conoce a Felisi, su situación así como su trayectoria. Por favor, confirmadme si vais a elaborarlo y a enviárnoslos, pues al Juzgado tenemos que contestarles sí o sí." ··············································· Respuesta del PAF: "Con respecto al informe no podemos darte esa información porque no la sabemos. No tenemos los informes de la discapacidad de Felisi ni sabemos cuando han sido las últimas revisiones. Entiendo que tanto esto, como los ámbitos que resultan afectados por la discapacidad y las necesidades de apoyo deben valorarlo desde dependencia o CADEX. Nosotras con Felisi, a no ser cuando hemos hecho compra con Aitor, hace mucho que no trabajamos porque tanto acompañamiento a médicos como sacar dinero y demás lo hacía la anterior compañera de FUTUEX, a no ser que tuviese vacaciones que nos coordinábamos y le acompañábamos nosotras. Sentimos no poder ayudaros."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2024-01-22','Ana: Reenvío correo de la Res. Banium Residencial a Alberto, jefe S. Ecca: "Te reenvío correo sobre subida de tarifa del C. Residencial relativo a CONCEPCIÓN BARBERO SÁNCHEZ. Si es viable y todo está correcto, hay que ponerlo a la firma devolvérselo firmado al centro por esta misma vía, tenéis el correo del centro a continuación." ········································································ Correo de Alberto a Lourdes, S. Ecca: "PASAMOS A FIRMA EL ANEXO DEL CONTRATO Y SE LO REENVIAMOS + ARCHIVAMOS NUESTRA COPIA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-01-22','Amalia , envio a S. eco : sale el 15 de febrero del Ctro. penitenciario de Sevilla. Se va acondicionar una vivienda en bastante buen estado de la familia pero que faltan electrodomésticos y algo de mobiliario . Se ha pedido un pto. y serían en torno a 2000€ . Tiene más de 15.000€ ahorrados , se le compraría de ese dinero . He pedido que las facturas se dividan en 2 o 3 plazos para evitar tener que pedir autorizaciones judiciales . Tiene una P. Orfandad de Clases Pasivas de 763€ . Se le puede hacer un reintegro de 600€ al mes para gastos de alimentación , higiene , ocio .. y guardar 163 para suministros de agua , luz .. . El S. decesos lo abona la madre . Se le puede ir haciendo el reintegro de 600€ para el 19 de febrero , y el resto de meses para retirar entre el 1 y 15 de cada mes . Se va a valorar contratar un par de horas de limpieza para mantener la casa limpia . No se puede solicitar por dependencia , ha dado sin grado . Planteo contratar un par de horas semanales , hay una chica interesada que va a casa de la madre y eso se abonaría de ahorros . No más de 100€ al mes .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2024-01-22','Ana: Envío correo-respuesta a Alberto y Estrella, S. Ecca., sobre los recibos que han cobrado a Pilar por su cuenta correspondientes al vehículo del hijo: "Desde la sección social se decide dar un plazo de 2 semanas a Abraham para que regularice su seguro de coche (debe abonarlo él, no su madre. Y lo domicilió por su cuenta sin haber consultado aquí nada al respecto, al igual que el impuesto de circulación). Mañana le llamo para comunicárselo. Si en dos semanas no lo ha modificado se devolverá el seguro del coche. *Recordad que abril habrá que estar pendiente de que no le pasen el Impuesto de Circulación, pues en tal caso habrá que devolverlo también."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2024-01-23','Ana: Reenvío a Ángel, A. Jurídico CTAEx, INFORME + Relación de Incidencias remitidas por el CRR para la Revisión de las Medidas Judiciales de Apoyo. ················· Guardo ambos en el Expte. digital. ····················· Juan Mario continua con el consumo diario de alcohol y bebidas azucaradas de cola y energéticas, con su patología de Diabetes M. Tipo II. Además del consumo esporádico de cannabis. Fue derivado al ECA, pero no acudió a las consultas ni a los controles.*No tiene conciencia de su enfermedad ni de situación actual así como de la incidencia en su estado de salud. ····· Presenta síntomas psicóticos positivos y alteraciones cognitivas que que afectan de manera significativa a su independencia funcional. ···· En estos momentos aspecto de abandono, descuido de su higiene e imagen y conductas desorganizadas y disruptivas. ···· Realiza venta, dentro y fuera del centro, de objetos de dudosa procedencia. Existen sospechas de hurtos en el recurso. ···· *Desde el CRR plantean la necesidad de buscar alternativa de recurso residencial. ···························································································································································································· Guardo en el expte. y reenvío también a Ángel, A. Jurídico, Informe de Seguimiento del ESM-CC, solicitado también para revisión de las medidas. ································································································································································································· En relación a la persistencia de inciencias en el CRR y al último ingreso en UHB, envío correo-respuesta a Sheila y añado a Eva, Raquel y Mariluz, Secc. Salud Mental - UPA, con copia a Maite, Jefa CTAEx: "Esto ya lo hemos hablado en otras ocasiones, pero dada la situación, cada día más insostenible, la reiteración de incidencias y el riesgo que supone sus conductas, tanto para el propio Juan Mario como para el resto de residentes e incluso para el personal del CRR, en mi opinión, sería conveniente convocar una subcomisión para valorar y plantear alternativas. Dado que desde la CTAEx nosotras no podemos pedirla/convocarla, si estáis de acuerdo, ya me decís cómo podemos proceder."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2024-01-23','TERESA El otro día tuvo el juicio, o más bien no lo tuvo, del tema de Valencia cuya citación os mandé, por videoconferencia. Habló con la abogada de oficio, y ésta veía que lo mejor era admitir la culpa, pero como hay otro implicado que no se presentó, no se pudo llegar a un acuerdo sobre la marcha. Así que, tal como la abogada le aconsejó, con la juez se acogió a su derecho a no declarar y el juicio quedó pendiente para más adelante','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2024-01-18','Ana: Correo de Sheila, Directora CRR (crr@grupociudadjardin.com): "Comunicar el ingreso en la UHB de Cáceres de la persona usuaria JUAN MARIO SAN ROMAN BLASCO por desestabilización de su patología de base, a fecha viernes 17 de enero de 2024. Fue necesario activar protocolo en dos ocasiones en el día de ayer, por lo que rogamos que se valore la situación y búsqueda de un recurso que se ajuste a sus necesidades."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2024-01-23','Ana: Amalia envía al centro CI par COLONOSCOPIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-01-23','Ana: Alberto, Jefe S. Ecca. solicita a Estrella que contrate seguro de deceso ajustado a sus posibilidades eccas. ································································································································································································· Correo de Ángel en relación al contrato de alquiler: "Ya hemos firmado el contrato. Empieza el 25/1/24."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2024-01-23','Ana: Correo de Cristina Hdez, TS CSS-Plas (cristina.hernandezca@salud-juntaex.es): "te informo que a la paciente Mª Teresa Nevado Martin le hemos solicitado 300€ junto con los gastos de bolsillo para ropa, ella elige y ve las tiendas que le gustan. Cuando miremos ropa y compremos mandaré los tickets escaneados."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-01-23','Ana: Llamada de Ángel Félix (643 622 174): se tiene que marchar de la vivienda en la que le tiene acogido. Y tiene que devolver el móvil que el propietario de dicha vivienda le tiene prestado. **Solicita de nuevo la compra de un móvil (no llegó a enviar presupuestos pues dice que en Electrocash le han puesto problemas) y alquilar una habitación en piso de alquiler compartido. ····· Además su hermana está grave en la UCI con Insuficiencia Respiratoria. ···························· Correo de Yéssica, TS Cáritas, informando también de esta misma situación. ··························· A ambos les digo que pediré a Futuex de forma urgente que le visiten y le apoyen en ambas gestiones. ··· Él aunque en principio se muestra reacio, finalmente acepta este apoyo e intermediación. ·················· Envío correo a Toni- Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='VALERO'and apellido2='AGUEDO'),'2024-01-16','Buenos días , le escribo desde la Comisión Tutelar de Adultos , y como curadores de Natalia Valero se acepta el pto. dental que nos han remitido. He hablado con Miriam para fijar los primeros pagos y se ha determinado : estudio 100€ cantidad inicial 600€ Se hará un primer pago total de 700€ por transferencia bancaria . Se hará mensualmente una transferencia de 68€ que se irá valorando cada seis meses hasta completar el tratamiento. Al final se abonará la funda retenedora de 160€ . Necesitamos que nos indiquen el Nº de cuenta donde hacer la transferencia. Gracias . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2024-01-23','Ana: Envío correo a Gema, Directora Res - Cedillo (gemamg.asoma@gmail.com) con CONSENTIMIENTO SUJECIONES, (cinturón silla y barandilla cama) firmado por la Presidenta CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2024-01-23','Ana: Correo de Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com) a mí y al ctutelar@: "Mª del Carmen Mellado Guardabrazos solicita acudir el fin de semana a su pueblo (Hoyos) con su pareja (Francisco Luis Padilla, residente de la asociación) para ver a su familia y llevar los regalos de Reyes a su sobrino. También aprovechará para estar en la Fiesta de la matanza que se celebra anualmente. Sería del 26 al 29 de enero y con el siguiente presupuesto: - Taxi 100 € - Hotel 150 € - Manutención 90 € - Dinero de bolsillo 60 € TOTAL SOLICITADO: 400 € A la espera de autorización o no a dicha salida del centro residencial." ··························· Respondo que, si es viable económicamente, por parte de la secc. social OK.','2');
