insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2024-01-24','Ana: Llamo al CRPS de Cáceres (927 23 21 06): Jorge Rojo, TS no se encuentra hoy. Me pasan con la Coordinadora, Ana Belén Roncero. Me informa que le dieron el alta en el CRPS por estabilidad Clínica y cumplimiento de objetivos en 2020. Estuvo participando como usuario desde Octubre del 2015 hasta Sep/2020. ·········· Me enviará hoy mismo documento de ALTA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-01-24','AMALIA . PLAN DE INTERVENCION A NIVEL ECO ENVIADO POR ALBERTO: REINTEGRO PUNTUAL 600 € ENTRE 19/02 Y 23/02/2024. REINTEGRO PERMANENTE QUINCENAL X 300 € A PARTIR 01/03/2024. ABONO ELECTRODOMÉSTICOS Y MOBILIARIO...TAL Y COMO TE LO VAYA INDICANDO AMALIA...EL LÍMITE APROX. ESTÁ EN LOS 2.000 €. OBSERVACIONES: COBRA 763 €/MES ---- AMALIA INDICA QUE AHORRAMOS 163 €/MES DE SU PAGA PARA CONSUMOS MENSUALES....LO COMPROBAMOS CADA 6 MESES APROX. OBSERVACIONES: MADRE VA A ABONAR LA PINTURA Y LIMPIEZA INICIAL DE LA VIVIENDA + IMPUESTOS Y SIMILARES. ESTRELLA: SEGURO DECESO: AMALIA INFORMA DE QUE EL SEGURO DE DECESO LO ABONA LA MADRE...ESTRELLA...OBTÉN LA INFORMACIÓN/DOCUMENTACIÓN QUE CONSIDERES OPORTUNA. AMALIA: AYUDA DOMICILIO 2 HORAS/SEMANA ---- ORGANÍZALO COMO TU VEAS, PERO, EN CÓMPUTO ANUAL, LA EVOLUCIÓN DEL SALDO SIEMPRE DEBE SER "0" O "+". TIENE 2 PAGAS EXTRAS + LOS 163 €/MES QUE AHORRAMOS TRAS REINTEGRO. OBSERVACIONES (AYUDA DOMICILIO SIEMPRE DEBE SER CON CONTRATO...TUTELADO ESTUVO EN CARCEL X HABER AGREDIDO A LA PERSONA QUE EN AQUEL MOMENTO SE ENCARGABA DE LA LIMPIEZA DE LA VIVIENDA QUE EL OCUPABA.','2');
