insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2024-01-25','Ana: Envío a Cristina, Ed. Vera (educadorasocial@asociacionvera.com) CI para ANESTESIA, firmado por la Presidenta CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESSICA ESPERANZA'and edp.apellido1='LEON'and apellido2='ENCINAS'),'2024-01-24','Ana: en relación a la APERTURA DE CUENTA BANCARIA PENDIENTE, reenvío a Alberto correo de noviembre y añado: "En relación a JESSICA ESPERANZA LEÓN ENCINAS, teníamos esto pendiente (subrayo en el hilo). Necesito saber si ya lo tenemos para solicitar la PNC. No queríamos hacerlo con la cuenta del Santander. Los ideal, por si aún no se ha abierto ninguna, es que sea en UNICAJA, pues es la entidad bancaria que hay en NUÑOMORAL, localidad de residencia. Por otra parte, ¿tenemos ya acceso a dicha cuenta del Santander?? Jessica sigue sin reintegro para gastos de bolsillo y nos lo reclaman desde el centro. Ya me decís cuando podáis."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2024-01-24','Ana: Llamada de Ángela- Placeat (637 765 025): "Juan José ingresó la semana pasada. A priori bien, pero luego se sintió tan agobiado (rasgos autistas) que al insistirle 2 educadoras para que pasara al comedor les agredió (una bofetada a cada una). Desde ese día no ha vuelto a agredir y parece que se va adaptando bien. ······ Está participando a diario en el Taller de Carpintería, parece gustarle y acude contento. ············ De momento está yendo todo los fines de semana a casa por insistencia del padre. *Según evolución se mantendrá o no. ·················· Facilito a Ángela la información sobre la pensión que percibe (PNC) y el nº de cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESSICA ESPERANZA'and edp.apellido1='LEON'and apellido2='ENCINAS'),'2024-01-24','Ana: respondo correo a Mónica, TS de Mensajero de la Paz - Nuñomoral (tsocialcrf@mensajerospazex.es): Desde el INSS, tras solicitarlo nos enviaron certificado comunicando que percibiría la PFHC a partir del día 01/01/2024. Entiendo que el primer ingreso será efectivo a partir de mañana. De momento la va a cobrar en la misma cuenta en la que cobraba la PFHC como menor. Banco Santander. En cuanto a la PNC no la he solicitado porque mis compañeras de la sección económica, no sé por qué aún no han podido abrirle cuenta nueva. Yo le pedí al jefe de dicha sección en noviembre que me facilitaran el número de nueva cuenta en cuanto lo tuvieran. Ya les he escrito para que me aclaren que ha pasado e intenten solucionarlo. Igualmente, he pedido que intenten solventar el hecho de que Jessica aún no tenga asignación de bolsillo, pero me consta que esto es complicado pues con el Santander siempre tienen muchos problemas para operar… te informo en cuanto me confirmen. Por cierto, una vez que esto esté solventado, sí que será mi compañera Teresa la que continuará con el seguimiento y el resto de gestiones pertinentes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-01-24','Ana: Tras hablar con Rosana, Directora Res. Alcuéscar, llamo a María, hija de Joaquina (871 114 458): sin éxito. ································· Envío correo a la secc. ecca.: "En relación con JOAQUINA MAYORAL PIZARRO, entiendo que ya tendremos acceso a las cuentas. Os reenvío correo de Rosana, Directora de la Residencia de Alcuéscar. Por favor!! ¿Podéis ver lo de los servicios de acompañamiento médicos que se deben desde que ingresó en este centro (como antes era curatela pero NO económica, no teníamos acceso, ahora es curatela representativa) y la posibilidad de hacer autorización para gastos de bolsillo? No se le está dando nada por el mismo motivo que no se abonaron los acompañamientos. En el correo aparecen los datos de contacto de Rosana. Habría que mirar cómo está la cuenta, y en función de sus ingresos y el abono al centro, ver qué cuantía se le puede autorizar y si en Alcuéscar hay oficina de su entidad bancaria para la retirada de efectivo. *Por otra parte, en conversación telefónica, Rosana me informa de que le ha llamada la hija de Joaquina, con la que yo no he conseguido hablar esta mañana, y le ha dicho que a la anterior Auxiliar de SAD (Miajadas) se le ha hecho un ingreso indebido de 400€, ¿Podríais comprobar si ha sido desde la cuenta de Joaquina? A mí me extraña un poco porque el servicio lo paga normalmente la empresa, pero no sé si será por el apoyo/acompañamiento que hizo antes de ingresar en la resi, sin estar ya contratada por la empresa, no sé, ya me decís si veis algo extraño." ···························································································································································································· Rosana me remite por mail TARJETA SANITARIA y DNI escaneados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA ISABEL'and edp.apellido1='ARGUELLO'and apellido2='CABALLERO'),'2024-01-24','-Amalia , está en CSS Mérida , ya han enviado I. S. Tiene discapacidad intelectual , contactaré con las TS para que una vez compensada pueda pasar a un centro de discapacidad. Presentó una denuncia a un compañero del CSS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-01-25','Ana: correo de ayer tarde de Azucena, cuñada de Juanjo (azuydavid153@gmail.com): "Hola sigue la plaza de juanjo para el centro cuando podéis me decís porfabor" ············································································· Mi respuesta: "Como ya te explicamos Maite y yo, había un plazo para aceptación de la plaza que ya finalizó. Dado que no aceptó la plaza en su momento, ya la ha ocupado otra persona. Por tanto, os recordamos que si de nuevo quiere ingresar tenemos que volver hacer la solicitud e iniciar el procedimiento de solicitud otra vez. Después pasará a la lista de espera hasta que quede otra plaza disponible y se la ofrezcan para ingresar. Por favor, confirmarnos si Juanjo quiere que hagamos de nuevo la solicitud de centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2024-01-25','Ana: Envío a Cristina, Ed. A. Vera, la autorización de salida para ir a su pueblo firmada por la Presidenta de la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2024-01-23','TERESA EMAIL DE TONI FUTUEX creemos firmemente que algo trata Lorenzo y algo debe haber hecho. Porque ningún profesional de la localidad esta al tanto de nada.. Lo que hemos averiguado en la localidad es que ayer se inció por la tarde, una llamada (no se sabe de quien ) a 112 y que la médico que estaba de guardia inicio el 112, luego hemos recabado un documento sobre el internamiento.. en el que se postula como defensor Lorenzo. Desconocemos si esto es asi realmente (o si Adolfo ha tenido procedimiento de revision de medidas y ha cambiado su situación júridica) . Esos documentos nos lo ha dado el. Que el dice que la ley a cambiado y que el quiere ser el tutor de su hermano y no se que.. él dice que, que no tiene ni idea quien ha llamado al 112, sin embargo sabe la hora y tiene datos que resultan extraños, él comenta que le han dicho que va a estar pocos dias para estabilizarlo.. es que es todo bastante raro. Nadie refiere que haya tenido una conducta significativamente diferente a las que estaba teniendo. Y es cierto que el comportamiento de su hermano es un poco extraño. Se ha anulado el catering, que es lo que me comentabas. Pero Lorenzo habia pedido comida, aun sabiendo que no esta alli su hermano.. hemos avisado al catering de que no le lleve nada sin estar Adolfo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2024-01-24','Ana: Recibimos el CDO. de PFHC que solicité en noviembre. ···· Guardado en su expdte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-01-25','TERESA CONTACO CON LA COMUNIDAD TERAPEUTICA DE CARITAS VICTOR: 672159498 CENTRO HERMANO: 607140783 VMARTINEZ.CDMEBA@CARITAS.ES LE ENVIO CORREO PORQEU NO CONSIGO CONTACTAR CON EL PIDIENDO INFORMACION PARA EL INGRESO EN LA COMUNIDAD TERAPEUTICA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2024-01-25','TERESA TRAS ALTA EN LA UHB DE MERIDA ES TRASLADADA AL CR HOSPITAL SANTIAGO DE ZAFRA TRAS SU LLEGA SE HA PUESTO A PEGAR A LAS RESIDENTES Y HAN ACTIVADO EL 112, SE ENCUENTRA INGRESADA EN EL HOSPITAL DE ZAFRA A LA ESPERA DE TRASLADO A LA UHB DE LLERENA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-01-25','TERESA Desde el equipo de apoyo social comunitario, sobre el caso Marta Rivera Núñez, en seguimiento efectuado está semana, constatamos que actualmente se encuentra en proceso para retirar el implante con la intención de quedarse embarazada. En relación con la situación actual de Marta, informar que reside en el hogar de sus suegros junto a su pareja, en Cabeza del Buey, debido a que han sido desahuciados de una vivienda en régimen de alquiler. Cabe destacar que, en la actualidad, Marta no mantiene comunicación con su madre ni con sus hermanas. Es importante señalar que, carece de un número de teléfono propio y responde exclusivamente al dispositivo móvil de su pareja. Asimismo, es relevante mencionar que Marta se encuentra en un proceso de indagación y recopilación de información con el fin de revocar la tutela vigente, como sabeis, con la aspiración de asumir responsabilidades autónomas. Aunque está participando en consultas con la matrona, hasta la fecha no se dispone de evidencia concluyente que indique un estado de embarazo. De acuerdo con la información proporcionada por Marta, refiere tener programada una cita para el día 7 de febrero en el servicio de planificación familiar, con el propósito de llevar a cabo la retirada de su implante contraceptivo. Esto lo puede hacer ella por su cuenta??','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-01-25','Ana: Llamo a Lourdes Pérez Ortega, TS - IMAS (927 212 335 Ext 4425): en relación al TAD, se le dio de alta el día 10/11/23. Desde el ingreso en el CSS, se le deja en suspenso el servicio durante 4 meses. ········ El SAD se le ha suspendido durante 3 meses. Si el ingreso se prolonga producirá baja.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-01-26','Ana: Correo de Paula, TO, CRR (tocupacional.crrplasencia@grupo5.net): "Hola buenos días Ana, te escribo para comentarte que Carmen Solana parece ser beneficiaria de la herencia de un tío que ha fallecido. He orientado a su madre, Benita, a contactar con vosotros porque es necesario realizar trámites (firma y entrega de 90 euros) el lunes en Badajoz, y no sabía si era ella o vosotros quienes teníais que realizarlos. Espero que ya haya contactado y que hayáis, podido hablar con ella y organizado cómo se van a realizar estos trámites y quién." ·················· Mi respuesta: "Yo no he hablado con Benita, así que me entero ahora por ti. Pongo en copia a mis compañeros Ángel y Miguel, Asesores Jurídicos - CTAEx, que son los que llevan temas de herencia, pero hoy no está trabajando ninguno de los dos. Lunes y martes Ángel no está y Miguel creo que el lunes sí trabaja ya, pero sinceramente no sé si estarán a tiempo de solventar nada ese día, pues la firma que se necesitará será la de la Presidenta de la CTAEx. ¿Tenéis la información de la Notaría para que Miguel pueda contactar el lunes? seguramente haya que aplazarlo. Sí podéis facilitárnoslo, porfa." ···································································· Respuesta de Paula, TO: "siento decirte que no tenemos más información, sería bueno si pudierais hablar con Benita, su madre (está en una residencia de mayores ahora te facilito su número 615611191 y el de la residencia en la que está, la directora se llama Ana 670309538." ·································· Llamo a Benita, madre de Carmen (615 611 191) sin éxito. ········ Llamo a Ana, Directora Residencia en que reside Benita (670 309 538), me dice que está reunida, que me devolverá la llamada, pero no lo hace.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2024-01-26','Ana: Correo de Tensi, TS (ssbtensi@riberosdeltajo.es): "te comunico que el día 25 de enero de 2024, Isidro ha tenido consulta de radiología, y anestesiología y reanimación en el Hospital Universitario de Cáceres. Cuando me los comento la Concejala, me dijo que le llevarían el Alcalde y ella. Te comento esto porque está pendiente de una operación de hernia, de ahi que le hagan estas pruebas."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2024-01-26','Ana: Correo de Tensi, TS (ssbtensi@riberosdeltajo.es): "te comunico que el día 25 de enero de 2024, Isidro ha tenido consulta de radiología, y anestesiología y reanimación en el Hospital Universitario de Cáceres. Cuando me los comento la Concejala, me dijo que le llevarían el Alcalde y ella. Te comento esto porque está pendiente de una operación de hernia, de ahi que le hagan estas pruebas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-01-26','Ana: Correo de Ana Castillo Foronda TS - FUNDACIÓN AUTISMO SUR (teayudamos@autismosur.es): "el lunes tenemos la cita con Ale en el Centro de Valoración. Quería preguntarte si nos podéis mandar un certificado de su prestación para poder entregarla." ·························· Mi respuesta: "Sí, lo recuerdo. Te adjunto carta con la revalorización relativa a 2023. La de 2024 aún no la hemos recibido."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2024-01-26','Ana: Correo de Esther Díaz, Adtvo. de la Residencia Ntra. Sra. de la Luz, de Malpartida de Plasencia (administracion@residencialaluz.com) con CI para extracción dentaria. ······ Cumplimento y paso para firma. ······················ Se lo devuelvo a Esther firmado y sellado y aprovecho para preguntar por Guadalupe. ·········· Respuesta de Esther: "me dice la Sandra, la enfermera que Guadalupe está bien, sigue como siempre. Tiene una buena conducta y esporádicamente dolor de cuerpo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2024-01-26','Ana: Nos envían desde la Res. (residenciafemar2019@gmail.com) REVALORIZACIÓN DE LA P. ORFANDA para 2024: 877,60€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2024-01-26','Ana: ante el correo de C. Residencial Banium (residencialbanium@villatermal.com): "Solicitamos AUTORIZACION ACOMPAÑAMIENTO PARA D. CONCEPCION BARBERO SANCHEZ, tutelada por ustedes, para las consultas telefónicas que a continuación detallamos y una vez recibidas por correo ordinario se las adjuntamos: 1.- CENTRO LUIS DE TORO (PLASENCIA ) DIA 29/01/2024 A LAS 11:10 RADIOGRAFIA Y A CONTINUACIÓN CONSULTA TRAUMATOLOGIA 2.- HOSPITAL VIRGEN DEL PUERTO TRAUMATOLOGIA DR. LOPEZ ORTIZ 30 DE ENERO DE 2024 A LAS 12:52 Quedamos pendiente de autorización," ················ RESPONDO: "Desde este Gabinete Técnico de la CTAEx, se autoriza el acompañamiento, telefónico y presencial, a estas y otras consultas médicas que puede tener Dª. CONCEPCION BARBERO SANCHEZ, por parte del personal del Centro Residencial Banium."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2024-01-26','Ana: Llamada de Doroteo (609 928 621): Se ha apuntado a dos cursos de la Universidad Popular: "Cocina mejicana" y "Postura saludable". Duran 3 meses. Cuestan 35€. Plantea pagarlo con el dinero que tiene allí en el centro, pero primero tiene que seleccionarle. ··· Le digo que no hay ningún inconveniente. Si finalmente le seleccionan y lo abona así le indico que se lo diga a Paula para que nos los comunique.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2024-01-26','Ana: Llamada de Jairo, desde el CSS: Hizo de Rey Mago en el centro, está muy contento "fue una experiencia muy bonita", "muchos pacientes se emocionaban". ······ Ya ha recibido visita de Clara, nueva Ed. Futuex, dice que es muy maja y está contento con ella. Le ha propuesto buscar algún hobbie. Ha solicitado apuntarse a Pádel y a Natación. ·········· Dice estar pensando en sacarse el permiso de conducir, si su enfermedad se lo permite, los psiquiatras no le han dicho que no pueda. ········· Después ya empieza a divagar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-01-29','Ana: Cumplimento y subo al portafirmas digital la Solicitud de Revisión PIA para solicitar plaza de Servicio de Atención Residencial de Discapacidad. ························· Envío a Toni-Futuex, las Autorizaciones de miembros de la Ud. Familiar de la solicitud de revisión PIA, para que las lleve la Educadora y sean firmadas por el hermano y la cuñada de Juanjo. ······························ Respuesta de Toni: "Ok, nos ocupamos y el viernes se lleva."··············································· Envío a REGISTRO (oac.merida.san@juntaex.es) oficio solicitud de Certificado actualizado de pensión de Orfandad para remitir por registro a la Dirección Provincial de INSS en Cáceres junto a los documentos necesarios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-01-29','Ana: Llamo a Ana, Directora Residencia en que reside Benita (670 309 538): dice que ella no sabe nada de este asunto, que Benita fue a hablar con ella y no entendía lo que le quería decir. Que al parecer se han enterado de la herencia de la noche a la mañana y hay varios herederos. No puede aclararme nada más. ··················· Lo comunico a Paula, TO-CRR y a Miguel, A. Jurídico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2024-01-29','Ana: Correo de Mª Paz, Psicóloga Clínica - UHDAC (mariapaz.casado@salud-juntaex.es) a Soraya Masa con copia a mí: "Buenos días Soraya. Te escribo en relación al paciente Cristofer F.R. (tutelado por CTA), que mantiene evolución favorable, estabilidad conductual y que sigue a la espera de que se le asigne plaza residencial, tal y como hemos informado en otras ocasiones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-01-29','Ana: Correo de Estrella Durán: "José Manuel Romero Mediavilla demanda comprarse unas zapatillas deportivas, ropa interior, calcetines y camisetas de manga corta, por lo que estima un gasto extra de 100 euros. Si se le concede, podría sacarlo con la Educadora de Futuex el día 1 con los 150 quincenales asignados..." ····································· Mi respuesta: "Esta petición hay que pasarla al Jefe de Sección Económica para valoración (el caso de José Manuel es complicado, como comprobarás continuamente está demandando cosas, además de los gastos fijos que tiene (suministros, cáterin, comunidad de vecinos, farmacia, gastos de bolsillo…) y estamos también pendiente de presupuesto de la obra de su vivienda. Alberto está de vacaciones, pero se lo envío y lo verá a partir del día 1 que vuelva. Por tanto, a José Manuel puedes transmitirle eso, que el jefe de sección valorará la petición a partir del día 1."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-01-29','Ana: Tras llamada de Carlos, envío correo a Alberto, jefe secc. ecca.: "En relación a CARLOS GONZÁLEZ LEO, solicita 2 cosas: 1. Un extra de 25 € para comprarse un libro por su cumpleaños, que es el día 12 de febrero. 2. Que se valore es posible una subida de asignación semanal, pues con la misma, además de la comida y pequeños gastos, abona también las recargas de la tarjeta de telefonía y las bombonas de Gas Butano." ··································································· *En conversación con Carlos, con manos libre porque está también Mamen, Ed. Futuex, con ella, manifiesta que no quiere volver a solicitar CATERING MUNICIPAL, pues tendría que ser asociado al SAD y no quiere. Dice que se vale por sí mismo para limpiar y hacerse la comida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2024-01-29','Ana: Corre de Belén Pavón (Belen.asoma@outlook.es): "Les escribo con motivo de solicitar el certificado de actualización de pensión 2024 de Doña María Salvadora Chaves Mendoza, residente en los Pisos Tutelados Villa del Rey, documento que suelen recibir todos los primeros de año a través del Sistema de la Seguridad social, para la correcta revisión anual, (tasa fijada según la ordenanza reguladora en vigor del Excelentísimo Ayuntamiento de Villa del Rey y conjunto de plazas socio sanitarias concertadas según convenio suscrito con la Consejería de Sanidad y Dependencia, Servicio Extremeño de Promoción a la Autonomía y Atención a la Dependencia y el Ayuntamiento de Villa del Rey SEPAD)." ····································· *Le envío el REVALORIACIÓN DE LA PENSIÓN DE VIUDEDAD. En 2024 la cuantía ascenderá: 825,20 €','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2024-01-30','Ana: Llamo a Lola, TS - Residencia Plena Inclusión Cabeza del Buey (690 04 14 05), pues todavía no hemos recibido el Informe Social que se le solicitó para el Inventario. Intentará elaborarlo y enviárnoslo entre hoy y mañana. ························· Por otra parte, le informo que aún no hemos conseguido tener acceso a la cuenta del B. Santander. *En el centro le siguen adelantando dinero para sus gastos de higiene y de actividades, pues no la quieren dejar fuera de actividades y terapias que le viene muy bien. ········· La semana pasada la llevaran a que probara HIPOTERAPIA y le encantó. Y hace unos días llevaron a merendar a un grupo a la Isla del Zújar y disfrutó muchísimo. ······························································································································································································ Redacto oficio adjuntando ALTA DE TERCERO y envío a Julio, CTAEx, para su REGISTRO a Serv. Territorial de Salud y Serv. Sociales de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-01-30','Ana: Envío correo a Toni-Futuex: "En relación a FRANCISCO CACHO GARRIDO solicito retoméis el seguimiento y la intervención con él. Ahora mismo dice que ha alquilado una habitación (con anterioridad ha estado en piso okupa). Su número de contacto es: 641 569 490 Dice que necesita comprarse unos pantalones, pero no ha conseguido que le faciliten presupuesto a su nombre, fue a Mango y creo que también dijo que había ido al Pull and Bear. Me parece que puede ser un buen momento para retomar el contacto y seguimiento. Le dije que os lo iba decir para que le acompañe la educadora a pedir presupuesto y a las malas, que nos digáis precio de los productos para que puedan autorizar desde la sección económica un extra a tal fin y que ella le acompañe a retirarlo y a comprar los pantalones, adjuntándonos después el ticket como justificante." ······················································ Envío correo a Alberto, Jefe S. Ecca: "FRANCISCO CACHO GARRIGO solicita: - 400 € para pasar a la cuenta de su prima para aportar a su hija (la cuenta debemos tenerla de otra vez que se le dio para libros), pues está estudiando en Sevilla y necesita una ayuda puntual. - Revisar su asignación económica mensual, para, si es posible, incrementársela a al menos 20€. Ya me dices." ········································································ Tras estos correos llama Francisco: pide por favor sacar un extra de 60 € para los pantalones que necesita el mismo día 1 cuando acuda a retirar su asignación mensual. Que si puede le acompañe la Educadora de Futuex y sino irá el sólo. ···························· Junto con las compañeras de la secc. ecca. (en ausencia de Albero y Maite) miramos la cuenta y decidimos autorizarle el extra de 60€ para ropa. ······································ Envío nuevo correo a Toni-Futuex: "En relación al correo de antes, te informo que acabo de hablar con Francisco de nuevo (lo del correo anterior fue en conversación de ayer). Pide poder sacar el extra para pantalones el mismo día 1 cuando vaya a retirar su asignación periódica mensual. Finalmente se ha autorizado este extra. Por tanto, si la educadora que se asigne desde el programa puede acompañarle al banco y a comprar los pantalones, perfecto, sino que vaya él sólo. También ha manifestado querer irse a vivir a Madrid, veremos… Ah, y donde está alojado ahora al parecer es una pensión, no un pido…" ··························· Confirmo a Francisco (641 569 490) que puede retirar el extra de 60€ el día 1.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2024-01-30','TERESA CONTACTO CON SU SOBRINA PARA GESTIONAR REINTEGRO PARA COMPRA DE LO PRESUPUESTADO TELFNO SOBRINA 660922661.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2024-01-30','TERESA ENVIO ELECCION DE CENTRO A LA SECCION DE DISCAPACIADAD PARA TRASLADO A PETICION DE M EUGENIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-01-30','Ana: envío correo a Toni-Futuex: "En relación a CARLOS GONZÁLEZ LEO, comunicaros que acaba de llamarme (ayer también me llamó estando Mamen con él) y quiero trasladaros una queja recurrente que hace Carlos desde que comenzó Mamen, Educadora, a intervenir con él. Dice que Mamen suele tomar decisiones por él e incluso no le deja hablar en los establecimientos como ocurrió, según explica, en la tienda de telefonía. Verbaliza que tiene discapacidad pero que no es tonto y tiene sus derechos. Según expresa, en el supermercado, a la hora de hacer la compra, no le deja elegir los productos, cuando él quiere comprar marca blanca ella le insiste en comprar primeras marcas. Además, también se queja de que traslada información de su vida personal a las hermanas del negocio de tapicería del barrio y él no quiere tener más relación con ellas ni quiere que ella les facilite información privada a estas personas, por mucho que se interesen por él. Ayer volvió a manifestar que no quiere SAD ni CÁTERIN municipal y privado y no quiere que Mamen insista más en esta idea. No sé hasta qué punto es esto así, pero lo cierto es que Carlos es muy autónomo y está acostumbrado a tomar sus propias decisiones por lo que entiendo que hay que tener más mano izquierda a la hora de tratar con él. Más que nada os lo comunico para que Mamen intente modificar su estilo de intervención, pues éste ya está amenazando de nuevo con bloquearla. Dice que es muy buena chica en general y que sabe que le quiere ayudar, pero que no le respeta en ciertas cuestiones y decisiones y que no le valora como sí lo hacía Patricia, la anterior Educadora. Sé que no es fácil la intervención con él, pero estoy segura de puede llegar a establecer un buen vínculo profesional."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2024-01-30','Ana: Correo de Sheila, CRR, a Raquel, Eva y Mariluz - S. Acceso SALUD MENTAL: "Comunicar el alta de la UHB de la persona usuaria JUAN MARIO SAN ROMAN BLASCO el pasado jueves. Adjuntamos incidencias del mismo desde su alta hasta hoy, dónde se evidencia que el consumo sigue presente en su día a día." ········································································ Respuesta de Raquel Gómez: "Muchas gracias por mantenernos informadas. No sabemos si ya se convocó la Comisión de Valoración, de no ser así habría que solicitarla o en su caso intentar agilizarla para que podamos valorar su situación y el recurso más adecuado para él, ya que en el CRR no está funcionando y no se puede seguir permitiendo un consumo diario. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2023-11-28','Ana: Recibios escrito del Serv. Territorial de Salud y SS.SS. de Badajoz (PNC) "LA solicitud de PNC tuvo entrada con fecha de 24/11/23" - 90 días para RESOLUCIÓN. Silencio Adtvo. negativo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2024-01-29','miguel, recibo email de renuncia del abogado Jorge Calvo: Buenos días, En referencia al asunto de la ejecución EFM 333/2022 del Juzgado de Primera Instancia nº 5 de Badajoz. A razón del estado del expediente y la falta de confianza que este letrado ha denotado del cliente. Vengo a anunciar mi RENUNCIA en la causa a fin de que pueda nombrar otro abogado en la misma. En tal sentido, tras 24 horas procederé a presentar oportuno escrito en el Juzgado para ello. Dándole la oportunidad de contactar conmigo a fin de poder dar la venía al letrado que me indique. Aprovecho para indicarle que queda pendiente la liquidación del proceso de ejecución y el pago de las cantidades solicitadas en comunicaciones previas. Quedo a la espera de sus noticias, Atentamente, Jorge Calvo Onsurbe Abogado ICABA 3397 El lun, 22 ene 2024 a las 13:02, Cristina Soto Ruiz (>csotoprocura@aicosl.com>) escribió: Buenos dias, pongo en copia a don Jorge Calvo como de costumbre para mejor seguimiento, ante la insistencia mostrada para que les remita lo actuado en este asunto y en el hilo del mismo correo de fecha 22-10-23 en el que les envié toda la documentación que a esa fecha obraba en mi expediente, les VUELVO A ENVIAR todo los documentos que hay notificados en el asunto de referencia descargado directamente de lexnet tal como nos parece a nosotros. Para que puedan cotejarlo, asi mismo les adjunto una relacion de las notificaciones recibidas en este asunto etj 176/2023 Atentamente, RUEGO CONFIRMEN RECEPCIÓN CRISTINA SOTO RUIZ Procuradora de los Tribunales colegiado nº 393 C/ San Blas, 11 06002- Badajoz Tf: 660 40 49 23 - 924 22 33 90','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2024-01-31','-Amalia : Contesto a la TS del SSASB de Zafra , a ellas no las deja entrar en el domicilio .Al parecer Josefa estuvo ayer en el Hospital , el medico la atendió y le dió el alta . La vió nerviosa y le indicó que podía pasar allí la noche y echó a correr. Le indico a la compañera del SSASB : El problema de Josefa , como bien conocéis es que no acepta la ayuda . Efectivamente he tramitado nuevo PIA , lo tenía suspendido . Aceptó a que Camila , una chica colombiana hiciera el servicio de ayuda a domicilio .Pero la chica sólo ha durado 15 días . Acabo de hablar con ella y me dice que envíe a otra persona , vamos a volver a intentarlo. Ella no acepta que nadie entre en su casa . Sólo se relaciona con una chica colombiana que la conoce hace años. He vuelto a hablar con ASINDE ( TF . RAfael 638922859 ) para decirle que seguimos con el servicio y envíe a otra chica , a ver si consiente que entre en casa . He vuelto a llamar por tf a Josefa 924098030 , ella solo está preocupada por el dinero y en cómo va a ir este mes a sacarlo . Dice que está mala . Le insisto en la necesidad de ingresar en R. Mayores , se niega . He pedido a la delegada tutelar que vaya a su domicilio , unas veces les abre la puerta y otras veces no . Por lo menos ha aceptado a que vaya una auxiliar a su casa . Paso ya el expediente a la zona de Teresa .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2024-01-31','TF DEL HERMANO 640831790 Ya saben por el Juzgado que tendría que entrar en residencia, se niegan " si vienen a por ella les pegará a todos " No aceptan ni en Zafra ni en ningun otro sitio . Voy a pedir residencia por Madex y pasará a lista de espera . C.O. ya está pedido . No hay plaza en ningún sitio , pasará a lista de espera . Vemos mejor lo del CO que ella iría voluntariamente. Cuando tenga pedido RAL pasaré el expediente a zona Tere , lo tengo hace bastantes meses y lo de CO va a tardar. De momento se mantiene estable , vive con la familia en La Morera .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2024-02-01','TERESA telefono de la auxiliar por si la contactais alguna vez +34 632 47 50 99, se llama Khadija, habla castellano mas o menos, se defiende.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2024-02-01','TERESA Como te ha comentado mi compañera Amalia a partir de ahora seré yo la profesional de referencia de este caso. Vamos a plantear un ingreso involuntario para residencia de mayores pero para solicitarlo necesito me facilites informe socia de la situación actual de Josefa en la que se justifique la necesidad de ese ingreso. MERCEDES TS HOSPITAL DE ZAFRA 40335','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2024-02-01','Ana: Reenvío a Ángel y Miguel, A. Jurídicos, correo de María Andrada - Cáritas (maaterion@gmail.com / 603 476 458): "No ponemos en contacto desde Cáritas Diocesana , parroquia de Fátima, con relación a Daniel Canela da del Río , hermano de Antonia Canelada del Río, la cual es usuaria de Ana Matamoros. Desde Cáritas estamos intentando gestionar una herencia de otra hermana fallecida. , , .Daniel ahora está bajo techo provisionalmente . Ruego se pongan en contacto conmigo, para poder agilizar los trámites."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2024-02-01','Ana: Reenvío a los A. Jurídicos, CÉDULA DE CITACIÓN DEL Jdo. para revisión de las Medidas, remitido por Ángela. ·· 21 de febrero de 2024 a las 10:10 horas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2024-02-01','AMALIA : Pongo a portafirma solicitud de plaza residencial RAL . Adjuntaré la sentencia judicial que lo autoriza . Ella no quiere ingresar . La pondrá en lista de espera de Centros , para cuando haya plaza . Ya se solicitó CO para centros de la zona a la que pertenece La Morera ( Manuela me indicó que le corresponde Zafra ) . Pasa a lista de espera no hay ninguna actualmente . Ella y la familia lo aceptaría . Si llegase una plaza y puede ingresar , sólo hay que comunicar al juzgado que ha ingresado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2024-02-01','TERESA Buenos días Soraya, buenos días Teresa, os escribo porque la situación en el centro con el ingreso de Nerea es lamentable, ya no sólo por las alteraciones de conductas de la chica, la cual me da verdadera pena, sino porque debido a esas alteraciones hemos tenido crisis en otras usuarias que hacía mucho tiempo que estaban estables con su medicación. Ayer a partir de las 20.00 horas Nerea entró en crisis, después de varias autolesiones y lesiones a compañeras y trabajadoras del centro, no tuvimos más remedio que llamar a los servicios de urgencia. Tras dos horas de crisis y una situación muy complicada con la chica asistieron los cuerpos de seguridad y del servicio de urgencias, le inyectaron la medicación pertinente y decidieron llamar a una unidad móvil y trasladarla al hospital. Así que aprovecho para anunciar que está ingresada de nuevo. Tras los dos episodios vividos en los 5 días que lleva Nerea, y viendo que, aunque tenga una persona al lado las 24 horas, se siguen repitiendo las crisis que desde nuestro centro no podemos barajar, por no estar preparado para personas con graves alteraciones de conductas. Como trabajadora social del centro os RUEGO encarecidamente que se tomen algunas medidas y se busquen centros que estén preparados tanto en infraestructuras como en personal para este tipo de usuarias, ya que es muy triste que no podamos atender sus necesidades y temo que acabe en lesionarse gravemente. Creo que es lo mejor que le podría pasar a Nerea es que sea atendida por profesionales especializados y desahogar esas crisis en lugares habilitados para ello, salas preparadas para esta problemática, ya que ayer fue milagroso que no se abriera la cabeza contra el cemento de nuestro patio. Me pongo a vuestra disposición para agilizar cualquier trámite e informaros del estado de Nerea, espero atendáis nuestra petición. Saludos! A MEDIA NOCHE LE HAN DADO EL ALTA Y ESTA DE NUEVO EN EL CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-02-01','-Amalia : solicitan movil y PC , lo derivo a S. eco para que valoren su viabilidad económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2024-02-01','-Amalia , escribo a Marga , la TS del Ctro.penitenciario "Me dice que está pendiente de recibir notificaciones judiciales de sus últimos juicios y que algunas de ellas son multas . Se lo he transmitido a los jurídicos y me piden que si llegase algo a ese centro nos lo hagáis llegar . Podéis remitirlo a mi email."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2024-02-01','Amalia : Escribo a Tere "He hablado esta mañana con Mamen del E. Dependencia para ver si habría que modificar PIA , no hay que hacer nada , sigue activado. Pero sí hay que firmar un contrato nuevo que la empresa registrará al SEPAD para la PVSAD. He hablado con Rafael , dueño de ASINDE y nos va a remitir el nuevo contrato . Cuando lo tenga te lo paso . Ya le he comentado a él el traspaso del expediente a tu zona y está informado . De momento , a ver si cuadra con la persona que entre y puede mantenerse en domicilio. Si la TS del hospital facilitara algún informe social y médico que Miguel pueda justificar el Int. involuntario estupendo .. otra cosa será que el juez lo autorice . "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='GALVAN'and apellido2='GARRIDO'),'2024-02-01','TERESA ENVIO CORREO A RM.LASERENADIR@CASTUEREA.ES INFORMANDO DE LA CURATELA Y PETICON DE PRESUPUESTO DE GASTOS ME RESPONDE EL DIRECTOR QEU LO PASRA POR LA CUENTA AL QUE HACE CON EL RESTO DE CURATELAS QUE RESIDEN EN EL CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2024-02-01','TERESA TRAS INGRESO EN LA UHB POR ORDEN JUDICIAL EL VIERNES SERA DADO DE ALTA YA QUE SE ENCUENTRA ESTABLE Y EL HERMANO SE COMPREME A CUIDAR DE EL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2024-02-01','Ana: Llamada de Anabel Galván, TS Mancomunidad de Vegas Altas - Ayto. Madrigalejo (672 146 686), está en su despacho Ana Priscila. Pide que se le suba la asignación. Anabel propone 150€ (Según rendición de 2022, saldo en cuenta de más de 64.000 €). ················ Envío correo a Alberto, Jefe S. Ecca haciendo esta propuesta de subida. Por mi parte Ok a la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-02-01','Ana: Llamada de Isabel Bargón, madre de Jesús, pregunta si su hijo sigue pasando los 200€ a sus hijos y hasta cuando debe ser esto. El hijo tiene 23 años y, según dice, trabaja a media jornada. La hija tiene 20 y trabaja en una peluquería, pero no sabe jornada ni sueldo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2024-02-01','Ana: Envío correo al ctutelar@ con copia Amalia, TS CTAEx: "Me han llamado del CRR de Mérida. Al parecer a JAVIER AGUDO CUMPLIDO, le han puesto hoy muchos problemas en el banco para darle el dinero, casualmente iba Gisela con él y finalmente se lo han dado, pero le han dicho que tenían que hablar con la CTAEx porque era requisito que fuera acompañado… no sé a qué se debe porque en Plasencia sacaba él sólo y en los meses que lleva en Mérida es la primera vez que le pasa, los anteriores le han dado su asignación sin problema yendo él sólo. ¿Podríais, por favor, comprobar la autorización que enviasteis al banco y si es necesario escribir o llamar a la oficina? Javier puede retirar su asignación sin necesidad de ir acompañado. Ya me decís, gracias de antemano. Pongo en copia a Amalia para que esté al corriente. Amalia: Dado que en diciembre Javier Pecero me dijo que Javier estaba adaptándose muy bien y ya no verbalizaba el deseo de volverse a marchar a Cataluña, sino el de quedarse en Mérida y al parecer esto sigue igual, te lo paso ya para que continúes tú con el seguimiento. Ante cualquier cosa, hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2024-02-01','Ana: Reenvío a la S. Ecca. una declaración de acompañamiento a cita Médica para que abonen este servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2024-02-01','miguel, envío email a José Santiago, JOSE SANTIAGO LAVADO >2981@icaba.com> Buenos días, adjunto lo que tenéis que modificar y el auto que hay que modificar (para que identifiquéis dicho auto en el escrito) Lo que hay que tenéis que solicitar que se modifique es lo que en su día nos envió el notario de los Santos D. Carlos. Enviadme justificante de presentación vía Lexnet cuando lo hagáis. ******************************************* Contestación de Santiago Lavado: Miguel, aqui hay un lío que no veas. A ver: El documento que yo titulo como Escrito de Sepad, es el que presentasteis vosotros y que efectivamente no se admite y no se tramita de fecha 27 de noviembre de 2023 Te lo adjunto. El documento que yo titulo como MIO, es la diligencia que se tiene por presentado el escrito inicial de mayo de 23 y se nos requiere para que lo presente en el otro procedimiento, de fecha 7 de diciembre de 23, que es lo que hicimos con los documentos que te adjunte en el anterior correo. ************************************************** Mi contestación: Hola, hablad con Alba del Juzgado que os lo va a aclarar, porque no son ninguno de los dos escritos que adjuntas porque el procedimiento es el X15 Autorización de bienes menores nº 436/2021, que es el auto que te he adjuntado. Si te fijas en los dos documentos que adjuntas ninguno indica este procedimiento que te indico y que se refleja en el Auto adjuntado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2024-02-01','miguel, contestación de José Santiago: Buenos días. Como ya te indiqué, este escrito por el que se interesaba la entrega en el procedimiento adecuado, dado que el inicial se inició en otro erróneo, al ser distinto, se presentó en el juzgado el día 14 de diciembre, posterior a mi personación en el juzgado en noviembre y recibir la Diligencia el día 7 de diciembre. Se adjunto justificante de los escritos. ********************************************************* Mi contestación: Buenos días, según me dijo Alba del Jzdo nº1 de Villafranca no cabía esa subsanación que presentasteis en los escritos que adjuntas. Me comentó que teníais que solicitarlo de nuevo, pues no cabía subsanación en la identificación incorrecta del procedimiento que inicialmente se hizo. Si queréis hablad con Alba del Jzdo para confirmar todo antes. Este escrito está bien identificado el procedimiento, sería presentar todo de nuevo pero identificando con este procedimiento que indicas y que coincide con el Auto a modificar…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2024-02-01','Ana escribe a S. eco y deriva el caso a zona Merida. Me han llamado del CRR de Mérida. Al parecer a JAVIER AGUDO CUMPLIDO, le han puesto hoy muchos problemas en el banco para darle el dinero, casualmente iba Gisela con él y finalmente se lo han dado, pero le han dicho que tenían que hablar con la CTAEx porque era requisito que fuera acompañado… no sé a qué se debe porque en Plasencia sacaba él sólo y en los meses que lleva en Mérida es la primera vez que le pasa, los anteriores le han dado su asignación sin problema yendo él sólo. ¿Podríais, por favor, comprobar la autorización que enviasteis al banco y si es necesario escribir o llamar a la oficina? Javier puede retirar su asignación sin necesidad de ir acompañado. Ya me decís, gracias de antemano. Pongo en copia a Amalia para que esté al corriente. Amalia: Dado que en diciembre Javier Pecero me dijo que Javier estaba adaptándose muy bien y ya no verbalizaba el deseo de volverse a marchar a Cataluña, sino el de quedarse en Mérida y al parecer esto sigue igual, te lo paso ya para que continúes tú con el seguimiento. Ante cualquier cosa, hablamos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2024-02-01','miguel, llamo a Enrique Perianes para que nos pasen los honorarios él y el procurador para que la Ctaex los abone antes del día 7-2-24. Se lo comento a Alberto para que los abone antes del día 7-2-24. Dice que está pendiente sólo de la sentencia y que llamarán al juzgado para asegurarse de que la dictan antes de dicha fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2024-02-02','TONI FUTUEX : Paso a detallar últimos acontecimientos sucedidos en la vida de Isabel Valadés Díaz: Tras varias visitas de seguimiento por parte de la educadora, a su domicilio y también en el exterior, Isabel va cogiendo confianza con la misma. En diferentes visitas, Isabel comenta que le han robado en la calle tras haberse mareado. Supuestamente, tres hombres le dan un tirón en el bolso y se llevan 150 euros que tenía (pide a la educadora que no comente nada a ctaex por miedo a que no le den más dinero, por lo que la historia nos parece un tanto extraña). Ella dice que lo denuncia a la policía pero no tiene copia de denuncia ni ningún documento que corrobore lo sucedido. Otro día comenta que se ha mareado en la calle y que además, se le olvidaron las llaves por lo que la policía, supuestamente la acompañó hasta casa y tuvieron que forzar la puerta. El casero comenta que es algo extraño porque siempre que la policía ha tenido constancia de este tipo de sucesos en su vivienda, lo han avisado, y en esta ocasión no. Cuando la educadora va al domicilio, observa que la puerta está muy brutalmente forzada y ve que no puede cerrarla, por lo que se queda abierta pudiendo entrar cualquier persona. La educadora entra sin que Isabel abra sencillamente empujando la puerta. Tras la llamada de la educadora al casero de Isabel, el casero acude a la vivienda y cambia la cerradura (el casero enviará la factura a ctaex para posterior pago). Además el casero le arregla otras cosas que estaban estropeadas y que Isabel no dice por miedo a represalias según comenta ella. Además, Tras haberse negado a ir a la cita programada de la resonancia que tenía pendiente por sus problemas digestivos, se comienza el proceso para reprogramar dicha cita. Archivo el informe del ESM en el que indica que le propone CRR pero no lo acepta y que no está descompensada como para tramitar nada más. * Se acude al Médico de atención primaria donde nos dicen que hay que reprogramar la cita en consultas externas e intentar explicarle la situación. Nos comenta que será complicado ya que al médico de digestivo no puede ir sin dicha prueba realizada y más aún cuando solicitó alta voluntaria cuando estuvo ingresada en el hospital para valorar su diagnóstico. (estamos pendientes que nos llegue dicha cita). * Se acude a cita con psiquiatra el 31 de Enero de 2024. En la consulta todo fue muy bien hasta que la educadora comentó aspectos importantes que Isabel no estaba contando. Como por ejemplo, la negación a ir a la prueba de resonancia, la decisión de no comer apenas nada sólido (ella cree que no comiendo sólido podrá solucionar su problema digestivo hasta que le den un diagnóstico), robo y mareos continuados en la calle. Por varias cuestiones, el psiquiatra le ajusta la medicación y además considera y recomienda el ingreso en un CRR , a lo que Isabel se niega en rotundo. SE adjunta informe. +++ A las dos visitas médicas se acude en taxi ya que Isabel necesita ir sujeta y caminar poco por la debilidad que presenta. Dada la premura de las citas, no hemos podido solicitar previamente la autorización, pero se trata de importes pequeños. tSe adjunta las dos facturas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-02-01','Ana: Correo de ayer de Estrella Durán, TS CSS- Plas.: "Os escribo porque me comenta la Psiquiatra que José Manuel Romero Mediavilla como sabéis está bien, su ingreso ha sido por causa social (tema vivienda), que le gustaría darle pase el fin de semana, que se iría con su hermano, con el que ya ha hablado y está de acuerdo, pero éste comenta que no lo puede ni recoger ni traer al centro. No sé que os parece que vaya en el bus que sale de la puerta del centro y vuelva con este mismo bus o que lo acompañe la Educadora de Futuex a la ida y a la vuelta...." ····························· En conversación telefónica le confirmo que no hay problema en que vaya él en autobús, es muy autónomo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GONZALEZ'and apellido2='GONZALEZ'),'2024-02-01','Ana: Correo de Toni-Futuex: "Comentarte al respecto de la tutela M. Carmen Gonzalez de Coria, tras el comienzo del programa esta constando mucho localizarla para llevar a cabo los seguimientos, parece ser que está consumiendo alcohol de forma abusiva, y su estado tanto fisico como mental, está muy deteriorado. Hemos estado con ella en la consulta de salud mental del día 19 de enero con la psicóloga y la trabadora social Marisa, la cual le recomendó el ingreso voluntario de Carmen durante 20/30 días en la UNIDAD DE ALCOHOLISMO en Plasencia, ya que en más ocasiones Carmen ha tenido de forma ambulatoria este programa y no ha cumplido del todo parece ser, por lo que tanto la trabajadora social como el psiquiatra le animaron a realizar este ingreso el cuál dicen que va a ser muy positivo en todos los aspectos de Carmen, y por lo que también lo necesita ya que comentaron que ni siquiera la reconocieron el día que se acudió SM de lo desmejorada que la encontraron. Ella quiere ir pero se siente mediatizada por su pareja (Enrique) que creemos que también consume tóxicos. Su máxima preocupación es su pareja.. Ya están concertadas las citas para la analítica y demás pruebas que tiene para hacer el ingreso y está todo bien y en orden. Aun no tiene fecha para ingreso, pero creemos que no debe tardar y creemos que finalmente no se niegue"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2024-02-01','Amalia : he escrito a la S. eco , ya tienen vuestros emails para solicitarlo como indica el banco . Es curioso que para dar de baja necesitan la autorización de la CTAEX porque está tutelada pero para abrirla y pedir al INSS el cambio de la pensión no lo está ? No es la primera vez que lo hace . Vamos a pedir al banco que proceda a deshacer todo el proceso . A nivel terapéutico creo que sería bueno que ella viese alguna consecuencia de lo que ha hecho, sobre todo para que no lo repita . Supongo que también lo estaréis valorando vosotros . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2024-02-02','TERESA ENVIO POR REGISTRO FACTURAS Y RECIBO BANCARIO A DEPENDECIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-01-24','miguel, Amalia me reenvia email de Sandra donde adjunta diligencia de ordenación de procedimiento donde se le reclaman unos 12.000€ deuda a la comunidad como heredero de la vivienda. Los trámites de la herencia le pedia a Sandra que los fuese enviando a Menaya con copia a mi.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-02-02','miguel, contesto a Sandra, parte social (Amalia y Maite), parte económica Alberto y copia a Angel: Buenos días Sandra, veo un email que envío Amalia. Tras las vacaciones estoy poniéndome al día en los emails. Veo un procedimiento monitorio 718/22 del jzdo nº7 de Badajoz, que por la fecha 22-12-23 ya han pasado los 20 días para oponernos al mismo y por tanto dictarán más adelante ejecución de los 12.000€…que le reclaman a la madre del curatelado fallecida Doña Manuela Moya Cordero, que entiendo por la reclamación de la comunidad de propietarios era la única titular de la vivienda… Como en su día te indiqué teneis que ir remitiendo a Joaquin de Asesoría Menaya la documentación para hacer la herencia que solicitó, y de la que tenéis que enviarme como ya dije copia a mi. Desconozco todo sobre la misma, masa hereditaria, herederos, si interesa por tanto o no aceptarla… Si no agilizamos dicha tramitación de herencia no podremos por tanto saber si le interesa o no aceptar la herencia. Por otra parte la parte económica de la comisión tendrá que estudiar si va a tener o no capacidad de pago de dicho importe, mas los honorarios que solicitó Asesoría Menaya. Quedo pendiente que me indiques si ya habéis enviado la documentación que pidió Menaya para hacer la herencia o en qué estado de trámites se encuentra y de que la parte económica estudie su capacidad de pago. ----------------------------------------------------- Contestación de Alberto: MIGUEL: SITUACIÓN ECO DEL TUTELADO...OS PASÉ AL ÁREA JURÍDICA INFORME REQUERIDO X EL JUZGADO EL 19/12/2023 (ESTÁ ACTUALIZADO). DE TODAS FORMAS EL RESUMEN DEL INFORME ES QUE, EN ESTE MOMENTO, LA SITUACIÓN ES CORRECTA: SALDO: 37.000 € APROX. EVOLUCIÓN SALDO ÚLTIMOS 12 MESES: +2.500 € APROX. ---- EVIDENTEMENTE, CON LOS GASTOS SOPORTADOS DURANTE ESE PERÍODO Y QUE, SALVO CUESTIONES SOBREVENIDAS, NO TENDRÍAN QUE VARIAR EN EL FUTURO PRÓXIMO. OPINIÓN: ECONÓMICAMENTE ESTÁ BIEN Y ESTA SITUACIÓN DEBERÍA PODER MANTENERSE EN EL TIEMPO. • UNA VEZ QUE SE CUANTIFIQUEN LAS DEUDAS RELACIONADAS CON LA HERENCIA Y LOS IMPUESTOS A ABONAR: ENTIENDO QUE DECIDIREMOS SI MERECE LA PENA O NO ACEPTAR LA HERENCIA  CPROPIETARIOS: MIGUEL HABLAS DE 12.000 €...PERO EN REALIDAD NO LE RECLAMAN MÁS DE 15.000 €???  IMPUESTOS.  OTROS ________________________________________ Mi contestación: Perfecto, pues que vaya asumiendo las deudas mientras la asesoria menaya le tramita la herencia. Los importes definitivos no los sabremos hasta que dicten ejecución del juzgado y hasta que la Asesoría nos pase las facturas de todos los trámites. Conforme me vayan requiriendo pagos te lo haré saber.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-01-31','Ana: Recibimos RESOLUCIÓN DE ACEPTACIÓN DEL DESISTIMIENTO DE LA SOLICITUD DE REVISIÓN DE LA SITUACIÓN DE DEPENDENCIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='COMENDADOR'and apellido2='GARCIA'),'2024-02-02','Ana: Tras hablar con Fernando Gago, TS Res. Real de Navalmoral de la Mata (927 533 322 // tsnavalmoral@residenciareal.com), reenvío a Alberto, jefe S. Ecca., correo de Fernando: "Juan ocupa en el centro una plaza sociosanitaria tipo T.3, la cual se abona en el banco a final de cada mes con la cantidad económica resuelta por el SEAPD. Hasta el mes pasado, su Hermana se encargaba de llevar el modelo 50 de Juan al banco para pagar su plaza y enviarnos una copia tras esa gestión. En Enero de 2024, nos informa la familia que ya no pueden gestionar la cuenta de Juan para este trámite debido a que es responsabilidad de la Comisión Tutelar. Necesitamos que mensualmente se le tramite a Juan esta gestión y nos envíen una copia del modelo 50 pagada a final de cada mes. Si esta cantidad no es abonada dos meses consecutivos, el SEPAD puede abrir expediente de retirada de plaza, dejando a Juan sin recurso. - Os adjunto resolución de Juan Comendador García plaza sociosanitaria T.3. - El modelo 50 ya preparado para abonar la cantidad en el banco y que se nos reenvíe una copia." ········ Añado: "Hay que ver situación eco, no sé si tiene seguro de decesos (mirar en movimientos bancarios, si no hay nada pediré al TS que pregunte a los familiares. En caso negativo, habrá que ver si hay posibilidad de contratar una póliza."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2024-02-02','Ana: Remito a Ángela - Placeat (directora@placeat.org): La documentación relativa al ingreso de Juanjo, firmada digitalmente: Pacto asistencial, Autorización actividades de ocio y Declaración Ingreso Voluntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2024-02-02','Ana: Correo de Lourdes, S. Ecca: "ya he enviado al banco un recordatorio, de que puede retirar su asignación, sin acompañamiento." ······················· Reenvío a Javier Pecero, Director del CRR, para su conocimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2024-02-05','Me comunica Paloma que la casera pide una subida de alquiler a 420€. Es una subida importante que me da la sensación que es para que se vayan de allí…. Podemos aceptar una subida hasta los 350€, que la delegada se ponga en contacto con la casera y el informe al respecto. En el caso que acepte los 350€ hay que modificar el contrato','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2024-01-17','miguel, email de Damian: Estoy en misa pidiendo por usted y sus familiares.al final quiero alquilarle el piso a mi otra prima.mi prima Toñi porque no tengo familia y ella me lo puede cuidar muy bien.esperamos a ver la resolución del juicio de la curatela a ver si sale todo bien.la familia es muy importante y es una prima que siempre me he llevado bien.ya lo he puesto en conocimiento de Amalia ahora mismo.que pase buen dia ---------------------------------------------- Otro email: Buenas tardes señor Miguel el viernes voy a una inmobiliaria en Mérida para ver un piso.he estado esta mañana en el banco y me han dicho que Juana la señora del Liberbank que está en contacto con la comisión.le he pasado a Pepi la del banco la sentencia y se lo ha mandado a Juana y me ha dicho que en 20 días más o menos ya tengo la cuenta donde aparezco yo solo y queda desbloqueada.entonces podré irme a un piso de alquiler independiente.lo tengo muy claro.buenas tardes y muchas gracias ------------------------------------------- Otro email: Mi prima no va a alquilarme el piso porque ya no está interesada seguimos con la venta.le voy a mandar a mi amigo el tasador que como yo ya tengo la copia de la sentencia llame a un cerrajero y me va a comprar el piso por 135000 euros y me compro un piso en Mérida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2024-01-17','miguel, email de Damian: Ya tengo la sentencia y me han retirado las medidas de apoyo.me he pasado por el banco y me ha dicho la del banco que hablará Juana con la comisión para el tema del desbloqueo de la cuenta estoy muy contento señor Miguel de mis progresos.ahora a seguir llevando una vida sana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2024-01-18','miguel, damian envía desordenado y por fotos la sentencia --------------------------------------------------- otro email: Amalia no me responde y yo quiero saber que si ya ha salido la sentencia. ---------------------------------------------------- otro email: Mi primo que tiene una inmobiliaria le voy a vender el piso y ya he llegado a un acuerdo por 135000 euros.despues he hablado con técnicas que me van a buscar para yo comprarme mi piso aquí en Mérida por la zona sur.buena tarde --------------------------------------------------------- otro email: Perdón que lo he escrito mal disculpe usted es no es técnicos es tecnocasa de la calle Almendralejo una vez venda en malaga compro aquí. --------------------------------------------------------- otro email: Hola señor Miguel quería cuando pudiera despedirme de usted.a mi prima por favor no me hablo con ella y no ponga en su conocimiento que me han quitado la curatela.cuando puedas llámeme para despedirme de usted. ----------------------------------------------------','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2024-01-22','miguel, email de Damian: Ya me han quitado la curatela y tengo un comprador.ya he hablado con María de la parte económica y me ha dicho que tenía la sentencia por delante e iba a arreglar el tema de desbloquear mi cuenta y tenía que darle cuentas al juez.estoy muy nervioso porque no sé cuándo se va a solucionar ------------------------------------------------------ Otro email: Tenía usted razón Amalia el precio que puse por el piso es muy barato voy a ser maduro y consecuente y venderlo por una cantidad razonable voy a consultarlo con asesores y abogados y antes de tomar la decisión de venderlo voy a esperar.muchas gracias por todo -------------------------------------------- otro email: Estoy más tranquilo y voy a coger las riendas de mi vida en condiciones y voy a ser responsable y venderlo por lo que me asesoren y antes de actuar tomar una decision ---------------------------------------------------','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2024-02-05','Ana: Envío correo a Juan Carlos Cano (juancarlos.cano@salud-juntaex.es): "Ésta es una SOLICITUD DE REVISIÓN PIA – DE DEPENDENCIA, relativa a YOLANDA CALDERA MARTÍN cuyo cargo ostenta la CTAEx, que hay que registrar a la UNIDAD DE ACCESO Y VALORACIÓN DE DEPENDENCIA, de aquí de Mérida, Servicios Centrales del SEPAD. Cuando lo hayas registrado, por favor, envíame el Justificante del Registro." ·································· Envío copia de la Solicitud + Justificante SIR a Soraya Masa y Maite Gómez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2024-02-05','AMALIA/ALBERTO: SE SUBE ASIGNACIÓN A 400 €/MES (ANTERIOR 200 €/MES) A PARTIR DEL 01/01/2024 ----- NO SE AUTORIZARÁ NINGÚN TIPO DE EXTRA. AMALIA: TIENES QUE OBTENER DATOS BANCARIOS MADRE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESSICA ESPERANZA'and edp.apellido1='LEON'and apellido2='ENCINAS'),'2024-02-05','Ana: Envío correo a Juan Carlos Cano (juancarlos.cano@salud-juntaex.es): "Te envío adjunta la SOLICITUD DE PNC (PENSIÓN NO CONTRIBUTIVA) de INVALIDEZ, relativa a JESSICA ESPERANZA LEÓN ENCINAS, cuyo cargo de Curatela Representativa ostenta la CTAEx, para registrarla a: Secretaría General de Servicios Sociales, Inclusión, Infancia y Familia Servicio Territorial de Cáceres. Plaza Hernán Cortés, 1. C.P. 10001- Cáceres. DIR3 A11030102 Junto a la siguiente documentación: - DNI solicitante - Certificado Discapacidad – CADEX - DNI Representante Legal – Presidenta de la CTAEx - Decreto Nombramiento – Directora Gerente – SEPAD - Resolución Delegación de Funciones – Presidenta CTAEx"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2024-02-05','TERESA TELFNO DORA 620226363','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2024-02-05','miguel, me llaman desde Cáritas donde reside el hno de la tutelada para preguntarme por los trámites de la herencia de la hna fallecida. Envío email a Angel: Buenos días Angel, me acaban de llamar de Cáritas de Cáceres (Mª Andrade Sanchez 603-476458) preguntando por la herencia de la hermana de la tutelada Antonia Canelada del Rio. Veo en el filtrado que es antiguo y que ya te pregunté en una ocasión. Desde Cáritas llevan al hermano de nuestra tutelada Daniel Donoso Arias (hermanastro supongo), y quieren saber qué hace falta para el desbloqueo de la cuenta de Liberbank (creo leyendo emails, intranet…que es lo único bien de la masa hereditaria). Echa un vistazo y me dices que he quedado en que o la llamas tú o yo para decirle el estado de trámite de esta herencia. Me pregunta también si podríamos encargarnos nosotros de gestionarlo todo porque para ellos es lioso…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2024-02-05','TERESA Te comento de Ati, de ayer... en primer lugar presentaba un comportamiento hostil, beligerante y exigente con la compañera. Pero ayer, el mismo fue quien llamó "disculpandose" mas o menos. Se fue a conocerlo muy amable y respetuoso en todo momento, se ha disculpado por ser tan tajante ayer diciendo que si no llevaba algún documento que me identificara no haría ninguna gestión conmigo. Ha contado un poco su historia y su posición "anti-sistema". Sobre el cambio de domicilio y población, él dice que no tiene problemas con nadie en el pueblo, tan solo está en contra de las personas que están al mando (ayuntamiento, guardia civil, policía local...), pero que no se mete con nadie supuestamente. Sin embargo no correlaciona con la información obtenida de la trabajadora social, que nos relató una serie de incidentes bastante graves. Se le ha explicado que he mirado en varias inmobiliarias y es todo bastante caro en Zafra, está complicado el tema del alquiler. Dice que también podría irse a vivir a Medina de las Torres o a Puebla de Sancho Pérez, que incluso lo prefiere para estar más cerca de Valencia del Ventoso para visitar a su mujer en el cementerio y también de Zafra para otras gestiones, estaría en medio y le vendría mejor. Así quizás haya más posibilidades de encontrar, se buscará también por estos pueblos. Ha enseñado la vivienda ya de vuelta y está muy muy sucia, pero nada destacable de acumulación ni otras cosas. Comentó que no estaba su compañera.. qeu suponemos a realquilado, al preguntarle si compartia piso decia que si, que de forma totalmente desinteresada .. y bueno "como quien colabora para los negritos, que es su acción solidaria" en fin...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2024-02-05','TERESA se le ha visitado hoy, se le avisó previamente para que estuviera en casa y acompañarlo a comprar, pues ayer hizo la retirada de una asignación extra para comida. No estaba en casa, se habla con su hermano porque el teléfono de Ramón no da llamada y facilita otro número que tiene ahora. Cuenta que está en La Albuera, que ha ido a ver a su madre a la residencia porque está enferma. Se le recuerda que habíamos quedado pero dice que está mala y que si o si tenía que ir. Sobre la compra, dice haber comprado, pero no podemos estar seguras... Tlf. Ramón: 632 644 830 Se ha ido a preguntar a varios establecimientos a ver si permitían el pago por transferencia para que Ramón pueda adquirir de este modo los alimentos. En una de ellas dicen que no hay ningún inconveniente, pero que se le debe dejar claro a Ramón que es exclusivamente para comida, pues suele ir y llevarse sacos y sacos de pienso para sus perros. Se habla con Ramón y parece aceptar. Esta parece la mejor opción ya que Ramón se queja de que su hermano (el que vive con él) le quita las cosas, y hacer la compra con él para una semana o 15 días podría significar que no sea él quien lo aproveche todo. Pudiendo ir a la tienda cuando necesite más a corto plazo es una manera de asegurar que se lo comerá él. Se queda a la espera de confirmar que se hará así o si por el contrario es preferible ir a hacer la compra con él con el dinero que retire.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2024-02-05','Ana: Reenvío a los A. Jurídicos, correo de Sheila, Directora del CRR, para que respondan y estén al corriente de los trámites de herencia: "La persona usuaria Antonia Canelada del Río, solicita que le hagamos una fotocopia de su DNI para entregar a su hermano por las gestiones que este está realizando en relación a la herencia de la hermana fallecida hace años en Plasencia. Antonia solicita que se os informe y que si no hay inconveniente por vuestra parte se procederá a entregarle una fotocopia del mismo para entregar a su hermano y pueda continuar los trámites necesarios."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2024-02-05','miguel, en email de contestación a los informes que remití a Josefa el 1-2-24, me indica que la vista ha sido el 23-1-24, estando yo de vacaciones, por lo que no se le han remitido dichos informes a tiempo.','2');
