insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2024-02-05','mIGUEL: cuando tengáis ingresada en Centro a Justa avísame para avisar a Banca Pueyo para que puedan organizar la ejecución hipotecaria de la vivienda. Voy a poner a firma otra solicitud nueva y la entrego con el resto de la documentacion + internamiento involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-02-05','Ana: Llamada de Estrella, TS - CSS Plas: Le han dado un pase para ir a domicilio a Enrique. Desde hoy mismo hasta el miércoles. Le han acompañado varias profesionales, ella, TO y Clara, Ed. Futuex, a quien han informado sobre los apoyos que necesitará para organizar compra y el hogar). Ya le han dejado en casa con la compra hecha y recogida. ············· Refiere que en el pueblo todas las personas con las que se han cruzado han saludado a Enrique educadamente y algunas incluso con cierto cariño. Dice que percepción no es la que expresa Puerto, TS SSASB. ······················ En correo del viernes indicó también: "Y volverá el miércoles día 7 en el bus de las 9 de la mañana que sale de Valdeobispo para Plasencia. Va a comprar el fin de semana una almohada, ya que dice que no tiene, para lo que le daremos 30 euros, deberá traer tiket. 50 euros para realizar compra de alimentos que realizaremos en Valdeobispo el mismo lunes. Y 15 euros para gastos de bolsillo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-10-25','AMALIA : el expediente pasa a la zona de Ana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-02-05','AMALIA : Escribo a S. Eco y derivo expediente a zona Cáceres : Estrella ya ha llegado resolución por la que se reanuda la PNC que tenía suspendida, me preguntaste por ella hace poco ( archivada en su expediente ) . Ya la tiene activada y le han ingresado 1938€ de atrasos . En cuenta peculio se le puede seguir enviando . Ya no va a ser trasladado de centro penitenciario , ha pasado por 3 diferentes . LLeva meses en el Centro Penitenciario de Cáceres , sin incidencias . Ana lo paso a tu zona para seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2024-02-05','Tiene las dos cuentas, ambas están controladas por la Ctaex. A partir de ahora las cuenta por la que se va a realizar los pagos, reintegros … es la acabada en _3331, rectifico el oficio con el número de cuenta modificado, en cuanto lo tenga firmado por su tutora legal, os lo envío. Por lo que respecta a su pensión, todo está correcto, es en la nueva cuenta donde se está ingresando la cuenta desde hace un tiempo. La cuenta que tenemos que cancelar es la __5037, y con la que se va a quedar e la __3331. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2024-02-05','Ana: Correo de Tensi, TS (ssbtensi@riberosdeltajo.es): "me terminan de comunicar que han llamado del Hospital San Pedro de Alcántara que el día 8 de febrero a Isidro le van a operar. Tiene que estar en el hospital a las 12 horas, y por la tarde le operarían. Lo que va hacer noche en el hospital, por lo que alguien va a tener que estar con él. Cómo lo hacemos?" ······································································· Llamo a Tensi, intentarán que haga el acompañamiento hospitalario una auxiliar de confianza y enviarnos la Declaración Jurada. ······················································································································ Envío a Tensi los CI para la Anestesia de la Intervención.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2024-02-05','Amalia : Melanica escribe : Informar que Aquilino Camacho Romero solicitó en el mes de enero la derivación a residencia de mayores. Lo acompañé yo a la T.S para comenzar con dicho trámite y en principio solo ha solicitado la residencia de la Granadilla en Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='CASQUERO'and apellido2='JAEN'),'2024-02-05','Amalia : Melania , CRR " informar que Maria Antonia Casquero Jaén solicitó revisión de grado de dependencia en el mes de diciembre y amplió residencias de mayores teniendo solicitadas actualmente: La granadilla en Badajoz, Cáceres y Olivenza."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2024-02-05','Ana: Envío a Ana Arrufat, Enfermera Casa Familiar Virgen de la Montaña (enfermeriacf-caceres@cruzblanca.org): "Adjunto documento de Consentimiento informado para prescripción de contenciones, relativo a Alejandro Montero Vázquez, debidamente firmado y sellado por la Representante Legal." ······································································································································· Envío a Raquel Árias, Psicóloga Casa Familiar Virgen de la Montaña (psicologiacf-caceres@cruzblanca.org) la autorización anual de actividades debidamente firmada y sellada por la D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2024-02-05','Respuesta de Miguel a la solicitud de EVa : necesitamos para poder solicitar autorización judicial para como indicas, la bajada o retirada del medicamento, nos remitáis informe del médico psiquiatra en ese sentido, por ser él especialista. Saludos -----Mensaje original----- De: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Enviado el: lunes, 5 de febrero de 2024 8:38 Para: MIGUEL FERNANDEZ DE LLERA >miguel.fernandezd@salud-juntaex.es>; Angel Marín Martínez >angel.marinm@salud-juntaex.es> Asunto: RV: A/A ALBERTO (JURÍDICO) Ha llegado al tutelar. -----Mensaje original----- De: Eva Álvarez >trabajadorasocialco@plenainclusionmontijo.org> Enviado el: viernes, 2 de febrero de 2024 13:59 Para: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: A/A ALBERTO (JURÍDICO) Buenas tardes. Me pongo en contacto contigo para comentarte un tema de Adrián Ortigosa Fuentes. Está tomando Decapeptil, un tratamiento inhibidor del deseo sexual, y hablando con el endocrino y el psiquiatra, consideramos que se puede ir retirando la administración de dicho medicamento, para ver qué tal es el comportamiento de Adrián, puesto que lleva muchos años con este inyectable. Nos dice el psiquiatra que, al ser un medicamento que lo autorizó un juez, él no puede pautar la bajada hasta retirada del mismo, por lo que nos gustaría saber si, desde Comisión Tutelar podéis solicitar al juez dicha autorización','2');
