insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2024-02-05','LOURDES: EN SU CUENTA FIGURA HOY 01/02/2024, COMO SALDO TOTAL 6.647,54 €, PERO COMO DISPONIBLE 5.119,34 €, POR TENER UN SALDO RETENIDO DE 1.738,2 €. ANTES DE PROCEDER A SUBIR O NO LA ASIGNACIÓN HAY QUE AVERIGUAR PORQUE TIENE ESE SALDO RETENIDO (EMBARGOS, DEUDAS, OTROS...) PREGUNTA A LA ENTIDAD BANCARIA Y LUEGO LO VEMOS TU Y YO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-02-05','Respuesta de Miguel al email de S. eco : " Perfecto, pues que vaya asumiendo las deudas mientras la asesoria menaya le tramita la herencia. Los importes definitivos no los sabremos hasta que dicten ejecución del juzgado y hasta que la Asesoría nos pase las facturas de todos los trámites. Conforme me vayan requiriendo pagos te lo haré saber. Alberto : ​ MIGUEL: SITUACIÓN ECO DEL TUTELADO...OS PASÉ AL ÁREA JURÍDICA INFORME REQUERIDO X EL JUZGADO EL 19/12/2023 (ESTÁ ACTUALIZADO). DE TODAS FORMAS EL RESUMEN DEL INFORME ES QUE, EN ESTE MOMENTO, LA SITUACIÓN ES CORRECTA: SALDO: 37.000 € APROX. EVOLUCIÓN SALDO ÚLTIMOS 12 MESES: +2.500 € APROX. ---- EVIDENTEMENTE, CON LOS GASTOS SOPORTADOS DURANTE ESE PERÍODO Y QUE, SALVO CUESTIONES SOBREVENIDAS, NO TENDRÍAN QUE VARIAR EN EL FUTURO PRÓXIMO. OPINIÓN: ECONÓMICAMENTE ESTÁ BIEN Y ESTA SITUACIÓN DEBERÍA PODER MANTENERSE EN EL TIEMPO. UNA VEZ QUE SE CUANTIFIQUEN LAS DEUDAS RELACIONADAS CON LA HERENCIA Y LOS IMPUESTOS A ABONAR: ENTIENDO QUE DECIDIREMOS SI MERECE LA PENA O NO ACEPTAR LA HERENCIA CPROPIETARIOS: MIGUEL HABLAS DE 12.000 €...PERO EN REALIDAD NO LE RECLAMAN MÁS DE 15.000 €??? IMPUESTOS. OTROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='TARANGO'and apellido2='DOMINGO'),'2024-02-06','Ana: Envío correo a Cristina Hdez, TS CSS (cristina.hernandezca@salud-juntaex.es): "Te reenvío correo de Abogacía General de la Junta con Citación para Manuel Tarango Domingo para reconocimiento médico forense el día 14/2 a las 11:30. Por favor, confírmame que desde el centro, como es habitual, se realizará el acompañamiento." ··································· Respuesta de Cristina: "Ya lo tenemos organizado y confirmamos el acompañamiento desde el centro."','2');
