insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-02-06','Ana: Envío correo a A. Jurídicos: "Adjunto los siguientes informes para la revisión de la medidas de JUAN JOSÉ MASEDA DEL SOL: - Informe Social emitido por la Trabajadora Social del Centro Ocupacional para personas con discapacidad de Novaforma, al que asiste los días de diario. - Informe de la Médica de Atención Primaria (Especialista en Medicina Familiar y Comunitaria) en el que deja constancia su no asistencia a la consulta (sólo acude por urgencia). A su última consulta en el Equipo de Salud Mental no acudió, por lo que hace años que dejó tener seguimiento por este servicio. - *Sería conveniente hacer hincapié en necesidad de que ingresara en centro residencial (lo indica en el Informe Social en la valoración final. Ya ha rechazado ingresos voluntarios y la familia demanda el ingreso. Él ha dicho en varias ocasiones que sí quiere ir a un centro, pero a la hora de ingresar rechaza la plaza.) Los 3 adultos que conviven presentan discapacidad y existe conflictividad en la convivencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-02-06','Amalia: Manoli Gordillo ya se ha jubilado , hablar con Antonio. Desde menores han accedido para que acabe el curso escolar en HOFA pero no han aceptado la propuesta de que se quede allí algún F.Semana. Hay que buscar plaza para junio , hablaremos con Manuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-02-01','Email respuesta de menores. Hola Soraya, me pongo en contacto contigo para saber si habéis podido avanzar algo en la búsqueda de domicilio definitivo para Regina. Hasta que finalice el curso escolar, estará inscrita en el piso de menores tutelado de Hofa, no obstante, a partir de junio, debería dejar el recurso, dado que estamos muy apurados de plazas. Lo vamos hablando. Gracias Ana Amaya Gala Jefa de Servicio de Protección y Atención a la Infancia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2024-02-06','Amalia : acudo con Maite a su domicilio : C/ MARGARITA XIRGÚ , Nº3 , 1º A , se verifica junto con un vecino que no hay filtraciones en su vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2024-02-06','LOURDES: OK A 60 €/MES REINTEGRO PERMANENTE A PARTIR DE 01/03/2024.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2024-02-06','Amalia : Pido a S. eco : cuando podáis , necesitamos que veáis qué ingresos tiene en su cuenta . Tiene PNC que le han subido de 487 a 517€ Percibe algo de IMIVI , necesitamos saber cuantía, para valorar subir su asignación mensual . No vamos a tocar los 4000€ que le dieron de atrasos hasta que IMIVI regularice sus datos , puede haber generado un cobro indebido .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2024-02-06','Solicito a S. eco : para poder regularizar los ingresos de Ingreso Minimo Vital ( IMIVI ) tenemos que remitir una declaración de sus ingresos de 2023 . Cuando podáis me lo remitís y lo envío al INSS .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2024-02-06','Ana: Envío a Raquel Arias, Psicóloga Casa Familiar Virgen de la Montaña (psicologiacf-caceres@cruzblanca.org) la autorización anual de actividades debidamente firmada y sellada por la D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2024-02-05','Ana: Envío a Raquel Árias, Psicóloga Casa Familiar Virgen de la Montaña (psicologiacf-caceres@cruzblanca.org) la autorización anual de actividades debidamente firmada y sellada por la D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2024-02-06','Ana: Tras hablar con Control de Pensiones del INSS (927 62 00 51), envío correo a Raquel Árias, Psicóloga (psicologiacf-caceres@cruzblanca.org) y a Paz Boticario, TS (et-caceres@cruzblanca.org) de la Casa Familiar Virgen de la Montaña - Hermanos Cruz Blanca: "Me pongo en contacto con vosotras en relación a ALEJANDRO MONTERO VÁZQUEZ, pues habíamos recibido RESOLUCIÓN de INSS de baja en la P. Orfandad por haber cumplido la edad establecida. Pensé que habría sido un error. Hoy he conseguido contactar con Control de Pensiones de la Dirección Provincial del INSS y me dicen que nos les consta la discapacidad, sí la TUTELA y que envíe un escrito con el Certificado de Discapacidad para subsanarlo. He procedido a ello y me encuentro con que el Certificado de Discapacidad tenía carácter provisional, con validez hasta el 31/07/2017. Así que entiendo que el problema está ahí, que no se le ha revisado… a no ser que vosotras me confirméis lo contrario… Así que, cuando podáis, por favor, facilitarle todos los informes médicos posibles así como vuestros, si lo consideráis oportuno, para solicitar valoración al CADEX."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PAJARES'and apellido2='TALAVERA'),'2024-02-06','Ana: Llamada de Mª José, madre de Santiago (671 605 814): ella es quién mantiene a su hijo, el padre no pasa desde hace mucho tiempo la pensión de manutención. Actualmente sólo cobra una subsidio, con lo que apenas llega a final de mes. El dinero que había en la cuenta a nombre de sus dos hijos, lo ha ahorrado ella y ahora no puede abonar las actividades que realiza su hijo por las tardes en la entidad ASPAINCA. Pide que e abonen con el dinero que tiene en la cuenta Santi, parar que pueda seguir participando (la mitad del dinero se separó en cuenta a parte para Santi). ·············································· Informo de eta situación a Alberto, Jefe Secc. Ecca. y a A. Jurídicos, a quienes les pido que contacten con la madre en relación a la reclamación de la pensión de alimentos. ······································································································································ Por otra parte, en cuanto a la renuncia a la plaza en Centro Vera, Mª José me comunica que Santi no quiere ir por varios motivos: 1. Tiene novia en Cáceres. 2. Quiere seguir viviendo con ella y acudiendo a sus actividades. 3. Su hermano Alex, con el que se lleva fatal, reside en Vera y no quiere convivir con él. La relación fue a peor a raíz de haber agredido Alex a la madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2024-02-06','TERESA TELFNO HELENA TS SSASB Mi teléfono directo es el 924540073.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2024-02-02','miguel, el tutelado me envía los datos de identificación del procedimiento de revisión de medidas de apoyo que se están tramitando en el jzdo nº2 de Coria: • Cliente: MANUEL DOMINGUEZ MARTIN Contrario: Juicio: REVISION MEDIDAS DT5 LEY 8/2021 N.º 576/2023 N.º Juzgado: JDO. 1ª INST. E INSTRUCCION Nº 2 CORIA M/Ref.: 20230000157OFI S/Ref.: Letrado: MIGUEL HERNANDEZ PEREZ','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2024-02-06','miguel, me llega email del tutelado Buenas Miguel, aquí le envío esta citación a ver si me puede decir que tengo que hacer ahora?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2024-02-07','miguel, contesto al tutelado en relación al procedimiento de revisión de medidas de apoyo que indica el tutelado. No hemos recibido nada del juzgado. Buenos días, debe hablar con el juzgado y decirles que comuniquen este procedimiento a la abogacía general de la junta de Extremadura. Los trámites del procedimiento de revisión dependen del juzgado no de la Comisión Tutelar por lo que no le puedo contestar a la pregunta que me hace. No hemos recibido nada en la Comisión Tutelar nada referente a este procedimiento','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-02-06','Ana: Correode Carmen Santos, hermana de Enrique (maluker6@hotmail.com): "Buenos días Miguel Ángel, soy Carmen, la hermana de Enrique Santos García-Puente les envío una petición de nuestro tío Miguel, hermano de nuestra madre para que ingresemos 20€ cada hermano en la cuenta que ahí nos indican por favor, ya que a mi madre le corresponden los 100€ que dice para pagos de la herencia aún pendiente de Salamanca. Ayer realizó el comprador del vehículo de nuestra madre las transferencias correspondientes a cada uno de nosotros, es decir, Enrique debe haber recibido en su cuenta 1600€ de Autoscastro, S.L. Como sabrán Enrique está de permiso en su casa desde ayer, me llamó 13 veces, he tenido que bloquear su número porque si no es insoportable su demanda continua. Me dijo ayer él que tienen intención de darle el alta y volver a su casa definitivamente. Se ha celebrado la subcomisión? Yo no puedo ir a darle el perro cada vez que él salga, ya que, por la seguridad de la familia que acoge el perro, no conviene que él sepa quienes son. El 26 de enero fui a visitarle y salimos a comer fuera, en esa salida estuvo con el perro. Su comportamiento fue de continua demanda y en la Plaza Mayor de Plasencia se acercó a una chica joven de nuestro pueblo, a la cual increpó, no sé muy bien qué la dijo, sí vi tanto el gesto de Enrique como el de la chica, la cual reaccionó con una cara de no estar a gusto e ignorarle. En fin Miguel Ángel, otra vez los hermanos tememos lo peor, él es repudiado/rechazado por mucha gente en el pueblo y no hay un sitio donde pueda ir a comer, ni nadie que le ayude a la limpieza, tiene ahora la casa limpia porque yo la limpié, no lo haré más. Se dedica a insistir de manera acosadora a ciertas personas del pueblo, que son muy buenos..., para que le lleven en coche a Montehermoso y Plasencia a sus compras... Hoy ha ido a Montehermoso con una de esas personas. Rezando para que no vuelva a faltar el respeto a niñas. Quedo a la espera de que me digan algo por favor. Pongo copia a Ana, Trabajadora Social."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2024-02-07','TERESA Adjunto solicitud de cambio de datos de dependencia a Nombre de Nerea Dacosta Lorenzo junto con justificante de ingreso en centro Hay que enviarlo a la sección de dependencia de Zafra','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2024-02-06','Ana: Correo de Soraya Masa a Palmira Sánchez (palmira.sanchez@salud-juntaex.es): "Hola Palmira, en el adjunto te hago llegar el informe que me han facilitado desde la UHDAC para el caso de Yolanda Caldera Martín. Como te comuniqué lleva bastante tiempo estable, y en este momento es necesario hacer el cambio a plaza Residencial. Yolanda es además una persona tutelada por la Comisión Tutelar de adultos, motivo por el que pongo en copia de este mail a Ana y Mayte que son compañeras de la comisión Tutelar. El objetivo sería facilitar que Yolanda se adapte al centro lo mejor posible. Si tienes alguna cuestión nos lo haces saber. Cuando lo veas nos vas diciendo para organizar todo lo referente al traslado." ······························ Guardo el informe de la Psicóloga Clínica de UHDAC en el expediente digital. ······························································································································································································· Soraya nos remite a Mª Magdalena Vicente Hdez. -Técnica Dependencia (mmagdalena.vicente@salud-juntaex.es), a Pilar Álvarez, Maite, Maribel Ramos y a mí: "Buenas, en el adjunto os hago llegar la aceptación Pia de Yolanda Caldera Martín, firmada por la Gerente del SEPAD. Por favor cuando nos hagáis la petición de plaza al buzón de acceso a recursos de discapacidad avisarnos para que continuemos con la asignación de plaza lo antes posible."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-02-07','Ana: tras recibir llamada de Felisa (614 361 144), envío correo a la S. Ecca: "Porfa, cuando podáis, mirad si Felisa Felipe Teomiro tiene seguro de hogar. Ella cree que sí, pero en el expediente digital no lo veo. Se le han roto algunas persianas y, en caso de tenerlo, habría que preguntar si le cubre." ······························································································································································································· Tras recibir nuevo requerimiento del Jdo.: "...requerir al tutor a fin de ayudar y propiciar la realización del informe del médico con los extremos indicados en el escrito de la Fiscalía", llamo al C. Salud de Navas del Madroño (927 37 52 82) donde me facilitan correos de Administración (navasdelmadrono.admon@salud-juntaex.es) y del MAP (geronimo.criado@salud-juntaex.es). ············· Envió mail a ambas direcciones: "En relación a Dª. FELISA FELIPE TEOMIRO, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura, me pongo en contacto desde el Gabinete Técnico de dicha comisión para solicitar Informe Médico de Atención Primaria que requiere el Juzgado en el procedimiento de revisión de las medidas judiciales de apoyo. Adjunto: - Requerimiento del Juzgado - Oficio-solicitud de Informe - Justificante del registro Como ven ya fue registrado a fecha de 26 de enero, pero dado que redistribuyen desde la Gerencia y esto puede demorarse, se lo adelanto por esta vía. Gracias por su colaboración y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-02-07','miguel, Estrella Duran nos envía la sentencia por delitos leves 12/23 del jzdo nº6 de CC por el que condenan a multa e indemización al tutelado. Mi contestación con copia a Ana Ts: Gracias Estrella, aunque está mal el nombre de José Manuel, en el fallo que lo cambian por Jaime Manuel, del contenido de la sentencia se desprende la multa e indemnización que habrá que pagar a José Manuel. Hay que esperar que llegue la ejecución de sentencia para poder abonarla. Cuando llegue se lo trasladaremos a la parte económica de la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2024-02-07','Ana: Reenvío corre de Estrella Durán, TS CSS-Plas a Alberto, Jefe S. Ecca: "Te escribo porque hoy he estado haciendo presupuesto de gastos mensuales con Alfonso Marín, (ya que extrajimos los 200 euros que le tenéis autorizados al mes, el día 17 de enero y ya no le queda nada), siendo el siguiente: 36,20 euros a la semana para comprar tabaco 20 euros a la semana para gastos de bolsillo por 4 semanas, hacen un TOTAL: 224,8 euros al mes. Él solicita se le puedan conceder 50 euros más al mes, es decir en vez de 200, sean 250"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2024-02-07','Ana: Correo de Tensi, TS (ssbtensi@riberosdeltajo.es): "solo comentarte que ya busqué una persona para que este con Isidro el día de la intervención y posteriores. Ya te iré informando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2024-02-07','Ana: Correo de Cristina Hdez, TS CSS-Plas (cristina.hernandezca@salud-juntaex.es) a la secc. ecca.: "adjunto mando ticket escaneados de la compra de ropa de Mª Teresa Nevado, en el mes e enero se secaron 300 euros en la asignación de gastos de bolsillo, ya que ella quería ir a varias tiendas para elegir su ropa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-02-07','Ana: Correo de Alberto, Jefe Secc. Ecca: "LOURDES: AUTORIZAMOS 80 €, CONCEPTO "ROPA"."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2024-02-07','Ana: Correo de Alberto, Jefe Secc. Ecca.: ESTRELLA: MODIFICAMOS LO ANTES POSIBLE EL REINTEGRO PERMANENTE Y LO SUBIMOS A 150 €/MES (ANTERIOR 95 €/MES). ······················· Reenvío a Toni-Futuex, para que lo comunique a María, Educadora, y a Anabel Galván, TS SSASB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2024-01-22','Ana: Correo del 16/01 (en mi ausencia): "Buenos días, quería comentaros que mañana operan, como estaba previsto hace un tiempo, a Isabel Cano de la placa del codo. Ha sido hoy cuando nos han avisado, por lo que procedemos a comunicároslo inmediatamente. Previsiblemente pasará en el hospital una noche y al día siguiente regresará a CRR. Está contenta y un poco nerviosa, dentro de lo normal en estas circunstancias. Os iremos contando cómo va todo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2023-12-11','Ana: correo de Paula, TO, del día 4/12/23 en mi ausencia: "disculpad la premura, pero tras mucho tiempo sin que M. Ángeles Santos pueda ir a ver a su padre, se ha presentado la oportunidad. Éste ha estado aquejado con varias dolencias y en este momento se encuentra mucho mejor y está preparando la posibilidad de encontrarse con sus hijos. Propone que Mari pueda ir con él cuatro noches (del 7 al 11 de diciembre) de manera que juntos puedan visitar a Joselito y Rosarito (hermanos de Mari y residentes en sendos recursos de rehabilitación) aprovechando festivos y fin de semana para no interrumpir actividades y procesos de éstos en los recursos. Por ello, si no hay problema por vuestra parte, procederemos a preparar dicha salida."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-06-29','Ana: correo de Paula, TO CRR-Plas.: "Hola Ana, comentarte que revisando incidencias no hemos podido encontrar una relación causal específica entre las visitas a Plasencia de la madre y las autolesiones. Mañana tiene Isabel cita con el Dr. Mora y el lunes tiene cita en Cirugía Plástica en Cáceres."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2024-02-07','Amalia : Escribe Raquel del CRR . Informarte de que han llamado desde psiquiatría para proceder con un ingreso involuntario en UHB y la iniciativa de traslado a UME. A pesar de la negativa de ingreso de Sonia, le han encontrado muy descompensada y en la noche por lo visto ha estado muy inadecuada y con bastantes muestras de agresividad. Les he dado los dos números que tengo de la Comisión para que puedan llamarte a ti y que te informen como tutora. También tienen el número del CRR así que cualquier información te la trasladaremos al momento. La verdad que Sonia no está bien y me da pena la actitud actual, pues ayer se mostró colaboradora y ella misma expresaba inquietud por su estado. Ojalá que pueda estabilizarse.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2024-02-07','miguel, email del abogado Javier Agenjo Ruíz >javieragenjo@hotmail.com> que va a tramitar la herencia de la madre en la notaria de Don Benito: Buenos días Miguel, soy Javier Agenjo Ruiz, Abogado. Mira en relación con la herencia de ISABEL DÍAZ RODRIGUEZ, te remito escrito de expediente de jurisdicción voluntaria para aceptación de herencia, toda vez que al estar incapacitada ISABEL VALADES DÍAZ, y ser sus tutores vosotros, vamos la Comisión Tutelada de Adultas de la Junta de Extremadura, la NOTARIA, me requiere para aportar autorización judicial, porque lo primero que hay que hacer es aceptar la herecnia. Lo que te remito es el escrito de solicitud que realizo en nombre de vuestra tutelada, ISABEL VALADES DÍAZ para presentar en el Juzgado de Don Benito. Lo único que necesito es que vayais con ISABEL al Juzgado más cercano (que entiendo es Mérida), llameis primero para realizar un poder apud acta en favor mia como letrado y de la procuradora para la iniciación de expediente de jurisdicción voluntaria. Te paso lo que tienes que decir: LLamar al Juzgado de Mérida para que den cita para la realización de un poder para presentación de expediente de jurisdicción voluntaria para aceptación de herencia. Que lleve su DNI. Que el poder se realizace para el Juzgado de primera Instnai e Instrucción decano de Don Benito. Que el poder se realice en favor del Letrado JAVIER AGENJO RUIZ colegiado 3546 ICABA, y en favor de la Procuradora FELICIA GARCÍA SERVÁN. Nada más. Te mando copia del expediente que se va a presentar por si tuvieras alguna duda. ----------------------------------------------------------- Llamo al abogado Javier Agenjo Ruiz 687277737: Le pido hable con Rafa de la notaria de Don Benito y se asegure si tengo que ir o puedo ratificar en Mérida y si será o no preciso la asistencia a la firma de la curatelada, que si vive en Mérida, no quedaría mas remedio que ratificar la curatelada y yo en Mérida, siendo imposible hacerlo en Don Benito. 2.-Que me envíe un email indicando los datos de la procuradora e importe que va a cobrar. Ya le he explicado que la curatelada no le llega para contratar abogado y procurador de pago. Me dice que sólo va a cobrar la procuradora y me enviará el presupuesto al email. Una vez que tenga los datos de la curatelada pediremos cita para hacer el poder apud acta en Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2024-02-07','Ana: Correo de Gema Morato, Directora Res. Cedillo (gemamg.asoma@gmail.com): "Adjunto remito carta que he recibido hoy del SEPAD en la que piden documentación de Julián Ramón para proceder con el seguimiento en la tramitación del expediente de solicitud de Ley de Dependencia. Supongo que ya os encargáis vosotros de hacer llegar la documentación a la dirección que aparece en la carta. Espero vuestra respuesta" ··············································· Reenvío correo a Alberto y añado: "Nos remiten esta carta de la RESIDENCIA en que reside JULIÁN RAMÓN CIVANTOS FERNÁNDEZ. No sé si ha presentado declaración de IRPF en estos años anteriores, sino es así, entiendo que habrá que contratar el servicio de una ASESORÍA/GESTORÍA a tal fin. Pues ESTÁ OBLIGO A PRESENTARLA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2024-02-07','Ana: Llamada de Isabel (649 642 635): Tiene cita para Radiografía y Traumatología, revisión por la operación del codo. ················· Pregunta también por el extra anual. Dice que Paula ya envío propuesta. Preguntaré a la secc. ecca. pues yo no tengo constancia. ················ Tiene muchas ganas de ir al pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2024-02-07','miguel, me llama Nadia en relación a una notifiación de procedimeinto monitorio que le han notificado en mano, para preguntar cómo proceder. Me la enviará más tarde. Le comento que si la deuda es de 2019 y no lo incpacitan hasta el 2020 y nos nombran, no vamos a poder hacer nada. Habrá que pagar los 626€ que le reclaman cuando llegue resolución firme del juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-02-07','Ana: Correo de Ana Castillo Foronda TS - FUNDACIÓN AUTISMO SUR (teayudamos@autismosur.es): "¿Cómo estás? Ale está muy bien, ya se hizo la revisión de la valoración de la discapacidad. Te envío la declaración responsable para firmarla que nos lo piden todos los años desde la Junta, si tienes la actualización de la pensión para este año también la necesitaría." ·············· Mi respuesta: De acuerdo, gracias. En cuanto tenga la declaración firmada te la hago llegar. En relación con la actualización de la pensión, no la hemos recibido, el año pasado tuve que reclamarla y me temo que este año va a ser igual. La pediré y cuando la reciba te la envío escaneada." ····································································· Me doy cuenta que viene cumplimentada con los datos de el Anterior Gerente. Necesito el modelo en blanco y se lo hago saber.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-02-09','Ana: cumplimento el Modelo de Declaración Responsable facilitado por Ana, TS - Autismo Sur y lo subo al portafirmas digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2024-02-07','TERESA TERESA TELFNO HELENA TS SSASB Mi teléfono directo es el 924540073.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MARTIN'and apellido2='SANCHEZ'),'2024-02-07','Ana: Envío correo a Estrella Durán (estrella.duranc@salud-juntaex.es) y Cristina Hdez. (cristina.hernandezca@salud-juntaex.es), TS del CSS-Plas: "...Os solicitamos, a requerimiento del Juzgado para el procedimiento de revisión de sus medidas de apoyo, INFORME SOCIAL en que se especifiquen las siguientes cuestiones: “situación actual de D. Teodoro en cuanto a: - Lugar en el que se encuentra - Discapacidad que presenta - Ámbitos y extensión que resulten afectados por su discapacidad y necesidad de apoyo - Cualquier consideración que estimen conveniente sobre ella en razón al procedimiento judicial de revisión de medidas de apoyo.” Cuando podáis, por favor, hacédnoslo llegar para poder remitirlo al Juzgado." ······································ Respuesta de Cristina: "Teodoro sigue siendo paciente mío ya que todavía no ha venido compi de sustitución. Hasta el lunes no vuelvo y no podría hacer el informe, tenemos tiempo ? ············ Confirmo que no hay problema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-02-07','Ana: Llamada de Estrella, TS CSS-Plas: José Manuel regresó ayer al CSS. Regresa con la misma actitud demandante. Me informa de que ya ha amenazado, en los días previos, a Auxiliares y Enfermeras. ············ Al poco de llegar se compró una radio muy grande. Ahora se la ha llevado a Cáceres el fin de semanas y demanda compararse otra. Ya le ha dicho que no. ·············· También demanda dinero para ropa. *Acordamos que como de los 300€ mensuales le sobran 70 del tabaco, que lo compre de ahí (zapatillas y ropa interior). *También ha verbalizado ya querer irse ya a casa. ······················································································································ Llamada de José Luis, hermano de José Manuel (687 581 061): dice que su hermano "está ya quemado de estar allí". Le recuerdo que no hace ni 24 h que ha regresado de estar con él en Cáceres. ················ Dice que se lo quiere llevar con él a su casa hasta que finalice la obra. *Le indico que al igual que el pase que le han dado para esos días, esa decisión es de la Psiquiatra. Que se lo plantee a ella. ··· Aunque también verbaliza que en los 4 días que ha estado en su casa, José Manuel le ha sacado otros 50€.··········· Le aclaro, que en mi opinión, su hermano debe permanecer en el recurso que le han asignado y que sabe de sobra cómo es y los problemas que le genera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-02-07','Ana: Llamo a Marina Carmen Cintas, Jefa Secc. Prestaciones - PNC (924 00 59 22), en relación a error en el cobro de la pensión de Mª Ángeles, desde noviembre, inclusive, se lo han estado ingresando en la cuenta antigua (en la que estaba con su padre y su hermano) y no en la actual en la que está ella sola con representante legal. ······················· Dice que con la fusión de las entidades bancarias han cogido el dato de Programa Alcántara, presumiendo que era ese. ················· Me pide que le envíe de nuevo (por mail y por registro) Alta de Tercero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='SORIANO'and apellido2='LEAL'),'2024-02-08','Amalia : se acepta el acompañamiento , Lourdes escribe: El saldo a fecha de hoy es de 88.744,86€. Tiene dinero, PONGO EN COPIA A ALBERTO, porque tiene balance positivo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='VAZQUEZ'and apellido2='MUÑOZ'),'2024-02-08','Amalia , me escribe TS del Centro La Luz : Hoy han valorado de la dependencia al curatelado JONATHAN VÁZQUEZ MUÑOZ. La valoradora ha sido Esther, del equipo de valoración de Olivenza. Su teléfono es 924478395. Te lo comunico para que estés al tanto por ver si se puede agilizar el que pueda conseguir la plaza de RAL + CO en nuestro Centro. Antes tenía reconocido un grado III y ahora seguramente pase a tener un grado I. No sé cómo esta nueva valoración puede llegar a influir, pero nosotros seguimos insistiendo en que lo más adecuado es que Jonathan consiga plaza en nuestro Centro teniendo en cuenta su trayectoria vital. Aunque ahora es alumno de Transición a la Vida Adulta en el servicio de Colegio, no habría problema en que pasara a CO ya que estamos seguros de que se adaptaría correctamente a dicho servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2024-02-08','Ana: Llamada de Sergio, Pisos Proyecto Mi Casa (627 24 12 53), Plena Inclusión Don Benito. Me informa que Alejandro está ya de camino a los pisos, pues ingresa hoy. ··········· Le informo de la cuantía actualizada para este 2024 de la Pensión de Clases Pasivas: 804,40 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-02-08','Ana: Recibimos por correo postal Certificado Médico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-02-08','Ana: Llamada de Estrella, TS y María, Psiquiatra - CSS Plas.: Puesto que José Manuel "está estable a nivel psicopatológico", ha sido un "ingreso por vulnerabilidad y social", no quiere estar en el CSS y su hermano Jose Luis propone llevárselo a casa, nos preguntan que nos parece si le dan el alta para que se vaya a Cáceres con el hermano. ····· En principio a Maite y mí no nos parece la opción más adecuada, el hermano y la cuñada pueden cansarse de su actitud, demandas y comportamientos. *Finalmente acordamos que en lugar del alta le darán un pase para que, en caso de ser necesario, pueda regresar al centro. ························· Por otra parte, solicito nos envíen informe en que reflejen los incidentes producidos en el centro (amenazas a auxiliares y enfermeras)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='SORIANO'and apellido2='LEAL'),'2024-02-08','Amalia : solicito factura de las gafas para abonarlas . El usuario tutelado FCO. JAVIER SORIANO LEAL ayer 24 de enero de 2024, de nuevo tuvo un episodio de agitación (conducta destructiva). De forma inesperada, se abalanzó sobre una de las usuarias, agrediéndola físicamente provocando que sus gafas se rompiesen. Ayer fueron a la óptica para ver si tenían arreglo, pero les indicaron que no se podía arreglar. Le dieron un ticket con el importe de las gafas que se debe comprar. Estoy pendiente de que me faciliten la factura con sus datos para hacérosla llegar. Te adelanto que según el ticket que me han facilitado, el importe de las gafas nuevas asciende a 393 euros. Ya me decís si puede ser abonada. Cuando tenga la factura os la envío.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-02-09','Ana: Correo de Lourdes, TS SAD IMAS-CC (lourdes.perez@ayto-caceres.es): "Hola, me comunican desde el servicio de teleasistencia que José Manuel les ha dicho que se vuelve a su casa 15 dias, me ha parecido extraño , por eso os lo comunico ? Un saludo" ··························· Mi respuesta: "Gracias por ponerte en contacto e informar. Ayer justo hablamos con la Psiquiatra de referencia de José Manual en el C. Sociosanitario y con la Trabajadora Social. Expresan que él está bien a nivel psicopatológico y que el motivo por el que está ingresado es social, por la vulnerabilidad que presenta y las condiciones actuales de la vivienda. Le dieron un pases para ir a casa de su hermano Jose Luis el fin de semana pasado y ahora le van a dar otro más largo de nuevo para ir a casa del hermano, pues este ha verbalizado querer tenerlo en su casa. En principio la obra tendrá lugar en estos días. Desde el sociosanitario le darán el alta en cuanto ésta esté finalizada. El tiempo exacto no lo sabemos." ································································································································································································ Envío corro a la Sección Económica: "Me dice Estrella, TS del C. Sociosanitario, que había enviado un correo con petición de 100€ para comprar ropa a José Manuel, yo no sé si esto se ha llegado va ver/valorar. Ahora José Manuel vuelve a estar unos días de pase en casa de su hermano José Luis y demanda también este dinero. Pide poder sacarlo el lunes para que le acompañe a comprarlo la educadora de Futuex, pues en el sociosanitario sólo le han dado dinero para tabaco. Ya me decís. No sé cómo tiene la cuenta y como le va a quedar con tanto pago que va a tener que realizar (obra y multa). Pero dice que está sin ropa interior y necesita también zapatillas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2024-02-09','Ana: Llamada de Tensi, TS Mancomunidad (927 300 400): La intervención de Isidro ha ido bien. Hoy mismo le dan el alta. ···················· Hace un planteamiento: Ocupa plaza municipal en PPTT, pero requiere pasar a plaza a Dependencia, tiene reconocido grado II. ···· Justo ahora han quedado plazas libres en la Res. de Mirabel, cree que sería una buena oportunidad de que ingresara allí de forma privada. Y podríamos reactivar el PIA para solicitar PRESTACIÓN ECONÓMICA VINCULADA o PLAZA PÚBLICA en dicho centro. *El problema es que la plaza cuesta en torno a 1.000€ e Isidro sólo percibe una PNC. Y tendría que abonarla unos meses. ·············· Harán la propuesta por escrito para que pasarla al Jefe de Secc. Ecca. Dependerá de los ahorros. ····································· Envío a Alberto, Jefe Secc. Ecca., el Informe-propuesta de cambio de recurso residencial emitido por Tensi, TS, para que valore si es viable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2024-02-09','Maite: A Yolanda se le va a adjudicar plaza en el CAMP de Plasencia. Hemos firmado la renucia a la plaza que tenia en INCLUSIVES de Villanueva de la Serena. Dicha renuncia se ha remitido al centro y a la sección de discapacidad por correo electrónico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-02-09','Maite: Hemos firmado la renuncia a la plaza de residencia en Plena Inclusión Mérida. Enviada por correo electrónico a la entidad y a la asección de discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-02-09','ANA: Envío correo a María, S. Ecca.:"Tal y como comentamos ayer, AUTORIZAMOS A CARLOS GONZÁLEZ LEO un EXTRA POR SU CUMPLEAÑOS de 25€ para la adquisición de un libro. Por favor, cuando puedas haz la autorización para que pueda retirarlo el lunes con su asignación semanal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-02-09','Amalia : escribo a Ana y a Estrella : Ana , este caso te lo había derivado la semana pasada porque llevaba meses en Ctro. penitenciario de CC y me habían comentado que ya no iba a volver a ser trasladado. Y ayer nos informan de otro traslado ! Me he puesto en contacto ya con el ctro. penit. de Badajoz para que nos digan el motivo , no puedo entender cómo lo trasladan tanto . LLeva ya 4 con éste . A no ser que haya sido sancionado por algo .. . Estrella, otra vez , hay que anular Cta. peculio de CC y volver a activar la que tenía en Badajoz . Su pensión ha subido 30 € si quieres aprovechar para subir la asignación está bien. Me dices que no podéis ver de qué son esos ingresos de más de 2000 mil € que ha recibido . No concuerda con la resolución de PNC , se la habían suspendido y la volví a activar . Le han dado 1938€ de atrasos pero no esas dos cantidades que comentas. Desconozco de dónde le habrá podido venir . Si os llega alguna información al respecto me decís . ------------ Contacto con Ctro.penitenciario , pido información sobre traslado y lo que le resta de condena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PAJARES'and apellido2='TALAVERA'),'2024-02-09','Maite: Hemos hecho la renucnia de Santiago a la plaza de residencia en VERA. Se la he pasado por correo electrónico a la secvción de discapacidad y al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2024-02-09','Ana: Raquel Arias me envía el RESOLUCIÓN del Grado de Revisión de Discapacidad y Dictamen Técnico del CADEX Alejandro, con carácter definitivo. ···· Sí le habían revisado. ······ Guardo en el expte. digital y actualizo base de datos. ················································· Envío a Juan Carlos, UPA y CTAEx: "Adjunto los siguientes documentos, relativos a D. Alejandro Montero Vázquez, cuyo cargo ostenta la CTAEx, para remitir a la Dirección Provincial de INSS en Cáceres: - Oficio – comunicación error - Resolución de la Revisión del Grado de Discapacidad - Testimonio de Aceptación del Cargo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-02-09','Ana: Llamada de José Manuel, ayer mismo le dejaron irse a CC. Dice que el dieron 100 € para tabaco. ···················· En cuanto a la ropa interior le digo que tenía que comprarla con los 70€/mes que le sobraban del tabaco, pero dice que Estrella, la TS del CSS, le ha dicho que tienen que autorizar desde la CTAEx los 100€ que pidió ella. *Aunque le explico que ese no fue el acuerdo último con Estrella, insiste en que lo solicite a S. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-01-24','Ana: correo de Estrella, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "Esta mañana he acordado con Enrique Santos un presupuesto mensual, para que tenga autocontrol en sus gastos superfluos y un ajuste realista a sus ingresos, ya que en la actualidad no tiene gastos en manutención, pero esto no va a ser siempre así, ya que está en una unidad hospitalaria, si pasa a una unidad residencial como por ejemplo URA tendría que pagar y si fuera de alta a domicilio también se tiene que mantener. En tabaco gasta 157,5 euros al mes, fumando un paquete al día, vale 5,25 euros por 30 días. En gastos de bolsillo, se le da a la semana 20 euros, por 4 semanas son 80 euros. Y para caprichos se le van a dar al mes 50 euros, por ejemplo el viernes viene su hermana a visitarlo, saldrá de pase con ella y la quiere invitar a comer....En este concepto entrarían también gastos en ropa y calzado no necesario. TOTAL: 287,5 Esperamos vuestra respuesta al respecto." ··························· Hablo con Estrella, ya había un presupuesto previo acordado que se envió por escrito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-02-09','AMALIA : Hablo con Antonio , cuidador de HOFA para valorar las 2 opciones , mantener a Regina un año más en el CEE o pasar ya a plaza RAL +CO. Regina y el resto del equipo HOFA y CEE consideran más idonea la primera , dado que es una formación reglada y le queda un año para acabarla . Propongo una reunion en la que estemos todas las partes para cuadrarlo . Nos reunirimaos en el Edf. SARA . Quedo pte. de la fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-11-10','Ana: Correo de Estrella Durán (estrella.duranc@salud-juntaex.es): "El miércoles día 21 de noviembre van de excursión a Mérida con el servicio de Terapia Ocupacional"','2');
