insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2023-11-10','Ana: Correo de Estrella Durán (estrella.duranc@salud-juntaex.es): "El miércoles día 21 de noviembre van de excursión a Mérida con el servicio de Terapia Ocupacional"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-02-09','Ana: Llamada de Carlos, tiene un juicio el día 14 a las 11:00, por la agresión de su primo. ·············· Le confirmo que se autorizan 25€ por su cumpleaños. Podrá retirarlo el lunes junto con su asignación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-02-12','Ana: Remito a Ana Castillo Foronda TS - FUNDACIÓN AUTISMO SUR (teayudamos@autismosur.es) la DECLARACIÓN RESPONSABLE DE USUARIO DE CENTRO RESIDENCIAL firmada digitalmente por la Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-02-12','Sandra AEXPAINBA : Una vez que la Entidad ha valorado junto con José María la mejor opción para su futuro, se ha decidido que el usuario continúe con su contrato laboral y por tanto cause baja en el servicio de Centro Ocupacional. El contrato de José María es de pocas horas, por lo que para completar el tiempo que ya no va a estar en centro ocupacional, desde el servicio de orientación laboral de Aexpainba se va a establecer un convenio de prácticas de limpieza para así, poder beneficiar su CV y tenga una mayor probabilidad de poder establecer más horas de contrato. Además, desde este mismo servicio también van a ayudar al usuario en la búsqueda activa de un trabajo que conlleve más horas o que complemente el que ya tiene actualmente. Cualquier duda que tengáis al respecto podéis poneros en contacto conmigo sin problema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2024-02-12','Amalia : se aprueba la subida del reintegro de 750 a 800€ mes .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2024-02-12','Ana: Envío a Raquel Arias, Psicóloga Casa Familiar Virgen de la Montaña (psicologiacf-caceres@cruzblanca.org)"Tal y como hemos acordado mediante conversación telefónica, te envío adjunta la autorización, firmada y sellada por la Representante Legal, para que Antonio Tejada Fernández pueda acudir al partido de fútbol a Madrid, acompañado por el voluntario de vuestra confianza."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2024-02-12','Ana: Envío correo a Toni-Futuex: "Te envío derivación de YOLANDA CALDERA MARTÍN. Por lo que veo en el expediente ya la tuvisteis en el programa hace años, pero no me consta cuando la dejasteis de visitar. Actualmente está ingresada en la UHDAC, pero este mismo miércoles día 14, la trasladarán al CAMP de Plasencia, en el que le han asignado plaza. Las especificaciones están en la hoja de derivación, ante cualquier otra cuestión, no dudéis en contactar." ································ Llamo a Ana Marta - CAMP Plas: Tuvieron una reunión con el CSS y bajaron a conocer a Yolanda, como están ahora al mínimo, han pospuesto el ingreso al lunes 19. ··········· Le pido que valoren la posibilidad de acordar un acompañamiento durante los primeros 10-15 días, en el horario que consideren que puede hacerles más falta, con alguna/s cuidadoras de confianza a las que se le abonaría mediante transferencia bancaria tras enviar declaración jurada, con el fin de facilitar la adaptación de Yolanda al nuevo recurso. ······················ Comunico a Toni que se pospone el ingreso al lunes 19.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEVERIANO'and edp.apellido1='TARANGO'and apellido2='DOMINGO'),'2024-02-12','LOURDES/AMALIA: OK A SUBIDA REINTEGRO MENSUAL A 500 €/MES (6.000 €/AÑO), LO ANTES POSIBLE ----- ANTERIOR REINTEGRO: 450 €/MES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2024-02-12','Ana: Correo de Estrella Durán: "Ana, se me olvidó decirte esta mañana cuando hablamos, que la visita de Guadalupe al CRR fue regular, sigue diciendo que no quiere ir, se muestra muy inhibida e insegura fuera del centro , con ganas de volver. Esta mañana ha venido a verme para que llamara a Montaña la T.S. de su pueblo, y ha dicho que prefiere irse a la Residencia de T.E. de su pueblo, te lo comunico por si esto lo podéis gestionar porque me temo que va a ser la única manera de evitar la institucionalización aquí... Ya me dices...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2024-02-12','Ana: Llamada de Sergio (640 654 897): pregunta cuándo podrá irse a otro centro, que no aguanta más allí, que la comida cada vez es peor y el pan duro... Que sí el día 24 no sabe nada de plaza se irá de allí. ····· También pregunta, una vez más, por el resto de su dinero. Le explico que lo que le queda mensual de su pensión, tras abonar centro y gastos de bolsillo, está en su cuenta, se le está ahorrando para lo que pueda necesitar. Y que si necesita algún extra para algo que lo hable con Julia, Coordinadora del centro, pues se puede gestionar. ················· Acordamos que tendrá algo más de paciencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2024-02-12','TERESA el día 15 de Febrero Nerea será trasladada a la UHDAC de Plasencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-02-12','Ana: Llamada de Julia (644 876 893): con el dinero autorizado se ha comprado un pantalón, una blusa y una chaqueta. ········ Dice que si es capaz de perder peso le valdría más ropa de la que tiene en casa. ······················· Ahora está sin Psiquiatra, no le han sustituido aún. ··········· Con la enfermera del ESM tiene cita el día 29.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2024-02-12','Ana: Soraya confirma a Maite que Yolanda ingresará con plaza RAE en el CAMP de Plasencia el miércoles 14/02. ·····························································································································','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2024-02-14','Ana: correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Trasladar información sobre la persona usuaria Esteve Pascual Ramos que ingresó el día 6 de febrero de 2024 en la UHB de Cáceres, tras activación de protocolo para atención y valoración para traslado a la urgencia en TMG, por desestabilización y aumento de agresividad, siendo dado de alta de la UHB de Cáceres el lunes 12 de febrero de 2024."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-02-14','Ana: correo de Lourdes, TS del SAD - IMAS (lourdes.perez@ayto-caceres.es): "Hola, me acaban de informar la empresa de ayuda a domicilio, que Jose Manuel está en su casa , les ha llamado para que le presten el servicio ." ······························································ Tras hablar con José Manuel, envío email a Lourdes, IMAS, Estrella, CSS, Toni-Futuex y Maite, Jefa CTAEx: "Os reenvío correo de Lourdes, compañera TdS de IMAS de Cáceres. Esta mañana he intentado hablar con su hermano, sin éxito, estará trabajando, pero después me ha llamado el propio José Manuel, que de entrada, por supuesto, no me ha dicho nada al respecto. Cuando le he preguntado, me dice que está en casa de su hermano, que a su casa va “a dar una vuelta” y que ha llamado al Servicio de Ayuda a Domicilio para que vayan limpiando para cuando se vaya a casa. La obra aún no está hecha, ahora le han dicho que irán la semana que viene. *Le he explicado, de nuevo, que hasta que la obra no esté terminada no puede instalarse en su casa y que no debe usar ese baño, y que por supuesto, hasta que no esté instalado en su casa no podrá acudir la Auxiliar de Ayuda a Domicilio a prestarle el servicio. Toni, no estoy segura si te comenté que iba de pase a casa de su hermano José Luis (15 días). Por favor, haced seguimiento allí y verificad que no se está quedando en su casa, pues el baño aún no puede usarlo. Prestarle los apoyos como siempre. Y si constatáis o veis indicios de que está en su casa quedándose o “más horas de la cuenta”, usando el baño, comunicádnoslo, por favor. Le he recordado que si no cumple lo pactado tendrá que volver al Socio hasta que finalice la obra. Por cierto, hoy su petición es la de ingresar en CRR…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2024-02-14','miguel, solicito autorización judicial para comprar e hipotecar inmueble','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MARTIN'and apellido2='SANCHEZ'),'2024-02-14','Ana: Envío a los A. Jurídicos, el INFORME SOCIAL para la revisión remitido por Cristina Hdez., TS del CSS-Plas (cristina.hernandezca@salud-juntaex.es). ································································································································ Según Informe Social, permanece en la ULE y no ha habido cambio desde los últimos informes para rendiciones. Apenas sale del centro (sólo a citas médicas y similar), el único hermano con el que tiene contacto ha querido sacarlo con pases en distintas ocasiones, pero él se negaba siempre. Cuando estuvo en el CRR, no se adaptó y regresó al CSS. Con sus otras 2 hermanas no tiene ningún tipo de relación. ··········· Apenas participa en actividades.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2024-02-14','TERESA Hoy se ha mantenido desde el equipo pequeño encuentro con la policía local de Zafra por el tema de Josefa, llama constantemente y querían informar para saber más claramente cual es su situación. Las llamadas normalmente son informativas, por ejemplo “ayer llamó diciendo que había una señora que le tocaba a la puerta y se escondía, que no quería que fueran pero para que lo supieran” y así cada vez que llama. Helena, la TS de los SSB, iba a enviar en la mañana de hoy los informes de la policía en los cuales se recogen estos hechos. Han establecido este protocolo de hacer informe cada vez que llame hace poco, de ahí para atrás hay otras muchas notas que si es necesario podrían estructurar y resumir para enviarlas también. También se ha hablado con Helena, la TS, sobre el tema. Sería perfecto que se llevara a cabo un ingreso voluntario, además por lo que comentaba puede permitirse una residencia privada, pero tendríamos que tener la seguridad de que no se negara en el último momento. En general, por las mañanas está cansada y se siente muy vulnerable, por lo que podría ser un buen momento si aceptara. A última hora de la mañana he ido a visitar a Mª Josefa a su domicilio, está muy apagada y dice todo el rato que se va a morir, que quiere irse ya a una residencia porque no quiere morir sola. HOY ESTABA COMPLETAMENTE A FAVOR Y DISPUESTA A INGRESAR . De hecho se le ha preguntado varias veces sobre si está segura que quiere estar en la residencia y ha dicho que si en todo momento, incluso se le ha hablado de que el hecho pudiera ser muy próximo, explicándole que a ver si pudiera ser todo para la semana que viene … ante lo que Josefa ha dicho “lo antes posible, que quiere irse ya " o tendremos que ir pero con un ataúd", palabras textuales. Es cierto que no podemos conocer si cambiará de opinión debido al estado de descompensacion psicopatologíca en que se encuentra , pero es cierto que en diciembre se negaba rotundamente a ir a una residencia, pero ahora creemos que influye que se ve muy mal y no quiere estar sola, por lo que es un buen momento para el ingreso voluntario,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-02-14','TERESA TODOS: TIENE UN SALDO HOY, SUPERIOR A 16.000 € X TANTO PODRÍA ASUMIR ESE GASTO DE 2.000 € -3.000 €/MES APROX. DURANTE LOS 2 MESES PREVISTOS. ÁREA SOCIAL: LA CTAEX NECESITARÍA UN INFORME PROPIO QUE JUSTIFIQUE ESTE GASTO...(TERE INDICA QUE HAY ORDEN DE INTERNAMIENTO INVOLUNTARIO Y QUE NO HAY PLAZAS DONDE INGRESAR A TUTELADO)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2024-02-14','Ana: Envío correo a Melania, CRR-Olivenza (MSERVAN@caseresidencial.es): "En relación a tu correo del día 7, con “presupuesto” de ropa para CEFERINO MARISCAL CRESPO y “presupuesto” de arreglo de la controladora, así como en respuesta a la situación/gestión económica en general, tras reunirme con Alberto, Jefe de la Sección Económica, el lunes a última hora, me remitió este correo que os reenvío, concretando la situación y para que os haga la siguiente propuesta y en los términos que podéis leer en el hilo: Al igual que se venía haciendo en el CRR de Plasencia, os proponemos que desde vuestro CRR os encargaseis de gestionar un extra anual para Ceferino, para todas aquellas cuestiones que pueda necesitar/demandar, y que valoréis necesarias/beneficiosas para él, sin tener que solicitar a la sección económica un extra para cada ocasión. Guardando, eso sí, las facturas/tickets para justificación anual. Sería una prueba que podríais extender en un futuro al resto de residentes a cargo de la CTAEx si os resultase práctico. Entendemos que puede ser de utilidad y serviría para agilizar y simplificar los trámites de tipo económicos. La cuantía propuesta sería la misma que se le aprobó en 2023 (3.500€ en dos plazos, más detallado en el hilo), no obstante, si lo consideras, en el caso de Cefe, podría incrementarse algo más (tendrían que decidirlo antes de enviar la autorización al banco). Y eso sí, en dicho extra, como podéis leer también, iría incluido todo tipo de gastos. Ya me decís que os parece, y si tenéis alguna duda al respecto, lo hablamos sin problema. Pongo a Amalia en copia para que esté al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-02-12','Estrella : Me dice que él ha pedido el traslado a Badajoz, para estar más cerca de su padre. Q vive en Helechosa de los Montes. Cuando salga el 22 de marzo , se va a ir a vivir con el padre al pueblo ( de momento). Voy a cancelar la permanente q tiene en peculio de Cáceres. Importe 350 €/mensual. Se le hará una puntual de 380€ para marzo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2024-02-13','OK A REINTEGRO DE 850 €/MES (NO HAY PROBLEMA)......ÚNICAMENTE DECIR QUE LAS CUENTAS QUE EL CENTRO HIZO HACE UN AÑO SE HAN QUEDADO MUY CORTAS EN MUY POCO TIEMPO + EL REINTEGRO MENSUAL (INCLUIDOS EXTRAS DE ESTOS ULTIMOS 12 MESES HA SIDO DE 783 €/MES + 450 € DE UN TAXI). LOURDES: MODIFICAMOS REINTEGRO PERMANENTE QUE, A PARTIR DE 01/03/2024, PASARÁ A 850 €/MES (ANTERIOR 750 €/MES)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='GARCIA'and apellido2='SANCHEZ'),'2024-02-14','Ana: Llamada de Pepi, Responsable Res. de Mayores de Madroñera (605 903 129 / info.madronera@acja.es): A Juan le ingresaron el domingo en el hospital San Pedro de Alcántara. Desde entonces no han sabido nada y no han conseguido contactar con el hptal. ·············· Por otra parte aprovecha para informarme de las dificultades que se encuentran habitualmente con Juan desde que ingresó. Como norma general, ni se asea ni permite que le aseen. No toma adecuadamente la medicación, la tira o escupe cuando se la administran. Desayuna en allí, pero después se va a su casa, aún no reuniendo condiciones de habitabilidad, y no regresa hasta las 17 - 18 h. No saben qué come en su casa. ····· No consiguen que la podóloga le corte las uñas. ····· Amenaza al personal con frecuencia. ············ Le indico, que si llegara a ser necesario por agresividad u otro tipo de riesgo pueden activar el 112. ·················· *Pido también informe de incidencias y situación para poder informa al Juzgado. ··············· *Aún no está valorado por dependencia. Pidieron valoración en 2022. ································································································································································································· Llamo a Luli, TS HSPA (56348): me informa que ingresado en Geriatría. El Médico que le lleva es Dr. Jaramillo (51574). Le llamo, me informa que Infección respiratoria (no oxígeno) y de orina, nauseas relacionadas con la tos, aunque no es productiva, no vomita. Está tolerando vía oral. Antibiótico oral. ··· Está comiendo, no se ha arrancado la vía. ········· Si todo continúa así en pocos días podrán darle el alta, posiblemente el viernes. ······ Están tendiendo dificultades en la comunicación debido a su sordera. ·············· *No es necesario contratar ninguna auxiliar, está bien atendido por el personal del hptal. ···· Sí sería bueno llevarle unas zapatillas, cerradas por detrás y que no resbalen, tipo "estar por casa" podrían valer o similar. ·································································································································· Llamo a Pepi: mañana le llevará ella las zapatillas al hospital y así también le ve y pregunta por evolución. *Si fuera necesario compararía unas zapatillas, pero cree que pueden valer unas que tiene allí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='GARCIA'and apellido2='SANCHEZ'),'2024-02-14','Ana: Llamada de Pepi, Responsable Res. de Mayores de Madroñera (605 903 129): A Juan le ingresaron el domingo en el hospital San Pedro de Alcántara. Desde entonces no han sabido nada y no han conseguido contactar con el hptal. ································································································································································································· Llamo a Luli, TS HSPA (56348): me informa que ingresado en Geriatría. El Médico que le lleva es Dr. Jaramillo (51574). Le llamo, me informa que Infección respiratoria (no oxígeno) y de orina, nauseas relacionadas con la tos, aunque no es productiva, no vomita. Está tolerando vía oral. Antibiótico oral. ··· Está comiendo, no se ha arrancado la vía. ········· Si todo continúa así en pocos días podrán darle el alta, posiblemente el viernes. ······ Están tendiendo dificultades en la comunicación debido a su sordera. ·············· *No es necesario contratar ninguna auxiliar, está bien atendido por el personal del hptal. ···· Sí sería bueno llevarle unas zapatillas, cerradas por detrás y que no resbalen, tipo "estar por casa" podrían valer o similar. ·································································································································· Llamo a Pepi: mañana le llevará ella las zapatillas al hospital y así también le ve y pregunta por evolución. *Si fuera necesario compararía unas zapatillas, pero cree que pueden valer unas que tiene allí.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESSICA ESPERANZA'and edp.apellido1='LEON'and apellido2='ENCINAS'),'2024-02-14','Ana: Llamo al CADEX (21993 - Adtvo), en octubre hicieron la reivisón del grado de discapacidad de Jessica. Aún les consta como domicilio el CAMP de Caminomorisco, le llevarían desde allí y no nos lo comunicaron. Ya tiene el grado definitivo. ·············· Me enviarán por mail el CERTIFICADO y el DICTAMEN TÉCNICO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2024-02-14','Ana: envío correo a Toni-Futuex: "En relación a ANDRÉS SILVA BONIFACIO, como sabéis sigue ingresado en la UHDAC, y me plantean Estrella, TS, que volváis a retomar seguimiento con él. De hecho te copio textualmente: “Hablé con Maripaz Psicóloga de UHDAC sobre el tema de derivar a Andrés Silva Bonifacio con Futuex. Me dice que sí, que hagáis la derivación.” Porque ya me lo había planteado antes, pero entendía que era necesario valoración clínica la respecto. Así que, cuando podáis, por favor, volver a visitarle y ya nos vais informando de procedencia y resultados de estos seguimientos/apoyos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-01-22','Ana._ Correo de Amalia del 15/01/24, al ctutelar@ y a mí: "Antonio va a ser derivado el día 17 del CSS Mérida al CRR Plasencia. Os paso el presupuesto que han elaborado para él para que cuando podáis gestionarlo : En relación al presupuesto que hemos elaborado es de aproximadamente 300 Euros mensuales y un extra puntual de 150 Euros (para sábanas; edredón; toallas; caja caudales): • Tabaco (15 paquetes mensuales); • Dinero de bolsillo; • Higiene personal; • Salidas/excursiones/actividades de ocio; • Teléfono móvil (recargas); • Necesidades extras (medicación no subvencionada; reparación objetos personales). Durante el periodo de adaptación seguirá en mi zona y luego pasará a la zona de Ana para seguimiento ."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-01-22','Ana: correo de Toni-Futuex, del día 15/01, estando yo de vacaciones: "Aunque creo que estais al tanto. Trasladamos que hoy José Manuel comunica a la educadora que su psiquiatra, el Dr. Molina, le ha llamado la semana pasada para decirle que puede ingresar en el centro sociosanitario de Plasencia a lo largo de esta semana, con vistas a que pueda estar allí unos meses hasta que haya una plaza libre en algún CRR de la provincia o de la Comunidad donde pueda residir. Esto derivado de la situación de emergencia social que consideró el doctor después de la última consulta con José Manuel donde le contó qué había ocurrido en su vivienda y cómo se encontraba actualmente. Y está información según informa, Jose Manuel, para intentar corroborarlo, se contacta con ESM Cácere, hemos conseguido hablar con el psiquiatra que comunica que sí es cierto todo esto y que está terminando el informe de José Manuel para empezar el proceso con la mayor brevedad posible, a poder ser esta misma semana. Él descarta la posibilidad de un CRR porque ya ha pasado por varios y de todos ellos ha salido con problemas (normalmente por agresiones) y, además, ahora mismo no hay plazas disponibles. Ha considerado junto con el SEPAD y la CTAEX que el ingreso en Plasencia es la mejor alternativa para la situación en la que se encuentra José Manuel actualmente. Se habla con él también sobre cómo se producirá el traslado hasta Plasencia, considera que lo mejor sería de una manera que a él no le haga cambiar de opinión, por ello se propone la posibilidad de contratar el servicio de un taxi para José Manuel y que la educadora pueda acompañarle hasta allí. El doctor queda en llamar directamente a la educadora cuando ya esté todo en marcha. Si os parece, podemos sondear algun taxi, de cara al desplazamiento, pero hasta no saber el dia concreto no se podra concertar." ················· Teresa, TS CTAEx. se encargó de las gestiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2024-02-15','Amalia : envio por email a la madre el certificado solicitado mamenmillon38@gmail.com tf de la madre 666898994','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2024-02-15','BUENAS TARDES; POR LA PRESENTE OS ENVÍO LAS SOLICITUDES DEL INTERNO EN LA CUAL DESEA , POR UN LADO, QUE EL DINERO LE SEA TRANSFERIDO A PUERTO I DADO SU RECIENTE TRASLADO –SE ADJUNTA NUMERO DE CUENTA- Y POR OTRO, UN TRANSFERENCIA PUNTUAL DE 213 EUROS PARA LA COMPRA DE TELEVISIÓN. SE HA COMPROBADO QUE NO TIENE NI TELEVISIÓN NI RADIO. SE ENCUENTRA EN RÉGIMEN CERRADO Y EN LA ACTUALIDAD SON MUCHAS LAS HORAS DE FORMA ININTERRUMPIDA EN LA CELDA SOLO. Raquel Billarin Gilbel Trabajadora Social Centro Penitenciario Puerto I Carretera Jerez-Rota Km. 6.4 11500 El Puerto de Santa María ( Cádiz) raquel.TS.71480@dgip.mir.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GEMA'and edp.apellido1='MONROY'and apellido2='FERNANDEZ'),'2024-02-15','Amalia : consulta jurídica desde Ap 3 y respuesta de Miguel , la madre quiere sacarla y la sentencia no es firme. Buenos días, si bien la sentencia de nombramiento a la Comisión Tutelar de Adultos no es firme, si que es ejecutable y por tanto si estimáis que no debe salir del centro, que no lo haga, salvo que os de el consentimiento de salida firmado la propia Gema. Por otro lado necesitaremos un informe de las distintas incidencias fechadas para comunicarlo al juzgado. firma miguel 2024 De: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es> Enviado el: miércoles, 14 de febrero de 2024 13:41 Para: MIGUEL FERNANDEZ DE LLERA >miguel.fernandezd@salud-juntaex.es>; Angel Marín Martínez >angel.marinm@salud-juntaex.es> CC: Catarina Maria Ferreira Barbedo >coordinacion.fa@aprosuba3.org> Asunto: RV: urgente madfre de Gema se la quiere llevar uenos días , desde Aprosuba 3 nos hacen una consulta jurídica . Está residiendo allí GEMA MONROY FERNANDEZ . Os envié la sentencia de medidas de apoyo que ya tenía el centro , pero en la Comisión no ha entrado nada . Y no se ha aceptado el cargo . Al parecer la madre está allí y se la quiere llevar . Os paso el email de la Trabajadora Social para que le podáis responder directamente . Ponedme en copia por favor . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='ESTEVEZ'and apellido2='RODRIGUEZ'),'2024-02-15','Amalia : se amplia el SAD , han dejado de ir al Ctro. Dia y comen en casa . Autorizado por Alberto a nivel eco. Recibo email de la empresa que no lo había iniciado aún . Nuria me ha comentado lo de las 30h/mes de Antonio Estevez, y ha habiado un error de entendimiento.... yo pensaba que el aumento de horas funciona como el Sepad (que hay que esperar que pasen unos meses para empezar) y siempre le había preguntado por el aumento de precio de las 20h, con lo cual... empezamos mañana con los 90 minutos en lugar de los 60 que se estaban trabajando hasta hoy 14','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-02-15','Ana: Correo de Toni: "Adjuntamos el documento que estaba pendiente de firma de los familiares de Juan Jose Maseda, se han resistido muchisimo, cada vez que se ha intentado y han sido varias, han puesto pegas.. que si no podian y otras excusas, puede ser que haya concidido que haya sido asi, o que tuvieran por el motivo que sea, reticencias a firmarlo , el caso es que ya está. El dia que la compañera va al domicilio de Juanjo Maseda, donde se quedó con Azucena (cuñada) y con David (hermano) para firmar la autorización familiar para la revisión del PIA de Juanjo, aprovechando la visita, los familiares enseñan cómo está la habitación de Juanjo, ya que no se responsabiliza de nada que tenga que ver con las tareas del hogar o incluso de su propia higiene, tienen que batallar a diario con él para que haga algo, y muchas veces no lo consiguen. Azucena comenta que ha escrito a la CTAEX para pedir un armario para Juanjo, la educadora comprueba que esto es necesario ya que no tiene y la ropa está por la habitación sin tener dónde guardarla, antes había un armario pero se rompió. El armario sería uno normal de dos puertas, no es necesario que sea muy grande. Pedimos presupuesto y lo enviamos?" ········································ Mi respuesta: "Vamos por partes: - Gracias por los documentos, no sé por qué se habrán mostrado tan reticentes cuando ha sido ella la que ha vuelto a pedir que se pide el ingreso poco tiempo después de haber rechazado… a saber. - Con respecto al armario, sí, por favor solicitar presupuesto y nos lo hacéis llegar. - Por otra parte, Azucena, lleva una temporada que envía continuamente peticiones de tipo económico solicitando extras varios. Intentad, porfa, canalizar vosotras todas las peticiones, proponiéndoles esta opción en lugar de enviar ella tantos correos con solicitudes varias. - Así mismo, ya sabéis que es importante que sigáis abordando con él, y con la familia, la necesidad de ingreso en centro para cuando vuelva a darse la oportunidad, pero ahora tiene pinta de que va a tardar ya que hoy mismo voy a presentar de nuevo la solicitud de revisión PIA." ···································································································································································································· Envío a Juan Carlos, Aux Adtvo.(juancarlos.cano@salud-juntaex.es): "Adjunto la siguiente documentación relativas a D. JUAN JOSÉ MASEDA DEL SOL, cuyo cargo ostenta la CTAEX: - Solicitud de revisión PIA – Plaza en Servicio de Atención Residencial de Discapacidad firmada electrónicamente por la representante legal - Autorización de Miembros de la Unidad Familiar para consulta/verificación de datos firmadas por los familiares - Decreto de Nombramiento de la Directora Gerente del SEPAD - Resolución de delegación de Funciones como Presidenta de la CTAEx - DNI – Presidenta de la CTAEx por delegación Para remitir por REGISTRO a la Unidad de Acceso y Valoración de Dependencia. Buzón Registro - Revisión PIA: A11034037"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-02-15','miguel, contestación a Amalia: Buenos días, acabo de hablar con la abogada que teníamos en intranet y le ha llevado algunos procedimientos, Olivia 691-236633. Me comenta que desconoce si le queda pendiente algo, por lo que como tiene previsto reunirse con José Vicente Vicente el lunes, me llamará después para confirmarme si le queda alguna pena pendiente, incluida la orden de alejamiento del padre. Si no tuviera nada pendiente no podremos limitar su decisión de ir a vivir con su padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-02-14','miguel, email de amalia: Buenas , este señor sale del Ctro. Penit. Badajoz el proximo 22 marzo. Ni reúne requisitos ni quiere ningún tipo de centro. Nos ha dicho que se va a ir a vivir con el padre a Helechosa de los Montes. Pero creo recordar que había una orden de alejamiento del padre por malos tratos , cómo podemos averiguar si se ha extinguido ?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-02-15','-Amalia : quedo pte. de la respuesta de Miguel para saber si ya ha finalizado la O.alejamiento del padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2024-02-15','Ana: Correo de Gema, Directora Res - Cedillo (gemamg.asoma@gmail.com): "Les comunico que ha fallecido Victor Manuel Blanco Poveda hoy día 15/02/2024 por si tenéis que tramitar algo" ····················· Llamo a Gema (639 694 905 // fijo de la residencia: 927 590 145): ha fallecido hoy de madrugada en el hospital. ············· Lo ha comunicado al hijo y a una tía de Víctor Manuel. ····· Es probable que trasladen el cuerpo a Valencia, al mismo pueblo donde están enterrados su padres. ···· También ha facilitado a la funeraria el número de póliza del Seguro de Decesos - Helvetia. ······ Los gastos de farmacia pendientes los abonará ella en efectivo con el dinero de bolsillo que le quedaba en el centro. ··············· *Hablará con la TS - SSASB, para comunicar la baja de la Prestación Vinculada a Dependencia. ················ Como tiene que volver a hablar con la funeraria, le pido que por favor les pida que nos manden el Certificado Literal de Defunción para la rendición final.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-02-15','Amalia : la TS del Ctro . Penitenciaro nos informa : Como ya tenéis constancia Gustavo sale en libertad el día 15 de febrero, tiene comprado billete. El día 16 tiene cita con Trabajadora Social Pilar de la US.M. de Cáceres. Espero que todo vaya bien y Gustavo pueda integrarse en un medio normalizado. ----------------------------------------------------- A nivel eco ya se ha realizado el pto. con las asignaciones mensuales . Se han comprado electrodomesticos y mobiliarios para habilitar el piso familiara donde va a ir a vivir . Seguimientos con Futuex y ESM Caceres .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA VALLE'and edp.apellido1='PATARRO'and apellido2='CARMELO'),'2024-02-15','Amalia , la semana pasada contacté con Rosa , TS del SSASB 924700000 , el expediente lo lleva la otra TS ( Natalia ) tengo que volver a llamar y que me pasen con ella. Está en los Pisos Tutelados de Fregenal C/ Bravo Murillo , 3 Fregenal .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2024-02-15','Ana: Respuesta de Maite, Jefa Sección a Estrella, TS UME-CSS, a su anterior correo: "Respecto a Guadalupe Gil, la opción de entrar en el centro de mayores de su pueblo no es posible. NO cumple requisito de edad para recurso de mayores. Cuando estuvo anteriormente, fue de forma muy excepcional ante la situación en la que se encontraba, ( ‘’ Le hicieron el favor a la trabajadora social). Por tanto , esta vía no la podemos contemplar. Habrá que seguir trabajando en el ingreso en CRR. O tendrá que permanecer en vuestro centro hasta que tenga la edad requerida para centro de mayores ( le quedan unos tres años). No hay muchas opciones., pero la vuelta a su casa no es viable"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2024-02-15','TERESA Buenas tardes, se envían varias cuestiones sobre el tema económico de Diego, algunos gastos son también compartidos con Juan Antonio (su hermano) pero su cuenta bancaria es la misma por lo que no debe haber inconveniente. Te lo paso a ti, y según tu valores, para pasar al area economica si te parece. En primer lugar, hay tres pagos pendientes que se deben abonar: -Factura taxi compartido Diego y Juan Antonio para renovarse el DNI (a Zafra): 60€ -Factura taxi compartido Diego y Juan Antonio para citación judicial (a Vca. de los Barros): 98€ (Se adjuntan facturas donde aparece todo detallado y el número de cuenta) -Pago de la renovación del DNI de ambos hermanos por la educadora (no llevaban dinero para ello y lo abonó la educadora) Coste de duplicado por pérdida: 12€ por cada uno Coste de las fotos de J. Antonio: 5€ TOTAL A ABONAR: 29€ (se adjuntan justificantes de pago y ticket del estudio de fotografía) A abonar a Patricia Gata González (educadora apoyo social comunitario Zafra) 29€, número de cuenta: ES31 2100 4540 0021 0025 3117 En segundo lugar, en la primera visita Raquel, la auxiliar del SAD, y Petrona, interna que cuida a Diego, comentaron que tras la crisis que ha sufrido y las condiciones en las que está necesita varias cosas de las cuales se ha pedido presupuestos y se adjuntan en pdf. Por otra parte, solicitan también si es posible un aumento de la asignación, dicen que dejan a deber en algunas ocasiones porque no tienen suficiente (se ha podido comprobar que en algunos tickets pone entrega x, deja a deber x). Han facilitado los tickets desde que ha vuelto a casa tras la crisis hasta finales de diciembre, y esta es la información que se ha obtenido: • SPAR: 197,97€ • Tienda de alimentación del pueblo: 828,51€ • Farmacia: 32,81€ • Eroski: 35,39€ • Agrog. La fuente (pienso para los perros): 31,60€ TOTAL GASTO DESDE APRÓX. EL 30 DE OCTUBRE AL 27 DE DICIEMBRE: 1126,28€ TOTAL RETIRADA DESDE EL 30 DE OCTUBRE AL 27 DE DICIEMBRE: 900€ (9 lunes, que es el día que hace la retirada, a 100€ semanales) Según lo que han facilitado, parece ser cierto que no llega, en los tickets se ha podido observar que no hay nada fuera de lo normal (fruta, verdura, carne, pescado, aceite, leche…) alimentos del día a día. En la farmacia suelen comprarle jarabe para los mocos, para la tos, corega… Le propusieron que le llevaran la comida a casa de la residencia, pero no le gusta lo que le ponen y apenas comía, ahora está muy bien cuidado, come y le gusta lo que le prepara, por lo que piden que siga siendo así. En principio, lo que más le urge son las cosas de las cuales se ha pedido presupuesto, y que se abone lo que se debe (el taxista ya ha preguntado que cuando le pagarán).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2024-02-15','TERESA Ayer se visitó a Adolfo y se estuvo en la cita de salud mental, lo que habia dicho Lorenzo de que se iba a hacer cargo creemos que ya no se está cumpliendo. Te desarrollo un poquito mejor: Ayer se habló con Lorenzo y se le avisó para ir a su casa, donde está viviendo ahora Adolfo supuestamente. Al llegar Lorenzo no sale (estando la puerta abierta), se le llamo por teléfono y dice que justo se acaba de ir Adolfo, que lo mismo está en su casa. Nos dirigimos a casa de Adolfo y allí está, se habla con él sobre qué tal estos días en Mérida y todo eso, cuenta que fue una situación muy incómoda el que viniera la policía y el traslado pero que allí muy bien, que le han dado medicación y que se le está tomando. Sobre donde vive, dice que ha pasado dos noches en casa de su hermano pero que ya va a empezar a quedarse de nuevo en su casa, que él no quiere vivir con su hermano porque prefiere estar en su casa tranquilo. Comienza a decir que Lorenzo es muy arisco pero se corta, se le dice que no se preocupe y que puede hablar lo que piense sin ningún problema, dice que Lorenzo tiene un carácter fuerte, que grita y se altera fácilmente y que eso a él no le gusta. Todo esto diciendo entre medias que lo trata muy bien y que no vaya a pensar nada malo de él, como cohibido o pensando que no debe decirlo. Se le preguntó qué va a comer y dice que la comida que le lleven del catering, a este establecimiento se le dijo que no llevaran más la comida porque Lorenzo había pedido un dinero en concepto de manutención y se haría cargo. Adolfo no tenía ni idea de que ya no le llevarían la comida, al comentárselo dice que entonces su hermano le llevará algo y que no tiene mucha hambre... Adolfo pide ir a dar un paseo y se le acompaña, pero Lorenzo nos me pide que lo acompañemos una tienda cercana a por unos tirantes y que se lo apunte a su nombre (de Lorenzo) que él lo paga. En dicho establecimiento dice la dependienta que ya mandó a Adolfo con otra chica a por cosas que supuestamente iba a pagar y no ha pagado, tiene una deuda de casi 100€. Como fácilmente se puede observar, esta persona no está para hacerse cargo de Adolfo ni está cumpliendo con lo que dijo, ya que él está en su casa y se duda incluso que haya pasado con él algún día. Mañana se Sobre la consulta de salud mental: La doctora Leticia le hace diferentes preguntas y Adolfo ha mostrado claramente su estado mental. Negaba tener un trastorno obsesivo compulsivo, decía haberse curado y le pedía el alta a la doctora, se negaba a tomar la medicación o decía que se tomaría "algo", hablaba de que su madre en algún momento resucitaría... Comentaba que no quiere más ingresos y que la CTAEx lo había "denunciado", siendo ese para él el motivo del ingreso. La doctora le ha intentado explicar el proceso de ingreso involuntario pero Adolfo insistía en lo mismo, no consigue entenderlo. Lorenzo, su hermano, le ha dicho que vive con él y que se encargará de intentar darle la medicación, mientras que Adolfo comentaba que se va a quedar en su casa y no con su hermano. También le ha dicho que se hace cargo, aspecto que se pone en duda, de hecho al salir de la consulta ha comentado que si Adolfo quiere vivir solo él no lo puede retener. También ha dicho que él le preparaba siempre la comida, cuando sabe perfectamente que se la llevaba el catering hasta que ha vuelto de Mérida, de hecho a la vez que Lorenzo decía que él le cocinaba Adolfo ha dicho que se la llevaban... Sobre el tema de la deuda en la tienda, se lo he comentado a Lorenzo y dice que habrá sido Adolfo el que ha ido sin que él lo supiera y ha dicho que lo pagaría él. Esto no es cierto, pues la dependienta dijo claramente que había mandado a otra chica con Adolfo diciendo que pagaría Lorenzo. ARCHIVO INFORME DE ALTA DONDE REFLEJA QUE SE VA A VIVIR CON SU HERMANO LORENZO HABRA QUE ESTAR PENDIENTE POR SI ES NECESARIO DEJAR DE PASAR LA MANUTENCION AL HERMANO Y CONTRATAR DE NUEVO CATERIONG','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESSICA ESPERANZA'and edp.apellido1='LEON'and apellido2='ENCINAS'),'2024-02-15','Ana: Guardo en el expediente digital el CERTIFICADO DE DISCAPACIDAD - CADEX (REVISIÓN) y DICTAMEN TÉCNICO remitidos por David Cambero, Adtvo. CADEX (david.camberoramos@salud-juntaex.es) ·················································· Envío correo a Juan Carlos Cano (juancarlos.cano@salud-juntaex.es): "Adjunto documentación para registrar a la SERVICIO TERRITORIAL DE SALUD Y SERVICIOS SOCIALES de Cáceres, relativa a la Dª. JESSICA ESPERANZA LEÓN ENCINAS, cuyo cargo ostenta la CTAEx: - Oficio - subsanación de solicitud de PNC y valoración de complemento de tercera persona - Certificado de Discapacidad - Revisión del CADEX - Resolución de la situación de Dependencia DIR3 A11030102"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2024-02-15','TERESA sobre Ati, me comentan que se le ha contactado por teléfono para concretar una cita mañana en Zafra para ayudarle con la gestión de búsqueda de piso. Dice que no tiene medios para desplazarse hasta Zafra, que no tiene dinero para pagar autobús ni taxi. Por otra parte, afirma que si la educadora no lleva algún documento que acredite su puesto de trabajo no hará ninguna gestión con ella, pide que vaya “identificada” en varias ocasiones durante la llamada. Se le explica que si se tiene la información es porque forma parte del trabajo, que ya conversó con la comisión sobre este asunto y que además ya han ido otras compañeras antes y sabe como funcionamos, pero le da igual, dice que no se fía. También exige, de manera firme y cortante, que "se le busque un buen piso y no como el que tiene, y que además deben aceptar mascotas". No sé como podemos hacer, seguiremos intentando , pero no va a facilitar las cosas nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2024-02-15','Ana: Llamada de Mª Aª (927 095 795 // 677 80 64 45) a Estrella, secc. ecca: solicita aumento de asignación mensual de 20€,se ha cambiado de piso de alquiler, a otro del mismo dueño, pero la habitación es más grande. ··············· También le dice que se quiere extraer una pieza dentaria, pero en lugar de hacerlo en la clínica en que se está haciendo el tto. quiere ir a la seguridad social. ··································· La llamo para comunicarle que **se aprueba la subida a 420€/mes. Pero no consigo contactar en ninguno de los teléfonos, fijo ni móvil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-02-14','Ana: Llamada de Carlos, ha acudido a la cita en el Jdo acompañado por Mamen, Ed. Futuex. Está con ella y pone el manos libre, pero no le deja hablar. *Ha firmado consentimiento para continuar con el procedimiento (denuncia a su primo por la agresión). Pero se ha suspendido el proceso de declaración del día al haber comunicado que está a cargo de la CTAEx. Entienden que volverán a citar para que pueda acudir alguien en representación. ··················· Mamen me pide que le llame cuando pueda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-02-15','Ana: Llamo a Mamen, Ed. Futuex (663 85 17 59 - nº del trabajo): le está costando mucho la intervención con Carlos, se contradice mucho, cree que a veces miente, pero cuenta todo de forma muy convincente con todo detalle. ········ A veces se pone agresivo verbalmente con ella. *Me pide que cuando pueda lea las notas de seguimiento que ha subido a al Aplicativo de Futuex. ·················· La cita en Psiquiatría le llegó a él a casa, pero él se lo ha ocultado y cuando se lo ha reconocido le ha dicho que la tenía muy temprano, a las 9:00 h y que no iba a ir a perder el tiempo allí, que sólo quieren "drogarle". ·············· Le informo de que hablé con la Psiquiatra y que reprogramarán nueva cita y nos la enviarán a la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-02-15','Ana: llamo a David Cambero, Adtvo. del CADEX, Cáceres (21993), como no obtengo respuesta le envío un correo (david.camberoramos@salud-juntaex.es): "En relación a D. AITOR MORENO FELIPE, cuyo cargo ostenta CTAEx, su certificado de discapacidad tiene carácter provisional hasta 29/02/2024. ¿Podríais informarme si está prevista su próxima revisión en este mes? Entiendo que es de oficio y no tenemos que solicitarlo desde la CTAEx, ya me dices cuando puedas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-02-16','Ana: Respuesta de David Cambero, Adtvo. CADEX (david.camberoramos@salud-juntaex.es): "Ya tiene cita programada se le llamará para indicar día y hora. Se puede hacer un certificado de prórroga si lo necesitáis para algún trámite." ························ Respondo: "Agradeceríamos nos comunicaseis también la cita a nosotros para asegurarnos de que acude y para que le puedan acompañar. Y sí, agradeceríamos que nos facilitaran un Certificado de Prórroga para presentarlo en el INSS, pues hemos recibido escrito en relación a la Prestación Familiar por Hijo a Cargo, indicando que si no presentamos la Renovación del Certificado antes del día 29 del presente, se extinguirá la misma."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES MARIA'and edp.apellido1='ALVAREZ'and apellido2='CARRASCO'),'2023-12-22','Amalia : tramito nueva solicitud de PFHC y comunico tanto a PFHC como a P.orfandad el nuevo Nº cuenta bancaria para que procedan a cambiar las pensiones . Desde el CSS de Mérida han dado una orden al banco para que en cuanto entre las pensiones en la cuenta anterior hagan transferencia interna a la nueva cuenta para evitar que la hermana saque el dinero .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES MARIA'and edp.apellido1='ALVAREZ'and apellido2='CARRASCO'),'2024-02-16','Amalia : Gloria de Pfhc me pide que haga la nueva PFHC , le reenvío email de la documentación y justificante de registro , eso ya está tramitado .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2024-02-16','miguel, me llama Coro y le explico que ayer teníamos cita en la notaria de Mérida de Don Gonzalo Fdez Pugnaire para firmar la ratificación de las 3 Cv, pero que no le ha dado tiempo a preparar el documento a la notaria, dandome nueva cita el jueves 22 a las 9,30h. Por otro lado le explico que José Santiago tras intercambiarse varios emails conmigo quedó que presentaría de nuevo el escrito en el juzgado de Villafranca para subsanar el Auto que autoriza las ventas, sin que haya vuelto a saber si lo ha redactado o presentado. Si en 1 semana no me llama lo llamaría yo. Quedo en informar a Coro, la notaria de los Santos y Maria Cadenas de la Providencia cuando tenga ratificada las 3 Compraventas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-02-16','Ana: envío correo a Toni-Futuex: "Hace algunas semanas, a petición de mi compañero Ángel, Asesor Jurídico, y tal y como pedía el Juzgado, solicité al Programa de Familia Tajo-Salor Informe relativo a Felisi, en los términos indicados a continuación, para presentar en el procedimiento de Revisión de Medidas Judiciales de Apoyo: “Discapacidad que presenta. Ámbitos y extensión que resulten afectados por su discapacidad y necesidad de apoyo. Situación familiar y asistencial. Cualquier consideración que estimen conveniente sobre él en razón al procedimiento judicial de revisión de medidas de apoyo.” No os lo pedí a vosotras porque las Educadoras nuevas llevaban poco tiempo y entendíamos que, desde el PAF, siendo recurso de proximidad y atención directa, conocían muy bien toda su situación así como su trayectoria, pues llevan muchos años interviniendo con la familia. Dado que la respuesta fue que no podían hacerlo, ¿podríais elaborarlo vosotras desde el programa?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2024-01-22','Ana: Correo de Lourdes, S. Ecca: "Te envio este correo, solo para que tengas conocimiento de que ha tenido que ir dos veces a consulta. La factura, ya está preparada para abonar." ····················· El que reenvía de Toni-Futuex: "Se adjunta factura de taxi, de DOS DESPLAZAMIENTOS, de la tutelada Eugenia Pacheco desde la residencia de Hervas donde reside actualmente a Plasencia, para una cita en SM, son dos servicios, porque fueron y no estaba la doctora, la educadora que le habia acompañado en el desplazamiento intento hacer las gestiones pertinentes pero les dijeron que se trataba de algún error y regresaron... y cuando estaban en el camino de vuelta les llamaron para decir que si, que efectivamente tenia la cita. Un despropósito en cuanto a la administración de este centro sanitario en este caso. Por esto es el motivo que de dos servicios en el mismo día, Hervás-Plasencia"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTIAN'and edp.apellido1='CARRASCO'and apellido2='BLANDON'),'2024-02-16','TERESA SOLICITO INFORME SALUD MENTAL A PETICION DEL CADEX POR CORREO ORDINARIO AL EQUIPO DE SALUD MENTAL DE MONESTERIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2024-02-16','Ana: envío correo a Alberto, Jefe S. Ecca: "La TS de NOVAFORMA, no solicita una subida de asignación mensual de José Fermín Gía Pablos, además de que ella lo ve necesario, él también la demanda. No sé exactamente con qué periodicidad retiran el efectivo, pero a él le dan 8€/semana para sus gastos del bolsillo y plantean una subida a 12€/semana. Por mi parte si es viable, ok a la misma."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2024-02-16','TERESA Jose Mª ha solicitado a Helena la trabajadora social que quiere ir residencia de mayores Necesito que el medico me rellene el informe que te adjunto para hacer la solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-02-16','Ana: subo al portafirmas digital la autorización para que procedan al cambio de médico que me remite Ana Foronda, TS F. Autismo Sur. ········· Motivo: "...Nos comentan desde el Centro de Salud que es necesario volver a pedirle médico ya que aparece como "pasivo" y necesitamos renovarle una medicación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2024-02-16','Ana: Reenvío a la S. Ecca. correo de Toni-Futuex: "Se adjunta carta recibida por Ventura Gómez, tiene pendiente un pago, por si nos hubiera llegado a vosotros, sobre el balneario. El teléfono parece que ya le funciona, tal vez tocó alguna cosa.."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-02-16','Ana: Envío a la S. Ecca.: "os reenvío este de la Trabajadora Social de Cáritas de Plasencia. Es un presupuesto de teléfono para ANGEL FÉLIZ MAILLO SANTIBAÑEZ. Se aprobó la compra de uno hace ya meses, pero por h o b, no acaba de comprarse. En el presupuesto no aparece número de cuenta bancaria, así que os paso el teléfono para que podáis hablarlo con la tienda y acordar el modo de pago. Tec & Phone: 927 77 73 93 Ya me decís si finalmente se compra ahí. Gracias." ···························· Nuevo correo de Yessica de Arriba, TS Caritas (ydearriba@caritasplasencia.org): "Por otro lado, ayer nos exigió Angel Félix que le busquemos una habitación urgentemente porque le han robado una herramienta para esculpir. Probablemente os comente a vosotros también esta exigencia. Os informo por si hay alguna posibilidad de encontrar habitación. Porque el Centro de Acogida tiene las plazas cubiertas." ···································································································································· Envío correo a Toni-Futuex: "En relación a Félix Maillo Santibañez, te reenvío correo de Yessica de Arriba, TS de Cáritas. Deciros: - Por un lado, que se hablará con la tienda para comprar el móvil. Si no hay inconveniente se abonará mediante transferencia. - Por otro, que por favor, intentéis retomar seguimiento con él y le prestéis apoyo en la búsqueda de alojamiento. *Si rechaza, pone impedimento, dificulta… por favor, elaborad informe al respecto de la falta de colaboración en el programa y la no aceptación de los apoyos tras haber retomado la intervención."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2024-02-16','Ana: Correo de Estrella Durán, TS CSS - Plas (estrella.duranc@salud-juntaex.es): "Como sabéis ayer ingresó Nerea Da Costa en la UHDAC, viene sin dinero, por lo que haced el favor de enviar la autorización para que pueda ir el Ordenanza a extraerlo del banco que sea. Por otra parte, está llamando su madre y su hermana, nos gustaría saber si podemos darle información, si es conveniente que hable con ellas, etc.... Esperamos vuestra respuesta" ·································· Tras consultar con Teresa, TS CTAEx, le reenvío respuesta: "la familia la desestabiliza mucho que le dejen hablar pero con supervisión "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-02-16','Ana: correo de Estrella Durán, TS CSS: "Os informo que el jueves día 22 irá 4 días de pase a domicilio Enrique. En el anterior pase, detectó que tenía el calentador de agua estropeado, por lo que he llamado a un Fontanero para que se lo vea ese mismo día. Éste me dice que en otras ocasiones, se lo ha arreglado y le ha llevado la nota al Ayuntamiento, y éste se la ha abonado, os lo comunico para que me digáis como proceder..." ······················································ Mi respuesta: "La factura, si nos la hacéis llegar con el número de cuenta den fontanero al correo ctutelar@salud-juntaex.es, la abonarán mis compañeras mediante transferencia bancaria."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2024-02-16','Ana: Reenvío correo de Laura, TS IMAS (laura.dominguez@ayto-caceres.es), a la secc. ecca.: "Tengo aqui a Montaña que me pide que te mande las facturas del gas que le dicen que tiene pendiente. Desde el IMAS le hemos ingresado unos 317€ para el gas y 20€ para el agua, pero ha habido un problema con la cuenta, porque no habia informada que la cuenta que teniamos aqui la habia cerrado, por lo que hemos solicitado el ingreso en la nueva cuenta de Unicaja. Lo recibirá en unos días. Me dice tambien que tiene dos cuentas abierta en UNIcaja, dice que por favor le cerreis la cuenta en la que menos dinero tiene. Ponte en contacto con ella si puedes...." ····· Explico/solicito también en mi correo: "Os reenvío correo que tenía pendiente de la semana pasada de la TS del IMAS (Ayto. Cáceres) *Hay que abonar las facturas pendientes, por favor. Y por cierto, hay que comprobar qué suministros están domiciliados en la nueva cuenta que se abrió desde aquí y lo que no esté domiciliado hay que domiciliarlo. Por cierto, como podéis leer, le gestionaron y concedieron la Ayuda para Suministros Mínimos Vitales, así que genial. Cuando podáis, me decís también cómo está su cuenta, pues creo que también dejaron de retenerle ya la pensión de alimentos. Supongo que algo habrá ahorrado desde su estancia en el CSS."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2023-07-10','Ana: Correo de Cristina Hdez., TS CSS (cristina.hernandezca@salud-juntaex.es): "Soy Cristina, Trabajadora Social de la Unidad de Rehabilitadora Activa del Centro Socio-Sanitario de Plasencia. Le escribo en relación a la paciente María Montaña González Rolo (tutelada por CTAEX) para informarle que el pasado día 3 de julio, tras el cambio de medidas se marcha de alta al domicilio con su familia. Ese mismo día es comunicado vía telefónica a Amalia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2024-02-16','miguel, me llama la hermana del tutelado Natalia 609253442, me pregunta los trámites para poner a nombre de los 4 hermanos la vivienda de Badajoz de los padres fallecidos (que no dejaron testamento). La relación no es buena entre las 3 hermanas por lo que me pondrá un email con copia a las hermansa para aclararlas cualquier duda sobre los trámites a realizar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2024-02-16','Ana: Reenvío a Tensi, TS SSASB, respuesta de Alberto, Jefe S. Ecca.: "...PROPUESTA: PASAR A CENTRO PRIVADO X 990 €/MES • NO ES VIABLE CON SUS INGRESOS ACTUALES • INCLUSO EN EL CASO DE QUE LE CONCEDAN LA VINCULADA, PARA QUE EL CAMBIO FUERA VIABLE, ESTA DEBERÍA SUPONER UN IMPORTE, COMO MÍNIMO DE 450 €/MES----O SUPERIOR SI LOS GASTOS MENSUALES ASOCIADOS AL CENTRO (REINTEGRO/OTROS) FUERAN SUPERIORES A LOS ACTUALES DE 12 €/MES."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='GARCIA'and apellido2='SANCHEZ'),'2024-02-16','Ana: Llamo al HPTAL. al Dr. Jaramillo (51574), pero no obtengo respuesta. ········· Llamo a la Pepi, responsable de la residencia, no le han dado el alta. Mañana intentará pasarse a ver cómo está. ········· No pudo llevarle las zapatillas porque la tienda del pueblo estaba cerrada y no tenía unas adecuadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2024-02-19','TERESA Pues se consiguió que Mª Josefa se vaya voluntariamente a la residencia, ayer!. Se le llamó a primera hora de la mañana y, aunque no se negaba, decía que era muy temprano. Más tarde se acudió a su casa y un poco enfadada porque para ella seguía siendo temprano y quejándose (como siempre), cogió algunas de sus cosas y se fueron para allá. Le preocupa que le roben o que alguien entre en su casa, ha pedido varias veces que la vigile la compañera, por si viera algo extraño... Ya en la residencia, ha tenido la entrevista con la coordinadora y enfermera, justo el médico que trabaja allí la conoce de toda la vida a ella y a su marido. Esto ha facilitado mucho, se ha sentido cómoda y ha hablado con él del pasado sobre cosas que él sabía, y eso le encanta. Aunque de primeras se negaba a ducharse y un poco a todo, la he dejado entrando en el baño con la auxiliar para bañarla y asearla, pues iba muy descuidada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-02-19','Ana: Remito a Ana Castillo Foronda TS - FUNDACIÓN AUTISMO SUR (teayudamos@autismosur.es) la AUTORIZACIÓN PARA EL CAMBIO DE MÉDICO, firmada digitalmente por la Representanta Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='GARCIA'and apellido2='SANCHEZ'),'2024-02-19','Ana: Correo de Pepi, Residencia - Madroñera (info.madronera@acja.es): "Ana como bien quedé contigo e echo el favor de ayer sábado día 17 de ir a ver a Juan a la residencia de San Pedro de Alcántara . e ido después de salida de mi trabajo . El señor Juan García Sánchez está ingresado en el San pedro de Alcántara en la octava planta de Geriatría . El estado de Juan es no muy agradable hablo con la geriatra y la enfermera que lleva al paciente me informan de que está en un estado muy grave el cual me dicen que puede fallecer en hora o días . Juan García Sánchez tiene una sobrina llamada Antonia , no tiene ninguna relación con su tío pero mi deber es informarla y que es su único familiar . La verdad es que la señora me llama y manda mensajes para ver el estado de su tío . Ana le e llevado unas zapatillas como me dijiste Te informo de lo poco que puedo saber , mañana si quieres me llamas y ya le voy informando de lo que vaya sabiendo." ·································································································································································································· Llamada de Pepi (613 84 29 36), comunica que acaba de FALLECER Juan. *Como no tiene seguro de decesos avisará a una funeraria del pueblo. *Nos enviarán presupuesto. ········ Tiene dinero suficiente para abonar el servicio. ··························· *Llamo al HPTAL. al Dr. Jaramillo (51574), a partir del jueves el riñón evolucionó a peor, ha fallecido por INSUFICIENCIA RENAL e infección intra-abdominal. ··········· Le indico que ya está avisada la funeraria para hacer el servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-02-14','Ana: Correo de Toni-Futuex: "Hola, de nuevo hoy se ha acompañado a Joaquina a la cita en el ESM de Cáceres con su psiquiatra, el Dr. Molina. Se adjunta informe. LLega bien en la ambulancia, pero está muy nerviosa y dice que se ha mareada en el viaje. Se percibe que se debe más a los nervios por la cita médica que por el viaje, Joaquina es una persona muy nerviosa y en cuanto esto le ocurre le aparecen eccemas en la piel de la cara, la educadora se fija que le han vuelto a salir. Respecto a la medicación, Joaquina expresa que le va muy bien con el Depakine y la inyección pero la pastilla que toma por la noche le deja demasiado anestesiada, incluso los minutos posteriores a ingerirla no es capaz de gesticular ni hablar debidamente. El doctor le rebaja la dosis de esta pastilla a la mitad (tomaba 300 y ahora tomará 150). Por lo demás se mantiene igual, la revisión será dentro de 4 meses. Joaquina cada vez se siente un poco mejor y su movilidad es mayor, hoy se ha movido sin el andador (otra recomendación del psiquiatra). En la consulta, Joaquina pregunta si va a poder irse a casa en algún momento, el doctor le dice que no es conveniente y que ella está mejor en un centro donde esté bien atendida, ella dice que está muy a gusto en Alcuéscar con todas las trabajadoras pero que le gustaría, al menos, estar más cerca de su pareja, Ángel, que está en Mérida. El psiquiatra valora el ingreso en la residencia de mayores de Mérida como positivo y viable, pero confirma que es una decisión que depende de la CTAEX y de si ellos consideran que puede llevarse a cabo, al menos solicitarlo (ya que es un proceso muy largo). Quiza es cierto que lleva bastante poco tiempo en Alcuescar y más que un cambio, pues no sabemos si seria factible que se autorizara alguna estancia puntual o algo asi.. Se vuelve a comentar, lo de la asignación, aunque fuera minima, para que tuviera algo para poder gastar en la residencia, siempre y cuando sea posible, lo demanda constantemente y se valora que podria ser beneficioso, para tomar algun café o alguna cosa de este tipo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-02-19','Ana: Envío correo a la sección económica preguntando si ya tenemos acceso a la cuanta de Joaquina y cómo está su situación económica, pues lleva meses en la Residencia ya sin asignación para gastos de bolsillo. ································································································································································································ Escribo a Toni-Futuex: "Ya he pedido de nuevo a la sección económica que comprueben si ya tienen acceso a la cuenta bancaria y, si es así, comprueben situación para poder estableces asignación para gastos de bolsillos. Por complicaciones con la firmeza de la nueva sentencia y el banco las ocasiones anteriores no se pudo hacer… Con respecto al cambio de centro residencial, aún es pronto para poder solicitarlo. En cuanto sea posible, se puede hacer. No obstante, creo que tanto cambio en tan poco tiempo podría resultar contraproducente. Vamos a ver cómo evoluciona, y cuando sea viable solicitarlo si mantiene la demanda me encargo de las gestiones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2024-02-19','Ana: Envío correo a IBERDROLA (prejub@iberdrola.es): "Me pongo en contacto con ustedes para comunicar la DEFUNCIÓN de D. VICTOR MANUEL BLANCO POVEDA, con DNI 04153418D, cuyo cargo de Curatela Representativa ostentaba la CTAEx. Adjunto Certificado Médico de Defunción con la fecha y hora de la misma: 15/02/2024, a las 06:30 en el Hospital Universitario de Cáceres. Aún no disponemos del Certificad Literal del Registro Civil, si lo precisan, cuando nos lo hagan llegar se lo podemos remitir." ··············································································································································· Envío a Juan Carlos, para REGISTRO, oficio-comunicación de FALLECIMIENTO, para remitir a la TESORERÍA DE LA SEGURIDAD SOCIAL. ······························································································································································································ Subo al PORTAFIRMAS DIGITAL la COMUNICACION A DEPENDENCIA DE BAJA EN PRESTACIÓN VINCUALDA POR FALLECIMIENTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-02-19','TERESA AITOR TIEN CITA EN ECA CACERES EL DIA 20 DE FEBRERO Lo de las benzo, nos ha sorprendido ya que, el no tiene pautada medicación, (no sabemos si las cogerá de la madre o de donde...) La cita del dia 20, es con la ts de la ECA, y ya está diciendo que no quiere ir. Entonces se nos ocurre una cosa, desde el programa no hay problema en acompañarlo bien a la ECA o en el pueblo al médico de primaria, pero creemos que no nos va a hacer mucho caso. Pero tú si eres bastante figura de referencia para el, y te suele hacer caso, asique si le comentas que tiene que ir al médico, tal vez sea mejor. Y luego esta el tema que ECA el dia que vaya, a la ts, puedan en todo caso pautarle algo debido a que va ingresar en la comunidad terapeutica y tal, que pudieran igual hacer el favor de que lo viera la medico, seria más adecuado que yendo a su medico de primaria no? osea más especifico, no más adecuado. No se , como lo veis??','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2024-02-19','TERESA GESTION TELEASISTENICIA PENDIENTE DE COMPRAR TELFONO Hemos hablado con la auxiliar, y nos comenta que no tiene inconveniente con que se le pueda poner a ella de persona de contacto, reside en la localidad, se llama Maria del Mar y su telefono es 663711108, intentamos también hablar con Maria (la casera) pero pasa temporadas en el campo y ademas choca con la auxiliar porque es un pco controladora, asique con el de ella, creemos que bastara.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2024-02-19','TERESA Se ha autorizado el pago de todo lo presentado, te aviso cuando este abonado para que pasen a recoger los ELECTRODOMESTICOS También necesito me facilites el DNI renovado de Diego.´ No podemos subir asignación pues la situación económica al tener la cuidadora es mala, no sé cuánto tiempo vamos a poder mantener este nivel de gastos….. y además no dejan de salir facturas pendientes de pagar que desconocíamos y con las cuales no contábamos cuando aceptamos el tener una interna. El tema de la perrera no lo vamos a pagar tendrá que ir a reclamarlo al juzgado pues nadie tenemos conocimiento de que eso se haya autorizado Si vuelve a necesitar acompañamiento hospitalario no vamos a poder pagar lo que se ha pagado anteriormente, ni tantas horas de acompañamiento, ni gastos de desplazamiento y de comida, hacérselo saber a Petrona para futuros ingresos. Si hay un ingreso habrá que cuestionarse el que vaya a una residencia directamente tras el alta hospitalaria…. Si Diego continua necesitando atencion 24 horas durante más de un año tendremos que llevarlo a una residencia porque se le habrá acabado el dinero. Los gastos ahora mismo son muy superiores a sus ingresos y estamos tirando de sus ahorros, habrá que buscar la manera de justificar esto en la rendición anual que se hace al juzgado cuando llegue el momento. Se podía ir tanteándole el tema de ingresar en la misma residencia que su hermano ya que vemos que no evoluciona y sus necesidades son de atencion continua. Se le puede solicitar porque las plazas suelen tardar pero claro no lo puedo llevar en contra de su voluntad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2024-02-19','Ana: Se acepta presupuesto para compra de frigorífico (389 €) remitida por Mª Ángeles, Aux. de SAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES MARIA'and edp.apellido1='ALVAREZ'and apellido2='CARRASCO'),'2024-02-19','-Amalia : hablo con PFHC . No habían visto la solicitud de PF nueva que envié por registro en diciembre. Ya la han encontrado , proceden a anular la antigua con la hna. y tutora anterior desde enero , las nominas de febrero y marzo las van a retener y en abril las pasan todas a la nueva cuenta. Hablé con Lola del CSS y me indicó que era más seguro así ,porque tiene dinero en la cuenta para esos dos meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2024-02-19','Ana: Tras recibir llamada de Teodora, madre de José Blas, de 85 años de edad (927 248 986) con quejas y peticiones varias (que su hijo ingrese en centro y que se le aumente la asignación en concepto de manutención) recibo correo de Ángel, A. Jurídico, pues a él también le ha llamado. ······························· Envío correo a Ángel y Alberto CTAEx: "Precisamente, en mayo de 2023, rechazaron una plaza en centro que se concedió aquí en Mérida. He tratado de explicarle que SIN AUTORIZACIÓN JUDICIAL, no podemos obligar a su hijo a ingresar en centro. Con quién yo he estado en contacto en otras ocasiones ha sido con su otro hijo, no con ella. Y fue éste el que comunicó la RENUNCIA. También lo corroboraron en el Centro Ocupacional al que asiste José Blas a diario, de 9:00 a 16:30 h (come allí). En el inventario he mirado y no ponía quiénes eran titulares de la cuenta de José Blas, o al menos yo no lo he visto. Estos son los mismos que al principio decían que no querían asignación para manutención y meses después sí lo pidieron. Precisamente, ALBERTO: iba a escribirte para trasladar la solicitud de aumento de la asignación pues la madre dice que es muy poco lo que se le da. Pide 600€/mes. Ya le he adelantado que no creo que se le pueda conceder tanto. Ya nos dices cuánto se le puede subir." ···································· *La educadora actual de Futuex, es Nieves. *Recientemente ha acompañado a José Blas a solicitar presupuesto para ropa que nos tendrán que enviar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2024-02-19','Email , de Raquel , la TS del ctro . penitenciario de el Puerto : ingresó en Puerto I el 01/02/2024 ; se encuentra clasificado en primer grado , régimen cerrado , esto es, un régimen de vida más restrictivo en relación a actividades en común con sus compañeros, horas de patio…se debe generalmente a una mala evolución conductual-en los últimos tres meses ha acumulado varias sanciones- de ahí el traslado y la actual clasificación penitenciaria. -el número de cuenta donde ingresar el dinero sería la cuenta de Peculio- creo que te lo adjunté si no ahí está de nuevo; en cuanto a la cantidad creo que puede ser la misma ya que en esta prisión no va a generar más gastos. En cualquier caso él ha manifestado su deseo de trabajar y podría tener una pequeña remuneración económica, ya os lo comentaría porque aún es pronto y carece de ingresos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2024-02-19','Amalia . No se pudo gestionar el acompañamiento a citación forense que tenía el 6/02/24. Nos informa Angel , que volverán a darle otra cita , llegará la nueva .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2024-02-19','Amalia : tras ver los movientos de cuentas que me han pasado desde la S. eco y teniendo en cuenta la subida de la PFHC y hasta que IMV no regularice las cuentas , considero que se le podria subir a 550€ . Se lo paso a Alberto para que decida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2024-02-19','Amalia : envio a registro para INSS , IMIVI , CDO. ingresos de 2023 para que procedan a regularizar las pensiones .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-02-20','TERESA Lo de la ECA de Aitor, respecto a la cita que tenia programa para hoy, que se ha negado a venir. Teniendo en el dia de ayer, una actitud desafiante y chulesca con la compañera. Ayer, se intentó contactar con Aitor en varias ocasiones para preguntarle para quedar para la cita que tiene con la trabajadora social de la ECA de Cáceres el día 20 de febrero. Él no contesta, evade la pregunta durante días. La semana pasada según comentamos al hablar con voostros se muestra dispuesto a acudir, a su madre también le dice que quiere ir a la cita en Cáceres. No le dice nada a la educadora, quien sigue insistiendo en saber si vendrá o no para organizar el taxi y el acompañamiento, pero sigue sin obtener respuesta. Durante el día de ayer le dice que no quiere ir porque no quiere gastar 60 euros en un taxi, y más tarde le dice a su madre que no quiere acudir a la cita si va la educadora. Osea todo en una actitud, infantil y ridicula. Está mareando a todo el mundo, que está tratando de intervenir con el. Ojala no mantenga esta actitud de cara al ingreso en la CT...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='MARCOS'and apellido2='GARZA'),'2024-02-20','TERESA HABLO CON LA TS DE RESIDENCIA 924778214 ACORDAMOS HACER INGRESO EN LA CUENTA QUE ME INDICA POR IMPORTE DE 30€/MES PARA CUBRIR GASTOS DE PODOLOGIA, FARMACIA, PELUQUERICA ETC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2024-02-20','De: ALBERTO MARTIN ROSETE >alberto.martinr@salud-juntaex.es> Enviado: martes, 20 de febrero de 2024 11:00 Para: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es>; MARIA LOURDES CORTES MARQUEZ >marialourdes.cortes@salud-juntaex.es> Asunto: RE: SUBIDA DE REINTEGROS EDUARDO CABALLERO PAEZ AMALIA: INGRESOS ACTUALES ---- PENDIENTES DE SABER CUALES SON LOS REALES: PRXHCARGO: 470,60 €/MES X 12 ----- TU INDICAS QUE ESTE IMPORTE ES EL QUE SE VA A MANTENER. IMVITAL: 604,18 €/MES X 14 ---- INDICAS QUE ESTE ES EL IMPORTE QUE SE VA A REDUCIR OSTENSIBLEMENTE, PERO QUE AÚN NO SABEMOS EN QUE IMPORTE SE VA A QUEDAR. AMALIA: SEGURO QUE NO VAMOS A TENER QUE DEVOLVER DINERO X COBRO INDEBIDO DEL IMVITAL??? ES POSIBLE QUE SE GENERE UN COBRO INDEBIDO , DE AHÍ QUE LE FACILITASTÉIS LA TARJETA MONEDERO CON RECARGA MENSUAL PARA EVITAR QUE PUEDA RETIRAR LOS 4000€ QUE LE INGRESARON DE ATRASOS DE LA PFHC YA TUVIMOS QUE SOPORTAR EMBARGOS X COBROS INDEBIDOS RENTA BÁSICA. AMBAS PENSIONES SON COMPATIBLES , SE LA VAN A BAJAR EN CUANTÍA PERO ALGO LE VA A QUEDAR . ES POR ELLO QUE OS PLANTEABA QUE EN MI OPINIÓN SE LE PODRÍA SUBIR 100€ AL MES , PARA QUE PUEDA TENER LOS MISMOS INGRESOS QUE VENÍA PERCIBIENDO ANTES DE SOLICITAR LA PFHC . DE MOMENTO , CUANDO SE REGULARICE EL IMVITAL SE PUEDE VOLVER A VALORAR , PERO ÉSTO PUEDE TARDAR. EL REINTEGRO ACTUAL ES DE 450 €/MES. AMALIA: YA SE QUE ES IMPOSIBLE TRABAJAR CON ESTA PERSONA...TENGO ANOTADO EN FICHA ECO: 2022/09/16. MAITE/ÓSCAR: SE AUTORIZA REINTEGRO DE TOTALIDAD DE PENSIÓN HASTA REALIZAR PLAN DE INTERVENCIÓN-----SEGUIMOS MANTENIENDO ESTE CRITERIO??? NO , ESTE CRITERIO YA SE VALORÓ Y SE CAMBIÓ HACE UNOS MESES . CUANDO SE LE SOLICITÓ LA PFHC , (A PETICIÓN DE RENTA EXTREMEÑA GARANTIZADA QUE NOS INFORMARON QUE SE LA IBAN A DENEGAR AL ESTAR CURATELADO Y TENER ACCESO A OTRA PENSIÓN PÚBLICA. ) Y SE ESTABLECIÓ EL LÍMITE DE 450€ EN LA TARJETA RECARGA QUE LE PEDISTEIS A LA ENTIDAD BANCARIA . ACTUACIÓN ECO: AMALIA: SI EL CRITERIO ES EL MISMO...YO PREFERIRÍA SABER CUANTO VA A COBRAR DE IMVITAL Y DESCARTAR QUE NO VAMOS A TENER QUE HACER PAGOS X COBRO INDEBIDO Y LUEGO DARLE LA TOTALIDAD DE LA PENSIÓN, SI LO ESTIMAIS OPORTUNO: IMAGÍNATE QUE NO LE DAN EL IMVITAL...LE ESTARIAMOS REINTEGRANDO 90 €/MES X ENCIMA DE SUS INGRESOS. ME REMITO AL ANTERIOR PUNTO , SE HA RESERVADO ESE DINERO ANTE UN POSIBLE COBRO INDEBIDO Y CON LA SUBIDA DE ESO 100€ NO AFECTARÍA A LO QUE LE DEN DE IMV. COMO TÚ LO VALORES .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2024-02-19','Según detalle de la Ficha eco , se le podría asignar un reintegro mensual de 850€ al mes , dejamos de fraccionar por quincenas por su estado de salud , para iniciar para el 1 de Marzo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2024-02-20','Ana: Llamo a Ventura (682 483 126) en relación a los dos viajes que ha solicitado, "Turismo Termal" del IMSERSO (marzo), "Primavera Senior" de la ONCE (mayo). Él quiere ir a los dos. Acordamos que entonces no podrá realizar ningún otro viaje hasta el de Navidad de la ONCE. ···················· Dice también que quiere que se le suba a asignación semanal, los 150€/semana ya le parecen muy poco. Lo solicitaré a Alberto, jefe secc. ecca. ·············· Cuenta también que el próximo domingo va a Mérida a una convivencia de la ONCE. ······························································································································································································· Envío correo a Laura, TS - ONCE (LASS@once.es): "Te comento, para que estés al corriente. Con Ventura ya lo he hablado por teléfono y se muestra conforme. Se autorizan finalmente tanto EL VIAJE “PRIMAVERA SENIOR” como el del TURISMO TERMAL DEL IMSERSO que también ha solicitado. Por tanto el acuerdo es que como va a estos dos, no podrá solicitar más viajes hasta el de NAVIDAD de la ONCE, al que lleva yendo 2 años consecutivos. Así que no puede pedir otros. Recientemente también se concedió el otro de la ONCE de 2 días. Ahora mismo cumplimento la solicitud y la subo al portafirmas digital." ·········································································· La Educadora de Referencia de Futuex es NIEVES. ··········································································· *Subo al portafirmas digital al SOLICITUD DE PROGR. VACACIONES PRIMAVERA SENIOR-ONCE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2024-02-19','LOURDES: A PARTIR 01/03/2024 MODIFICAMOS REINTEGRO PERMANENTE QUE PASA A 850 €/MES (ABONO MENSUAL) -----ANTERIOR: 110 €/QUINCENA. AMALIA: XFA, DÉJALE A TUTELADA CLARO, QUE ESE ES SU PRESPUESTO MENSUAL...NO EXTRAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-02-20','Ana: Correo de David, Aux. Adtvo. CADEX (david.camberoramos@salud-juntaex.es): "La cita la tiene programada el día 8 de marzo a las 12:00. No obstante no es oficial hasta que reciba la llamada telefónica para citarle." ·················· Contesto: "Comunicar que Aitor ya no reside en el centro de menores de Trujillo, ¿hay algún documento u forma concreta para comunicar el cambio de domicilio? ¿O se podría comunicar cuando acuda a la revisión? Por otra parte, agradeceríamos que, tras llamada telefónica nos lo comuniquéis también a nosotras, como te indiqué en correo anterior para asegurarnos de que acuda y lo haga acompañado. Es un caso complejo." ···················· Respuesta de David: "Puede cambiar la dirección el día de la cita. No obstante al tener tutor las notificaciones se dirigirán a la dirección de este. El lunes de la semana que le toca la cita mándame un correo y te confirmo." ·································································································································· Envío a Juan Carlos (juancarlos.cano@salud-juntaex.es) para REGISTRO: "En relación con AITOR MORENO FELIPE, cuyo cargo ostenta la CTAEx, adjunto los siguientes documentos para remitir por REGISTRO a la Dirección Provincial del INSS en Cáceres: - Oficio aportando documentación INSS - Certificado de prórroga del grado de discapacidad del CADEX - Escrito remitido por Dirección Provincial del INSS - Cáceres"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-02-20','Amalia : José V. sale del Ctro. Penitenciario de Badajoz el próximo 22 de marzo , habría que enviar una autorización extra por los siguientes conceptos: -380€ de asignación mensual en cuenta peculio de Badajoz para el mes de marzo y dar de baja a la cuenta peculio de Cáceres . -300€ para pagar el taxi que lo trasladará del Ctro. penitenciario de Badajoz a Helechosa de los Montes . No puede ir en transporte público porque lleva máquina de oxígeno . Son muchos kms , y por lo menos ascenderá a 300€ esa factura. -300 € para comprarse un móvil y tarjeta . Solicita que se le autorice contrato de móvil , ya tiene visto uno con llamadas ilimitadas por 20€ al mes . Se compromete a no sobrepasarla . Necesitamos que tenga móvil para poder contactar con él . Mantiene contactos con sus hermanas . Tiene una PNC y 4000€ ahorrados , le han ingresado recientemente la reanudación del pago de la pensión que la ha tenido suspendida por más de 2455€. Su intención es la de irse a vivir con su padre al pueblo . El padre tiene un piso en el que podría vivir . Estrella , volverá a llamarte para que le indiques si ya está hecha esa autorización. El extra lo puedes dejar para enviar el 20 de marzo para que no disponga antes de ese dinero . No puede llamarme a mí porque ha dado tu Nº de tf en el Centro . Le he pedido que lo cambie pero ya cree que no va a dar tiempo. Cuando salga del Ctro. con su móvil me llamará a mi teléfono . De momento se cuadra plan de intervención de excarcelación con estas indicaciones. Cuando esté en el domicilio solicitaré visita por la Delegada tutelar . Se le subirá la asignación a 450€ al mes a partir del mes de abril . Todo ello pendiente de la autorización de Alberto . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2024-02-20','email de Alberto : LOURDES: SUBIMOS REINTEGRO PERMANENTE A 550 €/MES A PARTIR DE 01/03/2023 ---- ANTERIOR 450 €/MES---TIENE TARJETA PREPAGO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MARTIN'and apellido2='DIAZ'),'2024-02-20','Ana: Escribo a Estrella y Cristina, TS CSS: Mañana es la cita para la revisión de las medidas de apoyo de Dolores. Según la documentación del Juzgado, el informe lo solicitaron directamente al CSS. Entendemos que le acompañarán desde el CSS. ······························ Respuesta de Cristina Hdez, TS CSS (cristina.hernandezca@salud-juntaex.es): "Hemos solicitado videoconferencia. Estaré yo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-02-20','Ana: Llamo a Ángel Félix, mis compañeras han hablado con la tienda de telefonía, puede pasar a elegir un teléfono. Desde la propia tienda enviarán el presupuesto para que se abone mediante transferencia y después podrá recogerlo. ·················· Informo a Yessica de Arriba, TS Cáritas (ydearriba@caritasplasencia.org) al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='CRESPO'and apellido2='PEREZ'),'2024-02-21','Ana: En relación al correo de Ángel, A. Jurídico CTAEx, envío correo a Cristina Hdez. y Estrella Durán, TS del CSS: "En relación a ÁNGEL CRESPO PÉREZ, en noviembre de 2021, tras hablar con mi compañero Ángel, Asesor Jurídico CTAEX, en relación a la vivienda propiedad de Ángel, pues sus hermanos querían poder venderla o alquilarla, llamé a Emilia Almodóvar, TS del CSS. Me dijo que NO había previsión de que Ángel fuera a regresar a su domicilio, pues además de no contar con red social de apoyo, no reunía capacidades para vivir solo y comenzaba a presentar deterioro cognitivo. Que no obstante, solicitaría tanto a Cándido, su Médico, como a Agapito, su Psiquiatra de referencia, informes al respecto. Pero éstos nunca llegaron. ¿Podríais, por favor, confirmarnos que esta situación permanece así, e incluso, si fuera posible solicitar breve informe a los médicos referidos? Él es el USUFRUCTUARIO de la vivienda, además del propietario del 50% de la misma, y queremos asegurarnos de que no tendrá que regresar a la misma antes de iniciar cualquier trámite de venta. Quedamos a la espera, un saludo y buena mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='CRESPO'and apellido2='PEREZ'),'2024-02-21','Ana: Llamada de Tensi, TS SSASB (Cañaveral L y X: 674 36 48 97): Tras la intervención quirúrgica Isidro ha regresado del hospital completamente desorientado y más deteriorado. La situación en los pisos comienza a ser insostenible: se desorienta por el pueblo, se hace sus necesidades encima, la médica le ha recetado bragas pañal, otro día salió desnudo al rellano de los pisos... *Vamos a solicitar REVISIÓN PIA, para ampliación de centros a MIRABEL, y hablará con la médica para ver si podría justificare ese empeoramiento con informe médico como para que diera más grado y solicitar también revisión del grado. ··········· Presenta deterioro moderado-grave, pero no hay informe de neurólogo ni geriatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-02-21','TERESA Buenas tardes Teresa, disculpa. A esa hora estaba hablando justamente con el taxi que ya estaba contratado, ha sido un jaleo pero al final ha ido bien. Aprovecho para comentarte directamente que en ECA no ha sido posible que le vea la médica porque se va a jubilar y además la TS ha dicho que no es el procedimiento y no podría haber sido así de igual manera. A la consulta con ella él ha entrado solo, por lo que no tengo conocimiento de lo que han hablado. Me ha dicho que su informe se mandará a Mérida en el momento que vea a la psicóloga y también a la médica, y tengan los tres informes correspondientes. Aitor ha ido después a su médico de cabecera para que le pueda pautar una medicación para la abstinencia como solicita la CT, he estado hablando con el médico por teléfono por falta de disponibilidad para acudir presencial, me decía que al no tratar mucho estos casos no sabía exactamente qué podía pautarle, al final ha puesto Tranxilium 10 mg en cápsulas, 1 Unidad cada 12 horas. Te adjunto imagen que me ha pasado Aitor de la pauta pero no se ve muy nítida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-02-19','Maite: Alexandra (trabajadora social Plena Inclusión Cabeza del Buey) ha llamado para informar sobre Marta. Estaban en el despacho marta y su hermana con Alexandra. He hablado con Marta. Dice que mañana se va a Valencia a vivir con su novio ( anteriormente habia comunicado que se iria unos dias para visitar a la familia de su pareja). Intenté persuadirla pero se mostro firme con su decisión.Quedamos que en cuanto se instalara se pondría encontacto para darnos su dirección. Acordamos que desde el centro le darían el dinero que quedaba de su asignación ( unos 80 €) , hasta que una vez allí,se pudiera gestionar la retirada en alguna oficina de su entidad bancaria','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-02-21','Maite: ha llamado Alexandra. MArta no se ha ido a Valencia. Sigue en el pueblo. No sabemos si tiene intención de irse finalmente. En el pueblo la vieron la noche del lunes, cenando en un restaurante con su pareja y unos amigos ( posiblemete se haya gastado todo el dinero). Hablaremos con ella para saber qué va a hacer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-02-21','Ana: Envío correo a Alberto, Jefe Secc. Ecca: "JUAN JOSÉ GONZÁLEZ CARRERO solicita subida de asignación semanal. No sé cómo está su situación, pero se le da 67€/semana y dice que con la subida de precios de todo, incluido BUTANO (30€), no le da para cubrir todos los gastos. Solicita subida de al menos unos 15-20€/semana. Por otra parte, solicita también 30€/MES para adquirir el BONO MENSUAL DEL BUS en Cáceres, pues se desplaza a diario y varias veces al día, a la Asociación a la que asiste para hacer actividades. Dime cuando puedas si son viables sendas solicitudes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2024-02-21','Ana: Tras llamada de Carmen Martín, TO EVD-Plas. (24109) ·········· Llamo a la Residencia de Hernán Perez (927 44 51 67) y hablo con Salva, Psicólogo. Éste informa de que Pilar mantiene su deseo de permanecer viviendo en la residencia en la que está. Se encuentra muy bien, estable, adaptada, participativa en las actividades y con buen ánimo. ··· Mañana tiene su primera cita en Psiquiatría - ESM de Cáceres (anteriormente acudía al equipo de Coria). ···· Me enviarán informe de la consulta así como otro Psicológico emitido por él mismo. ································································································································································································ Envío correo a Carmen, TO, EVD (carmen.martinmon@salud-juntaex.es): "En relación a Pilar Díez Santiago, he hablado con el Psicólogo de la Residencia. Corrobora la información que te di mediante conversación telefónica, Pilar mantiene su deseo de permanecer en el centro en el que está, así que, tal y como hemos acordado: - Solicitamos la Prestación vinculada al servicio - Plaza pública en el mismo centro en el que está. Ante cualquier cuestión, seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2024-02-21','Ana: Tras llamar a Melania, TO, CRR-Olivenza (924 49 28 90), envío correo a Alberto, Maite y Amalia - CTAEx: "En relación con CEFERINO MARISCAL CRESPO, ante la falta de respuesta al correo remitido a Melania, T. Ocupacional del CRR, la he llamado. Nos responderán por escrito a la propuesta del extra anual planteada, pero ya me ha dicho que no pueden aceptarla, pues no tiene medios ni personal para custodiar y gestionar allí tanta cantidad de dinero. Piden mantener una reunión ONLINE con las secciones económica y social con respecto a los objetivos de trabajo que se han marcado y la organización/canalización de las peticiones económicas continuas de Ceferino. Sobre el modo de funcionar que quieren adoptar con él. Amalia, piden que estemos amabas, pues tú continuarás con este expediente cuanto ya está zanjada la cuestión económica. Maite, entiendo que tú también querrás estar, pero tú decides. Alberto, además de la reunión, lee el hilo del correo, subrayo en amarillo, son peticiones que consideran necesarias y ya lleva semanas esperando respuesta. No se le dio porque se iba a realizar la propuesta de extra anual. *Por mi parte ok a ambos “presupuestos”. Habría que autorizar retirada de efectivo y después nos enviarían las facturas. *TODOS: proponed fecha para reunión online." ······························································································································································································· Respuesta de Alberto: "ANA: ENTIENDO QUE TODOS TENEMOS CLARO QUE TIENE UN EXTRA ANUAL DE 3.500 €/AÑO....CTAEX, NO PUEDE OBLIGAR A NINGÚN CENTRO A CUSTODIAR DINERO...ENTIENDO QUE ENTONCES LO TENDRÁ QUE HACER LA CTAEX. CANALIZACIÓN (MI OPINIÓN): • ENTRE ÁREA SOCIAL Y ECO YA SE HA ESTABLECIDO UN LÍMITE DE 3.500 €/AÑO (HABÍAMOS HABLADO DE ESTE LÍMITE PARA EL CENTRO). AQUÍ ENTRE ABSOLUTAMENTE TODO (VACACIONES, ROPA, CALZADO...TODO LO QUE PROPONGA EL ÁREA SOCIAL)...PERO EN NINGÚN CASO SE SOBREPASARÁ EL LÍMITE ESTABLECIDO. HAY QUE TENER EN CUENTA QUE TUTELADO TIENE ADEMÁS SU REINTEGRO PERMANENTE: ACTUALMENTE 450 €/MES. • ÁREA SOCIAL CONTROLA ESOS 3.500 € Y LOS GASTA COMO CONSIDERE, SIN DAR NINGUNA EXPLICACIÓN AL ÁREA ECO. • DIRECTAMENTE ÁREA SOCIAL DA ORDEN DE PAGO Y ECO ABONA. • COMPROMISO: RESPETAR LA LIMITACIÓN...UNA VEZ ALCANZADO EL LÍMITE DE 3.500 €...YO NO SE REALIZARÁ NI SE PROPONDRÁ NINGÚN PAGO HASTA EL AÑO SIGUIENTE."','2');
