insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRIADO'and apellido2='RODRIGUEZ'),'2024-02-21','Ana: En relación al correo de Administraciones Parra (admon.parra@gmail.com): "Contactamos con ustedes para informarles que MAÑANA MARTES DÍA 23 DE ENERO A PARTIR DE LAS 12.00, se procederá al cambio del bombín de la puerta de entrada al edificio, como ya les avisamos la semana pasada . Les recordamos que les dejaremos dos copias de la nueva llave en sus buzones de correos." ····················· Llamo a Toni Futuex, cree que aún tienen las llaves de Mª Jesús, custodiadas desde la obra. Pasarán a recoger las nuevas del buzón y llevarán todas al TS de Almoharín o a los PPTT de la misma localidad en que reside. ···································· La dirección del piso en CC es Avda. de la Hispanidad, 10.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-02-21','Ana: Llamo a Esther, TS SSASB Cilleros (927 51 20 37)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-02-21','Ana: envío correo a Teresa, TS CTAEx con copia a Toni-FUTUEX: "Me acaban de llamar del CADEX de Cáceres, en relación a la próxima revisión de Aitor para renovar el Certificado de Discapacidad. Han intentado contactar con él sin éxito. Nos enviarán carta con la notificación de la citación. No obstante me confirman ya que la fecha de la cita es el día 08/03/24 a las 12:00h. Pongo en copia a Toni para que esté al corriente y puedan ir organizando el acompañamiento. En cuanto al traslado, mientras no sepamos si ingresa finalmente antes en centro o no, pues no se puede concertar taxi ni nada. *Toni, es importante que él sepa que si no lo renueva, perderá las pensiones que percibe. De hecho ya nos han enviado escrito del INSS relativo a la PFHC. Si no se renueva procederán a la extinción de la misma."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-02-21','Amalia : El informe médico recibido no lo he solicitado yo. Contacto con el psiquiatra Juan Angel Lopez Sevilla que lo firma . Está jubilado pero trabaja en la privada para MUFACE. tf . 927413579 . Me indica que ha visitado a este chico el 22/01/24 en Plasencia , que lo ha traído su hermana . Desde el Centro de Avila donde se encuentra no nos han notificado nada ni la hermana tampoco . Es la que ha solicitado el reconocimiento , desconocemos con qué intención , creo que puede ser para adjuntar a la declaracion anual de persisntencia de requisitos para las prestaciones de Muface que se envian todos los años . El modelo de declaración anual no ha llegado aún , no lo localizo en internet . Quedo a la espera de que llegue . Escaneo el cdo. medico en su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2024-02-21','Ayer por la tarde se le dio el alta a Sonia de UHB y ya se encuentra con nosotros. Iremos valorando estado y evolución y estaremos en contacto con psiquiatría por si requiere de una estancia más larga. A ver qué tal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='DIAZ'and apellido2='ROMERO'),'2024-02-21','Amalia : he registrado documento de cambio de PIA de nuestro curatelado ALBERTO DIAZ ROMERO , para registrar a la sección de dependencia de Montijo . Con este cambio he solicitado traslado a VT+CO en Badajoz capital cuando haya plaza por dependencia .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2024-02-22','Ana: Envío correo a Laura, TS - ONCE (LASS@once.es): "Te remito la solicitud para el programa PRIMAVERA SENIOR de Ventura Gómez García, firmado digitalmente por la Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2024-02-22','Ana: Envío a Gema, Directora Res - Cedillo (gemamg.asoma@gmail.com): "Buenos días Gema, Tal y como habíamos acordado, te envío adjunta la comunicación a Dependencia del fallecimiento de Victor Manuel Blanco Poveda junto con el Certificado Literal de Defunción, para que podáis aportar ambas cosas juntas.." ······························································································································································································ Envío correo a IBERDROLA (prejub@iberdrola.es): "Adjunto el CERTIFICADO LITERAL DE DEFUNCIÓN relativo a D. VICTOR MANUEL BLANCO POVEDA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2024-02-22','Ana: En relación a la respuesta de ayer de Alberto, envío correo a la Secc. Ecca: "os remito correo de Alberto para vuestro conocimiento y para solicitar, en base a ello, lo que subrayo en amarillo en el hilo. Hay que hacer autorización y confirmar al centro de cuando puede ir a retirarlo. Pongo en copia a Amalia para que esté al corriente. Amalia, independientemente de la reunión, que también estaré. Todo tuyo para seguimiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-02-22','Ana: Se autoriza a José Manuel 100 € para ropa. Hoy en teoría tenía que regresar al CSS-Plas.(fin del pase) pero le dijeron que puede regresar mañana viernes. *Mañana le acompañará Clara, Ed. Futuex Plas. a retirar el efectivo al banco comprar la ropa en Plasencia. ····· Después nos remitirán las facturas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GONZALEZ'and apellido2='GONZALEZ'),'2024-02-21','Ana: Correo de Toni-Futuex: "En el día de ayer se tenía cita con el centro sociosanitario de Plasencia para el ingreso de Carmen Gonzalez, de Coria, en la UNIDAD DE ALCOHOLISMO a las 10:30. Se estrucutró el desplazamiento en taxi desde Coria , en compañia del equipo, ya que no habia opciones de trasporte público y fue informada con pocos dias de antelación. Se adjunta la factura a este email. Todo transcurrió sin incidencias, alli, fue recepcionada por los profesionales de la unidad, que preguntaron sobre algunas cuestiones de la vida diara de Carmen y sus rutinas El médico y la enfermera se han reunido con Carmen a solas y se han quedado con ella para ya instalarse en su habitación. La duración del ingreso será de un mes y luego ha comentado la psicóloga de la unidad que sería muy bueno que acudiese a una comunidad terapéutica para que esto valga la pena. Pero al tratarse de un recurso voluntario no sabemos si ella estará dispuesta a otro ingreso posterior en CT. Durante el ingreso, se le visitara, siempre y cuando los profesionales lo consideren pertienente." ························ Envío factura a la secc. ecca. para que abonen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-02-22','EXTRAS ECO PREPARACIÓN SALIDA (22/03/2024) CENTRO PENITENCIARIO: ESTRELLA: ENTIENDO QUE MANTENEMOS LA TRANSFERENCIA PERMANENTE A CCC PECUNIO X 350 € HASTA 01/04/2024....DESPUÉS CANCELAR!!! 1 TRANSFERENCIA A CCC PECUNIO X 600 € (TAXI 300 + MOVIL 300: XFA, DEJA CONSTANCIA DE LO QUE INCLUYE ESTA TRANSFERENCIA EN EL ESCRITO CTAEX). EN CUANTO A MOMENTO EN EL QUE HACER ESTA TRANSFERENCIA EXTRA...ESTÁTE A LO QUE TE INDICA AMALIA/CENTRO PENITENCIARIO. SITUACIÓN ECO "PERMANENTE" A PARTIR SALIDA CENTRO PENITENCIARIO 01/04/2024: AMALIA: REINTEGRO PERMANENTE A PARTIR DE 01/04/2024 X 450 €/MES, EN IBECAJA HELECHOSA DE LOS MONTES (TFONO.: 924658026 + Avenida Virgen de Guadalupe, 6, Helechosa de los Montes - 06692) TELEFONIA: AMALIA (IMPORTANTE): YO NO AUTORIZARÍA CONTRATO...SI TU CONSIDERAS QUE SI Y LE HACES ENTENDER/COMPROMETERSE A ELLO, PROBAMOS...PERO TIENE QUE QUEDAR CLARO QUE, SI LLEGA FACTURA X IMPORTE SUPERIOR A LO PACTADO...SE DEVOLVERÁ EL RECIBO SIN AVISAR (ESTO TIENE QUE QUEDAR CLARO)...Y SI NO ES CAPAZ...LE SUBIMOS REINTEGRO A 470 €/MES Y QUE FUNCIONE CON PREPAGO....TEN EN CUENTA QUE UNA PERSONA VA A TENER QUE ESTAR PENDIENTE CADA "POCO" TIEMPO DE QUE LAS FACTURAS DE TELEFONÍA DE UNA PERSONA CON UNA PNC NO SUPERAN LO PACTADO. ESTRELLA: DEPENDIENDO DE LO QUE NOS INDIQUE AMALIA: REINTEGRO PERMANENTE X 450 €/MES A PARTIR DE 01/04/2024 ----- O ----- 470 €/MES, EN CASO DE QUE INCLUYAMOS RECARGA TARJETA PREPAGO (NOS LO INDICARÁ AMALIA) ESTRELLA (DECESO): SE QUE TIENE CASER (CON SU MADRE???): XFA, COMPRUEBA QUE ESE SEGURO SIGUE VIGENTE Y SE ESTÁ ABONANDO X FAMILIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2024-02-22','Buenos días , ya conocéis de sobra a Ana Rosco , no creo que acuda a esa cita . No se le va a poner acompañamiento porque no acepta ninguna intervención de la Comisión Tutelar . Lo último que ha rechazado ha sido acudir a la cita que tenía en el CADEX . Creo recordar que se envió escrito al juzgado comunicando la imposibilidad de ejercer el cargo . Aprovechando esta citación veo conveniente recalcar esta situación , si la persona no admite , ni colabora en las medidas es imposible ejercer la curatela . Es cierto que se maneja y vive sóla desde hace años sin necesidad de la Comisión . Administra su persona y su dinero , tiene capacidad para escribir a las distintas administraciones cuando necesita algo concreto y es asidua de los servicios sociales sólo a su demanda . A nivel eco , se le puso un límite económico pero amenaza a las empleadas del banco que acaban dándole lo que les pide . No podemos determinar ni qué medidas serían las necesarias porque ella se gobierna sola y no acepta ningún tipo de ayuda . No facilita que se la visite , ni atiende al tf cuando se le llame, ni facilita que la delegada tutelar pueda ir al domicilio . .. En estos casos , en los que la persona se niega a la curatela , y es inviable ejercer el cargo habría que buscar alguna solución judicial . Lo que sí se ha hecho es tramitarle todo tipo de pensiones públicas a las que podría tener derecho y percibe PNC , y en cuantía más reducida I.M. Vital y Renta Extremeña Garantizada .Las tiene aceptadas y se garantiza así sus ingresos económicos. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2024-02-22','Ana: Envío correo al Habilitado - Clases Pasivas (zancash@gmail.com): "En relación a las siguiente personas, cuyo cargo ostenta la Comisión Tutelar de Adultos (CTAEx), solicitamos nos remitan los certificados actualizados /revalorizaciones de las distintas prestaciones/pensiones que perciben: - D. Álvaro González Álvarez - Dª. Ana Priscila Saquero Sánchez"','2');
