insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='SERRANO'and apellido2='TRANCON'),'2024-02-22','Ana: Envío a Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com): "A petición de mis compañeros Asesores Jurídicos, te solicito Informe Social que contemplen los siguientes términos, para remitir al Juzgado para el procedimiento de revisión de la medidas de apoyo: “Lugar de residencia Discapacidad que presenta Ámbitos y extensión que resulten afectados por su discapacidad y necesidad de apoyo Cualquier consideración que estimen conveniente sobre ella en razón al procedimiento judicial de revisión de medidas de apoyo”."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2024-02-22','Ana: Llamada de Isabel (649 642 635): la semana que viene se irá al pueblo desde el lunes al viernes, está muy contenta pues va a poder estar y disfrutar con su sobrina. ···································································································································· Derivaré a Futuex para que hagan seguimiento y apoyo, sobre todo cada vez que acuda unos días a su pueblo. ··· No debe tener contacto con la pareja de su padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2024-02-22','Ana: Reenvío corre de Toni-Futuex del día 14 a Estrella Durán, TS CSS, con copia a Toni -Futuex y Maite, Jefa CTAEx: "Tenía pendiente trasladarte esta información que me facilitan desde el Programa de Apoyo Comunitario gestionado por Futuex. Yo en otras ocasiones he hablado con la madre, la última vez fue en diciembre, antes de irse de pase unos días a Leganés a casa de un hermano. Se le autorizó un extra para los gastos. Pero de esta cuestión, efectivamente no sabíamos nada. Aunque sí hace tiempo que me preguntó si se podía derivar desde el CSS a Leganés y ya le expliqué que en principio no era posible, pues las derivaciones que pueden hacerse aquí son, en principio, dentro de la red de recursos de a Extremadura. No volvió a decirme nada más. Te lo envío, más que nada, para que estéis al corriente, pues ya sé Estrella que estáis abordando alternativas al CSS con él y se muestra más que reticente. Desde la CTAEx, como ya sabéis, la opción de que vuelva a casa de su madre no la contemplamos, pues volvería a la misma rutina totalmente perjudicial para su salud y que mantuvo durante años con las consecuencias y desencadenantes que todas conocemos. Por favor, si hay alguna novedad al respecto, como siempre, mantenernos informadas y por favor, cuando habléis con la madre, intentad abordar este asunto también. Yo por mi parte intentaré llamarle hoy o mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2024-02-14','Ana: Correo de Toni-Futuex: "Tal y como comentamos, parece ser que la madre de Alfonso Marín de Cáceres está buscando cambiarlo de centro pero a otra provincia y en Leganés, concretamente. Ya que no quiere que su hijo regrese al domicilio en Torrecilla de los Angeles, cuando reciba alta del sociosanitario. Se le comenta que no puede hacer nada sin la autorizacion de la comision, ya que no se puede llevarlo a ningún otro centro así sin aviso ni nada por el estilo, por ejemplo a un recurso privado y hoy nos corrobora y claro que la comisión no sabe nada que ha intentado llamar .. Se le ha explicado la situación por la que debe de ponerse en contacto antes de hacer nada de ningún tipo de trámite, de todos modos dejamos el numero de contacto, por si considera hablar con ella. TELÉFONO ISABEL: 680784490 Y por si se tienen contactos con el sociosanitario por si pudiera derivarse a algun otro recurso desde alli, o valorar no darle el alta, ya que el , comenta que centros no quiere.. que quiere irse a vivir solo a Madrid o si no a su casa (de su madre) , tiene una falsa autopercepción de independencia. No creemos que tenga ninguna habilidad o solvencia para vivir solo, de hecho en las visitas que se hacian en el domilio, apenas salia de cuarto, donde estaba conusmiendo cannabis y jugando, sistematicamente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2024-02-22','miguel, firmo la ratificación de la herencia y envío email a Miguel Mariscal de la gestoría: Buenos días Miguel, te confirmo que he dejado firmada esta mañana la ratificación de la herencia familiar de Sonia con el notario de Mérida Don Borja Igartua Fesser con protocolo 211. Dicha escritura la van a remitir telemáticamente desde la notaria de Mérida a la de Cáceres de Don Alberto Sáenz de Santa Maria Vierna.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2024-02-22','miguel, firmo la ratificación de las 3 escrituras de compraventa pendientes y envío email a Maria Cadenas, José Santiago y notaria de los Santos de Maimona: Buenos días esta mañana he dejado ratificada las tres escrituras de compraventa pendientes en la notaria de Mérida de Don Borja Igartua Fesser. Dicha escritura la remitirá en breve la notaria de Mérida a la de los Santos de Maimona. Queda por tanto únicamente pendiente de que se modifique el Auto judicial defectuoso a efectos de que se pueda vender el resto de bienes que queden ********************************************************** Envío email a José Santiago: Buenos días, habéis presentado finalmente de nuevo al juzgado la solicitud de modificación del Auto que comentamos? ******************************************************** Contestación de José Santiago: Si, está presentado y pendiente de proveer. Ya me hace 10 días y me dijeron que estaba, pero que no habían llegado aún a los escritos presentados en diciembre. Dentro de unos días volveré a llamar. ********************************************************** mi contestación a José Santiago: Gracias, me puedes enviar una copia del documento presentado cuando puedas para guardarlo en el expediente?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2024-02-22','miguel, email de Maria Jesús: Hola Miguel, Hemos acabado la Fase I de demolición, te adjunto el acta donde verás como ha quedado rematado todo. Por otro lado te adjunto la factura pendiente que hay que pagar al albañil, para que le hagan la transferencia. Cuando esté hecha mándame el justificante. También quería comentarte que mi intención es poder ir sacando escombro poco a poco según vayamos teniendo algo de dinero. ¿Sería viable disponer de 1.500€ para sacar dos bañeras de escombro ( unos 18m3 cada una) y gestionar ese residuo? **************************************************** email a Alberto y Ana: Buenos días, por favor abonad esta factura para continuar la obra de Martin Quiros Berrocal. Enviadme justificante cuando hagáis la transferencia para enviárselo a la arquitecta. Ah! Me pregunta: “¿Sería viable disponer de 1.500€ para sacar dos bañeras de escombro ( unos 18m3 cada una) y gestionar ese residuo?” Sería viable? ******************************************************** Contestación de Alberto: MIGUEL: XFA, PONED EL NOMBRE DEL TUTELADO EN EL ASUNTO. MIGUEL: CUANDO TRATAMOS EL TEMA DE ABONAR TODO ESTE DINERAL, INDICAMOS QUE EL PRESUPUESTO TENÍA QUE AJUSTARSE A LO QUE INICIALMENTE SE ESTABLECIÓ YA QUE ESTA PERSONA VIVE DE UNA PENSIÓN (761,21 €/MES)...EL SALDO HOY ES DE 4.000 € APROX. (YA NOS HEMOS GASTADO 4.000 € DESDE OCTUBRE 2023)...PERO TE RECUERDO QUE SI FALLECE NO TIENE SEGURO DECESO (- 2.000/3.000 €). LO QUE NO PODEMOS HACER ES COMPROMETER MILES DE EUROS PARA QUE VAYAN APARECIENDO CUESTIONES NUEVAS X 1.500 €....VA A HABER NUEVOS IMPREVISTOS??? TODAS ESTAS CUESTIONES YA TENÍAN QUE ESTAR PRESUPUESTADAS INICIALMENTE...SI NO ES IMPOSIBLE FUNCIONAR CON UNA PERSONA CON UNOS INGRESOS TAN AJUSTADOS. ANA/MIGUEL: LO QUE DECIDÁIS...SI CONSIDERAIS QUE HAY QUE ABONAR LOS 1.500 € X LAS BAÑERAS, PARA NO SE QUE CUESTIÓN, ME LO INDICÁIS Y ABONAMOS ********************************************************* Me reuno con Ana y Maite y contesto a Alberto con copia a Ana: Buenos días Alberto, tras reunirnos la parte social y jurídica entendemos que ese dinero que solicita la arquitecta (y vecina colindante afectada) (que os recuerdo no cobra por sus gestiones, siendo los pagos que se están haciendo tasas que cobra por el proyecto el Colegio de Arquitectos, el Ayuntamiento, y el albañil) Para ahorrar en todas las gestiones que está haciendo, incluso ha prescindido de contratar maquinaria para la obra porque no llegaba. Esta obra la ha dividido ella en dos fases: la primera que está haciendo, apuntalar y tirar muros para que no se caigan encima de su casa, pues filtraciones y caída de parte de muro ya se estaban produciendo y que pueden suponer aguantar esta situación unos años pues Martin Quiros Berrocal tiene cerca de 80 años, y sólo tiene una sobrina que no sabemos si aceptará la herencia o no el día de mañana. La segunda fase sería arreglar en condiciones aquello. Digamos que lo que se está haciendo es lo más esencial. Y el extra que está pidiendo la arquitecta es para la retirada de escombros contaminantes que el ayuntamiento si se entera y no lo retiramos nos multaría, y sería vuelta a empezar. Por tanto debemos abonar la factura y esa cantidad extra. La opción venta no se contempla pues los bienes están en el pueblo y no se vende nada por allí (ya me informé por distintas fuentes, ayto, la vecina, etc. En el pueblo no hay de nada, ni inmobiliaria, empresa de reformas, etc. La opción ejecución subsidiaria con el Ayuntamiento donde les pedí incluso que embargaran los bienes de Martin tampoco la aceptó el Ayto obligando al arreglo cuyo presupuesto inicial por el técnico de la Mancomunidad era de más de 40.000€ Cualquier duda lo hablamos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2024-02-22','TERESA En relación a ARTURO ROCHA MERCHÁN, hace ya bastantes meses que se trasladó e ingresó en la Residencia Municipal de Los Santos de Maimona (mayo de 2023). No recuerdo si llegué a hacerte la derivación. El señor está adaptado y está bien. Contacto: - Isabel, Directora de la Res. Municipal Antonio Zapata - Los Santos de Maimona (924 029 563 / rmayores@lossantosdemaimona.org ) - Esperanza, Enfermera de la Res. Antonio Zapata - Santos de Maimona (atsrmayores@lossantosdemimona.org) Seguimos! Buena mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2024-02-22','TERESA Se ha visistado a Josefa en el hospital, está muy floja, le cuesta incluso hablar. Le tienen puesta mucha medicación para que no le duela y esté tranquila, porque a veces intenta arrancarse la vía. Se le ha acompañado un rato y se ha charlado un poquito con ella, hoy parecía más ubicada que ayer, ya sabe que está en el Hospital de Zafra y ha contado que se ha caído en la residencia (ayer lo negaba...). Se ha hablado con la TS del hospital porque el traumatólogo ha dicho a una de las enfermeras que le faltaban los consentimientos y que no podían operarla. (Tremendo esto) Se le ha explicado a la TS la situación y que ayer se les entregó, aunque estén escaneados tienen el mismo valor, ella misma no entendía porque no le valían así... Tras hablar conjuntamente con el traumatólogo y explicarle la situación ha aceptado y la operaran hoy primera hora (está aun en la intervención) Por otra parte, ya se han recibido las etiquetas para marcar la ropa de Josefa. Adjuntamos el documento donde viene el importe, número de cuenta y código que se debe poner en el concepto de la transferencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2024-01-05','miguel, recibo email de Amelia (tia)dirigido a David de la Caixa DAVID HENCHE SOLANO >dhenche@caixabank.com>: Buenas tardes, David y feliz año. Me podrías confirmar, o que lo haga Sergio, que el saldo de las cuentas de mis tíos y primos se ha transferido ya a las cuentas indicadas por la Comisión de Tutelados de la Junta de Extremadura? Tengo que ponerme en contacto con ellos, gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2024-02-12','miguel, escribo a Amelia; mtmuelas@icaguadalajara.org; melitonarodrigo@hotmail.es Buenos días Amelia, tras revisar mis compañeros de la parte económica los ingresos desde la cuenta de reparto a la vista nº ES83 2100 8771 1821 0012 3169 donde eran titulares los padres Máximo y Teresa, a los hermanos Gil Sanz, y donde comprobamos lo siguiente: “Raul el pasado 6 de diciembre tiene un ingreso de 23.826,48 €. Pero en la cuenta de Sergio no hay ningún ingreso. Y NO tenemos acceso a ninguna de las dos cuentas “ Leed por favor los emails que envía la Caixa debajo donde indica, entiendo que no han repartido la parte del padre Máximo porque falfa porque presentes la liquidación del impuesto de sucesiones del padre (tal como hiciste con el de la madre) A parte de faltar por presentar dicho impuesto de Maximo (padre), se ha producido un error que también debes indicar a la Caixa cuando presentes dicha liquidación del impuesto, y es que han ingresado a Raúl no sé si el total de lo que tenían que haber ingresado a los dos hermanos, ya que Sergio no ha recibido nada. Habla con la Caixa para que solucionen el reparto entre los hermanos y si tienen que retrotraer las cantidades y volver a repartir lo hagan. Diles también que impiden el acceso a la Comisión Tutelar de Adultos a las cuentas, que por favor quiten el bloqueo al acceso a las mismas. La persona de contacto de la Caixa es MARIA EUGENIA PARDO BANDA mepardo@caixabank.com Maria Eugenia Pardo Banda 16233 Soporte Operativo Banca Institucional Sur sobi.sur@instituciones.caixabank.com Móvil: +34 628 200 445','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2024-01-16','miguel, recibo email de la Caixa MARIA EUGENIA PARDO BANDA >mepardo@caixabank.com> Enviado el: martes, 16 de enero de 2024 10:07 Para: AMELIA RODRIGO SANZ >melitonarodrigo@hotmail.es>; DAVID HENCHE SOLANO >dhenche@caixabank.com>; SERGIO MELERO RECIO >smelero@caixabank.com>; 08771 CIFUENTES. PLAZA MAYOR >8771@caixabank.com>; 08779 BRIHUEGA. AVDA CONSTITUCION >8779@caixabank.com> CC: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Buenos días, Reiteramos que el trámite de expediente de defunción no nos corresponde, le corresponde a la oficina gestora del cliente en cuestión. Rogamos que en sucesivas comunicaciones eliminen de los destinatarios el email sobi.sur@instituciones.caixabank.com y mepardo@caixabank.com, direcciones que corresponden al departamento de Soporte Banca Institucional Sur que nada tienen que ver con éste asunto,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2024-02-22','miguel, envio email a Teresa Muelas y Amelia mtmuelas@icaguadalajara.org; melitonarodrigo@hotmail.es Buenos días Amelia, me confirman desde la parte económica de la Comisión que el desembolso de la herencia está completado y correcto desde hace algo más de un mes. Por tanto no te preocupes en cuanto al desembolso del dinero. Lógicamente la cantidad inicial que aparecía en la cuenta quedó disminuida porque en la misma se realizaban cargo de gastos entiendo relacionados con la casa. Ahora la parte económica tiene otros trámites pendientes con la Caixa como es el acceso online, que ya están tramitando. Por tanto sólo queda pendiente la venta de la casa de los padres. En su día lo ibas a poner en venta. Necesitamos lo vayas moviendo. Quedo a tu disposición para lo que vayas necesitando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2024-02-21','miguel, Amelia me reenvía email enviado a la Caixa SERGIO MELERO RECIO >smelero@caixabank.com>; DAVID HENCHE SOLANO >dhenche@caixabank.com> Buenos días, David Han trascurrido varios años desde que comuniqué a la oficina de Cifuentes, donde mis tíos Maximo Gil y Teresa Sanz tenían sus cuentas, el fallecimiento de los mismos, presentando toda la documentación que se necesitaba en su momento, mucha de ella o la totalidad, la remití vía email, desde enero del 2020 que falleció mi tía a fecha de hoy tengo conocimiento que se ha recibido un importe en la cuenta designada por la Comisión de Tutelados de la Junta de Extremadura de uno de mis primos pero no del otro, no puedo contactar telefónicamente con la oficina, tampoco contigo y aunque te he dejado varios mensajes, tampoco me devuelves las llamadas, según tu correo del pasado de enero indicas que lo lleva otra persona y se quedará solucionado esa misma semana, te he preguntado al respecto y nadie me ha respondido ni llamado para informarme, TAMPOCO a los contactos que os he enviado de la Comisión de Tutelados de Extremadura, no sé si hay algún problema con algo porque no tengo constancia de ello y tampoco debiera haberlo porque se ha mandado TODO LO NECESARIO para que se haga la testamentaria de mis tíos fallecidos y mis primos, titulares y beneficiarios de los saldos que sus padres tenían en Caixabank reciban la totalidad de los saldos que mantenían sus padres repartidos al 50% en las cuentas que han designado sus tutores legales actualmente… Por favor, necesitamos que esta gestión tan cotidiana en una entidad bancaria, finalice satisfactoriamente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2024-02-22','TERESA Y al respecto de la situación económica, ayer se le ha estado visitando, el no quiere irse a una residencia y Petrona tampoco estaba en un primer momento de acuerdo en que se redujeran horas del servicio. Pero es que es cierto que está mejorando poco a poco, y es una persona joven. Ademas el médico también es partidario de que amenos lo que pueda hacer el lo haga, para recuperar amenos parte de su autonomía. Por lo tanto, lo que hemos considerado, que alomejor.. podria considerarse reducir las horas de la asistencia personal, si continua en esta progresión?? como lo ves?? Lo fundamentamos, en lo que venimos observando, ayer se acudió con Diego a su cita con la psiquiatra, acudió con Petrona, su cuidadora interna. Se pasará la factura del taxi cuando este la facilite. Se les ha comentado a ambos la información sobre el tema económico, en principio la cuidadora negaba que Diego pudiera estar solo y él se niega a ir a una residencia, no quiere moverse de su casa. En la consulta, la doctora le ha preguntado a Petrona sobre la rutina de Diego, ella contaba que le ayuda a levantarse y a vestirse, le ponía el desayuno y salían a pasear. Al preguntarle si él puede hacerlo solo dice que sí, que si lo deja se viste solo y se levanta. La doctora le pide que, si es así, por favor no le ayude, debe dejarlo que vuelva a ser autónomo como lo era antes y si se le ayuda demasiado va a acomodarse y no conseguirá dicha autonomía. Cuenta también que pasa mucho tiempo del día durmiendo, le ha bajado la medicación a ver si así se espabila un poco más y no está tan adormilado, por si fuese por eso. La noche la pasa entera dormido, desde que volvió a casa tras el ingreso (que ha mejorado mucho) no llama a Petrona por la noche para nada. Tampoco necesita pañal durante el día, solo lo usa por la noche, la doctora le ha pedido que, siempre que pueda, intente levantarse también por la noche aunque lo use por prevenir. En resumen, le aconseja que se mueva, que ande, que se relacione..., es muy joven y tiene que volver a ser autónomo, está segura de que poco a poco puede. Al salir de la consulta, tras ver que en realidad Diego si que podría pasar tiempo solo, se ha vuelto a hablar con Petrona sobre la posibilidad de reducir las horas y que no sea necesario su cuidado 24 horas. Se le ha propuesto que, quizás, podría ir para prepararle la comida y la cena, y ciertas horas al día solamente. Por la mañana también tiene una auxiliar de ayuda a domicilio, esas horas también esta acompañado y podría ser ella quien se encargue del desayuno. Va a valorarlo (porque obviamente le conviene estar interna y es lo que quiere...) y, en caso de que lo considere, comenta que hablaría directamente sobre el tema económico con vosotros. En todo caso, tambien se puede valorar, si esta persona no estuviera interesada, otros profesionales. Ya comentas lo que consideres, pero es cierto que según su situación eco, tal y como dijiste, no podra aguantar mucho tiempo 24 horas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2024-02-22','TERESA Buenos días Teresa,. Tenemos en el Asilo a JULIO GALAN GILGADO, 08771942H, con incapacitación Nº 560/2020. Se ha producido un altercado violento con otro usuario y la situación no es sostenible. Hemos querido mantener la normalidad durante años, pero se nos ha desbordado. Es urgente encontrar un centro residencial donde se `pueda acoger a Julio , con carácter de urgencia. Mí telf.. es 646512626. He intentado contactar contigo, pero no ha sido posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2024-02-22','Ana: Reenvío a Alberto correo de Juan Manuel Cañas Lozano, hermano de José Blas (jmcl1966@hotmail.com) el 21/01, comunicando que la gran mayoría del dinero que había en la cuenta de José Blas cuando se aceptó el cargo era de sus padres y SOLICITANDO que se le transfiera ese dinero (descontando lo que haya cobrado José Blas de pensión desde que comenzó a percibir la Pensión de Orfandad a fecha, según refiere, de Septiembre de 21 tras fallecer su padre. ······························································································································································································· Envío correo a Toni-Futuex: "En relación a José Blas Cañas Lozano, antes de ayer recibí llamada de la madre informando de la insostenibilidad de la convivencia, las relaciones conflictivas y el miedo a que su hijo pueda llegar a agredirla. Como sabéis José Blas renunció a la plaza residencial que se le concedió en Plena Inclusión Mérida en mayo de 2023. Su hermano era conocedor y estaba de acuerdo con esta decisión pues decía que José Blas tenía su vida hecha en Cáceres y no lo veía viviendo fuera de dicha localidad. Justo en aquel momento la relación estaba más apaciguada. Ahora, meses después, su hermano también ha escrito un correo, solicitando, entre otras cosas, que su hermano ingrese en un recurso. Los trámites de solicitud ya se hicieron hace meses, de hecho la ACEPTACIÓN PIA se firmó y registró en el mes de noviembre de 2023. No obstante, NO TENEMOS AUTORIZACION DE INTERNAMIENTO INVOLUNTARIO, a pesar de que el Medico forense, según se expone en la sentencia, consideraba necesario que José Blas residiera en centro residencial. Por lo que os SOLICITAMOS remitáis un INFORME firmado lo más detallado posible de la situación actual y del riesgo que supone la convivencia, para que desde aquí solicitemos AUTORIZACIÓN JUDICIAL DE INGRESO INVOLUNTARIO. Pues si vuelven a concederle plaza y él no quiere seguiremos en las mismas." ··························································································································································································· Envío correo desde el ctutelar@ a Juan Manuel, hermano de José Blas (jmcl1966@hotmail.com): "Ya he pasado al Jefe de la Sección Económica la cuestión que planteas relativa a la cuenta y al dinero que había en ella. Entiendo que te darán respuesta en cuanto les sea posible. En cuanto a la demanda de ingreso en centro que planteas, recordar y aclarar varias cuestiones: 1. En mayo de 2023, José Blas renunció a la plaza que se le había concedido en Plena Inclusión Mérida, cuestión con la que además estabas de acuerdo porque considerabas que él tenía su vida hecha en Cáceres y no lo veías viviendo fuera de dicha localidad. 2. En agosto de 2023 volví a solicitar REVISIÓN PIA para ingreso en centro residencial 3. En noviembre nos remitieron desde dependencia la ACEPTACIÓN PIA para ingreso en centro, se firmó por parte de la Representante Legal y le dimos registro. Por tanto ahora se encuentra en lista de espera para acceder a otra plaza residencial. 4. NO TENEMOS AUTORIZACIÓN JUDICIAL DE INGRESO INVOLUNTARIO, por tanto si llegado el momento tu hermano volviera a negarse, no se le podría obligar a ingresar. 5. Antes de ayer hablé con tu madre y dada situación que expone, vamos a recabar informe para solicitar, en cuanto nos sea posible, dicha autorización de ingreso involuntario al Juzgado.Ante cualquier otra cuestión, no dudes en volver a contactar. Un saludo. PD: Se ha autorizado una subida de asignación para los gastos a 450 €. También se va a aprobar el presupuesto que acabamos de recibir de ropa del Sprinter. Cuando haya otras cuestiones como ropa, viajes o similar, o bien a través tuya o de la Educadora de Futuex, no dudéis en hacérnoslo llegar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2024-02-22','miguel, me llama por teléfono Marisol y la informo, y quedamos que para que ella pueda justificar los trámites que se están realizando, le remita justificante de presentación al jzdo Decano de Badajoz. Recibo email de Marisol (hna del curatelado 618756139: Buenos días Miguel, Agradecería nos informara sobre la situación de las gestiones llevadas a cabo para la compra de la vivienda de Jose Antonio Garcia Ramirez. Un saludo Marisol García Ramirez, Teléfono: 618 75 61 39. ****************************************************** Mi contestación a Marisol con copia a Amalia y paco marisolgarram@gmail.com; Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es>; paco garcia ramirez >pakogara@hotmail.com>: Buenas tardes Marisol, adjunto justificante de presentación, vía electrónica, es decir por la plataforma oficial, Lexnet, en el juzgado Decano de Badajoz la solicitud para la compra-hipoteca del piso. Estamos a la espera que asignen a un juzgado y éste de procedimiento e iniciará los trámites correspondientes. El tiempo estimado no lo sabemos porque depende del juzgado. Lo más que podemos hacer es una vez que asignen juzgado y número de procedimiento es decíroslo para que insistamos al juzgado que lo tramiten lo antes posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-02-22','Ingresado desde marzo de 2015 en la Residencia de Mayores , Jardín del Tíetar , Dirección: Carr. Ávila, 1, 05400 Parra ( La ), Ávila Teléfono: 920 37 11 73','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-02-22','direccion@jardindeltietar.com TF 670726479','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-02-22','-Amalia : hablo con la encargada de la residencia llamando al tf fijo , es Soraya . Desconoce el I. médico . Lo mismo indica la enfermera Estefanía y Marisa la Dtra. Me informa que Jesús ha estado ingresado hace unos meses en el hospital provincial de Avila de la SS , derivado desde el médico de AP de Arenas de San Pedro . Activaron el 112 y se personó la ambulancia y la G. civil . Ha estado allí ingresado un mes , no han comunicado nada . Les indico que Jesús pertenece a Muface y su clínica está en Madrid que es donde se tendria que haber derivado. No ha llegado nada para abonar ese mes de la SS. Me cuentan que Jesus sale los jueves , viaje de ida y vuelta a Arganda del Rey en Madrid que es donde vive su hna Ana Victoria ,la otra hermana falleció. Igualmente no habían comunicado nada y no tiene la autorización de salidas. el email de la enfermera que es la persona que más lo atiende enfermeriajardindeltietar@outlook.com Me faciitan el tf de su hermana Ana 606424930 La Dtra. aprovecha para indicar que van a subir la cuota conforme al IPC y lo que establece el contrato , que el año pasado no lo subieron. Va a enviar la factura .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-02-22','Maite: ha llegado por segunda vez un infrome en modelo oficial cumlimentado a mano de un psquitara de MUFACE de Plasencia. Amalia hbaló con este para saber cual era el motivo de la realizaci´`on del informe, ya que desde la CTAEX no se ha solicitado. La hermana de Jesús es la que lo ha pedido y lo trajo a PLAsencia para que lo viera este facultativo. Desde el centro no nos comunicaron nada. La dirección desde la que se envía el informe,cuyo remitente es Jesús Bermejo Tello es: VAd Ruta de la PLata 4 3ºC de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-02-23','Ana: Respuesta de Alberto, Jefe S. Ecca. a la solicitud de Juan José de subida de asignación: "• SALDO HOY: 4.848 € - HA EVOLUCIONADO NEGATIVAMENTE X UNAS PLUSVALÍAS QUE HA TENIDO QUE ABONAR A OAR DE CÁCERES (ENTIENDO QUE YA NO TENDRÁ MÁS DEUDAS) • IMPORTE CÁTERING: NO ES EL QUE INICIALMENTE (HACE TIEMPO) TENIAMOS: EJEMPLO: DICIEMBRE 2023: 406 € + ENERO 2024: 441 €...SALVO QUE EMPRESA DIGA OTRA COSA TENGO QUE PRESUPUESTAR EL CÁTERING EN "PONGAMOS": 440 €/MES (Y ESPEREMOS QUE NO SEA SUPERIOR). • OTROS GASTOS: 80 €/MES A MADRE X CONSUMOS (RESIDE EN VIVIENDA MADRE). • REINTEGRO: EL REINTEGRO REAL (INCLUIDOS EXTRAS) ES DE 342 €/MES Y NO LOS 290 €/MES QUE DEBERÍAN DE SER (X TANTO...BASTANTES REINTEGROS EXTRAS). PROPUESTA SUBIDA REINTEGRO PERMANENTE ANA: X EJEMPLO (+17 €/SEM) - 85 €/SEMANA (369 €/MES) + REINTEGRO TRANSPORTE URBANO (30 €/MES): TOTAL REINTEGRO: 400 €/MES APROX. ECO: CON ESOS 400 €/MES Y RESTO DE GASTOS (Y PENDIENTE CALCULAR COSTE VIVIENDA X HERENCIA (IBI, OTROS))---SÓLO AHORRARÍA 250 €/AÑO: EN MI OPINIÓN DEMASIADO ARRIESGADO...LO HABLAMOS CUANDO QUIERAS LOURDES: • XFA, HABLA CON OAR CC Y COMPRUEBA QUE NO TENEMOS NINGUNA DEUDA PENDIENTE DE ESTE TUTELADO Y QUE NO TENEMOS PENDIENTE DOMICILIAR NADA. MOTIVO: HEREDÓ UNA VIVIENDA DE SU PADRE (ABAJO INCLUYO PAGO PLUSVALIA QUE INDICA CUAL ES LA VIVIENDA) Y CREO QUE TENDREMOS QUE ABONAR IBI Y OTROS IMPUESTOS" ················································································· Reenvío correo a Toni, Futuex, dada la propuesta de subida de asignación que plantean también desde el programa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2024-02-23','Ana: Vuelvo a enviar a Alberto, Jefe S. Ecca., el correo con el presupuesto de obra que le envié en octubre. Anabel TS ha llamado a Lourdes, S. Ecca., preguntando al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2024-02-23','Ana: En relación a la llamada de Mª José, actual responsable Res. Hervás (927 473 410 / residencia_mayores@hervas.es ), le envío: "Buenos días, de nuevo, Mª José, Tal y como hemos acordado, adjunto la póliza del seguro de decesos de Mª Eugenia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2024-02-23','Ana: Envío correo con cédula de citación y providencia, para entrevista personal para la revisión de las medidas de apoyo para el día 20 de marzo de 2024, a las 13:00 horas, a Pilar, Directora - Residencia FEMAR (residenciafemar2019@gmail.com).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='SANCHEZ'and apellido2='MORENO'),'2024-02-23','FUTUEX : ( LES PIDO PRESUPUESTOS PARA VALORAR LA REFORMA POSIBLE ) En relación al último seguimiento, cuando se acudió al domicilio de Remedios, la encontramos con la compañía de su hermana Petri y su marido Inocente, siendo ahora las personas de referencia de Remedios y también su hermano Manuel. Exponen, desde inicio, la necesidad de varias reformas dentro de la vivienda de Remedios, vivienda habitual, aunque pase algún día en casa de su hermano Manuel. Remedios puede seguir residiendo en su domicilio, es algo que demanda y expone constantemente. Tiene el apoyo de su familia y de su entorno de vecinos, aunque destacamos que, menos hacer de comer y manejo de gas butano, en el momento actual es autónoma para las actividades básicas de la vida diaria. Sería necesario reforma su cuarto de baño, que es pequeño, pero se encuentra en mal estado, así como muebles de cocina y toda la fontanería. Muy conveniente también, un cambio de calentador de gas butano a eléctrico, para evitar el uso diario y evitar el irregular manejo que tiene Remedios. Se adjuntan algunas fotos del estado actual de la vivienda para tener una idea de las necesidades que exponen. Se le explica a la familia allí presente que, cuando se valore por la ctaex y si se llegara a autorizar, hay que solicitar presupuesto y además factura de dicha obra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2024-02-23','Ana: Envío correo a Laura, TS - ONCE (LASS@once.es): "...Adjunto ambos documentos firmados y sellado por la Representante Legal: - Consentimiento para tratamiento de datos - Cesión Derechos de imagen Éste último debe firmarlo también Ventura de acuerdo a la legislación vigente dado que él entiende los términos del mismo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2024-02-23','TERESA Buenas tardes, en relación a Angela Rodriguez Figueredo actualizamos la información, tras la ultimo que nos has comunicado. Se realizó visita presencial al domicilio de Ángela, donde nos recibió con muy buena interacción y acogida. Nos comunica que ha solicitado con la trabajadora social (María) plaza de ingreso en centro residencial de Jerez de los Caballeros. Ella expone que ya se encuentra con menos autonomía que, aunque tiene contratada a su vecina Quini toda la semana (está dos horas diarias) entiende que lo mejor para Ella es un centro donde estará más cuidada sin necesidad de preocuparse de las cosas. Y ha elegido esta localidad, ya que en ella existe una comunidad importante de Testigos de jehová, grupo al que Ángela pertenece como miembro activo, organizando la comunidad un encuentro todos los domingos. Lo ha firmado voluntariamente en el despacho de la trabajadora social, Lleva muy mal los momentos de soledad, por eso muchos fines de semana, que la auxiliar no acude al domicilio, realice llamadas insistentes al centro de salud demandado que pasen por el domicilio. Tal es la insistencia y demanda que, su auxiliar en contacto telefónico, nos comunica que no puede más y piensa dejar de acudir al domicilio de Ángela. Podemos sospechar que quizás, no realice bien la toma de medicación, aunque Ella, lleva buen control de la pauta a seguir. Se ha recibido llamada de la trabajadora social de centro de salud de Villanueva del fresno (Emilia) para informar que en el transcurso de la mañana de hoy (jueves 22 febrero) va a realizar visita al domicilio de Ángela y poder hablar con Ella. Emilia expresa que Ángela podría aceptar ingresar en plaza residencial en la misma localidad (Villanueva del Fresno) pero al exigirse grado II, debería en principio abonar de manera privada, su plaza hasta la nueva valoración y obtención de grado. Pues no sabemos cuánto puede demorarse su plaza en Jerez de los Caballeros, para la que solo necesita su grado I. El 31 de enero ha estado en consulta de endocrinología para revisión de su bocio, por nódulo dominante en zona izquierda. Está pendiente de recibir cita para ecografía y valoración de posible intervención.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='SANCHEZ'and apellido2='GARCIA'),'2024-02-23','Ana: Cristina Hdez., TS del CSS, hace unos días llamó una hermana de Mª Concepción y quién decía ser su abogada, solicitando resolución judicial y motivo de internamiento. Les dijo que por protección de datos no podía facilitarles información y que como su hermana estaba a cargo de la CTAEx, se dirigiera a la misma. ···································· Mª Concepción se encuentra bien. Sin novedades.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2024-02-23','TERESA He hablado con Vanesa la directora de la residencia de Jerez de los Caballeros, Hernando de Soto, esta la seis en la lista de espera y hay posibilidad de que pueda ingresar pero para ello tiene que hacer una entrevista previa para ver el nivel de autonomia que tiene ya que es una plaza de validos. La ha citado el día 5 de marzo a las 11:30 para valoracion Organizar con la cuidadora para que le acerque ese día a Jerez. Tambien me ha llamado Emilia la trabajadora social de Villanueva para comentarme que estan valorando la posibilidad que entre en el piso de Villanueva pero estan en la misma tesitura de valorar su autonomía. TELEFNO EMILA TS 43330 L,M,X, OLIVA 42912 J-V VILLANUEVA VANESA DIRECTORA HERNANDO DE SOTO 21781','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2024-02-23','Ana: Envío correo a Alberto, Jefe S. Ecca: "Necesito saber cómo está la situación económica de Martín Domínguez Palencia, pues me llaman del CSS, para recordar que sigue sin nada de dinero de bolsillo y sería conveniente concederse, si es viable, al menos 10€/semana. Por otra parte, también necesita ropa y calculan unos 200€ en tal concepto. Le acompañarían a comprarla y enviarían después factura. Si se aceptan estas propuestas, o alguna de ellas, HABRÍA QUE HACER AUTORIZACIÓN GENERAL DE CENTRO, pues según me dicen no la tienen."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='CRESPO'and apellido2='PEREZ'),'2024-02-23','Ana: Llamada de Cristina Hdez, TS CSS (24185), consultará a los médicos con respecto a la posibilidad de que Ángel pudiera regresar al domicilio en un futuro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2024-02-23','Ana: Envío a Cristina Hdez., TS CSS-Plas (cristina.hernandezca@salud-juntaex.es) el consentimiento de tratamiento con DISULFIRÁN y CIANAMIDA CÁLCICA, debidamente firmado y sellado por la Representanta Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2024-02-23','Ana: Correo de Estela, C.R. Las Eras - Mensajeros de la Paz (rmhernanperez@mensajerospazex.es). Envían NOTA DE TRATAMIENTO PSIQUIÁTRICO, NOTA DE próxima CITA (V. 9/08/2024) e INFORME DE SITUACIÓN ACTUAL emitido por el NEUROPSICÓLOGO del centro- Salvador Fdez., en el que indica: "Su proceso de adaptación en el centro ha sido muy favorable, teniendo una actitud la mayor parte del tiempo afable, alegre y colaboradora. Desde un inicio ha estado muy motivada en la realización de las actividades de envejecimiento activo que se desarrollan en el centro." y "A nivel clínico destaca la presencia de alucinaciones y delirios sobre todo por la noche pero sin angustia ni ansiedad observable. Por su parte no se detectan síntomas negativos de la esquizofrenia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CESAREO'and edp.apellido1='PANIAGUA'and apellido2='CALLE'),'2024-02-23','Ana: Vuelvo a llamar al Padre Miguel Muñoz (679 077 448) salta el buzón de voz. Dejo un mensaje pidiendo devuelvan la llamada. ·································································· Envío un correo a la dirección de que disponemos de la Asociación "NUNQUAM SANTIS" (hildegardamil@hotmail.com): "Mi nombre es Ana, soy Trabajadora Social del Gabinete Técnico de la Comisión Tutelar de Adultos de Extremadura (CTAEx), tras no poder contactar con usted en los número de que disponemos: (619 040 701 / 679 077 448) me pongo en contacto por esta vía en relación a D. CESÁREO PANIAGUA CALLE, cuyo cargo ostenta la CTAEx, para hacerles llegar la CITACIÓN para RECONOCIMIENTO MÉDICO FORENSE el próximo día 06/03/2024 a las 10:50 horas en el INSTITUTO DE MEDICINA LEGAL DE CÁCERES. Este reconocimiento forma parte del proceso judicial de REVISIÓN DE LAS MEDIDAS DE APOYO. Agradeceríamos que nos confirmaran que Cesáreo podrá asistir y que, a ser posible, irá acompañado. También, si lo requiere, podríamos solicitar desde aquí que le acompañara una Educadora del Programa de Apoyo Comunitario gestionado por la Entidad Futuex en base al convenio con la Junta de Extremadura. Pero entendemos que irá más tranquilo con alguien de confianza. Ante cualquier cuestión, no duden en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CESAREO'and edp.apellido1='PANIAGUA'and apellido2='CALLE'),'2024-02-20','Ana: En relación a la citación en el Juzgado (día 06/03/2024 a las 10:50 horas) para realización de reconocimiento medico forense, llamo al Padre Miguel Muñoz (619 040 701 *éste número corresponde ya a una empresa). En el 679 077 448 no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-02-23','TERESA hablo con m carmen de casa roja 619306510, me comenta que ha estado hablanco con Aitor y la conversacion se ha ido de madre termiando en amenazas Me dice que asi no puede ingrear qeu lo idoneo esque que ingrese en la uhb para que le pongan un tratameinto psiquiatrico y de alli pase a la comunidad terapeutica','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2024-02-23','Ana: Corre de Belén Pavón (Belen.asoma@outlook.es) a mi correo y al ctutelar@: "Adjunto actualización de la tasa mensual 2024 de la estancia de Doña María Salvadora Chaves Mendoza. Cualquier consulta o sugerencia, estamos a su disposición"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2024-02-23','Ana: Correo de Inés - S. Jurídica CTAEx con DILIGENCIA DE ORDENACIÓN que dice literalmente: "Puestos en contacto con la Residencia de Mayores de Riolobos, nos informan que desde hace varios meses el demandado JOSE Manuel Moreno Carlos está ingresado en la planta de psiquiatría del Hospital Virgen del Puerto de Plasencia, que desde el hospital le han informado que su evolución está siendo muy lenta, no pudiendo concretar ni posible fecha de alta ni si una vez se le de alta volverá a la residencia, por lo que se acuerda requerir a la Comisión tutelar de adultos de la Junta de Extremadura a fin de que informe a este Juzgado una vez se produzca el alta de D. JOSE MANUEL MORENO CARLOS y lugar en el que se encuentre,"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-02-26','-Amalia : remito email a la Residencia de Jardín del Tietar. direccion@jardindeltietar.com enfermeriajardindeltietar@outlook.com Buenos días , os voy enviando documentación según conversación telefónica , lo más importante es la sentencia y la aceptación del cargo . Es un tutela absoluta , abarca todas las esferas tanto la personal como la económica , incluida la esfera de la salud . Esta sentencia se mantiene hasta la revisión de las medidas de apoyo . Por lo tanto ,para cualquier asunto referido a la esfera sanitaria podemos intervenir desde esta Comisión . Le he trasladado a mi compañero el asesor jurídico las dudas que surgían tras la emisión del informe médico elaborado por el psiquiatra de Plasencia. Corrobora lo comentado con la doctora esta mañana , habrá que pautar lo que los médicos hayan establecido tras su último ingreso en la Unidad de Psiquiatría del Hospital Provincial de Ávila . Me indica que si hay alguna incidencia ,ya sea por parte de Jesús , su hermana ... que nos hagáis un escrito y lo podría remitir al juzgado pertinente . Con ésto , se cubre las decisiones sanitarias que se tengan que tomar . Os adjunto la sentencia , y os iré enviado el resto de documentación : la autorización para salidas y contactos del hospital de Madrid de MUFACE . Todo ello con las reservas oportunas de Protección de Datos , al ser información de especial protección por el ámbito de la salud que menciona ( incluso de las hermanas ) . Estando coordinados será mucho más eficiente la intervención. Gracias . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-02-23','-Amalia ; hablo con la Dtra. y con la Dtra. de la residencia .Me comenta que ella activó el 112 para el intern involuntario por brote , debido a que dejó de tomar la medicación. Encontraron en su habitación las pastillas guardadas sin tomar. Lo derivó por urgencias , en esos casos da igual que sea de muface pq prima la seguridad . Lo puso como usuario de SS pq desconocía que era Muface pero aún así ante la urgencia es lo que establece el protocolo. Le voy a pasar información del hospital de Madrid de Muface por si se necesita en otra ocasión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-02-26','Escribo a los jurídicos para qu deriven el caso a Avila , lleva muchos años allí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2024-02-23','miguel, recibo email de la abogada Estefania Estefania@beramendiygonzalez.com Buenas tardes Miguel, perdona la tardanza pero entre que quedé con Mercedes y entre que me enviaron la documentación, además de por el exceso de trabajo que tengo, no he podido contestarte antes. Respecto de lo que me indicas, voy por partes porque me ha sido imposible repasar toda la documentación que me han traído. A la pregunta que me haces: De la reclamación a la aseguradora para el desembolso, eso se ingresó en la cuenta común, donde también se hacen los ingresos-gastos de la vivienda de Madrid? Os lo ingresaron directamente a vosotros y después se realizó el pago a la cuenta de la Funeraria. Te mandé toda la documentación en su día. Respecto de la documentación que me solicitas te envío la copia de la escritura de Madrid de Alfonsa junto con la cancelación de hipoteca (te la adjunto). Te la puedo hacer llegar por correo, indicándome una dirección. Por otro lado, te indico que no saben decirme cuando se recibieron dos notificaciones de Hacienda imponiendo una sanción a Alfonsa (que te adjunto), yo creo que es por no pagar el IBI. Supongo que vosotros podréis haceros con esa información. Podemos pagarlo nosotros a cuenta de la herencia con lo cobrado por los alquileres. Me trajeron la liquidación pero tengo aún que analizarla. Hablamos la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2024-02-26','miguel, mi contestación a Estefanía, la abogada: Buenos días Estefanía, gracias por la información. Necesitamos que de hoy a ayer, ya que esta señora tiene 84 años agilicemos este asunto, y estábamos ya en puertas de preparar la documentación para enviar a la notaria y que en pocas semanas hicieran la herencia. Para ello y recapitulando necesitamos que: 1) Me remitas lo antes posible aquel excell de ingresos y gastos a incluir en la escritura por estos años de alquileres, gastos de administración de bienes, etc. 2) Como comentamos en su día los gastos de administración de los bienes de la herencia debían ser asumidos por la cuenta común y por tanto no entiendo que el ibi no se haya abonado en su totalidad por dicha cuenta. Abonad esas notificaciones de AEAT. 3) Aunque yo remita la documentación que te indiqué y de qué dispongo, si solicitan algún original desde la notaria de Herrera del Duque, tendríais que remitírsela vosotros directamente. Esperaré un par de semanas para que me remitas documentación que entiendas que falta a la relación que te envié y las cuentas bancarias que haya, y saldo a fecha de fallecimiento de los hijos de Alfonsa para remitir a la notaria lo que dispongamos. Recuerda que el trámite posterior a la firma de la escritura de adjudicación de herencia, será que el abogado que nombremos deberá aceptar dicha adjudicación de herencia y solicitar posterior autorización de venta. Hablamos esta semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2024-02-26','miguel, llega la autorización de venta de inmueble del juzgado, que ya no sirve por que el curatelado ha recuperado su capacidad. Le reenvío a Damian dicha resolución judicial','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2024-02-23','miguel, recibo email del tutelado Hola Miguel, llamo al juzgado pero, con quien tengo que hablar? Y estoy en mi derecho para que hagan la gestión?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2024-02-26','miguel, le contesto: Buenos días, debe hablar con el juzgado de 1º instancia e instrucción nº2 de Coria que es el que está tramitando su procedimiento REVISION MEDIDAS DT5 LEY 8/2021 576/2023. Dígales que lo que tengan que enviar a la Comisión Tutelar de Adultos, tienen que enviarlo a la abogacía general','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2024-02-26','Ana: Envío correo con DERIVACIÓN al programa a Toni-Futuex, para que hagan visita/segumiento cada vez que va a su pueblo. En esta ocasión va desde hoy L hasta el V.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-02-26','Ana: Llamada de José Luis, hermano de José Manuel (687 581 061): para informar de que ya está finalizada la obra y pagada la obra, dice que asume él los gastos de albañilería para que no tenga tantos su hermano. En cuanto al resto de gastos que reclama el vecino de abajo hablaremos desde aquí con la aseguradora y el propietario. ···················································· Envío a los A. Jurídicos, el correo de Toni-Futuex, sobre los desperfectos y otras cuestiones que tiene que abonar José Manuel a su vecino de abajo, tras el incidente del baño, añadiendo la siguiente explicación: "Tras haberlo hablado con Maite, os reenvío correo de Toni Futuex, en relación al incidente acaecido y la obra correspondiente en la vivienda de José Manuel Romero Mediavilla, el pasado mes de enero. Como sabréis hubo un desprendimiento del techo del cuarto de baño del piso de José Manuel a la vivienda de abajo. La avería proviene de la casa de José Manuel. Puesto que no tiene seguro de hogar, tiene que asumir los costes correspondientes. Pero a mí hay cuestiones que se me escapan de todo lo que le corresponde asumir a él o no. Por eso, ¿sería posible que llamaseis alguno de vosotros a la compañía de seguros del propietario y, si fuera necesario, al propio propietario, para que os expliquen y solicitéis la documentación pertinente para abonar o no lo que reclaman? "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2024-02-26','TF MIGEL 642632131','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2024-02-26','teléfono de mi hermana gema 642137837, Es la persona que él quiere que sea su curadora','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2024-02-26','Ana: Envío correo con HOJA DE DERIVACIÓN al programa de apoyo comunitario a Toni-futuex, para seguimiento y apoyo periódico en Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-02-26','miguel, recibimos la parte económica, social y jurídica el email de Sandra Sánchez >ssanchez@inteligencialimite.org>: La tramitación de la documentación está siendo complicada adquirirla, pues nuestra Entidad no tenía contacto con la familia del curatelado. Por una parte, estamos intentando poder entrar en la casa, por si hubiera documentación dentro. Nos está costando pues cuando hemos ido con las llaves del usuario, se había cambiado una de las cerraduras. Solicitamos a comisión tutelar el dinero para cambiar dicha cerradura pero cuando volvimos, parecía que había sido manipulada otra de las cerraduras, por lo que tampoco pudimos entrar. Estamos esperando presupuestos de las cerrajerías para solicitar el dinero correspondiente a comisión. Por otro lado, conseguimos ponernos en contacto con Dori, la tía de José María y una de las herederas. Comenta que no tiene ningún tipo de documentación y que no quiere saber nada de este proceso. Sin embargo, indica que se acercará a la notaría que llevó el caso de las fallecidas y la herencia y que nos informará al respecto. La semana pasada me volví a poner en contacto con ella pero no había ido todavía. Además, nos facilitó el teléfono de Lolo, hermano de José María y otro de los herederos. Parece ser que este chico tiene en su poder las escrituras de la casa y otros documentos de valor, pero nunca ha querido facilitarlos a la familia. Teresa de Futuex quedó en llamarle pero por diversas circunstancias no ha podido. Por último, el propio usuario trabaja y tiene horarios muy cambiantes, por lo que también se hace complicado poder quedar con él para acudir a diferentes administraciones a preguntar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2024-02-26','SE HA AMPLIADO PLAZA A TODA EXTREMADURA DE R.M.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2024-02-26','Ana: Envío a Juan Carlos para REGISTRO: "En relación con Dª. PILAR DÍEZ SANTIAGO, cuyo cargo ostenta la CTAEx, adjunto remito la siguiente documentación: - Aceptación PIA - Servicio de Atención Residencial de Mayores - Anexo Informativo Aceptación – PIA – SAR - Testimonio de Sentencia de Medida Judicial de Apoyo y Nombramiento - Testimonio de Aceptación del Cargo - Decreto de nombramiento de Directora Gerente del SEPAD - Resolución de Delegación de Funciones como PRESIDENTA DE LA CTAEx. - DNI – Representante Legal (Presidenta CTAEx) para remitir por REGISTRO a: SEPAD Sección de Dependencia V Ctra de Cáceres, s/n 10600 PLASENCIA (CÁCERES) Buzón de Registro: A11030404" ································································································································ Entrego a las compañeras de la S. Ecca el ALTA DE TERCEROS, para que lo lleven al banco. ·············· *Cuando lo traigan remitiré para registro la Aceptación PIA para la Prestación Vinculada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-02-22','TERESA Desde el equipo de apoyo social comunitario, sobre el caso de Marta Rivera Nuñez, destacamos la información recibida el 14 de febrero 2024, por Marta y confirmado por la trabajadora social a su cargo en Plena Inclusión Cabeza del Buey. Afirman que el 1 de marzo de 2024, Marta procederá a trasladarse a Valencia con el propósito de establecer su residencia allí. Desconocemos si ella puede actuar de forma autonoma para este traslado o si se autoriza. En el día del ultimo seguimiento, 20 de febrero, se constata la ausencia de Marta en la institución de Plena Inclusión, así como en su cita programada con el psiquiatra. Con el propósito de informarnos de esta situación, se ha realizado contacto telefónico con Plena Inclusión Cabeza del Buey, quienes han comunicado haber mantenido conversaciones directas con la Comisión. Además, se nos ha informado que el día anterior, 19 de febrero, Marta recibió su asignación semanal, lo que lleva a concluir que posiblemente no asistirá al centro durante la presente semana, siendo este incentivo el motivo principal de su presencia habitual. No obstante, se nos ha indicado la imposibilidad de ofrecer detalles adicionales sobre el incidente. A pesar de que se les explica que este programa está fundamentamente para recoger información in situ y darle traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2024-02-26','TERESA HABLO CON LA DIRECTORA DEL CENTRO DE MAYORES DE JEREZ PARA VER POSIBLE INGERESO Y LA CITA PARA VALORACION EL 5 DE MARZO LE COMUNICO A FUTUEX PARA ACOMPAÑAMIENTO TAMBIEN SE ESTA A LA ESPERA DE ACEPTACION EN PISOS DE MAYORES EN VILLANUEVA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-02-26','Ana: Envío a Toni-Futuex, con copia a Mamen, Ed Futuex (delegadapoyo.caceres@futuex.es): "Adjunto NUEVA CITACIÓN de PSIQUIATRÍA, que me remiten desde el Equipo de Salud Mental, relativa a CARLOS GONZÁLEZ LEO. ¿Podéis por favor comunicárselo a él e intentar por todos los medios que acuda a la cita y lo haga acompañado de Mamen? La pongo en copia para que hoy también esté al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2024-02-27','Ana: Correo de Cristina Hdez, TS CSS (cristina.hernandezca@salud-juntaex.es): "la paciente MªGuadalupe Gil Cabello ha pasado a la Unidad de rehabilitación, como sabéis dicha unidad tiene copago. Necesitamos nº cuenta, así como tipo de pensión e importe." ······························································································································································································· Mi respuesta: "Guadalupe percibe una PNC, cuya cuantía este 2024 asciende a 517,90 €. Su situación económica era realmente precaria cuando ingresó en el C. Sociosanitario, no sé exactamente cómo estará a día de hoy. Pongo en copia a Alberto, Jefe de la Sección Económica, para su conocimiento y porque tendrá que recalcular la asignación máxima autorizada para gastos de bolsillo ahora que abonará centro. Había autorizado 200 €/mes. Su nº de cuenta, según veo en su ficha es: ES28 2103 7565 6000 1002 0007. Alberto, corrígeme si me equivoco, porfa, porque en la Base de Datos aparece otra, entiendo que por la fusiones de las entidades bancarias."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='CRESPO'and apellido2='PEREZ'),'2024-02-27','Ana: Correo de Fco. Javier Rodríguez, nuevo TS - CSS (javier.rdguezper@salud-juntaex.es): "Adjunto informe médico de Ángel Crespo." ······ En el Informe del Dr. Herrero, Psiquiatra, indica: "ingresado en el centro, con una estancia ininterrumpida 30/01/2020", "padece ESQUIZOFRENIA RESIDUAL, manteniéndose en este momento los síntomas que hacen aconsejable la continuidad de internamiento sin que exista previsión de alta" ···························· Se lo reenvío a Ángel, A. Jurídico CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2024-02-27','Ana: Subo al portafirmas digital los documentos de ingreso en UHDAC que remite Estrella, Durán, TS - CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2024-02-27','JUAN JOSE MURILLO ROMANO PENSION 517,90€ INGRESO DE FUNDACION MORICHE 171€ ASIGNACION MENSUAL 100€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-02-27','JOSE MARIA RODRIGUEZ MOYA PENSION 877,60€ ASIGNACION MENSUAL 150€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2024-02-27','Ana: En relación al correo de Miguel, A. Jurídico, solicitando datos e informes relativos a Mª Mar, respondo a la Secc. Jurídica: "Adjunto copia del DNI de María del Mar Campos Encina, así como Certificado de Empadronamiento Colectivo con los datos de su cónyuge Jacinto Sánchez Villar, con quién convive, así como libro de familia. Tiene 3 hermanos que residen en IBAHERNANDO, de los cuáles no tengo datos. Intento recabarlos y os digo. El teléfono de contacto es: 648 625 099 El domicilio: C/ SANTA LUCIA, 15, 5º A – Aldea Moret (Cáceres) En cuanto a los informes, procedo a solicitar Informe Médico y e Informe Social actualizados. En cuanto los tenga" ·························· Subo al portafirmas para la firma de Maite, Jefa - CTAEX, Oficio-solicitud de Informe Social al IMAS. ·································································································································· Envío a Juan Carlos Cano, Aux. Adtvo, para que remita por REGISTRO al C.Salud de Aldea Moret, Oficio-solicitud de Informe Médico para la revisión de las Medidas de apoyo junto con el Testimonio de Aceptación del cargo. ····························································································································································································· Pido a Toni-Futuex: "...- Informe de seguimiento ya situación actual, firmado, para que tengan otra fuente de información antes de decidir. - Datos de los hermanos (nombre, apellidos, DNI, dirección y teléfono), residentes en Ibahernando, para aportarlos al Juzgado, pues no disponemos de ellos y nos lo piden. Según un informe antiguo la mayoría de los miembros de la familia presentaban discapacidad, si podéis averiguar esto también os lo agradeceríamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-02-27','Ana: Tras recibir llamada de Rosana, Directora de la Res (699 19 81 86), reenvío a Alberto el correo de día 21 y añado: "Te reenvío correo de la semana pasada. Lee por favor el hilo, correo de Lourdes y el mío inicial (lunes 19). Me acaban de llamar, otra vez, la Directora de la Residencia, porque Joaquina sigue sin poder disponer de dinero de bolsillo y además se deben varios acompañamientos desde hace ya meses. URGE buscar una solución a esta situación. No sé cómo puedes contactar CAIXABANK para solucionarlo, si tienen que intervenir los Jurídicos o cómo, pero esto no puede seguir así más meses. Sino, como te decía el día 21, habrá que buscar otra alternativa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-02-20','Ana: Corro de Lourdes - S. Ecca., desde el ctutelar@: "Seguimos sin poder hacer nada, se envío el 5 de enero la documentación para que incluyeran a su tutora como autorizada, posteriormente nos reclamaron unas sentencias y aceptaciones que enviamos a finales de enero o primeros de febrero, pero he entrado en la Caixabank y no se ve. He vuelto a reenviarles el mismo correo, a ver si me dicen algo pronto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-02-21','Ana: Reenvío a Alberto, J. Secc. Ecca., el correo de Lourdes de ayer y añado: "Con respecto a este asunto, ¿se te ocurre alguna otra alternativa? Abrirle otra cuenta o algo, lleva ya meses sin poder acceder a nada de su dinero para gastos de bolsillo y eso no ayuda precisamente a su adaptación al centro que fue ingreso involuntario."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2024-02-27','miguel, recibo email de la compradora Ana María Muñoz Toro >anamariamt99@gmail.com> Por favor, necesito solucionar esto ya. Hace más de 2 años de la compra de la vivienda y este asunto sigue sin solucionarse. Espero nuevas noticias ***************************************************** Envío desde Ctutelar email a Ibercaja, rsc@ibercaja.es; atencioncliente@ibercaja.es; GUADIANA DEL CAUDILLO 4507, Oficina de >2085.4507@ibercaja.es> Buenos días, les requerimos de nuevo para procedan a realizar las actuaciones necesarias para el levantamiento de la carga registral de la hipoteca de caja Badajoz que recae sobre la finca registral 39649 del registro de la propiedad de Badajoz nº1, cuyo prestatario era el vendedor (curatelado por esta Comisión Tutelar de Adultos de la Junta de Extremadura) Don Juan Carlos Rubio Galan con dni 08849335Q. Habiendo transcurrido más de dos años desde que se les solicitó dicho levantamiento de carga registral, o nos fuesen indicando los trámites a realizar conjuntamente con su entidad bancaria, a fecha de hoy no hemos obtenido respuesta, motivo por el cual ponemos en copia a la parte compradora para su conocimiento. Les requerimos nuevamente para procedan a levantar dicha carga, quedando a su disposición para la correspondiente provisión de fondos, firma de documentación (autorización para que los trámites los realice la gestoría de Ibercaja). Les adjunto de nuevo documentación referida a dicho préstamo: certificado de deuda, y datos del préstamo del curatelado Juan Carlos Rubio Galan, copia simple de la venta, y certificado de nacimiento acreditativo de estar curatelado por la Comisión Tutelar de Adultos de la Junta de Extremadura. Rogamos confirmen la recepción y contestación a este email. ******************************************************** Reenvío este email y contesto a la compradora Ana María Muñoz Toro >anamariamt99@gmail.com>: Buenos días, adjunto nuevo email remitido a la sucursal de Guadiana del Caudillo a las que vuelvo a solicitar agilicen el trámite. Dicho trámite depende exclusivamente de la Entidad como puede ver en los emails que les hemos remitido en reiteradas ocasiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2024-02-27','Ana: Tras conversación con Beatriz, Res. Mayores Garrovillas de Alconétar (619 553 189 // beapavonguerra@hotmail.com), tal y como habíamos acordado me envía mail: ", adjunto envío consulta médica de María Rosario Moreno Hermosa, mañana 28 de febrero al Hospital Universitario de Caceres. Le acompaña una trabajadora, cuando venga de la consulta, te mandamos declaración jurada con los datos de la acompañante para que le hagáis transferencia bancaria, también te mandaré informe médico de la consulta." ·································· *Cita en Radiología el día 28/02/24 a las 11:15 h. ································································································································································································ Envío a Juan Carlos, Aux. Adtvo. (juancarlos.cano@salud-juntaex.es): "Adjunto, para remitir a la DIRECCIÓN PROVINCIAL DEL INSS en Cáceres, la siguiente documentación relativa a Dª. Rosario Moreno Hermosa: - Oficio-solicitud de REVOLORIZACIÓN/CERTIFICADO ACTUALIZADO DE PENSIÓN. - TESTIMONIO DE SENTENCIA - ACUERDO DE ACEPTACIÓN DEL CARGO"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2024-02-27','Ana: Conversación con Beatriz, Res. Mayores Garrovillas de Alconétar (619 553 189 // beapavonguerra@hotmail.com): Acaban de recibir una CITACIÓN para consulta especialista dentro de 2 días. ················· Acordamos que el acompañamiento lo realizará una auxiliar de confianza. El coste son 50€. *Nos remitirán Declaración Jurada a posteriori. ························· Comunico a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2024-02-27','miguel, envio email a Alberto, Estrella y Tere: Buenas tardes, he logrado hablar con AEAT, y me han dado cita en la oficina de Mérida para me den las 6 notificaciones que me han comentado que tiene pendientes la tutelada. Parece ser que al menos desde el 2019 no presenta la declaración de la renta. No me han querido decir el importe que se debe pero parece ser que es altísimo. Teniendo en cuenta que la herencia está en situación de bloqueo por que dependemos de la documentación (escrituras y algunos originales) e información (ingresos y gastos comunes a la herencia, entre ellos el alquiler del piso de Madrid ) que tiene la abogada de Gijón (abogada de la exnuera), unido al hecho que estuvimos al menos año y medio detrás de la notaria de Herrera del Duque para que preparara las dos declaraciones de herederos de los dos hijos fallecidos…vamos que es un expediente gafao. En conclusión que el jueves me dará hacienda las cartas de pago de todo lo que se debe que será mucho y tendremos que ver si se puede fraccionar y cómo afrontar este gasto. Me confirma Alberto que no tiene dinero para enterrarse llegado el momento. Mientras en dos semanas tal como le dije esta semana a la abogada si no me manda los ingresos y gastos a incluir en la escritura de adjudicación de herencia…que debió remitirme hace meses, enviaré a la notaria de Herrera del Duque lo que tenemos para que preparen la escritura, y buscar quién nos haga el trámite de inscripción en el registro de las dos propiedades, Herrera del Duque y Madrid (que es donde se ubican los dos inmuebles), creo que no hay cuentas bancarias que repartir. Os recuerdo que luego vendrá el trámite de contratar abogado que solicite aprobación de herencia, y autorización de venta de inmuebles (que entre otros requisitos necesita tasación). Por tanto los trámites van para largo y la deuda con Hacienda es inminente. Una vez os la envíe desde la parte económica tendréis que coordinar hacer todas las declaraciones de la renta pendientes. Parte social, Tere, ves buscándole una residencia lo más barata posible porque empezarán a embargarle la cuenta pronto. El jueves os comentaré lo que averigüe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2024-02-26','miguel, envío email a Tere, Alberto y Estrella: Buenos días, podéis comprobar si están abonadas estas notificaciones que me ha enviado la abogada? Caso contrario necesitaremos las cartas de pago, a no ser que ya le hayan hecho el cargo en la cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-02-27','Ana: Las compañeras de la secc. ecca. aportan el ALTA DE TERCEROS pendiente. ·········································· Escribo a Marina Carmen Cintas, Jefa Secc. Prestaciones - PNC (marinac.jimenez@salud-juntaex.es): "Tal y como acordamos mediante conversación telefónica hace algunas semanas, adjunto de nuevo el ALTA DE TERCEROS relativo a Dª. MARÍA ÁNGELES SANTOS URBANO, con DNI 28942071K, cuyo cargo ostenta la CTAEx. Si recuerdas, me informaste que hubo un error y al actualizar los datos en el Programa Alcántara y cogisteis el número de cuenta antiguo, en la que está el padre, pero la CTAEx no tiene acceso a la misma y Mª Ángeles ha dejado de percibir la PNC en su cuenta desde noviembre de 2023. Como acordamos también la remitiremos por registro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2024-02-27','Ana: Envío a Juan Carlos Cano, Aux. Adtvo. (juancarlos.cano@salud-juntaex.es): "Adjunto la siguiente documentación relativa a D. JUAN GREGORIO LOZANO VALLE, para remitir por REGISTRO a la DIRECCIÓN PROVINCIAL DEL INSS en CÁCERES. - Oficio-solicitud de REVOLORIZACIÓN/CERTIFICADO ACTUALIZADO DE PENSIÓN. - TESTIMONIO DE NOMBRAMIENTO Y ACEPTACIÓN DEL CARGO"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2024-02-27','Ana: Envío a Juan Carlos, Aux. Adtvo (juancarlos.cano@salud-juntaex.es) para REGISTRO: "...adjunto remito la siguiente documentación: - Aceptación PIA – PRESTACIÓN ECONÓMICA VINCULADA – Servicio de Atención Residencial - Anexo Informativo Aceptación – Prestación Económica Vinculada al SAR - Modelo de Alta para terceros - para remitir por REGISTRO a: SEPAD Sección de Dependencia V Ctra de Cáceres, s/n 10600 PLASENCIA (CÁCERES) Buzón de Registro: A11030404"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2024-02-28','Ana: Recibimos Informe Social para Inventario, pero el que envían es el INFORME DE SITUACIÓN DEL CAM de Caminomorisco. ·········· Se lo remito a María, S. Ecca. ······································································· Derivo el expediente a Teresa, TS CTAEx, para seguimiento, pues ya ha pasado el periodo de adaptación y están las gestiones del Plan de Intervención Inicial realizadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-02-27','Ana: correo de Toni-Futuex: "José Manuel se pone en contacto con la educadora de Cáceres para comunicarle que le han dado el alta en el sociosanitario de Plasencia y está volviendo a Cáceres. Se llamará al catering Mesa y Mantel para reactivar este servicio ya que él dice no tener nada de comida en casa ni suficiente dinero para comprar., si os parece bien. También comunica que el día 28 tiene que ir a recoger una notificación a los juzgados, no sabe porqué puede ser, se le acompañará a esta gestión."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-02-28','Ana: Llamada de Mª Carmen, TS HSPA (56283): Francisco ingresó en la UHB el día 24/02, mediante INGRESO INVOLUNTARIO. El motivo que les consta es "problemas sociales". ········· Les ha manifestado que está preocupado porque si está allí los primeros días del mes no podrá retirar su asignación mensual. *Pido que le expliquen que no habrá problema, que nos avisen unos días antes del alta, según previsión, para que mis compañeras puedan enviar nueva autorización al banco. ······························ Comunico a Toni-Futuex, en relación a su seguimiento desde el programa. ·············· Respuesta de Toni: "...es cierto que nos estaba resultando imposible.. ni cogía el teléfono, ni se le veía en las retiradas en el banco, como se suele ir con otros y allí también se coincidía,, lo ultimo que comentó la compañera es que creía haberlo visto en ECA . Y lo ultimo que comento él, es que se iba a ir a Madrid. Asique nada, cuando salga intentaremos retomar el seguimiento.."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2024-02-27','Ana: Correo de Toni-Futuex: "Al parecer según lo observado en los seguimientos y lo comentado por la auxiliar del SAD, hace unos dias se le cayó el calefactor que tiene en el salón y se rompió, pero él aún así lo sigue utilizando (a ella le da miedo que pueda suponer un peligro). Se acompaña a Ventura a ver un calefactor al Electrocash, donde ya se ha trabajado anteriormente en otras ocasiones, y allí se pide presupuesto de un radiador de aceite que es más seguro y consume mucho menos que una estufa de cuarzo que es la que él tiene. Se adjunta presupuesto para que se valore. Somos conscientes que hace nada se le han pagado dos viajes, y se dijo taxativamente que no se le iban a conceder mas extras, y se está intentando trabajar con el, para que se lo compre de su asignación, pero por ahora no lo conseguimos.." ···················· Paso el presupuesto a la secc. ecca. Lo que habíamos hablado es que no se daría más extras para viajes, para este tipo de cuestiones, si es viable, entiendo que no habrá problemas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2024-02-28','Ana: En relación a la llamada de Guadalupe, TS SAD-IMAS (927 212 335), envío correo a Toni-Futuex con copia a Nieves, Ed. Fututex (delegadapoyo.caceres2@futuex.es): "Me han llamado de Serv. de Ayuda a Domicilio del IMAS – Cáceres. Como sabes también gestionan el Cáterin Municipal. En relación a este servicio del que Ventura es usuario, nos informan de que NO está haciendo buen uso del mismo. Acumula tuppers de comida en el frigorífico que acaba estropeándose y finalmente hay que tirarlos. No quisieran, ni queremos, que le suspendan el servicio por mal uso del mismo, pues además con la diabetes de Ventura, le conviene comer bien. Nos informan también de que sale mucho a comer fuera, pero no sabemos qué come exactamente y cómo puede afectarle a su estado de salud. Y que tiende a comprar muchos productos azucarados que tampoco debería ingerir. **Nos piden, por favor, que seamos discretas, pues Ventura tiene muy buen vínculo con la Auxiliar de SAD, así por favor, que ni la nombren en este asunto. Igualmente, de algunos productos frescos que le dan en Cáritas, a menudo se le estropea la fruta porque tampoco se la come. Nuestra petición es que, en los seguimientos que haga Nieves, pueda comprobar por sí misma estos hecho e intervenir al respecto, primero porque no queremos que se tire la comida (hay muchas otras personas que pueden necesitarlo), segundo porque no queremos que se quede sin el servicio y tercero porque lo ideal sería que mantuviera una dieta saludable y adecuada a su estado de salud y patologías. Como cuarto punto, indicar la necesidad de alcanzar el objetivo de adquisición de hábitos más saludables por parte de Ventura, que redunden favorablemente en su estado de salud." ···························································································································································································································································· Envío a la Secc. Ecca: "Os paso presupuesto para RADIADOR DE ACEITE para VENTURA GÓMEZ GARCÍA. Se le ha caído el que tenía y se le ha roto (subrayo en amarillo en el hilo). Entiendo que es necesario y que él puede permitírselo, así que por mi parte OK al presupuesto. Si no me equivoco, acordamos que no se concedería ningún extra más para viajes este año, pero no para este tipo de cuestiones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2024-02-28','Ana: Envío a Estrella Durán, TS CSS (estrella.duranc@salud-juntaex.es) los documentos relativos al ingreso en UHDAC firmados digitalmente por la Presidenta de la CTAEx: "Compromiso Formal" y "Autorización expresa" para cuestiones varias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-02-28','Ana: Envío correo a Juan Carlos Cano, Aux. Adtvo. (juancarlos.cano@salud-juntaex.es): "adjunto - Solicitud de variación de datos bancarios - Modelo de Alta de Terceros, debidamente formalizado por el banco para su registro a: Secretaria General de Servicios Sociales, Inclusión, Infancia y Familia SERVICIO DE PRESTACIONES SOCIALES C/ ANTONIO RODRIGUEZ MOÑINO 2, 2ª Planta C.P. 06800 MÉRIDA DIR3 A11030105"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-02-28','Ana: Envío a Juan Carlos, Aux. Adtvo. (juancarlos.cano@salud-juntaex.es) para REGISTRO: "adjunto: - Declaración Anual de Pensionista – PNC – 2023/2024 - DNI de la actual Presidenta de la Comisión Tutelar de Adultos - Decreto de nombramiento como Directora Gerente del SEPAD - Resolución de Delegación de competencias como Presidenta de la CTAEx Para remitir por registro a la siguiente unidad de tramitación: DELEGACIÓN TERRITORIAL DE INCLUSIÓN SOCIAL, JUVENTUD, FAMILIAS E IGUALDAD C/ CORDOBA, Nº 4 – MÁLAGA (29001) A01035475" ························································································································································································································································ Remito a Ana Castillo Foronda TS - FUNDACIÓN AUTISMO SUR (teayudamos@autismosur.es), REVALORIZACIÓN DE LA PENSIÓN - 2024','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2024-02-26','miguel, recibo email de la abogada ROSA MARIA MUÑOZ BERNALDEZ >2913@icaba.com> O20230000025 RAFAEL FAUS LEMUS DILIGENCIAS PREVIAS 180/19 NUM. 1 DE ZAFRA JERONIMO VAZQUEZ MORAN Soy Rosa Muñoz Bernáldez, abogada de oficio de RAFAEL FAUS LEMUS, tenemos una citación en el Penal Nº 1 de Badajoz, para el día 28 de febrero a las 11:00 horas, a efectos de una posible conformidad. Esta mañana me han dado en el Juzgado de lo penal, el teléfono del Centro Penitenciario, Puerto 1, donde está interno este hombre, y he hablado con la Trabajadora Social, quién me ha indicado que Rafael está incapacitado judicialmente, y que la tutela la tiene La Comisión Tutelar de Adultos de la Junta de Extremadura, en el Juzgado no tienen conocimiento de que este hombre esté incapacitado, así que necesitarían la resolución de la incapacidad y de la tutela, puede por favor enviármela por este medio, a fin de acompañarla al Juzgado. También, tendréis que estar presentes en el Juzgado el día 28 de febrero, a efectos de una posible conformidad, pues sí este hombre está incapacitado, entiendo que no podrá prestar su consentimiento. Sí hace el favor de facilitarme un teléfono donde poder hablar con Vd. o bien llamarme Vd. a mí al teléfono 647835693 -------------------------------------------------------- Contesto a la abogada y reenvío email a Angel y Amalia: Buenos días Rosa, conforme conversación telefónica adjunto testimonio de sentencia de incapacitación, nombramiento, aceptación de cargo y certificado de discapacidad y dictamen técnico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2024-02-28','miguel, me llaman del juzgado y me piden que demos nuestra conformidad a la que dé el tutelado. Le doy los datos del email ctutelar para nos remita toda la documentación y nos requieran para que demos esa conformidad. Pide que sea hoy y le digo que tendrán que citarnos nuevamente porque no da tiempo a estudiar la documentación cuándo la remita, y a preparar un escrito y firmarlo por nuestra Gerente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2024-02-28','Ana: Envío a Juan Carlo, Aux. Adtvo (juancarlos.cano@salud-juntaex.es): "Adjunto OFICIO SOLICITUD DE INFORME SOCIAL relativo a Dª. MARÍA DEL MAR CAMPOS ENCINAS, para remitir al INSTITUTO MUNICIPAL DE ASUNTOS SOCIALES (IMAS), C/ Atahualpa s/n 10005 Cáceres."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-02-28','Ana: comunico a Lourdes, TS del SAD - IMAS (lourdes.perez@ayto-caceres.es) que José Manuel ya está en casa, le dieron el alta ayer y la vivienda ya es habitable.···· Pueden reactivar SAD y TAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-02-28','Ana: Llamo a Ángel Félix (643 622 174), le comunico que desde la secc. ecca. ya han pagado el teléfono móvil a la tienda de telefonía y puede pasar a recogerlo cuando quiera. ·················· Envío correo a la secc. ecca.: "El día 6 de marzo es el cumpleaños de ÁNGEL FÉLIX MAILLO SANTIBAÑEZ, solicita 150€ de extra por este concepto. Decirme si es viable y en tal caso habrá que autorizarle la retirada de efectivo y comunicarle fecha para ello."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-02-28','Ana: Envío correo Alberto, Jefe S. Ecca.: "Cuando puedas porfa, mira la situación económica de FELISA FELIPE TEOMIRO, hace varios años, si no recuerdo mal, que no se le sube la asignación y va muy ajustada con lo que tiene autorizado. A ver si es posible subírsela al menos un poco." ································· Envío correo a Toni-Futuex: "Cuando podáis, porfa, acompañad a Felisi a pedir presupuesto para comprar ropa. Quiere ir a Cáceres. Mirad realmente que tipo de prendas necesita antes de ir."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-02-29','Le han cambiado la pauta, que tranxilium no debe tomarlo. Le ha puesto Gapentina y trazadona, para los efectos de la abstinencia. Le han dicho que deberia ir dos dias en semana, martes y viernes, para lo cual ir en taxi es inviable, creo que estabais gestionando la tarjeta de transporte interurbano, pero no estoy segura de si ya la tiene operativa o no. La médico ha comentado tambien que van a pedirle una CT y que en concreto la privada donde tiene plaza ha sido expendientada y que ya no está en la red de adicciones. Damos traslado a lo mas significativo de la visita, desconocemos más datos. La semana que viene tiene que hacerse una analitica ademas de los controles de orina. El por el momento, parece estar motivado. Le ha visto tambien haciendole un favor, la psicologa, y le ha mandado una serie de test, para los que se prestara apoyo para que pueda realizar en los proximos dias. Pasa buena tarde','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GONZALEZ'and apellido2='GONZALEZ'),'2024-02-29','Ana: Correo de Toni-Futuex: "como sabes ingresada en la UNIDAD DE ALCOHOLISMO de Plasencia, necesitaria retirar los 120euros que retira semanalmente (los lunes) en Coria, para comprar tabaco y mallas que le hacen falta, ya apenas le queda tabaco... y desde el centro tambien corrobaran la necesidad de comprar algunas prendas. Se solicita, si os parece adecuado que se le pudiera hacer una autorización para retirar en alguna oficina UNICAJA de Plasencia, y el viernes, se iria desde el programa con ella a retirar el dinero y comprar lo que necesita. Nos comentan que la cantidad de dinero que le sobre la guardarian las auxiliares del socio para lo que le vaya haciendo falta, mientras dure el ingreso. Carmen está un poco agobiada por este tema ya que dice que le hace mucha falta las mallas y se le acaba el tabaco para el viernes.. asique ya nos indicareis si es posbible la retirada" ············· Reenvío a la Secc. Ecca. para que hagan la autorización de retirada en Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-02-29','Ana: reenvío PRESUPUESTO DE ARMARIO remitido por Toni-Futuex, a Alberto, Jefe. S. Ecca. ········ Por mi parte si es viable, ok al mismo. Es necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MORA'and apellido2='GARCIA MORA'),'2024-02-19','TERESA SE SOLICITA REVISION DE GRADO Y CAMBIO DE PIA PARA QUE LE ASIGNEN CENTRO RESIDENCIAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='RODERO'and apellido2='COMERON'),'2024-02-29','Ana: Recibimos INFORME SOCIAL para INVENTARIO emitido por Felisa Custodio, TS CAMF-Acuéscar: 53 años. Divorciado. Con un hijo, Izan, de 16 años. *No muestra interés en tener relación con él, pese a las propuestas de la TS de retomar las relaciones afectivas. ···· Otros familiares: Teresa y Agustín, tíos de avanzada edad, residentes en Salamanca, los únicos que se llaman al centro interesándose por él. ········· Ingresado en el CAMF desde noviembre de 2019. Presenta enfermedad rara degenerativa, Grado II de Dependencia, Grado de Discapacidad definitivo del 65%. ······ NO interés y poco implicación en la Terapia Ocupacional del centro. ···· Participa en la actividad de pesca. ····· Pensión de incapacidad permanente absoluta 809,75€/mes para 2024. ··· Múltiples DEUDAS. Embargos y RETENCIÓN de 200 €/mes. ······ 2 PRESTAMOS de 45 y 35 €, no se sabe en qué conceptos. ····· Le dieron de BAJA en SEGURO DE DECESOS POR IMPAGO. ··· *No ha querido actualizar la pensión de manutención que pasa a hijo (120 €/mes) conforme al IPC y a la sentencia. ··· El Jdo. también le reclama GASTO EXTRAORDINARIO a su hijo: 6151,03 € ····· Pendiente de posible INDEMNIZACIÓN POR ATROPELLO. Solicitaron abogado de oficio. ···· GASTOS MENSUALES: 30€ para tabaco y 10€ para gastos de FARMACIA (Medicación pautada por facultativo del centro que no cubre la Seg. Soc). *Desde su ingreso, nunca a aceptado orientación profesional sobre sus gastos económicos. ································································································································································································· Envío correo a Alberto, Jefe Secc. Ecca. con propuesta realizada por Felisa Custodio, con la que estoy totalmente de acuerdo: " - Bloqueo INMEDIATO de cuenta - Anulación tarjetas bancarias y cartilla - Autorización de 40€/mes para tabaco y farmacia - Dar de baja suscripciones - Devolución de prestamos - *Actualización de ASIGNACIÓN MENSULA AL HIJO *Yo añado también, para cuando se pueda, CONTRATAR SEGURO DE DECESOS.". Reenvío en el mismo correo, el que envía Lourdes con respuesta de Juana Heras - Unicaja: "Ayer sacó 600€ en la oficina. Sólo tiene 193€ en cuenta"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2024-02-29','Ana: Llamada de Cristina, Ed. Asociación Vera (681 143 911 // educadorasocial@asociacionvera.com): A Antonia tienen que hacerle una BIOPSIA por sangrado uterino. Puesto que ella no se está quieta, la GINECÓLOGA ha considerado hacer el proceso con ANESTESIA. Tiene la cita el día 5 de marzo a las 7:45 h, tendrá que estar allí hasta por la tarde. Pregunta si es viable un acompañamiento. Coste: 35€ el traslado (ida y vuelta) + 10€/h acompañamiento. Podría costar en torno a 135-155 €. ························ Compruebo en la última rendición que se realizó que no tiene problemas para asumirlo. ········· Cristina enviará un correo al ctutelar@ comunicándolo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-02-29','Ana: Llamada de Pilar y Jesús, su pareja (691 629 533): informan de que están bien en la casa nueva. Están retirando sin problema la asignación de 70€ semanales. A él le llega bien la transferencia de los 150€ para el alquiler y suministros (parte de Pilar). ···························· Por otra parte, Pilar dice que quiere comprarse ropa. Le indico que va a ser difícil, recordándoles que no tenían nada en la cuenta cuando pudimos empezara intervenir y con sus escasos ingresos apenas se ha podido ahorrar dinero. ······· Proponen esperara a la paga extra del verano. Momento en que se valorará de nuevo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2024-02-29','miguel, tras recibir cita en AEAT, voy a la oficina de Mérida y me dan los procedimientos y cartas de pago en periodo voluntario, los dos procedimientos finalizados de 2019 y 2021, y Sara la jefa de Recaudación de AEAT 924-387720, me pide la llame mañana para me envíe lo que se encuentra en recaudación. Hablo con Alberto y se lo asigna a Lourdes. Quedo con Lourdes que escane todo y lo suba al expte. Mañana me hare con lo que se debe en recaudación (parte ejecutiva) Lourdes pregunta al banco y le permiten hacer los cargos con lo que hoy va a abonar el periodo voluntario y mañana el ejecutivo que yo le envíe','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2024-02-29','miguel, recibo email de Estefania: Buenos días Miguel, me han mandado esta documentación. Por una parte está la nota simple de la vivienda de Madrid, por otro lado, justificante de la cuota de 155 euros de los que se está haciendo cargo el inquilino y por otro el informe de tasación de la vivienda, pues parece ser que éste quiere comprarla. Las cuentas me las trajeron en papel, voy a ver si me las pueden pasar a excell. ******************************************************** Mi contestación: Gracias Estefanía, por favor agiliza todo porque he ido a AEAT y el importe de deuda es altísimo. Necesitamos se agilice la herencia y venta de inmueble para lograr ahorros para ella y por si llegan otras complementarias porque no hacia declaraciones IRPF...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2024-02-29','Ana: Llamada de la Dra. Sandra Gallego, Nefróloga del HSPA (56274), su compañera, por si fuera necesario, es la Dra. Silvia Glez. ··· Pilar padece enfermedad crónica renal avanzada. Su función renal está muy deteriorada, sólo al 13%. ··· Va a necesitar DIÁLISIS. ····· Posiblemente tendrán que ponerle un CATÉTER TUNELIZADO PARA HEMODIALISIS. ··························· *Nos enviarán informe médico. ····· Y por otra parte, acordamos que a través de Mamen, Ed. de Futuex, se le explicará en qué consiste el proceso e implicaciones, para que exprese su voluntad y en función de ambas cuestiones tomaremos decisión, tal y como dice la sentencia de incapacitación. ········ La doctora entiende que es necesario, pero dice que ella no lo puede decidir. ························ Si se decide realizar el tratamiento nos enviarán Consentimientos Informados. ································································································································································································ Correo de la Dra. Sandra, Nefróloga (sandra.gallego@salud-juntaex.es): "Te envío tras la conversación telefónica el informe médico de la paciente. Quedo a la espera de su aceptación de terapia renal sustitutiva (TRS) y si es así en un segundo tiempo enviaré los consentimientos de ello." ······················· Guardo en el expediente digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2024-02-29','Ana: llamada de Doroteo (609 928 621): dice que quiere solicitar traslado al CRR de Cáceres, pues quiere estar cerca de la familia. Le recuerdo que con su madre la relación no era buena y con su hermana no tiene mucho trato, aún no han ido a verle ni una vez. Viven en Monroy. Le indico que es muy pronto para pedir el traslado, sólo lleva 6 meses, además se ha adaptado muy bien al centro y a Plasencia y está muy estable. Po otra parte, se pueden organizar visitas a la familia de ida y vuelta en el día, porque dice que en casa de su hermana no se puede quedar a dormir. *Le parece buena opción. ···· De todos modos la semana que viene tiene cita con la T.O. y con la Psicóloga y abordará todas estas cuestiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2024-02-29','TERESA Gracias ...ya comunico que el Lunes 4 de Marzo tenemos cita en Ontológica Radioterapica del Hospital Universitario de Badajoz y el día 7 de Marzo en el Centro de Investigación Clínica también el Universitario ... Supongo la TAC llegara Rápido','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-02-29','Ana: Llamada de Mª Carmen, TS de la UHB - HSPA (56283): el Psiquiatra le ha dicho que tienen previsto darle el alta el martes o miércoles próximo. Francisco ha verbalizado que días previos al ingreso estaba en situación de calle, pero ahora quiere irse a un piso. *Le explico que dada su situación y el mercado inmobiliario de alquiler, en cuestión de días es más que complicado encontrar nada. Por su parte,d dada la PATOLOGÍA DUAL que presenta Fco (consumo) sólo podría plantearle COMUNIDAD TERAPÉUTICA pasando previamente por el protocolo del ECA. ················ No cumple ahora mismo perfil para otro RR. ······························································································································································································································ Llamo a Miriam, TS Cáritas (607 68 05 53): están llenos, no tienen ni una plaza libre ni previsión de que se vaya a ir nadie. ·············· Como última opción está el CES (Centro de Emergencia Social) donde podría acudir a pasar la noche y ducharse. Ubicado en el Ed. Valhondo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-02-29','Ana: tras nuevo requerimiento del Jdo. de Informes de Felisa, llamo al C. Salud de Navas del Madroño (927 37 52 82): la persona que me atiende dice que se lo dijo al MAP, Dr. Gregorio, pero éste le dijo que hasta que no le llegara por registro no lo haría. ···· Le recuerdo que lo remitimos previamente por registro a fecha de 26/06, tienen en el correo electrónico el JUSTIFICANTE del mismo. Y pueden consultar a la Gerencia de Salud si ha habido algún problema con la redistribución. ·················· Reenviará el correo al médico y consultará a la Gerencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-02-29','Ana: Respuesta de Lourdes, TS del SAD - IMAS (lourdes.perez@ayto-caceres.es): "vale pue reiniciamos el servicio" ········································································ Correo de EStrella Durán, TS CSS: "Te informo que ayer se fue de alta José Manuel Romero Mediavilla." ································································································································································································ INFORME DE ALTA EN UME - CSS PLAS: "...acude al centro acompañado por personal de la CTAJEX para ingreso en la UME por problemática social (vivienda en condiciones de no habitabilidad por siniestro en la comunidad), coordinado por SEPD y derivado por su psiquiatra de referencia (Dr. Molina) por el mismo motivo, a lo que se añade la solicitud del paciente de venir a esta Unidad y la necesidad de un abordaje rehabilitador. Exploración al Ingreso A su llegada a la unidad tranquilo y colaborador. Acepta y solicita le ingreso. Al día siguiente del ingreso se valora en la unida don epsiodio de inquiietud psicomotriz y alteración conductual, inestabilidad emocional, baja tolerancia a la frustración, rasgos de personalidad b. Conciencia de enfermedad parcial. Evolución y Comentarios Durante el ingreso se objetiva conducta mediada principalmente por rasgos desadaptativos de personalidad cluster B (límites y antisociales) y rigidez cognitiva en posible relación con capacidad intelectual límite. No ideas autolíticas ni pensamientos de muerte durante el ingreso. Se han realizado pases al domicilio de su hermano sin incidencias conocidas. Ayer la CTA nos comunicó que su vivienda ya está habitable y dado que el motivo del ingreso fue ese y que no objetivo signos de descompensación psicopatológia aguda en este momento, se procede al alta. Al alta no ideas auto ni heteroagresivas, no signos de descompensación afectiva ni psicótica mayor. Se compromete a toma de tratamiento y a acudir al esm."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-02-29','Ana: Correo de Lourdes, S. Ecca. desde el ctutelar@: "Para el lunes puede pasar a retirar los 150€ por su cumpleaños." ······································· Llamo a Ángel Félix (643 622 174) y se lo comunico. ······· Le pregunto por si hermana, que estuvo muy delicada en la UCI, y dice que ya está muy bien, mejoró muchísimo. ············································· Informo a Yessica, TS Cáritas, de la comprar del teléfono y el extra por el cumpleaños.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2024-02-28','Maite: Hemos tenido reunión con el CRR de Olivenza para hablar sobre la gestión del dinero de Ceferino. Los asistentes a esta reunión han sido: MAr y Melania( psicóloga y terapeuta del CRR), Ana y yo. Nos exponen que han comenzado a trabajar con Cefe el paso a una vida independiente. Han hecho un cálculo aproximado de sus gastos mensuales si alquilase una habitación en un piso ( 800€), para trabajar la gestión del dinero. Su propuesta de gasto está vinculada a la consecución de objetivos. Los acuerdos alcanzados han sido: - Va a disponer de una cantidad máxima de 1800 € para extras ( si hay publicación de libro no se tendrá en cuenta dentro de esta cantidad). - Las peticiones para esos extras se harán de forma trimestral. - El centro nos hará llegar esas demandas, habiéndolas flitrado previamente. - El centro llevará el control para que no exceda de la cantidad permitida de gasto anual. - Mensualmente, enviaremos un correo electrónico al CRR informando si Cefe contacta con la CTAEX para demandar dinero, ya que están trabajando con él la impulsividad. Les preguntamos por los objetivos marcados en su plan de intervención: - Trabajar la impulsividad, que no haga las demandas a varios profesionales. - Compromiso y asistencia a talleres y actividades . - Responsabilidad farmacológica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-02-27','Ana: Correo de Ana Castillo, TS Fundación Autismo Sur (teayudamos@autismosur.es): "Te comento. Estamos valorando la posibilidad de solicitar una cita médica privada con el neurólogo para Ale, ya que por la seguridad social perdimos una cita y ahora tendríamos que volver a esperar meses para conseguir una. Todo esto viene porque Ale está comenzando a tener conductas disruptivas, que le pueden ocasionar daños, y la psiquiatra nos comentó que tendría que valorar un neurólogo porque puede ser un signo de crisis epiléptica. Te lo comento también porque supongo que será necesario la autorización por parte de su tutora para poder acompañarlo al médico privado. Si puedes, confírmame y en cuanto tuviésemos la cita te pasaría la autorización para firmarla su tutora. Otro asunto que quería tratar contigo sería el tema de tramitar la nacionalidad de Ale, ya que, por ejemplo, al solicitarle el médico no nos pueden asignar un médico definitivo porque no tiene número de seguridad social, y hay que renovarlo cada año. Teniendo la nacionalidad los trámites serían menos complicados. Si te viene bien, esto lo podríamos hablar por teléfono." ··································································································································································································· Mi respuesta: "En relación a la cita médica privada de Neurología, nos tendríais que enviar primero un presupuesto de la misma para que el Jefe de sección económica, si ve que es viable, dé el ok. En principio no haría falta otra autorización si se autoriza el presupuesto en sí. Además ya estáis autorizados para acompañarle a cualquier consulta médica. En cuanto a la tramitación de la Nacionalidad Española, no habría ningún problema. Si ya reúne todos los requisitos se podría hacer. La documentación que tenga que firmar la representante legal nos la hacéis llegar"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-03-01','Ana: Llamada de Felisa (614 361 144) está desesperada con la situación con su hijo en casa. Dice que ya no puede más. Anoche se fue de fiesta y no llegó hasta las tantas. ······ Sigue consumiendo drogas además de tomarse las pastillas que le recetó el médico. Con algunas de la cuales también trapichea, le ha dicho que ha vendido algunas pastillas. ·············· Él no colabora nada en casa y ella está cansada de la situación, cada vez más insostenible. ···· Dice que ya no se cree que vaya a ingresar en ningún centro. ················ Le explico que se está haciendo todo lo posible para que ingrese en una Comunidad Terapéutica, de hecho hoy ha acudido a la cita en el ECA para el control de orina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2024-03-01','Ana: Subo al portafirmas digital la SOLICITUD DE REVISIÓN DE GRADO de dependencia por empeoramiento y solicitud de ampliación del centros a Plaza Pública de Mirabel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES MARIA'and edp.apellido1='ALVAREZ'and apellido2='CARRASCO'),'2024-03-01','miguel, enviamos por lexnet comunicación con solicitud de intervención al jzdo nº2 de Merida por posible delito por robo por la hermana Montserrat, extrayendo sin autorización continuamente dinero de la cuenta. Asi mismo se solicita que el juzgado dicte de oficio las medidas de apoyo que considere hasta que el INSS cambie la domiciliación de la pensión por orfandad','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2024-03-01','miguel, ayer se hicieron los abonos en periodo voluntario que figuran en la carpeta area económica /aeat/periodo voluntario. Hoy me envían desde la AEAT lo pendiente en periodo ejecutivo, y que abonará hoy Lourdes. Salvo la última carta de pago por un procedimiento sancionador por importe de 300,66€ porque la CSV me la ha dado mal y no me cogen ya el teléfono. Conforme a indicaciones de AEAT en 1 o 2 meses estarán listas las notificaciones por procedimientos sancionadores, así que más adelante habrá que pedir esas notificaciones','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2024-03-01','Ana: Llamo varias veces a Cristina Hdez, TS CSS (24185 // cristina.hernandezca@salud-juntaex.es) en relación al cobro de la plaza de Guadalupe (URH): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-03-01','Ana: a petición de Alberto, jefe secc.ecca., envío mail a la Asociación NACE (asociacionace@hotmail.com): "Tal y como me solicita el Jefe de la Sección Económica, me pongo en contacto con vosotros para comunicar una serie de cuestiones relativas a la situación económica de Dª. SOLEDAD ESTEBAN IGLESIAS, residente en vuestro recurso y cuyo cargo ostenta la CTAEx. - LA EVOLUCIÓN DE SU SALDO EN CUENTA ES NEGATIVA - Como sabéis: o sus únicos ingresos corresponde a una Prestación Familiar por Hijo a Cargo, cuya cuantía para este 2024 asciende a 470,60 €/MES x 12 pagas o Abona LA PLAZA RESIDENCIAL o El REINTEGRO para sus gastos de bolsillo SE LE SUBIO EN 2023 A 80 €/MES. o Abona un SEGURO DE DECESOS o Se aprueban distintos EXTRAS solicitados cada año en distintos conceptos Hasta ahí , todo asumible. El problema, según me transmite, son LOS GASTOS ASOCIADOS A LA ESTANCIA CENTRO QUE NOS HACÉIS LLEGAR A PRINCIPIO DE CADA AÑO RELATIVOS SIEMPRE AL AÑO ANTERIOR. Éstos, al no estar presupuestados previamente, no se pueden tener en cuenta en el cálculo anual y han supuesto, durante estos dos últimos años consecutivos (2022 y 2023) un gasto total por encima de sus posibilidades, pues ha gastado más de lo que ingresa, lo que conlleva, no sólo que no se le haya podido ahorra un poco para posibles vicisitudes futuras, sino que hayan mermado sus ahorros. Por ello, me piden que os SOLICITE, que tratéis de ajustar y disminuir esos gastos anuales, pues no puede seguir asumiéndolos. De no ser así, habría que tomar otras medidas como reducir las solicitudes de gatos estraordinarios. Agradecemos vuestra comprensión y colaboración."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='RODERO'and apellido2='COMERON'),'2024-03-01','email de la parte económica, Alberto: SITUACIÓN ECO INICIAL: MUY, MUY MALA...SIN SALDO, IMPAGOS CENTRO (HOY APROX. UNA DEUDA DE 7.500 €), EMBARGOS CONTINUADOS (PENDIENTES DE ESTUDIAR PERO QUE PODRÍAN ESTAR RELACIONADOS CON EL IMPAGO DEL CENTRO (CAMF ALCUESCAR QUE ES ESTATAL), 2 PRESTAMOS UNICAJA (PTE DE SABER SITUACIÓN)....LO ÚNICO QUE PARECE QUE ABONA REGULARMENTE ES LA PENSIÓN ALIMENTICIA HIJO (PENDIENTE DE QUE LO VEAIS LOS JURÍDICOS (MÁS ABAJO) ++++ POSIBLES INGRESOS INDEMNIZACIÓN X ATROPELLO: PTE DE QUE LO VEA ÁREA JURÍDICA. MARIA: URGENTE: AUNQUE NO SE SI AÚN HABRÁN BASTANTEADO, LA COMUNICACIÓN Y PETICIÓN INFORMACIÓN LA HACEMOS: • AUTORIZACIÓN GENERAL A CENTRO: LO HABLAS CON ELLOS...PERO TIENES QUE DEJARLES CLARO QUE, HASTA QUE NO CONTROLEMOS LAS CUENTAS Y NOS QUITEMOS DE ENCIMA LAS DEUDAS MÁS IMPORTANTES (INCLUIDA DE QUE TENEMOS CON ELLOS (7.652,24 €), NO DEBEN DE ASUMIR NINGÚN GASTO QUE INTERFIERA EN ESA REGULARIZACIÓN (AL MENOS SIN CONSULTARLO PREVIAMENTE CON NOSOTROS). • REINTEGRO PERMANENTE X 40 €/MES.....ACOMPAÑAMIENTO????? (LO VES CON CENTRO) • CANCELACIÓN INMEDIATA DE TODAS LAS TARJETAS/LIBRETAS/OTROS QUE PERMITAN PAGAR O EXTRAER DINERO...EN 1 AÑO HA PAGADO X CONCEPTOS RELACIONADOS CON TARJETAS 1.310 € APROX. o IMPORTANTE: TENGO LA IMPRESIÓN DE QUE TIENE TARJETAS O SIMILARES CON PAGOS APLAZADOS O QUE FINANCIAN COMPRAS QUE TUTELADO HA HECHO. o OBJETIVO: CANCELACIÓN...PERO, EN CASO DE QUE NO PODAMOS CANCELAR X DEUDAS HAY QUE CONSEGUIR QUE ESAS TARJETAS/OTROS, DEJEN DE SER OPERATIVAS, HASTA QUE PODAMOS SALDAR ESA DEUDA Y CANCELARLAS DE FORMA EFECTIVA. • PRESTAMOS: 2 PRESTAMOS QUE LLEVAN EL MISMO Nº EN LOS MOVIMIENTOS BANCARIOS (2103 7705 0500012204 ....IMAGINO QUE LOS Nº ESTARÁN INCOMPLETOS). IMPORTES APROX:  45,60 €/MES APROX.  35 €/MES  IMPORTANTE: DESDE 25/10/2023 NO HAN VUELTO A PASAR LOS PRÉSTAMOS UNICAJA: O HA TERMINADO DE PAGARLOS....O LO MAS PROBABLE ES QUE ESTÉ GENERANDO DEUDA X IMPAGO: OBTENER INFORMACIÓN/DOCUMENTACIÓN DE LOS PRÉSTAMOS (FECHA FORMALIZACIÓN, IMPORTE INICIAL, IMPORTE PENDIENTE HOY, POSIBLES DEUDAS...) LOURDES: EN LA FECHA PUEDES VER LOS EMBARGOS DE LA TGSS QUE LE HAN CARGADO DURANTE LOS ÚLTIMOS 12 MESES (TB EN EL PDF QUE TENEMOS): HABLAS CON TGSS Y QUE NOS ACTUALICEN SITUACIÓN: DEUDAS PENDIENTES Y COMO PODRÍAMOS AMORTIZARLAS...OJO: QUIZÁS EL CENTRO TE PUEDA INDICAR UN POQUITO (CREO QUE ESTOS EMBARGOS DERIVAN DE LOS IMPAGOS DEL CENTRO X PARTE DEL TUTELADO) AREA JURÍDICA: QUIZÁS YA OS LO REMITIÓ ANA:...VIENE EN EL INFORME SOCIAL...LO HABLAMOS CUANDO QUERAIS. ÁREA JURÍDICA: HAY ALGÚN PROBLEMA CON ESTO???...TENÉIS IDEA DE QUIEN PAGA LO QUE SE HAGA CUANDO ESTA PERSONA FALLEZCA???:...ME REFIERO A DONAR CUERPO A LA CIENCIA...IMPLICACIONES: SI SU MUERTE NO TIENE COSTE, NO HACEMOS SEGURO DECESO Y NOS AHORRAMOS UN GASTO. ESTRELLA: DEPENDIENDO DE A QUE CONCLUSIONES LLEGUEMOS DEBEREMOS O NO FORMALIZAR SEGURO DECESO: CENTRO INDICA: SEGURO DECESO BAJA X IMPAGO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='RODERO'and apellido2='COMERON'),'2024-03-01','email de Alberto: MUY IMPORTANTE: ANGEL/MIGUEL/MARIA: SEGUN INFORME FISCAL NO TIENE PROPIEDADES...SIN EMBARGO SI TIENE PRÉSTAMO HIPOTECARIO SI LOS 2 PRESTAMOS DEL CORREO INICIAL SE RELACIONAN CON ESTE (QUE SEPAREN CAPITAL DE INTERESES), TENEMOS UN MUY GRAVE PROBLEMA, PK NO VEO PAGOS DE ESE PRESTAMO DESDE OCTUBRE DE 2023 (YA SON 4 MESES). MARIA: ES MUY URGENTE VER ESTA INFORMACIÓN CON UNICAJA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-03-01','miguel, seguimos pendientes que Futuex le envíe informe social, y que el médico del centro de salud emita el certificado requerido varias veces por el juzgado (según le dice a Ana no ha recibido la petición) En su día pedí informe al SERVICIO DE ATENCIÓN A FAMILIAS, me dijeron que no lo iban a hacer. Dada la respuesta se lo pedí también al Programa de Apoyo comunitario de FUTUEX, y me consta que ayer Maite se lo recordó a Toni, Coodinadora. En cuanto al informe de salud, ayer llamé al centro de salud para reiterar la petición. Al parecer no han recibido el que se pidió por REGISTRO, pues se envía a la Gerencia de salud desde donde los distribuyen (no tiene buzón propio). Y el Médico dijo que hasta que no llegaba por registro no lo iba a hacer. *Le recordé que cuando se lo pedí por correo envié adjunto el oficio y el JUSTIFICANTE DEL REGISTRO. Le lo iba a volver a reenviar al médico…. Y hasta ahí puedo leer…','2');
