insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-02-29','ANA: Correo de Lourdes al CRR-Pla (administracion.crrplasencia@grupo5.net): "Buenos días, para el lunes día 4 de marzo, podrán realizar retirar los siguientes extras: • REINTEGRO PERMANENTE 300 €/MES . • REINTEGRO PUNTUAL 150 € "GASTOS CENTRO". • REINEGRO ANUAL: OK A LOS 900 € QUE PROPONE EL CENTRO."','2');
