insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='RODERO'and apellido2='COMERON'),'2024-03-01','miguel, email de Ana: Os envío los documentos que aporta la TS del CAMF de Alcuéscar. De las cuestiones económicas ya he informado a Alberto. De la página 77 hasta el final, tenéis una Solicitud de inscripción del documento de EXPRESIÓN ANTICIPADA DE VOLUTADES, yo no he detenido en leer esa parte, he tenido bastante con las otras 70 páginas… ---------------------------------------------------------- ANA: IMPORTANTE: HEMOS VISTO QUE EN LA PENSIÓN LE RETIENEN 200 €/MES (EN REALIDAD DEBERÍA COBRAR 1.009,75 €/MES X 14)...HAY QUE VERLO EN EL CERTIFICADO DE LA TGSSOCIAL (DOC.2) ANA: HABLAS CON LA TESORERÍA Y COMPRUEBAS MOTIVO RETENCIÓN Y HASTA CUANDO SE APLICA. ANA/ÁREA JURÍDICA: TENEIS LA SENTENCIA DE DIVORCIO (DOC.4) Y OTRA X IMPAGO CANTIDADES RELACIONADAS CON EL MISMO X EL TUTELADO (DOC.5), PARA QUE LE ECHÉIS UN VISTAZO','2');
