insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2024-03-01','miguel, email de Estefania (abogada) Buenas tardes Miguel, te envío, como quedamos, el cuadro excell, a ver si con ese dinero se puede abonar el IRPF. Ya hablamos como podemos proceder.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2024-03-04','miguel, envio email a Estefanía: Buenos días Estefanía si todos esos gastos quedan acreditados en facturas, se incorporaran en la escritura de adjudicación de herencia y deberán ser compensados en dicha escritura de herencia. Si te parece hablamos esta semana para poner inmediatamente en marcha la remisión de documentación a la notaria de Herrera del Duque para que preparen la firma de la adjudicación de herencia. Los gastos que conlleve en adelante todo el procedimiento herencia y ventas deberán ser abonados por la masa hereditaria, pues esta mujer ya no dispone casi de ahorros después de pagar las multas de hacienda.','2');
