insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2024-03-04','TERESA, EMAIL DE MERCEDES TS HOSPITAL DE ZAFRA Tal y como acordamos en conversación telefónica y justificando por tu parte, que ya tenía plaza de carácter privado, en la Residencia de Mayores Sierra Pinar, la paciente regresó a dicho centro tras el alta hospitalaria. Eso sí, se solicitó plaza sociosanitaria tipo T3, también cordado en la conversación a la que me refiero.','2');
