insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='ESTEBAN'and apellido2='CORRAL'),'2024-03-04','miguel, email de Alberto: 2024/03/04: SITUACIÓN ACTUAL - PARECE QUE SE ESTÁ TRAMITANDO LA HERENCIA ---SI HAY ALGÚN INCONVENIENTE LO VEMOS: CCC ES90 2085 4586 2703 3036 6701 (CON OTROS TITULARES INCLUIDO SU PADRE (FALLECIDO - HERENCIA): EN ESTA CCC, SI NO INDICAIS LO CONTRARIO: • MANTENEMOS TRANSFERENCIA PERMANENTE A PLENA INCLUSION PUEBLA DE ALCOCER X 509,93 €/MES: CENTRO TUTELADO (SE ABONA AL MENOS DESDE 2020 Y CONTINUA). • MANTENEMOS TRANSFERENCIA PERMANENTE A PLENA INCLUSION PUEBLA DE ALCOCER X 50€/MES: GASTOS CENTRO TUTELADO (SE ABONA AL MENOS DESDE 2020 Y CONTINUA). • LO INDICO PK, EN TEORÍA, ESTA CCC EN LA QUE HAY VARIOS TUTELADOS (TUTELADO + ESTEBAN BONILLA, PABLO (PADRE FALLECIDO) Y ESTEBAN HERRERA, MARIANO (SOBRINO TUTELADO)):  IMAGINO QUE ESTARÁ SUJETA A LA HERENCIA QUE SE TRAMITE.  YA NO TIENE INGRESOS...NO PENSIÓN PADRE FALLECIDO + NO PRXHCARGO TUTELADO X PASARSELA A UNA CCC EN LA QUE ESTÁ SOLO.  TIENE GASTOS RELACIONADOS CON: o IMPUESTOS VIVIENDAS. o CONSUMOS. o LAS 2 TRANSFERENCIAS QUE INDICO AL PRINCIPIO (CENTRO Y GASTOS TUTELADO) QUE SE VIENEN HACIENDO HISTÓRICAMENTE. ACTUACIONES: • MIGUEL: VAS A COMENZAR A TRAMITAR/GESTIONAR EL TEMA DE HERENCIA? • MIGUEL: SÓLO INFORMO: A PARTE DE ESTA CCC....SE ESTÁN PAGANDO MUCHOS RECIBOS DE OAR...IMAGINO QUE ESO TAMBIÉN TENDRÁ QUE ENTRAR EN LA HERENCIA • ECO VA A MANTENER LA SITUACIÓN QUE INDICO SALVO QUE ME DIGAIS ALGUNA COSA EN CONTRA....Y SI LUEGO RECLAMAN ALGO DE EFECTIVO DE LA HERENCIA, ECHÁMOS CUENTAS...ME DECÍS. --------------------------------------------------------- contestación de Tere: Yo le voy a solicitar orfandad pero estoy a la espera me facilite la trabajadora social la documentación que necesito para tramitarla ------------------------------------------------------- miguel, contesto: Buenos días, a día de hoy no he comenzado a trabajar con la herencia, pues tal como indiqué en emails anteriores, Elvira, Pilar (que indicó Tere) no me ha remitido documentación alguna para poder empezar a trabajar…Tere está al tanto de este asunto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2024-03-04','TERESA Buenas de nuevo, a continuación te actualizo información recogida sobre Angela Rodriguez Figueredo: En el transcurso de la mañana, del lunes 26 de febrero de 2024 se recibió llamada de la trabajadora social del SSB del Ayuntamiento de Villanueva del Fresno (María Chaves), para comunicar la siguiente información: Ángela comunica que ha recibido llamada de Emilia, trabajadora social del centro de salud de Villanueva del Fresno, para decirle que, el próximo martes 5 de marzo tiene que incorporarse a su plaza residencial en Jerez de los Caballeros a las 11.00 horas. Es la misma información que nos cuenta a nosotros en la llamada realizada. Se recibe después otra llamada desde el centro de salud para informarnos que, Ángela tenía cita a las 12:00 con Natividad, su médico de atención primaria, ya que Ángela presentaba hoy tensión arterial muy baja y exponiendo que no se encontraba bien. Por decisión de su médico se la deriva en ambulancia a urgencias del hospital Perpetuo Socorro de Badajoz y puesto que es una paciente que presenta síndrome depresivo y alteración conductual, se nos pide, desde centro de salud, la posibilidad de localizar a las trabajadoras sociales del hospital para informarles de la situación, ya que su auxiliar Quini nos ha comentado que ella no puede acompañarla. Desde el servicio de urgencias, valoraron que Ángela no presentaba nada orgánico que requiera ingreso, y se recomendaba fuera valorada por su psiquiatra. Ayer jueves 29 de febrero, se recibe otra vez llamada de Quini, auxiliar de ayuda a domicilio, de manera privada, que tiene Ángela Rodríguez Figueredo, para confirmar que ella NO PUEDE ACOMPAÑAR A Ángela en la entrevista que tiene planificada el MARTES 5 DE MARZO A LAS 11.30 HORAS EN LA RESIDENCIA HERNANDO DE SOTO de Jerez de los Caballeros. Una vez se le realice la valoración, ya se le indicará el día de ingreso, Ángela está con el nº 5 en lista de espera. Se ha logrado contactar con su psiquiatra Dr. Samino que, se ha puesto en comunicación con su médico de atención primaria para modificar la pauta de psiquiatría y poder tranquilizar a Ángela, ante la situación de llamadas constantes al centro de salud, demandado atención. Ella piensa que este martes es ya para ingresar, y cuando se le ha expuesto que solo es entrevista, de inicio se niega a acudir, repite que quiere ya ingresar. Hemos hablado de nuevo con ella, también desde los servicios sociales, para tranquilizarla y comunicarle que irá acompañada. Desde el programa, prodiamos gestionar un taxi e ir con ella, ya que si la cuidadora no quiere, no se nos ocurre otro modo... LE ACOMPAÑA LUZ MARIA 685507495,CONTACTO GESTIONADO A TRAVES DE EMILIA TS DEL CENTRO DE SALUD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2024-03-04','LOURDES: TRANSFERENCIA PERMANENTE CCC PECUNIO: OK A 350 €/MES (ANTERIOR 250 €/MES). EL GASTO REAL ANTES DE ESTA SUBIDA NO ERA 250 €/MES, SI NO 300 €/MES SI INCLUIMOS EXTRAS...ENTENDEMOS QUE CON LA SUBIDA LOS EXTRAS BAJARAN. TRANSFERENCIA PUNTUAL ZAPATILLAS A HERMANO TUTELADO: 50 €---OK.','2');
