insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-03-04','miguel, tras hablar con el hno de José Manuel, José Luis, envío email a la parte económica y social: Buenos días, acabo de hablar con el hermano de José Manuel Romero Mediavilla, José Luis 687581061, me confirma que la vivienda que habita José Manuel es propiedad de los 7 hermanos (dos están fallecidos y con hijos). Tras los daños el año pasado y éste al vecino por goteras, me dice que tras hacerles levantar el baño el año pasado, las goteras finalmente fueron del vecino. Alberto: se supone que desde el año pasado pidieron tener un seguro de la vivienda, según me dice José Luis. Es necesario hacer un seguro a la vivienda lo antes posible. Por lo que me comenta José Luis (hno), el vecino está intentando sacar tajada pidiendo otros daños: móvil, meses de alquiler que está perdiendo, etc. Me ha dicho que debido a la urgente situación él ha abonado los 400€ de arreglo del albañil, pero quedaría pintar, arreglar el plato de ducha (que si bien ha sufrido daños, el albañil le ha confirmado que hacía años que no se usaba), también habría que pagarle la alcachofa y la tapa del váter. Me insistía en hablar con el vecino, el perito, etc, y le he dicho que no hablaremos con nadie, lo que quieran nos envíen un informe de daños y lo estudiaremos (bien a través de él o bien directamente), paralelamente él irá pidiendo y enviándonos presupuesto de arreglo de la mampara y taza de váter. Le he explicado que no paguen nada sin enviar siempre el presupuesto y se les autorice a arreglarlo por adelantado. Así mismo, le he dicho que los gastos extraordinarios son comunes a todos los hermanos y por tanto no tiene que asumirlos en su totalidad José Manuel, pero me dice que a cambio de no cobrar nada a José Manuel de alquiler y al estar el resto de los hermanos pelados de dinero, quedaron en que José Manuel asumiera los gastos del piso...esta cuestión no sé si está analizada por la parte social y la económica. En conclusión: quedamos a la espera de informe del perito del vecino, presupuesto de arreglos del baño por el hno de José Manuel y parte económica haced un seguro de la vivienda para el futuro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2024-03-04','miguel, llega citación 11-3-24 para procedimiento de división de herencia procedimiento 22/23 del jzdo nº1 de Coria. Pido a Inés pida videoconferencia y abogado de oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2024-03-04','miguel, recibo llamada de Lola (ex de Ctaex y actual terapeuta 85704)me dice que Manuel va continuamente al juzgado nº2 de Coria y que ha hablado con compañero de la que lleva el procedimiento de Revisión de Medidas. Le explico que a fecha de hoy nadie nos ha mandado nada del procedimiento y me dice que el jzdo le dice que ha dado la guarda a los padres y parece ser que a la Ctaex y a la abogacía no han notificado nada. Le explico que si habla con el juzgado les explique que tienen que comunicar el procedimiento a abogacía que nos representa procesalmente, y que a día de hoy no se han puesto en contacto ni con ctaex ni con abogacía q sepamos. Manuel tendrá que esperar q nos envíen la firmeza de la sentencia y si hubiera remoción la parte económica lo comunicaría como en otras ocasiones al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-03-04','miguel, email de Alberto MIGUEL: DEUDA COMUNIDAD PROPIETARIOX X IMPORTE SUPERIOR A 12.000 €...YA SE QUE ESTÁS CON ESTO...PERO TODAVÍA NO TENEMOS QUE HACER NADA, VERDAD??? --------------------------------------------------------- contesto:Hola Alberto, a día de hoy el juzgado no se ha puesto en contacto con nosotros para esta reclamación de 12.000€ por la Cdad de Vecino. En el momento que llegue la sentencia, si llega la estudiaremos, por lo que aquí no vamos a hacer nada, pues es deuda de la masa hereditaria (de los padres entiendo) En cuanto a la tramitación de la herencia, ya os contesté a la parte social y económica el 5-2-24 y 26-2-24: te recuerdo…el trámite de la herencia lo hemos encargado a Asesoría Menaya y para ello, el contacto, la trabajadora Social Sandra Sánchez debe enviar la documentación a dichas asesoría, que a fecha de hoy no ha hecho, por que le dije nos pusiera en copia en todo. La última comunicación de Sandra es de 26-2-24: “La tramitación de la documentación está siendo complicada adquirirla, pues nuestra Entidad no tenía contacto con la familia del curatelado. Por una parte, estamos intentando poder entrar en la casa, por si hubiera documentación dentro. Nos está costando pues cuando hemos ido con las llaves del usuario, se había cambiado una de las cerraduras. Solicitamos a comisión tutelar el dinero para cambiar dicha cerradura pero cuando volvimos, parecía que había sido manipulada otra de las cerraduras, por lo que tampoco pudimos entrar. Estamos esperando presupuestos de las cerrajerías para solicitar el dinero correspondiente a comisión. Por otro lado, conseguimos ponernos en contacto con Dori, la tía de José María y una de las herederas. Comenta que no tiene ningún tipo de documentación y que no quiere saber nada de este proceso. Sin embargo, indica que se acercará a la notaría que llevó el caso de las fallecidas y la herencia y que nos informará al respecto. La semana pasada me volví a poner en contacto con ella pero no había ido todavía. Además, nos facilitó el teléfono de Lolo, hermano de José María y otro de los herederos. Parece ser que este chico tiene en su poder las escrituras de la casa y otros documentos de valor, pero nunca ha querido facilitarlos a la familia. Teresa de Futuex quedó en llamarle pero por diversas circunstancias no ha podido. Por último, el propio usuario trabaja y tiene horarios muy cambiantes, por lo que también se hace complicado poder quedar con él para acudir a diferentes administraciones a preguntar”','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-03-04','Ana: Llamada de Mª Carmen, TS de la UHB - HSPA (56283): Ya le han dado el alta a Francisco. ······ El CRR no se le propuso porque con consumo no puede ingresar en el mismo. No obstante él manifestó no querer ir a ningún recurso residencial. *La Comunidad Terapéutica sí se la plantearon e insistió en que no quiere ir a ningún centro. Sólo quería piso de alquiler. ············· Solicito me envíen Informe de Alta, se lo dirá al Psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-03-04','Ana: Envío correo a Alberto y Maite: "He recibido llamada de JOSÉ MANUEL ROMERO MEDIAVILLA, dice que esta mañana ha acudido al banco, ha pedido 800€ y se los han dado. Que había pensado en comprarse un aire acondicionado, pero que finalmente se ha comprado una TV de 50 pulgadas. Entiendo que habrá que dar un toque al banco y que desde la sección económica se tomará alguna otra medida. No obstante, se me ocurre que estos hechos se pueden poner también en conocimiento del Juzgado. No sólo por lo difícil que resulta ejercer el cargo, sino por las continuos incidentes que nos surgen con él. No sé qué os parece." ··············································································· Nueva llamada de José Manuel. Lo ha pensado mejor, y puesto que ya tiene TV, ha ido a Electrocash y ha solicitado el cambio de la TV (que estaba encargada y pagada) por un AIRE ACONDICIONADO que le va a venir mejor para el verano. ································································································································································································· Correo de Alberto, Jefe S. Ecca: "LOURDES: SE MODIFICA REINTEGRO PERMANENTE QUE PASA A SER DE 200 €/MES DURANTE, EN PRINCIPIO 8 MESES...NO RECUPERARÁ SU REINEGRO HABITUAL HASTA NOVIEMBRE DE 2024. ANA/LOURDES: TAMPOCO DISPONDRÁ DE REINTEGROS EXTRAS EXCEPTO AQUELLO QUE TENGA QUE VER CON ASPECTOS SANITARIOS----LOURDES: XFA, HAZ EXTENSIVO ESTO A COMPAÑERAS ECO. ANA: SI ES POSIBLE, QUE DEVUELVA LA TV...EN ESE MOMENTO REVISAREMOS ESTA SITUACIÓN. LOURDES: MUY URGENTE. HAY QUE PONERSE EN CONTACTO CON LA OFICINA 3283 (QUE ES DONDE HA EFECTUADO EL REINTEGRO) Y, SI NO HAY RESPUESTA, CON LA HABITUAL DEL TUTELADO, PARA QUE NOS DEN UNA EXPLICACIÓN DE LO OCURRIDO..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NICOLAS'and edp.apellido1='SANCHEZ'and apellido2='AREVALO DONOSO'),'2024-03-04','Ana: Pongo a la firma de la D-Gerente la DECLARACIÓN ANUAL DE PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2024-03-04','Mª Rosa Serrano, NUEVA : curatela en el ámbito de la salud, en el ámbito económico-jurídico-administrativo y contractuales para actos complejos relacionados con el ART. 287 . Para controlar su pensión que este año es de 900€ no necesitaría autorización, en cuanto sea firme deberíamos revisarlo . El problema es que tiene deudas con otros bancos y habrá siempre que ahorrarle para esos pagos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2024-03-04','AMALIA : Manuela saca 600€ todos los meses , no tiene la cuenta bloquead, de momento es permanente .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2024-03-04','Ana: Envío correo a Toni (areasocial3@futuex.es) y Mamen, Ed. (delegadapoyo.caceres@futuex.es) Futuex: "Tras valorarlo hoy con Maite y hablar el jueves pasado con la Dra. Sandra Gallego, Nefróloga de Mª PILAR GARCÍA MORENO, os remito el Informe de la Consulta con la intención de que Mamen pueda hablarlo con Pilar con calma y volver a explicarle, de modo que Pilar lo entienda, en qué consistiría la Hemodiálisis, los días que aproximadamente tendría que acudir en ambulancia a recibir el tratamiento, el tiempo que pasaría allí cada vez que acudiera (la información aparece en el informe)… es duro, pero en principio sería la mejor opción para alargar su esperanza de vida. La Dra. entiende que es la mejor alternativa, pero, evidentemente dice que ella no puede decidir ni influir en la decisión que tomen. Puesto que, además de lo dispuesto en la Ley 8/21, de 2 de junio sobre los deseos y preferencias de las personas con medidas de apoyo, el fallo de la sentencia de “Incapacitación” de Pilar (pendiente de revisar aún) dice literalmente que “deberá ser escuchada por su tutor, que tendrá en cuenta su opinión salvo que sea claramente contraria a su persona o a sus bienes”, lo que queremos es que tras explicárselo Mamen le dé la oportunidad de expresar su voluntad con respecto a someterse o no al tratamiento de Hemodiálisis y que nos trasladéis la misma para comunicarlo a la Nefróloga y, en su caso, firmar los Consentimientos Informados correspondientes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-03-04','Amalia : escribo a Alberto : Este señor ha pasado del CSS de Mérida a CRR Plasencia . Enviaste este email con unas aclaraciones que necesitabas antes de autorizar el pto. anual que solicitaban . Yo envié al centro esas preguntas , junto con el presupuesto mensual ,que hasta la fecha no me han remitido . Hablé con la T. Ocupacional que indicó que necesitaba más tiempo para ver qué necesidades tendría Antonio allí. He vuelto a hablar con ella hoy , y me indica que el presupuesto mensual se ha establecido en 300€/ mes y el extra anual en 900€/ mes. Al parecer ha tenido problemas con su correo , cree que ha escrito / hablado con Lourdes y ya ha podido sacar tanto el pto. mensual como el anual . Pero te lo especifico para que lo tengas en cuenta . El tema del contrato telefónico he solicitado que de mantenerlo si lo ven necesario , tendrán que pasar a un contrato de 20€ al mes con llamadas ilimitadas. El caso pasa ya a Ana para seguimiento . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-03-04','Amalia : Escribo a Ana : Te reenvío a tí también el email que acabo de poner a Alberto . He hablado hoy con la T.O . , Paula. Queda cerrado el tema del presupuesto y el de telefonía . Lo derivo ya a tu zona para seguimiento . Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2024-03-04','Ana: correo de Lourdes a Placeat: " Buenas tardes, se autoriza transferencia con carácter puntual, por importe de 50€ para gastos de bolsillo de Juan Jose-."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2024-03-04','-Amalia : llega su tarjeta acreditativa del Gº discapacidad con un 65%, la pongo para archivar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-03-05','Ana: Envío correo a Carolina, Directora CRR (direccion.crrplasencia@grupo5.net), Paula, TO (tocupacional.crrplasencia@grupo5.net) y Beatriz, Psicóloga (psicologia.crrplasencia@grupo5.net): "Os traslado solicitud que realizan desde la sección jurídica de la CTAEX, que a su vez solicitan desde Abogacía General de la Junta (Escalona es Letrado y es uno de los que acude a los procedimientos) “…en relación a la revisión de medidas de apoyo 1505/2024 que está conociendo el jzdo de 1º instancia e instrucción nº5 de Plasencia, referido al tutelada Maria de los Ángeles Santos Urbano, adjunto solicitud que nos hace Escalona de informe, en los siguientes términos: Informe sobre la situación actual de Dña. Maria de los Ángeles en cuanto a: - Discapacidad que presenta - Ámbitos y extensión que resulten afectados por su discapacidad y necesidad de apoyo - Cualquier consideración que estimen conveniente sobre ella en razón al procedimiento judicial de revisión de medidas de apoyo” Agradeceríamos nos lo hicieseis llegar a la mayor brevedad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-03-05','Ana: Llamada de José Manuel, tiene cita el día 13 a las 15 h. para hacerse una COLONOSCOPIA. Dice que le da cosa hacérsela. Le explico y argumento lo importante y necesaria que es la prueba para que puedan hacer un diagnóstico y, si fuera necesario poner un tratamiento. *Hace 2 años no acudió a la cita para hacérsela. ····· Él mismo reconoce que, tanto su hermana melliza como otro hermano, fallecieron de cáncer de colon. *La Ed. de Futuex le ha dicho que aunque sea a esa hora le acompañará. ····················································· En cuanto al dinero, le informo de la decisión que ha tomado el Jefe de la S. Ecca. de reducirle la asignación mensual a 200€ durante 8 meses, hasta compensar los 800€ que retiró ayer sin autorización. ··········· Ayer ya abonó el aire acondicionado que ha encargado en Electrocash.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-03-05','Ana: Escribo a Paula, TO, Beatriz, Psicóloga y Carolina, Directora del CRR: "os reenvío directamente el correo que me ha remitido Alberto, jefe de la secc. económica, para que estéis al corriente de cómo se va a proceder y podáis explicárselo también a Antonio." ·················· Correo de Alberto: "YA ESTÁ HECHO EL REINTEGRO MENSUAL X 300 €/MES + EL EXTRA ANUAL X 900 € TAMBIÉN ESTÁ. ADVERTENCIA: CENTRO ENTENDÍA QUE ES MEJOR EL CONTRATO CON LÍMITE DE 20 €/MES...YA SABES QUE NO ES EL CRITERIO ADECUADO X GENERAL UN CONTROL QUE NO SE PUEDE REALIZAR...EN ECO SE VA A ACTUAR ASÍ (YA SE LO COMENTÉ A AMALIA Y ENTIENDO QUE ELLA SE LO TRASLADÓ AL CENTRO): • LOURDES:  COMPROBARA CADA 2 MESES LAS FACTURAS DE TELEFONO.  SI APARECE CUALQUIER FACTURA QUE SUPERE LOS 20 € SERÁ DEVUELTA DE INMEDIATO SIN NINGÚN TIPO DE AVISO.  SI EL CENTRO ENTIENDE QUE TIENE QUE FUNCIONAR CON CONTRATO, QUE LO CONTROLE." ··································································································································································································· Respuesta de Paula: "Tras la conversación con Amalia remití al equipo de educadores indicaciones para abordar con él la cuestión acerca del origen del teléfono y sobre todo de la necesidad de buscar un contrato que limite el gasto a 20 euros mensuales. La intervención desde el CRR consistiría en un proceso en el cual facilitáramos los apoyos para la toma de conciencia del gasto y apoyar, si va resultando factible, una toma de decisiones ajustada a sus posibilidades. Hoy he hablado con él y estaría de acuerdo en pasar de contrato a tarjeta, no identificando los motivos por los que puede estar gastando más dinero (pensaba que estaba gastando 10 euros al mes). Desde el CRR no hay ningún interés especial en mantener el contrato, entendíamos que a veces resulta cómodo para la persona, pero no queremos que se convierta en un problema, y por vuestro correo estáis de acuerdo y preferís esta opción, así que orientaremos, con el beneplácito de todas las partes, para que se realice el cambio a tarjeta cuanto antes . Por la información transmitida por Amalia, trataremos de apoyarle e intervenir con Antonio en la línea de "darse cuenta" y discriminar un buen uso del teléfono frente a un mal uso y facilitar que pueda tomar cierta responsabilidad en el manejo del mismo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2024-03-05','TERESA REGISTRO SOLICITUD INGRESO EN RESIDENCIA VIA DECRETO PARA FUENTE ATENOR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='RODERO'and apellido2='COMERON'),'2024-03-05','Ana: Tras llamar a la Seg.Soc., envío correo a A. Jurídicos y a Alberto, Jefe S. Ecca.: "En el informe social, de la TS del CAMF, dice que, en relación al accidente, ya han solicitado ABOGADO DE OFICIO (pág. 3 + Doc. 3 que aporta). Por otra parte, acabo de llamar a Control de Pensiones de la Seg. Soc., me dicen que la DEDUCCIÓN de su pensión es una retención judicial por ALIMENTOS, solicita por el Jdo. de 1ª Instancia nº 8 de Salamanca (TFM85). Es todo lo que me pueden decir."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2024-03-05','miguel, envio email a Rosa la abogada, ROSA MARIA MUÑOZ BERNALDEZ >2913@icaba.com> Buenos días Rosa, el viernes me llamaron desde el juzgado para que la comisión prestara su conformidad al acuerdo al que quería llegar el tutelado. Quedó el que me llamó que me enviaría toda la documentación del procedimiento para que preparamos un documento firmado por la representante de la Comisión, la actual Gerente del SEPAD. A día de hoy dicho juzgado no nos ha remitido nada, lo digo porque si nos citan no podemos dar el visto bueno a un procedimiento que desconocemos. Lógicamente lo único que podemos es ratificar la conformidad a la que voluntariamente quiera llegar el tutelado, ya que si éste se opusiera nosotros no iremos en contra de su voluntad. *************************************************** Contestación de Rosa: Buenos días Miguel: El tutelado finalmente no quiso reconocer los hechos y llegar a un acuerdo, así que nos citarán del Juzgado para el juicio, que de momento no se ha señalado. Entiendo que a vosotros también os citarán el día del juicio, de todas formas cuando tenga fecha de señalamiento, os la hago llegar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2024-03-05','El año pasado nos comentaron que los chicos tenían un extra de 480€ para extras anuales. Preferimos que sean puntuales, porque nosotros hemos creado un documento donde vamos anotando todos los extras que se conceden y, cuando lleguen al tope ya no se pide más. Lo de Cris fue por el tema play station que tuvo que pagarle a un compañero porque le hizo el chachullo ese. Nosotras hemos valorado un extra anual de 500€, ya que las pensiones han subido también. Este año para Cris también se pide extra de semana santa. Otra cosa, sería posible que se suba la asignación mensual a 100€?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2024-03-05','El año pasado nos comentaron que los chicos tenían un extra de 480€ para extras anuales. Preferimos que sean puntuales, porque nosotros hemos creado un documento donde vamos anotando todos los extras que se conceden y, cuando lleguen al tope ya no se pide más. Lo de Cris fue por el tema play station que tuvo que pagarle a un compañero porque le hizo el chachullo ese. Nosotras hemos valorado un extra anual de 500€, ya que las pensiones han subido también. Este año para Cris también se pide extra de semana santa. Otra cosa, sería posible que se suba la asignación mensual a 100€?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='LOPEZ'and apellido2='THOMAS'),'2024-03-05','Ana: Recibimos Resolución de ATRASOS de la PRESTACION ECCA. VINCULADA AL SAR por la actualización. Corresponde al periodo de 1/08/23 al 31/08/23, por un total de 32,18€ ··························································· Cumplimento y subo a firma Comunicación de Fallecimiento que en principio iban a comunicar desde el centro (probablemente esté hecho, pero por si acaso).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-03-05','ANA: Mª Carmen, TS HSPA, remite INFORME DE ALTA DE LA UHB. ··········· Conciencia parcial de enfermedad. "Previo al ingreso NULA ADHERENCIA AL TRATAMIENTO" antes del ingreso, según analítica-orina, consumo de cannabinoides y benzodiacepinas. ··· Él mismo refiere también aumento de tabaquismo y consumo de hachís. ······· Presentaba "discurso incoherente que impresionaba de intención manipuladora". "Actitud querulante" que se fue adaptando según avanzó el ingreso. ···················· Manifestó haber pasado 2 semanas en Vallecas y haber sido atendido en el Hptal. de dicha localidad. ··············· Según JARA la última administración del TREVICTA fue en 27/11/2023. ··············· Discurso poco fiable en cuanto a seguimiento de medicación. ················································ Cita para consulta en Psiquiatría - UHB para el próximo 8/03/24 a las 11:10 h con la Dra. Cristina Donoso. ····································· Envío correo a Toni - Futuex: "Comunicaros que a FRANCISCO CACHO GARRIGO le dieron el alta ayer. Hoy me han enviado informe con fecha para hacer seguimiento ambulatorio, según indico: La han dado cita para seguimiento en consulta de Psiquiatría - UHB para el próximo 8/03/24 a las 11:10 h con la Dra. Cristina Donoso. Imagino que vuelve a situación de calle. Llamé a Cáritas y no había plazas en Centro Vida. Puede acudir al CES (Centro de Emergencia Social), él ya lo sabe y pedí que se lo recordaran en el hospital antes del alta. ¿Podéis, por favor, contactar con él y acompañarle a la cita en Salud Mental? Según dijo durante el ingreso, llegó a irse a Madrid, donde estuvo un par de semanas en Vallecas. También debe continuar seguimiento en el ECA, tendrá que solicitar cita. Se lo indicaron en el hospital. Ha estado con consumo activo previo al ingreso (cannabis y bezodiacepinas). Por faro, intentad apoyarle también en esta cuestión."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2024-03-05','Ana: Correo de Mamen, Ed. Futuex (delegadapoyo.caceres@futuex.es) a Toni y a mí: "Acabo de visitar a Pilar en su domicilio, estaba junto con Abraham, y he podido hablar con ellos sobre el tratamiento de diálisis. Lo que el otro día parecía sugestión por parte de Abraham, para evitar el tratamiento, hoy he valorado que lo han hablado y llegado el momento aceptan que Pilar se someta al tratamiento. Abraham tiene mucha dependencia de su madre, por lo que le da miedo que el tratamiento empeore su estado o la vuelva más dependiente, por ello Abraham desea postergarlo todo lo posible en el tiempo, pero no muestra una negación al proceso de diálisis. Además, le he explicado que Pilar acudiría en transporte sanitario, que la recogen en su puerta, puede ir sola con el tiempo, aunque al principio él le quiere acompañar, en función de la evolución puede que acuda menos días... Al parecer Abraham le ha comprado recientemente alimentos más adecuado a su patología, y he aprovechado, de nuevo, para ofrecerle la opción del catering para Pilar cuando salga la convocatoria, esta vez no han rechazo la propuesta, aun así les he dado tiempo para que lo piense, asimismo les he explicado los beneficios y el funcionamiento del programa. Queda pendiente de que me confirmen si lo desea solicitar Pilar. Aprovecho este correo para comunicarle a Ana, que Pilar tiene el DNI cumplido desde más o menos un año, me lo ha comentado Abraham en la visita de hoy. Por lo que, pediré cita cuanto antes para renovárselo. Las fotos no han puesto impedimento en pagarlas, ni la tasa del DNI (creo que es alrededor de 12€). Pero me gustaría que me aclarases si le puedo pedir yo la cita introduciendo los datos de Pilar, tiene que dar algún consentimiento CTAEX, hay alguna tasa especial para personas con discapacidad y/o curatelada o como sería el proceso para tenerlo en cuenta en futuras ocasiones." ································································································· Mi respuesta: "Muchísimas gracias por la intervención, implicación e rápida información Mamen. Yo tenía intención de llamar hoy a Abraham por este asunto así como en relación al seguro de coche e impuestos que le pasan a la madre, que gestionó él a nombre de esta sin comunicación ni autorización por parte de la CTAEx, pero se me ha complicado la mañana y no ha podido ser, mañana le llamaré. Mamen, por favor, en cuanto confirme Pilar que quiere someterse al Tratamiento de Diálisis, por favor decírmelo para que pueda comunicárselo lo antes posible a la Nefróloga. En cuanto al Cáterin, al ser usuarias de SAD, si finalmente se deciden y si vuelve a salir la convocatoria para el municipal gratuito procederé a solicitarlo. Si éste no pudiera ser podríamos valorar un presupuesto de Cáterin privado. Por último, en relación a la RENOVACIÓN DEL DNI, los trámites son los mismos que para cualquier persona y las tasas también. No es necesario la autorización de la CTAEx, así que te agradecemos que cuando puedas procedas a hacer las gestiones oportunas y a acompañarles si fuera necesario."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2024-03-05','Ana: Correo de Javier, TS del CSS Plas con citación del Jdo. nº 1 de Plas. a fecha de 28/05/2024 a las 11:00 h, para la "celebración de la vista y examen del discapacitado". ································ Solicito organicen acompañamiento desde el centro y pongo en copia a los A. Jurídicos CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2024-03-05','Ana: Correo de Lourdes, S. Ecca. a Casa de la Misericordia: ", al entrar en la cuenta de Sergio Solanilla, compruebo que su pensión es de 603,10€. Por lo que debe haber un error en la modificación de la cuota del centro para 2024. Ruego confirmen la misma, por si hay que modificarlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-03-06','miguel, email de Tere La situación es Esta en lista de espera en dos comunidades terapéuticas del ámbito privado y a la espera de derivación a comunidad terapéutica publica a través del ECA(equipo conductas adictivas), pero claro si deja de asistir a las cita como ha hecho hoy esa derivación no se va a llevar a cabo con lo cual nunca va a entrar en la red publica Por otra parte se ha intentado ingreso en centro de discapacidad pero no puede acceder a este tipo de centro estando en consumo activo Con lo cual esto es la pescadilla que se muerde la cola… tenemos autorización de ingreso involuntario pero no hay centro donde meterlo Esto es un imposible y mientras tanto su madre sufriendo las alteraciones y extorsiones de su hijo Si alguien se le ocurre algo… yo ya no se que mas hacer','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-03-05','miguel, envio email a la parte social tras hablar con abogacía general: Buenos días, acabo de hablar con el letrado de la Junta Pedro Claros, que me ha llamado para preguntar por este expte. Dice que por ahora sólo tiene la denuncia. Le he mandado testimonios de nombramientos, aceptación de cargo, etc, junto con revisión de medidas de apoyo de Felisa, y el Auto de Internamiento de Aitor. Lo que le preocupa es que haya posible conflictos de intereses y por tanto abogacía sólo represente a uno de ellos, por lo que el otro debería el juzgado solicitar al colegio de abogados nombre uno de oficio. Es posible que el juzgado obligue a ingresar inmediatamente a Aitor como medida cautelar por lo que deberíamos ir agilizando el trámite de dar cumplimiento al Auto de Internamiento Involuntario. Ya le he explicado que no ha sido posible por como dice Ana, sus conductas adictivas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-03-06','Ana: Correo de Estrella Durán, TS del CSS: "Está pensando la Psiquiatra darle un pase más largo a Enrique, antes de convocar la subcomisión, que al parecer va a ser el día 20 de este mes. Para supervisar dicho pase, iremos algún día el Equipo Asertivo Comunitario (ETAC). Creemos que sería conveniente que también hiciera supervisión la Educadora de Futuex, ¿cómo lo ves?" ···················· Reenvío a Maite, Jefa CTAEx para valorar en equipo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='PEREZ'),'2024-03-06','TERESA SOLICITO PENSION DE ORFANDAD SIMPLE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='CRUZ'and apellido2='SANTOS'),'2024-03-06','TERESA SE SOLICITA REACTIVACION DEL EXPEDIENTE Y VINCULADA DE SAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTIAN'and edp.apellido1='CARRASCO'and apellido2='BLANDON'),'2024-03-06','Ángel: Asisto hoy a la declaración de Cristian en el Juzgado de Primera Instancia e Instrucción, nº, 1, de Zafra, en relación con el procedimiento DP 685/23 (Sumario 1/2024). Declara en sala que Daniela, que es con quien tiene la orden de alejamiento, está intentando contactar con él a través de instagram. La jueza le ha pedido que le enseñe el móvil para comprobarlo. Ella le ha saludado con un "hola", él no la ha respondido. Termina la declaración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='DIAZ'and apellido2='ROMERO'),'2024-02-21','solicito cambio de PIA para pasar de VT +CO de Montijo a Badajoz por acercamiento familiar . Sonia me va a devolver una documentación para firmar. Lo pongo a portafirma.Y queda registrado por Juan Carlos Cano a dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2024-03-06','Ana: Llamada de Manuel, Técnico Valorador Secc. Dependencia -Cáceres (64703): Ayer acudió al domicilio a valorar a Teodora, madre de José Blas. En ese momento José Blas salía de casa para acudir a C.O. ··············· Teodora ha dado Grado I. Recibe por las mañana SAD municipal, que va a mantener y van a solicitarle C. Día para que acuda por las tardes y pueda recibir también rehabilitación. Pero sí José Blas sigue en casa por las tardes le ha dicho que como tiene que estar pendiente de él, no podría acudir al C.D. ··········· Informa de la insostenibilidad de la convivencia con su hijo, las amenazas y las reacciones de éste. Estaba allí la Auxiliar de SAD que ha corroborado esta situación, pues a veces ha presenciado estas conductas. ········ *Según le ha dicho Teodora, ahora su hijo sí quere ingresar. ·································· Ha preguntado a Maribel, TS de la Secc. Discapacidad. Aún no está en lista de espera. Nos pasarán la solicitud de elección de centros. ·················· Maite, Jefa Secc. sube a firma y pasa a las Secc. de Discapacidad la ELECCIÓN DE CENTROS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='RODERO'and apellido2='COMERON'),'2024-03-06','Ana: Envío mail a Alberto, Jefe S. Ecca. y a A. Jurídicos: "Os reenvío correo de la TS del CAMF de Alcuéscar con la propuesta de INDEMNIZACION que hace la compañía de Seguros del dueño del vehículo que le atropelló. Si estamos de acuerdo hay que enviar la aceptación firmada." ······························································································································································································· Correo de Ángela, A. Jurídico: "Os envío certificado del Registro de la Propiedad nº 10, de Valencia, en el que indican que Prudencio Rodero Cameron, no dispone de propiedades inscritas a su nombre, en todo el territorio nacional. En catastro tampoco tiene propiedades a su nombre." ······························································································································································································ A petición de Ángel, A. Jurídico, llamo a Felisa Custodio, TS CAMF-Alcuéscar (927 38 41 25). ···················· Envío correo a Ángel y Alberto: "Acabo de hablar con Felisa, TS del CAMF. Me dice que pidieron abogado de oficio porque pasados más de 5 meses del accidente seguían sin saber nada. Pero luego llamó al Juzgado y resulta se había extraviado la documentación. La policía local tuvo que enviar el acta/parte policial de nuevo y raíz de ahí ya toso se puso en marcha. Finalmente llamaron al Colegio de Abogados y RENUNCIARON al Abogado de oficio. Por su parte considera, que viendo la propuesta que hace la compañía de seguros no es necesario volver a solicitarlo" ··············································· Ángel, A. Jurídico, pone para firma la aceptación de la indemnización.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2024-03-06','ECO: LA PERSONA ECO ENCARGADA DE INCLUIR LOS IMPORTES Y TRAMITAR LOS PAGOS ES LOURDES. ECO: EL LÍMITE INTERNO SOCIAL/ECO SON 3.500 € - EL LÍMITE QUE SOCIAL ACUERDE CON CENTRO NO AFECTA A ECO. SOCIAL: ÚNICAMENTE SOLICITARÁ A ECO (LOURDES) QUE HAY QUE REALIZAR UN PAGO (A EFECTOS ECO ES IRRELEVANTE SEMANAL/MENSUAL/TRIMESTRAL) Y APORTARÁ LA JUSTIFICACIÓN DEL MISMO (COMO EN CUALQUIER OTRO TIPO DE PAGO). ECO: ÚNICAMENTE ABONARÁ CUANDO INDIQUE SOCIAL + INCLUIRÁ DATOS EN HOJA CÁLCULO. PROCESO: SOCIAL COMPRUEBA PREVIAMENTE QUE QUEDA SALDO EN HOJA CALCULO ---- EXPTE. TUTELADO/ÁREA ECONÓMICA/0CONTROL EXTRA ANUAL/PESTAÑA DE AÑO CORRESPONDIENTE. SOCIAL SOLCITA PAGO A ECO - APORTANDO DOCUMENTACIÓN JUSTIFICATIVA (FACTURA, ETC...) ECO ABONA ECO REGISTRA EN HOJA CÁLCULO EL ABONO CRITERIOS: EXTRA INCLUYE "TODO": VACACIONES, VIAJES, SALIDAS EXTRAORDINARIAS, TODO TIPO DE OCIO, ROPA, CALZADO, ELECTRONICA/TELEFONÍA (INCLUIDAS TODO TIPO DE REPARACIONES), ETC. EL IMPORTE ACORDADO NO SE PODRÁ SUPERAR BAJO NINGÚN CONCEPTO LA COMPROBACIÓN DEL SALDO SIEMPRE SE HARÁ "PREVIAMENTE" X ÁREA SOCIAL. De: Maria Teresa Gomez Martin >maria.gomezma@salud-juntaex.es> Enviado: martes, 5 de marzo de 2024 14:46 Para: ALBERTO MARTIN ROSETE >alberto.martinr@salud-juntaex.es> Cc: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es> Asunto: CEFERINO MARISCAL CRESPO Buenas, Respecto a la gestión económica de Ceferino Mariscal lo acordado es lo siguiente: Se ha fijado con el centro una cantidad de 1800 € anuales para gastos extraordinarios. Las peticiones de gastos extras serán trimestrales. Dichas peticiones se las hará llegar el centro directamente al área social ( Amalia). Desde dicho área se pasará a la sección económica ( Lourdes) para dar el ok ( Se consultará en la hoja de cálculo como va el gasto y el saldo disponible). Alberto, tal y como sugeriste la cantidad de extra anual de forma interna será de 3000/ 3500 ( lo concretamos), y en función de esta iremos gestionando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2024-03-06','TERESA REGISTRO SOLICITUD INGRESO EN RESIDENCIA VIA DECRETO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2024-03-06','Ana: Envío correo a Cristina Hdez, TS CSS - Plas. (cristina.hernandezca@salud-juntaex.es): "En relación a la conversación que mantuvimos sobre Martín Domínguez Palencia el día 23 de febrero, te transmito la respuesta de Alberto, Jefe de la Sección Económica, que no ha podido verlo antes: • REINTEGRO: OK A LOS 43 €/MES (10 € X SEMANA) (él calcula por 52/semanas/año). Si alguna semana necesita un poco más no habría problema siempre que fuera coherente y controlado el gasto. • EXTRA ROPA X 200 €: OK. Cuando vuelva a ser necesario en cambio de temporada podría hacerse otro reintegro similar. Informa también que de Martín sí teníais autorización general de centro para retirada desde septiembre de 2022, os la envío adjunta. Con ella podréis retirar sin problema la cantidades indicadas. Por otra parte, me pide Alberto que os consulte: • CENTRO: LE ESTÁN COBRANDO 540,91 €/MES (ES MUY POCO PARA SU PENSIÓN DE 916,63 €/MES)...XFA, CUANDO HABLES CON CENTRO INFÓRMALES DE ESTO PK YO ENTIENDO QUE EL COSTE DEBERÍA DE SER SUPERIOR. Yo creo que en su día ajustaron el precio en función de las elevadas deudas, multas, etc. que tenía. Podéis mirar para actualizar el cobro, pues su cuenta ya está algo más saneada. Aunque recientemente también le han pasado otra multa pendiente… Por cierto, tenemos que hablas sobre la posibilidad de venta de uno de sus inmuebles y de si a día de hoy él estaría en disposición de opinar/expresar su voluntad sobre ello."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-03-06','Ana: Correo de Cristina, TS - SSASB - Malpartida de Cáceres (ssb@malpartidadecaceres.es // 927 275 003): "Buenos días Ana, M Carmen Solana Chanclón, está incapacitada y vosotros tenéis parcialmente la tutela (administración económica). Va ha recibir una herencia (poco dinero y parte de vivienda) me parece importante que lo conozcáis ya me dices que tenemos que hacer." ·························· Reenvío correo a los A. Jurídicos para que le den respuesta y/o se pongan en contacto con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2024-03-06','Ana: en relación con el correo de Nieves, Ed. Futuex (delegadapoyo.caceres2@futuex.es), el lunes: "Buenas tardes, se ha acudido hoy al domicilio de Ventura para hacer seguimiento del estado del mismo y también del tema del catering que se notificó la semana pasada. Respecto a esto, es cierto que Ventura acumula muchos tuppers de comida porque varios días come fuera, unas veces por viajes organizados por la ONCE y otras por salidas que hace con personas del obispado, donde acude muy a menudo. Se ha comprometido a hacer uso de los que tiene guardados ahora mismo en la nevera, ya se le ha avisado que otro día de esta semana se volverá a revisar para que quede constancia de si lo cumple o no. Se le ha tirado muchos caramelos que tenía guardados en casa, él ya no los quiere y además no le hacen bien. También respeto al catering se avisará mañana para comunicar que Ventura estará fuera dos semanas, para que pausen el servicio hasta principios de abril (esto se ha calculado con la auxiliar del SAD). Por otro lado, al llegar al domicilio la auxiliar pregunta si ya se pagó la reserva del balneario, y se le dice que sí y que Ventura ya estaba avisado hace días. Ella comunica que él fue solo a pagarlo también y enseña el resguardo (se adjunta a este correo). Se le explica a Ventura que todas estas gestiones tiene que consultarlas con la educadora, él dice que pensaba que se le acababa el plazo (ya estaba avisado de que se había pagado la reserva). Por lo tanto, se ha pagado un total de 80 euros por el viaje al balneario este 15 de marzo, se traslada esta información para que se pueda avisar de que en el importe total se tenga en cuenta o que procedáis como consideréis." ·············································· Comunico a Lourdes, S. Ecca. el abono por duplicado de la reserva. Pido que consulten si se puede descontar del resto del coste del viaje (si no se ha pagado aún esta parte) o en su defecto si lo pueden devolver.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2024-03-06','Ana: Llamo varias veces a Cristina Hdez, TS CSS (24185): consultará en administración y me dará respusta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-03-06','Ana: Llamo a Carlos (644 949 205): mañana a las 10:10 h tiene la cita la la Dra. Cristina Donoso, Psiquiatra. Dice que acudirá, que va a llamar a Mamen, Ed. Futuex, ahora. ····························· Envío correo a Mamen (delegadapoyo.caceres@futuex.es) para comunicárselo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2024-03-06','Dejamos pendiente en la reunión confirmaros si en el caso de que Cefe quisiera publicar un nuevo libro el gasto estaba dentro o fuera del extra anual. Lo he hablado con Alberto y sería un gasto a parte, no con cargo a los 1800 € anuales. Por cierto Ceferino hoy ha llamado a las compañeras de la parte económica. Les hemos dicho que no respondan. Como acordamos tiene que hacer las demandas a través de vosotras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-03-06','Ana: Llamada de Alicia, TS SSASB - Alcuéscar (927 384 002): me comunica que este mes de febrero el banco ha devuelto el pago de la plaza residencial además de los "gastos de servicios adicionales". Enviará extractos bancarios. ··········································································· Comunico la situación a Alberto y a Lourdes, S. Ecca., y adjunto los recibos bancarios que me facilita Alicia, TS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-03-06','Ana: Reenvío a la sección jurídica el INFORME PARA LA REVISIÓN DE LAS MEDIDAS DE APOYO facilitado por el CRR-Plas. ······················· En el Informe especifican las necesidades de apoyo en el día a día tanto para ABVD como AIVD, sus déficits a nivel cognitivo y su buena predisposición tanto para acudir al médico, para el seguimiento de tratamientos, así como para participar en actividades del centro y colaborar/ayudar a otros compañeros en tareas sencillas. ······ Está bien valorada/considerada por la mayor parte de residentes y profesionales. ······ También hacen constar su deseo manifiesto de en un futuro no muy lejano solicita plaza residencial de mayores en su pueblo o cerca del mismo para poder estar más cerca de su padre, con quien mantiene muy buena relación. Éste también tiene intención de solicitar plaza de las mismas características. ······ Llegado el momento procederán con los trámites de solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='DIAZ'and apellido2='ROMERO'),'2024-02-20','Efectivamente, no puede pedir traslado en Centro Ocupacional. Tendría que renunciar a P.I. Montijo y solicitar C.O. en Badajoz, siempre y cuando estuviera domiciliado en Badajoz. Otra cosa es solicitar el traslado de Vivienda Tutelada, eso lo puede hacer cuando quiera a través de la revisión del PIA (si tiene grado, claro). Lo tendría que solicitar por "reunificación familiar".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2024-03-06','Ana: Llamo a Abraham, hijo de Pilar (927 234 706 / 639 887 897): Expresa que él no puede abonar el seguro del coche. Que "si le obligamos" le dirá a su amigo que se lo lleve. ········· Que otro motivo para tenerlo es que a su madre le gusta hacer pequeñas excursiones/viajes. El año pasado le llevó a ver el cerezo en flor, a Trujillo y a otras localidades de Cáceres. - Le recuerdo que si no hubiera actuado a espaldas de las CTAEx, para la contratación del mismo y el abono del Impuesto de Circulación igual se hubiera aceptado y no estaríamos ahora en esta situación. ····················· En cuanto al tratamiento de Hemodiálisis, él pensaba que podían dar respuesta a la Nefróloga en la próxima consulta en mayo. Dice que su madre quiere y no quiere, pues tiene miedo. Puesto que hay que dar antes la respuesta, hablará de nuevo con su madre y me llamará entre mañana y el lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-03-06','TERESA MANDO POR CORREO CERTIFICADO TARJETA DE TRANSPORTE','2');
