insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2024-03-07','Ana: Llamada de Abraham, hijo de Pilar (927 234 706): dice que ha hablado con su madre y ésta ha decidido realizar el Tratamiento de hemodiálisis. ·························································································· Ana: Llamo a la Dra. Sandra Gallego, Nefróloga del HSPA (56274): confirmo que Pilar quiere someterse al tratamiento. Me enviará los CI. ······························· Lo comunico a Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2024-03-07','Amalia : archivo en su expediente los recibos que envia el centro : "Adjunto todos los recibos de los ingresos que ha estado recibiendo Juan José Murillo Romano por su contrato de formación en RAEES. A partir del 1 de mayo, comenzará su contrato de prácticas, en el que cobrará al mes el 75% del sueldo mínimo interprofesional.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2024-03-07','Email del centro : Informaros que en el día de hoy se ha celebrado el juicio de Juan José Murillo Romano por "robo con fuerza en las cosas". Llegó un comunicado al juzgado por parte de la comisión tutelar de adultos para que el usuario tuviera vuestra representación a través de videollamada. Sin embargo, aunque se ha llamado al teléfono indicado, no ha sido posible poder localizaros. El juez ha estimado condenar a Juan José a 6 meses de prisión. Sin embargo, y teniendo en cuenta su evolución favorable en diversos ámbitos de su vida, ha decidido SUSPENDER esta condena. A partir de ahora, y durante un período de 2 años, el usuario tendrá que seguir asistiendo al servicio CEDEX, a tratamiento psicológico y a consulta con el psiquiatra. En principio cada 3 meses se tendrá que enviar al juzgado un informe de valoración como comprobante que Juan José está cumpliendo con la sentencia pactada. Cuando nos llegue la sentencia os la haré llegar. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='BLANCO'and apellido2='POVEDA'),'2024-03-07','Ana: Correo de Gema Morato: "Ya se ha tramitado la baja en la ayuda vinculada de Victor Manuel Blanco Poveda. Os aviso porque es lo que quedaba pendiente en el tema económico de este señor. Si necesitáis alguna otra cosa no dudéis en llamarme"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2024-03-07','miguel, email de Tere: Me reclaman el pago de esta factura de la cual no se ha pedido autorización previa, tras hablar con el albañil y explicarle que para hacer un gasto hay que aprobarlo previamente por la Ctaex me dice palabras textuales: “a mi diego no me comentó nada de eso, solo me dijo que lo hiciera, que eso era poco” Necesito me digas que le tengo que decir exactamente ya que no se va abonar, imagino que esto ha pasado en otras ocasiones para actuar de la misma manera…. ****************************************************** email de Alberto: TOD@S: NOS ENCONTRAMOS CON UNA FACTURA DE 2.413,95 € A NOMBRE DE D. JOSÉ LUIS GUERRERO SUAREZ X TRABAJOS QUE DICEN HABER REALIZADO PARA EL TUTELADO D. DIEGO MARÍA SÁNCHEZ SANTIAGO. DE ESTA OBRA LA CTAEX NO HA TENIDO CONOCIMIENTO Y X SUPUESTO NO HA AUTORIZADO LA MISMA. CUESTIÓN A DISCUTIR: EN MI OPINIÓN NO DEBERIAMOS PAGAR + DEBERIAMOS DE COMUNICAR AL JUZGADO LO OCURRIDO + INDICARLE AL CONSTRUCTOR QUE SI QUIERE COBRAR, DEBE DE IR A DICHO JUZGADO Y VER LO QUE ESTE DECIDE. *************************************************** contestación de Tere: Por mi parte al ser un importe tan elevado y que no se había autorizado creo que lo mejor es comunicar al juzgado y que nos digan si la abonamos ******************************************************* mi contestación a la parte económica (Alberto) y social(Tere): Buenos días, tras ver el expediente, no veo que nadie haya autorizado este gasto, por tanto que lo reclamen vía judicial. Es una obra ya realizada (sin autorización, parece ser por lo que leo que el albañil dice haber sido autorizado por el tutelado) y por tanto no podemos pedir autorización de gasto extraordinario por una obra finalizada, no tiene sentido porque ya está hecha…y además es inferior al importe de más de 3000€ que solemos hacer y bajo un previo informe de necesidad y varios presupuestos…requisitos que aquí no se dan. Por tanto, que lo reclamen o bien si decidís pagarlo en la próxima rendición de cuentas anuales tendríais que indicarlo. Por otro lado en el procedimiento de revisión de medidas de apoyo 179/2023 Juzgado de Primera Instancia núm. 1 de Villafranca de los Barros todavía no finalizado que sepamos (lo lleva Escalona), figura este informe social que os adjunto y en él en el punto 7 se hace mención a esta obra y Antonio Nisa indica que es innecesaria. Por tanto que lo reclamen vía judicial o que se dirijan al juzgado que está conociendo del procedimiento y si les autorizan a dicho gasto antes de resolver, pues que lo incluyan. Por parte de la Comisión entiendo no tenemos que hacer nada La auxiliar de ayuda a domicilio me ha dicho que la obra era necesaria pues con estas perreras se evita que los perros anden sueltos por la casa con lo que ello conlleva…','2');
