insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2024-03-08','LOURDES: OK A REINTEGRO PERMANENTE DE 100 €/MES (ANTERIOR DE 90 €/MES). AMALIA: ACTUALIZAMOS EL LÍMITE ANUAL DE 480 A 500 €/AÑO---OJO: TIENE PNC, ASÍ QUE EL CENTRO TIENE QUE SEGUIR CON EL TRABAJO DE LIMITAR MUCHO AL TUELADO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2024-03-08','Buenas de nuevo , me indican desde la S. económica que el banco ya ha solucionado el problema y Jose Mª recibirá a partir de abril un ingreso permanente de 400€. Para el mes de marzo van a hacerle un reintegro puntual de 320€ , para que cada semana pueda sacar los 80€ máximos a lo que está limitado. Este chico tiene P. orfandad y PFHC , con bastantes ingresos y tiene muchos ahorros. Si consideráis que necesita una TV , ropa , calzado ... nos pasáis un presupuesto y lo abonamos . Saludos.','2');
