insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INOCENCIO'and edp.apellido1='MARTINEZ'and apellido2='NOVAS'),'2024-03-08','Ana: Pongo para firma la DECLARACIÓN ANUAL DE PNC. ··············· Actualizo cuantía en la Base de Datos: 517,90 € ······························ Modifico domicilio en la Declaración Anual: CAMP - C/ Pedro y Francisco González 2. CP: 10600 - Plasencia (Cáceres)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-03-08','Ana: Correo de Estrella, S. Ecca. CTAEx: "ya le he preparado a Felisa la nueva asignación, importe 175 € quincenal, el 15 de marzo le haré la recarga de la tarjeta con el nuevo importe" ································ Lo comunico a Toni y Nieves, Ed. Futuex (delegadapoyo.caceres2@futuex.es) ······························································································································································································· Envío a la S. Ecca: "Por parte de Alberto está autorizado un extra para ropa. Tal y como plantea Toni-Futuex (leed el hilo que reenvío el correo), ¿podríais añadir de forma puntual a la recarga del próximos viernes 70€ de extra para ropa? Para que vaya directamente a comprar la ropa acompañada de la Educadora en lugar de tener que enviar presupuesto previo y abonar después mediante transferencia. Por favor, confirmad a Toni cuando esté hecho para que puedan organizar la agenda."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2024-03-08','miguel, hablo con Estefanía (abogada) Estefania@beramendiygonzalez.com ,985-170250 para coordinar el envío de documentación a Loli MARIA DOLORES ORELLANA BARBA >notariaherreraloli@gmail.com>(notaria de Herrera del Duque) para que prepare la herencia de los hijos fallecidos (Juan Felipe y Agustin): Buenos días Loli, necesitamos vayas preparando la herencia familiar de la tutelada Doña Alfonsa Montalban Serrano. Ya se firmó en vuestra notaria las declaraciones de herederos de los fallecidos hijos de la tutelada por la Comisión Tutelar de Adultos, Doña Alfonsa Montalbán Serrano, Agustin y Juan Felipe Rodriguez Montalban (adjunto las actas de notoriedad) Sólo forman parte de la herencia la viuda de Juan Felipe y nuestra tutelada Alfonsa. Necesitaría nos indicases a parte de la documentación que te adjunto, y de la que ya tenéis en la notaria, qué te haría falta para la firma de las herencias de Agustín y Felipe Rodriguez Montalban (hijos fallecidos de la tutelada). La masa hereditaria está formada por las fincas de Talarrubias y Madrid. Los certificados de cuenta que pueda haber te los enviará Estefanía (abogada de la nuera), junto con los gastos que puedan recaer por la administración de los bienes estos años (ibi, comunidad de propietarios, etc) Te adjunto la herencia del fallecido marido, libro de familia, certificado del centro de mayores donde reside la tutelada, acta de declaración de herederos del hijo de la tutelada fallecido Juan Felipe Rodriguez Montalban(que dejo viuda Mª Mercedes Dominguez Martinez, no hijos), y acta de herederos del otro hijo fallecido Agustin Rodriguez Montalban, impuesto de sucesiones abonados por la tutelada, notas simples de los dos inmuebles de Talarrubia y Madrid, certificados de catastro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2024-03-08','Ana: Correo de Ana Sánchez, Res. (anatdelat@hotmail.com): "Les escribo desde la Residencia de Mayores de Torrecillas de la Tiesa, sobre la usuaria Isabel Muñoz Melchor. Su tutora, Clara, me comenta que el lunes día 11 tienen cita con el notario a las 12:30h y que les dijo que la consulta eran de 50 a 70€. Habría posibilidad de que ingresaran hoy en la cuenta la cuantía de 70€ para que el lunes lo lleve Isabel a la consulta del notario?" ········································ Envío correo a A. Jurídicos, secc. ecca., Ana Sánchez y Clara, Ed. Futuex (delegadapoyo.plasencia@futuex.es), con copia a Toni también: "Ángel y Miguel, os reenvío este correo para para vuestro conocimiento, no sé si tendréis que llamar al Notario o algo. Es la Notaría de Trujillo. Clara, gracias por las gestiones, por teléfono las veces que lo he intentado no he obtenido respuesta. Compañeras de Sección Económica, no he visto este correo hasta ahora. ¿Es posible Isabel Muñoz Melchor pueda retirar hoy mismo o el lunes a primera hora de la mañana los 70€ que nos comentan desde la residencia? El mismo lunes cuando acuda a la cita tendrá que abonarlo. Confirmar poniendo en copia a la residencia, por favor (Ana Sanchez) Ana, gracias por la información. Por favor, recuérdale que deben pedir FACTURA A NOMBRE DE ISABEL para remitirla después a la sección económica para la justificación del gasto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-03-08','Ana: Reenvío a Alberto, Jefe S. Ecca, el correo de Toni: "Francisco Cacho lleva desde que salió del hospital pernoctando en la calle, como suponías, el primer día al parecer en una casa ocupa donde le robaron la medicación y un saco de dormir, según el refiere, y el resto de noches en el albergue. En este último solo puede estar desde las 10 de la noches hasta las 10 de la mañana, el resto del día lo está pasando en la calle. Él mismo ha manifestado que necesita "quitarse de la calle" y poder "estar en un sitio tranquilo". Se sabe que está yendo al ECA a hacerse los controles y a las consultas con los profesionales, ayer mismo tuvo control y acudió , y mañana irá acompañado a una cita con su psiquiatra, que nos trasladasteis. El dinero de su asignación de este mes lo ha utilizado en comprar un móvil (se lo robaron estando en Madrid, según dice) en un saco de dormir y algo de ropa (la educadora le acompañó a hacer alguna de estas compras). Ahora mismo dice que no le queda nada de dinero y que lo está pasando muy mal en la calle. Él comunica su deseo de poder tener una habitación donde estar tranquilo, y que está dispuesto a que le bajen su asignación mensual para hacer frente a este gasto. No sabemos si sera viable, por si situación economica, el que pudiera pernoctar en un hostal. Se considera, que pudiera ser, un buen momento para intentar que encauce su situación alejándose durante unos días de la calle y los hábitos que ésta conlleva, aunque somos conocedores que es muy complejo garantizar esto, y que está solución sera algo temporal, que no podria costear posiblemente durante mucho tiempo, tambien se ha valorado el poderle acompañar a buscar pisos compartidos, pero esta opcion no deja de ser complicada también, por las circunstancias. Se ha pedido presupuesto en uno de los hostales donde ya se ha trabajado anteriormente y aceptan transferencia, el hostal Neptuno, y desde mañana viernes 8 hasta el día jueves 14 (ambos inclusive) serían 230 euros." Le aclaro algunas cuestiones y pido que intente mirarlo y dar respuesta hoy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2024-03-08','Ana: Correo de Tensi, TS (ssbtensi@riberosdeltajo.es): "el martes se tramitó la revisión del Grado así como la ampliación de centros de Isidro Torres Villegas, para tu conocimiento"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2024-03-08','Ana: Envío correo a Alberto, Jefe S. Ecca: "Me confirman desde el C. Sociosanitario que el copago de la plaza de GUADALUPE GIL CABELLO es de 388,43€/mes. Es decir, 75% de sus ingresos excluyendo pagas extras. Cuando hagas los cálculos, porfa, dime de qué reintegro máximo pueden disponer para gastos de bolsillo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2024-03-08','-Amalia , envío email a Ana la TS que lleva Gévora para informarle que la semana pasada llegó el cdo. de discapacidad , le han otorgado el 65%. Tiene G.I dependencia con P.V. SAD pero suspendió el servicio y tiene una deuda con el SEPAD de 260€. Se quedó con el SAD municipal que era más económico. Gestionar con Dependencia este pago. Vamos a solicitar cambio de PIA para solicitar centro de discapacidad ó salud mental . Necesito que me envíes a la mayor brevedad informe social de emergencia social , puedes utilizar el informe que me enviaste , en el que se justifique que su situación actual reviste emergencia social . Me he reunido con la Sección de discapacidad en Mérida esta semana para hablar de este caso . Su patología es de discapacidad y de salud mental . Voy a solicitar derivación también a su ESM para que si estiman oportuno hagan derivación a CRR . Por si el CADEX desestimase ingreso en centro de discapacidad. Todo ello ,siempre que ella voluntariamente quisiera ingresar . Preguntado por la voluntariedad , Manuela se niega a ingresar en ningun recurso tendremos que pedir nternamiento involuntario Me indicas que pide dinero, tiene acceso a 600€ de reintegro mensuales , debería tener para cubrir sus gastos. Ha emitido I. Social para justificar la emergencia socila y datos personales de Manuela . Vive sola en Gevora , tiene algunos hnos en Badajoz sin contacto familira El dictamen CADEX estable RMLeve y Tno Ansiendad . Acude desde hace años al ESM Ciudad Jardín. Tiene 49 años . Tiene bono social de la luz , Teleasistencia y SAD municipal. Le dan alimentos en Caritas . No tiene S. decesos , se lo indico a Estrella . Desde el P. Familia la educadora nos indica que se solicite centro por internamiento involuntario. Lo valoro con los juridicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2024-03-08','Amalia , escribo a Eva la TS : Se adjunta solicitud de H. Funcional para que podáis gestionar y continuar el trámite enviándolo al CADEX junto con el resto de informes y documentación . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2024-03-08','-Amalia ; he puesto a portafirma una solicitud para cambiar los centros pedidos y quitar el de La Providencia ,porque tenía opciones de entrar y de momento , lo que queremos y ella aceptaría es C.O. Cuando esté firmado se lo paso a J. Carlos para registrar a Maribel, he puesto en el documento el nº DIR .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-03-08','Ana: Envío a Alberto, Jefe S. Ecca: "Para abaratar costes a JUAN JOSÉ GONZÁLEZ CARRERO, facilitan desde Futuex, otros presupuestos más económicos que te envío. Lee el hilo porfa porque uno de ellos no viene en documento aparte."','2');
