insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='LOPEZ'and apellido2='THOMAS'),'2024-03-11','Ana: Envío a Juan Carlos, Aux. Adtvo: "Adjunto para remitir por REGISTRO a la Gerencia Territorial de Cáceres, Sección de dependencia de Plasencia, los siguientes documentos relativos a ANTONIA LÓPEZ THOMAS: - Comunicación de Fallecimiento - Certificado Literal de Fallecimiento"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-03-07','Ana: Correo de Paula, TO del CRR-Plas: "comentaros que Antonio ha cambiado ya de contrato a tarjeta prepago desde ayer, con un presupuesto máximo de 20 Euros, que le incluye tanto llamadas ilimitadas como una cantidad de megas que le permite sostener la comunicación con su familia por WhatsApp y otros fines (participación en actividades de talleres, ocio...) esta vez con un máximo de gasto. Revisando con él se había suscrito a alguna página que podría suponer un coste y procedió, con apoyo de educadores, a cancelar estas suscripciones (contenido pornográfico). Se le ha informado de los posibles costes de estas páginas, y de aspectos a tener en cuenta para el buen uso del teléfono y contener el gasto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2024-03-11','Ana: Pongo para la firma la DECLARACIÓN ANUAL DE PNC. *Comunico que convive con la madre y el hermano. En el aplicativo de PNC aparecía sin más miembros en la unidad de convivencia. ····························· Actualizo cuantía en la Base de Datos: 776,85 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-03-11','Ana: Reenvío a Alberto, jefe Secc. Ecca. y a los A. Jurídicos, el correo-respuesta de Chema Tovar: "una vez recibido el pasado día 1 de marzo vuestro correo, contestamos a las cuestiones que nos exponéis. Informaros que las pensiones de las tuteladas: Soledad Esteban Iglesias, Carmen Gracia Estévez, Isabel Tejada Fernández, Vanesa Carrera Pérez como la de Tomás Esteban Iglesias fueron gestionadas en su día por la educadora Mª José Pérez Olgado, desde ese momento, siempre hemos sido conscientes de procurar un colchón económico para posibles gastos imprevistos que no son recogidos en la Nominativa. Sí, es verdad que siendo actualizadas las pensiones de las que actualmente son beneficiarias, vemos que la de Soledad Esteban es inferior a la de las otras tres tuteladas. Lo cual, nos lleva a recordaros que dicha tutelada está pendiente de recibir la parte que le corresponde por ley de la herencia de su hermano fallecido Tomás Esteban Iglesias. Aprovechamos este escrito para solicitaros que se actualicen las pensiones que perciben las tuteladas en 2024. Saludos cordiales." ···················································· Respuesta de Miguel, A. Jurídico: "Buenos días, el único bien que dejó es una cuenta bancaria y por tanto no debería ser complicado repartir la herencia. Lo veo con Angel y decidimos si nos da tiempo a tramitarlo o le buscamos una asesoría que tramite declaración de herederos (no creo tuviese testamento) para lo cual necesitaremos dos testigos (nos valen dos trabajadores del último centro donde residió), impuesto de sucesiones, y redacción y control del importe a repartir de Unicaja."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='MARTINEZ'and apellido2='VAZQUEZ'),'2024-03-11','Ana: Pongo para la firma la DECLARACIÓN ANUAL DE PNC. ············· Actualizo la cuantía en la base de datos: 776,85 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MARTIN'and apellido2='SANCHEZ'),'2024-03-11','Ana: Pongo para la firma de la D. Gerente la DECLARACIÓN ANUAL DE PNC. ············· Actualizo cuantía en la base de datos: 517,90 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-03-11','TERESA Me ha llamado la madre (643430944) Ahora esta viviendo con su madre, desde el miércoles, me dice que la convivencia es imposible no atiende a normas y la discute mucho con la pareja de la madre. Graba las conversaciones que tienen en casa con el móvil, dice que la busca continuamente en el trabajo. Esta desesperada la mujer….','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2024-03-11','Ana: Envío a Teresa Nogueira, TS de Novaforma: "A partir del mes que viene se le sube a JOSE FERMÍN GARCÍA PABLOS la asignación a 93€/mes a partir del 1 de abril. Pero además, esta semana, podrá acudir a retirar un reintegro extra de 20 € (hasta el viernes) para compensar lo de este mes y que pueda disponer ya del dinero que indicabais para gastos de bolsillo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-03-11','TRRESA Desde el equipo de apoyo social comunitario, hemos elaborado pequeña nota para informar sobre una incidencia relevante ocurrida durante el miércoles 6 de marzo de 2024 La educadora asignada a este caso fue notificada el 5 de marzo, por parte de la ts de la localidad, acerca de las amenazas de suicidio proferidas por Pedro. En un principio, siempre según comentan se dirigió al Ayuntamiento solicitando asistencia económica al alcalde para hacer frente a sus deudas, como ha sido su práctica en ocasiones anteriores. Ante la negativa del alcalde en esta ocasión, Pedro amenazó con quitarse la vida. En un estado de alteración, se observó a Pedro caminando por la calle portando un cuchillo de cocina, lo que motivó la intervención de la policía local para su búsqueda y resguardo. A pesar de los esfuerzos, Pedro no fue localizado inicialmente. Intentan contactar con él de manera telefónica. Durante una conversación telefónica, se percibió en su voz indicios de posible consumo de sustancias, los cuales él admitió. Posteriormente, fue encontrado en un establecimiento consumiendo alcohol, siendo acompañado a su residencia por las autoridades pertinentes por la policía local. En este punto, se procedió a contactar a la educadora de referencia para establecer las pautas de actuación. Se recomendó iniciar el protocolo correspondiente, incluyendo la comunicación con el servicio de emergencia 112. No obstante, el alcalde sugirió esperar y no hacer uso inmediato de este recurso. En horas vespertinas, Pedro se dirigió a la residencia de un familiar del alcalde para solicitar nuevamente el apoyo financiero para saldar una deuda, demandado esa mañana. En esta ocasión, lo acompañaba otro individuo cuya procedencia no fue identificada (según Pedro era un camello) y quien también exigía el mencionado dinero. Como resultado de esta interacción, se le proporcionó la cantidad solicitada a Pedro. En la mañana de ayer, la educadora se puso en contacto con la trabajadora social de Monterrubio con el propósito de obtener detalles sobre los acontecimientos del día anterior y coordinar una visita a Pedro. Durante la comunicación, se informó que Pedro había aceptado ingresar de manera voluntaria. Al llegar al lugar, nos encontramos con que Pedro ya se encontraba en la ambulancia. Mantuvimos una conversación con él y coordinamos acciones con el ayuntamiento, la policía local y el alcalde. Se acordó redactar informes detallados acerca de los sucesos, reiterando la necesidad de reconocer que Pedro no es apto para vivir de forma independiente mientras continúe con sus consumos. Además, se señaló que su vivienda presenta condiciones infrahumanas que requieren atención inmediata. Nos dirigimos a urgencias en Don Benito, donde Pedro se encontraba antes de ser trasladado para ser evaluado en Mérida, ya que en Don Benito, no hay UHB. Durante nuestra estancia, Pedro expresó su deseo de cambiar su estilo de vida y reconoció la necesidad de iniciar este proceso de inmediato, lo cual fue reforzado positivamente por mi parte. Mientras esperábamos el traslado, adquirimos alimentos. Pedro mencionó el incidente del día anterior sin profundizar en detalles, pero admitió la necesidad de un ingreso y el consumo. Posteriormente, Pedro fue evaluado en Mérida y se le dio el alta con la indicación de iniciar el proceso de admisión en Proines. Asimismo, se le informó que se reducirá el intervalo de tiempo entre las revisiones psiquiátricas. También, se propone desde psiquiatría comenzar con el ECA para lo cual sería necesario un dinero extra ya que solo se dispone de la asignación, pero esta opcion ya sabemos que no es viable, porque ECA esta en Castuera y no puede asumir ese gasto de taxi dos veces en semana para ir a controles... En CT el, voluntariamente, en este momento no quiere acudir... Complicado, porque ya estan alterados en la localidad tambien...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2024-03-11','miguel, asisto a la vista por videoconferencia, y envío email a la parte social, económica y juridica informando: Hola a todos, os informo: acabo de asistir a la vista del juicio del procedimiento DIH Div. Herencia 26/2023, juzgado de 1º instancia e instrucción nº1 de Coria, para la formación del inventario de herencia del hermano de la fallecido que estaba casado en gananciales sin hijos, y que queda aplazado para ver si incluyen o no en el Pasivo 240.000€ que solicita la viuda. La demanda nos llegó hace pocos días y en la vista me he enterado que el abogado de la mujer del hno fallecido Facundo solicita un reconocimiento de deuda, el cual acredita en documento privado (será difícil puedan demostrar su validez). Debido a que no podemos saber el Activo y Pasivo de la herencia, debemos fiarnos de lo indicado en la demanda…pues los bienes inmuebles que es lo único que nos afecta en cuanto al Activo deben aparecer en su totalidad, fiándonos además que el abogado de parte demanda (viuda) no se opone tras reuniones de acuerdos a la formación del activo con abogado de parte demandante (resto de la familia) No nos oponemos por tanto a la formación del activo que nos presentan pero sí al pasivo donde en la vista, como digo, el abogado de la mujer dice que tiene un documento privado de reconocimiento de deuda de 240.000€. En el testamento se legan a la mujer tanto el usufructo como las cuentas bancarias y depósitos bancarios que ascienden a cerca de 330.000€, y en cuanto a los bienes inmuebles una vez se determinen qué bienes forman parte del activo y pasivo, y se determine su valor con un contador partidor se repartirá la herencia dando a la mujer el dinero de cuentas bancarias, la mitad de los bienes gananciales y el usufructo de los bienes inmuebles privativos. Y a cinco hermanos los nombra herederos a partes iguales, entre ellos a Emilia. En definitiva que el 4-4-24 nos citan a las 11h en juicio verbal, a efectos de determinar cómo queda el inventario, y a partir de ahí si el pasivo fuese mayor que el activo poder renunciar a la herencia. Ya le he dicho al juzgado que soliciten abogado de oficio, porque me han dicho que hoy no era preciso pero sí para las actuaciones en adelante, con lo cual lo solicitará el juzgado directamente a los colegios de abogado y procuradores. Confirman también al centro que ha asistido por videoconferencia que no será necesaria la presencia en adelante de Emilia porque ya estará representada por procurador y abogado, y además las demás partes no van a pedir entrevista o testimonio. A efectos de afrontar gastos Maria me confirma que tiene dos pensiones de 597,93€ y 377,98€ y los gastos= comunidad de propietarios 75+23€; seguro de decesos mensual 30€+770,30€ residencia el Cuartillo. Saldo a día de hoy 4.743,02€ Vamos por tanto a esperar se determine el inventario y si el activo es superior al pasivo seguiremos adelante pero si no lo fuera tendremos que renunciar a la herencia. Adjunto el testamento del hermano y la demanda por si queréis consultar algo. Inés, apunto en cuadro excell cambio de fecha y hora a 4-4-24 a 11h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2024-03-11','Ana: Cumplimento y subo a firma la DECLARACIÓN ANUAL DE PNC. ················· Actualizo cuantía en la base de datos: 776,85 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-03-11','Ana: Llamada de José Luis (687 581 061), hermano de José Manuel. Dice que tal y como le indicó Miguel, A. Jurídico CTAEx, ha estado llamando al perito, pero éste no le coge el teléfono. ···················· Envío mail a Miguel: "...¿podrías intentarlo tú desde aquí? El número de teléfono lo tienes en el hilo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MACARRO'and apellido2='CAMACHO'),'2024-03-11','TERESA ENVIO HOJA DE DERIVACION A FUTUEX PARA INTERVENCION EN DOMICILIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-03-11','miguel, recibo emaiil de Ana Ts: Buenos días, Miguel, He recibió llamada de José Luis, hermano de José Manuel Romero Mediavilla. Dice que tal y como le indicaste, ha estado llamando al perito, pero éste no le coge el teléfono. Se lo cogió la semana pasada, le dijo que estaba ocupado, que le llamara más tarde y desde entonces no consique que le coja el teléfono. Por favor, ¿podrías intentarlo tú desde aquí? El número de teléfono lo tienes en el hilo. ------------------------------------------------------------ Contesto a Ana y Maite: Buenos días Ana, he llamado al teléfono del perito de Zurich 615936664 y sale apagado. Os recuerdo que la vivienda está a nombre de todos los hermanos y que sobre el siniestro ni el vecino (Javier Rebollo 633-446263) ni su perito nos ha pasado nada por escrito (reclamación concretando los daños, ni póliza de seguro, informe del perito). Este vecino puede decir lo que quiera, como lo de que se le paguen un montón de meses de alquiler...que lo reclame vía judicial. Sólo se abonará lo que el perito dictamine. Sobre este asunto me remito a mi email de 4-3-24: " Buenos días, acabo de hablar con el hermano de José Manuel Romero Mediavilla, José Luis 687581061, me confirma que la vivienda que habita José Manuel es propiedad de los 7 hermanos (dos están fallecidos y con hijos). Tras los daños el año pasado y éste al vecino por goteras, me dice que tras hacerles levantar el baño el año pasado, las goteras finalmente fueron del vecino. Alberto: se supone que desde el año pasado pidieron tener un seguro de la vivienda, según me dice José Luis. Es necesario hacer un seguro a la vivienda lo antes posible. Por lo que me comenta José Luis (hno), el vecino está intentando sacar tajada pidiendo otros daños: móvil, meses de alquiler que está perdiendo, etc. Me ha dicho que debido a la urgente situación él ha abonado los 400€ de arreglo del albañil, pero quedaría pintar, arreglar el plato de ducha (que si bien ha sufrido daños, el albañil le ha confirmado que hacía años que no se usaba), también habría que pagarle la alcachofa y la tapa del váter. Me insistía en hablar con el vecino, el perito, etc, y le he dicho que no hablaremos con nadie, lo que quieran nos envíen un informe de daños y lo estudiaremos (bien a través de él o bien directamente), paralelamente él irá pidiendo y enviándonos presupuesto de arreglo de la mampara y taza de váter. Le he explicado que no paguen nada sin enviar siempre el presupuesto y se les autorice a arreglarlo por adelantado. Así mismo, le he dicho que los gastos extraordinarios son comunes a todos los hermanos y por tanto no tiene que asumirlos en su totalidad José Manuel, pero me dice que a cambio de no cobrar nada a José Manuel de alquiler y al estar el resto de los hermanos pelados de dinero, quedaron en que José Manuel asumiera los gastos del piso...esta cuestión no sé si está analizada por la parte social y la económica. En conclusión: quedamos a la espera de informe del perito del vecino, presupuesto de arreglos del baño por el hno de José Manuel y parte económica haced un seguro de la vivienda para el futuro". Al ser los interesados el vecino y su perito, hasta que no envíen informe y lo estudiemos no se le arreglará nada, y no debemos de entrar en el juego de llamadas con el vecino que lo que quiere es que se le arregle de todo. Caso que no esté de acuerdo, como digo, que reclame vía judicial. Lo que es importante Ana es que te asegures con Alberto que la vivienda se le hace rápidamente un seguro con tomador de seguro José Manuel que es quién vive.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2024-03-11','Ana: Envío correo a la sección económica: "Os reenvío correo Javier, TS del C. Sociosanitario de Plasencia con presupuesto para gafas de JAIRO PUERTAS MARTÍN. En el hilo subrayo en amarillo el número de cuenta para hacer transferencia. Por mi parte, si es viable ok al mismo. No es elevado (89 €). Javier, por favor, si no te importa, los próximos presupuestos y cuestiones estrictamente económicas, remítelos directamente a la atención de la sección económica a la siguiente dirección: ctutelar@salud-juntaex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2024-03-11','Ana: Envío correo a Toni-Futuex, con copia a Cristina, TS del CSS: "En relación a MARTÍN DOMÍNGUEZ PALENCIA, solicitaros que cuando podáis le visitéis en el C. Sociosanitario con motivo de volver a plantearle la necesidad de vender una de sus viviendas. Su situación económica, aunque ya está algo más saneada, es complicada por las múltiples deudas y multas que tenía acumuladas. Desde el Gabinete Técnico de la CTAEx, consideramos que debería vender el adosado de la C/ García Márquez, nº 10, pues entre otras cuestiones, sólo le genera gastos y además no debe reunir condiciones de habitabilidad. Entendemos que en caso de que le dieran el alta en el CSS, podría volver a su otro domicilio en la C/ Huaina Capac, nº 1, 3 – E, en el que residía antes de su ingreso. Pero necesitaríamos su conformidad para que mis compañeros Asesores Jurídicos puedan comenzar los trámites. *Pediros también que, cuando podáis, acudáis a visitar y hacer fotografías al adosado. Para dicha visita, entiendo que podéis contactar con el hermano, Jesús (927 23 75 73 // 600 70 22 55) quién mostrado colaborador en otras ocasiones. Pongo en copia a Cristina, TS del C. Sociosanitario para que esté al corriente y porque creo que podría estar presente durante la visita a Martín y colaborar para hacer entender a Martín la necesidad de dicha venta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2024-03-06','Ana: Correo de la RRMM Santa Catalina de Calzadilla (residenciasantacatalina@gmail.com) al ctutelar@: "adjunto citación de Emiliana para ser revisada por forense en los Juzgados de coria, será el próximo día 13 de marzo y ya lo he programado con la compañera de Futuex."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2024-03-11','El juez ha estimado condenar a Juan José a 6 meses de prisión. Sin embargo, y teniendo en cuenta su evolución favorable en diversos ámbitos de su vida, ha decidido SUSPENDER esta condena. A partir de ahora, y durante un período de 2 años, el usuario tendrá que seguir asistiendo al servicio CEDEX, a tratamiento psicológico y a consulta con el psiquiatra. En principio cada 3 meses se tendrá que enviar al juzgado un informe de valoración como comprobante que Juan José está cumpliendo con la sentencia pactada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2024-03-11','S. eco : Buenos días, podéis domiciliar el agua, os informo del número de cuenta que debéis facilitar. PLATA MACEDO MANUELA 08.865.351R CCC CAJA RURAL DE EXTREMADURA ES49 3009 0029 38 2370523413','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2024-03-11','Ana: Escribo a la S. Jurídica: "Adjunto el INFORME SOCIAL que solicité en noviembre para la revisión de las medidas judiciales de apoyo de Sandra Sandín Hernández."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2023-11-16','miguel, envio email a la asesoría y la abogada ANA IGLESIAS AVILA >anaiglesias@icac.es>; fiscal@grupoteficon.es adjuntando el poder apud acta, que en su día se firmó: Buenos días Ana, ayer hablando con Alvaro de la asesoría, no recordaba que ya hay un poder para que solicites la aprobación judicial de la herencia y la autorización de venta llegado el caso. Me confirmó Alvaro que las escrituras originales de la herencia las tendrá en su poder la asesoría, para tu conocimiento por si necesitas incorporarlas a la solicitud judicial de aprobación de herencia. Por otra parte, para que yo pueda ratificar la herencia en la notaria de Mérida, me piden el certificado literal de nacimiento en donde conste que Enrique esta curatelado representativamente por la Comisión Tutelar de Adultos de la Junta de Extremadura. Adjunto justificante de solicitud al registro de la propiedad de Salamanca (lugar de nacimiento). Si es posible que podáis agilizar el remitirme un certificado literal de nacimiento en el que conste que la Comisión Tutelar de Adultos es su curador representativo ganaríamos tiempo. En caso de que el juzgado en su día no diera orden o no hubiese sido inscrito en dicho registro civil la situación de curatelado por la Comisión, tendríamos que solicitar al juzgado, que en su día dictó dicha curatela, que diese orden al registro civil para su inscripción, ya que los registros civiles no aceptan nuestra solicitud directamente.','2');
